INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_hello_09_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_hello_09_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_Hello_Info","outputIds":["DIA_Horatio_Hello_09_00"],"lines":[{"speaker":"npc","text":{"pl":"Co tu robisz? Szukasz kłopotów?","en":"What are you doing here? You looking for trouble?","de":"Was machst du hier? Willst du Ärger haben?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791207);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_hello_be_cool_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_hello_be_cool_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_Hello_BeCool","outputIds":["DIA_Horatio_Hello_BeCool_15_00","DIA_Horatio_Hello_BeCool_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Spokojnie! Jestem tu nowy.","en":"Hey, relax! I''m a newcomer.","de":"Entspann dich! Ich bin neu hier."}},{"speaker":"npc","text":{"pl":"Hmmm... Wyglądasz w porządku. Chociaż nigdy nie wiadomo - zawsze znajdzie się jakiś nowy, który wyobraża sobie niewiadomo co.","en":"Huh... You look okay though. You never know. You get new guys come along thinking they''re it every day.","de":"Hm ... siehst mir ganz in Ordnung aus - hier weiß man nie. Da kommt jeden Tag ein neuer Mistkerl, der''s wissen will."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791207);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_hello_piss_off_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_hello_piss_off_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_Hello_PissOff","outputIds":["DIA_Horatio_Hello_PissOff_15_00","DIA_Horatio_Hello_PissOff_09_01","DIA_Horatio_Hello_PissOff_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Kłopotów? A co - grozisz mi, robolu?!","en":"Trouble? Who with? A peasant?","de":"Ärger? Von wem? Von einem Bauern?"}},{"speaker":"npc","text":{"pl":"Tylko dlatego, że pracuję w polu, myślisz, że nie dam sobie rady z kimś takim jak ty?","en":"Just because I work in the fields, doesn''t mean I can''t defend myself against guys like you.","de":"Nur weil ich auf den Feldern arbeite, heißt das nicht, dass ich mich nicht gegen Typen wie dich wehren kann."}},{"speaker":"npc","text":{"pl":"No, jeśli szukasz guza, to chodź!","en":"So come here if you want trouble!","de":"Also komm nur her, wenn du Ärger willst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791207);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_help_str_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_help_str_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_HelpSTR_Info","outputIds":["DIA_Horatio_HelpSTR_15_00","DIA_Horatio_HelpSTR_09_01","DIA_Horatio_HelpSTR_15_02"],"lines":[{"speaker":"hero","text":{"pl":"MOGĘ pokonać Ryżowego Księcia i jego bandytów - jeśli mi pomożesz!","en":"I WILL defeat the Rice Lord and his thugs - if you help me!","de":"Ich WERDE den Reislord und seine Schläger fertig machen - wenn du mir dabei hilfst!"}},{"speaker":"npc","text":{"pl":"Dobrze! Przysięgłem, że nigdy nie zaatakuję innego człowieka, ale nie powiedziałem, że nie pokażę komuś jak to zrobić!","en":"Good! I''ve sworn I''ll never attack anyone again, but I never said I wouldn''t teach anyone else to do it.","de":"Gut! Ich habe geschworen, nie wieder jemanden anzugreifen, aber NICHT, es niemandem beizubringen."}},{"speaker":"hero","text":{"pl":"Zamieniam się w słuch.","en":"I''m all ears!","de":"Ich bin ganz Ohr!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791207);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_sorry_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_sorry_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_SORRY_Info","outputIds":["DIA_Horatio_SORRY_15_00","DIA_Horatio_SORRY_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Przepraszam, nie chciałem być złośliwy.","en":"I''m sorry I said what I did about the peasants.","de":"Tut mir Leid, der Spruch mit dem Bauern."}},{"speaker":"npc","text":{"pl":"Trzeba było pomyśleć o tym wcześniej, chłopcze.","en":"You should have thought of that before, boy!","de":"Das hättest du dir eher überlegen sollen, Junge!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_story_09_04_4', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_story_09_04_4","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_Story_Info","outputIds":["DIA_Horatio_Story_09_04","DIA_Horatio_Story_09_05"],"lines":[{"speaker":"npc","text":{"pl":"Zwykła bójka w karczmie. Nie chciałem zabić faceta - chyba po prostu za mocno go walnąłem.","en":"It was just an ordinary bar fight. I didn''t mean to kill the guy, I just must have hit him too hard.","de":"Es war ein einfacher Streit in einer Kneipe. Ich wollte den Mann nicht töten, aber ich habe zu stark zugeschlagen."}},{"speaker":"npc","text":{"pl":"Byłem wtedy kowalem. Najwyraźniej nie doceniłem własnej siły.","en":"I was a blacksmith at the time. I didn''t know my own strength...","de":"Ich habe damals als Schmied gearbeitet. Ich konnte meine Kraft nicht kontrollieren ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_story_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_story_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_Story_Info","outputIds":["DIA_Horatio_Story_15_00","DIA_Horatio_Story_09_01","DIA_Horatio_Story_09_02","DIA_Horatio_Story_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Co ktoś taki jak ty robi w towarzystwie zbieraczy?","en":"What''s a man like you doing with the peasants?","de":"Was macht ein Kerl wie du bei den Bauern?"}},{"speaker":"npc","text":{"pl":"Lee też mnie o to pytał. Nie chce już walczyć, no chyba że w obronie własnej.","en":"Lee asked me that. I don''t fight any more - except to defend myself.","de":"Das hat Lee mich auch gefragt, aber ich kämpfe nicht mehr - außer um mich zu verteidigen."}},{"speaker":"npc","text":{"pl":"Raz zabiłem człowieka i jak dla mnie to było o jeden raz za dużo. Zresztą dlatego właśnie trafiłem do tej zapchlonej kolonii.","en":"I killed a guy once, and that was once too many. That''s why they chucked me in this goddamn colony - it was justice.","de":"Ich habe einmal getötet, das war einmal zu viel. Deswegen haben sie mich in diese gottverdammte Kolonie geworfen - und das war nur gerecht."}},{"speaker":"hero","text":{"pl":"Jak to się stało?","en":"How did it happen?","de":"Was ist passiert?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_thanks_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_thanks_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_Thanks_Info","outputIds":["DIA_Horatio_Thanks_15_00","DIA_Horatio_Thanks_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Dzięki za pomoc!","en":"Thanks for your help!","de":"Danke für deine Hilfe!"}},{"speaker":"npc","text":{"pl":"Wykorzystaj tę wiedzę wyłącznie w słusznej sprawie!","en":"Use your knowledge for a just cause, and for NOTHING ELSE.","de":"Nutze dein Wissen für die gerechte Sache! Und NUR DAFÜR."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_thought_str_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_thought_str_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_ThoughtSTR_Info","outputIds":["DIA_Horatio_ThoughtSTR_15_00","DIA_Horatio_ThoughtSTR_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Przemyślałem sobie to wszystko jeszcze raz...","en":"I''ve been thinking the whole thing over...","de":"Ich hab'' noch einmal über die Sache nachgedacht ..."}},{"speaker":"npc","text":{"pl":"No i? Wymyśliłeś coś lepszego?","en":"And? Have you thought of anything better?","de":"Und? Ist dir was Besseres eingefallen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_thought_str_no_idea_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_thought_str_no_idea_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_ThoughtSTR_NoIdea","outputIds":["DIA_Horatio_ThoughtSTR_NoIdea_15_00","DIA_Horatio_ThoughtSTR_NoIdea_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie.","en":"No.","de":"Nein."}},{"speaker":"npc","text":{"pl":"Tak myślałem.","en":"I thought so.","de":"Dachte ich mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_thought_str_ricelord_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_thought_str_ricelord_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_ThoughtSTR_Ricelord","outputIds":["DIA_Horatio_ThoughtSTR_Ricelord_15_00","DIA_Horatio_ThoughtSTR_Ricelord_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Tak. Chciałbym przeciwstawić się Ryżowemu Księciu i jego zbirom!","en":"Yes. I want to be able to take on the Rice Lord and his thugs!","de":"Ja. Ich will es mit dem Reislord und seinen Schlägern aufnehmen können!"}},{"speaker":"npc","text":{"pl":"Hmmm... Wielu już próbowało przed tobą.","en":"Hmm... You wouldn''t be the first to try.","de":"Hmm ... Du bist nicht der Erste, der das versucht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_why_here_09_04_4', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_why_here_09_04_4","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_WhyHere_Info","outputIds":["DIA_Horatio_WhyHere_09_04"],"lines":[{"speaker":"npc","text":{"pl":"Może. Tak, czy inaczej - tutaj znalazłem spokój. Radzę ci pójść w moje ślady.","en":"Maybe. Anyway, I''ve found peace here, and you should try the same.","de":"Kann schon sein. Immerhin habe ICH hier meinen Frieden gefunden. Und das solltest du auch versuchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_dia_horatio_why_here_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_dia_horatio_why_here_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"DIA_Horatio_WhyHere_Info","outputIds":["DIA_Horatio_WhyHere_15_00","DIA_Horatio_WhyHere_09_01","DIA_Horatio_WhyHere_09_02","DIA_Horatio_WhyHere_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego dołączyłeś właśnie do TEGO obozu?","en":"Why did you join THIS camp?","de":"Warum bist du ausgerechnet in DIESES Lager gegangen?"}},{"speaker":"npc","text":{"pl":"Już ci mówię: do wyboru miałem tylko tych świrów z Sekty, a nie uśmiechało mi się pranie mózgu, któremu chcieli mnie poddać.","en":"I''ll tell you: My only option was to join those sect loonies, and I didn''t wanna let those Gurus of theirs mess about with my brain.","de":"Das will ich dir sagen: Die einzig andere Wahl wären die Sektenspinner gewesen, aber ich habe keine Lust, mir von den Gurus den Kopf waschen zu lassen."}},{"speaker":"npc","text":{"pl":"W Starym Obozie miałbym za dużo kłopotów ze Strażnikami, a tutaj Najemnicy i Szkodniki traktują mnie z szacunkiem.","en":"In the Old Camp, I''d have had too much trouble with the guards, but the mercenaries and rogues do have some respect.","de":"Im Alten Lager hätte ich keine Ruhe vor den Gardisten gehabt, aber die Söldner und Banditen haben Respekt."}},{"speaker":"hero","text":{"pl":"To znaczy - boją się ciebie...","en":"They''re afraid of you...","de":"Sie fürchten dich ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_901_horatio_info_horatio_wasser_15_00_0', 'BAU_901_Horatio', '{"id":"missions_dia_bau_901_horatio_info_horatio_wasser_15_00_0","npcId":"BAU_901_Horatio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_901_Horatio.d","sourceFunction":"Info_Horatio_Wasser_Info","outputIds":["Info_Horatio_Wasser_15_00","Info_Horatio_Wasser_09_01","Info_Horatio_Wasser_NOWATER_09_00"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Lewus. Przyniosłem wam wodę.","en":"Lefty sent me. I''ve brought you some water.","de":"Lefty schickt mich. Ich hab'' Wasser für dich."}},{"speaker":"npc","text":{"pl":"Dzięki, kolego. Jeszcze trochę, a zacząłbym pić z kałuży!","en":"Thanks, man! I was just about to start drinking the mud.","de":"Danke, Mann! Ich war schon kurz davor, den Schlamm zu saufen."}},{"speaker":"npc","text":{"pl":"Chyba ci się skończyła! Trudno, wezmę trochę od innych.","en":"You''ve run out. I''ll get some from the others.","de":"Du hast nichts mehr. Ich hol mir von den anderen was."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_902_pock_dia_pock_forgot_all_15_00_0', 'BAU_902_Pock', '{"id":"missions_dia_bau_902_pock_dia_pock_forgot_all_15_00_0","npcId":"BAU_902_Pock","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_902_Pock.d","sourceFunction":"DIA_Pock_ForgotAll_Info","outputIds":["DIA_Pock_ForgotAll_15_00","DIA_Pock_ForgotAll_04_01","DIA_Pock_ForgotAll_15_02","DIA_Pock_ForgotAll_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Wszystko w porządku?","en":"Everything okay with you?","de":"Alles klar bei dir?"}},{"speaker":"npc","text":{"pl":"Miło zobaczyć nową twarz.","en":"It''s good to see a new face.","de":"Schön mal wieder ein neues Gesicht zu sehen."}},{"speaker":"hero","text":{"pl":"Czekaj! My już kiedyś rozmawialiśmy!","en":"Hang on! We talked earlier.","de":"Moment mal! Wir hatten uns schon unterhalten."}},{"speaker":"npc","text":{"pl":"Nie! To niemożliwe. Widzę cię pierwszy raz w życiu!","en":"No! No, we can''t have done. I''ve never seen you before in my life.","de":"Nein! Nein, das ist ausgeschlossen. Dich hab'' ich hier noch nie gesehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_902_pock_dia_pock_hello_15_00_0', 'BAU_902_Pock', '{"id":"missions_dia_bau_902_pock_dia_pock_hello_15_00_0","npcId":"BAU_902_Pock","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_902_Pock.d","sourceFunction":"DIA_Pock_Hello_Info","outputIds":["DIA_Pock_Hello_15_00","DIA_Pock_Hello_04_01","DIA_Pock_Hello_15_02","DIA_Pock_Hello_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Jestem tu nowy.","en":"Hi! I''m new here.","de":"Hi! Ich bin neu hier."}},{"speaker":"npc","text":{"pl":"Miło zobaczyć nową twarz.","en":"It''s good to see a fresh face.","de":"Schön mal wieder ein neues Gesicht zu sehen."}},{"speaker":"hero","text":{"pl":"Pewnie jesteś tu już od dawna?","en":"You must have been here a long time, huh?","de":"Du bist schon lange in der Kolonie, hm?"}},{"speaker":"npc","text":{"pl":"Święta racja, chłopcze. Byłem jednym z pierwszych, którzy tu trafili.","en":"Darned right, boy. I was one of the first.","de":"Stimmt genau, Junge. Ich war einer der Ersten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_902_pock_dia_pock_know_much_15_00_0', 'BAU_902_Pock', '{"id":"missions_dia_bau_902_pock_dia_pock_know_much_15_00_0","npcId":"BAU_902_Pock","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_902_Pock.d","sourceFunction":"DIA_Pock_KnowMuch_Info","outputIds":["DIA_Pock_KnowMuch_15_00","DIA_Pock_KnowMuch_04_01","DIA_Pock_KnowMuch_04_02"],"lines":[{"speaker":"hero","text":{"pl":"W takim razie na pewno dużo wiesz o tym miejscu?","en":"In that case you must know a lot about this place?","de":"Dann weißt du bestimmt ne Menge über all das hier?"}},{"speaker":"npc","text":{"pl":"Co nieco. Większość czasu spędzam tutaj - na polu.","en":"So so. I spend most of my time out here, just picking rice.","de":"Tja wie man''s nimmt, die meiste Zeit verbringe ich hier beim Reispflücken."}},{"speaker":"npc","text":{"pl":"Pewnie dlatego udało mi się tak długo przeżyć. Dostajemy sporo ryżu i trochę gorzałki. Może nie jest to wiele, ale mi wystarczy.","en":"That''s what let me get so old. We get some rice and the odd schnapps. It''s not much, but it''s enough.","de":"Nur dadurch bin ich so alt geworden. Wir bekommen etwas Reis ab und vielleicht mal Schnaps, nicht viel, aber es reicht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_902_pock_dia_pock_why_jail_15_00_0', 'BAU_902_Pock', '{"id":"missions_dia_bau_902_pock_dia_pock_why_jail_15_00_0","npcId":"BAU_902_Pock","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_902_Pock.d","sourceFunction":"DIA_Pock_WhyJail_Info","outputIds":["DIA_Pock_WhyJail_15_00","DIA_Pock_WhyJail_04_01","DIA_Pock_WhyJail_04_02","DIA_Pock_WhyJail_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego tu trafiłeś?","en":"Why are you here?","de":"Weshalb bist du hier?"}},{"speaker":"npc","text":{"pl":"Podatki, chłopcze. Podatki! Moja chata była równie pusta jak mój żołądek i po prostu nie mogłem dłużej płacić!","en":"Taxes, boy, taxes. My shed was as empty as my stomach, and I just couldn''t pay.","de":"Die Steuern, mein Junge, die Steuern. Meine Scheune war so leer wie mein Bauch, da konnte ich nicht mehr zahlen."}},{"speaker":"npc","text":{"pl":"No i pewnego dnia schwytali mnie królewscy żołnierze i przywlekli mnie tutaj. Prawdę mówiąc, na zewnątrz wcale nie było mi lepiej. Tutaj przynajmniej nie głoduję.","en":"So one day the soldiers came and brought me here. But it''s no worse in here than it is out there. At least I won''t starve in here.","de":"Irgendwann kamen die Soldaten und brachten mich her. Aber hier ist es nicht schlechter als draußen. Ich werde wenigstens nicht vor Hunger sterben."}},{"speaker":"npc","text":{"pl":"Wcześniej zawsze płaciłem podatki - przez całe życie! Ale dla tego sukinsyna w koronie to nie był żaden argument!","en":"I''d always paid my taxes before - all my life. But that wasn''t good enough for that son of a bitch with the crown!","de":"Hab immer meine Steuern gezahlt - jahrelang. Aber das hat dem Hurensohn mit der Krone nicht gereicht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_902_pock_info_pock_wasser_15_00_0', 'BAU_902_Pock', '{"id":"missions_dia_bau_902_pock_info_pock_wasser_15_00_0","npcId":"BAU_902_Pock","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_902_Pock.d","sourceFunction":"Info_Pock_Wasser_Info","outputIds":["Info_Pock_Wasser_15_00","Info_Pock_Wasser_04_01","Info_Pock_Wasser_NOWATER_04_00"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Lewus. Mam dla ciebie trochę wody.","en":"Lefty sent me. I''ve brought you some water.","de":"Lefty schickt mich. Ich hab'' Wasser für dich."}},{"speaker":"npc","text":{"pl":"Dzięki, chłopcze. Piękne dzięki.","en":"Thanks, boy! I needed that!","de":"Danke, Junge! Das hab'' ich gebraucht!"}},{"speaker":"npc","text":{"pl":"Ale nic ci już nie zostało! Trudno, wezmę trochę od pozostałych.","en":"But you don''t have any left. Never mind, boy. I''ll ask the others.","de":"Aber du hast nichts mehr. Ist schon gut, Junge. Ich werd mich an die andern halten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_903_rufus_dia_rufus_hello_15_00_0', 'BAU_903_Rufus', '{"id":"missions_dia_bau_903_rufus_dia_rufus_hello_15_00_0","npcId":"BAU_903_Rufus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_903_Rufus.d","sourceFunction":"DIA_Rufus_Hello_Info","outputIds":["DIA_Rufus_Hello_15_00","DIA_Rufus_Hello_02_01","DIA_Rufus_Hello_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Jestem tu nowy. Chciałbym się dowiedzieć, co się tu dzieje.","en":"Hi! I''m new here. I just wanted to know what goes on around here.","de":"Hi! Ich bin neu hier. Wollte mal fragen, was hier so läuft."}},{"speaker":"npc","text":{"pl":"Zapytaj kogoś innego, dobra? Ja tu tylko uprawiam ryż. Na innych rzeczach się nie znam.","en":"Ask someone else, will ya. I do nothin'' but work out here in the fields, I don''t know nothin''.","de":"Frag jemand anderen. Ich arbeite den ganzen Tag auf den Feldern und krieg nichts von dem mit, was hier läuft."}},{"speaker":"npc","text":{"pl":"Najchętniej powiedziałbym Ryżowemu Księciuniowi, żeby sam odwalał swoją brudną robotę!","en":"Man, I''d love to tell the Rice Lord to do his own damn dirty work!","de":"Mann, wie gerne würd'' ich zum Reislord gehen und ihm sagen, er soll seinen Scheiß alleine machen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_903_rufus_dia_rufus_ricelord_15_00_0', 'BAU_903_Rufus', '{"id":"missions_dia_bau_903_rufus_dia_rufus_ricelord_15_00_0","npcId":"BAU_903_Rufus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_903_Rufus.d","sourceFunction":"DIA_Rufus_Ricelord_Info","outputIds":["DIA_Rufus_Ricelord_15_00","DIA_Rufus_Ricelord_02_01","DIA_Rufus_Ricelord_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Kim jest Ryżowy Książe?","en":"Who is the Rice Lord?","de":"Wer ist der Reislord?"}},{"speaker":"npc","text":{"pl":"Był jednym z pierwszych ludzi, którzy tutaj trafili. Pomagał w zakładaniu Obozu i rozpoczął uprawę ryżu.","en":"He was one of the first to arrive here. He helped found the Camp and start up the rice fields.","de":"Er war einer der Ersten hier. Hat das Lager mit gegründet und die Reisfelder angelegt."}},{"speaker":"npc","text":{"pl":"Dziś jedyne, co robi, to obnosi swoje brzuszysko po magazynie. Tłusty wieprz!","en":"These days he just hangs out at the warehouse stretching his stomach, the fat pig!","de":"Heute steht er nur noch vor seinem Lagerhaus und streckt seine Wampe raus, der alte Fettsack!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_903_rufus_dia_rufus_why_02_04_4', 'BAU_903_Rufus', '{"id":"missions_dia_bau_903_rufus_dia_rufus_why_02_04_4","npcId":"BAU_903_Rufus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_903_Rufus.d","sourceFunction":"DIA_Rufus_Why_Info","outputIds":["DIA_Rufus_Why_02_04","DIA_Rufus_Why_02_05","DIA_Rufus_Why_02_06","DIA_Rufus_Why_02_07"],"lines":[{"speaker":"npc","text":{"pl":"Powiedział: \"Chyba nie chcesz, żeby twoi koledzy odwalali za ciebie całą robotę, co?\".","en":"You don''t wanna let your colleagues do all their work by themselves, do you?'' he asked.","de":"''Du willst doch nicht deine Kollegen ganz alleine schuften lassen?'', hat er gesagt."}},{"speaker":"npc","text":{"pl":"Powiedziałem mu, że jestem wyczerpany wczorajszą pracą, i że potrzebuję odpoczynku. Ale on miał to gdzieś.","en":"I told him I was exhausted from the previous day''s work, that I needed a rest and all that. But he never listened.","de":"Ich hab'' ihm erklärt, dass ich kaputt bin vom Tag vorher, dass ich mich ausruhen muss und so. Aber er hat mir nicht zugehört."}},{"speaker":"npc","text":{"pl":"Złapał mnie za kołnierz i ZACIĄGNĄŁ z powrotem na pole.","en":"He grabbed me by the collar and dragged me back to the field.","de":"Er hat mich am Kragen gepackt und auf die Felder geschleift."}},{"speaker":"npc","text":{"pl":"Od tamtej pory codziennie czekał na mnie na progu mojej chaty - dopóki nie nauczyłem się sam wychodzić w pole. Nie chciałem, żeby mnie poturbowali.","en":"From that day on, he stood outside my doorstep every day - until I got used to going on my own. I didn''t want any trouble with those guys.","de":"Seit dem Tag stand er jeden Morgen vor meiner Tür - irgendwann bin ich dann von alleine gekommen - ich wollte keinen Ärger mit den Typen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_903_rufus_dia_rufus_why_02_08_8', 'BAU_903_Rufus', '{"id":"missions_dia_bau_903_rufus_dia_rufus_why_02_08_8","npcId":"BAU_903_Rufus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_903_Rufus.d","sourceFunction":"DIA_Rufus_Why_Info","outputIds":["DIA_Rufus_Why_02_08"],"lines":[{"speaker":"npc","text":{"pl":"To banda morderców. Lepiej trzymaj się od nich z daleka.","en":"They''re real cut-throats, you''d better steer clear of them.","de":"Das sind richtige Halsabschneider, mit denen legst du dich besser nicht an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_903_rufus_dia_rufus_why_15_00_0', 'BAU_903_Rufus', '{"id":"missions_dia_bau_903_rufus_dia_rufus_why_15_00_0","npcId":"BAU_903_Rufus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_903_Rufus.d","sourceFunction":"DIA_Rufus_Why_Info","outputIds":["DIA_Rufus_Why_15_00","DIA_Rufus_Why_02_01","DIA_Rufus_Why_02_02","DIA_Rufus_Why_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Skoro tak ci to nie odpowiada, dlaczego tu pracujesz?","en":"If you don''t like it, why are you working here?","de":"Wenn''s dir nicht gefällt, warum arbeitest du dann hier?"}},{"speaker":"npc","text":{"pl":"To się zdarzyło pierwszego dnia po moim przybyciu. Lewus, jeden z oprychów pracujących dla Ryżowego Księcia, podszedł do mnie i spytał czy nie mógłbym im pomóc na polu.","en":"It happened the first day I got here. Lefty, one of the thugs that works for the Rice Lord, came up to me and asked if I could lend a hand in the rice fields.","de":"Es war am ersten Tag als ich hier war. Lefty, einer der Schläger, die für den Reislord arbeiten, kam zu mir und fragte mich, ob ich mal kurz auf den Reisfeldern helfen könnte."}},{"speaker":"npc","text":{"pl":"Powiedziałem \"jasne\". W końcu byłem tu nowy i zależało mi na znalezieniu sobie przyjaciół.","en":"Sure, I said. I was new here and I wanted to make myself useful.","de":"Klar, hab'' ich gesagt. Ich war neu und wollte mich nützlich machen."}},{"speaker":"npc","text":{"pl":"Następnego dnia, kiedy ucinałem sobie drzemkę, facet znowu się zjawił.","en":"The next day, when I was taking a short rest, the guy turned up again.","de":"Als ich mich am nächsten Tag von der Arbeit ausruhte, steht der Typ schon wieder vor mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_903_rufus_info_rufus_wasser_15_00_0', 'BAU_903_Rufus', '{"id":"missions_dia_bau_903_rufus_info_rufus_wasser_15_00_0","npcId":"BAU_903_Rufus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_903_Rufus.d","sourceFunction":"Info_Rufus_Wasser_Info","outputIds":["Info_Rufus_Wasser_15_00","Info_Rufus_Wasser_02_01","Info_Rufus_Wasser_NOWATER_02_00"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Lewus. Przynoszę ci wodę.","en":"Lefty sent me. I''ve brought you some water.","de":"Lefty schickt mich. Ich hab'' Wasser für dich."}},{"speaker":"npc","text":{"pl":"Dzięki, stary. W gębie mi już zaschło.","en":"Thanks, man. My mouth''s like a desert!","de":"Danke, Mann. Ich sterbe vor Durst."}},{"speaker":"npc","text":{"pl":"Woda?! Hej, kolego! Nic ci już nie zostało. Tylko mi nie mów, że znowu wszyscy zdążyli się napić oprócz mnie!","en":"Water! Hey, man! There''s none left! Don''t tell me everyone got some except me, again?","de":"Wasser! Hey, Mann! Du hast nichts mehr! Haben wieder alle was gekriegt bis auf mich?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_912_jeremiah_dia_jeremiah_hallo_15_00_0', 'BAU_912_Jeremiah', '{"id":"missions_dia_bau_912_jeremiah_dia_jeremiah_hallo_15_00_0","npcId":"BAU_912_Jeremiah","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_912_Jeremiah.d","sourceFunction":"DIA_Jeremiah_Hallo_Info","outputIds":["DIA_Jeremiah_Hallo_15_00","DIA_Jeremiah_Hallo_04_01","DIA_Jeremiah_Hallo_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Co robisz?","en":"What are you doing?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Przygotowuję ryżówkę, chłopcze.","en":"I''m making rice schnapps, boy.","de":"Ich brenne den Reisschnaps, Junge."}},{"speaker":"npc","text":{"pl":"Proszę - weź sobie jedną butelkę. Tylko nie mów Silasowi.","en":"Here - have a bottle. But don''t tell Silas.","de":"Hier - nimm ne Flasche. Aber sag nichts Silas."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_912_jeremiah_dia_jeremiah_horatio_04_04_4', 'BAU_912_Jeremiah', '{"id":"missions_dia_bau_912_jeremiah_dia_jeremiah_horatio_04_04_4","npcId":"BAU_912_Jeremiah","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_912_Jeremiah.d","sourceFunction":"DIA_Jeremiah_Horatio_Info","outputIds":["DIA_Jeremiah_Horatio_04_04"],"lines":[{"speaker":"npc","text":{"pl":"To by było wbrew jego zasadom.","en":"It''d go against his beliefs.","de":"Seine Überzeugung hält ihn davon ab."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_912_jeremiah_dia_jeremiah_horatio_15_00_0', 'BAU_912_Jeremiah', '{"id":"missions_dia_bau_912_jeremiah_dia_jeremiah_horatio_15_00_0","npcId":"BAU_912_Jeremiah","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_912_Jeremiah.d","sourceFunction":"DIA_Jeremiah_Horatio_Info","outputIds":["DIA_Jeremiah_Horatio_15_00","DIA_Jeremiah_Horatio_04_01","DIA_Jeremiah_Horatio_04_02","DIA_Jeremiah_Horatio_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Co możesz mi powiedzieć o Ryżowym Księciu?","en":"What can you tell me about the Rice Lord?","de":"Was kannst du mir über den Reislord sagen?"}},{"speaker":"npc","text":{"pl":"To zapchlony wieprz! Jego siepacze zmuszają słabszych do pracy na polach.","en":"He''s a damn swine! His thugs pick on the weak and force ''em to work in the fields.","de":"Er ist ein verdammtes Schwein! Seine Schläger suchen sich die Schwachen aus, um sie zur Arbeit auf den Feldern zu zwingen."}},{"speaker":"npc","text":{"pl":"Jedyna osoba, która mogłaby się mu przeciwstawić to Horacy. Ale on nie lubi przemocy.","en":"The only one who could stand up to him is Horatio. But he doesn''t do violence.","de":"Der einzige, der sich wehren könnte ist Horatio. Aber der hat mit Gewalt nichts am Hut."}},{"speaker":"npc","text":{"pl":"Słyszałem, jak kiedyś powiedział, że ma ochotę pogruchotać Księciu kości, ale tak naprawdę nigdy by tego nie zrobił.","en":"I did once hear him say he''d love to smash the Rice Lord''s head in, but he''d never really do it.","de":"Ich hab'' mal gehört, wie er gesagt hat, er würde dem Reislord gerne den Schädel einschlagen, aber das würde er nie tun."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_912_jeremiah_dia_jeremiah_perm_15_00_0', 'BAU_912_Jeremiah', '{"id":"missions_dia_bau_912_jeremiah_dia_jeremiah_perm_15_00_0","npcId":"BAU_912_Jeremiah","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_912_Jeremiah.d","sourceFunction":"DIA_Jeremiah_PERM_Info","outputIds":["DIA_Jeremiah_PERM_15_00","DIA_Jeremiah_PERM_04_01","DIA_Jeremiah_PERM_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak idzie destylacja?","en":"How''s the distillery going?","de":"Wie läuft das Schnapsbrennergeschäft?"}},{"speaker":"npc","text":{"pl":"Przy tych facetach ledwie nadążam z zamówieniami. Ci to potrafią wypić!","en":"I can hardly keep up with these guys. Man, can they drink!","de":"Ich kann kaum soviel nachlegen, wie die Kerle wegsaufen."}},{"speaker":"npc","text":{"pl":"I nawet mi to na rękę. Przynajmniej psy Ryżowego Księcia zostawiają mnie w spokoju.","en":"It''s a good thing really. While I''m busy, the Rice Lord''s lapdogs leave me alone.","de":"Ist auch ganz gut so - solange ich hier genug zu tun habe, lassen mich die Jungs vom Reislord in Ruhe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_935_homer_dia_homer_built_dam_15_00_0', 'BAU_935_Homer', '{"id":"missions_dia_bau_935_homer_dia_homer_built_dam_15_00_0","npcId":"BAU_935_Homer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_935_Homer.d","sourceFunction":"DIA_Homer_BuiltDam_Info","outputIds":["DIA_Homer_BuiltDam_15_00","DIA_Homer_BuiltDam_02_01","DIA_Homer_BuiltDam_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Czy to TY zbudowałeś tę tamę?","en":"Did YOU build the dam?","de":"Hast DU den Damm gebaut?"}},{"speaker":"npc","text":{"pl":"Tak. Zbudowałem ją dawno temu, gdy Nowy Obóz dopiero powstawał.","en":"Yes. I built the dam back when we founded the New Camp.","de":"Ja. Als wir damals das neue Lager gegründet haben, habe ich den Damm errichtet."}},{"speaker":"npc","text":{"pl":"Oczywiście wszyscy pomagali, ale to ja nadzorowałem budowę.","en":"Of course everyone helped, but I was the master builder.","de":"Natürlich haben alle mitgeholfen, aber ich war der Baumeister."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_935_homer_dia_homer_hello_15_00_0', 'BAU_935_Homer', '{"id":"missions_dia_bau_935_homer_dia_homer_hello_15_00_0","npcId":"BAU_935_Homer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_935_Homer.d","sourceFunction":"DIA_Homer_Hello_Info","outputIds":["DIA_Homer_Hello_15_00","DIA_Homer_Hello_02_01","DIA_Homer_Hello_02_02","DIA_Homer_Hello_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Szukasz czegoś?","en":"Are you looking for something?","de":"Hältst du nach irgendwas Ausschau?"}},{"speaker":"npc","text":{"pl":"Szukam pęknięć w tamie. Chyba jakiś topielec podgryza jej fundamenty.","en":"I''m looking for leaks in the dam. I reckon there''s a lurker gnawing at the foundations.","de":"Ich suche undichte Stellen im Damm. Ich habe den Verdacht, dass ein Lurker am Fundament des Damms nagt."}},{"speaker":"npc","text":{"pl":"Paskuda uszkadza zębami i pazurami kamienie i drewniane pale pod wodą.","en":"The beast grinds its teeth and claws against the stones and wooden beams under water.","de":"Das Vieh wetzt seine Zähne und Krallen an den Steinen und Holzbalken unter Wasser."}},{"speaker":"npc","text":{"pl":"Jeśli nie przestanie, całą tamę trafi szlag!","en":"If it carries on, the whole dam will soon be undermined.","de":"Auf diese Weise ist bald der gesamte Damm untergraben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_935_homer_dia_homer_perm_15_00_0', 'BAU_935_Homer', '{"id":"missions_dia_bau_935_homer_dia_homer_perm_15_00_0","npcId":"BAU_935_Homer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_935_Homer.d","sourceFunction":"DIA_Homer_PERM_Info","outputIds":["DIA_Homer_PERM_15_00","DIA_Homer_PERM_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Z tamą wszystko w porządku?","en":"Everything okay with the dam?","de":"Alles klar beim Damm?"}},{"speaker":"npc","text":{"pl":"Mocna jak skała. Nic jej nie zaszkodzi!","en":"It''s strong as a fortress, nothing can knock it down.","de":"Steht wie ''ne Festung, den kriegt so schnell nichts klein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_935_homer_dia_homer_running_15_00_0', 'BAU_935_Homer', '{"id":"missions_dia_bau_935_homer_dia_homer_running_15_00_0","npcId":"BAU_935_Homer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_935_Homer.d","sourceFunction":"DIA_Homer_Running_Info","outputIds":["DIA_Homer_Running_15_00","DIA_Homer_Running_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę ją znaleźć?","en":"Where can I find the beast?","de":"Wo finde ich das Biest?"}},{"speaker":"npc","text":{"pl":"Rozejrzyj się po drugiej stronie jeziora. Nikt tam nigdy nie zagląda. Założę się, że tam ma swoje leże!","en":"I''d hunt round on the other side of the lake. Nobody ever goes there. That''s probably where its den is.","de":"Ich würde auf der anderen Seite des Sees suchen. Keiner von den Leuten hier geht da hin. Wahrscheinlich hat es da seine Höhle."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_935_homer_dia_homer_success_15_00_0', 'BAU_935_Homer', '{"id":"missions_dia_bau_935_homer_dia_homer_success_15_00_0","npcId":"BAU_935_Homer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_935_Homer.d","sourceFunction":"DIA_Homer_Success_Info","outputIds":["DIA_Homer_Success_15_00","DIA_Homer_Success_02_01","DIA_Homer_Success_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Zabiłem bestię!","en":"I''ve killed the beast!","de":"Ich hab'' das Biest erledigt!"}},{"speaker":"npc","text":{"pl":"Świetnie! Ściągnąłem tu kilku ludzi Ryżowego Księcia, którzy pomogli mi naprawić uszkodzenia.","en":"Great! I got some of the Rice Lord''s men to help me fix some of the damage it''s caused.","de":"Gut! Ich habe schon zusammen mit einigen von Reislords Leuten die Schäden behoben, die es bisher angerichtet hat."}},{"speaker":"npc","text":{"pl":"Nareszcie mogę się porządnie wyspać.","en":"Now I can finally get some sleep.","de":"Jetzt kann ich mich endlich mal wieder in Ruhe schlafen legen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_bau_935_homer_dia_homer_wanna_help_15_00_0', 'BAU_935_Homer', '{"id":"missions_dia_bau_935_homer_dia_homer_wanna_help_15_00_0","npcId":"BAU_935_Homer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_BAU_935_Homer.d","sourceFunction":"DIA_Homer_WannaHelp_Info","outputIds":["DIA_Homer_WannaHelp_15_00","DIA_Homer_WannaHelp_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Może mogę ci jakoś pomóc?","en":"Is there anything I can do to help?","de":"Kann ich dir helfen?"}},{"speaker":"npc","text":{"pl":"Jasne. Spraw, żeby ta bestia przestała podżerać moją tamę.","en":"Sure, stop that beast from gnawing at my dam.","de":"Klar, halt das Vieh davon ab, weiter an meinem Damm rumzunagen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_ebr_100_gomez_wait4_sc_11_05_4', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_ebr_100_gomez_wait4_sc_11_05_4","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_EBR_100_Gomez_Wait4SC_Info","outputIds":["DIA_EBR_100_Gomez_Wait4SC_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Osobiście dopilnuję, żebyś już nigdy nie wszedł mi w drogę.","en":"I will personally take care that you never get in my way again.","de":"Ich werde persönlich sicherstellen, dass du mir nie wieder in die Suppe spucken wirst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_dabei_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_dabei_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Dabei_Info","outputIds":["DIA_Gomez_Dabei_15_00","DIA_Gomez_Dabei_11_01","DIA_Gomez_Dabei_11_02"],"lines":[{"speaker":"hero","text":{"pl":"To znaczy, że jestem jednym z was?","en":"Does that mean I''m in?","de":"Heißt das, ich bin dabei?"}},{"speaker":"npc","text":{"pl":"Właśnie tak. Witaj w drużynie, chłopcze.","en":"You bet it does. You''re one of us now, kid.","de":"Genau das heißt es. Du bist jetzt einer von uns, Kleiner."}},{"speaker":"npc","text":{"pl":"Kruk wprowadzi cię w szczegóły.","en":"Raven''ll fill you in on everything.","de":"Alles Weitere wird dir Raven erzählen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_fault_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_fault_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Fault_Info","outputIds":["DIA_Gomez_Fault_15_00","DIA_Gomez_Fault_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Przychodzę zaoferować swoje usługi.","en":"I came to offer my services.","de":"Ich bin gekommen, um dir meine Dienste anzubieten."}},{"speaker":"npc","text":{"pl":"Śmiesz tak po prostu tutaj wmaszerować i zawracać mi głowę? Ty gnido! STRAŻ!","en":"You just come marching in here and expect me to concern myself with you, you worm? GUARDS!","de":"Du platzt hier einfach rein und erwartest, dass ich mich mit dir befasse, du Wurm? WACHE!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Info","outputIds":["DIA_Gomez_Hello_15_00","DIA_Gomez_Hello_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Przychodzę zaoferować swoje usługi.","en":"I have come to offer my services.","de":"Ich bin gekommen, um dir meine Dienste anzubieten."}},{"speaker":"npc","text":{"pl":"A dlaczego myślisz, że potrzebuję twoich usług?","en":"What makes you think we''re interested in your services?","de":"Warum denkst du, dass wir an deinen Diensten interessiert sind?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte","outputIds":["DIA_Gomez_Hello_Kontakte_15_00","DIA_Gomez_Hello_Kontakte_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Przemierzyłem sporą część kolonii i mam kontakty we wszystkich obozach.","en":"I''ve been traveling around the colony a lot and I have contacts in all the camps.","de":"Ich bin viel in der Kolonie rumgekommen und habe gute Kontakte in allen Lagern."}},{"speaker":"npc","text":{"pl":"No! To się może przydać. Z kim konkretnie utrzymujesz kontakty?","en":"Now that could prove useful. Who are you in contact with?","de":"Das ist tatsächlich ein guter Grund. Zu wem hast du Kontakte?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_baals_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_baals_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_Baals","outputIds":["DIA_Gomez_Hello_Kontakte_Baals_15_00","DIA_Gomez_Hello_Kontakte_Baals_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Z kilkoma Baalami w obozie Bractwa.","en":"A few of the Baals in the Brotherhood''s camp.","de":"Zu einigen Baals aus dem Lager der Bruderschaft."}},{"speaker":"npc","text":{"pl":"I?","en":"And?","de":"Und?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_kalom_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_kalom_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_Kalom","outputIds":["DIA_Gomez_Hello_Kontakte_Kalom_15_00","DIA_Gomez_Hello_Kontakte_Kalom_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Z Cor Kalomem","en":"Cor Kalom.","de":"Zu Cor Kalom."}},{"speaker":"npc","text":{"pl":"I?","en":"And?","de":"Und?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_lares_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_lares_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_Lares","outputIds":["DIA_Gomez_Hello_Kontakte_Lares_15_00","DIA_Gomez_Hello_Kontakte_Lares_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Z Laresem.","en":"Lares.","de":"Zu Lares."}},{"speaker":"npc","text":{"pl":"I?","en":"And?","de":"Und?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_lee_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_lee_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_Lee","outputIds":["DIA_Gomez_Hello_Kontakte_Lee_15_00","DIA_Gomez_Hello_Kontakte_Lee_11_01","DIA_Gomez_Hello_Kontakte_Lee_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Zu Lee.","en":"Zu Lee.","de":"Zu Lee."}},{"speaker":"npc","text":{"pl":"Lee ist also ein guter Freund von dir, ja?","en":"Lee ist also ein guter Freund von dir, ja?","de":"Lee ist also ein guter Freund von dir, ja?"}},{"speaker":"npc","text":{"pl":"Dann sieht die Sache natürlich ANDERS AUS (zornig am ENDE)","en":"Dann sieht die Sache natürlich ANDERS AUS (zornig am ENDE)","de":"Dann sieht die Sache natürlich ANDERS AUS (zornig am ENDE)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_nlhehler_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_nlhehler_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_NLHehler","outputIds":["DIA_Gomez_Hello_Kontakte_NLHehler_15_00","DIA_Gomez_Hello_Kontakte_NLHehler_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Z kilkoma łobuzami z Nowego Obozu.","en":"A couple of the fences in the New Camp.","de":"Zu einigen Hehlern im Neuen Lager."}},{"speaker":"npc","text":{"pl":"I?","en":"And?","de":"Und?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_thats_all_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_thats_all_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_ThatsAll","outputIds":["DIA_Gomez_Hello_Kontakte_ThatsAll_15_00","DIA_Gomez_Hello_Kontakte_ThatsAll_11_01","DIA_Gomez_Hello_Kontakte_ThatsAll_11_02","DIA_Gomez_Hello_Kontakte_ThatsAll_INSUFF_11_00"],"lines":[{"speaker":"hero","text":{"pl":"To już wszyscy, z tych ważniejszych.","en":"Those were the important ones.","de":"Das waren alle wichtigen."}},{"speaker":"npc","text":{"pl":"Nieźle - jak na żółtodzioba.","en":"Not bad - for a beginner...","de":"Beachtlich - für einen Neuling wie dich ..."}},{"speaker":"npc","text":{"pl":"Dostaniesz swoją szansę.","en":"You shall have your chance.","de":"Du sollst deine Chance kriegen."}},{"speaker":"npc","text":{"pl":"I co? Mam być pod wrażeniem?! Znam Kopaczy, którzy mają lepsze kontakty od ciebie!","en":"You expect THAT to impress me? We have DIGGERS with better connections!","de":"DAMIT willst du mich beeindrucken? Im Lager gibt es BUDDLER, die bessere Beziehungen haben!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_yberion_11_04_4', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_yberion_11_04_4","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_YBerion","outputIds":["DIA_Gomez_Hello_Kontakte_YBerion_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Nie lubię, kiedy ktoś sprawia mi przykrość.","en":"I hate being disappointed.","de":"Ich hasse es, enttäuscht zu werden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_yberion_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kontakte_yberion_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Kontakte_YBerion","outputIds":["DIA_Gomez_Hello_Kontakte_YBerion_15_00","DIA_Gomez_Hello_Kontakte_YBerion_11_01","DIA_Gomez_Hello_Kontakte_YBerion_11_02","DIA_Gomez_Hello_Kontakte_YBerion_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Z Y''Berionem.","en":"Y''Berion.","de":"Zu Y''Berion."}},{"speaker":"npc","text":{"pl":"Y''Berion nie traci czasu na rozmowy z ludźmi twojego pokroju.","en":"Y''Berion doesn''t waste his time on guys like you.","de":"Y''Berion gibt sich nicht mit Burschen wie dir ab."}},{"speaker":"npc","text":{"pl":"Z twoich kłamstw wnoszę, że masz mnie za idiotę!","en":"Your lies tell me you think I am an idiot.","de":"Dass du lügst, zeigt mir, dass du mich für dumm hältst."}},{"speaker":"npc","text":{"pl":"Przykro mi, że masz mnie za takiego głupca.","en":"I''m disappointed to see you think I''m STUPID.","de":"Dass du mich für DUMM hältst, enttäuscht mich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_kopf_ab_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_kopf_ab_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_KopfAb","outputIds":["DIA_Gomez_Hello_KopfAb_15_00","DIA_Gomez_Hello_KopfAb_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Mam nadzieję, że nie będę musiał odrąbać ci głowy, żeby udowodnić, że potrafię posługiwać się bronią.","en":"I hope I''m not going to have to chop your head off to prove that I can handle a weapon.","de":"Ich hoffe ich muss dir nicht erst den Kopf abhacken, um dir zu beweisen, dass ich mit einer Waffe umgehen kann"}},{"speaker":"npc","text":{"pl":"Pomiędzy odwagą a głupotą jest tylko cienka linia...","en":"Thers''s a fine line between bravery and stupidity.","de":"Mut und Dummheit liegen dicht beieinander ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_spinner_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_spinner_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_Spinner","outputIds":["DIA_Gomez_Hello_Spinner_15_00","DIA_Gomez_Hello_Spinner_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Bo większość z twoich ludzi to leniwe bałwany czyhające na jakiegoś żółtodzioba, który odwali za nich czarną robotę.","en":"There''s only blockheads around here, on the lookout for newcomers to pass their jobs onto instead of doing them themselves.","de":"Weil hier nur Schwachköpfe rumrennen, die ihre Aufgaben lieber an Neulinge weitergeben, statt sie selber zu erledigen."}},{"speaker":"npc","text":{"pl":"Tak jest, poza pewnymi chlubnymi wyjątkami. Ale to jeszcze nie powód, żeby zatrudnić kolejnego leniwego bałwana.","en":"That may be true, with few exceptions. Still, it''s no reason to hire another blockhead.","de":"Das ist zwar bis auf wenige Ausnahmen richtig, aber kein Grund einen weiteren Schwachkopf anzuheuern."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_hello_thorus_says_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_hello_thorus_says_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_Hello_ThorusSays","outputIds":["DIA_Gomez_Hello_ThorusSays_15_00","DIA_Gomez_Hello_ThorusSays_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Przeszedłem test zaufania, a Thorus twierdzi, że się nadaję.","en":"I have stood the test of faith and Thorus says I''m worth it.","de":"Ich habe die Prüfung des Vertrauens bestanden und Thorus sagt, ich bin ein guter Mann."}},{"speaker":"npc","text":{"pl":"Gdyby tak nie było, nie dostałbyś się tutaj żywy. Mam nadzieję, że stać cię jeszcze na więcej.","en":"You wouldn''t have gotten in here alive if that weren''t so. I hope that''s not the best you can do.","de":"Du wärst hier nicht lebend reingekommen, wenn das nicht so wäre. Ich hoffe, das war nicht schon alles."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_100_gomez_dia_gomez_nur_so_15_00_0', 'EBR_100_Gomez', '{"id":"missions_dia_ebr_100_gomez_dia_gomez_nur_so_15_00_0","npcId":"EBR_100_Gomez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_100_Gomez.d","sourceFunction":"DIA_Gomez_NurSo_Info","outputIds":["DIA_Gomez_NurSo_15_00","DIA_Gomez_NurSo_11_00"],"lines":[{"speaker":"hero","text":{"pl":"Pomyślałem, że zdam ci raport...","en":"I just thought I''d report in.","de":"Ich wollte mal einen Zwischenbericht abgeben."}},{"speaker":"npc","text":{"pl":"Idź porozmawiać z Krukiem. I nigdy więcej nie odzywaj się do mnie bez pozwolenia!","en":"Then go and see Raven. And never speak to me again unless you''re told to!","de":"Dann geh zu Raven. Und sprich mich nie wieder an, ohne dass du dazu aufgefordert worden bist!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_101_scar_dia_scar_frau_08_04_4', 'EBR_101_Scar', '{"id":"missions_dia_ebr_101_scar_dia_scar_frau_08_04_4","npcId":"EBR_101_Scar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_101_Scar.d","sourceFunction":"DIA_SCAR_Frau_Info","outputIds":["DIA_SCAR_Frau_08_04","DIA_SCAR_Frau_08_05"],"lines":[{"speaker":"npc","text":{"pl":"Dopiero co ją dostarczono i Gomez kazał ją zamknąć w swojej komnacie.","en":"She''s only just got here and Gomez has her locked in his room.","de":"Sie ist gerade angekommen und Gomez hat sie bei sich auf dem Zimmer eingesperrt."}},{"speaker":"npc","text":{"pl":"Jak już mu się znudzi, może przyśle ją tu, na dół. Ale póki co, ona należy DO NIEGO, więc lepiej nie zawracaj sobie nią głowy.","en":"When he''s done with her, he might just send her down. But for now, she''s HIS - so you''d better take your mind off her.","de":"Wenn er sie ''ne Zeit lang gehabt hat, schickt er sie vielleicht runter. Aber jetzt gehört sie IHM - also verschwende besser keinen Gedanken an sie."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_101_scar_dia_scar_frau_15_00_0', 'EBR_101_Scar', '{"id":"missions_dia_ebr_101_scar_dia_scar_frau_15_00_0","npcId":"EBR_101_Scar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_101_Scar.d","sourceFunction":"DIA_SCAR_Frau_Info","outputIds":["DIA_SCAR_Frau_15_00","DIA_SCAR_Frau_08_01","DIA_SCAR_Frau_15_02","DIA_SCAR_Frau_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Kiedy mnie tu zrzucano, widziałem kobietę opuszczaną na dół wraz z ładunkiem.","en":"When they threw me in here, I saw a woman being brought down with the goods.","de":"Als sie mich reingeworfen haben, habe ich gesehen, wie eine Frau zusammen mit den Waren heruntergefahren wurde."}},{"speaker":"npc","text":{"pl":"I co z tego?","en":"So what?","de":"Und?"}},{"speaker":"hero","text":{"pl":"Jest tutaj?","en":"Is she here?","de":"Ist sie hier?"}},{"speaker":"npc","text":{"pl":"Słuchaj, jeśli wiążesz z nią jakieś nadzieje, dam ci dobrą radę: Zapomnij o niej.","en":"Look, in case you''re interested in her, let me give you some advice: Forget her.","de":"Wenn du dich für sie interessierst, geb'' ich dir einen guten Rat: Vergiss sie."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_101_scar_dia_scar_perm_15_00_0', 'EBR_101_Scar', '{"id":"missions_dia_ebr_101_scar_dia_scar_perm_15_00_0","npcId":"EBR_101_Scar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_101_Scar.d","sourceFunction":"DIA_SCAR_PERM_Info","outputIds":["DIA_SCAR_PERM_15_00","DIA_SCAR_PERM_08_01","DIA_SCAR_PERM_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Co możesz mi powiedzieć o Gomezie?","en":"Is there anything you can tell me about Gomez?","de":"Kannst du mir etwas über Gomez erzählen?"}},{"speaker":"npc","text":{"pl":"To najpotężniejszy człowiek w całej kolonii. To ci powinno wystarczyć.","en":"All you need to know is that he''s the most powerful man in the colony.","de":"Über ihn musst du nur wissen, dass er der mächtigste Mann der Kolonie ist."}},{"speaker":"npc","text":{"pl":"Dostaje wszystko, czego zapragnie, choć tak naprawdę zależy mu tylko na władzy.","en":"He gets what he wants, but all he really wants is power.","de":"Er kann alles haben, was er will, aber das einzige, was ihn WIRKLICH interessiert, ist Einfluss."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_101_scar_dia_scar_what_15_00_0', 'EBR_101_Scar', '{"id":"missions_dia_ebr_101_scar_dia_scar_what_15_00_0","npcId":"EBR_101_Scar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_101_Scar.d","sourceFunction":"DIA_SCAR_What_Info","outputIds":["DIA_SCAR_What_15_00","DIA_SCAR_What_08_01","DIA_SCAR_What_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Czym się zajmujesz?","en":"What''s your job?","de":"Was ist deine Aufgabe hier?"}},{"speaker":"npc","text":{"pl":"Ja i Arto zapewniamy Gomezowi spokój przed nieproszonymi gośćmi.","en":"Me and Arto make sure nobody gets to see Gomez unless they''re invited.","de":"Ich und Arto passen auf, dass Gomez niemand zu nahe kommt, der hier nicht eingeladen wurde,"}},{"speaker":"npc","text":{"pl":"Oprócz tego, do moich obowiązków należy poskramianie co zadziorniejszych kobiet.","en":"And I make sure the women don''t get restless.","de":"Außerdem kümmere ich mich darum, dass die Frauen hier nicht zu kurz kommen ."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_102_arto_dia_arto_perm_15_00_0', 'EBR_102_Arto', '{"id":"missions_dia_ebr_102_arto_dia_arto_perm_15_00_0","npcId":"EBR_102_Arto","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_102_Arto.d","sourceFunction":"DIA_ARTO_PERM_Info","outputIds":["DIA_ARTO_PERM_15_00","DIA_ARTO_PERM_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie lubisz dużo gadać, co?","en":"You don''t talk much, do you?","de":"Du redest nicht viel, was?"}},{"speaker":"npc","text":{"pl":"Nie.","en":"Nope.","de":"Nein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_102_arto_dia_arto_what_15_00_0', 'EBR_102_Arto', '{"id":"missions_dia_ebr_102_arto_dia_arto_what_15_00_0","npcId":"EBR_102_Arto","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_102_Arto.d","sourceFunction":"DIA_ARTO_What_Info","outputIds":["DIA_ARTO_What_15_00","DIA_ARTO_What_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Czym się tutaj zajmujesz?","en":"What do you do around here?","de":"Was machst du so?"}},{"speaker":"npc","text":{"pl":"Jestem strażnikiem Gomeza.","en":"I''m Gomez'' bodyguard.","de":"Ich bin Gomez'' Leibwächter."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_aufnahme_15_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_aufnahme_15_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_Aufnahme_Info","outputIds":["DIA_Raven_Aufnahme_15_00","DIA_Raven_Aufnahme_10_01","DIA_Raven_Aufnahme_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Chcę się zobaczyć z Gomezem. Thorus powiedział, że mogę zostać Cieniem.","en":"I want to see Gomez. Thorus says I''m to be taken on as a Shadow.","de":"Ich will zu Gomez. Thorus sagt, ich soll als Schatten aufgenommen werden."}},{"speaker":"npc","text":{"pl":"Dobrych ludzi nigdy nie za wielu. Chyba masz wystarczająco równo pod sufitem. Możesz się nam przydać.","en":"We''re always on the lookout for good men. You seem to have your wits about you. You might be okay.","de":"Wir sind immer auf der Suche nach guten Leuten. Du scheinst mir nicht auf den Kopf gefallen zu sein. Du könntest es hier zu was bringen."}},{"speaker":"npc","text":{"pl":"Zabiorę cię do Gomeza. Chodź za mną, tylko niczego nie dotykaj!","en":"I''ll take you to Gomez. Follow me. And don''t touch anything!","de":"Ich werde dich zu Gomez führen. Folge mir. Und fass nichts an!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_bin_dabei_15_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_bin_dabei_15_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_BinDabei_Info","outputIds":["DIA_Raven_BinDabei_15_00","DIA_Raven_BinDabei_10_01","DIA_Raven_BinDabei_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Gomez powiedział, że się nadaję.","en":"Gomez says I''m in.","de":"Gomez sagt, ich bin dabei."}},{"speaker":"npc","text":{"pl":"Świetnie! Tak się składa, że możesz od razu udowodnić, na co cię stać. Jest dla ciebie robota.","en":"Great! In that case, you can prove your worth with a first task.","de":"Gut! Du kannst dich gleich bei deinem ersten Auftrag bewähren."}},{"speaker":"npc","text":{"pl":"To nie powinno być zbyt trudne, jeśli rzeczywiście masz kontakty, o jakich mówiłeś.","en":"It shouldn''t be too difficult for you, provided your connections are as good as you say.","de":"Wenn deine Verbindungen wirklich so gut sind, wie du sagst, solltest du keine Probleme damit haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_equipment_15_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_equipment_15_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_Equipment_Info","outputIds":["DIA_Raven_Equipment_15_00","DIA_Raven_Equipment_10_01","DIA_Raven_Equipment_10_02","DIA_Raven_Equipment_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę dostać lepsze wyposażenie?","en":"Where can I get better equipment?","de":"Wo bekomme ich bessere Ausrüstung her?"}},{"speaker":"npc","text":{"pl":"Porozmawiaj z Diego, on da ci jakąś zbroję. Ten pancerz nie tylko uchroni cię przed śmiercią, ale będzie również służył jako znak rozpoznawczy.","en":"Go and see Diego, he''ll give you some armor. It''ll stop you from getting killed and it''ll serve as an ID at the same time.","de":"Geh zu Diego, er wird dir ''ne Rüstung geben. Damit wirst du nicht so schnell umgebracht und sie dient auch gleichzeitig als Ausweis."}},{"speaker":"npc","text":{"pl":"Dzięki niemu zyskasz dostęp do wszystkich ważniejszych miejsc.","en":"Your armor should give you access to all the places you need to go.","de":"Mit deiner neuen Rüstung solltest du hier überall hinkommen, wo du hin musst."}},{"speaker":"npc","text":{"pl":"Gdybyś potrzebował broni, porozmawiaj ze Skipem. Znajdziesz go w tej wielkiej szopie, w lewym tylnym rogu zamkowego dziedzińca.","en":"If you need any weapons, go and talk to Skip. You''ll find him in the big shed right at the back, left of the castle courtyard.","de":"Und wenn du Waffen brauchst, geh zu Skip, er ist in der großen Scheune hinten links auf den Burgplatz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_first_in_10_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_first_in_10_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_FirstIn_Info","outputIds":["DIA_Raven_FirstIn_10_00"],"lines":[{"speaker":"npc","text":{"pl":"Co mogę dla ciebie zrobić?","en":"What can I do for you?","de":"Was kann ich für dich tun?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_krautbote_15_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_krautbote_15_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_Krautbote_Info","outputIds":["DIA_Raven_Krautbote_15_00","DIA_Raven_Krautbote_10_01","DIA_Raven_Krautbote_10_02","DIA_Raven_Krautbote_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam trochę bagiennego ziela dla Gomeza od Cor Kaloma.","en":"I have some weed for Gomez from Cor Kalom.","de":"Ich habe eine Ladung Kraut für Gomez von Cor Kalom."}},{"speaker":"npc","text":{"pl":"Gomez nie zajmuje się takimi rzeczami osobiście. To działka Bartholo.","en":"Bartholo deals with that kind of thing. Gomez isn''t bothered with gofers.","de":"Bartholo kümmert sich um diese Sachen, Gomez selbst gibt sich nicht mit Boten ab."}},{"speaker":"npc","text":{"pl":"Znajdziesz go w komnacie na prawo od wejścia, albo w kuchni w dużej wieży.","en":"You''ll find him in the room on the right, behind the entrance, or in the kitchen in the big tower.","de":"Du findest ihn in der Kammer hier rechts hinter dem Eingang oder in der Küche im großen Turm."}},{"speaker":"npc","text":{"pl":"Oczywiście w nocy pewnie śpi. Na twoim miejscu nie przeszkadzałbym mu do rana.","en":"Course he sleeps at night. I wouldn''t disturb him then, if I were you.","de":"Nachts schläft er natürlich. Da würd'' ich es nicht wagen, ihn zu stören."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_perm_15_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_perm_15_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_PERM_Info","outputIds":["DIA_Raven_PERM_15_00","DIA_Raven_PERM_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Jak idzie handel rudą?","en":"How''s the ore trade going?","de":"Wie steht der Erzhandel?"}},{"speaker":"npc","text":{"pl":"Stara Kopalnia jakoś radzi sobie z wydobyciem. Ostatni transport do zewnętrznego świata był bardzo duży.","en":"The Old Mine''s doing well. The last load of supplies from the outside world was massive.","de":"Die Alte Mine spuckt genug aus. Die letzte Lieferung aus der Außenwelt war ziemlich fett."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_spy_bericht_10_06_8', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_spy_bericht_10_06_8","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_SpyBericht_Info","outputIds":["DIA_Raven_SpyBericht_10_06"],"lines":[{"speaker":"npc","text":{"pl":"To dlaczego zawracasz mi głowę?","en":"Then why are you bothering me?","de":"Was belästigst du mich dann?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_spy_bericht_15_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_spy_bericht_15_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_SpyBericht_Info","outputIds":["DIA_Raven_SpyBericht_15_00","DIA_Raven_SpyBericht_10_01","Org_826_Mordrag_RUNNING_15_04","DIA_Raven_SpyBericht_10_04"],"lines":[{"speaker":"hero","text":{"pl":"Pomyślałem, że zdam ci raport...","en":"I just thought I''d report in.","de":"Ich will einen Zwischenbericht abgeben."}},{"speaker":"npc","text":{"pl":"To dobrze. Lubię być informowany na bieżąco.","en":"Good. I like being kept up to date.","de":"Gut. Ich bin gerne gut informiert."}},{"speaker":"hero","text":{"pl":"Odbyło się wielkie przywołanie.","en":"The great invocation has taken place.","de":"Die große Beschwörung hat stattgefunden."}},{"speaker":"npc","text":{"pl":"Dobrze się spisałeś.","en":"You have done well.","de":"Du hast deine Sache gut gemacht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_spy_bericht_15_02_4', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_spy_bericht_15_02_4","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_SpyBericht_Info","outputIds":["DIA_Raven_SpyBericht_15_02","DIA_Raven_SpyBericht_10_03","DIA_Raven_SpyBericht_10_04","DIA_Raven_SpyBericht_15_05"],"lines":[{"speaker":"hero","text":{"pl":"Teraz Bractwo potrzebuje jaj królowej pełzaczy. Przygotują z nich napój, który umożliwi im nawiązanie kontaktu ze Śniącym. Mam te jaja przy sobie.","en":"They now want a minecrawler queen''s eggs, so they can brew a potion that will enable them to contact the Sleeper. I have the eggs with me.","de":"Sie wollen die Eier einer Minecrawler-Königin, um daraus ein Elixier herzustellen, durch das sie Kontakt zum Schläfer aufnehmen können. Ich habe die Eier bei mir."}},{"speaker":"npc","text":{"pl":"Hmm, interesujące. Ciekawe czy to zadziała. Zanieś jaja do świątyni.","en":"Very interesting. I wonder if it will work. Bring the eggs to the temple.","de":"Interessant. Bin gespannt, ob die Sache funktioniert. Bring die Eier in den Tempel."}},{"speaker":"npc","text":{"pl":"Dobrze się spisałeś.","en":"You have done well.","de":"Du hast deine Sache gut gemacht."}},{"speaker":"hero","text":{"pl":"Niestety, jeszcze nie wiem, co planują ludzie z Bractwa.","en":"I don''t really know what they''re planning yet.","de":"Ich weiß noch nicht GENAU was sie vorhaben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_spy_sect_10_04_4', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_spy_sect_10_04_4","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_SpySect_Info","outputIds":["DIA_Raven_SpySect_10_04","DIA_Raven_SpySect_15_05","DIA_Raven_SpySect_10_06"],"lines":[{"speaker":"npc","text":{"pl":"Im więcej wywęszysz, tym lepiej. Ta misja wymaga odrobiny taktu, jeśli wiesz, co mam na myśli.","en":"The more you find out, the better. It''ll take a bit of tact, if you know what I mean.","de":"Und je mehr du erfährst, desto besser. Das Ganze erfordert ein gewisses Feingefühl. Du weißt, was ich meine?"}},{"speaker":"hero","text":{"pl":"Bez obaw. Postaram się ich nie rozzłościć.","en":"Keep cool, I''m not going to get them angry.","de":"Bleib ruhig, ich werde ihren Zorn nicht heraufbeschwören."}},{"speaker":"npc","text":{"pl":"Wiedziałem, że się zrozumiemy.","en":"I knew you''d understand.","de":"Ich wusste, dass du mich verstehen würdest."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_spy_sect_15_00_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_spy_sect_15_00_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_SpySect_Info","outputIds":["DIA_Raven_SpySect_15_00","DIA_Raven_SpySect_10_01","DIA_Raven_SpySect_10_02","DIA_Raven_SpySect_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Co mam zrobić?","en":"What d''you want me to do?","de":"Was soll ich für dich erledigen?"}},{"speaker":"npc","text":{"pl":"Prowadzimy intensywną wymianę handlową z Bractwem, co nie znaczy, że im do końca ufamy.","en":"We do a lot of trade with the Brotherhood. That doesn''t mean to say we trust ''em.","de":"Wir stehen mit der Bruderschaft in Handelskontakt. Das bedeutet nicht, das wir ihnen unbedingt vertrauen."}},{"speaker":"npc","text":{"pl":"Idź na bagna.","en":"Go to the swamp.","de":"Mach dich auf den Weg in den Sumpf."}},{"speaker":"npc","text":{"pl":"Kiedy dotrzesz do Obozu Bractwa, miej uszy i oczy szeroko otwarte. Każdy strzępek informacji może się okazać niezwykle cenny.","en":"When you get to the Camp, keep your ears open. Anything you pick up might be useful for us.","de":"Wenn du dort im Lager bist, halte die Ohren auf. Alles was du erfährst, kann für uns nützlich sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_105_raven_dia_raven_there_10_01_0', 'EBR_105_Raven', '{"id":"missions_dia_ebr_105_raven_dia_raven_there_10_01_0","npcId":"EBR_105_Raven","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_105_Raven.d","sourceFunction":"DIA_Raven_There_Info","outputIds":["DIA_Raven_There_10_01"],"lines":[{"speaker":"npc","text":{"pl":"Gomez jest tam. Jeśli nie okażesz mu należnego szacunku, osobiście nauczę cię dobrych manier. Zrozumiano?","en":"Gomez is over there. If you don''t show him some respect, I''ll take pleasure in teaching it to you personally, have you got that?","de":"Dort hinten ist Gomez. Wenn du ihm keinen Respekt zeigst, werde ich dir persönlich welchen beibringen, ist das klar?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_106_bartholo_info_bartholo_12_01_0', 'EBR_106_Bartholo', '{"id":"missions_dia_ebr_106_bartholo_info_bartholo_12_01_0","npcId":"EBR_106_Bartholo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_106_Bartholo.d","sourceFunction":"DIA_EBR_106_Bartholo_Wait4SC_Info","outputIds":["Info_Bartholo_12_01","Info_Bartholo_12_02","Info_Bartholo_15_03","Info_Bartholo_12_04"],"lines":[{"speaker":"npc","text":{"pl":"Podejrzewałem, że prędzej czy później ktoś spróbuje użyć pentagramu.","en":"I knew that somebody would try to get at us through the pentagram!","de":"Ich hatte mir fast gedacht, dass es jemand durch das Pentagramm versuchen würde!"}},{"speaker":"npc","text":{"pl":"Ale w odróżnieniu od tego zdradzieckiego kowala, Stone''a, CIEBIE już nie potrzebujemy!","en":"But, unlike that traitorous smith Stone, we don''t need you any more!","de":"Aber im Gegensatz zu diesem verräterischen Schmied Stone brauchen wir dich nicht mehr!"}},{"speaker":"hero","text":{"pl":"Gdzie jest Stone?","en":"Where is Stone?","de":"Wo ist Stone?"}},{"speaker":"npc","text":{"pl":"Za kratkami! Ale ciebie czeka miły, przytulny GRÓB!","en":"Behind bars! But you''re gonna be six feet under in a minute!","de":"Hinter Gittern! Aber dafür wirst du gleich unter der Erde liegen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_106_bartholo_info_bartholo_12_05_4', 'EBR_106_Bartholo', '{"id":"missions_dia_ebr_106_bartholo_info_bartholo_12_05_4","npcId":"EBR_106_Bartholo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_106_Bartholo.d","sourceFunction":"DIA_EBR_106_Bartholo_Wait4SC_Info","outputIds":["Info_Bartholo_12_05"],"lines":[{"speaker":"npc","text":{"pl":"Brać go, chłopcy! Posiekać go!","en":"Get him, guys, and slice him up!","de":"Schnappt ihn euch, Jungs, und macht ihn kalt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_106_bartholo_info_bartholo_hallo_12_04_4', 'EBR_106_Bartholo', '{"id":"missions_dia_ebr_106_bartholo_info_bartholo_hallo_12_04_4","npcId":"EBR_106_Bartholo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_106_Bartholo.d","sourceFunction":"Info_Bartholo_HAllo_Info","outputIds":["Info_Bartholo_HAllo_12_04"],"lines":[{"speaker":"npc","text":{"pl":"Te błazny powinny mi być wdzięczne. Gomez nie toleruje partactwa, nawet w kuchni. Poprzednich dwóch kucharzy skarmił topielcom w rzece.","en":"They should be grateful. Gomez won''t put up with any crap. He fed the last two cooks to the lurkers in the river.","de":"Sie sollten mir dafür dankbar sein. Gomez lässt sich nicht jeden Fraß gefallen. Die letzten beiden hat er an die Snapper im Fluss verfüttert."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_106_bartholo_info_bartholo_krautbote_15_00_0', 'EBR_106_Bartholo', '{"id":"missions_dia_ebr_106_bartholo_info_bartholo_krautbote_15_00_0","npcId":"EBR_106_Bartholo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_106_Bartholo.d","sourceFunction":"Info_Bartholo_Krautbote_Info","outputIds":["Info_Bartholo_Krautbote_15_00","Info_Bartholo_Krautbote_12_01","Info_Bartholo_Krautbote_12_02","Info_Bartholo_Krautbote_12_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam tu trochę ziela dla Gomeza. Przysyła je Cor Kalom.","en":"I have some weed here for Gomez. Cor Kalom sent it.","de":"Ich habe ''ne Ladung Kraut von Cor Kalom für Gomez."}},{"speaker":"npc","text":{"pl":"Pokaż!","en":"Show me!","de":"Zeig her!"}},{"speaker":"npc","text":{"pl":"Hmmmmmm...","en":"Hmmmmmmm...","de":"Hmmmmmmm ..."}},{"speaker":"npc","text":{"pl":"Świetnie! Gomez zaczął się już niecierpliwić. Masz szczęście, że przyniosłeś je jeszcze dzisiaj!","en":"Alright! Gomez has been getting impatient. It''s lucky for you that you delivered it today!","de":"Gut! Gomez ist beinahe ungeduldig geworden. Sei froh, dass du es heute noch abgeliefert hast!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_106_bartholo_info_bartholo_krautbote_15_04_4', 'EBR_106_Bartholo', '{"id":"missions_dia_ebr_106_bartholo_info_bartholo_krautbote_15_04_4","npcId":"EBR_106_Bartholo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_106_Bartholo.d","sourceFunction":"Info_Bartholo_Krautbote_Info","outputIds":["Info_Bartholo_Krautbote_15_04","Info_Bartholo_Krautbote_12_05","Info_Bartholo_Krautbote_NoKraut_12_00"],"lines":[{"speaker":"hero","text":{"pl":"A co z moją zapłatą?","en":"What about the pay?","de":"Was ist mit der Bezahlung?"}},{"speaker":"npc","text":{"pl":"Spokojnie... Masz tu 500 bryłek rudy. Taka była umowa.","en":"Not so fast... Here, take that. 500 ore is what we agreed on.","de":"Nicht so eilig ... Hier, nimm. 500 Erz waren abgemacht."}},{"speaker":"npc","text":{"pl":"Jak na posłańca masz przy sobie trochę za mało ziela! Mam nadzieję, że nie sprzedałeś go komuś innemu! Wróć, jak będziesz miał całą partię.","en":"You don''t have enough weed to be a gofer! I hope for your sake that you haven''t sold the stuff elsewhere! Come back when you have the right amount!","de":"Du hast zu wenig Kraut für einen Boten! Ich will für dich nicht hoffen, dass du das Zeug verscherbelt hast! Komm wieder, wenn du die richtige Menge dabei hast!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ebr_106_bartholo_info_bartholo_perm_15_00_0', 'EBR_106_Bartholo', '{"id":"missions_dia_ebr_106_bartholo_info_bartholo_perm_15_00_0","npcId":"EBR_106_Bartholo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_EBR_106_Bartholo.d","sourceFunction":"Info_Bartholo_PERM_Info","outputIds":["Info_Bartholo_PERM_15_00","Info_Bartholo_PERM_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Chcę dobić z tobą targu.","en":"I wanna make a deal with you.","de":"Ich will mit dir handeln."}},{"speaker":"npc","text":{"pl":"Mam sporo ciekawych rzeczy - jeśli masz wystarczająco dużo rudy.","en":"I have a lot to offer - if you have enough ore.","de":"Ich habe einiges da - wenn du genug Erz hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_aufnahme_info_09_05_4', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_aufnahme_info_09_05_4","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_AUFNAHME_Info","outputIds":["GRD_200_Thorus_AUFNAHME_Info_09_05","GRD_200_Thorus_AUFNAHME_Info_09_06","GRD_200_Thorus_AUFNAHME_Info_09_07","GRD_200_Thorus_AUFNAHME_Info_09_08"],"lines":[{"speaker":"npc","text":{"pl":"Dniem i nocą strzeżemy korytarzy kopalni. Dniem i nocą pilnujemy bram Obozu i pozwalamy jego mieszkańcom wieść spokojne życie.","en":"Day and night, we''re in the mine. Day and night, we stand at the gates of the Camp and make sure folks get to sleep peacefully.","de":"Wir stehen Tag und Nacht in der Mine. Wir stehen Tag und Nacht an den Toren des Lagers und passen auf, dass alle ruhig schlafen können."}},{"speaker":"npc","text":{"pl":"Na początku byliśmy tylko bezładną zgrają, ale staliśmy się siłą, z którą każdy musi się liczyć. Ciężko pracowaliśmy, by zasłużyć na tę reputację.","en":"We were a wild bunch when we started out here, but now we''re a force to be reckoned with. We''ve all worked hard to build up this life for ourselves.","de":"Als wir hier angefangen haben, da waren wir Freiwild, aber wir haben uns behauptet. Wir alle haben hart dafür gearbeitet, uns dieses Leben aufzubauen."}},{"speaker":"npc","text":{"pl":"Od moich ludzi oczekuję więc wyłącznie jednego: lojalności. Tylko stojąc ramię w ramię będziemy w stanie obronić to, co należy do nas...","en":"I only expect one thing from my boys: that they stick together. Only by standing together will we be able to hold on to what we have.","de":"Ich erwarte nur eins von meinen Jungs: dass sie zusammenhalten. Denn nur wenn wir zusammen stehen, dann werden wir das alles behalten können."}},{"speaker":"npc","text":{"pl":"...i przetrwać.","en":"And to survive.","de":"Dann überleben wir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_aufnahme_info_09_09_8', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_aufnahme_info_09_09_8","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_AUFNAHME_Info","outputIds":["GRD_200_Thorus_AUFNAHME_Info_09_09","GRD_200_Thorus_AUFNAHME_Info_09_10","GRD_200_Thorus_AUFNAHME_Info_09_11"],"lines":[{"speaker":"npc","text":{"pl":"Pozostałych rzeczy dowiesz się w swoim czasie. Bądź gotów do pomocy każdemu, kto jej potrzebuje, nieważne jak trudne i niebezpieczne to zadanie.","en":"You''ll learn everything else in due course. Be ready and help out wherever help is needed or something needs to be done.","de":"Alles andere wirst du schon mit der Zeit rauskriegen. Halte dich bereit und hilf da, wo gerade Not am Mann ist oder irgendwas zu erledigen ist."}},{"speaker":"npc","text":{"pl":"Idź do Stone''a i poproś go o zbroję i miecz.","en":"Go and ask Stone to give you some armor and a sword.","de":"Du kannst dir bei Stone deine Rüstung und dein Schwert holen."}},{"speaker":"npc","text":{"pl":"Znajdziesz go w kuźni, w Wewnętrznym Pierścieniu.","en":"You''ll find Stone in the blacksmith''s shop in the Inner Ring.","de":"Du findest Stone im inneren Ring, in der Schmiede."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_aufnahme_info_15_01_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_aufnahme_info_15_01_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_AUFNAHME_Info","outputIds":["GRD_200_Thorus_AUFNAHME_Info_15_01","GRD_200_Thorus_AUFNAHME_Info_09_02","GRD_200_Thorus_AUFNAHME_Info_09_03","GRD_200_Thorus_AUFNAHME_Info_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Chcę zostać Strażnikiem!","en":"I want to become a guard.","de":"Ich will Gardist werden."}},{"speaker":"npc","text":{"pl":"Miło mi to słyszeć, ale najpierw muszę ci powiedzieć to, co mówię wszystkim nowym rekrutom. Słuchaj uważnie, bo nie będę się powtarzał.","en":"I''m glad to hear it. But first I must tell you something that I tell all new recruits. Listen carefully, I shall say this only once.","de":"Das freut mich. Doch zunächst: Es gibt da ein paar Dinge, die ich jedem Neuen sage. Pass gut auf, denn ich sage sie nur einmal."}},{"speaker":"npc","text":{"pl":"Do tej pory żyłeś na własny rachunek, ale to się od dziś zmieni. Moi ludzie trzymają się razem. Do Strażników należy dbanie o bezpieczeństwo Magnatów, rudy, obozu i kopalni.","en":"So far, you''ve tried to get by on your own. Those days are over now. My boys stick together. We guards protect the Ore Barons, the ore, the camp and the mine.","de":"Bisher hast du versucht, auf eigene Faust zu überleben. Damit ist nun Schluss. Meine Jungs halten zusammen. Wir Gardisten beschützen die Erzbarone, das Erz, das Lager und die Mine."}},{"speaker":"npc","text":{"pl":"Ruda wydobywana jest przez Kopaczy, ale to my pilnujemy, żeby nie pożarły ich pełzacze. Pertraktacje z królem prowadzą Magnaci, ale to my dbamy o ich bezpieczeństwo.","en":"The diggers collect the ore, but we make sure that they don''t get eaten by crawlers. The Ore Barons negotiate with the King, but we''re the ones that protect them.","de":"Die Buddler schürfen das Erz, aber wir sorgen dafür, dass sie nicht von den Crawlern gefressen werden. Die Barone verhandeln mit dem König, aber wir decken ihren Arsch dabei."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_gardist_info_09_05_4', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_gardist_info_09_05_4","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_GARDIST_Info","outputIds":["GRD_200_Thorus_GARDIST_Info_09_05"],"lines":[{"speaker":"npc","text":{"pl":"Daję ci niepowtarzalną szansę. Co ty na to?","en":"I''m giving you a chance. What do you say?","de":"Ich gebe dir eine Chance. Wie sieht''s aus?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_gardist_info_15_01_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_gardist_info_15_01_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_GARDIST_Info","outputIds":["GRD_200_Thorus_GARDIST_Info_15_01","GRD_200_Thorus_GARDIST_Info_09_02","GRD_200_Thorus_GARDIST_Info_09_03","GRD_200_Thorus_GARDIST_Info_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Chciałeś mi coś powiedzieć?","en":"You have something to tell me?","de":"Du wolltest mir etwas mitteilen?"}},{"speaker":"npc","text":{"pl":"Tak. To, co pokazałeś w kopalni, świadczy nie tylko o twojej odwadze, ale również o niepospolitej sile i umiejętnościach.","en":"Yes. What you did in the mine not only shows some courage, but it also proves your strength and your fighting skills.","de":"Ja. Durch das, was du in der Mine getan hast, hast du nicht nur deine Tapferkeit, sondern auch deine Stärke und deine Fähigkeit im Kampf unter Beweis gestellt."}},{"speaker":"npc","text":{"pl":"Chętnie bym cię widział w szeregach straży.","en":"I''m ready to accept you into the ranks of the guards.","de":"Ich bin bereit, dich in die Reihen der Gardisten aufzunehmen."}},{"speaker":"npc","text":{"pl":"Ale zanim to nastąpi musisz jeszcze trochę popracować nad swoimi umiejętnościami. Tylko najlepsi mogą zostać strażnikami.","en":"But you''re not quite ready to become a guard yet. You need to gather a little more experience before I can take you on.","de":"Aber du bist noch nicht bereit, Gardist zu werden. Sammle erst noch mehr Erfahrung, dann werde ich dich aufnehmen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_nochwas_info_09_01_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_nochwas_info_09_01_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_NOCHWAS_Info","outputIds":["GRD_200_Thorus_NOCHWAS_Info_09_01","GRD_200_Thorus_NOCHWAS_Info_09_02"],"lines":[{"speaker":"npc","text":{"pl":"A, i jeszcze coś...","en":"Oh, one more thing...","de":"Ach, noch eine Sache ..."}},{"speaker":"npc","text":{"pl":"Witamy w Straży...","en":"Welcome to the Guards.","de":"Willkommen bei der Garde."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_wannabemage_info_15_01_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_wannabemage_info_15_01_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_WANNABEMAGE_Info","outputIds":["GRD_200_Thorus_WANNABEMAGE_Info_15_01","GRD_200_Thorus_WANNABEMAGE_Info_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Interesuje mnie ścieżka magii...","en":"I''m interested in the path of magic.","de":"Ich interessiere mich für den Weg der Magie."}},{"speaker":"npc","text":{"pl":"W takim razie powinieneś porozmawiać z Corristo. To on uczył Miltena. Chyba nie powinno być żadnych przeciwwskazań.","en":"Well, in that case maybe you should talk to Corristo. He taught Milten. I''m sure there''s nothing to stop you.","de":"Nun, dann solltest du vielleicht mit Corristo sprechen. Er hat auch Milten unterrichtet. Ich bin sicher, dem steht nichts im Wege."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_zweihand1_info_09_05_4', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_zweihand1_info_09_05_4","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_ZWEIHAND1_Info","outputIds":["GRD_200_Thorus_ZWEIHAND1_Info_09_05","GRD_200_Thorus_ZWEIHAND1_Info_09_06","GRD_200_Thorus_ZWEIHAND1_Info_09_07"],"lines":[{"speaker":"npc","text":{"pl":"Wykorzystaj bezwładność broni, by unieść ją ponownie do góry.","en":"Use the momentum of the weapon to bring it straight back up again.","de":"Nutze den Schwung, wenn die Waffe unten ist, um direkt wieder nach oben zu schlagen."}},{"speaker":"npc","text":{"pl":"Dwuręczne miecze świetnie sprawdzają się przy zadawaniu ciosów z boku. W ten sposób możesz trzymać przeciwnika na dystans.","en":"Two-handed swords are ideal for coordinating side hits to keep opponents at a distance.","de":"Seitliche Schläge lassen sich ausgezeichnet mit einem Zweihänder koordinieren. Damit hältst du dir die Gegner vom Hals."}},{"speaker":"npc","text":{"pl":"To ci powinno wystarczyć na początek. Teraz trochę poćwicz.","en":"That should do to begin with. Have a practice.","de":"Das sollte erst einmal reichen. Übe das."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_zweihand1_info_15_01_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_zweihand1_info_15_01_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_ZWEIHAND1_Info","outputIds":["GRD_200_Thorus_ZWEIHAND1_Info_15_01","GRD_200_Thorus_ZWEIHAND1_Info_09_02","GRD_200_Thorus_ZWEIHAND1_Info_09_03","GRD_200_Thorus_ZWEIHAND1_Info_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym nauczyć się posługiwać dwuręcznym mieczem.","en":"I want to learn how to handle a two-handed sword.","de":"Ich möchte den Umgang mit dem Zweihänder lernen."}},{"speaker":"npc","text":{"pl":"Dobrze, najpierw zajmiemy się podstawami.","en":"Okay, let''s go through the basics first.","de":"Nun, dann gehen wir zuerst die Grundbegriffe durch."}},{"speaker":"npc","text":{"pl":"Wyciągnij miecz przed siebie. Aby zaatakować wroga tak ciężką bronią, musisz mocniej się zamachnąć.","en":"Hold the sword in a horizontal position. You''ll need more swing to attack your opponent with such a heavy weapon.","de":"Halte das Schwert waagerecht. Um den Gegner mit einer großen Waffe anzugreifen, brauchst du viel Schwung."}},{"speaker":"npc","text":{"pl":"Unieś ramię i zdecydowanie opuść miecz. To powinno wystarczyć, żeby powalić przeciwnika na ziemię.","en":"Raise your arm and swing it straight down. That''s usually enough to knock the opponent down.","de":"Hole mit der Waffe aus und schlage am besten direkt von oben. Meistens reicht das aus, um Gegner zu Boden zu strecken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_zweihand2_info_09_05_4', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_zweihand2_info_09_05_4","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_ZWEIHAND2_Info","outputIds":["GRD_200_Thorus_ZWEIHAND2_Info_09_05","GRD_200_Thorus_ZWEIHAND2_Info_09_06","GRD_200_Thorus_ZWEIHAND2_Info_09_07","GRD_200_Thorus_ZWEIHAND2_Info_09_08"],"lines":[{"speaker":"npc","text":{"pl":"Albo spróbuj wyprowadzić z lewej strony cios do przodu, aby odrzucić od siebie rywala.","en":"Or bring the sword down from the top left in a forward thrust to drive your opponent back.","de":"Sonst schlage wieder nach vorne von links oben, um so den Gegner zurückzutreiben."}},{"speaker":"npc","text":{"pl":"Teraz obrót, żeby kolejny cios nabrał odpowiedniej mocy. Przy odrobinie szczęścia wróg nie przeżyje tego uderzenia.","en":"Spin around to give your next blow the necessary momentum to strike your opponent down.","de":"Eine schnelle Körperdrehung verleiht deinem nächsten Schlag die nötige Wucht, um den Gegner zu Boden zu zwingen."}},{"speaker":"npc","text":{"pl":"A jeśli i to nie wystarczy, wykorzystaj resztę siły zamachowej, by ponownie unieść miecz do góry.","en":"If it isn''t enough, use your remaining swing to wield the sword again.","de":"Falls das nicht ausreichen sollte, dann nutze den übrigen Schwung, um die Klinge noch einmal tanzen zu lassen."}},{"speaker":"npc","text":{"pl":"Po skończonym ataku wykonaj zasłonę i wypatruj luki w obronie przeciwnika.","en":"When you''ve finished your attack, block your opponent and wait for an opening to strike again.","de":"Geh nach deinem Angriff in den Block und suche eine Lücke, damit du erneut zuschlagen kannst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_zweihand2_info_09_09_8', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_zweihand2_info_09_09_8","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_ZWEIHAND2_Info","outputIds":["GRD_200_Thorus_ZWEIHAND2_Info_09_09"],"lines":[{"speaker":"npc","text":{"pl":"Kluczem do sukcesu jest ciągła zmiana pozycji i umiejętne wykorzystanie bezwładności broni.","en":"The key to success is varying your stances and changing positions.","de":"Abwechslung in den Kampfbewegungen und Positionswechsel sind der Schlüssel zum Sieg."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_grd_200_thorus_zweihand2_info_15_01_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_grd_200_thorus_zweihand2_info_15_01_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"GRD_200_Thorus_ZWEIHAND2_Info","outputIds":["GRD_200_Thorus_ZWEIHAND2_Info_15_01","GRD_200_Thorus_ZWEIHAND2_Info_09_02","GRD_200_Thorus_ZWEIHAND2_Info_09_03","GRD_200_Thorus_ZWEIHAND2_Info_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym dowiedzieć się czegoś więcej o walce dwuręcznym mieczem.","en":"I want to learn more about fighting with a two-handed sword.","de":"Ich möchte mehr über den zweihändigen Kampf lernen."}},{"speaker":"npc","text":{"pl":"Musisz się nauczyć płynnie przenosić środek ciężkości. Trzymaj miecz pionowo. Obie dłonie mocno zaciśnij na jego rękojeści i przesuń go nieco w bok.","en":"First of all, you need to change your basic stance. Hold the sword vertically, grasp the hilt firmly in both hands and hold it at the side of your body.","de":"Zunächst ändere deine Grundhaltung. Halte das Schwert aufrecht, fasse den Griff mit beiden Händen und halte es seitlich am Körper."}},{"speaker":"npc","text":{"pl":"Teraz uderz szybko od góry, i pozwól klindze powędrować nad twoje ramię. Teraz możesz wyprowadzić szybkie cięcie na prawo.","en":"Bring it down quickly and swing the blade over your shoulder. Now''s your chance to do a quick slash to your right.","de":"Schlage schnell von oben und lass die Klinge über deine Schulter gleiten. Nun hast du die Möglichkeit, einen schnellen Schlag nach rechts zu machen."}},{"speaker":"npc","text":{"pl":"Twój przeciwnik nie będzie miał okazji podejść bliżej.","en":"Your opponent won''t have time to come at you.","de":"Damit bietest du dem Gegner keine Chance, an dich ranzukommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_info_thorus_mordrag_ko_kill_him_15_00_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_info_thorus_mordrag_ko_kill_him_15_00_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"Info_Thorus_MordragKo_KillHim","outputIds":["Info_Thorus_MordragKo_KillHim_15_00","Info_Thorus_MordragKo_KillHim_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Chcesz, żebym go zabił, tak?","en":"D''you want me to kill the guy?","de":"Soll ich den Kerl umbringen?"}},{"speaker":"npc","text":{"pl":"Chcę mieć pewność, że już nigdy więcej się tu nie pojawi. Jak to osiągniesz - to już twoja sprawa.","en":"I want you to make sure I never see his face around here again. I don''t care how you do it.","de":"Du sollst dafür sorgen, dass ich ihn hier nie wieder sehen muss. Wie du das anstellst, ist deine Sache."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mage_problem_15_00_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mage_problem_15_00_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"Info_Thorus_MordragKo_MageProblem","outputIds":["Info_Thorus_MordragKo_MageProblem_15_00","Info_Thorus_MordragKo_MageProblem_09_01","Info_Thorus_MordragKo_MageProblem_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Widzę, że masz trochę problemów z Magami...","en":"Sounds to me like the mages are your problem...","de":"Klingt eher, als wären die Magier dein Problem ..."}},{"speaker":"npc","text":{"pl":"Tak. I to problemów, które nie łatwo rozwiązać. Kilka lat temu jeden z Cieni próbował zasztyletować we śnie Arcymistrza Magów Ognia.","en":"Yeah, but they''re a problem that''s hard to solve. A few years back one of the Shadows tried to stab the High Magician of the Circle of Fire while he was sleeping.","de":"Ja, aber eines, das sich schwer lösen lässt. Vor ein paar Jahren hat mal einer der Schatten versucht, den Obersten Magier des Feuers im Schlaf zu erdolchen."}},{"speaker":"npc","text":{"pl":"Faceta znaleziono potem w Zewnętrznym Pierścieniu. Jeśli chodzi o ścisłość - rozsmarowanego PO CAŁYM Zewnętrznym Pierścieniu.","en":"They found him later in the Outer Ring - in fact, he was scattered ALL OVER the Outer Ring.","de":"Er wurde später im Außenring gefunden - an VERSCHIEDENEN Stellen im Außenring."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mages_protect_09_04_4', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mages_protect_09_04_4","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"Info_Thorus_MordragKo_MagesProtect","outputIds":["Info_Thorus_MordragKo_MagesProtect_09_04"],"lines":[{"speaker":"npc","text":{"pl":"Jesteś tu nowy, nic ci nie będzie. Ale ja odpowiadam za wszystko, co robią moi ludzie. Dlatego musisz trzymać język za zębami.","en":"You''re new here. You''ll be okay. But I''m responsible for what my boys do. That''s why it''s vital that you keep your mouth shut.","de":"Du bist neu. Dir passiert gar nichts. ICH dagegen bin für das verantwortlich, was meine Jungs tun. Deswegen ist es ja so wichtig, dass du die Klappe hältst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mages_protect_15_00_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mages_protect_15_00_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"Info_Thorus_MordragKo_MagesProtect","outputIds":["Info_Thorus_MordragKo_MagesProtect_15_00","Info_Thorus_MordragKo_MagesProtect_09_01","Info_Thorus_MordragKo_MagesProtect_09_02","Info_Thorus_MordragKo_MagesProtect_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego Magowie bronią Mordraga?","en":"Why do the mages protect that Mordrag?","de":"Wieso beschützen die Magier diesen Mordrag?"}},{"speaker":"npc","text":{"pl":"Bo służy im za posłańca. Nasi magowie utrzymują kontakty z czarodziejami z Nowego Obozu. Często wymieniają informacje za pośrednictwem gońców.","en":"Because they use him as a gofer. Our local mages are in contact with the mages over in the New Camp. They often send gofers back and forth.","de":"Weil er als Bote für sie arbeitet. Unsere Magier stehen mit den Magiern des Neuen Lagers in Kontakt. Sie schicken regelmäßig Boten hin und her."}},{"speaker":"npc","text":{"pl":"Podejrzewam, że nieźle się wkurzą na wieść, że coś przydarzyło się ich kurierowi.","en":"They''re likely to become VERY unpleasant if I throw one of their gofers out of the Camp or have him killed.","de":"Wenn ich einen ihrer Boten aus dem Lager werfe oder umlegen lasse, könnten sie SEHR unangenehm werden."}},{"speaker":"hero","text":{"pl":"A co ze mną? Co Magowie mogą mi zrobić?","en":"What about ME? What do you think the mages will do to ME?","de":"Was ist mit MIR? Was glaubst du machen die Magier mit MIR?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mordrag_dead_15_00_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mordrag_dead_15_00_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"Info_Thorus_MordragKo_MordragDead","outputIds":["Info_Thorus_MordragKo_MordragDead_15_00","Info_Thorus_MordragKo_MordragDead_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Mordrag już nigdy nikogo nie okradnie!","en":"Mordrag will never steal anything from anyone ever again!","de":"Mordrag wird nie wieder irgendwen bestehlen!"}},{"speaker":"npc","text":{"pl":"Chcesz powiedzieć, że go pokonałeś? Nieźle, chłopcze.","en":"You mean you defeated him? That''s not bad, kid.","de":"Du hast ihn geschafft? Nicht schlecht, Kleiner."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mordrag_gone_15_00_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_info_thorus_mordrag_ko_mordrag_gone_15_00_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"Info_Thorus_MordragKo_MordragGone","outputIds":["Info_Thorus_MordragKo_MordragGone_15_00","Info_Thorus_MordragKo_MordragGone_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Facet już nigdy się tu nie pokaże!","en":"He''s never gonna show his face around here again!","de":"Der Typ wird sich hier nie wieder blicken lassen!"}},{"speaker":"npc","text":{"pl":"Wolałbym, żebyś go zabił.","en":"I''d have felt happier if you''d killed him.","de":"Lieber wär'' mir gewesen, du hättest ihn umgelegt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_200_thorus_info_thorus_mordrag_ko_where_15_00_0', 'GRD_200_Thorus', '{"id":"missions_dia_grd_200_thorus_info_thorus_mordrag_ko_where_15_00_0","npcId":"GRD_200_Thorus","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_200_Thorus.d","sourceFunction":"Info_Thorus_MordragKo_Where","outputIds":["Info_Thorus_MordragKo_Where_15_00","Info_Thorus_MordragKo_Where_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę Mordraga?","en":"Where can I find Mordrag?","de":"Wo finde ich Mordrag?"}},{"speaker":"npc","text":{"pl":"Kręci się przy południowej bramie, po przeciwnej stronie zamku, tuż za wejściem. Sukinsyn boi się pojawiać bliżej centrum.","en":"You''ll find him at the south gate on the other side of the castle, just beyond the entrance. The bastard wouldn''t dare come any further into the Camp.","de":"Du findest ihn am Südtor, auf der anderen Seite der Burg, direkt hinter dem Eingang. Weiter traut sich dieser Halunke nicht ins Lager."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_grd_201_jackal_welcome_info_07_01_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_grd_201_jackal_welcome_info_07_01_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"GRD_201_Jackal_WELCOME_Info","outputIds":["GRD_201_Jackal_WELCOME_Info_07_01"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że szybko pniesz się do góry. Dobra robota, stary!","en":"You''ve worked your way up pretty fast! Well done, man!","de":"Du hast dich ziemlich schnell nach oben gearbeitet! Gut gemacht, Mann!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_hello_07_00_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_hello_07_00_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_Hello_Info","outputIds":["Info_Jackal_Hello_07_00","Info_Jackal_Hello_15_01","Info_Jackal_Hello_07_02","Info_Jackal_Hello_07_03"],"lines":[{"speaker":"npc","text":{"pl":"Ach! Nowa twarz!","en":"Ah! A new face.","de":"Ah! Ein neues Gesicht."}},{"speaker":"hero","text":{"pl":"Czego chcesz?","en":"What do you want?","de":"Was willst du?"}},{"speaker":"npc","text":{"pl":"Chcę ci zaoferować pomoc. Jesteś tu nowy, a nowi zawsze pakują się w kłopoty... Możesz sobie zaoszczędzić nieprzyjemności ofiarując mi... drobny datek.","en":"I wanna offer you help. You''re new here, an'' new ''uns always get into trouble... You could save yourself a lot by makin'' a small donation.","de":"Ich will dir meine Hilfe anbieten. Du bist neu hier und Neue bekommen schnell Ärger ... Mit einer kleinen Spende an mich könntest du dir einiges davon ersparen."}},{"speaker":"npc","text":{"pl":"Marne 10 bryłek rudy. Toż to grosze...","en":"Just 10 ore, man! It ain''t much to ask.","de":"Nur 10 Erz, Mann! Das ist nicht viel."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_hello_later_15_00_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_hello_later_15_00_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_Hello_Later","outputIds":["Info_Jackal_Hello_Later_15_00","Info_Jackal_Hello_Later_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Do zobaczenia.","en":"I''ll see you later.","de":"Wir sehen uns später."}},{"speaker":"npc","text":{"pl":"Miej oczy szeroko otwarte.","en":"Just you take care of yourself.","de":"Pass solange gut auf dich auf."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_hello_pay_15_00_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_hello_pay_15_00_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_Hello_Pay","outputIds":["Info_Jackal_Hello_Pay_15_00","Info_Jackal_Hello_Pay_07_01","Info_Jackal_Hello_Pay_07_02","Info_Jackal_Schutz_NoOre_07_00"],"lines":[{"speaker":"hero","text":{"pl":"Masz tu 10 bryłek. Ale pomożesz mi, w razie potrzeby?","en":"Here''s 10 ore. And you''ll have to help me if I get into trouble.","de":"Hier. 10 Erz. Und du hilfst mir, wenn ich Ärger habe."}},{"speaker":"npc","text":{"pl":"Jeśli tylko będę w pobliżu, możesz na mnie liczyć. Znajdziesz mnie pomiędzy targowiskiem a południową bramą.","en":"You can count on me if I''m close by. You''ll find me between the market place and the south gate.","de":"Wenn ich in der Nähe bin, kannst du auf mich zählen. Du kannst mich jederzeit zischen dem Marktplatz und dem Südtor finden."}},{"speaker":"npc","text":{"pl":"Resztę obozu obstawiają Fletcher i Bloodwyn.","en":"The other areas are Fletcher and Bloodwyn''s affair.","de":"Um die anderen Bereiche kümmern sich Fletcher und Bloodwyn."}},{"speaker":"npc","text":{"pl":"Hej, masz mnie za idiotę?! Wróć, jak będziesz miał dość rudy!","en":"Hey, watch who you''re trying to fool! Come back when you have the ore!","de":"Hey, verarsch mich nicht! Komm wieder, wenn du das Erz hast!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_hello_what_do_iget_15_00_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_hello_what_do_iget_15_00_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_Hello_WhatDoIGet","outputIds":["Info_Jackal_Hello_WhatDoIGet_15_00","Info_Jackal_Hello_WhatDoIGet_07_01","Info_Jackal_Hello_WhatDoIGet_07_02","Info_Jackal_Hello_WhatDoIGet_07_03"],"lines":[{"speaker":"hero","text":{"pl":"A co będę z tego miał?","en":"And what do I get out of it?","de":"Und was bekomme ich dafür?"}},{"speaker":"npc","text":{"pl":"Dopilnuję, żeby nic złego ci się nie przydarzyło na moim terenie.","en":"While you''re in my district, I''ll protect you.","de":"Solange du in meinem Viertel bist, passe ich auf dich auf."}},{"speaker":"npc","text":{"pl":"Jak goście z Nowego Obozu nadepną ci na odcisk albo wkurzy cię jakiś świr z Sekty, możesz na mnie liczyć.","en":"If you get into any trouble with the guys from the New Camp or if one of the sect loonies gets on your nerves, you can count on me.","de":"Wenn du mal Ärger mit Typen aus dem Neuen Lager haben solltest oder mit einem der Sektenspinner, die dir die Backe voll quatschen, kannst du auf mich zählen."}},{"speaker":"npc","text":{"pl":"Jeśli weźmiesz się za łby z jakimś Kopaczem, pomożemy temu z was, który zapłacił podatek - proste, nie?","en":"If you have bother with one of the diggers, we''ll help whichever one of you has paid - it''s as simple as that.","de":"Wenn du dich mit einem Buddler anlegst, helfen wir dem, der gezahlt hat - so einfach ist das."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_hello_what_do_iget_15_04_4', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_hello_what_do_iget_15_04_4","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_Hello_WhatDoIGet","outputIds":["Info_Jackal_Hello_WhatDoIGet_15_04","Info_Jackal_Hello_WhatDoIGet_07_05"],"lines":[{"speaker":"hero","text":{"pl":"A jeśli okaże się, że obydwaj zapłaciliśmy?","en":"And what if both have paid?","de":"Und wenn beide gezahlt haben?"}},{"speaker":"npc","text":{"pl":"Wtedy będziemy spokojnie patrzeć, jak się zarzynacie. Ale to się nie zdarza zbyt często.","en":"Then we sit back an'' watch the show. But that don''t happen too often.","de":"Dann sehen wir uns die Show an. Aber oft kommt das nicht vor."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_hello_what_if_15_00_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_hello_what_if_15_00_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_Hello_WhatIf","outputIds":["Info_Jackal_Hello_WhatIf_15_00","Info_Jackal_Hello_WhatIf_07_01","Info_Jackal_Hello_WhatIf_07_02"],"lines":[{"speaker":"hero","text":{"pl":"A jeśli nie zapłacę?","en":"What if I don''t pay?","de":"Und wenn ich nicht zahle?"}},{"speaker":"npc","text":{"pl":"Człowieku, nie narażaj się na niepotrzebny stres! Jesteś tu nowy - rozejrzyj się dookoła. Zbierz trochę rudy, a jak będziesz miał już dość - zapłać. Tak jest bezpieczniej.","en":"Hey man, don''t stress yourself! You''re a newcomer - take a look around. Collect a bit of ore and when you''re ready to pay, then pay.","de":"Hey Mann, mach dir keinen Stress! Du bist neu hier - sieh dich mal ein bisschen um. Sammel'' erst mal etwas Erz und wenn du bereit bist zu zahlen - dann zahlst du."}},{"speaker":"npc","text":{"pl":"Możesz to zrobić teraz, albo później. Tylko nie licz na moją pomoc, dopóki nie dostanę rudy. Mam nadzieję, że się rozumiemy?","en":"You can do it anytime - but don''t count on my help until you''ve made your contribution to my expenses - I''m sure you''ll understand.","de":"Du kannst das jederzeit nachholen - nur bitte rechne nicht mit meiner Hilfe, solange du nicht einen kleinen Beitrag zu meinen Unkosten geleistet hast - das verstehst du doch?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_payday_07_01_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_payday_07_01_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_PAYDAY_Info","outputIds":["Info_Jackal_PAYDAY_07_01","Info_Jackal_PAYDAY_07_02","Info_Jackal_PAYDAY_07_03","Info_Jackal_PAYDAY_07_04"],"lines":[{"speaker":"npc","text":{"pl":"Patrzcie państwo. Toż to nasz arcy-zdrajca!","en":"Hey, look at that! It''s the traitor that switched camps!","de":"Sieh mal einer an. Der Verräter, der das Lager gewechselt hat!"}},{"speaker":"npc","text":{"pl":"Gdybyś nie zadawał się z tymi fajtłapami, mógłbyś nadal być jednym z nas!","en":"You shouldn''t have got involved with those losers, you''d still be one of us!","de":"Du hättest dich nicht mit diesen Verlierern einlassen sollen, dann würdest du noch zu uns gehören!"}},{"speaker":"npc","text":{"pl":"Hej, patrzcie! To ten facet z Nowego Obozu, przez którego mamy tyle kłopotów.","en":"Hey, look at that! It''s that guy from the New Camp, the one that caused us all that trouble!","de":"Sieh mal einer an. Der Typ aus dem Neuen Lager, der uns schon so viel Ärger gemacht hat!"}},{"speaker":"npc","text":{"pl":"Gdybyś wykazał wtedy choć odrobinę rozsądku, mógłbyś teraz być po stronie zwycięzców... po NASZEJ stronie!","en":"If you''d shown a bit more sense back then, you could be on our side now - the side of the winners!","de":"Wenn du damals schlauer gewesen wärst, würdest du heute zu uns - den Siegern - gehören!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_payday_07_05_4', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_payday_07_05_4","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_PAYDAY_Info","outputIds":["Info_Jackal_PAYDAY_07_05","Info_Jackal_PAYDAY_07_06","Info_Jackal_PAYDAY_07_07","Info_Jackal_PAYDAY_07_08"],"lines":[{"speaker":"npc","text":{"pl":"Patrzcie no! To ten gość z obozu na bagnie.","en":"Will you look at that. It''s the guy from the swamp camp.","de":"Sieh mal einer an. Der Typ aus dem Sumpflager."}},{"speaker":"npc","text":{"pl":"Za długo zadawałeś się z tymi świrami z Sekty. Zdążyli ci zrobić wodę z mózgu.","en":"You''ve been around those loonies too long, they''ve made you soft in the head!","de":"Du hast dich zu lange bei diesen Spinnern aufgehalten, die haben dein Hirn weich gekocht!"}},{"speaker":"npc","text":{"pl":"Teraz nie uratują cię nawet pieniądze, które zapłaciłeś mi za ochronę!","en":"Even the protection money you paid me ain''t gonna help you now.","de":"Da hilft dir auch nicht, dass du mir Schutzgeld bezahlt hast."}},{"speaker":"npc","text":{"pl":"Trzeba mi było zapłacić kiedy miałeś okazję.","en":"You should have paid me when you still had the chance.","de":"Hättest mich damals bezahlen sollen, als es noch Zeit war."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_payday_15_09_8', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_payday_15_09_8","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_PAYDAY_Info","outputIds":["Info_Jackal_PAYDAY_15_09","Info_Jackal_PAYDAY_07_10","Info_Jackal_PAYDAY_07_11"],"lines":[{"speaker":"hero","text":{"pl":"Posunęliście się za daleko. Atak na kopalnię był poważnym błędem.","en":"You''ve gone too far! It was a dumb idea to attack the mine!","de":"Ihr seid zu weit gegangen! Der Überfall auf die Mine war dumm von euch!"}},{"speaker":"npc","text":{"pl":"Ale wygląda na to, że się udało. A tobie już nic do tego!","en":"Seems to have worked though. And you ain''t gonna change that, believe me!","de":"Scheint aber funktioniert zu haben. Und du wirst daran auch nichts ändern, dafür werde ich persönlich Sorge tragen!"}},{"speaker":"npc","text":{"pl":"DALEJ, CHŁOPCY! WYKOŃCZMY GO!!!","en":"HEY GUYS, LET''S TAKE HIM OUT!!!","de":"LOS, WIR MACHEN IHN KALT, JUNGS!!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_perm_paid_15_00_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_perm_paid_15_00_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_PermPaid_Info","outputIds":["Info_Jackal_PermPaid_15_00","Info_Jackal_PermPaid_07_01"],"lines":[{"speaker":"hero","text":{"pl":"No i, jak leci?","en":"Well, how''s it going?","de":"Na, wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Możesz na mnie liczyć, chłopcze!","en":"You can always count on me, kid!","de":"Du kannst nach wie vor auf mich zählen, Kleiner!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_201_jackal_info_jackal_schutz_15_00_0', 'GRD_201_Jackal', '{"id":"missions_dia_grd_201_jackal_info_jackal_schutz_15_00_0","npcId":"GRD_201_Jackal","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_201_Jackal.d","sourceFunction":"Info_Jackal_Schutz_Info","outputIds":["Info_Jackal_Schutz_15_00","Info_Jackal_Schutz_07_01","Info_Jackal_Schutz_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Przemyślałem sobie to, co powiedziałeś. Oto 10 bryłek rudy.","en":"I''ve been thinking about that protection money - here''s your 10 ore.","de":"Ich hab'' noch mal über das Schutzgeld nachgedacht - hier sind deine 10 Erz."}},{"speaker":"npc","text":{"pl":"Mądra decyzja, kolego. Od tej pory możesz liczyć na moją pomoc.","en":"You''ve made the right choice, man. I''ll protect you from now on!","de":"Du hast eine gute Wahl getroffen, Mann. Ab jetzt pass ich auf dich auf!"}},{"speaker":"npc","text":{"pl":"Nie widzę u ciebie żadnych 10 bryłek. Wróć, jak będziesz miał całą kwotę.","en":"I don''t see any 10 ore, man. Come back when you have it.","de":"Ich sehe keine 10 Erz, Mann. Komm wieder, wenn du 10 Erz hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_203_bullit_dia_bullit_aufs_maul_15_00_0', 'GRD_203_Bullit', '{"id":"missions_dia_grd_203_bullit_dia_bullit_aufs_maul_15_00_0","npcId":"GRD_203_Bullit","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_203_Bullit.d","sourceFunction":"DIA_Bullit_AufsMAul_Info","outputIds":["DIA_Bullit_AufsMAul_15_00","DIA_Bullit_AufsMAul_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Przyszedłem pogruchotać ci szczękę.","en":"I''ve come to stuff your big mouth for you.","de":"Ich bin gekommen, um dir dein großes Maul zu stopfen."}},{"speaker":"npc","text":{"pl":"Ha! No to chodź tutaj i spróbuj szczęścia, synku!","en":"Hah, well come here an'' give it a try, sonny!","de":"Ja, dann komm mal her, Bürschchen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_203_bullit_dia_bullit_first_06_00_0', 'GRD_203_Bullit', '{"id":"missions_dia_grd_203_bullit_dia_bullit_first_06_00_0","npcId":"GRD_203_Bullit","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_203_Bullit.d","sourceFunction":"DIA_Bullit_First_Info","outputIds":["DIA_Bullit_First_06_00"],"lines":[{"speaker":"npc","text":{"pl":"Kogo my tu mamy? Czy to nie ta ofiara, którą ochrzciłem wcześniej? Czego chcesz? Przyszedłeś po repetę?","en":"Who have we here? Ain''t you the guy I baptized earlier? What do you want? You come back for more?","de":"Wen haben wir denn da? Du bist doch der Typ, den ich getauft habe? Was willst du? Noch mehr Schläge?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_203_bullit_dia_grd_203_bullit_wait4_sc_06_01_0', 'GRD_203_Bullit', '{"id":"missions_dia_grd_203_bullit_dia_grd_203_bullit_wait4_sc_06_01_0","npcId":"GRD_203_Bullit","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_203_Bullit.d","sourceFunction":"DIA_GRD_203_Bullit_Wait4SC_Info","outputIds":["DIA_GRD_203_Bullit_Wait4SC_06_01","DIA_GRD_203_Bullit_Wait4SC_15_02","DIA_GRD_203_Bullit_Wait4SC_06_03"],"lines":[{"speaker":"npc","text":{"pl":"Znowu ty?! Powinienem cię utopić w jeziorze podczas naszego pierwszego spotkania!","en":"You again?! I should have drowned you in the lake the moment I set eyes on you!","de":"Du schon wieder. Ich hätte dich schon am ersten Tag im See versenken sollen!"}},{"speaker":"hero","text":{"pl":"Wtedy nie miałem szans - teraz karta się odwróciła.","en":"I didn''t stand a chance back then - now the tables are turned.","de":"Damals hatte ich keine Chance - jetzt ist genau das Gegenteil der Fall."}},{"speaker":"npc","text":{"pl":"Ty gnido! Mam tylko nadzieję, że będziesz trudniejszym przeciwnikiem niż ostatnio!","en":"You worm! I only hope you don''t make it as easy for me as you did the first time!","de":"Du Wurm! Ich hoffe, dass du es mir nicht so einfach machst, wie beim ersten Mal!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_dia_scorpio_hello_13_00_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_dia_scorpio_hello_13_00_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"DIA_Scorpio_Hello_Info","outputIds":["DIA_Scorpio_Hello_13_00","DIA_Scorpio_Hello_15_01","DIA_Scorpio_Hello_13_02"],"lines":[{"speaker":"npc","text":{"pl":"Kto cię tu wpuścił?","en":"Who let YOU in?","de":"Wer hat DICH denn reingelassen?"}},{"speaker":"hero","text":{"pl":"Thorus.","en":"Thorus.","de":"Thorus."}},{"speaker":"npc","text":{"pl":"I czego tu szukasz?","en":"And what do you think you''re doing?","de":"Und was willst du hier?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_dia_scorpio_hello_join_15_00_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_dia_scorpio_hello_join_15_00_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"DIA_Scorpio_Hello_Join","outputIds":["DIA_Scorpio_Hello_Join_15_00","DIA_Scorpio_Hello_Join_13_01","DIA_Scorpio_Hello_Join_15_02","DIA_Scorpio_Hello_Join_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Idę zobaczyć się z Gomezem. Zamierzam do was dołączyć.","en":"I''m on my way to see Gomez. I''m going to join up with you.","de":"Ich bin auf dem Weg zu Gomez. Ich will mich euch anschließen."}},{"speaker":"npc","text":{"pl":"Ty? A co z ciebie będzie za pożytek?","en":"You? What have you ever done for us?","de":"Du? Hast du überhaupt schon was für uns geleistet?"}},{"speaker":"hero","text":{"pl":"Cienie na mnie nie narzekały.","en":"The Shadows were very happy with me...","de":"Die Schatten waren zufrieden."}},{"speaker":"npc","text":{"pl":"Ale my nie chcemy nawet słyszeć o Cieniach! To MY trzymamy rękę na pulsie.","en":"None of us in here wants to hear anything about Shadows. WE have the say in here.","de":"Von Schatten will hier keiner was hören. Hier drin geben WIR den Ton an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_dia_scorpio_hello_just_looking_15_00_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_dia_scorpio_hello_just_looking_15_00_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"DIA_Scorpio_Hello_JustLooking","outputIds":["DIA_Scorpio_Hello_JustLooking_15_00","DIA_Scorpio_Hello_JustLooking_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Chciałem się tylko trochę rozejrzeć.","en":"I just wanted to see what it''s like in here.","de":"Ich wollte mal wissen, wie''s hier drin aussieht."}},{"speaker":"npc","text":{"pl":"Bardzo śmieszne.","en":"Very funny.","de":"Sehr witzig."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_dia_scorpio_hello_kraut_15_00_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_dia_scorpio_hello_kraut_15_00_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"DIA_Scorpio_Hello_Kraut","outputIds":["DIA_Scorpio_Hello_Kraut_15_00","DIA_Scorpio_Hello_Kraut_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Przyniosłem bagienne ziele dla Gomeza.","en":"I''ve brought some weed for Gomez.","de":"Ich habe eine Ladung Kraut für Gomez."}},{"speaker":"npc","text":{"pl":"To zanieś je do tego domu, którego wejścia broni dwóch strażników.","en":"Then take it to the house with the two guards outside the door.","de":"Dann bring sie in das Haus mit den beiden Wachen vor der Tür."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_dia_scorpio_hello_mages_15_00_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_dia_scorpio_hello_mages_15_00_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"DIA_Scorpio_Hello_Mages","outputIds":["DIA_Scorpio_Hello_Mages_15_00","DIA_Scorpio_Hello_Mages_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Mam wiadomość dla magów.","en":"I have a message for the mages.","de":"Ich habe eine Botschaft für die Magier."}},{"speaker":"npc","text":{"pl":"Pracujesz dla magów? Nie chcę mieć z nimi nic do czynienia!","en":"You work for the mages? I don''t want nothing to do with them...","de":"Du arbeitest für die Magier? Damit will ich nichts zu tun haben ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_banished_info_15_01_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_banished_info_15_01_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_BANISHED_Info","outputIds":["GRD_205_Scorpio_BANISHED_Info_15_01","GRD_205_Scorpio_BANISHED_Info_13_02","GRD_205_Scorpio_BANISHED_Info_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Wszystko w porządku?","en":"You okay?","de":"Alles klar bei dir?"}},{"speaker":"npc","text":{"pl":"Ukrywam się. Mam już dość machlojek strażników.","en":"I''m hiding away here. I don''t care for the trash those guards are pulling off.","de":"Ich habe mich hier her verzogen. Für den Mist, den die Gardisten gerade abziehen, habe ich nichts übrig."}},{"speaker":"npc","text":{"pl":"Ale zabrałem kilka niezłych cacek ze zbrojowni. Gdybyś potrzebował broni - zgłoś się do mnie.","en":"But I''ve taken some pretty good stuff from the arsenal. If you need a weapon, just let me know.","de":"Aber ich habe mir ein paar gute Stücke aus der Waffenkammer mitgenommen. Wenn du eine Waffe brauchst, sag mir Bescheid."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow_info_15_01_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow_info_15_01_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_CROSSBOW_Info","outputIds":["GRD_205_Scorpio_CROSSBOW_Info_15_01","GRD_205_Scorpio_CROSSBOW_Info_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie czegoś nauczyć?","en":"Will you train me?","de":"Kann ich von dir lernen?"}},{"speaker":"npc","text":{"pl":"Jeśli masz dość rudy, pokażę ci jak posługiwać się kuszą. To cię będzie kosztować jakieś 200 bryłek.","en":"If you have enough ore, I''ll teach you how to use a crossbow. Just pay me 200 ore.","de":"Wenn du genug Erz hast, zeige ich dir den Umgang mit der Armbrust. Gib mir einfach 200 Erz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow_ok_13_05_4', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow_ok_13_05_4","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_CROSSBOW_OK","outputIds":["GRD_205_Scorpio_CROSSBOW_OK_13_05","GRD_205_Scorpio_CROSSBOW_OK_13_06","GRD_205_Scorpio_CROSSBOW_OK_13_07"],"lines":[{"speaker":"npc","text":{"pl":"Po jakimś tygodniu będziesz miał ręce ze stali!","en":"But after just one week, you''ll have a shoulder like a rock!","de":"Aber schon nach einer Woche hast du eine Schulter wie aus Stein!"}},{"speaker":"npc","text":{"pl":"Wyceluj spokojnie i powoli ściągnij spust. Bełt niesie ze sobą więcej siły niż strzała, dlatego powoduje większe zniszczenia.","en":"Aim right at your target and pull the bolt right back. There''s more force behind a bolt than there is behind an arrow from a longbow, so it''s going to cause more damage!","de":"Visier dein Ziel an und zieh durch. Der Bolzen bekommt mehr Kraft als ein Pfeil durch einen gespannten Bogen, von daher richtest du mehr Schaden an!"}},{"speaker":"npc","text":{"pl":"DWIEŚCIE BRYŁEK RUDY, płatne do ręki i to od razu! Inaczej nie mamy o czym rozmawiać!","en":"TWO HUNDRED ORE, right here, in my hand. If you don''t have enough ore, then get some!","de":"ZWEIHUNDERT ERZ. Jeder einzelne Brocken in meine Hand. Wenn du das Erz nicht hast, dann besorge es dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow_ok_15_01_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow_ok_15_01_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_CROSSBOW_OK","outputIds":["GRD_205_Scorpio_CROSSBOW_OK_15_01","GRD_205_Scorpio_CROSSBOW_OK_13_02","GRD_205_Scorpio_CROSSBOW_OK_13_03","GRD_205_Scorpio_CROSSBOW_OK_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Umowa stoi. Pokaż mi jak obchodzić się z kuszą.","en":"It''s a deal. So show me how to handle a crossbow.","de":"Einverstanden. Zeig mir den Umgang mit der Armbrust."}},{"speaker":"npc","text":{"pl":"Dobra. Bierzmy się do roboty.","en":"Okay, let''s get started.","de":"Gut, fangen wir direkt an."}},{"speaker":"npc","text":{"pl":"Złap kuszę mocno i oprzyj ją o ramię. To powinno zwiększyć celność strzału.","en":"Grab hold of the shaft, and hold it close against your shoulder. That''ll steady your aim.","de":"Fasse die Armbrust am Schaft an, um ruhig zielen zu können, drücke sie an deine Schulter."}},{"speaker":"npc","text":{"pl":"Przez kilka pierwszych dni twoje ramię da ci się nieźle we znaki, ale z czasem przywykniesz.","en":"Your shoulder''s gonna feel like it''s liable to fall off during the first few days.","de":"In den ersten paar Tagen wirst du ein Gefühl haben, als ob dir die Schulter abfällt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow2_info_15_01_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow2_info_15_01_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_CROSSBOW2_Info","outputIds":["GRD_205_Scorpio_CROSSBOW2_Info_15_01","GRD_205_Scorpio_CROSSBOW2_Info_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym dowiedzieć się czegoś więcej o strzelaniu z kuszy.","en":"Show me more about how to handle a crossbow.","de":"Zeige mir mehr über den Umgang mit der Armbrust"}},{"speaker":"npc","text":{"pl":"To cię będzie kosztować 300 bryłek rudy.","en":"That''ll cost you 300 ore.","de":"Kostet dich 300 Erz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow2_ok_13_05_4', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow2_ok_13_05_4","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_CROSSBOW2_OK","outputIds":["GRD_205_Scorpio_CROSSBOW2_OK_13_05","GRD_205_Scorpio_CROSSBOW2_OK_13_06","GRD_205_Scorpio_CROSSBOW2_OK_13_07"],"lines":[{"speaker":"npc","text":{"pl":"Jeśli atakujesz więcej niż jeden cel, nie trać czasu: musisz możliwie szybko przygwoździć jeden za drugim dobrze wymierzonymi strzałami.","en":"If there''s more than one target, don''t waste any time. Nail ''em all down one after the other with calculated shots.","de":"Wenn du mehrere Ziele hast, dann verschwende keine Zeit, sondern nagel'' alle Ziele mit gezielten Schüssen fest und strecke sie abwechselnd nieder."}},{"speaker":"npc","text":{"pl":"To by było na tyle.","en":"That''s it, I''ve taught you all I know.","de":"Du hast jetzt alles gelernt, was ich dir beibringen kann."}},{"speaker":"npc","text":{"pl":"Najpierw postaraj się zdobyć te TRZYSTA BRYŁEK RUDY!","en":"See if you can get THREE HUNDRED ore from somewhere.","de":"Junge, sieh erst mal zu, dass du irgendwo DREIHUNDERT Erz auftreibst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow2_ok_15_01_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_crossbow2_ok_15_01_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_CROSSBOW2_OK","outputIds":["GRD_205_Scorpio_CROSSBOW2_OK_15_01","GRD_205_Scorpio_CROSSBOW2_OK_13_02","GRD_205_Scorpio_CROSSBOW2_OK_13_03","GRD_205_Scorpio_CROSSBOW2_OK_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Zaczynajmy.","en":"Let''s start now.","de":"Lass uns direkt anfangen."}},{"speaker":"npc","text":{"pl":"Dobra. Twoje strzały będą celniejsze, jeśli przed ściągnięciem spustu ugniesz nieco nogi w kolanach.","en":"Right. Your shots''ll be more accurate and straight if you bend your knees when firing.","de":"Gut. Du bekommst mehr Treffsicherheit und Ruhe, wenn du beim Schuss in die Knie gehst"}},{"speaker":"npc","text":{"pl":"Naucz się poprawnie oceniać prędkość z jaką porusza się twój cel.","en":"You''ll have to learn to judge what speed your target''s moving at.","de":"Lerne die Geschwindigkeit von beweglichen Zielen einzuschätzen."}},{"speaker":"npc","text":{"pl":"Wystrzel pocisk tak, by w odpowiednim miejscu i czasie przeciął ścieżkę, którą porusza się cel.","en":"Fire your bolt into the moving target''s path to hit it and slow it down.","de":"Schieß in die Laufbahn des Zieles, dann wirst du es treffen und es dadurch auch in seiner Bewegung aufhalten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_hey_pc_info_13_01_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_hey_pc_info_13_01_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_HeyPC_Info","outputIds":["GRD_205_Scorpio_HeyPC_Info_13_01"],"lines":[{"speaker":"npc","text":{"pl":"Nie bój się, człowieku! Chodź no tutaj!","en":"Hey, no sweat, man. Come over here!","de":"Hey, keine Angst, Mann, komm mal rüber!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_205_scorpio_grd_205_scorpio_welcome_info_13_01_0', 'GRD_205_Scorpio', '{"id":"missions_dia_grd_205_scorpio_grd_205_scorpio_welcome_info_13_01_0","npcId":"GRD_205_Scorpio","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_205_Scorpio.d","sourceFunction":"GRD_205_Scorpio_WELCOME_Info","outputIds":["GRD_205_Scorpio_WELCOME_Info_13_01"],"lines":[{"speaker":"npc","text":{"pl":"Przejście do nas było najmądrzejszą decyzją twojego życia!","en":"Joining us was the best choice you ever made!","de":"War die beste Entscheidung von dir, zu uns zu kommen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_208_cutter_dia_cutter_burg_15_00_0', 'GRD_208_Cutter', '{"id":"missions_dia_grd_208_cutter_dia_cutter_burg_15_00_0","npcId":"GRD_208_Cutter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_208_Cutter.d","sourceFunction":"DIA_Cutter_Burg_Info","outputIds":["DIA_Cutter_Burg_15_00","DIA_Cutter_Burg_08_01","DIA_Cutter_Burg_08_02","DIA_Cutter_Burg_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mi opowiedzieć o tym zamku?","en":"What can you tell me about the castle?","de":"Was kannst du mir über die Burg sagen?"}},{"speaker":"npc","text":{"pl":"Co tu dużo mówić: Gomez i jego ludzie zajęli go po wielkim buncie.","en":"Gomez and his gang took it over after the big uprising.","de":"Nach dem großen Aufstand haben sich Gomez und seine Jungs die Burg unter den Nagel gerissen."}},{"speaker":"npc","text":{"pl":"Od początku wiedziałem, że warto będzie stanąć po jego stronie.","en":"I knew right away it was better to join up with him.","de":"Ich hab'' damals schnell gemerkt, dass es besser ist, sich ihm anzuschließen."}},{"speaker":"npc","text":{"pl":"Wielu z nas, jeszcze jako więźniowie zamknięci w lochach lub zmuszani do pracy w kopalni, uznawało zwierzchnictwo Gomeza.","en":"Even when we were still cooped up in the dungeons, and had to slave away in the mines, the rest of us prisoners always did what he said.","de":"Schon als wir damals noch alle im Kerker eingepfercht waren, und in den Minen schuften mussten hatte er unter den Gefangenen am meisten zu sagen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_208_cutter_dia_cutter_burg_15_04_4', 'GRD_208_Cutter', '{"id":"missions_dia_grd_208_cutter_dia_cutter_burg_15_04_4","npcId":"GRD_208_Cutter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_208_Cutter.d","sourceFunction":"DIA_Cutter_Burg_Info","outputIds":["DIA_Cutter_Burg_15_04","DIA_Cutter_Burg_08_05"],"lines":[{"speaker":"hero","text":{"pl":"Czy te lochy znajdują się pod zamkiem?","en":"Are there dungeons under the castle then?","de":"Es gibt Kerker unter der Burg?"}},{"speaker":"npc","text":{"pl":"Tak, ale teraz świecą pustką. Nikt tam nie schodził od czasu wielkiego buntu.","en":"Yeah, but there ain''t nothing in them now. Nobody ever went down there after the big uprising.","de":"Ja, aber sie sind heute leer. Seit dem großen Aufstand will da niemand mehr rein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_208_cutter_dia_cutter_hello_15_00_0', 'GRD_208_Cutter', '{"id":"missions_dia_grd_208_cutter_dia_cutter_hello_15_00_0","npcId":"GRD_208_Cutter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_208_Cutter.d","sourceFunction":"DIA_Cutter_Hello_Info","outputIds":["DIA_Cutter_Hello_15_00","DIA_Cutter_Hello_08_01","DIA_Cutter_Hello_15_02"],"lines":[{"speaker":"hero","text":{"pl":"Wasz zamek jest bardzo duży.","en":"This castle''s pretty roomy.","de":"Ihr habt ganz schön viel Platz hier in der Burg."}},{"speaker":"npc","text":{"pl":"Chyba cię jeszcze tutaj nie widziałem. Kim jesteś?","en":"I don''t think I''ve seen you here before. Who are you?","de":"Ich habe dich hier noch nie gesehen. Wer bist du?"}},{"speaker":"hero","text":{"pl":"Jestem tu nowy. Chciałem się trochę rozejrzeć.","en":"I''m a newcomer. Just thought I''d take a look around.","de":"Ich bin neu hier. Wollte mich mal ein bisschen umsehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_208_cutter_dia_cutter_perm_15_00_0', 'GRD_208_Cutter', '{"id":"missions_dia_grd_208_cutter_dia_cutter_perm_15_00_0","npcId":"GRD_208_Cutter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_208_Cutter.d","sourceFunction":"DIA_Cutter_PERM_Info","outputIds":["DIA_Cutter_PERM_15_00","DIA_Cutter_PERM_08_01","DIA_Cutter_PERM_15_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak wygląda życie strażnika?","en":"What''s life like as a guard?","de":"Wie ist das Leben als Gardist?"}},{"speaker":"npc","text":{"pl":"Jest spokojne. Jesteśmy największym i najsilniejszym obozem w kolonii. Nikt nie śmie nas zaczepiać.","en":"Quiet. We''re the biggest, strongest camp in the whole of the colony. Nobody messes with us.","de":"Ruhig. Wir sind das größte und stärkste Lager in der Kolonie - mit uns legt sich keiner an."}},{"speaker":"hero","text":{"pl":"Rozumiem.","en":"I see.","de":"Verstehe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_208_cutter_grd_208_cutter_welcome_info_08_01_0', 'GRD_208_Cutter', '{"id":"missions_dia_grd_208_cutter_grd_208_cutter_welcome_info_08_01_0","npcId":"GRD_208_Cutter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_208_Cutter.d","sourceFunction":"GRD_208_Cutter_WELCOME_Info","outputIds":["GRD_208_Cutter_WELCOME_Info_08_01"],"lines":[{"speaker":"npc","text":{"pl":"Dokonałeś właściwego wyboru. Spodoba ci się bycie Strażnikiem!","en":"You''ve made the right choice. You''ll enjoy being a guard!","de":"Du hast die richtige Entscheidung getroffen. Das Leben als Gardist wird dir gefallen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_join_oc_15_00_0', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_join_oc_15_00_0","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_JoinOC_Info","outputIds":["DIA_Scatty_JoinOC_15_00","DIA_Scatty_JoinOC_01_01","DIA_Scatty_JoinOC_01_02","DIA_Scatty_JoinOC_01_03"],"lines":[{"speaker":"hero","text":{"pl":"Chcę dołączyć do waszego obozu. Możesz mi pomóc?","en":"I want to join the Camp. Can you help me?","de":"Ich will mich dem Lager anschließen. Kannst du mir dabei helfen?"}},{"speaker":"npc","text":{"pl":"Pomogę ci, jeśli zrobisz na mnie odpowiednio dobre wrażenie.","en":"I might be able to, if you manage to impress me.","de":"Wenn du es schaffst, mich zu beeindrucken - vielleicht."}},{"speaker":"npc","text":{"pl":"Najlepsi wojownicy z wszystkich obozów przybywają tutaj, by stanąć w szranki na mojej arenie.","en":"Some of the best fighters from all three camps come here to compete against each other.","de":"Einige der besten Kämpfer aller drei Lager kommen hier her um sich zu messen."}},{"speaker":"npc","text":{"pl":"Wyzwij któregoś z nich na pojedynek. Zobaczę, co potrafisz, i jeśli mi się spodoba, może szepnę słówko w twoim imieniu.","en":"Challenge one of them to a fight. I''ll watch you, and if you''re good maybe I''ll think about it.","de":"Fordere einen von ihnen heraus und kämpfe gegen ihn. Je nachdem, wie gut du dich schlägst, wird mein Urteil über dich ausfallen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_kharimsuccess_01_04_4', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_kharimsuccess_01_04_4","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_KHARIMSuccess_Info","outputIds":["DIA_Scatty_KHARIMSuccess_01_04","DIA_Scatty_KHARIMSuccess_01_05"],"lines":[{"speaker":"npc","text":{"pl":"I pokonałeś go! Muszę przyznać, że świetnie sobie poradziłeś. Kharim od dawna uchodził za jednego z najlepszych wojowników w kolonii.","en":"And you knocked him down! I have to admit that wasn''t bad going. He''s always been known as one of the toughest fighters.","de":"Und du hast ihn umgehauen! Ich muss schon sagen, nicht schlecht. Er war immer einer der besten Kämpfer hier."}},{"speaker":"npc","text":{"pl":"Jestem pod wrażeniem!","en":"I''m deeply impressed!","de":"Du hast mich schwer beeindruckt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_kharimsuccess_15_00_0', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_kharimsuccess_15_00_0","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_KHARIMSuccess_Info","outputIds":["DIA_Scatty_KHARIMSuccess_15_00","DIA_Scatty_KHARIMSuccess_01_01","DIA_Scatty_KHARIMSuccess_01_02","DIA_Scatty_KHARIMSuccess_01_03"],"lines":[{"speaker":"hero","text":{"pl":"Wyzwałem Kharima na pojedynek!","en":"I challenged Kharim!","de":"Ich bin gegen Kharim angetreten!"}},{"speaker":"npc","text":{"pl":"I spuścił ci niezłe baty!","en":"And boy, did he whack you!","de":"Er hat dir ganz schön in den Arsch getreten."}},{"speaker":"npc","text":{"pl":"Ale muszę przyznać, że wybrałeś sobie dobrego przeciwnika. Nie znoszę tych sukinsynów z Nowego Obozu.","en":"Still, you chose the right opponent! I just can''t stand those bastards from the New Camp.","de":"Trotzdem hast du dir den richtigen Gegner gewählt! Ich kann diese Bastarde aus dem Neuen Lager nicht ausstehen."}},{"speaker":"npc","text":{"pl":"Widzę, że myślimy podobnie. Przyda się nam ktoś taki jak ty!","en":"Seems like you feel the same way - you''re just the kind of guy we need!","de":"Scheint dir ja genauso zu gehen - so jemanden können wir hier brauchen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_kirgo_success_15_00_0', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_kirgo_success_15_00_0","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_KirgoSuccess_Info","outputIds":["DIA_Scatty_KirgoSuccess_15_00","DIA_Scatty_KirgoSuccess_01_01","DIA_Scatty_KirgoSuccess_01_02","DIA_Scatty_KirgoSuccess_01_03"],"lines":[{"speaker":"hero","text":{"pl":"Walczyłem z Kirgo!","en":"I fought Kirgo!","de":"Ich habe gegen Kirgo gekämpft!"}},{"speaker":"npc","text":{"pl":"Tak, ale przegrałeś!","en":"Yeah, and you lost!","de":"Und du hast dich besiegen lassen!"}},{"speaker":"npc","text":{"pl":"Chyba nie myślisz, że będę pod wrażeniem takiego popisu...","en":"Surely you don''t expect me to be impressed by that...","de":"Du erwartest hoffentlich nicht, dass ich durch dein Versagen beeindruckt bin ..."}},{"speaker":"npc","text":{"pl":"I pokonałeś go! Całkiem nieźle jak na takiego żółtodzioba! Jestem pod wrażeniem!","en":"And you defeated him! That''s not bad for a beginner like you! I''m impressed!","de":"Und du hast ihn geschafft! Nicht schlecht für einen Anfänger wie dich! Ich bin beeindruckt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_other_camps_15_00_0', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_other_camps_15_00_0","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_OtherCamps_Info","outputIds":["DIA_Scatty_OtherCamps_15_00","DIA_Scatty_OtherCamps_01_01","DIA_Scatty_OtherCamps_01_02","DIA_Scatty_OtherCamps_01_03"],"lines":[{"speaker":"hero","text":{"pl":"Myślałem, że Stary i Nowy Obóz nie dogadują się najlepiej. Dlaczego pozwalacie obcym walczyć na waszej arenie?","en":"I thought that the Old Camp and the New Camp didn''t get on - so why d''you let their people fight here?","de":"Ich dachte, das Alte und das Neue Lager verstehen sich nicht besonders gut - wieso lasst ihr ihre Leute hier kämpfen?"}},{"speaker":"npc","text":{"pl":"To proste. Raz w tygodniu organizujemy walki, a Kopacze lubią patrzeć, jak Szkodniki z Nowego Obozu dostają po głowie.","en":"It''s simple: There''s fights here once a week, and the diggers always like to see one of the rogues from the New Camp get flattened.","de":"Ganz einfach: Wenn es hier einmal die Woche einen Kampf gibt, sehen es die Buddler am liebsten, wenn einer der Banditen aus dem Neuen Lager was aufs Maul bekommt."}},{"speaker":"npc","text":{"pl":"Gdy walczy któryś z nich przyjmuję więcej zakładów, a to dobrze wpływa na interes!","en":"If one of them fights, there''s more bets - and that''s good for business!","de":"Wenn einer von denen kämpft, wird mehr gewettet - das ist gut!"}},{"speaker":"npc","text":{"pl":"Osobiście nienawidzę tych wieprzy z Nowego Obozu, ale w tych trudnych czasach żaden pieniądz nie śmierdzi...","en":"Personally, I can''t stand the swines from the New Camp - but business is business...","de":"Ich persönlich kann die Schweine aus dem Neuen Lager ja nicht ausstehen - aber Geschäft ist nun mal Geschäft ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_wanna_bet_15_00_0', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_wanna_bet_15_00_0","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_WannaBet_Info","outputIds":["DIA_Scatty_WannaBet_15_00","DIA_Scatty_WannaBet_01_01","DIA_Scatty_WannaBet_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym obstawić walkę.","en":"I want to place a bet.","de":"Ich will wetten."}},{"speaker":"npc","text":{"pl":"Przecież teraz nikt nie walczy!","en":"But there''s no fight on.","de":"Aber im Moment findet kein Kampf statt."}},{"speaker":"npc","text":{"pl":"Najbliższa walka odbędzie się dopiero za kilka dni. Będzie ogłoszenie!","en":"The next fight''s due in a couple of days. There''ll be an announcement.","de":"Der nächste Kampf ist in ein paar Tagen - er wird vorher angekündigt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_wanna_fight_15_00_0', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_wanna_fight_15_00_0","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_WannaFight_Info","outputIds":["DIA_Scatty_WannaFight_15_00","DIA_Scatty_WannaFight_01_01","DIA_Scatty_WannaFight_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym stoczyć walkę na arenie.","en":"I want to fight in the arena!","de":"Ich will in der Arena kämpfen!"}},{"speaker":"npc","text":{"pl":"Nie mogę ci pozwolić walczyć, póki nie dołączysz do któregoś z obozów.","en":"I can''t let you fight until you''ve joined one of the camps!","de":"Bevor du nicht einem der Lager angehörst, werde ich dich nicht kämpfen lassen!"}},{"speaker":"npc","text":{"pl":"Ludzi nie interesują niezależni wojownicy.","en":"Nobody wants to see an independent fighter!","de":"Einen unabhängigen Kämpfer will hier keiner sehen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_210_scatty_dia_scatty_what_do_you_do_15_00_0', 'GRD_210_Scatty', '{"id":"missions_dia_grd_210_scatty_dia_scatty_what_do_you_do_15_00_0","npcId":"GRD_210_Scatty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_210_Scatty.d","sourceFunction":"DIA_Scatty_WhatDoYouDo_Info","outputIds":["DIA_Scatty_WhatDoYouDo_15_00","DIA_Scatty_WhatDoYouDo_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Czym się tutaj zajmujesz?","en":"What''s your job here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Organizuję walki na arenie. Przyjmuję zakłady, pozyskuję nowych wojowników... No wiesz.","en":"I''m in charge of the arena. I organize the bets, hire new fighters... You know.","de":"Ich kümmere mich um die Arena. Organisiere die Wetten, heuere neue Kämpfer an und so weiter ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_first_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_first_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_First_Info","outputIds":["DIA_Skip_First_15_00","DIA_Skip_First_12_01","DIA_Skip_First_15_02","DIA_Skip_First_12_03"],"lines":[{"speaker":"hero","text":{"pl":"Czym się tutaj zajmujesz?","en":"What do you do here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Dbam o broń strażników.","en":"I take care of the guards'' weapons.","de":"Ich kümmere mich um die Waffen der Gardisten."}},{"speaker":"hero","text":{"pl":"Sprzedajesz oręż?","en":"D''you sell weapons?","de":"Verkaufst du Waffen?"}},{"speaker":"npc","text":{"pl":"Też, ale tylko Gomezowi i jego ludziom.","en":"Only to Gomez and his men.","de":"Nur an Gomez'' Leute."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_first_gomez_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_first_gomez_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_First_Gomez","outputIds":["DIA_Skip_First_Gomez_15_00","DIA_Skip_First_Gomez_12_01","DIA_Skip_First_Gomez_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Gomez. Podobno masz dla mnie jakieś wyposażenie.","en":"Gomez sent me. He told me you''d give me some equipment.","de":"Gomez hat mich zu dir geschickt. Ich soll mich ausrüsten lassen."}},{"speaker":"npc","text":{"pl":"To co zwykle, tak? Nowy pancerz i najlepsza broń, jaką mam na składzie.","en":"The usual, eh? New armor and the best weapon I have in stock.","de":"Also das Übliche: ''Ne neue Rüstung und die beste Waffe, die ich da habe."}},{"speaker":"npc","text":{"pl":"Wynoś się, albo cię stąd wyniosą!","en":"Get out of here, before I come after you!","de":"Mach, dass du wegkommst, oder ich zieh'' dir das Fell über die Ohren!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_first_thorus_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_first_thorus_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_First_Thorus","outputIds":["DIA_Skip_First_Thorus_15_00","DIA_Skip_First_Thorus_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Thorus. Kazał mi wybrać sobie jakąś broń.","en":"Thorus sent me. He told me to get myself a weapon.","de":"Thorus hat mich zu dir geschickt. Ich soll mir ''ne Waffe besorgen."}},{"speaker":"npc","text":{"pl":"Czyżby?","en":"Oh?","de":"So?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_first_thorus_ask_him_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_first_thorus_ask_him_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_First_Thorus_AskHim","outputIds":["DIA_Skip_First_Thorus_AskHim_15_00","DIA_Skip_First_Thorus_AskHim_12_01","DIA_Skip_First_Thorus_AskHim_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Jeśli mi nie wierzysz, idź i sam go zapytaj.","en":"Why don''t you go and ask him?","de":"Geh und frag ihn."}},{"speaker":"npc","text":{"pl":"Oczywiście, że zapytam! Ale nie teraz. Założę się, że zainteresują go historie, które o nim opowiadasz.","en":"You bet I will. But not right now. I bet he''ll be interested to hear the stories you''re telling about him.","de":"Mach'' ich glatt. Aber nicht jetzt. Interessiert ihn bestimmt, was du über ihn erzählst."}},{"speaker":"npc","text":{"pl":"Nie wiem kto cię tu wpuścił, ale radziłbym ci wynosić się stąd, póki jeszcze możesz.","en":"I don''t know who let you in here, but you''d better take the shortest way out again!","de":"Ich weiß nicht, wer dich hier reingelassen hat, aber du solltest schleunigst wieder verschwinden!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_first_thorus_kick_ass_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_first_thorus_kick_ass_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_First_Thorus_KickAss","outputIds":["DIA_Skip_First_Thorus_KickAss_15_00","DIA_Skip_First_Thorus_KickAss_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Powiedział, że mam ci dać porządnego kopa w dupę jeśli będziesz sprawiał kłopoty.","en":"He said to give you a mighty big kick in the butt unless you give me a weapon.","de":"Er hat gesagt, wenn du keine Waffe rausrückst, soll ich dir einen kräftigen Tritt in den Hintern geben."}},{"speaker":"npc","text":{"pl":"Naprawdę? Wiesz co? Zrobimy inaczej: jeśli nie wyjdziesz stąd w tej chwili, to TY dostaniesz kopa w dupę!","en":"Oh yeah? The way I see it, unless you get out of here a bit fast, I''ll be the one kicking YOUR butt!","de":"Ach? Ich glaube, wenn du hier nicht gleich verschwunden bist, gebe ich DIR einen Tritt in den Hintern!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_first_thorus_kick_ass_again_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_first_thorus_kick_ass_again_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_First_Thorus_KickAssAGAIN","outputIds":["DIA_Skip_First_Thorus_KickAssAGAIN_15_00","DIA_Skip_First_Thorus_KickAssAGAIN_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Powiedział, że mam ci dać porządnego kopa w dupę jeśli będziesz sprawiał kłopoty.","en":"He said to give you a mighty big kick in the butt unless you give me a weapon.","de":"Er hat gesagt, wenn du keine Waffe rausrückst, soll ich dir einen kräftigen Tritt in den Hintern geben."}},{"speaker":"npc","text":{"pl":"Dobra, stary, czego potrzebujesz?","en":"Okay, man, what do you want?","de":"Schon gut, Mann, was willst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_first_thorus_stranger_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_first_thorus_stranger_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_First_Thorus_Stranger","outputIds":["DIA_Skip_First_Thorus_Stranger_15_00","DIA_Skip_First_Thorus_Stranger_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Widzisz, mam zrobić dla niego coś, czego nie może zrobić żaden z ludzi Gomeza.","en":"He wants me to do something for him that none of you can do, you see?","de":"Ich soll für ihn ''ne Sache erledigen, die keiner von euch machen kann - du verstehst."}},{"speaker":"npc","text":{"pl":"Tak? I pewnie stary Thorus nie ma nic lepszego do roboty niż przysyłać cię do mnie, co?","en":"Yeah? And I suppose he has nothing better to do than send you to me, right?","de":"Ach? Und da hat er nichts Besseres zu tun, als dich zu mir zu schicken?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_dia_skip_verpatzt_15_00_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_dia_skip_verpatzt_15_00_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"DIA_Skip_VERPATZT_Info","outputIds":["DIA_Skip_VERPATZT_15_00","DIA_Skip_VERPATZT_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Pomyślałem, że zajrzę do ciebie i zapytam o to wyposażenie...","en":"I just thought I''d come back and ask about that equipment...","de":"Ich dachte, ich frag'' noch mal wegen der Ausrüstung ..."}},{"speaker":"npc","text":{"pl":"Spadaj!","en":"Beat it!","de":"Zisch ab!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_211_skip_grd_211_skip_welcome_info_12_01_0', 'GRD_211_Skip', '{"id":"missions_dia_grd_211_skip_grd_211_skip_welcome_info_12_01_0","npcId":"GRD_211_Skip","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_211_Skip.d","sourceFunction":"GRD_211_Skip_WELCOME_Info","outputIds":["GRD_211_Skip_WELCOME_Info_12_01"],"lines":[{"speaker":"npc","text":{"pl":"Hej, daleko zaszedłeś, jak na kogoś, kto jest tu tak krótko.","en":"Hey, you''ve made it pretty far, considering you ain''t been here long!","de":"Hey, dafür dass du noch nicht so lange hier bist, hast du es ziemlich weit gebracht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone_06_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone_06_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone_Info","outputIds":["DIA_GRD_219_Stone_06_01"],"lines":[{"speaker":"npc","text":{"pl":"Czego chcesz? Nie wyglądasz mi na jednego z siepaczy Gomeza.","en":"What do you want? You don''t look like one of Gomez'' henchmen?","de":"Was willst du, du siehst nicht aus wie einer von Gomez'' Schergen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone1_06_09_8', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone1_06_09_8","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone1_Info","outputIds":["DIA_GRD_219_Stone1_06_09","DIA_GRD_219_Stone1_06_10"],"lines":[{"speaker":"npc","text":{"pl":"Cóż, wielkie dzięki...","en":"Well, thank you...","de":"Habe Dank ..."}},{"speaker":"npc","text":{"pl":"...Jestem ci niezmiernie wdzięczny. Wpadnij kiedyś do mojej kuźni, to pogadamy.","en":"... I''m much obliged to you. Come and see me at the smithy, we can talk there.","de":"... ich stehe in deiner Schuld, triff mich in der Schmiede, dort reden wir weiter."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone1_15_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone1_15_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone1_Info","outputIds":["DIA_GRD_219_Stone1_15_01","DIA_GRD_219_Stone1_06_02","DIA_GRD_219_Stone1_15_03","DIA_GRD_219_Stone1_06_04"],"lines":[{"speaker":"hero","text":{"pl":"Masz rację, nie pracuję dla Gomeza.","en":"You''re right, I''m not with Gomez.","de":"Stimmt, ich gehöre nicht zu Gomez."}},{"speaker":"npc","text":{"pl":"Więc jak się tutaj dostałeś? Tylko Gomez ma klucz do lochów...","en":"Then how did you get here? Gomez had the key to the dungeons...","de":"Wie bist du dann hier rein gekommen? Gomez hatte den Schlüssel zum Kerker."}},{"speaker":"hero","text":{"pl":"Dostałem go od niego.","en":"He gave it to me.","de":"Er hat ihn mir überlassen."}},{"speaker":"npc","text":{"pl":"Chcesz powiedzieć, że to ty załatwiłeś Gomeza?","en":"Are you trying to tell me YOU''re the guy that wiped out Gomez?","de":"Du willst doch nicht andeuten, dass DU Gomez aus dem Weg geräumt hast?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone1_15_05_4', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone1_15_05_4","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone1_Info","outputIds":["DIA_GRD_219_Stone1_15_05","DIA_GRD_219_Stone1_06_06","DIA_GRD_219_Stone1_06_07","DIA_GRD_219_Stone1_15_08"],"lines":[{"speaker":"hero","text":{"pl":"Dokładnie.","en":"That''s me.","de":"Doch, will ich."}},{"speaker":"npc","text":{"pl":"Stary, nie wiedziałem, że stać cię na coś takiego. Ale cieszę się, że ten przeklęty bandzior dostał wreszcie co mu się należało.","en":"Boy, I never thought you had it in you. But I''m glad the dirty cut-throat finally got what was coming to him.","de":"Junge, das hätte ich dir gar nicht zugetraut, es freut mich aber, dass dieser dreckige Halsabschneider endlich das bekommen hat, was er verdient."}},{"speaker":"npc","text":{"pl":"Ale dlaczego mnie uwolniłeś?","en":"But why are you releasing me?","de":"Aber warum hast du mich befreit?"}},{"speaker":"hero","text":{"pl":"Usłyszałem, że siedzisz tu zamknięty i pomyślałem, że mógłbym załatwić Gomeza i zwrócić ci wolność.","en":"I just heard you''d been locked away and I thought I''d take the opportunity of getting Gomez out of the way and rescuing you.","de":"Ich habe gehört, dass du im Kerker bist, und habe die Gelegenheit genutzt, um Gomez ruhig zu stellen und dich zu befreien."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone2_15_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone2_15_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone2_Info","outputIds":["DIA_GRD_219_Stone2_15_01","DIA_GRD_219_Stone2_06_02","DIA_GRD_219_Stone2_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego Gomez kazał zamknąć cię w lochu?","en":"Why did they lock you in the dungeons?","de":"Warum hat man dich in den Kerker geworfen?"}},{"speaker":"npc","text":{"pl":"Ten sukinsyn ubzdurał sobie, że spiskuje potajemnie z Magami Ognia. Nie zabił mnie tylko dlatego, że jestem najlepszym kowalem w całym Starym Obozie.","en":"Gomez - the bastard - claimed I was in cahoots with the fire mages. The only reason he didn''t kill me is because I''m the best smith in the whole Old Camp.","de":"Gomez! Der Bastard hat mir unterstellt, dass ich gemeinsame Sache mit den Feuermagiern machen würde. Nur weil ich der beste Schmied im Alten Lager bin, konnte ich meinen Kopf retten."}},{"speaker":"npc","text":{"pl":"No i wrzucił mnie do tej zapluskwionej celi i wypuszczał tylko wtedy, gdy była dla mnie jakaś robota.","en":"So he threw me into the rat''s nest and only let me out when he needed me to make something for him.","de":"Er hat mich in dieses Rattenloch werfen lassen und immer nur dann rausgelassen, wenn er meine Fähigkeiten gebraucht hat."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone3_06_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone3_06_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone3_Info","outputIds":["DIA_GRD_219_Stone3_06_01","DIA_GRD_219_Stone3_06_02","DIA_GRD_219_Stone3_06_03"],"lines":[{"speaker":"npc","text":{"pl":"Ach, jesteś. Mam u ciebie dług wdzięczności za wypuszczenie mnie z lochu!","en":"There you are. I owe you for getting me out of that rat''s nest, man!","de":"Da bist du ja. Da du mich aus diesem Rattenloch befreit hast, hast du was gut bei mir, Mann!"}},{"speaker":"npc","text":{"pl":"Wiesz, tak sobie myślę: nie mam nic cennego, co mógłbym ci dać, więc może zamiast tego wykuję dla ciebie coś specjalnego.","en":"You know, I was thinking: There''s not much I can give you, so I''ll forge something for you.","de":"Ich habe mir überlegt, da es nicht viel gibt, was ich dir geben kann, werde ich dir etwas schmieden."}},{"speaker":"npc","text":{"pl":"Może jakiś pierścień, albo coś w tym stylu...","en":"Maybe a ring or some such thing...","de":"Könnte ein Ring sein oder etwas Vergleichbares ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone4_15_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone4_15_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone4_Info","outputIds":["DIA_GRD_219_Stone4_15_01","DIA_GRD_219_Stone4_06_02","DIA_GRD_219_Stone4_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Możesz dla mnie wzmocnić tę magiczną zbroję?","en":"Can you reinforce this ore armor for me?","de":"Kannst du mir diese Erzrüstung verstärken?"}},{"speaker":"npc","text":{"pl":"Jasne! Daj mi ją i zaczekaj chwilę.","en":"Sure I can. Hand it over and hang on a minute.","de":"Natürlich kann ich sie verstärken? Gib sie mir und warte kurz."}},{"speaker":"npc","text":{"pl":"Oto twoja wzmocniona zbroja. Teraz jesteśmy kwita.","en":"Here is the reinforced armor. We''re quits now.","de":"Hier ist die verstärkte Rüstung, damit habe ich meine Schuld beglichen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone5_15_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone5_15_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone5_Info","outputIds":["DIA_GRD_219_Stone5_15_01","DIA_GRD_219_Stone5_06_02","DIA_GRD_219_Stone5_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Przydał by mi się pierścień wzmacniający witalność.","en":"I could use a ring to increase my life energy.","de":"Ich könnte einen Ring gebrauchen, der meine Lebenskraft steigert."}},{"speaker":"npc","text":{"pl":"To nie powinno być zbyt trudne. Zaczekaj.","en":"That''s not difficult, hold on.","de":"Das ist nicht so schwer, warte kurz."}},{"speaker":"npc","text":{"pl":"Ten pierścień zwiększy twoje siły witalne. Myślę, że po takim prezencie jesteśmy kwita.","en":"This ring will give you extra life energy. That should be more than enough to settle the score between us.","de":"Dieser Ring verleiht dir Lebenskraft, damit müsste meine Schuld mehr als beglichen sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone6_15_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone6_15_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone6_Info","outputIds":["DIA_GRD_219_Stone6_15_01","DIA_GRD_219_Stone6_06_02","DIA_GRD_219_Stone6_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym, żebyś wykuł dla mnie pierścień ochronny.","en":"I want you to forge me a protection ring.","de":"Ich will einen Schutzring geschmiedet haben."}},{"speaker":"npc","text":{"pl":"Pierścień ochronny? Nie ma sprawy! Od razu wezmę się do roboty. Zaczekaj chwilę.","en":"A protection ring? Okay, I''ll start right away. Just wait a while.","de":"Einen Schutzring, dann gehe ich an die Arbeit. Warte solange."}},{"speaker":"npc","text":{"pl":"Chciałeś pierścień ochronny? Oto on! Teraz jesteśmy kwita.","en":"You asked for a protection ring, you have one, so now we''re quits.","de":"Einen Schutzring wolltest du, hier ist er, jetzt sind wir quitt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_grd_219_stone7_15_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_grd_219_stone7_15_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone7_Info","outputIds":["DIA_GRD_219_Stone7_15_01","DIA_GRD_219_Stone7_06_02","DIA_GRD_219_Stone7_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję czegoś, co zwiększy moje umiejętności magiczne.","en":"Make me something to increase my magic powers.","de":"Schmiede mir einen Gegenstand, der meine magische Energie vermehrt."}},{"speaker":"npc","text":{"pl":"...Zwiększy umiejętności magiczne, powiadasz? Może jakiś amulet! Tak, zrobię dla ciebie magiczny amulet. To nie potrwa długo.","en":"... Something to increase magic powers...? An amulet! That''s it, I''ll forge an amulet for you. It won''t take long.","de":"... Einen Gegenstand, der magische Energie vermehrt ... ein Amulett, ich schmiede dir ein Amulett. Das dauert nicht lange."}},{"speaker":"npc","text":{"pl":"Dobra, amulet gotowy. Muszę przyznać, że wyszedł całkiem nieźle. Proszę, teraz jesteśmy kwita.","en":"Right, the amulet''s finished, and I must say I''ve made a good job of it. We''re quits now.","de":"So, das Amulett ist fertig, und ich muss sagen, es ist mir gut gelungen. Somit ist die Schuld beglichen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_dia_stone_hello_15_00_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_dia_stone_hello_15_00_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_Stone_Hello_Info","outputIds":["DIA_Stone_Hello_15_00","DIA_Stone_Hello_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Jesteś kowalem, czyż nie?","en":"You''re the smith, aren''t you?","de":"Du bist der Schmied, richtig?"}},{"speaker":"npc","text":{"pl":"Racja.","en":"That''s right.","de":"Richtig."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_grd_219_stone_getstuff_info_15_01_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_grd_219_stone_getstuff_info_15_01_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"GRD_219_Stone_GETSTUFF_Info","outputIds":["GRD_219_Stone_GETSTUFF_Info_15_01","GRD_219_Stone_GETSTUFF_Info_06_02","GRD_219_Stone_GETSTUFF_Info_06_03","GRD_219_Stone_GETSTUFF_Info_06_04"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję zbroi.","en":"I need armor.","de":"Ich brauche eine Rüstung."}},{"speaker":"npc","text":{"pl":"A więc Thorus jednak cię przyjął, co? Gratuluję!","en":"So, Thorus has accepted you, eh? Congratulations!","de":"Thorus hat dich in die Truppe aufgenommen? Glückwunsch!"}},{"speaker":"npc","text":{"pl":"Jeszcze jeden, któremu spieszno przelać krew za Gomeza. A zresztą - co mnie to obchodzi?","en":"Another one eager to stick his neck out for Gomez. Oh well, what do I care?","de":"Wieder einer mehr, der seinen Hals für Gomez in die Schlinge legt. Na, mir soll''s recht sein."}},{"speaker":"npc","text":{"pl":"Masz - weź tę broń i miecz. Witamy w straży.","en":"Here, takes this armor and sword. Welcome to the Guards.","de":"Hier, nimm die Rüstung und dieses Schwert. Willkommen bei der Garde."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_219_stone_info_exit_06_02_0', 'GRD_219_Stone', '{"id":"missions_dia_grd_219_stone_info_exit_06_02_0","npcId":"GRD_219_Stone","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_219_Stone.d","sourceFunction":"DIA_GRD_219_Stone_Exit_Info","outputIds":["Info_EXIT_06_02","Info_EXIT_06_03"],"lines":[{"speaker":"npc","text":{"pl":"Do zobaczenia.","en":"I''ll see you.","de":"Wir sehen uns."}},{"speaker":"npc","text":{"pl":"Do zobaczenia.","en":"I''ll see you.","de":"Wir sehen uns."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_224_pacho_info_pacho_stop_13_01_0', 'GRD_224_Pacho', '{"id":"missions_dia_grd_224_pacho_info_pacho_stop_13_01_0","npcId":"GRD_224_Pacho","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_224_Pacho.d","sourceFunction":"Info_Pacho_STOP_Info","outputIds":["Info_Pacho_STOP_13_01","Info_Pacho_STOP_15_02","Info_Pacho_STOP_13_03","Info_Pacho_STOP_13_04"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey, du!"}},{"speaker":"hero","text":{"pl":"Kto? Ja?","en":"Who? Me?","de":"Wer? Ich?"}},{"speaker":"npc","text":{"pl":"Nie, twoja babcia... Jasne, że ty!!!","en":"No, your grandmother... Who else could I mean?!","de":"Nein, ich mein deine Großmutter ... Natürlich mein ich dich!"}},{"speaker":"npc","text":{"pl":"Na twoim miejscu nie szedłbym dalej!","en":"I wouldn''t go down that way if I were you!","de":"Wenn ich du wäre, dann würde ich diesen Weg hier nicht weitergehen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_224_pacho_info_pacho_stop_15_05_4', 'GRD_224_Pacho', '{"id":"missions_dia_grd_224_pacho_info_pacho_stop_15_05_4","npcId":"GRD_224_Pacho","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_224_Pacho.d","sourceFunction":"Info_Pacho_STOP_Info","outputIds":["Info_Pacho_STOP_15_05","Info_Pacho_STOP_13_06","Info_Pacho_STOP_13_07","Info_Pacho_STOP_13_08"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego?","en":"Why not?","de":"Warum nicht?"}},{"speaker":"npc","text":{"pl":"Widzę, że jesteś tu nowy, co?","en":"You can''t have been here long!","de":"Du scheinst wirklich neu hier zu sein!"}},{"speaker":"npc","text":{"pl":"Stary, ta droga prowadzi na ziemie Orków...","en":"Man, that''s the way to the Orc land...","de":"Mann, hier geht es ins Orkgebiet!"}},{"speaker":"npc","text":{"pl":"Zrobią z ciebie kotlety!","en":"They''ll make mincemeat out of you!","de":"Die machen Kleinholz aus dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_224_pacho_info_pacho_stop_15_09_8', 'GRD_224_Pacho', '{"id":"missions_dia_grd_224_pacho_info_pacho_stop_15_09_8","npcId":"GRD_224_Pacho","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_224_Pacho.d","sourceFunction":"Info_Pacho_STOP_Info","outputIds":["Info_Pacho_STOP_15_09","Info_Pacho_STOP_13_10"],"lines":[{"speaker":"hero","text":{"pl":"Och!","en":"Oh.","de":"Oh."}},{"speaker":"npc","text":{"pl":"Nie ma za co!","en":"You''re welcome!","de":"Gern geschehen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_grd_233_bloodwyn_welcome_info_08_01_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_grd_233_bloodwyn_welcome_info_08_01_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"GRD_233_Bloodwyn_WELCOME_Info","outputIds":["GRD_233_Bloodwyn_WELCOME_Info_08_01"],"lines":[{"speaker":"npc","text":{"pl":"Teraz jesteś jednym z nas! Dobra robota! Straży przyda się ktoś taki jak ty!","en":"You''re one of us now. Well done. The Guards need men like you!","de":"Du gehörst jetzt zu uns. Gute Arbeit. Die Garde braucht Männer wie dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_die_08_05_4', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_die_08_05_4","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_DIE_Info","outputIds":["Info_Bloodwyn_DIE_08_05","Info_Bloodwyn_DIE_15_06","Info_Bloodwyn_DIE_08_07","Info_Bloodwyn_DIE_15_08"],"lines":[{"speaker":"npc","text":{"pl":"Spiknąłeś się z Nowym Obozem, tak?","en":"So you''re in cahoots with the New Camp, huh?","de":"Machst gemeinsame Sache mit dem Neuen Lager, was?"}},{"speaker":"hero","text":{"pl":"Nie, czekaj! Ja dalej...","en":"No, wait, I''m still...","de":"Warte mal, ich bin doch noch immer ..."}},{"speaker":"npc","text":{"pl":"Co, myślałeś, że damy się tak łatwo wykiwać, hę?","en":"Guess you must have thought you could go on like that forever.","de":"Glaubtest wohl, das könnte ewig so gehen."}},{"speaker":"hero","text":{"pl":"Przestań gadać od rzeczy...","en":"Stop this nonsense...","de":"Jetzt hör aber auf mit diesem Unsinn ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_die_08_09_8', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_die_08_09_8","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_DIE_Info","outputIds":["Info_Bloodwyn_DIE_08_09","Info_Bloodwyn_DIE_08_10","Info_Bloodwyn_DIE_08_11","Info_Bloodwyn_DIE_08_12"],"lines":[{"speaker":"npc","text":{"pl":"Zdrajcy tacy jak ty zasługują tylko na śmierć.","en":"Traitors like you must die.","de":"Verräter wie dich machen wir kalt."}},{"speaker":"npc","text":{"pl":"GIŃ!!!","en":"DIE, TRAITOR!!!","de":"STIRB, ABTRÜNNIGER!!!"}},{"speaker":"npc","text":{"pl":"Postanowiłeś zobaczyć, jak wygląda świat na zewnątrz Nowego Obozu, co? To był błąd!","en":"So you''ve ventured out of your New Camp? That was mighty stupid of you!","de":"Du wagst dich tatsächlich aus deinem Neuen Lager heraus? Wie dumm von dir!"}},{"speaker":"npc","text":{"pl":"No proszę, znudził ci się twój nowy dom na bagnach? Popełniłeś błąd przychodząc tutaj.","en":"Oh, so you''ve ventured out of your swamp camp? That was mighty stupid of you!","de":"Du wagst dich tatsächlich aus deinem Sumpflager heraus? Wie dumm von dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_die_15_13_12', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_die_15_13_12","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_DIE_Info","outputIds":["Info_Bloodwyn_DIE_15_13","Info_Bloodwyn_DIE_08_14","Info_Bloodwyn_DIE_15_15","Info_Bloodwyn_DIE_08_16"],"lines":[{"speaker":"hero","text":{"pl":"Co? O co ci chodzi?!","en":"What? What do you mean?","de":"Was soll das? Was meinst du?"}},{"speaker":"npc","text":{"pl":"Nie słyszałeś o ataku na waszą kopalnię?","en":"Haven''t you heard about the attack on your mine?","de":"Hast wohl noch nichts von unserem Überfall auf eure Mine gehört, was?"}},{"speaker":"hero","text":{"pl":"Chwileczkę...","en":"What...","de":"Moment mal ..."}},{"speaker":"npc","text":{"pl":"Przykro mi, ale nie możemy pozwolić, żebyś o tym komuś powiedział!","en":"Sorry, but we can''t let you go shooting your mouth off!","de":"Leider können wir es nicht zulassen, dass du das irgendwo herumerzählst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_die_15_17_16', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_die_15_17_16","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_DIE_Info","outputIds":["Info_Bloodwyn_DIE_15_17","Info_Bloodwyn_DIE_08_18","Info_Bloodwyn_DIE_15_19","Info_Bloodwyn_DIE_08_20"],"lines":[{"speaker":"hero","text":{"pl":"Hej, nie chcę żadnych kłopotów...","en":"Hey, I don''t want any trouble...","de":"Hey, ich will keinen Streit ..."}},{"speaker":"npc","text":{"pl":"Trzeba było o tym pomyśleć trochę wcześniej!","en":"You should''ve thought of that before!","de":"Das hättest du dir vorher überlegen sollen!"}},{"speaker":"hero","text":{"pl":"Słuchaj, mam tego serdecznie dość...","en":"Look, I''ve had about enough of this...","de":"Jetzt ist es aber genug ..."}},{"speaker":"npc","text":{"pl":"Ja też! ZABIĆ GO!!!","en":"So have I! KILL HIM!","de":"Richtig! TÖTET IHN!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_doch_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_doch_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Doch_Info","outputIds":["Info_Bloodwyn_Doch_15_00","Info_Bloodwyn_Doch_08_01","Info_Bloodwyn_Doch_08_02","Info_Bloodwyn_Doch_NoOre_08_00"],"lines":[{"speaker":"hero","text":{"pl":"Zmieniłem zdanie. Postanowiłem jednak zapłacić ci te 10 bryłek rudy.","en":"I''ve changed my mind. I''m going to pay you the 10 ore after all.","de":"Ich hab''s mir überlegt - ich würde DOCH gern die 10 Erz bezahlen."}},{"speaker":"npc","text":{"pl":"Trzeba tak było od razu! Mądry z ciebie gość.","en":"There now! You see, you CAN make the right choices.","de":"Na siehst du! Du kannst ja DOCH die richtige Entscheidung treffen."}},{"speaker":"npc","text":{"pl":"Ale od tej pory będziesz płacił swoją dzienną składkę, co?","en":"And from now on, you''ll keep paying me your daily contribution, won''t you?","de":"Und von jetzt an zahlen wir schön brav täglich unsere Unterstützung, ja?"}},{"speaker":"npc","text":{"pl":"To wróć, jak będziesz miał trochę rudy.","en":"Then come back when you have it.","de":"Dann komm wieder, wenn du sie hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_exit_schutzgeld_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_exit_schutzgeld_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_EXIT_Schutzgeld_Info","outputIds":["Info_Bloodwyn_EXIT_Schutzgeld_15_00","Info_Bloodwyn_EXIT_Schutzgeld_08_01","Info_Bloodwyn_EXIT_Schutzgeld_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Do zobaczenia.","en":"See ya.","de":"Wir sehen uns."}},{"speaker":"npc","text":{"pl":"Trzymaj się, kolego.","en":"Take care of yourself, kid.","de":"Pass gut auf dich auf, Kleiner!"}},{"speaker":"npc","text":{"pl":"W Obozie nie musisz się niczego obawiać. Będziemy mieli na ciebie oko.","en":"Don''t you worry about anything here in the Camp! We''ll be looking out for you.","de":"Mach dir keine Sorgen, während du hier im Lager bist! Wir passen auf dich auf."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_forget_it_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_forget_it_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_ForgetIt","outputIds":["Info_Bloodwyn_ForgetIt_15_00","Info_Bloodwyn_ForgetIt_08_01"],"lines":[{"speaker":"hero","text":{"pl":"To znaczy, że mam ci zapłacić za ochronę? Dzięki, ale nie! Sam sobie dam radę!","en":"You mean you want me to pay protection money? No thanks, I can take care of myself!","de":"Ich soll Schutzgeld zahlen? Ich kann auf mich selbst aufpassen!"}},{"speaker":"npc","text":{"pl":"Jak sobie chcesz, chłopcze. Ale wkrótce pożałujesz, że odrzuciłeś tę przyjacielską propozycję!","en":"Have it your own way, kid. You''ll soon regret turning down a friendly offer!","de":"Wie du meinst, Kleiner. Wirst schon sehen, was du davon hast, ein Freundschaftsangebot abzulehnen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_08_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_08_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_Info","outputIds":["Info_Bloodwyn_Hello_08_00","Info_Bloodwyn_Hello_15_01","Info_Bloodwyn_Hello_08_02","Info_Bloodwyn_Hello_08_03"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey du!"}},{"speaker":"hero","text":{"pl":"Mówisz do mnie?","en":"Are you talking to me?","de":"Redest du mit mir?"}},{"speaker":"npc","text":{"pl":"Ostrzegam cię! Tacy jak ty łatwo mogą napytać sobie biedy!","en":"I''m warning you! People like you can get into trouble awfully quick round here!","de":"Ich will dich warnen! Jemand wie du hat hier schnell Ärger am Hals!"}},{"speaker":"npc","text":{"pl":"W końcu większość z tutejszych ludzi to straszne zbiry!","en":"And most of the guys they chuck in here are bastards!","de":"Und die meisten, die sie hier reingeworfen haben, sind Arschlöcher!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_08_04_4', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_08_04_4","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_Info","outputIds":["Info_Bloodwyn_Hello_08_04","Info_Bloodwyn_Hello_08_05","Info_Bloodwyn_Hello_08_06"],"lines":[{"speaker":"npc","text":{"pl":"Wydaje się im, że mogą tu robić, co im się żywnie podoba. No, ale my im na to nie pozwalamy.","en":"They think they can do what they like to you. But we won''t allow that.","de":"Sie denken, dass sie mit dir machen können, was sie wollen. Aber das lassen wir nicht zu."}},{"speaker":"npc","text":{"pl":"Gomezowi zależy na spokoju w Obozie, a do nas - Strażników - należy dbanie o porządek. Oczywiście jest to bardzo wyczerpujące... i KOSZTOWNE zajęcie.","en":"Gomez wants some peace in the Camp, and we guards make sure he gets it. But it''s a job that doesn''t come cheap.","de":"Gomez will, dass Ruhe im Lager herrscht. Und wir Gardisten sorgen dafür. Aber so eine Aufgabe ist extrem kostspielig."}},{"speaker":"npc","text":{"pl":"Dlatego właśnie chcę cię prosić o drobne wsparcie finansowe... Na znak przyjaźni. Ty pomożesz nam, a my pomożemy tobie. Jeśli będziesz miał kłopoty - możesz na nas liczyć.","en":"That''s why I''m asking you for some ore. Look at it as a kind of token of friendship. You help us, and we''ll help you. If you get in trouble, we''ll be there for you.","de":"Darum bitte ich dich um etwas Erz. Du musst das als Freundschaftsdienst verstehen. Du hilfst uns und wir helfen dir. Wenn du mal Ärger hast, sind wir da."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_how_much_15_01_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_how_much_15_01_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_HowMuch","outputIds":["Info_Bloodwyn_Hello_HowMuch_15_01","Info_Bloodwyn_Hello_HowMuch_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Czemu by nie? Ile mam ci zapłacić?","en":"Why not? How much ore were you thinking of?","de":"Warum nicht. An wie viel Erz hast du denn gedacht?"}},{"speaker":"npc","text":{"pl":"Niewiele. 10 bryłek rudy, to wszystko.","en":"Not much. 10 ore, that''s all I need.","de":"Nicht viel. 10 Erz, mehr brauche ich nicht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_not_now_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_not_now_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_NotNow","outputIds":["Info_Bloodwyn_Hello_NotNow_15_00","Info_Bloodwyn_Hello_NotNow_08_01","Info_Bloodwyn_Hello_NotNow_08_02","Info_Bloodwyn_Hello_NotNow_TenOreMore_08_00"],"lines":[{"speaker":"hero","text":{"pl":"Nie mam tyle przy sobie.","en":"I don''t have 10 ore.","de":"Ich habe gerade keine 10 Erz."}},{"speaker":"npc","text":{"pl":"Trudno. Wezmę co masz. Resztę dopłacisz przy następnym spotkaniu.","en":"Then I''ll take whatever you have - that''s okay. You can give me the rest next time I see you.","de":"Dann nehme ich das, was du hast - ist schon okay. Du kannst ja beim nächsten Mal die volle Summe zahlen."}},{"speaker":"npc","text":{"pl":"Zobaczmy...","en":"Let me see...","de":"Lass mal sehen ..."}},{"speaker":"npc","text":{"pl":"No patrzcie państwo! Ktoś tu nie umie liczyć do 10, co?","en":"Hey, look at that? Looks like someone can''t count to 10, eh?","de":"Na, was haben wir denn da? Kann da jemand nicht bis 10 zählen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_not_now_ten_ore_more_08_01_4', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_not_now_ten_ore_more_08_01_4","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_NotNow","outputIds":["Info_Bloodwyn_Hello_NotNow_TenOreMore_08_01","Info_Bloodwyn_Hello_NotNow_LessThanTen_08_00","Info_Bloodwyn_Hello_NotNow_LessThanTen_08_01","Info_Bloodwyn_Hello_NotNow_NoOre_08_00"],"lines":[{"speaker":"npc","text":{"pl":"Wezmę wszystko co masz. To mi pomoże zapomnieć, że próbowałeś mnie wykiwać.","en":"I''m just gonna take everything you have. That''ll help me forget you lied to me.","de":"Ich werd einfach alles nehmen, was du hast. Dafür vergesse ich, dass du mich belogen hast."}},{"speaker":"npc","text":{"pl":"O, przyjmuję również mniejsze datki. W końcu liczy się pamięć! Dzięki za rudę, chłopcze!","en":"Oh, I take small donations too. It''s the thought that counts! Thanks for the ore, kid!","de":"Ich nehme auch kleine Spenden, es ist der gute Wille, der zählt! Danke für das Erz, Kleiner!"}},{"speaker":"npc","text":{"pl":"Od tej pory będę miał na ciebie oko. W Obozie nic ci już nie grozi.","en":"From now on, I''ll be watching out for you whenever you''re in the Camp.","de":"Von jetzt an werden wir ein Auge auf dich haben, solange du im Lager bist."}},{"speaker":"npc","text":{"pl":"Hmmm, naprawdę jesteś spłukany, co? Trudno. Może innym razem...","en":"Hm, you really are broke, aren''t you. Well, I guess there''s always next time...","de":"Du hast ja wirklich nichts ... Na, wie gesagt, beim nächsten Mal ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_ok_take_it_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_hello_ok_take_it_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_OkTakeIt","outputIds":["Info_Bloodwyn_Hello_OkTakeIt_15_00","Info_Bloodwyn_Hello_OkTakeIt_08_01","Info_Bloodwyn_Hello_OkTakeIt_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Proszę, oto ruda. Przyjaciół nigdy nie za wielu.","en":"Here''s your ore. I can always use a friend or two.","de":"Hier hast du das Erz. Ich kann Freunde gebrauchen."}},{"speaker":"npc","text":{"pl":"Widzę, że mądry z ciebie gość. Od tej pory będziemy cię mieli na oku.","en":"You seem to be a clever lad. From now on, we''ll be watching out for you.","de":"Du scheinst mir ein kluges Bürschchen zu sein. Von nun an werden wir auf dich aufpassen."}},{"speaker":"npc","text":{"pl":"Ale to nie znaczy, że możesz tu robić, co ci się żywnie podoba, jasne?","en":"But that doesn''t mean to say you can do what you like around here, okay?","de":"Aber das heißt nicht, dass du hier machen kannst, was du willst, verstanden?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_08_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_08_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_PayDay_Info","outputIds":["Info_Bloodwyn_PayDay_08_00","Info_Bloodwyn_PayDay_08_01","Info_Bloodwyn_PayDay_Den_08_00","Info_Bloodwyn_PayDay_Den_15_01"],"lines":[{"speaker":"npc","text":{"pl":"Miło cię widzieć, przyjacielu!","en":"Ah, good to see you, my friend!","de":"Gut, dass ich dich treffe, mein Freund!"}},{"speaker":"npc","text":{"pl":"No i jak tam z twoim wsparciem finansowym? Wciąż zalegasz z 10 bryłkami rudy!","en":"How about your daily contribution? Your 10 ore is due, you know.","de":"Wie sieht''s mit deiner täglichen Unterstützung aus? Deine 10 Erz sind wieder mal fällig."}},{"speaker":"npc","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey du!"}},{"speaker":"hero","text":{"pl":"Czego znowu?","en":"Now what?","de":"Was denn jetzt schon wieder?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_den_08_02_4', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_den_08_02_4","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_PayDay_Info","outputIds":["Info_Bloodwyn_PayDay_Den_08_02","Info_Bloodwyn_PayDay_Den_08_03"],"lines":[{"speaker":"npc","text":{"pl":"Pora udowodnić, że jesteś prawdziwym przyjacielem.","en":"The time''s come for you to prove you''re a true friend.","de":"Es ist eine neue Gelegenheit für dich gekommen, dich als Freund zu erweisen."}},{"speaker":"npc","text":{"pl":"Marne 10 bryłek rudy, i wszystko będzie w porządku. Co ty na to?","en":"Just 10 ore, and you''re in - what d''you say?","de":"Mit nur 10 Erz bist du dabei - wie sieht''s aus?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_pay_again_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_pay_again_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_PayDay_PayAgain","outputIds":["Info_Bloodwyn_PayDay_PayAgain_15_00","Info_Bloodwyn_PayDay_PayAgain_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Proszę. Czym jest 10 bryłek rudy wobec prawdziwej przyjaźni.","en":"Here, take it. 10 ore''s not much among friends.","de":"Hier, nimm - 10 Erz sind nicht viel unter Freunden"}},{"speaker":"npc","text":{"pl":"Czytasz w moich myślach!","en":"My thoughts exactly!","de":"Genau so sehe ich das auch."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_pay_no_more_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_day_pay_no_more_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_PayDay_PayNoMore","outputIds":["Info_Bloodwyn_PayDay_PayNoMore_15_00","Info_Bloodwyn_PayDay_PayNoMore_08_01","Info_Bloodwyn_PayDay_PayNoMore_15_02","Info_Bloodwyn_PayDay_PayNoMore_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Nie będę ci więcej płacił. Dość już ode mnie dostałeś!","en":"I''m not paying - you''ve had enough out of me already.","de":"Ich werde nicht mehr zahlen - du hast schon genug gekriegt."}},{"speaker":"npc","text":{"pl":"Zawiodłem się na tobie! Taki z ciebie przyjaciel? Dobrze, jak sobie chcesz! Od tej pory sam dbaj o siebie. Ja umywam ręce.","en":"You disappoint me! We''re not friends anymore. See to it that you don''t get mugged and robbed on your own now!","de":"Du enttäuschst mich! Von nun an sind wir keine Freunde mehr. Du wirst selber aufpassen müssen, dass du nicht von üblen Halunken niedergeschlagen und ausgeraubt wirst."}},{"speaker":"hero","text":{"pl":"Bez obawy. Jakoś sobie poradzę bez twojej pomocy.","en":"Don''t worry, I can take care of myself just fine.","de":"Ich kann ganz gut auf mich selbst aufpassen."}},{"speaker":"npc","text":{"pl":"To się dopiero okaże...","en":"We''ll see...","de":"Das werden wir ja sehen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_for_jesse_08_04_4', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_for_jesse_08_04_4","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_PayForJesse_Info","outputIds":["Info_Bloodwyn_PayForJesse_08_04","Info_Bloodwyn_PayForJesse_15_05","Info_Bloodwyn_PayForJesse_08_06"],"lines":[{"speaker":"npc","text":{"pl":"Dobra, jak sobie chcesz.","en":"Okay, man, if that''s the way you want it.","de":"Wie du willst, Mann - wie du willst."}},{"speaker":"hero","text":{"pl":"Hmmm... Właśnie sobie przypomniałem, że nie mam teraz tyle rudy.","en":"Oh! It looks like I don''t have that much ore on me.","de":"Oh! Ich merke gerade, ich habe gar nicht so viel Erz bei mir."}},{"speaker":"npc","text":{"pl":"To znak, człowieku! Przemyśl to sobie. Płacąc za tego gościa wyrzucasz rudę w błoto!","en":"That''s an omen, man! Think again! Paying for that bum is a waste of good ore!","de":"Das ist ein Zeichen, Mann! Überleg''s dir noch mal! Für den Penner zu zahlen, ist glatte Verschwendung!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_for_jesse_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_pay_for_jesse_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_PayForJesse_Info","outputIds":["Info_Bloodwyn_PayForJesse_15_00","Info_Bloodwyn_PayForJesse_08_01","Info_Bloodwyn_PayForJesse_08_02","Info_Bloodwyn_PayForJesse_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Jesse przysyła mnie, żebym zapłacił jego 10 bryłek.","en":"Jesse sent me to pay his 10 ore for him.","de":"Jesse schickt mich - ich will seine 10 Erz für ihn zahlen."}},{"speaker":"npc","text":{"pl":"Powinieneś raczej zapłacić SWOJE 10 bryłek.","en":"What you should do is pay YOUR 10 ore.","de":"Du solltest lieber DEINE 10 Erz zahlen."}},{"speaker":"npc","text":{"pl":"Zapomnij o tym facecie: Jesse i tak długo nie pociągnie.","en":"Never mind about Jesse. He''s a loser, he''s not got long anyway.","de":"Vergiss Jesse. Er ist ein Verlierer und wird sowieso bald draufgehen."}},{"speaker":"hero","text":{"pl":"Nie - zapłacę za niego. Masz tu jego 10 bryłek i zostaw go w spokoju.","en":"No - I am paying for him. So take his 10 ore and leave him be!","de":"Nein - ich werde für ihn zahlen - hier nimm die 10 Erz und jetzt lass ihn in Ruhe!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_233_bloodwyn_info_bloodwyn_soll_drohung_sein_15_00_0', 'GRD_233_Bloodwyn', '{"id":"missions_dia_grd_233_bloodwyn_info_bloodwyn_soll_drohung_sein_15_00_0","npcId":"GRD_233_Bloodwyn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_233_Bloodwyn.d","sourceFunction":"Info_Bloodwyn_Hello_SollDrohungSein","outputIds":["Info_Bloodwyn_SollDrohungSein_15_00","Info_Bloodwyn_SollDrohungSein_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Grozisz mi?","en":"Is that a threat?","de":"Soll das eine Drohung sein?"}},{"speaker":"npc","text":{"pl":"Wręcz przeciwnie! Oferuję ci pomoc!","en":"On the contrary! It''s an offer of friendship!","de":"Im Gegenteil! Es ist ein Freundschaftsangebot!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_charge_15_00_0', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_charge_15_00_0","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_Charge_Info","outputIds":["Info_Kirgo_Charge_15_00","Info_Kirgo_Charge_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym cię wyzwać na pojedynek na arenie!","en":"I''d like to challenge you to a fight in the arena!","de":"Ich fordere dich zum Kampf in der Arena!"}},{"speaker":"npc","text":{"pl":"Co? Ale ja nie chcę z tobą walczyć! Może napijemy się po prostu piwa i pogadamy o zewnętrznym świecie?","en":"What? But I don''t wanna fight. Why don''t we just have a beer together and talk about the outside world?","de":"Was? Aber ich hab'' gerade keine Lust zu kämpfen. Lass uns doch lieber ein Bier zusammen trinken und erzähl mir was von draußen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_charge_beer_05_08_8', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_charge_beer_05_08_8","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_Charge_Beer","outputIds":["Info_Kirgo_Charge_Beer_05_08","Info_Kirgo_Charge_Beer_05_09"],"lines":[{"speaker":"npc","text":{"pl":"Ale jeśli naprawdę chcesz go do siebie przekonać, powinieneś stawić czoła Kharimowi. Tylko obawiam się, że on może być dla ciebie za dobry!","en":"But if you really want to impress him, it''s Kharim you need to beat. Only thing is, I''m afraid he might be too good for you!","de":"Aber wenn du ihm richtig imponieren willst, müsstest du Kharim umhauen. Ich fürchte nur, er ist viel zu gut für dich!"}},{"speaker":"npc","text":{"pl":"Jeśli nadal chcesz ze mną walczyć, daj mi znać! Chociaż nie chciałbym ci robić krzywdy.","en":"If you still want to fight me, let me know! But I won''t enjoy knocking you out cold.","de":"Falls du immer noch gegen mich kämpfen willst - sag mir Bescheid! Aber ich werd'' dir nicht gerne die Fresse polieren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_charge_beer_15_00_0', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_charge_beer_15_00_0","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_Charge_Beer","outputIds":["Info_Kirgo_Charge_Beer_15_00","Info_Kirgo_Charge_Beer_05_01","Info_Kirgo_Charge_Beer_15_02","Info_Kirgo_Charge_Beer_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Dobra, daj mi piwo!","en":"Okay, give me a beer then!","de":"Okay, gib mir ein Bier rüber!"}},{"speaker":"npc","text":{"pl":"Proszę bardzo!","en":"Here you are!","de":"Hier nimm!"}},{"speaker":"hero","text":{"pl":"Dzięki! Obawiam się, że nie mogę ci zbyt wiele powiedzieć o wydarzeniach na zewnątrz. Prawie dwa miesiące przesiedziałem w ciemnicy. Zaraz potem trafiłem tutaj.","en":"Thanks! I''m afraid I can''t tell you much about the outside world - they kept me locked away in a dark hole for almost two months before throwing me in here.","de":"Danke! Ich fürchte, von draußen kann ich nicht viel erzählen - sie haben mich fast zwei Monate in einem dunklen Loch gefangen gehalten, bevor sie mich hier reingeworfen haben."}},{"speaker":"npc","text":{"pl":"Wielka szkoda... Cóż, trudno... Całkiem nieźle się trzymasz, jak na kogoś, kto przesiedział w celi dwa miesiące.","en":"That''s a shame... Oh well, never mind... Hey, you''re still looking pretty good for someone who''s been locked up for two months.","de":"Schade ... Na, was soll''s ... Hey, für zwei Monate Kerker siehst du aber noch ziemlich gut aus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_charge_beer_15_04_4', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_charge_beer_15_04_4","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_Charge_Beer","outputIds":["Info_Kirgo_Charge_Beer_15_04","Info_Kirgo_Charge_Beer_05_05","Info_Kirgo_Charge_Beer_15_06","Info_Kirgo_Charge_Beer_05_07"],"lines":[{"speaker":"hero","text":{"pl":"I zamierzam się postarać, żeby tak zostało.","en":"I''d like it to stay that way, too.","de":"Ich werde zusehen, dass das so bleibt."}},{"speaker":"npc","text":{"pl":"To dlaczego tak ci zależy na walce z jednym z nas?","en":"Then why do you insist on fighting one of us?","de":"Warum willst du dann unbedingt gegen einen von uns antreten?"}},{"speaker":"hero","text":{"pl":"Chcę zasłużyć na szacunek w Obozie.","en":"I want to get acknowledged in the Camp!","de":"Ich will Anerkennung im Lager finden!"}},{"speaker":"npc","text":{"pl":"To znaczy, że chcesz przekonać do siebie Scatty''ego, tak? To jeden z bardziej wpływowych ludzi w Zewnętrznym Pierścieniu... Może będzie pod wrażeniem, jeśli uda ci się mnie pokonać...","en":"By Scatty, you mean? Hm, he''s one of the most influential men in the Outer Ring... You might be able to impress him by defeating me...","de":"Bei Scatty, meinst du? Hm, er ist einer der einflussreichsten Leute hier im Außenring ... Wenn du mich besiegst, könnte ihn das schon beeindrucken ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_charge_now_15_00_0', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_charge_now_15_00_0","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_Charge_NOW","outputIds":["Info_Kirgo_Charge_NOW_15_00","Info_Kirgo_Charge_NOW_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie! Chcę się bić! Natychmiast!","en":"No! I want to fight. Now!","de":"Nein! Ich will gegen dich kämpfen. Jetzt!"}},{"speaker":"npc","text":{"pl":"W takim razie... Możemy zaczynać, jak tylko będziesz gotów.","en":"In that case... I''m ready when you are.","de":"Wie du willst ... Ich bin bereit, wenn du es bist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_charge_real_15_00_0', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_charge_real_15_00_0","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_ChargeREAL_Info","outputIds":["Info_Kirgo_ChargeREAL_15_00","Info_Kirgo_ChargeREAL_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Chcę z tobą walczyć - jesteś gotów?","en":"Let''s fight - are you ready?","de":"Lass uns kämpfen - Bist du bereit?"}},{"speaker":"npc","text":{"pl":"Chodź za mną!","en":"Follow me!","de":"Folge mir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_good_15_00_0', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_good_15_00_0","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_Good_Info","outputIds":["Info_Kirgo_Good_15_00","Info_Kirgo_Good_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Jesteś dobry?","en":"Are you good?","de":"Bist du gut?"}},{"speaker":"npc","text":{"pl":"W walce? Nie zajmuję się tym zbyt długo, ale wygrałem już swoją pierwszą walkę!","en":"At fighting? I haven''t been doing it for long, but I''ve already won a fight!","de":"Im Kämpfen? Ich bin noch nicht lange dabei, aber ich habe schon einen Kampf gewonnen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_251_kirgo_info_kirgo_in_arena_05_00_0', 'GRD_251_Kirgo', '{"id":"missions_dia_grd_251_kirgo_info_kirgo_in_arena_05_00_0","npcId":"GRD_251_Kirgo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_251_Kirgo.d","sourceFunction":"Info_Kirgo_InArena_Info","outputIds":["Info_Kirgo_InArena_05_00","SVM_5_LetsForgetOurLittleFight"],"lines":[{"speaker":"npc","text":{"pl":"Dobra, zaczynajmy! Niech wygra najlepszy!","en":"Right, let''s get to it. May the best man win!","de":"So, dann wollen wir mal. Möge der Bessere gewinnen!"}},{"speaker":"npc","text":{"pl":"Może zapomnijmy o naszej małej sprzeczce, dobra?","en":"Den kleinen Streit vergessen wir, okay?","de":"Den kleinen Streit vergessen wir, okay?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_guard_gate_06_04_4', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_guard_gate_06_04_4","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_GuardGate_Info","outputIds":["DIA_Orry_GuardGate_06_04","DIA_Orry_GuardGate_06_05","DIA_Orry_GuardGate_06_06"],"lines":[{"speaker":"npc","text":{"pl":"W takim razie uważaj na ludzi z Nowego Obozu!","en":"Then you''d better watch out for the guys from the New Camp!","de":"Dann solltest du wissen, dass du dich vor den Typen aus dem Neuen Lager in Acht nehmen musst!"}},{"speaker":"npc","text":{"pl":"Ja jestem ze Starego Obozu, tak jak wszyscy, których widziałeś na miejscu wymiany.","en":"I work for the Old Camp, same as the others you saw at the exchange place.","de":"Ich arbeite fürs alte Lager. Genau wie alle anderen, die du an der Austauschstelle gesehen hast."}},{"speaker":"npc","text":{"pl":"Zakładam, że rozmawiałeś już z Diego?","en":"I assume you''ve talked to Diego...?","de":"Du hast schon mit Diego geredet, nehme ich an?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_guard_gate_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_guard_gate_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_GuardGate_Info","outputIds":["DIA_Orry_GuardGate_15_00","DIA_Orry_GuardGate_06_01","DIA_Orry_GuardGate_06_02","DIA_Orry_GuardGate_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Czym się tutaj zajmujesz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Dbam o to, by nikt niepowołany nie dostał się w pobliże miejsca wymiany. Zwłaszcza ci bandyci z Nowego Obozu.","en":"Making sure no-one gets near the exchange place. Especially none of those cut-throats from the New Camp.","de":"Dafür sorgen, dass keiner an die Austauschstelle rankommt. Vor allem nicht die Halsabschneider aus dem Neuen Lager."}},{"speaker":"npc","text":{"pl":"Hej, to ciebie dziś zrzucili tutaj, co?","en":"You''re the new guy they chucked in today, right?","de":"Du bist der Neue, den sie heute reingeworfen haben, nicht?"}},{"speaker":"hero","text":{"pl":"Zgadza się.","en":"That''s me.","de":"Sieht so aus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_guard_gate_no_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_guard_gate_no_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_GuardGate_No","outputIds":["DIA_Orry_GuardGate_No_15_00","DIA_Orry_GuardGate_No_06_01","DIA_Orry_GuardGate_No_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie.","en":"No.","de":"Nein."}},{"speaker":"npc","text":{"pl":"Więc zrób to! On zajmuje się wszystkimi nowoprzybyłymi.","en":"Then do so! He''s the one that deals with newcomers.","de":"Dann solltest du das tun! Er kümmert sich um die Neuen."}},{"speaker":"npc","text":{"pl":"Od niego dowiesz się wszystkiego co żółtodziób wiedzieć powinien.","en":"He knows a lot about the colony - things that are important to new people like you.","de":"Er weiß viele Dinge über die Kolonie, die für einen Neuen sehr wichtig sein können."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_guard_gate_yes_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_guard_gate_yes_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_GuardGate_Yes","outputIds":["DIA_Orry_GuardGate_Yes_15_00","DIA_Orry_GuardGate_Yes_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Tak, rozmawiałem.","en":"Yes, I have.","de":"Ja, hab'' ich."}},{"speaker":"npc","text":{"pl":"To dobrze. Zatem wiesz już mniej więcej co i jak.","en":"Good. Then you know what''s what around here.","de":"Gut! Dann weißt du ja schon Bescheid."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_new_camp_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_new_camp_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_NewCamp_Info","outputIds":["DIA_Orry_NewCamp_15_00","DIA_Orry_NewCamp_06_01","DIA_Orry_NewCamp_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego mam uważać na ludzi z Nowego Obozu?","en":"Why do I have to watch out for the guys from the New Camp?","de":"Warum sollte ich mich vor dem Neuen Lager in Acht nehmen?"}},{"speaker":"npc","text":{"pl":"W porównaniu z Nowym Obozem, Stary Obóz to ciche i przytulne miejsce!","en":"Compared to the New Camp, the Old Camp''s a quiet, peaceful sort of place.","de":"Verglichen mit dem Neuen Lager ist das Alte Lager ein ruhiger und friedlicher Ort."}},{"speaker":"npc","text":{"pl":"Nowy Obóz nie otrzymuje żadnych przesyłek z zewnątrz. Te szkodniki po prostu kradną wszystko, czego potrzebują.","en":"The New Camp doesn''t get any deliveries from the outside world. Most of the rogues there just steal whatever they need.","de":"Das Neue Lager bekommt keine Waren aus der Außenwelt. Die meisten Banditen klauen sich zusammen, was sie zum Leben brauchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_old_camp_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_old_camp_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_OldCamp_Info","outputIds":["DIA_Orry_OldCamp_15_00","DIA_Orry_OldCamp_06_01","DIA_Orry_OldCamp_06_02"],"lines":[{"speaker":"hero","text":{"pl":"A Stary Obóz?","en":"And the Old Camp?","de":"Und das Alte Lager?"}},{"speaker":"npc","text":{"pl":"Tutaj wszystkim rządzą Magnaci, handlujący rudą. Pod nimi są Strażnicy, a następnie Cienie. Najniższą kastę stanowią Kopacze.","en":"The Ore Barons have everything under control. Next in line to them are the guards, followed by the Shadows. The diggers are the lowest.","de":"Die Erzbarone haben alles unter Kontrolle. Unter ihnen stehen die Gardisten. Unter denen wiederum stehen die Schatten. Ganz am Ende kommen die Buddler."}},{"speaker":"npc","text":{"pl":"Każdy, kto tu trafi, zaczyna jako Kopacz. Jeśli masz większe ambicje, musisz zostać przyjęty do Cieni.","en":"Everyone who arrives here starts out as a digger. If you want to become something better than that, you''ll have to get accepted as a Shadow first.","de":"Buddler ist jeder, der hier ankommt. Wenn du was Besseres werden willst, musst du als erstes bei den Schatten aufgenommen werden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_pre_exit_06_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_pre_exit_06_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_PreExit_Info","outputIds":["DIA_Orry_PreExit_06_00"],"lines":[{"speaker":"npc","text":{"pl":"Postaraj się dotrzeć do Starego Obozu w jednym kawałku!","en":"You''d better make sure you reach the Old Camp in one piece!","de":"Sieh zu, das du heil zum Alten Lager kommst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_shore_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_shore_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_Shore_Info","outputIds":["DIA_Orry_Shore_15_00","DIA_Orry_Shore_06_01","DIA_Orry_Shore_15_02","DIA_Orry_Shore_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Kiedy tutaj wylądowałem, jeden z waszych uderzył mnie w twarz.","en":"When I was washed ashore, one of the guys punched me in the face.","de":"Als ich ans Ufer gespült wurde, hat mich einer von den Typen mit einem Schlag ins Gesicht begrüßt."}},{"speaker":"npc","text":{"pl":"Robią tak z wszystkimi nowymi. Mówią na to \"Chrzest Wody\".","en":"They do that to all the newcomers. They call it ''Standing Godfather''.","de":"Das machen sie mit jedem Neuen. Sie nennen es ''Die Taufe''."}},{"speaker":"hero","text":{"pl":"Rozumiem. Czy w Starym Obozie jest wielu takich zawadiaków?","en":"Oh. Are all the guys like that in the Old Camp?","de":"Habt ihr im Alten Lager noch mehr so nette Leute?"}},{"speaker":"npc","text":{"pl":"Jest kilka czarnych owiec. Ale nie zrobią ci krzywdy, jeśli zapłacisz im za ochronę.","en":"We do have a few suckers. But they won''t touch you as long as you pay them protection money.","de":"Es gibt schon einige Schweine. Aber solange du dein Schutzgeld zahlst, kann dir nichts passieren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_waffe_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_waffe_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_Waffe_Info","outputIds":["DIA_Orry_Waffe_15_00","DIA_Orry_Waffe_06_01","DIA_Orry_Waffe_06_02","DIA_Orry_Waffe_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję broni...","en":"I''m looking for a weapon...","de":"Ich suche eine Waffe ..."}},{"speaker":"npc","text":{"pl":"Rozejrzyj się trochę przy zamkniętej kopalni, w głębi kanionu. Na pewno coś tam znajdziesz.","en":"There should be some old weapons by the derelict mine further down the canyon.","de":"Bei der verlassenen Mine weiter hinten im Canyon müsstest du alte Waffen finden."}},{"speaker":"npc","text":{"pl":"Tylko nie wdawaj się w poważne bójki uzbrojony w głupi kilof. To bardzo ciężka i nieporęczna broń.","en":"But don''t go and start a war with nothing but a rusty pickaxe for a weapon - those things are slow and heavy.","de":"Aber mach bloß nicht den Fehler und zieh mit ''ner rostigen Spitzhacke in den Krieg - die Dinger sind schwer und langsam."}},{"speaker":"npc","text":{"pl":"Niedoświadczony wojownik powinien posługiwać się nim tylko w ostateczności.","en":"An inexperienced fighter should never use one of them unless it''s an emergency.","de":"Ein ungeübter Kämpfer sollte sie nur im Notfall benutzen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_woman_06_04_4', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_woman_06_04_4","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_Woman_Info","outputIds":["DIA_Orry_Woman_06_04"],"lines":[{"speaker":"npc","text":{"pl":"Sam już nie wiem, co jest dla nich gorsze...","en":"I''m not sure what''s worse...","de":"Bin mir nicht sicher, was schlimmer ist ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_254_orry_dia_orry_woman_15_00_0', 'GRD_254_Orry', '{"id":"missions_dia_grd_254_orry_dia_orry_woman_15_00_0","npcId":"GRD_254_Orry","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_254_Orry.d","sourceFunction":"DIA_Orry_Woman_Info","outputIds":["DIA_Orry_Woman_15_00","DIA_Orry_Woman_06_01","DIA_Orry_Woman_15_02","DIA_Orry_Woman_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Widziałem, jak spuszczano tutaj jakąś kobietę.","en":"I saw a woman being sent down with the goods.","de":"Ich habe gesehen, wie sie eine Frau zusammen mit den Waren reingeschickt haben."}},{"speaker":"npc","text":{"pl":"Cóż, Magnaci dostają wszystko, czego zapragną.","en":"Yeah, the Ore Barons get everything they want.","de":"Ja, die Erzbarone bekommen alles, was sie wollen."}},{"speaker":"hero","text":{"pl":"Chcesz powiedzieć, że król wymienia kobiety na rudę?","en":"D''you mean to say the King exchanges women for ore?","de":"Du meinst, der König tauscht Erz gegen Frauen?"}},{"speaker":"npc","text":{"pl":"Naturalnie one też trafiają tutaj prosto z więzienia. Gdyby Gomez nie ściągnął ich tutaj, dalej gniłyby w jakimś lochu.","en":"They''re convicted criminals too, of course. But if Gomez hadn''t asked for them, they''d be sitting in some dungeon or other.","de":"Sie sind natürlich auch verurteilte Gefangene. Aber wenn Gomez sie nicht angefordert hätte, säßen sie in irgendwelchen Kerkern."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_first_06_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_first_06_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_First_Info","outputIds":["DIA_Fletcher_First_06_00","DIA_Fletcher_First_15_01","DIA_Fletcher_First_06_02","DIA_Fletcher_First_06_03"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey, du!"}},{"speaker":"hero","text":{"pl":"Kto? Ja?","en":"Who? Me?","de":"Wer? Ich?"}},{"speaker":"npc","text":{"pl":"Wiesz dobrze, do kogo mówię, synku!","en":"You know who I mean, sonny!","de":"Du weißt genau, mit wem ich rede, Bürschchen!"}},{"speaker":"npc","text":{"pl":"Coś ci powiem: to mój rejon. I nie chcę tutaj żadnych kłopotów!","en":"Let me tell you something: This is MY district. And I don''t want any trouble!","de":"Ich will dir mal was sagen: Das hier ist MEIN Viertel. Und ich will hier keinen Ärger!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_first_06_04_4', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_first_06_04_4","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_First_Info","outputIds":["DIA_Fletcher_First_06_04","DIA_Fletcher_First_06_05","DIA_Fletcher_First_06_06"],"lines":[{"speaker":"npc","text":{"pl":"Ale nowi, tacy jak ty, zawsze sprawiają kłopoty. Zwłaszcza, kiedy buszują tutaj w nocy.","en":"But new guys like you are always trouble. Especially when they sneak around the place at night.","de":"Aber neue Typen wie du bedeuten immer Ärger. Vor allem, wenn sie hier mitten in der Nacht rumlaufen."}},{"speaker":"npc","text":{"pl":"Lepiej będzie jeśli pójdziesz sobie już do domu i nie pokażesz się tutaj zbyt prędko. Przy arenie jest jedna pusta chata, ma daszek nad wejściem. Idź spać!","en":"So why don''t you go home and make sure I don''t see you here again? There''s an empty hut opposite the arena, the one with the canopy. Get some sleep.","de":"Also, warum sorgst du nicht dafür, dass ich dich hier nicht mehr sehe. Die Hütte gegenüber der Arena mit dem Vordach ist frei. Leg dich ''ne Runde ins Bett."}},{"speaker":"npc","text":{"pl":"Ale jeśli złapię cię na grzebaniu w cudzych chatach, osobiście postaram się, żebyś już nigdy więcej tego nie zrobił!","en":"And if I catch you in one of the other huts, I shall personally see to it that you live to regret it.","de":"Wenn ich dich in einer der anderen Hütten erwische, zieh ich dir das Fell über die Ohren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_hello_15_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_hello_15_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_Hello_Info","outputIds":["DIA_Fletcher_Hello_15_00","DIA_Fletcher_Hello_06_01","DIA_Fletcher_Hello_15_02","DIA_Fletcher_Hello_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey, du!"}},{"speaker":"npc","text":{"pl":"Jeśli chcesz się pozbyć swoich pieniędzy za ochronę, wybrałeś zły dzień.","en":"If you want to get rid of your protection money - you''ve picked the wrong day.","de":"Wenn du dein Schutzgeld loswerden willst - heute ist nicht der Tag."}},{"speaker":"hero","text":{"pl":"Tak? A dlaczego?","en":"Yeah? Why''s that?","de":"So? Und warum nicht?"}},{"speaker":"npc","text":{"pl":"Bo mnie tu nie ma.","en":"Cos I''m not here.","de":"Weil ich gar nicht da bin."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_hello_where_else_15_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_hello_where_else_15_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_Hello_WhereElse","outputIds":["DIA_Fletcher_Hello_WhereElse_15_00","DIA_Fletcher_Hello_WhereElse_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Czyżby? A gdzie jesteś?","en":"Oh, where are you then?","de":"Wo bist du denn?"}},{"speaker":"npc","text":{"pl":"W tej chwili siedzę w zamku, przy ognisku i popijam piwo.","en":"I''m actually at the castle, sitting by the big camp fire, drinking a mug of beer.","de":"Eigentlich bin ich in der Burg, am großen Lagerfeuer, und trinke ein Bier."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_hello_why_talk_15_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_hello_why_talk_15_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_Hello_WhyTalk","outputIds":["DIA_Fletcher_Hello_WhyTalk_15_00","DIA_Fletcher_Hello_WhyTalk_06_01","DIA_Fletcher_Hello_WhyTalk_06_02"],"lines":[{"speaker":"hero","text":{"pl":"To jakim cudem z tobą rozmawiam?","en":"Then how come I''m talking to you?","de":"Wie kommt es dann, dass wir beide uns unterhalten?"}},{"speaker":"npc","text":{"pl":"Nek gdzieś zniknął. Zwykle to on patroluje ten rejon.","en":"Nek''s vanished. This district is usually his responsibility.","de":"Nek ist verschwunden. Er ist normalerweise für dieses Viertel verantwortlich."}},{"speaker":"npc","text":{"pl":"A dopóki nie raczy się tutaj zjawić, Thorus kazał MI mieć oko na wszystko.","en":"And until he reappears, Thorus has ordered ME to guard it.","de":"Bis er wieder da ist, hat Thorus MICH hier eingesetzt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_problem_15_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_problem_15_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_Problem_Info","outputIds":["DIA_Fletcher_Problem_15_00","DIA_Fletcher_Problem_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Jaki problem?","en":"What''s the problem?","de":"Was ist dein Problem?"}},{"speaker":"npc","text":{"pl":"Jestem winien Scatty''emu nie lada sumkę. Kiedy dowie się, że przejąłem działkę Neka, będzie mnie nachodził codziennie...","en":"I''m in debt to Scatty, right up to my neck. Now he knows I''m doing Nek''s job, he''ll be coming round every day...","de":"Ich habe Schulden bei Scatty. ''Ne Menge Schulden. Jetzt, wo er weiß, dass ich Neks Job mache, wird er jeden Tag bei mir auf der Matte stehen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_tro_schu_15_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_tro_schu_15_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_TroSchu_Info","outputIds":["DIA_Fletcher_TroSchu_15_00","DIA_Fletcher_TroSchu_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Ale dlaczego nie zbierasz pieniędzy za ochronę?","en":"Why don''t you just collect some more protection money?","de":"Warum sammelst du nicht trotzdem Schutzgeld?"}},{"speaker":"npc","text":{"pl":"Nek zebrał już, co było do zebrania. Więcej z nich nie wycisnę.","en":"Nek did his rounds before he disappeared. There''s not much left to collect now.","de":"Kurz bevor er verschwunden ist, hat Nek noch einmal alle kräftig zur Kasse gebeten. Da ist nicht mehr viel zu holen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_wegen_nek_06_08_8', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_wegen_nek_06_08_8","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_WegenNek_Info","outputIds":["DIA_Fletcher_WegenNek_06_08"],"lines":[{"speaker":"npc","text":{"pl":"Informuj mnie na bieżąco.","en":"Keep me posted.","de":"Halt mich auf dem Laufenden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_wegen_nek_15_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_wegen_nek_15_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_WegenNek_Info","outputIds":["DIA_Fletcher_WegenNek_15_00","DIA_Fletcher_WegenNek_06_01","DIA_Fletcher_WegenNek_15_02","DIA_Fletcher_WegenNek_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Chodzi o Neka.","en":"It''s about Nek...","de":"Wegen Nek ..."}},{"speaker":"npc","text":{"pl":"Tak?","en":"Yeah?","de":"Ja?"}},{"speaker":"hero","text":{"pl":"Chyba go znalazłem.","en":"I think I''ve found him.","de":"Ich glaub'', ich hab'' ihn gefunden."}},{"speaker":"npc","text":{"pl":"Co? Gdzie on jest?","en":"What? Where is he?","de":"Was? Wo ist er?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_wegen_nek_15_04_4', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_wegen_nek_15_04_4","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_WegenNek_Info","outputIds":["DIA_Fletcher_WegenNek_15_04","DIA_Fletcher_WegenNek_06_05","DIA_Fletcher_WegenNek_06_06","DIA_Fletcher_WegenNek_15_07"],"lines":[{"speaker":"hero","text":{"pl":"W innym, lepszym świecie...","en":"Feeding the rats...","de":"Er ist Futter für die Ratten."}},{"speaker":"npc","text":{"pl":"O cholera! To znaczy, że będę tutaj tkwił do końca życia. Miałem nadzieję, że ten bęcwał jednak wróci.","en":"Oh no! Damn it! That means I have to run the show here now. I was hoping he''d be coming back.","de":"Nein! Verdammt! Dann muss ICH jetzt den Laden hier schmeißen. Ich hatte gehofft, er kommt wieder."}},{"speaker":"npc","text":{"pl":"Teraz mam kłopot.","en":"Now I have a problem.","de":"Jetzt hab'' ich ein Problem ..."}},{"speaker":"hero","text":{"pl":"Żadnych wieści.","en":"No news.","de":"Noch nichts Neues."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_dia_fletcher_wo_nek_15_00_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_dia_fletcher_wo_nek_15_00_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"DIA_Fletcher_WoNek_Info","outputIds":["DIA_Fletcher_WoNek_15_00","DIA_Fletcher_WoNek_06_01","DIA_Fletcher_WoNek_06_02","DIA_Fletcher_WoNek_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Wiesz, gdzie się podziewa Nek?","en":"D''you know where Nek''s got to?","de":"Weißt du, wo Nek geblieben ist?"}},{"speaker":"npc","text":{"pl":"Nie, i raczej się tego nie dowiem.","en":"No, and I''m not likely to find out.","de":"Nein, und ich werde es auch nicht rausfinden."}},{"speaker":"npc","text":{"pl":"Jeśli komuś coś o tym wiadomo, to pewnie tutejszym Kopaczom. Ale oni nie rozmawiają ze Strażnikami.","en":"If anything, the diggers in this district might know something. But diggers don''t talk to guards.","de":"Wenn einer was weiß, dann die Buddler aus diesem Viertel. Aber die Buddler reden nicht mit Gardisten."}},{"speaker":"npc","text":{"pl":"A zwłaszcza ze mną, bo wiedzą, że brzydzę się ich robotą. Założę się, że podśmiewają się ze mnie za moimi plecami.","en":"Especially not now they know I hate this filthy work. I bet they''re laughing behind my back!","de":"Vor allem nicht jetzt, denn sie wissen, dass ich diese Drecksarbeit hier verabscheue, und insgeheim lachen sie sich über mich tot!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_grd_255_fletcher_welcome_info_06_01_0', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_grd_255_fletcher_welcome_info_06_01_0","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"Grd_255_Fletcher_WELCOME_Info","outputIds":["Grd_255_Fletcher_WELCOME_Info_06_01"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że szybko nauczyłeś się dbać o swoje interesy. Witamy w Straży!","en":"You have got used to our ways pretty fast. Welcome to the Guards!","de":"Du hast ziemlich schnell kapiert, wie es hier läuft. Willkommen bei der Garde!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_info_fletcher_die_06_05_4', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_info_fletcher_die_06_05_4","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"Info_Fletcher_DIE_Info","outputIds":["Info_Fletcher_DIE_06_05","Info_Fletcher_DIE_15_06","Info_Fletcher_DIE_06_07","Info_Fletcher_DIE_15_08"],"lines":[{"speaker":"npc","text":{"pl":"Zadajesz się z tymi bandziorami z Nowego Obozu! A może nie?!","en":"You''re in with that New Camp scum, aren''t you?","de":"Steckst mit diesem abtrünnigen Abschaum aus dem Neuen Lager unter einer Decke, was?"}},{"speaker":"hero","text":{"pl":"Zaczekaj...","en":"Hold on...","de":"Warte mal ..."}},{"speaker":"npc","text":{"pl":"Myślałeś, że się nie domyślimy, co? CO?!","en":"I guess you must''ve thought we wouldn''t figure it out, huh?","de":"Hattest wohl gedacht, wir würden nicht dahinter kommen, wie?"}},{"speaker":"hero","text":{"pl":"Hej... Postradałeś zmysły?!","en":"Woah... Hold your horses!","de":"Jetzt aber mal halblang ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_info_fletcher_die_06_09_8', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_info_fletcher_die_06_09_8","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"Info_Fletcher_DIE_Info","outputIds":["Info_Fletcher_DIE_06_09","Info_Fletcher_DIE_06_10","Info_Fletcher_DIE_06_11","Info_Fletcher_DIE_06_12"],"lines":[{"speaker":"npc","text":{"pl":"Ja? Ależ skąd. Za to TY za chwilę stracisz GŁOWĘ, kolego.","en":"No, YOU hold on - hold on to your head. ''Cos you''re going to be missing it soon.","de":"Wir werden DICH halblang machen. Oder genauer gesagt, einen Kopf kürzer."}},{"speaker":"npc","text":{"pl":"GIŃ, ZDRAJCO!!!","en":"DIE, TRAITOR!!!","de":"STIRB, VERRÄTER!!!"}},{"speaker":"npc","text":{"pl":"No proszę. To gość z Nowego Obozu!","en":"Look at that. It''s a guy from the New Camp!","de":"Sieh mal einer an. Einer aus dem Neuen Lager!"}},{"speaker":"npc","text":{"pl":"Patrzcie no. To gość z Sekty!","en":"Look at that. It''s a guy from the swamp camp!","de":"Sieh mal einer an. Einer aus dem Sumpflager!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_info_fletcher_die_15_13_12', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_info_fletcher_die_15_13_12","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"Info_Fletcher_DIE_Info","outputIds":["Info_Fletcher_DIE_15_13","Info_Fletcher_DIE_06_14","Info_Fletcher_DIE_15_15","Info_Fletcher_DIE_06_16"],"lines":[{"speaker":"hero","text":{"pl":"I co z tego? Masz z tym jakiś problem?","en":"So what? What business is it of yours?","de":"Ja, und? Was geht dich das an?"}},{"speaker":"npc","text":{"pl":"Mieć, to ja będę waszą małą kopalnię!","en":"Your mine''s gonna be ours soon.","de":"Bald wird auch eure Mine zu uns gehören."}},{"speaker":"hero","text":{"pl":"Czyżby? Chyba śnisz!","en":"Yeah? Well dream on!","de":"Davon träumst du doch nur!"}},{"speaker":"npc","text":{"pl":"Przykro mi, ale nie możemy pozwolić, żebyś o tym komuś powiedział!","en":"Sorry, but I can''t risk you telling anyone about it!","de":"Leider können wir es nicht zulassen, dass du das irgendwo herumerzählst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_255_fletcher_info_fletcher_die_15_17_16', 'GRD_255_Fletcher', '{"id":"missions_dia_grd_255_fletcher_info_fletcher_die_15_17_16","npcId":"GRD_255_Fletcher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_255_Fletcher.d","sourceFunction":"Info_Fletcher_DIE_Info","outputIds":["Info_Fletcher_DIE_15_17","Info_Fletcher_DIE_06_18","Info_Fletcher_DIE_15_19","Info_Fletcher_DIE_06_20"],"lines":[{"speaker":"hero","text":{"pl":"Zaczekaj, nie szukam kłopotów.","en":"Hang on, I don''t want any trouble.","de":"Warte mal, ich bin nicht auf Streit aus ..."}},{"speaker":"npc","text":{"pl":"Trzeba było o tym pomyśleć zanim tutaj przyszedłeś!","en":"You should have thought of that before you showed your face here!","de":"Das hättest du dir überlegen sollen, bevor du hier aufkreuzt!"}},{"speaker":"hero","text":{"pl":"Hej, co u...","en":"Hey, what the...","de":"He, was soll der Unfug ..."}},{"speaker":"npc","text":{"pl":"Dalej chłopcy! Na niego!","en":"Go, boys, let''s get him!","de":"Auf ihn Jungs, den schnappen wir uns!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_crawler_okay_11_06_4', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_crawler_okay_11_06_4","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Crawler_Okay_Info","outputIds":["Grd_260_Drake_Crawler_Okay_11_06"],"lines":[{"speaker":"npc","text":{"pl":"Żartujesz sobie ze mnie? Wróć, jak będziesz miał dla mnie piwo.","en":"Are you kidding me? Come back when you have some beer.","de":"Willst du mich verarschen? Komm wieder, wenn du Bier hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_crawler_okay_15_01_0', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_crawler_okay_15_01_0","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Crawler_Okay_Info","outputIds":["Grd_260_Drake_Crawler_Okay_15_01","Grd_260_Drake_Crawler_Okay_11_02","Grd_260_Drake_Crawler_Okay_11_03","Grd_260_Drake_Crawler_Okay_11_04"],"lines":[{"speaker":"hero","text":{"pl":"Proszę, wypij moje zdrowie!","en":"Here, drink to my health!","de":"Hier, trink einen auf mein Wohl!"}},{"speaker":"npc","text":{"pl":"Dzięki. A co do pełzaczy - żyją w dużych stadach, głównie w bocznych jaskiniach.","en":"Thanks. Well, crawlers live in large packs, mostly in the side caves.","de":"Danke. Also die Crawler gibt es hier zuhauf in vielen Nebenhöhlen."}},{"speaker":"npc","text":{"pl":"Jeszcze nigdy nie widziano ich tutaj, w głównym szybie. Gdybyś spotkał kiedyś pełzacza, wiej ile sił w nogach!","en":"They''ve never attacked us here in the main shaft yet. If you ever meet one of ''em, run!","de":"Hier im Hauptschacht haben sie noch nicht angegriffen. Wenn du ihnen mal begegnest, dann lauf!"}},{"speaker":"npc","text":{"pl":"Albo stań plecami do ściany. W ten sposób będziesz miał jakąś szansę!","en":"Or stand with your back to the wall. That way you may stand a chance!","de":"Oder stell dich mit dem Rücken zur Wand. Dann hast du vielleicht noch eine Chance!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_gardeaufnahme_info_11_01_0', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_gardeaufnahme_info_11_01_0","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_GARDEAUFNAHME_Info","outputIds":["Grd_260_Drake_GARDEAUFNAHME_Info_11_01","Grd_260_Drake_GARDEAUFNAHME_Info_11_02"],"lines":[{"speaker":"npc","text":{"pl":"Hej, nieźle sobie poradziłeś z tymi pełzaczami! Zasłużyłeś sobie na przyjęcie w poczet Strażników.","en":"Hey, you did a good job with the crawlers! You deserve to be admitted as a guard now!","de":"Hey, gute Arbeit, das mit den Crawlern! Damit hast du dir deine Aufnahme bei den Gardisten verdient!"}},{"speaker":"npc","text":{"pl":"Idź do Starego Obozu i porozmawiaj z Thorusem!","en":"Just go over to the Old Camp and speak to Thorus about it!","de":"Geh doch mal zum Alten Lager und sprich mit Thorus darüber!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_gefahr_info_11_05_4', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_gefahr_info_11_05_4","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Gefahr_Info","outputIds":["Grd_260_Drake_Gefahr_Info_11_05","Grd_260_Drake_Gefahr_Info_11_06"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz, zaschło mi w ustach...","en":"Oh, but my tongue''s so dry...","de":"Nun, ich hab'' eine ziemlich trockene Kehle."}},{"speaker":"npc","text":{"pl":"Przynieś mi piwo, to ci opowiem o pełzaczach.","en":"You bring me a beer, and I''ll tell you something about the crawlers.","de":"Wenn du ein Bier ausgibst, erzähl ich dir noch was über die Crawler."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_gefahr_info_15_01_0', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_gefahr_info_15_01_0","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Gefahr_Info","outputIds":["Grd_260_Drake_Gefahr_Info_15_01","Grd_260_Drake_Gefahr_Info_11_02","Grd_260_Drake_Gefahr_Info_11_03","Grd_260_Drake_Gefahr_Info_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Na co powinienem uważać w kopalni?","en":"What do I need to look out for in the mine?","de":"Auf was sollte ich in der Mine achten?"}},{"speaker":"npc","text":{"pl":"Przede wszystkim na pełzacze. Groźne bestie.","en":"Minecrawlers, mainly. Dangerous beasts.","de":"Vor allem auf Minecrawler. Das sind gefährliche Biester."}},{"speaker":"npc","text":{"pl":"To przez nie musieliśmy zrezygnować z wydobycia w paru jaskiniach. Niestety, pożarły nam już sporą grupę Kopaczy.","en":"We''ve had to give up a few caves because of them. They''ve eaten quite a few diggers, too.","de":"Wir mussten wegen ihnen schon einige Höhlen aufgeben. Haben schon so manchen Buddler verspeist."}},{"speaker":"hero","text":{"pl":"Opowiedz mi o pełzaczach.","en":"Tell me about the crawlers.","de":"Erzähl mir von den Crawlern."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_ian_info_11_05_4', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_ian_info_11_05_4","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Ian_Info","outputIds":["Grd_260_Drake_Ian_Info_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Jak podpadniesz jemu - podpadniesz nam wszystkim. Zrozumiano?","en":"If you get into trouble with him, you''ll be in trouble with us all. Understood?","de":"Legst du dich mit ihm an, legst du dich mit uns allen an. Verstanden?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_ian_info_15_01_0', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_ian_info_15_01_0","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Ian_Info","outputIds":["Grd_260_Drake_Ian_Info_15_01","Grd_260_Drake_Ian_Info_11_02","Grd_260_Drake_Ian_Info_11_03","Grd_260_Drake_Ian_Info_11_04"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę znaleźć Iana?","en":"Where can I find Ian?","de":"Wo kann ich Ian finden ?"}},{"speaker":"npc","text":{"pl":"Poszukaj go na środku głównego szybu, obok składowiska.","en":"He''s right in the middle of the main shaft, next to the storeroom.","de":"Er steht in der Mitte des Hauptschachtes, beim Warenlager."}},{"speaker":"npc","text":{"pl":"Ach, i jeszcze coś: znasz Thorusa, prawda? Zapomnij o nim!","en":"Oh, one more thing - you know Thorus, don''t you? Forget him!","de":"Ach noch was, du kennst doch Thorus? Vergiss ihn!"}},{"speaker":"npc","text":{"pl":"W kopalni rządzi tylko jedna osoba i jest nią Ian. To nasz szef.","en":"There''s just one person who has the say in here and that''s Ian. He''s the boss.","de":"Hier drin hat nur einer das Sagen und das ist Ian. Er ist hier der Chef."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_mine_info_15_01_0', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_mine_info_15_01_0","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Mine_Info","outputIds":["Grd_260_Drake_Mine_Info_15_01","Grd_260_Drake_Mine_Info_11_02","Grd_260_Drake_Mine_Info_11_03","Grd_260_Drake_Mine_Info_11_04"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mi opowiedzieć o tej kopalni?","en":"Can you tell me anything about the mine?","de":"Kannst du mir was über die Mine erzählen?"}},{"speaker":"npc","text":{"pl":"Stoimy teraz w głównym szybie. Na dół można zejść po rusztowaniach.","en":"Well, this part we''re standing in now is the main shaft. A system of catwalks takes you down to the bottom.","de":"Hier, wo wir uns befinden, das ist der Hauptschacht. Über ein Stegsystem kommst du bis ganz nach unten."}},{"speaker":"npc","text":{"pl":"Wszędzie dookoła Kopacze wydobywają rudę. Musisz bardzo uważać na pełzacze. One też są wszędzie dookoła!","en":"And they''re digging for ore everywhere. But you need to be careful, there are many minecrawlers there as well.","de":"Und überall wird Erz geschürft. Doch sei vorsichtig, hier gibt''s auch eine Menge Minecrawler."}},{"speaker":"npc","text":{"pl":"Na samym dole, część wydobytej rudy przeznaczona do wykorzystania tutaj jest od razu przetapiana.","en":"Right at the bottom is the smelting place. We''re smelting a part of the ore to use it right there.","de":"Ganz unten steht die Schmelze. Einen Teil des Erzes schmelzen wir direkt ein und verarbeiten es."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_260_drake_grd_260_drake_mine_mehr_info_15_01_0', 'GRD_260_Drake', '{"id":"missions_dia_grd_260_drake_grd_260_drake_mine_mehr_info_15_01_0","npcId":"GRD_260_Drake","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_260_Drake.d","sourceFunction":"Grd_260_Drake_Mine_Mehr_Info","outputIds":["Grd_260_Drake_Mine_Mehr_Info_15_01","Grd_260_Drake_Mine_Mehr_Info_11_02","Grd_260_Drake_Mine_Mehr_Info_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi o tym coś więcej!","en":"Tell me more about it!","de":"Erzähl mir mehr davon!"}},{"speaker":"npc","text":{"pl":"Jeśli chcesz wiedzieć więcej, pogadaj z Wężem. On zajmuje się wytopem.","en":"If you want to know more, go to Viper. He''s the smelter.","de":"Wenn du mehr wissen willst, dann wende dich an Viper. Er ist der Schmelzer."}},{"speaker":"npc","text":{"pl":"Albo zapytaj Iana. On tu rządzi. Odpowiada za organizację pracy w całej kopalni.","en":"Or talk to Ian. He''s the boss. He organizes everything here in the mine.","de":"Oder wende dich an Ian. Er ist der Boss. Er organisiert hier in der Mine alles."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_261_brandick_grd_261_brandick_aleph_info_15_01_0', 'GRD_261_Brandick', '{"id":"missions_dia_grd_261_brandick_grd_261_brandick_aleph_info_15_01_0","npcId":"GRD_261_Brandick","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_261_Brandick.d","sourceFunction":"GRD_261_Brandick_ALEPH_Info","outputIds":["GRD_261_Brandick_ALEPH_Info_15_01","GRD_261_Brandick_ALEPH_Info_06_02","GRD_261_Brandick_ALEPH_Info_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Słuchaj, za każdym razem, kiedy się odwracasz, Aleph siedzi bezczynnie i zbija bąki.","en":"Listen, when you''re not there Aleph just sits around there all the time without doing any work.","de":"Hör mal, wenn du nicht da bist, sitzt Aleph die ganze Zeit nur rum, ohne zu arbeiten."}},{"speaker":"npc","text":{"pl":"Czyżby?","en":"Is that true?","de":"Ist das so?"}},{"speaker":"npc","text":{"pl":"Wiesz jakich ludzi nienawidzę jeszcze bardziej od obiboków? Donosicieli! Zejdź mi z oczu!","en":"Do you know what I despise even more than lazybones? Traitors. So just get lost!","de":"Weißt du, was ich noch viel weniger leiden kann als Faulpelze? Das sind Verräter. Also geh mir aus den Augen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_grd_262_aaron_bluff_bad_15_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_grd_262_aaron_bluff_bad_15_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_BLUFF_BAD","outputIds":["GRD_262_Aaron_BLUFF_BAD_15_01","GRD_262_Aaron_BLUFF_BAD_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Ma już dość twojego lenistwa.","en":"He''ll kill you ''cos you''re so lazy.","de":"Er will dir kräftig in den Arsch treten, weil du so faul bist."}},{"speaker":"npc","text":{"pl":"Phi. To nic nowego. Spadaj!","en":"Well, that''s no news. Scram!","de":"Na, das ist doch nichts Neues. Geh weg!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_grd_262_aaron_bluff_bandit_15_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_grd_262_aaron_bluff_bandit_15_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_BLUFF_BANDIT","outputIds":["GRD_262_Aaron_BLUFF_BANDIT_15_01","GRD_262_Aaron_BLUFF_BANDIT_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Podobno w waszej kopalni są jacyś rabusie. Zamierzają ukraść ładunek rudy!","en":"I''ve heard that there are gangsters in the mine here. They want the ore!","de":"Ich hab'' gehört, dass Banditen in der Mine sind. Sie wollen das Erz!"}},{"speaker":"npc","text":{"pl":"Masz mnie za głupca? Nie odważyliby się na coś takiego!","en":"Do you think I''m stupid? They''d never dare to do anything like that!","de":"Hältst du mich für blöd? Das würden sie niemals wagen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_grd_262_aaron_bluff_good_15_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_grd_262_aaron_bluff_good_15_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_BLUFF_GOOD","outputIds":["GRD_262_Aaron_BLUFF_GOOD_15_01","GRD_262_Aaron_BLUFF_GOOD_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Ma ci wręczyć nagrodę za przykładną pracę.","en":"He wants to give you a reward for your good work.","de":"Er will dir eine Belohnung für deine guten Dienste geben."}},{"speaker":"npc","text":{"pl":"Czyżby? Wiesz co? Lepiej już stąd idź.","en":"Ah, really? I think you''d better go now.","de":"Ach, tatsächlich? Ich glaube, du gehst jetzt besser."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_grd_262_aaron_bluff_ian_15_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_grd_262_aaron_bluff_ian_15_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_BLUFF_IAN","outputIds":["GRD_262_Aaron_BLUFF_IAN_15_01","GRD_262_Aaron_BLUFF_IAN_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Ian. Masz się do niego natychmiast zgłosić!","en":"Ian sent me. You should go to see him at once!","de":"Ian schickt mich. Du sollst sofort zu ihm kommen!"}},{"speaker":"npc","text":{"pl":"A czego ode mnie chce?","en":"What does he want?","de":"Was will er denn?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_grd_262_aaron_bluff_ore_15_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_grd_262_aaron_bluff_ore_15_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_BLUFF_ORE","outputIds":["GRD_262_Aaron_BLUFF_ORE_15_01","GRD_262_Aaron_BLUFF_ORE_09_02","GRD_262_Aaron_BLUFF_ORE_15_03","GRD_262_Aaron_BLUFF_ORE_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Kopacze znaleźli ogromną bryłę rudy!","en":"The diggers have found a massive ore nugget!","de":"Die Buddler haben einen riesigen Erzbrocken gefunden!"}},{"speaker":"npc","text":{"pl":"I co z tego?","en":"So what?","de":"Na und?"}},{"speaker":"hero","text":{"pl":"Powinieneś na nią rzucić okiem.","en":"You have to take a look at it!","de":"Den musst du dir unbedingt ansehen!"}},{"speaker":"npc","text":{"pl":"Nie ma mowy.","en":"Forget it.","de":"Vergiss es."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_grd_262_aaron_bluff_ugly_15_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_grd_262_aaron_bluff_ugly_15_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_BLUFF_UGLY","outputIds":["GRD_262_Aaron_BLUFF_UGLY_15_01","GRD_262_Aaron_BLUFF_UGLY_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie wiem. Pewnie sam ci to powie. Inaczej po co by cię wzywał?","en":"No idea. Ian will tell you that himself! Do you think he''d tell me something like that?","de":"Keine Ahnung. Das wird Ian dir schon selber sagen! Glaubst du, er erzählt mir so was?"}},{"speaker":"npc","text":{"pl":"Ach, trudno. W takim razie zajrzę do niego.","en":"Then I''ll go to see him!","de":"Dann werde ich mal zu ihm gehen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_grd_262_aaron_chest_info_15_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_grd_262_aaron_chest_info_15_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_CHEST_Info","outputIds":["GRD_262_Aaron_CHEST_Info_15_01","GRD_262_Aaron_CHEST_Info_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Czym się tutaj zajmujesz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Pilnuję, żeby Kopacze, tacy jak nasz drogi Snipes, trzymali łapy z dala od mojej skrzyni.","en":"I''m watching diggers like Snipes over there to make sure they keep their hands off my chest.","de":"Ich pass auf, dass so Buddler wie Snipes da drüben die Finger von meiner Truhe hier lassen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_262_aaron_info_aaron_pissed_09_01_0', 'GRD_262_Aaron', '{"id":"missions_dia_grd_262_aaron_info_aaron_pissed_09_01_0","npcId":"GRD_262_Aaron","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_262_Aaron.d","sourceFunction":"GRD_262_Aaron_PISSED_Info","outputIds":["Info_Aaron_PISSED_09_01"],"lines":[{"speaker":"npc","text":{"pl":"HEJ, TY! Jeśli jeszcze raz spróbujesz wystrychnąć mnie na dudka, pogadamy inaczej. Zrozumiano?!","en":"HEY, YOU!!! If you try to make a fool out of me again, you had it, you got that?","de":"HEY, DU!!! Wenn du mich noch einmal so verarschst, dann gibt''s ne ordentliche Tracht Prügel, verstanden?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_263_asghan_grd_263_asghan_lairfound_info_15_01_0', 'GRD_263_Asghan', '{"id":"missions_dia_grd_263_asghan_grd_263_asghan_lairfound_info_15_01_0","npcId":"GRD_263_Asghan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_263_Asghan.d","sourceFunction":"Grd_263_Asghan_LAIRFOUND_Info","outputIds":["Grd_263_Asghan_LAIRFOUND_Info_15_01","Grd_263_Asghan_LAIRFOUND_Info_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Pełzacze nie będą wam już zagrażały!","en":"The minecrawlers shouldn''t be a threat anymore!","de":"Die Bedrohung durch die Minecrawler dürfte beendet sein!"}},{"speaker":"npc","text":{"pl":"To wspaniała wiadomość! Wyślę gońca do Thorusa z dobrymi nowinami!","en":"That''s good news. I''ll just send a messenger to Thorus!","de":"Das ist eine gute Nachricht. Werde gleich einen Boten zu Thorus schicken!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_263_asghan_grd_263_asghan_nest_info_15_01_0', 'GRD_263_Asghan', '{"id":"missions_dia_grd_263_asghan_grd_263_asghan_nest_info_15_01_0","npcId":"GRD_263_Asghan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_263_Asghan.d","sourceFunction":"Grd_263_Asghan_NEST_Info","outputIds":["Grd_263_Asghan_NEST_Info_15_01","Grd_263_Asghan_NEST_Info_06_02","Grd_263_Asghan_NEST_Info_15_03","Grd_263_Asghan_NEST_Info_06_04"],"lines":[{"speaker":"hero","text":{"pl":"Gdzieś tutaj musi być gniazdo pełzaczy.","en":"There must be a nest of minecrawlers here somewhere.","de":"Es muss hier irgendwo ein Nest der Minecrawler geben."}},{"speaker":"npc","text":{"pl":"Cała ta przeklęta góra jest jednym wielkim gniazdem pełzaczy!","en":"The whole bloody mountain is just one big crawler nest!","de":"Dieser ganze verdammte Berg ist ein einziges Nest."}},{"speaker":"hero","text":{"pl":"Dlaczego zamknięto ten szyb?","en":"Why have you closed this shaft?","de":"Warum ist dieser Schacht versperrt?"}},{"speaker":"npc","text":{"pl":"Nieważne ile pełzaczy zabijaliśmy, kolejne zastępy wyrastały jak spod ziemi.","en":"It didn''t matter how many crawlers we killed, more and more just kept coming out.","de":"Egal wie viele Crawler wir getötet haben, von dort kamen immer wieder mehr."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_263_asghan_grd_263_asghan_nest_info_15_05_4', 'GRD_263_Asghan', '{"id":"missions_dia_grd_263_asghan_grd_263_asghan_nest_info_15_05_4","npcId":"GRD_263_Asghan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_263_Asghan.d","sourceFunction":"Grd_263_Asghan_NEST_Info","outputIds":["Grd_263_Asghan_NEST_Info_15_05","Grd_263_Asghan_NEST_Info_06_06"],"lines":[{"speaker":"hero","text":{"pl":"Wygląda na to, że gdzieś w pobliżu jest ich gniazdo. Pozwól mi otworzyć drzwi!","en":"Sounds like there must be a nest somewhere near. Let me open the gate!","de":"Dann wird dort irgendwo ein Nest sein. Lass mich das Tor öffnen!"}},{"speaker":"npc","text":{"pl":"Nie! To przejście można otworzyć tylko za pozwoleniem Iana! Bez tego nie ma o czym mówić!","en":"No! This gate can only be opened with Ian''s permission! Nothing will be done before.","de":"Nein! Erst wenn Ian die Erlaubnis gibt, wird dieses Tor geöffnet! Vorher geht gar nichts."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_263_asghan_grd_263_asghan_open_info_15_05_4', 'GRD_263_Asghan', '{"id":"missions_dia_grd_263_asghan_grd_263_asghan_open_info_15_05_4","npcId":"GRD_263_Asghan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_263_Asghan.d","sourceFunction":"Grd_263_Asghan_OPEN_Info","outputIds":["Grd_263_Asghan_OPEN_Info_15_05","Grd_263_Asghan_OPEN_Info_06_06"],"lines":[{"speaker":"hero","text":{"pl":"Jakim warunkiem?","en":"What condition is that?","de":"Spuck''s aus, was für eine Bedingung?"}},{"speaker":"npc","text":{"pl":"Sprowadź mi tu najpierw dwóch albo trzech Strażników Świątynnych. Nie chcę tu siedzieć sam, gdy cały szyb zaroi się od pełzaczy!","en":"Just get me two or three templars for support, I don''t want to be here on my own when the crawlers come out of the shaft!","de":"Besorge erst mal zwei bis drei Templer zur Verstärkung, ich will nicht alleine hier stehen, falls die Crawler aus dem Schacht kommen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_263_asghan_grd_263_asghan_open_now_info_15_01_0', 'GRD_263_Asghan', '{"id":"missions_dia_grd_263_asghan_grd_263_asghan_open_now_info_15_01_0","npcId":"GRD_263_Asghan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_263_Asghan.d","sourceFunction":"Grd_263_Asghan_OPEN_NOW_Info","outputIds":["Grd_263_Asghan_OPEN_NOW_Info_15_01","Grd_263_Asghan_OPEN_NOW_Info_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Przygotowania skończone. Można już otworzyć drzwi!","en":"All preparations have been made. The gate can now be opened!","de":"Alle Vorbereitungen sind getroffen. Das Tor kann geöffnet werden!"}},{"speaker":"npc","text":{"pl":"Dobra, otwieramy szyb. Będzie niezły bal!","en":"Okay then, open the shaft now. Let the show begin.","de":"In Ordnung, dann öffne du den Schacht. Der Tanz kann beginnen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_grd_263_asghan_grd_263_asghan_smalltalk_info_15_01_0', 'GRD_263_Asghan', '{"id":"missions_dia_grd_263_asghan_grd_263_asghan_smalltalk_info_15_01_0","npcId":"GRD_263_Asghan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GRD_263_Asghan.d","sourceFunction":"Grd_263_Asghan_SMALLTALK_Info","outputIds":["Grd_263_Asghan_SMALLTALK_Info_15_01","Grd_263_Asghan_SMALLTALK_Info_06_02","Grd_263_Asghan_SMALLTALK_Info_15_03","Grd_263_Asghan_SMALLTALK_Info_06_04"],"lines":[{"speaker":"hero","text":{"pl":"Jak leci?","en":"Hey, how are you doing?","de":"Hey, wie siehts aus?"}},{"speaker":"npc","text":{"pl":"Ujdzie... Tak długo jak nikt nie będzie próbował otworzyć tych drzwi, nie będę musiał wdawać się w bójki.","en":"Okay... so long as nobody don''t get the idea of opening this gate, I don''t need to hurt anybody, either.","de":"Noch gut... Solange Niemand auf die Idee kommt, dieses Tor öffnen zu wollen, muss ich auch niemandem wehtun."}},{"speaker":"hero","text":{"pl":"A co jest takiego szczególnego za tymi drzwiami?","en":"What''s so special about this gate?","de":"Was ist denn so besonderes hinter dem Tor?"}},{"speaker":"npc","text":{"pl":"Pełzacze. Wielkie, paskudne pełzacze. Całe mnóstwo wielkich, paskudnych pełzaczy!","en":"Minecrawlers. Big, bad minecrawlers. Lots and lots and lots of them.","de":"Minecrawler. Große böse Minecrawler. Und zwar sehr...sehr...sehr viele."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_fokus_15_01_0', 'GUR_1200_YBerion', '{"id":"missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_fokus_15_01_0","npcId":"GUR_1200_YBerion","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1200_YBerion.d","sourceFunction":"Info_YBerion_BringFocus_FOKUS","outputIds":["Sit_2_PSI_Yberion_BringFocus_FOKUS_15_01","Sit_2_PSI_Yberion_BringFocus_FOKUS_12_02","Sit_2_PSI_Yberion_BringFocus_FOKUS_12_03","Sit_2_PSI_Yberion_BringFocus_FOKUS_12_04"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego ten kamień jest taki ważny?","en":"Why is the focus so important?","de":"Was hat es mit dem Fokus auf sich?"}},{"speaker":"npc","text":{"pl":"Ten magiczny artefakt zogniskuje duchową siłę naszych braci.","en":"It is a magical object which can concentrate our spiritual powers.","de":"Es ist ein magischer Gegenstand, der unsere geistigen Kräfte vereinigen wird."}},{"speaker":"npc","text":{"pl":"To jeden z pięciu kamieni ogniskujących, które posłużyły magom do utworzenia Bariery.","en":"It is one of the five focus stones used by the mages to erect the Barrier.","de":"Es handelt sich dabei um einen der fünf Fokussteine, den die Magier zum Errichten der Barriere benutzt haben."}},{"speaker":"npc","text":{"pl":"Jedna z moich wizji objawiła mi zastosowanie kamienia.","en":"In a vision I saw that we need to use the power of the focus.","de":"In einer Vision sah ich, dass wir uns die Kraft eines Fokus zu Nutze machen müssen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_fokus_15_05_4', 'GUR_1200_YBerion', '{"id":"missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_fokus_15_05_4","npcId":"GUR_1200_YBerion","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1200_YBerion.d","sourceFunction":"Info_YBerion_BringFocus_FOKUS","outputIds":["Sit_2_PSI_Yberion_BringFocus_FOKUS_15_05","Sit_2_PSI_Yberion_BringFocus_FOKUS_12_06"],"lines":[{"speaker":"hero","text":{"pl":"To musiała być niezwykle ciekawa wizja.","en":"Sounds like quite an interesting vision.","de":"War wohl eine ziemlich spannende Vision."}},{"speaker":"npc","text":{"pl":"Zesłał mi ją sam Śniący! Dzięki kamieniowi ogniskującemu będziemy mogli nawiązać z nim kontakt!","en":"My vision was a sign from the Sleeper. We can reach him with the focus!","de":"Meine Vision war ein Zeichen vom Schläfer. Mit dem Fokus können wir ihn erreichen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_ok_15_01_0', 'GUR_1200_YBerion', '{"id":"missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_ok_15_01_0","npcId":"GUR_1200_YBerion","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1200_YBerion.d","sourceFunction":"Info_YBerion_BringFocus_OK","outputIds":["Sit_2_PSI_Yberion_BringFocus_OK_15_01","Sit_2_PSI_Yberion_BringFocus_OK_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Przyniosę ci ten kamień ogniskujący!","en":"I''ll bring the focus back!","de":"Ich werde den Fokus zurückbringen!"}},{"speaker":"npc","text":{"pl":"Weź tę mapę. Zaznaczono na niej położenie kamienia.","en":"Take this map. The location of the focus is recorded on it.","de":"Nimm diese Karte hier, dort ist der Ort des Fokus verzeichnet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_wo_15_01_0', 'GUR_1200_YBerion', '{"id":"missions_dia_gur_1200_yberion_sit_2_psi_yberion_bring_focus_wo_15_01_0","npcId":"GUR_1200_YBerion","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1200_YBerion.d","sourceFunction":"Info_YBerion_BringFocus_WO","outputIds":["Sit_2_PSI_Yberion_BringFocus_WO_15_01","Sit_2_PSI_Yberion_BringFocus_WO_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie powinienem zacząć poszukiwania?","en":"Where shall I begin to search?","de":"Wo soll ich suchen?"}},{"speaker":"npc","text":{"pl":"Po wyjściu z Obozu skręć w prawo i wejdź na strome zbocze. Idź przez las, dopóki nie dojdziesz nad brzeg morza. Tam znajdziesz kamień ogniskujący.","en":"Leave the Camp, turn right and go up to the tall cliff. Go beyond the forest until you can see the sea. There you''ll find the focus.","de":"Wenn du das Lager verlässt, wende dich nach rechts und steige hinauf zur großen Klippe. Dort, hinter dem Wald, wo du das Meer sehen kannst, wirst du den Fokus finden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_bringweed_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_bringweed_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_BRINGWEED_Info","outputIds":["GUR_1201_CorKalom_BRINGWEED_15_00","GUR_1201_CorKalom_BRINGWEED_10_01","GUR_1201_CorKalom_BRINGWEED_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Przynoszę codzienną porcję ziela!","en":"I''m delivering the daily swampweed harvest!","de":"Ich bringe die tägliche Sumpfkrauternte!"}},{"speaker":"npc","text":{"pl":"TO ma być WSZYSTKO? Masz mi przynieść przynajmniej 100 sztuk!","en":"And THAT''s supposed to be the lot??? I expect the COMPLETE harvest, which means at least a 100 stalks!!!","de":"Und DAS soll alles sein??? Ich erwarte die KOMPLETTE Ernte, das sind mindestens 100 Stengel!!!"}},{"speaker":"npc","text":{"pl":"Ach, daj mi to. A teraz zejdź mi z oczu!","en":"Aargh, give it to me. And now get out of my sight!","de":"Ah, gib her. Und verzieh dich wieder!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_crawler_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_crawler_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_CRAWLER_Info","outputIds":["GUR_1201_CorKalom_CRAWLER_Info_15_01","GUR_1201_CorKalom_CRAWLER_Info_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak należy walczyć z pełzaczami?","en":"What''s the best way to fight the minecrawlers?","de":"Wie kämpfe ich am besten gegen die Minecrawler?"}},{"speaker":"npc","text":{"pl":"W kopalni spotkasz kilku naszych Strażników polujących na pełzacze dla ich wydzieliny. Porozmawiaj z Gor Na Videm, on ci pomoże.","en":"There are templars in the mine. They hunt the crawlers for their mandibles. Speak to Gor Na Vid. He will help you.","de":"In der Mine sind Templer. Sie jagen die Crawler wegen ihrer Zangen. Wende dich an Gor Na Vid. Er wird dir helfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_crawlerzangen_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_crawlerzangen_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_Crawlerzangen_Info","outputIds":["GUR_1201_CorKalom_Crawlerzangen_15_00","GUR_1201_CorKalom_Crawlerzangen_10_01","GUR_1201_CorKalom_Crawlerzangen_10_02","GUR_1201_CorKalom_Crawlerzangen_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Przyniosłem ci wnętrzności pełzaczy.","en":"I have crawlers'' mandibles for you...","de":"Ich habe Crawlerzangen für dich..."}},{"speaker":"npc","text":{"pl":"Wspaniale. W nagrodę możesz sobie wziąć jeden z moich najlepszych wywarów.","en":"Very good. Take some of my best potions as reward.","de":"Sehr gut. Nimm einige meiner besten Tränke als Belohnung."}},{"speaker":"npc","text":{"pl":"Świetnie. Weź sobie w nagrodę kilka moich wywarów.","en":"Good. Take some potions as a reward.","de":"Gut. Nimm ein paar Tränke als Belohnung."}},{"speaker":"npc","text":{"pl":"Hm. Tylko tyle? Masz tu napój mana i zejdź mi z oczu.","en":"Hm. That''s all of them? Here, take a mana potion and disappear.","de":"Hm. Das soll alles sein? Hier, nimm einen Manatrank und verschwinde."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_exit_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_exit_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_Exit_Info","outputIds":["GUR_1201_CorKalom_Exit_15_01","GUR_1201_CorKalom_Exit_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Do zobaczenia.","en":"I''ll be seeing you.","de":"Wir sehen uns."}},{"speaker":"npc","text":{"pl":"Oby Śniący wskazał ci właściwą drogę.","en":"May the Sleeper enlighten you.","de":"Möge der Schläfer dich erleuchten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_experimente_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_experimente_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_Experimente_Info","outputIds":["GUR_1201_CorKalom_Experimente_15_00","GUR_1201_CorKalom_Experimente_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Jakie eksperymenty przeprowadzasz?","en":"What kind of experiments do you do?","de":"Was machst du für Experimente?"}},{"speaker":"npc","text":{"pl":"Moje badania dotyczą spraw, o których nie masz najmniejszego pojęcia, chłopcze, więc przestań zawracać mi głowę!","en":"My research takes place on a level you don''t understand anything about, boy. So don''t waste my time!","de":"Meine Forschung befindet sich auf einer Ebene, von der du nichts verstehst, Bursche. Also verschwende nicht meine Zeit!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_find_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_find_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_FIND_Info","outputIds":["GUR_1201_CorKalom_FIND_Info_15_01","GUR_1201_CorKalom_FIND_Info_10_02","GUR_1201_CorKalom_FIND_Info_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak mam odnaleźć gniazdo pełzaczy?","en":"How can I find the nest in the mine?","de":"Wie soll ich in der Mine das Nest finden?"}},{"speaker":"npc","text":{"pl":"To najtrudniejsza część zadania. Nie wiem, gdzie powinieneś szukać, ani czego. Ale Śniący wskaże ci drogę w odpowiednim momencie.","en":"That''s the hardest part of the mission. I can''t tell you where to search, nor what to search for. But the Sleeper will be with you.","de":"Das ist der schwierige Teil der Mission. Ich kann dir weder sagen wo, noch was du suchen musst. Aber der Schläfer wird bei dir sein."}},{"speaker":"hero","text":{"pl":"To ci dopiero pocieszenie.","en":"Well, that''s a comfort.","de":"Na dann bin ich ja beruhigt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_first_10_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_first_10_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_FIRST_Info","outputIds":["GUR_1201_CorKalom_FIRST_10_00"],"lines":[{"speaker":"npc","text":{"pl":"Czego chcesz?","en":"What do you want?","de":"Was willst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_10_08_8', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_10_08_8","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_JoinPSI_Info","outputIds":["GUR_1201_CorKalom_JoinPSI_10_08","GUR_1201_CorKalom_JoinPSI_10_09","GUR_1201_CorKalom_JoinPSI_NOT_10_00","GUR_1201_CorKalom_JoinPSI_NOT_15_01"],"lines":[{"speaker":"npc","text":{"pl":"Dobrze. Jeśli Baalowie przemawiają za tobą, to mi wystarczy.","en":"Good. If the Baals support you, that should be enough for me.","de":"Gut. Wenn die Baals für dich sprechen, dann soll mir das reichen."}},{"speaker":"npc","text":{"pl":"Masz. Załóż to. A teraz idź robić coś pożytecznego.","en":"Here, put this on. And now go and make yourself useful.","de":"Hier, zieh das an. Und jetzt geh und mach dich nützlich."}},{"speaker":"npc","text":{"pl":"I?","en":"And?","de":"Und?"}},{"speaker":"hero","text":{"pl":"To już wszystko.","en":"That was it.","de":"Das war alles."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_JoinPSI_Info","outputIds":["GUR_1201_CorKalom_JoinPSI_15_00","GUR_1201_CorKalom_JoinPSI_15_01","GUR_1201_CorKalom_JoinPSI_10_02","GUR_1201_CorKalom_JoinPSI_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Chyba udało mi się przekonać Baalów!","en":"I think I have convinced the Baals!","de":"Ich glaube, ich habe die Baals überzeugt!"}},{"speaker":"hero","text":{"pl":"Baal Orun uważa, że jestem godnym sługą Śniącego.","en":"Baal Orun says I have proven to be a worthy servant of the Sleeper.","de":"Baal Orun sagt, ich habe mich als würdiger Diener des Schläfers erwiesen."}},{"speaker":"npc","text":{"pl":"Mów dalej...","en":"Carry on...","de":"Weiter ..."}},{"speaker":"hero","text":{"pl":"Baal Cadar ma mnie za pojętnego ucznia.","en":"Baal Cadar considers me a receptive student.","de":"Baal Cadar hält mich für einen gelehrigen Schüler."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_15_04_4', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_15_04_4","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_JoinPSI_Info","outputIds":["GUR_1201_CorKalom_JoinPSI_15_04","GUR_1201_CorKalom_JoinPSI_15_05","GUR_1201_CorKalom_JoinPSI_10_06","GUR_1201_CorKalom_JoinPSI_15_07"],"lines":[{"speaker":"hero","text":{"pl":"Baal Namib jest przekonany co do szczerości mojej wiary.","en":"Baal Namib is convinced that I''m a true believer.","de":"Baal Namib ist überzeugt, dass ich ein wahrer Anhänger des Glaubens bin."}},{"speaker":"hero","text":{"pl":"Dzięki mnie, Baal Tyon przeżył objawienie.","en":"Thanks to me, Baal Tyon had a vision.","de":"Baal Tyon hatte dank mir eine Vision."}},{"speaker":"npc","text":{"pl":"I?","en":"And?","de":"Und?"}},{"speaker":"hero","text":{"pl":"Baal Tondral uważa, że powinienem zostać przyjęty. Przyprowadziłem mu nowego ucznia.","en":"Baal Tondral says, I should receive the robe. I have brought him a new student.","de":"Baal Tondral sagt, ich soll die Robe erhalten. Ich habe einen neuen Schüler zu ihm geführt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_15_10_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_15_10_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_JoinPSI2_Info","outputIds":["GUR_1201_CorKalom_JoinPSI_15_10","GUR_1201_CorKalom_JoinPSI_10_11","GUR_1201_CorKalom_JoinPSI_15_12","GUR_1201_CorKalom_JoinPSI_10_13"],"lines":[{"speaker":"hero","text":{"pl":"Tylko tyle? Żadnego powitania, ani nic?","en":"\"That was it? No \"\"welcome\"\", no nothing?\"","de":"Das war alles? Kein \"Herzlich Willkommen\", kein gar nichts?"}},{"speaker":"npc","text":{"pl":"Witamy.","en":"Welcome.","de":"Herzlich willkommen."}},{"speaker":"hero","text":{"pl":"O wiele lepiej.","en":"Sounds much better.","de":"Gefällt mir schon viel besser."}},{"speaker":"npc","text":{"pl":"Przestań się tu kręcić. Zrób coś pożytecznego. Zanieś to ziele do Starego Obozu i daj je Gomezowi.","en":"Don''t hang around here! Do something. Take these weeds and give them to Gomez in the Old Camp.","de":"Steh hier nicht rum! Tu was. Hier, nimm dieses Kraut und bring es zu Gomez ins alte Lager."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_not_10_02_12', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_join_psi_not_10_02_12","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_JoinPSI_Info","outputIds":["GUR_1201_CorKalom_JoinPSI_NOT_10_02"],"lines":[{"speaker":"npc","text":{"pl":"Marnujesz tylko mój cenny czas. Wróć kiedy uda ci się przekonać do siebie co najmniej czterech Baalów!","en":"You''re wasting my precious time! Come back as soon as four of the Baals consider you worthy!","de":"Du stiehlst mir meine kostbare Zeit! Komm wieder, wenn mindestens vier der Baals dich für würdig erachten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_nest_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_nest_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_NEST_Info","outputIds":["GUR_1201_CorKalom_NEST_Info_15_01","GUR_1201_CorKalom_NEST_Info_10_02","GUR_1201_CorKalom_NEST_Info_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Nie przeprowadzaliście żadnych badań na pełzaczach? Może jakaś część ich ciała zawiera większe ilości wydzieliny od innych?","en":"Have you never examined the minecrawlers? I mean, maybe there''s another body part which contains more of the secretion.","de":"Habt ihr die Minecrawler nie untersucht? Ich meine, vielleicht gibt es ein anders Körperteil, das mehr von dem Sekret enthält."}},{"speaker":"npc","text":{"pl":"Oczywiście, zbadaliśmy kilka martwych pełzaczy, ale wydzielina zdaje się być gromadzona wyłącznie w ich gruczołach jadowych.","en":"Of course we have taken some minecrawlers apart, but only their mandibles seemed to contain the secretion.","de":"Natürlich haben wir schon einige Minecrawler seziert, aber nur ihre Zangen scheinen das Sekret zu enthalten."}},{"speaker":"npc","text":{"pl":"To musi być coś innego. Znajdź ich gniazdo, a poznasz odpowiedź!","en":"There must be something else. Find their nest and you''ll find the answer!","de":"Es muss etwas anderes geben. Finde ihr Nest und du findest die Antwort!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_rat_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_rat_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_RAT_Info","outputIds":["GUR_1201_CorKalom_RAT_Info_15_01","GUR_1201_CorKalom_RAT_Info_10_02","GUR_1201_CorKalom_RAT_Info_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Widzę, że nie obejdzie się bez rozlewu krwi.","en":"Looks like this might become quite a bloody adventure!","de":"Das wird bestimmt ein blutiges Abenteuer!"}},{"speaker":"npc","text":{"pl":"Weź ze sobą te wywary.","en":"Take these potions with you.","de":"Nimm diese Heiltränke mit."}},{"speaker":"npc","text":{"pl":"Nie dostajesz ich ode mnie dlatego, że zależy mi na twoim życiu, tylko ze względu na rangę zadania.","en":"I am not giving them to you because I want you to stay alive, but because this task needs to be done.","de":"Ich gebe sie dir nicht, weil ich unbedingt will, das du am Leben bleibst, sondern weil diese Aufgabe erfüllt werden muss."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_recipe_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_recipe_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_Recipe_Info","outputIds":["GUR_1201_CorKalom_Recipe_15_00","GUR_1201_CorKalom_Recipe_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Jeden z kupców ze Starego Obozu jest zainteresowany twoją recepturą na napój uzdrawiający.","en":"One of the merchants from the Old Camp would like to have the recipe for a healing potion.","de":"Einer der Händler aus dem Alten Lager will das Rezept für einen Heiltrank von dir haben."}},{"speaker":"npc","text":{"pl":"Moje receptury nie są na sprzedaż!","en":"My recipes are not for sale!","de":"Meine Rezepte sind unverkäuflich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_run_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_run_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_RUN_Info","outputIds":["GUR_1201_CorKalom_RUN_Info_15_01","GUR_1201_CorKalom_RUN_Info_10_02","GUR_1201_CorKalom_RUN_Info_15_03","GUR_1201_CorKalom_RUN_Info_10_04"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę te pełzacze?","en":"Where will I find the minecrawlers?","de":"Wo finde ich die Minecrawler?"}},{"speaker":"npc","text":{"pl":"W Starej Kopalni.","en":"In the Old Mine.","de":"In der Alten Mine."}},{"speaker":"hero","text":{"pl":"A gdzie leży Stara Kopalnia?","en":"Where is the Old Mine?","de":"Wo ist die Alte Mine?"}},{"speaker":"npc","text":{"pl":"Weź tę mapę. Zaznaczono na niej wszystkie ważniejsze miejsca wewnątrz Bariery.","en":"Take this map. Any important places within the Barrier are marked on it.","de":"Nimm diese Karte. Dort sind alle wichtigen Orte innerhalb der Barriere eingezeichnet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_sache_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_sache_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_SACHE_Info","outputIds":["GUR_1201_CorKalom_SACHE_Info_15_01","GUR_1201_CorKalom_SACHE_Info_10_02","GUR_1201_CorKalom_SACHE_Info_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Wydzieliny?","en":"Secretion?","de":"Sekret?"}},{"speaker":"npc","text":{"pl":"Tak. Jak zapewne wiesz, przygotowuję magiczne wywary, które pozwolą nam nawiązać kontakt ze Śniącym. Jednak do tego celu potrzebuję dużych ilości wydzieliny z wnętrzności pełzaczy.","en":"Yes. As you must know, I produce the magic potions for the invocation of the Sleeper. For this purpose I need the secretion from the minecrawlers'' mandibles.","de":"Ja. Wie du sicher schon weißt, stelle ich die Elixiere für die Anrufung des Schläfers her. Ich benutze dafür das Sekret aus den Zangen der Minecrawler."}},{"speaker":"npc","text":{"pl":"Wiesz, co to są pełzacze, prawda?","en":"You know what minecrawlers are, don''t you?","de":"Du weißt doch, was Minecrawler sind?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_sache_ja_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_sache_ja_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_SACHE_JA","outputIds":["GUR_1201_CorKalom_SACHE_JA_15_01","GUR_1201_CorKalom_SACHE_JA_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Tak.","en":"Yes.","de":"Ja."}},{"speaker":"npc","text":{"pl":"To świetnie!","en":"Very good!","de":"Ausgezeichnet!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_sache_nein_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_sache_nein_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_SACHE_NEIN","outputIds":["GUR_1201_CorKalom_SACHE_NEIN_15_01","GUR_1201_CorKalom_SACHE_NEIN_10_02","GUR_1201_CorKalom_SACHE_NEIN_10_03","GUR_1201_CorKalom_SACHE_NEIN_10_04"],"lines":[{"speaker":"hero","text":{"pl":"Nie.","en":"No.","de":"Nein"}},{"speaker":"npc","text":{"pl":"To bardzo groźne istoty zamieszkujące mroczne korytarze kopalni. Pełzacze często atakują pracujących tam górników.","en":"They are dangerous beasts that creep through dark mines and devour any human flesh they can get.","de":"Das sind gefährliche Bestien, die durch die dunklen Minen kriechen und jeden Menschen verspeisen, den sie fassen können."}},{"speaker":"npc","text":{"pl":"Ich wnętrzności zawierają szczególną wydzielinę.","en":"Their mandibles contain a special secretion.","de":"Ihre Zangen enthalten ein ganz besonderes Sekret."}},{"speaker":"npc","text":{"pl":"Wykorzystuję ją do wytwarzania napoju, który otwiera przed nami duchową ścieżkę do Śniącego.","en":"I use it to produce a potion which guides the spiritual path to the Sleeper.","de":"Aus diesem Sekret stelle ich ein Elixier her, das uns den spirituellen Weg zum Schläfer zeigt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_vision_info_10_09_8', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_vision_info_10_09_8","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_VISION_Info","outputIds":["GUR_1201_CorKalom_VISION_Info_10_09"],"lines":[{"speaker":"npc","text":{"pl":"Musi być coś jeszcze.","en":"There must be something else.","de":"Es muss etwas anderes geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791208);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_vision_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_vision_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_VISION_Info","outputIds":["GUR_1201_CorKalom_VISION_Info_15_01","GUR_1201_CorKalom_VISION_Info_10_02","GUR_1201_CorKalom_VISION_Info_10_03","GUR_1201_CorKalom_VISION_Info_10_04"],"lines":[{"speaker":"hero","text":{"pl":"Mów dalej...","en":"Speak on!","de":"Erzähl weiter!"}},{"speaker":"npc","text":{"pl":"Cóż, jakiś czas temu Śniący objawił mi się osobiście i dał mi znak.","en":"Well, just a short time ago I had a vision of the Sleeper himself. He gave me a sign.","de":"Also, ich hatte vor kurzem eine Vision vom Schläfer persönlich. Er gab mir ein Zeichen."}},{"speaker":"npc","text":{"pl":"Dał mi do zrozumienia, że istnieje inny sposób, nie wymagający wydzieliny z wnętrzności pełzaczy.","en":"He made me understand that there is a means other than the secretion from the mandibles.","de":"Er gab mir zu verstehen, dass es ein anderes Mittel gibt als das Sekret der Zangen."}},{"speaker":"npc","text":{"pl":"I wybrał mnie, bym przekazał komuś jego zalecenia. Nie wypełniasz tego zadania dla mnie! To polecenie samego Śniącego!","en":"And he chose me to pass on this mission. You''re not getting this mission from me. You''re getting it from the Sleeper!","de":"Und er wählte mich, diese Mission weiterzugeben. Du bekommst diese Mission nicht von mir. Du bekommst sie vom Schläfer!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_vision_info_15_05_4', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_vision_info_15_05_4","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_VISION_Info","outputIds":["GUR_1201_CorKalom_VISION_Info_15_05","GUR_1201_CorKalom_VISION_Info_10_06","GUR_1201_CorKalom_VISION_Info_10_07","GUR_1201_CorKalom_VISION_Info_10_08"],"lines":[{"speaker":"hero","text":{"pl":"To niemożliwe!","en":"Impossible!","de":"Nicht möglich!"}},{"speaker":"npc","text":{"pl":"Milcz, głupcze!","en":"Be silent, fool!","de":"Schweig, Narr!"}},{"speaker":"npc","text":{"pl":"Dał mi do zrozumienia, że wybraliśmy właściwą drogę, ale dysponujemy niewystarczającymi środkami.","en":"He made me understand that the path I have embarked upon is right, but the means aren''t strong enough.","de":"Er gab mir zu verstehen, dass mein Weg richtig ist, nur dass das Mittel nicht stark genug sei."}},{"speaker":"npc","text":{"pl":"Oznacza to, że WŁAŚCIWE środki znajdziemy u pełzaczy, ale sama wydzielina z wnętrzności to za mało.","en":"The right means can be found with the minecrawlers, but the mandibles are not sufficient.","de":"Das bedeutet, das Mittel, was wir suchen, finden wir bei den Minecrawlern, nur die Zangen sind nicht ausreichend."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_wanna_join_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_wanna_join_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_WannaJoin_Info","outputIds":["GUR_1201_CorKalom_WannaJoin_15_00","GUR_1201_CorKalom_WannaJoin_15_01","GUR_1201_CorKalom_WannaJoin_10_02","GUR_1201_CorKalom_WannaJoin_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym przyłączyć się do Bractwa.","en":"I would like to join the Brotherhood.","de":"Ich will in die Bruderschaft aufgenommen werden."}},{"speaker":"hero","text":{"pl":"Podobno jesteś zwierzchnikiem Nowicjuszy i to ty decydujesz kto zostanie przyjęty.","en":"I''ve heard you''re the master of the novices and that you decide who''s allowed to join.","de":"Ich habe gehört, du bist der Meister der Novizen, und entscheidest, wer aufgenommen wird."}},{"speaker":"npc","text":{"pl":"Nie mam teraz czasu! Moje eksperymenty są zbyt ważne, bym mógł zawracać sobie głowę nowoprzybyłymi!","en":"I don''t have time! My experiments are too important for me to spend any time on new novices.","de":"Ich habe keine Zeit! Meine Experimente sind zu wichtig, als dass ich mich um neue Novizen kümmern könnte."}},{"speaker":"npc","text":{"pl":"Zdam się na osąd Baalów. Jeśli oni uznają, że jesteś gotów, by do nas dołączyć zgłoś się do mnie ponownie.","en":"I''ll rely on the judgement of the Baals. When they say you''re ready to wear the robe of a novice, come back to me.","de":"Ich verlasse mich auf das Urteil der Baals. Wenn sie sagen, dass du bereit bist, die Robe eines Novizen zu tragen, kehre zu mir zurück."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_weg_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_gur_1201_cor_kalom_weg_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"GUR_1201_CorKalom_WEG_Info","outputIds":["GUR_1201_CorKalom_WEG_Info_15_01","GUR_1201_CorKalom_WEG_Info_10_02","GUR_1201_CorKalom_WEG_Info_10_03","GUR_1201_CorKalom_WEG_Info_10_04"],"lines":[{"speaker":"hero","text":{"pl":"To ci dopiero będzie mroczna wyprawa.","en":"That sounds like a dark and sinister kind of search!","de":"Das wird bestimmt eine finstere Suche!"}},{"speaker":"npc","text":{"pl":"Weź te zwoje. Znajdziesz na nich magiczne formuły zaklęcia Światła. Przydadzą ci się w nieoświetlonych szybach.","en":"Take these spell scrolls of light, you''ll be able to make good use of them in the dark shafts.","de":"Nimm diese Spruchrollen des Lichts, du wirst sie in den dunklen Stollen gut gebrauchen können."}},{"speaker":"npc","text":{"pl":"Świątynni Strażnicy z kopalni będą ci służyć pomocą.","en":"The templars in the mines will help you.","de":"Die Templer in den Minen werden dir helfen."}},{"speaker":"npc","text":{"pl":"Oby Śniący dodał ci sił. Niech jego blask rozświetla twą drogę, gdziekolwiek się udajesz!","en":"May the Sleeper give you power, may his light shine on your path and enlighten your spirit, and may he strengthen your will!","de":"Möge der Schläfer dir Kraft schenken, möge sein Licht auf deinem Weg leuchten, deinen Geist erhellen und deinen Willen festigen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_Belohnung_Info","outputIds":["Info_CorKalom_Belohnung_15_00","Info_CorKalom_Belohnung_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Co z moją zapłatą?","en":"What about my payment?","de":"Wie sieht es mit einer Belohnung aus?"}},{"speaker":"npc","text":{"pl":"A czego chcesz?","en":"What do you want?","de":"Was willst du haben?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_mana_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_mana_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_Belohnung_MANA","outputIds":["Info_CorKalom_Belohnung_MANA_15_00","Info_CorKalom_Belohnung_MANA_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Daj mi napoje mana.","en":"Mana potions.","de":"Manatränke."}},{"speaker":"npc","text":{"pl":"Niech te napoje dodadzą ci sił!","en":"May these potions give you strength!","de":"Mögen diese Tränke dir Kraft schenken!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_ore_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_ore_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_Belohnung_ORE","outputIds":["Info_CorKalom_Belohnung_ORE_15_00","Info_CorKalom_Belohnung_ORE_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Wystarczy mi ruda.","en":"Give me ore.","de":"Gib mir Erz."}},{"speaker":"npc","text":{"pl":"To powinno zaspokoić twoją chciwość.","en":"This should satisfy your greed for ore.","de":"Dies soll deine Gier nach Erz zufrieden stellen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_scroll_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_belohnung_scroll_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_Belohnung_SCROLL","outputIds":["Info_CorKalom_Belohnung_SCROLL_15_00","Info_CorKalom_Belohnung_SCROLL_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Daj mi te zwoje z zaklęciami.","en":"Give me these spell scrolls.","de":"Gib mir die Spruchrollen."}},{"speaker":"npc","text":{"pl":"Wykorzystaj je mądrze.","en":"Use these spells wisely.","de":"Setze diese Zauber hier mit Bedacht ein!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_earn_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_earn_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_EARN","outputIds":["Info_CorKalom_BringBook_Earn_15_01","Info_CorKalom_BringBook_Earn_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Co dostanę w zamian?","en":"What will I get for it?","de":"Was ist für mich drin?"}},{"speaker":"npc","text":{"pl":"Czyż nie przekonałem cię już o mojej hojności? Otrzymasz nagrodę odpowiednią do rangi zadania.","en":"Have I not already proven my generosity to you? You will receive a just reward.","de":"Habe ich nicht schon mehr als einmal meine Großzügigkeit bewiesen? Du wirst angemessen entlohnt werden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_info_10_05_4', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_info_10_05_4","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_Info","outputIds":["Info_CorKalom_BringBook_Info_10_05","Info_CorKalom_BringBook_Info_10_06","Info_CorKalom_BringBook_Info_10_07","Info_CorKalom_BringBook_Info_10_08"],"lines":[{"speaker":"npc","text":{"pl":"Nie. Posłuchaj: istnieje prastary almanach zawierający potrzebne nam informacje.","en":"No, listen to me. There''s an almanac which contains what we need to know.","de":"Nein, hör mir zu. Es gibt einen Almanach, in dem das steht, was wir wissen müssen."}},{"speaker":"npc","text":{"pl":"Odkupiliśmy go od Corristo, jednego z Magów Ognia ze Starego Obozu.","en":"We bought the book off the fire mage Corristo from the Old Camp.","de":"Wir haben dieses Buch dem Feuermagier Corristo aus dem Alten Lager abgekauft."}},{"speaker":"npc","text":{"pl":"Niestety, został nam skradziony w drodze ze Starego Obozu.","en":"However, it was stolen when they tried to bring it here from the Old Camp.","de":"Allerdings ist es beim Transport vom Alten Lager hierher geraubt worden."}},{"speaker":"npc","text":{"pl":"Kazałem Talasowi, jednemu z Nowicjuszy, dostarczyć mi tę księgę, ale ten głupiec pozwolił się okraść.","en":"I had charged Talas, a novice, with collecting the book for me, but he was robbed.","de":"Ich hatte Talas, einen Novizen, damit beauftragt, das Buch zu mir zu bringen, aber er wurde überfallen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_info_10_09_8', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_info_10_09_8","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_Info","outputIds":["Info_CorKalom_BringBook_Info_10_09","Info_CorKalom_BringBook_Info_10_10"],"lines":[{"speaker":"npc","text":{"pl":"Zawiódł mnie, ale postanowiłem dać mu drugą szansę. Ma odzyskać almanach.","en":"He let me down, but I''ve given him another chance. He must get the stolen almanac back.","de":"Er hat mich enttäuscht, aber ich habe ihm noch eine Chance gegeben. Er hat nun den Auftrag, den gestohlenen Almanach zurückzuholen."}},{"speaker":"npc","text":{"pl":"Porozmawiaj z nim. Przyda mu się każda pomoc.","en":"Talk to him. He''ll need any help he can get.","de":"Sprich mit ihm. Er wird alle Hilfe brauchen, die er bekommen kann."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_info_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_info_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_Info","outputIds":["Info_CorKalom_BringBook_Info_15_01","Info_CorKalom_BringBook_Info_10_02","Info_CorKalom_BringBook_Info_10_03","Info_CorKalom_BringBook_Info_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Czy możemy teraz przystąpić do przywołania Śniącego?","en":"Can we start invoking the Sleeper now?","de":"Kann nun die Anrufung des Schläfers beginnen?"}},{"speaker":"npc","text":{"pl":"Nie! Nie udało mi się jeszcze znaleźć sposobu na naładowanie kamienia ogniskującego.","en":"No! I haven''t found a method to charge the focus yet.","de":"Nein! Es ist mir noch nicht gelungen, eine Methode zu entwickeln, den Fokus aufzuladen."}},{"speaker":"npc","text":{"pl":"Niestety, nie dysponujemy starożytną wiedzą na temat tych artefaktów.","en":"We are missing the ancient knowledge about these artefacts.","de":"Uns fehlt das Alte Wissen über diese Artefakte."}},{"speaker":"hero","text":{"pl":"Chcesz powiedzieć, że zdobyłem te jaja na próżno?","en":"Do you mean to say I collected the eggs for nothing?","de":"Heißt das, es war vergebens, die Eier zu holen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_success_10_05_4', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_success_10_05_4","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_Success_Info","outputIds":["Info_CorKalom_BringBook_Success_10_05"],"lines":[{"speaker":"npc","text":{"pl":"Zaczekaj do wieczora, wtedy przyjdź na dziedziniec świątyni. Tam się zbierzemy i spróbujemy przywołać Śniącego.","en":"Wait till nighttime, then come to the temple courtyard. We will gather there to invoke the almighty Sleeper.","de":"Komme bei Nacht zum Tempelvorplatz. Dort werden wir uns versammeln, um den allmächtigen Schläfer zu rufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_success_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_success_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_Success_Info","outputIds":["Info_CorKalom_BringBook_Success_15_01","Info_CorKalom_BringBook_Success_10_02","Info_CorKalom_BringBook_Success_10_03","Info_CorKalom_BringBook_Success_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem twoją księgę.","en":"I''ve found the book","de":"Ich hab'' das Buch gefunden"}},{"speaker":"npc","text":{"pl":"Dobra robota. Teraz mamy wszystkie potrzebne składniki.","en":"Good work. You have all we need.","de":"Gute Arbeit. Du hast alles besorgt, was wir brauchen."}},{"speaker":"npc","text":{"pl":"Zajmę się teraz przygotowaniami.","en":"I''ll complete the preparations now.","de":"Ich werde jetzt die letzten Vorbereitungen treffen."}},{"speaker":"hero","text":{"pl":"Kiedy odbędzie się wielkie przywołanie?","en":"Where will the invocation take place?","de":"Wo wird die Anrufung stattfinden?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_where_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_where_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_WHERE","outputIds":["Info_CorKalom_BringBook_Where_15_01","Info_CorKalom_BringBook_Where_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę Talasa?","en":"Where can I find Talas?","de":"Wo finde ich Talas?"}},{"speaker":"npc","text":{"pl":"Powinien być u stóp świątyni. Próbuje zjednać sobie kogoś do pomocy.","en":"He''s in the forecourt at the temple hill, trying to get people to help him.","de":"Er versucht auf dem Vorplatz des Tempelbergs Leute zu finden, die ihm helfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_who_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_info_cor_kalom_bring_book_who_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringBook_WHO","outputIds":["Info_CorKalom_BringBook_Who_15_01","Info_CorKalom_BringBook_Who_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Kto ukradł tę księgę?","en":"Who stole the almanac?","de":"Wer hat den Almanach gestohlen?"}},{"speaker":"npc","text":{"pl":"Talas twierdzi, że został obrabowany przez Czarne Gobliny. Brzmi nieprawdopodobnie, ale mogło się tak zdarzyć...","en":"Talas told me he was mugged by black goblins. It sounds strange, but not impossible.","de":"Talas hat berichtet, dass er von schwarzen Goblins überfallen wurde. Merkwürdig, aber nicht unmöglich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_drug_monopol_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_drug_monopol_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_Kalom_DrugMonopol_Info","outputIds":["Mis_1_Psi_Kalom_DrugMonopol_15_00","Mis_1_Psi_Kalom_DrugMonopol_10_01","Mis_1_Psi_Kalom_DrugMonopol_10_02","Mis_1_Psi_Kalom_DrugMonopol_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Masz dla mnie jeszcze jakieś zadania?","en":"Have YOU got another task for me?","de":"Hast DU noch eine Aufgabe für mich?"}},{"speaker":"npc","text":{"pl":"W Nowym Obozie kilku ludzi zaczęło uprawę ziela na własną rękę.","en":"In the New Camp there is a small group of men who have started producing their own weed.","de":"Im Neuen Lager gibt es eine kleine Gruppe von Männern, die ihre eigene Krautproduktion angefangen haben."}},{"speaker":"npc","text":{"pl":"Sie wollen unsere Kunden im Neuen Lager abwerben, Das werden wir nicht zulassen.","en":"Sie wollen unsere Kunden im Neuen Lager abwerben, Das werden wir nicht zulassen.","de":"Sie wollen unsere Kunden im Neuen Lager abwerben, Das werden wir nicht zulassen."}},{"speaker":"npc","text":{"pl":"Chcę, żebyś położył temu kres.","en":"See to it that they stop their production.","de":"Kümmere dich darum, dass sie die Produktion einstellen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_drug_monopol_15_04_4', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_drug_monopol_15_04_4","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_Kalom_DrugMonopol_Info","outputIds":["Mis_1_Psi_Kalom_DrugMonopol_15_04","Mis_1_Psi_Kalom_DrugMonopol_10_05","Mis_1_Psi_Kalom_DrugMonopol_10_06"],"lines":[{"speaker":"hero","text":{"pl":"Jak...","en":"How...","de":"Und wie ..."}},{"speaker":"npc","text":{"pl":"To już nie moja sprawa!","en":"Do not bother me with details!","de":"Belästige mich nicht mit Details!"}},{"speaker":"npc","text":{"pl":"Ich obozowisko musi znajdować się gdzieś w pobliżu Nowego Obozu. Wiesz, co masz zrobić...","en":"The weed mixers'' camp must be somewhere outside the New Camp. You know what to do.","de":"Die Krautmischer müssen ihr Lager irgendwo außerhalb des Neuen Lagers haben. Du weißt, was du zu tun hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_krautbote_back_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_krautbote_back_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_Kalom_KrautboteBACK_Info","outputIds":["Mis_1_Psi_Kalom_KrautboteBACK_15_00","Mis_1_Psi_Kalom_KrautboteBACK_10_01","Mis_1_Psi_Kalom_KrautboteBACK_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Dostarczyłem przesyłkę.","en":"I''ve delivered the weed.","de":"Ich habe das Kraut abgeliefert."}},{"speaker":"npc","text":{"pl":"To dobrze. Poszukaj sobie jakiegoś nowego zajęcia.","en":"Good. Get another task somewhere else.","de":"Gut. Mach dich anderweitig nützlich."}},{"speaker":"npc","text":{"pl":"Gdzie jest 500 bryłek rudy, chłopcze? Lepiej się pospiesz. Nie będę długo czekał.","en":"Where''s the 500 ore, boy? Make sure I get them real fast!","de":"Wo sind die 500 Erz, Bursche? Beeil dich besser, sie mir zu bringen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_success_15_00_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_success_15_00_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_Kalom_Success_Info","outputIds":["Mis_1_Psi_Kalom_Success_15_00","Mis_1_Psi_Kalom_Success_10_01","Mis_1_Psi_Kalom_Success_15_02","Mis_1_Psi_Kalom_Success_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Wracając do produkcji ziela w Nowym Obozie...","en":"Regarding the weed production in the New Camp...","de":"Wegen der Krautherstellung im Neuen Lager ..."}},{"speaker":"npc","text":{"pl":"Tak?","en":"Yes?","de":"Ja?"}},{"speaker":"hero","text":{"pl":"Nie mogę znaleźć tych ludzi.","en":"I can''t find these men.","de":"Ich finde die Männer nicht."}},{"speaker":"npc","text":{"pl":"Cóż, mogłem się tego po tobie spodziewać.","en":"I wouldn''t have expected anything else from you.","de":"Ich hatte nichts anderes von dir erwartet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_success_15_04_4', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_1_psi_kalom_success_15_04_4","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_Kalom_Success_Info","outputIds":["Mis_1_Psi_Kalom_Success_15_04","Mis_1_Psi_Kalom_Success_10_05","Mis_1_Psi_Kalom_Success_10_06"],"lines":[{"speaker":"hero","text":{"pl":"Już po kłopocie.","en":"They are gone.","de":"Es gibt sie nicht mehr."}},{"speaker":"npc","text":{"pl":"Zaskakujesz mnie. Chyba cię trochę niedoceniałem. Może jednak będzie z ciebie jakiś pożytek.","en":"You surprise me. I underestimated your abilities. Maybe you could be useful after all.","de":"Du überraschst mich. Ich hatte dich unterschätzt. Vielleicht könntest du uns doch zu etwas nützen."}},{"speaker":"npc","text":{"pl":"Rede mit den Baals.","en":"Rede mit den Baals.","de":"Rede mit den Baals."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_10_05_4', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_10_05_4","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringMCQBalls_Success_Info","outputIds":["Mis_2_PSI_Kalom_BringMCQEggs_Success_10_05","Mis_2_PSI_Kalom_BringMCQEggs_Success_15_06","Mis_2_PSI_Kalom_BringMCQEggs_Success_10_07"],"lines":[{"speaker":"npc","text":{"pl":"A, tak... Dziękuję.","en":"Oh, right... Thank you.","de":"Ah, ja richtig ... Danke."}},{"speaker":"hero","text":{"pl":"Wolałbym jakąś NAMACALNĄ nagrodę!","en":"I mean a TANGIBLE reward.","de":"Ich meine eine HANDFESTE Belohnung."}},{"speaker":"npc","text":{"pl":"Dobrze już! Czego chcesz?","en":"Okay, okay. What do you want?","de":"Na gut, na gut. Was willst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringMCQBalls_Success_Info","outputIds":["Mis_2_PSI_Kalom_BringMCQEggs_Success_15_01","Mis_2_PSI_Kalom_BringMCQEggs_Success_10_02","Mis_2_PSI_Kalom_BringMCQEggs_Success_10_03","Mis_2_PSI_Kalom_BringMCQEggs_Success_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem jaja złożone przez królową pełzaczy.","en":"I found eggs belonging to a crawler queen","de":"Ich habe Eier einer Crawler-Königin gefunden"}},{"speaker":"npc","text":{"pl":"Wiedziałem! Moja wizja była znakiem od Śniącego! Te jaja z pewnością zawierają silną wydzielinę!","en":"I knew it. My vision was a sign. The queen''s eggs must contain the strong secretion!","de":"Ich wusste es. Meine Vision war ein Zeichen. Die Eier ihrer Königin enthalten also das starke Sekret!"}},{"speaker":"npc","text":{"pl":"Świetnie. Dzięki nim przygotuję napój, który pozwoli nam nawiązać kontakt ze Śniącym!","en":"Excellent, with it I can create a potion to contact the Sleeper!","de":"Ausgezeichnet, damit kann ich ein Elixier brauen, das uns den Kontakt zum Schläfer ermöglicht!"}},{"speaker":"hero","text":{"pl":"A co z moją nagrodą?","en":"What about my reward?","de":"Was ist mit der Belohnung?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_heal_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_heal_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringMCQBalls_Success_HEAL","outputIds":["Mis_2_PSI_Kalom_BringMCQEggs_Success_HEAL_15_01","Mis_2_PSI_Kalom_BringMCQEggs_Success_HEAL_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Daj mi napój uzdrawiający.","en":"A healing potion.","de":"Ein Heilmittel."}},{"speaker":"npc","text":{"pl":"Niech ten napój przedłuży twoje życie.","en":"May this potion prolong your life!","de":"Möge dieser Trank dein Leben verlängern !"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_mana_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_mana_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringMCQBalls_Success_MANA","outputIds":["Mis_2_PSI_Kalom_BringMCQEggs_Success_MANA_15_01","Mis_2_PSI_Kalom_BringMCQEggs_Success_MANA_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Może być mana.","en":"Mana.","de":"Mana."}},{"speaker":"npc","text":{"pl":"Niech ten napój wzmocni drzemiącą w tobie magię.","en":"May this potion strengthen the magic within you!","de":"Möge dieser Trank die magische Energie in dir stärken!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_ore_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_ore_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringMCQBalls_Success_ORE","outputIds":["Mis_2_PSI_Kalom_BringMCQEggs_Success_ORE_15_01","Mis_2_PSI_Kalom_BringMCQEggs_Success_ORE_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Wystarczy mi ruda.","en":"Ore.","de":"Erz."}},{"speaker":"npc","text":{"pl":"Przyjmij tę rudę jako oznakę wdzięczności całego Bractwa!","en":"Take this ore as a sign of gratitude from the entire Brotherhood!","de":"Nimm dieses Erz als Zeichen der Dankbarkeit der gesamten Bruderschaft!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_rune_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_rune_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringMCQBalls_Success_RUNE","outputIds":["Mis_2_PSI_Kalom_BringMCQEggs_Success_RUNE_15_01","Mis_2_PSI_Kalom_BringMCQEggs_Success_RUNE_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Daj mi jakąś runę.","en":"A rune.","de":"Eine Rune."}},{"speaker":"npc","text":{"pl":"Niech ta runa rozświetla twą drogę!","en":"May this rune shine on your path!","de":"Möge diese Rune hier deinen Weg erleuchten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_waffe_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_mis_2_psi_kalom_bring_mcqeggs_success_waffe_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringMCQBalls_Success_WAFFE","outputIds":["Mis_2_PSI_Kalom_BringMCQEggs_Success_WAFFE_15_01","Mis_2_PSI_Kalom_BringMCQEggs_Success_WAFFE_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Daj mi jakiś oręż.","en":"A weapon.","de":"Eine Waffe."}},{"speaker":"npc","text":{"pl":"Niech ten oręż sieje śmierć w szeregach twoich wrogów!","en":"May this weapon destroy your enemies!","de":"Möge diese Waffe deine Feinde niederstrecken!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_sit_2_psi_yberion_bluff_info3_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_sit_2_psi_yberion_bluff_info3_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BLUFF_Info","outputIds":["Sit_2_PSI_Yberion_BLUFF_Info3_15_01","Sit_2_PSI_Yberion_BLUFF_Info3_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Y''Berion powiedział, że wynagrodzisz mnie za dostarczenie kamienia!","en":"Y''Berion said you''d pay me if I brought you the focus!","de":"Y''Berion sagte mir, du würdest mich entlohnen, wenn ich dir den Fokus bringe!"}},{"speaker":"npc","text":{"pl":"Czyżby? Tak powiedział? No tak. 50 bryłek rudy chyba wystarczy?","en":"Really? He said that? Well then. I suppose 50 ore should be enough!","de":"Tatsächlich? Hat er das gesagt? Nun gut. Ich denke, 50 Erz sollten reichen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1201_cor_kalom_sit_2_psi_yberion_bring_focus_info3_15_01_0', 'GUR_1201_CorKalom', '{"id":"missions_dia_gur_1201_cor_kalom_sit_2_psi_yberion_bring_focus_info3_15_01_0","npcId":"GUR_1201_CorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1201_CorKalom.d","sourceFunction":"Info_CorKalom_BringFocus_Info","outputIds":["Sit_2_PSI_Yberion_BringFocus_Info3_15_01","Sit_2_PSI_Yberion_BringFocus_Info3_10_02","Sit_2_PSI_Yberion_BringFocus_Info3_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Y''Berion. Mam kamień ogniskujący.","en":"Y''Berion sent me. I have the focus.","de":"Y''Berion schickt mich. Ich habe den Fokus."}},{"speaker":"npc","text":{"pl":"Ach, kamień ogniskujący... Nareszcie mogę zbadać magiczną naturę tego artefaktu.","en":"Ahhhh - the focus... At last. Now I can study the magic of these artefacts.","de":"Ahhhh - der Fokus ... Jetzt kann ich mich endlich den Studien über die Magie dieser Artefakte widmen."}},{"speaker":"npc","text":{"pl":"Gdybym tylko miał dość wydzieliny... Niech to piekło pochłonie!","en":"If I only had enough secretion... damn!","de":"Wenn ich nur ausreichend Sekret hätte ... Verflucht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_after_info_08_09_8', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_after_info_08_09_8","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_AFTER_Info","outputIds":["GUR_1202_CorAngar_AFTER_Info_08_09","GUR_1202_CorAngar_AFTER_Info_08_10","GUR_1202_CorAngar_AFTER_Info_08_11","GUR_1202_CorAngar_AFTER_Info_08_12"],"lines":[{"speaker":"npc","text":{"pl":"Nie wierzę, żeby błogosławiony wpływ Śniącego mógł go popchnąć do tak brutalnego działania.","en":"I don''t believe that the influence of the Sleeper can cause such violent deeds.","de":"Ich glaube nicht, dass der Einfluss des Schläfers solch grausame Taten verursacht."}},{"speaker":"npc","text":{"pl":"To nie może... Nie może... NIEWAŻNE!!!","en":"It cannot... cannot... IRRELEVANT!","de":"Es darf nicht ... darf nicht ... EGAL!"}},{"speaker":"npc","text":{"pl":"Najważniejsze, że zamiar Baala Lukora się nie powiódł.","en":"The most important thing is that Baal Lukor did not succeed in his madness.","de":"Die Hauptsache ist, dass Baal Lukor in seinem Wahn keinen Erfolg hatte."}},{"speaker":"npc","text":{"pl":"Teraz naszą jedyną nadzieją jest Y''Berion.","en":"Y''Berion is our only hope now.","de":"Y''Berion ist nun unsere einzige Hoffnung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_after_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_after_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_AFTER_Info","outputIds":["GUR_1202_CorAngar_AFTER_Info_15_01","GUR_1202_CorAngar_AFTER_Info_08_02","GUR_1202_CorAngar_AFTER_Info_15_03","GUR_1202_CorAngar_AFTER_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Byłem na Cmentarzysku Orków. Tam NIC NIE MA. Ani Śniącego, ani znaku... Nic!","en":"I''ve been to the Orc cemetery. There was NOTHING THERE. No Sleeper, no sign, no nothing.","de":"Ich war im Ork-Friedhof. Dort gibt es NICHTS. Keinen Schläfer, kein Zeichen, gar nichts."}},{"speaker":"npc","text":{"pl":"A co z Baalem Lukorem i Strażnikami?","en":"What about Baal Lukor and the templars?","de":"Was ist mit Baal Lukor und den Templern?"}},{"speaker":"hero","text":{"pl":"Wszyscy zginęli.","en":"They''re all dead.","de":"Sie sind alle tot."}},{"speaker":"npc","text":{"pl":"Zginęli? Ale dlaczego, co się stało?","en":"Dead? But why, what happened?","de":"Tot? Aber warum, was ist dort vorgefallen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_after_info_15_05_4', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_after_info_15_05_4","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_AFTER_Info","outputIds":["GUR_1202_CorAngar_AFTER_Info_15_05","GUR_1202_CorAngar_AFTER_Info_15_06","GUR_1202_CorAngar_AFTER_Info_15_07","GUR_1202_CorAngar_AFTER_Info_08_08"],"lines":[{"speaker":"hero","text":{"pl":"W jaskiniach aż roiło się od Orków. Wybili Straż Świątynną do nogi.","en":"The entire cave system is teeming with Orcs. They killed all of the templars.","de":"Im gesamten Höhlensystem wimmelte es von Orks. Sie haben alle Templer getötet."}},{"speaker":"hero","text":{"pl":"Tylko ja i Baal Lukor wyszliśmy z tego cało, ale nagle Baal postradał zmysły.","en":"Baal Lukor and myself survived, but suddenly Baal Lukor went mad.","de":"Baal Lukor und ich, wir haben überlebt, aber auf einmal drehte Baal Lukor völlig durch."}},{"speaker":"hero","text":{"pl":"Wrzeszczał, że Śniący kazał mu mnie zabić i zamierzał wykonać to polecenie.","en":"He screamed that the Sleeper had ordered him to kill me, and he intended to obey this order.","de":"Er schrie, der Schläfer hätte ihm befohlen, mich zu töten, und das wollte er dann auch tun."}},{"speaker":"npc","text":{"pl":"Najwyraźniej nie mógł się pogodzić z niepowodzeniem swojej misji.","en":"It would appear he couldn''t handle the fact that he hadn''t found anything.","de":"Offensichtlich kam er mit der großen Enttäuschung, nichts gefunden zu haben, nicht zurecht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_death_info_08_03_8', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_death_info_08_03_8","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_Success_Info","outputIds":["GUR_1202_CorAngar_DEATH_Info_08_03","GUR_1202_CorAngar_DEATH_Info_15_04","GUR_1202_CorAngar_DEATH_Info_08_05","GUR_1202_CorAngar_DEATH_Info_15_06"],"lines":[{"speaker":"npc","text":{"pl":"Zawsze ufałem Y''Berionowi. Tuż przed śmiercią kazał nam upatrywać nadziei ocalenia w planie ucieczki opracowanym przez Magów Wody.","en":"I have always trusted Y''Berion. Shortly before he died, he placed all his hopes on the escape plan of the Magicians of Water.","de":"Ich habe Y''Berion immer vertraut. Kurz bevor er starb, legte er all seine Hoffnungen in den Ausbruchsplan der Wassermagier."}},{"speaker":"hero","text":{"pl":"Dlatego powinniśmy wesprzeć Magów Wody w ich dążeniach.","en":"Then we should support the Magicians of Water in their plan.","de":"Dann sollten wir die Wassermagier bei ihrem Vorhaben unterstützen."}},{"speaker":"npc","text":{"pl":"Przyda się im kamień ogniskujący i almanach. Ale te są wciąż w rękach Cor Kaloma.","en":"They''ll need the focus and the almanac. Both things are still in Cor Kalom''s possession.","de":"Sie werden den Fokus und den Almanach benötigen. Beides befindet sich noch in Cor Kaloms Besitz."}},{"speaker":"hero","text":{"pl":"A gdzie jest Cor Kalom?","en":"Where is Cor Kalom?","de":"Wo ist Cor Kalom?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_death_info_08_07_12', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_death_info_08_07_12","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_Success_Info","outputIds":["GUR_1202_CorAngar_DEATH_Info_08_07","GUR_1202_CorAngar_DEATH_Info_15_08","GUR_1202_CorAngar_DEATH_Info_08_09"],"lines":[{"speaker":"npc","text":{"pl":"W gniewie zebrał oddział Strażników Świątynnych i wyruszył na poszukiwanie Śniącego.","en":"In a rage, he set out with a couple of templars to find his own way to the Sleeper.","de":"Er ist mit einigen Templern völlig zornerfüllt aufgebrochen, um einen eigenen Weg zum Schläfer zu finden."}},{"speaker":"hero","text":{"pl":"Niech to szlag! I jak teraz odzyskamy kamień ogniskujący?","en":"Damn, how can we get the focus now?","de":"Verdammt, wie sollen wir jetzt an den Fokus kommen?"}},{"speaker":"npc","text":{"pl":"Zdaję się, że kamień i księga są wciąż w jego laboratorium. Masz tu klucz do skrzyni.","en":"I believe he left the book and focus in his laboratory. Here is the key for the chest.","de":"Ich schätze, er ließ Buch und Fokus in seinem Labor zurück. Hier ist der Schlüssel für seine Truhe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_earn_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_earn_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_SENDS_EARN","outputIds":["GUR_1202_CorAngar_SENDS_EARN_Info_15_01","GUR_1202_CorAngar_SENDS_EARN_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"A co dostanę w zamian?","en":"What will I get in exchange?","de":"Was springt für mich dabei raus?"}},{"speaker":"npc","text":{"pl":"Chcesz rudy? Chyba jednak źle cię oceniłem. Ale potrzebuję twojej pomocy. Proszę, oto 100 bryłek rudy. Więcej ode mnie nie dostaniesz!","en":"You want ore? It seems my impression of you was wrong after all. But I need you. Here, take 100 ore. You won''t get any more!","de":"Du willst Erz? Anscheinend habe ich mich in dir getäuscht. Aber ich brauche dich. Hier, 100 Erz. Mehr gibt es nicht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_info_08_05_4', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_info_08_05_4","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_SENDS_Info","outputIds":["GUR_1202_CorAngar_SENDS_Info_08_05","GUR_1202_CorAngar_SENDS_Info_08_06","GUR_1202_CorAngar_SENDS_Info_15_07","GUR_1202_CorAngar_SENDS_Info_08_08"],"lines":[{"speaker":"npc","text":{"pl":"Nasz Guru, Baal Lukor udał się tam z oddziałem Strażników Świątynnych. Może znajdą coś, co pozwoli nam wyjaśnić znaczenie wizji.","en":"The Guru Baal Lukor has gone there with some templars. Maybe we''ll find something there to help us understand the vision.","de":"Der Guru Baal Lukor ist mit einigen Templern dorthin aufgebrochen. Vielleicht finden wir dort etwas, das uns hilft, die Vision besser zu verstehen."}},{"speaker":"npc","text":{"pl":"Przydałby mi się ktoś, kto rozejrzy się tam trochę i zda mi raport z sytuacji.","en":"I need somebody to have a look around that place and to report to me about the situation.","de":"Ich brauche jemanden, der dort nach dem Rechten sieht und mir von der Situation berichtet."}},{"speaker":"hero","text":{"pl":"Dlaczego nie pójdziesz tam sam? W końcu jesteś przywódcą Straży Świątynnej!","en":"Why don''t you go yourself? You are the leader of the templars!","de":"Warum gehst du nicht selber? Du bist doch der Anführer der Templer!"}},{"speaker":"npc","text":{"pl":"Moim zadaniem jest ochrona Jaśnie Oświeconego. Muszę zostać na miejscu, żeby strzec Y''Beriona.","en":"My task is to protect the Enlightened One. I must stay here with Y''Berion and guard him.","de":"Meine Aufgabe ist es, den Erleuchteten zu schützen. Ich bleibe hier bei Y''Berion und wache über ihn."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_info_08_09_8', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_info_08_09_8","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_SENDS_Info","outputIds":["GUR_1202_CorAngar_SENDS_Info_08_09","GUR_1202_CorAngar_SENDS_Info_08_10"],"lines":[{"speaker":"npc","text":{"pl":"Oddałeś Obozowi nieocenione usługi. Tylko na tobie mogę polegać.","en":"You have done good service for the Camp. I trust you more than anybody else here.","de":"Du hast dem Lager schon große Dienste erwiesen. Ich vertraue dir mehr als jedem anderen hier."}},{"speaker":"npc","text":{"pl":"Proszę, udaj się na Cmentarzysko Orków i dostarcz mi informacji na temat odkryć poczynionych przez Strażników.","en":"I am asking you to go to the Orc cemetery and report to me what the templars have found.","de":"Ich bitte dich, gehe zum Ork-Friedhof und berichte mir, was die Templer dort gefunden haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_SENDS_Info","outputIds":["GUR_1202_CorAngar_SENDS_Info_15_01","GUR_1202_CorAngar_SENDS_Info_08_02","GUR_1202_CorAngar_SENDS_Info_08_03","GUR_1202_CorAngar_SENDS_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Co się stanie teraz?","en":"What happens now?","de":"Wie geht es jetzt weiter?"}},{"speaker":"npc","text":{"pl":"Wizja była bardzo mglista. Zamiast odpowiedzi dała nam jeszcze więcej pytań.","en":"The vision was very vague, it brought us more riddles than answers.","de":"Die Vision war sehr verschwommen und gab mehr Rätsel auf, als dass sie uns Antworten brachte."}},{"speaker":"npc","text":{"pl":"Ale jedna rzecz nie ulega wątpliwości: widziałem Orka w jaskini. W pobliżu znajduje się opuszczone miejsce orkowego kultu.","en":"But one thing was perfectly clear: I saw an Orc in a cave. There is an old abandoned Orcish place of worship nearby.","de":"Aber eines war klar. Mann konnte einen Ork in einer Höhle erkennen. Es gibt eine alte verlassene Kultstätte der Orks ganz hier in der Nähe."}},{"speaker":"npc","text":{"pl":"Orkowie chowali tam swoich zmarłych, dlatego nazywamy ten labirynt jaskiń Cmentarzyskiem Orków.","en":"The Orcs used to bury their dead there, that''s why we call this system of caves the Orc cemetery.","de":"Früher haben dort die Orks ihre Verstorbenen beigesetzt, daher nennen wir dieses Höhlensystem den Ork-Friedhof."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_know_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_sends_know_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_SENDS_KNOW","outputIds":["GUR_1202_CorAngar_SENDS_KNOW_Info_15_01","GUR_1202_CorAngar_SENDS_KNOW_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Natychmiast ruszę w drogę!","en":"I''ll get on my way right now!","de":"Ich mache mich sofort auf den Weg!"}},{"speaker":"npc","text":{"pl":"Zanim pójdziesz, weź ten pierścień. Niech cię chroni w walce.","en":"Before you go, take this ring. May it protect you in battle!","de":"Bevor du losgehst, nimm diesen Ring. Er möge dich im Kampf schützen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_wannabetpl_info_08_05_4', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_wannabetpl_info_08_05_4","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_WANNABETPL_Info","outputIds":["GUR_1202_CorAngar_WANNABETPL_Info_08_05","GUR_1202_CorAngar_WANNABETPL_Info_08_06","GUR_1202_CorAngar_WANNABETPL_Info_08_07","GUR_1202_CorAngar_WANNABETPL_Info_08_08"],"lines":[{"speaker":"npc","text":{"pl":"Wykorzystujemy zarówno naszą siłę fizyczną jak i duchową. Prawdziwym Strażnikiem Świątynnym może zostać tylko ten, którego ciało i duch funkcjonują w idealnej harmonii.","en":"We make use of both our physical and our spiritual strength. Only those whose body and spirit are in unison can become true templars.","de":"Wir nutzen unsere geistige und unsere körperliche Kraft zu gleichen Teilen. Nur ein Mann, dessen Körper und Geist sich in Einklang befinden, kann ein aufrechter Templer sein."}},{"speaker":"npc","text":{"pl":"Cieszę się, że udało ci się osiągnąć tak wiele w tak krótkim czasie.","en":"I''m really pleased that you managed to achieve a great deal within such a short time. Now you are ready to join us.","de":"Es freut mich, dass du es in so kurzer Zeit geschafft hast, so weit zu kommen, dass du nun bereit bist, einer der Unseren zu werden."}},{"speaker":"npc","text":{"pl":"Pamiętaj: Duchowa koncentracja i zdrowe ciało sprostają każdemu wyzwaniu.","en":"Remember: A focused spirit and a trained body may withstand any threat.","de":"Und vergiss nicht: ein konzentrierter Geist in einem gestählten Körper widersteht jeder Bedrohung."}},{"speaker":"npc","text":{"pl":"Idź teraz do Gor Na Totha. Znajdziesz go na placu treningowym. On da ci nowy pancerz.","en":"Now go to Gor Na Toth at the training ground. He''ll give you new armor.","de":"Gehe nun zu Gor Na Toth am Übungsplatz. Er wird dir deine neue Rüstung geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_wannabetpl_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_wannabetpl_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_WANNABETPL_Info","outputIds":["GUR_1202_CorAngar_WANNABETPL_Info_15_01","GUR_1202_CorAngar_WANNABETPL_Info_08_02","GUR_1202_CorAngar_WANNABETPL_Info_08_03","GUR_1202_CorAngar_WANNABETPL_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Chcę zostać Świątynnym Strażnikiem!","en":"I want to become a templar!","de":"Ich möchte Templer werden!"}},{"speaker":"npc","text":{"pl":"Nie jesteś jeszcze gotowy. Możesz do nas dołączyć, kiedy zdobędziesz nieco więcej doświadczenia.","en":"You are not yet ready. You can join us as soon as you''ve gathered more experience.","de":"Du bist noch nicht bereit. Wenn du erfahrener geworden bist, werde ich dich aufnehmen."}},{"speaker":"npc","text":{"pl":"Nadszedł dzień, w którym dane ci będzie do nas dołączyć.","en":"The time has come for you to join us.","de":"Die Zeit ist gekommen, da du aufgenommen wirst."}},{"speaker":"npc","text":{"pl":"Pamiętaj, że Świątynny Strażnik to coś więcej niż wojownik strzegący obozu Bractwa. Jesteśmy wybranymi strażnikami wyznawców Śniącego. Bronimy duchowej aury tego miejsca.","en":"Remember that a templar is not only a good warrior and a guardian of the Camp. We are the chosen guards of the Sleeper. The guardians of the spirit.","de":"Du solltest eins wissen: Templer zu sein, bedeutet nicht nur gut kämpfen zu können und das Lager zu beschützen. Wir sind die auserwählte Wache des Schläfers. Die Hüter des Geistes."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_where_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_where_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_WHERE_Info","outputIds":["GUR_1202_CorAngar_WHERE_Info_15_01","GUR_1202_CorAngar_WHERE_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie jest to Cmentarzysko Orków?","en":"Where is the Orc cemetery?","de":"Wo ist der Ork-Friedhof?"}},{"speaker":"npc","text":{"pl":"Niedaleko stąd. Nowicjusz Talas wskaże ci drogę. Znajdziesz go na świątynnym dziedzińcu. On będzie twoim przewodnikiem.","en":"Not far from here. The novice Talas knows the way. You''ll find him in the temple courtyard. He''ll guide you there.","de":"Nicht weit von hier. Der Novize Talas kennt den Weg. Du findest ihn unten auf dem Vorplatz des Tempels. Er wird dich dort hinführen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_wie_templer_15_00_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_wie_templer_15_00_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"DIA_CorAngar_WieTempler_Info","outputIds":["GUR_1202_CorAngar_WieTempler_15_00","GUR_1202_CorAngar_WieTempler_08_01","GUR_1202_CorAngar_WieTempler_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Co mam zrobić, żeby zostać Świątynnym Strażnikiem?","en":"How can I become a templar?","de":"Wie werde ich in den Kreis der Templer aufgenommen?"}},{"speaker":"npc","text":{"pl":"Najpierw musisz odsłużyć swoje jako Nowicjusz, dopóki nie przekonamy się, że jesteś oddanym sługą Śniącego.","en":"First, you will have to serve as a novice for a while to prove that you truly believe in the Sleeper.","de":"Du musst eine Zeit lang als Novize gedient haben, um deinen Glauben an den Schläfer unter Beweis zu stellen."}},{"speaker":"npc","text":{"pl":"Dopiero wtedy możesz do mnie wrócić, a ja udzielę ci lekcji.","en":"Then come back to me, and I will instruct you.","de":"Dann kehre zu mir zurück, und ich werde dich unterweisen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand1_info_08_05_4', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand1_info_08_05_4","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_ZWEIHAND1_Info","outputIds":["GUR_1202_CorAngar_ZWEIHAND1_Info_08_05"],"lines":[{"speaker":"npc","text":{"pl":"Koncentracja to podstawa. To ona jednoczy ciało i umysł.","en":"Concentration is the key. Body and mind unite in concentration.","de":"Konzentration ist der Schlüssel. Körper und Geist verschmelzen in Konzentration zusammen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand1_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand1_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_ZWEIHAND1_Info","outputIds":["GUR_1202_CorAngar_ZWEIHAND1_Info_15_01","GUR_1202_CorAngar_ZWEIHAND1_Info_08_02","GUR_1202_CorAngar_ZWEIHAND1_Info_08_03","GUR_1202_CorAngar_ZWEIHAND1_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym potrafić posługiwać się dwuręcznym mieczem.","en":"I want to learn how to handle a two-handed sword.","de":"Ich möchte den Umgang mit dem Zweihänder lernen."}},{"speaker":"npc","text":{"pl":"Walka dwuręcznym orężem stanowi poważne wyzwanie dla twojej siły i zręczności.","en":"Fighting with two-handed weapons requires certain levels of strength and dexterity.","de":"Der Kampf mit zweihändigen Waffen setzt nicht nur ein Mindestmaß an Stärke und Geschick voraus."}},{"speaker":"npc","text":{"pl":"Aby móc sprawnie posługiwać się dwuręczna bronią musisz nie tylko rozwijać swoje ciało, ale również i umysł.","en":"To wield a two-handed weapon, you will not only need to master your body, but your mind as well.","de":"Um eine zweihändige Waffe zu führen, musst du nicht nur deinen Körper, sondern auch deinen Geist beherrschen."}},{"speaker":"npc","text":{"pl":"Tylko pełna kontrola nad ciałem i umysłem pozwoli ci rozwijać swoje umiejętności.","en":"Only if you master both mind and body will you be able to learn the skill.","de":"Nur wenn du Körper und Geist ganz beherrscht, kannst du das Talent lernen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand2_info_08_05_4', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand2_info_08_05_4","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_ZWEIHAND2_Info","outputIds":["GUR_1202_CorAngar_ZWEIHAND2_Info_08_05","GUR_1202_CorAngar_ZWEIHAND2_Info_08_06","GUR_1202_CorAngar_ZWEIHAND2_Info_08_07","GUR_1202_CorAngar_ZWEIHAND2_Info_08_08"],"lines":[{"speaker":"npc","text":{"pl":"Bądź szybki, twoja ruchliwość i płynność twoich ruchów powinny iść w parze z siłą i precyzją twoich ciosów.","en":"Be fast, your movements will have to be surprising and fluent, your hits precise and hard.","de":"Sei schnell, deine Bewegungen müssen überraschend und fließend sein, deine Schläge präzise und hart."}},{"speaker":"npc","text":{"pl":"Naucz się ignorować ból. To twoja siła ducha zadecyduje o ostatecznym wyniku starcia.","en":"Learn to ignore the pain. It''s your willpower that will finally decide the outcome of the fight.","de":"Lerne den Schmerz zu ignorieren. Dein Wille ist es, der letztendlich über den Ausgang des Kampfes entscheidet."}},{"speaker":"npc","text":{"pl":"Zachowaj spokój. Zachowanie czystości umysłu i niezachwianej koncentracji przypieczętuje twoje zwycięstwo.","en":"Remain calm. Only if you enter a fight calmly and with concentration, will you survive it.","de":"Bewahre die Ruhe. Nur wenn du ruhig und konzentriert in einen Kampf gehst, wirst du ihn auch überleben."}},{"speaker":"npc","text":{"pl":"Rozsądnie wykorzystuj swoje umiejętności, i pamiętaj: kto prowokuje walkę - ginie w walce.","en":"Use your skill cautiously. And remember: To provoke a fight means you will die in a fight.","de":"Setze dein Talent mit Vorsicht ein. Und denke daran: Wer den Kampf fordert, kommt durch den Kampf um."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand2_info_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_gur_1202_cor_angar_zweihand2_info_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"GUR_1202_CorAngar_ZWEIHAND2_Info","outputIds":["GUR_1202_CorAngar_ZWEIHAND2_Info_15_01","GUR_1202_CorAngar_ZWEIHAND2_Info_08_02","GUR_1202_CorAngar_ZWEIHAND2_Info_08_03","GUR_1202_CorAngar_ZWEIHAND2_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym dowiedzieć się czegoś więcej o walce dwuręcznym orężem.","en":"I want to learn more about fighting with two-handed weapons.","de":"Ich möchte mehr über den zweihändigen Kampf lernen."}},{"speaker":"npc","text":{"pl":"Wiesz już jak zmusić ostrze swego miecza do tańca śmierci. Teraz pokażę ci jak wykorzystać twoje umiejętności w walce.","en":"You''re now in command of the dance with the blade. Now I''ll show you how to master the fight.","de":"Den Tanz mit der Klinge beherrscht du nun. Jetzt werde ich dir die Meisterschaft des Kampfes zeigen."}},{"speaker":"npc","text":{"pl":"Oczyma duszy spróbuj przewidzieć następny ruch twojego przeciwnika.","en":"Use your spiritual force to anticipate your enemy''s movements before he attacks.","de":"Nutze deine geistige Kraft, um die Bewegungen des Gegners vor dem Angriff zu erkennen."}},{"speaker":"npc","text":{"pl":"Poznanie sposobu walki nieprzyjaciela to już połowa sukcesu.","en":"Knowing how your enemy fights is half the victory.","de":"Zu wissen, wie dein Gegner kämpft, ist der halbe Sieg über ihn."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_look_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_look_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_LOOK_Info","outputIds":["Info_CorAngar_FindHerb_LOOK_15_01","Info_CorAngar_FindHerb_LOOK_08_02","Info_CorAngar_FindHerb_LOOK_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak rozpoznam te zioła?","en":"How will I recognize these herbs?","de":"Wie kann ich diese Kräuter erkennen?"}},{"speaker":"npc","text":{"pl":"Przypominają gwiazdę z ośmioma zielonymi i pomarańczowymi liśćmi.","en":"They look like a star with eight green and orange leaves.","de":"Sie sehen aus wie ein Stern und tragen acht grüne und orangefarbene Blätter."}},{"speaker":"npc","text":{"pl":"Ruszaj w drogę.","en":"On your way now.","de":"Nun geh aber los."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_running_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_running_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_Running_Info","outputIds":["Info_CorAngar_FindHerb_Running_15_01","Info_CorAngar_FindHerb_Running_08_02","Info_CorAngar_FindHerb_Running_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Nie znalazłem jeszcze potrzebnej ilości ziół.","en":"I haven''t found enough healing herbs yet.","de":"Ich habe noch nicht genug Heilkräuter gefunden"}},{"speaker":"npc","text":{"pl":"Może Fortuno, handlarz ziołami, ma trochę w swoich zapasach.","en":"Maybe Fortuno, the herbs trader, has some in stock.","de":"Vielleicht hat auch Fortuno, der Kräuterhändler, zurzeit einige davon in seinen Regalen."}},{"speaker":"npc","text":{"pl":"Pospiesz się. Potrzebuję pięciu ziół. Y''Berionowi nie zostało już zbyt wiele czasu.","en":"Hurry. I need five of them. Y''Berion doesn''t have much time left.","de":"Beeil dich. Ich brauche fünf Stück. Y''Berion bleibt nicht mehr viel Zeit."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_success_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_success_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_Success_Info","outputIds":["Info_CorAngar_FindHerb_Success_15_01","Info_CorAngar_FindHerb_Success_08_02","Info_CorAngar_FindHerb_Success_15_03","Info_CorAngar_FindHerb_Success_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Mam już wszystkie uzdrawiające zioła dla Y''Beriona.","en":"I have the healing herbs for Y''Berion.","de":"Ich habe die Heilkräuter für Y''Berion."}},{"speaker":"npc","text":{"pl":"Dobra robota. Y''Berion zbudził się na chwilę tuż przed twoim przybyciem.","en":"Well done. Y''Berion woke up for a short time while you were out.","de":"Gut gemacht. Als du unterwegs warst, ist Y''Berion kurzzeitig erwacht."}},{"speaker":"hero","text":{"pl":"Powiedział coś?","en":"Did he say anything?","de":"Hat er was gesagt?"}},{"speaker":"npc","text":{"pl":"Tak. Powiedział, że Śniący nie jest tym, za co go uważamy. Pod żadnym pozorem nie wolno nam go zbudzić.","en":"Yes, he said that the Sleeper is not what we think he is. We must try not to awaken him again.","de":"Ja, er sagte, das der Schläfer nicht der ist, für den wir ihn halten. Wir dürfen nicht weiter versuchen, ihn zu erwecken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_where_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_info_cor_angar_find_herb_where_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_WHERE_Info","outputIds":["Info_CorAngar_FindHerb_WHERE_15_01","Info_CorAngar_FindHerb_WHERE_08_02","Info_CorAngar_FindHerb_WHERE_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę znaleźć te zioła?","en":"Where can I find these plants?","de":"Wo findet man solche Pflanzen ?"}},{"speaker":"npc","text":{"pl":"Poszukaj na bagnach za Obozem. Musisz się zapuścić dość daleko, więc uważaj na błotne węże!","en":"Search for them in the swamp behind the Camp. You need to go very deep into it, but mind the swampsharks don''t get you.","de":"Suche im Sumpf hinter dem Lager. Du musst sehr tief hineingehen aber pass auf, dass dich die Sumpfhaie nicht erwischen."}},{"speaker":"npc","text":{"pl":"I nie trać ani chwili. Idź już!","en":"And now don''t waste my time. Go!","de":"Und jetzt verliere nicht noch mehr Zeit. Geh!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_info_cor_angar_teleport_08_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_info_cor_angar_teleport_08_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_TELEPORT_Info","outputIds":["Info_CorAngar_TELEPORT_08_01","Info_CorAngar_TELEPORT_15_02","Info_CorAngar_TELEPORT_08_03","Info_CorAngar_TELEPORT_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Jeszcze coś!","en":"One moment!","de":"Einen Moment noch!"}},{"speaker":"hero","text":{"pl":"Tak?","en":"Yes?","de":"Ja?"}},{"speaker":"npc","text":{"pl":"Weź tę magiczną runę jako symbol naszej wdzięczności za twoje dokonania.","en":"Take this rune of magic as a sign of our gratitude for your great deeds.","de":"Nimm diese Zauberrune als Zeichen unseres Dankes für deine großen Taten."}},{"speaker":"npc","text":{"pl":"Pozwoli ci ona w dogodnej chwili przeteleportować się na świątynny dziedziniec.","en":"This will allow you to teleport fast and easily to the courtyard of our temple whenever the need arises.","de":"Damit kannst du dich jederzeit schnell und bequem auf unseren Tempelvorplatz teleportieren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_mis_3_nc_cor_angar_find_herb_08_05_4', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_mis_3_nc_cor_angar_find_herb_08_05_4","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_Info","outputIds":["Mis_3_NC_CorAngar_FindHerb_08_05"],"lines":[{"speaker":"npc","text":{"pl":"Spiesz się!","en":"Please hurry!","de":"Und bitte beeile dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1202_cor_angar_mis_3_nc_cor_angar_find_herb_15_01_0', 'GUR_1202_CorAngar', '{"id":"missions_dia_gur_1202_cor_angar_mis_3_nc_cor_angar_find_herb_15_01_0","npcId":"GUR_1202_CorAngar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1202_CorAngar.d","sourceFunction":"Info_CorAngar_FindHerb_Info","outputIds":["Mis_3_NC_CorAngar_FindHerb_15_01","Mis_3_NC_CorAngar_FindHerb_08_02","Mis_3_NC_CorAngar_FindHerb_15_03","Mis_3_NC_CorAngar_FindHerb_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać u Jaśnie Oświeconego?","en":"How is Y''Berion doing?","de":"Wie steht es um Y''Berion?"}},{"speaker":"npc","text":{"pl":"Nie budzi się. I z godziny na godzinę jest co raz słabszy. Wiem, jak można go zbudzić, ale potrzebuję twojej pomocy.","en":"He won''t wake of his own accord. And he is growing weaker and weaker. I know how to wake him up, but I need your help.","de":"Er wird nicht von alleine erwachen. Und er wird immer schwächer. Ich weiß, wie ich ihn wachbekommen kann, aber dazu brauche ich deine Hilfe."}},{"speaker":"hero","text":{"pl":"Co mam zrobić?","en":"What do you want me to do?","de":"Was ist zu tun?"}},{"speaker":"npc","text":{"pl":"Przynieś mi pięć najmocniejszych ziół uzdrawiających jakie można znaleźć na bagnach!","en":"Get me the healing herbs from the swamp. Five of the strongest kind should be sufficient!","de":"Besorge mir die Heilkräuter aus dem Sumpf. Fünf von der stärksten Sorte sollten genügen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_dusty_success_13_04_4', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_dusty_success_13_04_4","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_DustySuccess_Info","outputIds":["DIA_BaalTondral_DustySuccess_13_04","DIA_BaalTondral_DustySuccess_03_05","DIA_BaalTondral_DustySuccess_15_06"],"lines":[{"speaker":"npc","text":{"pl":"Każdego dnia będziesz przychodził do mojej chaty po nauki. Dla twojej duszy jeszcze nie jest zbyt późno.","en":"You will come to my hut every day to listen to my words. Your soul can still be saved.","de":"Von heute an wirst du dich täglich vor meiner Hütte einfinden und meinen Worten lauschen. Deine Seele ist noch zu retten."}},{"speaker":"hero","text":{"pl":"Heißt das, ich bin dabei - einfach so?","en":"Heißt das, ich bin dabei - einfach so?","de":"Heißt das, ich bin dabei - einfach so?"}},{"speaker":"hero","text":{"pl":"Sieht so aus. Tu einfach, was der Meister dir sagt.","en":"Sieht so aus. Tu einfach, was der Meister dir sagt.","de":"Sieht so aus. Tu einfach, was der Meister dir sagt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_dusty_success_15_00_0', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_dusty_success_15_00_0","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_DustySuccess_Info","outputIds":["DIA_BaalTondral_DustySuccess_15_00","DIA_BaalTondral_DustySuccess_13_01","DIA_BaalTondral_DustySuccess_15_02","DIA_BaalTondral_DustySuccess_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Mistrzu, oto ktoś, kto chciałby cię poznać!","en":"Here''s somebody who would like to make your acquaintance, Master!","de":"Ich habe hier jemanden, der dich kennen lernen möchte, Meister!"}},{"speaker":"npc","text":{"pl":"Kogóż mi tu przyprowadziłeś? Czy jest godzien?","en":"Who have you brought me? Is he worthy?","de":"Wen bringst du zu mir? Ist er würdig?"}},{"speaker":"hero","text":{"pl":"Cóż, bez twojego duchowego wsparcia zapewne się nie obędzie, Mistrzu.","en":"He will certainly require your spiritual guidance, Master.","de":"Er bedarf sicherlich noch eurer geistigen Führung, Meister."}},{"speaker":"npc","text":{"pl":"Dobrze. Od dzisiaj ten człowiek będzie moim uczniem.","en":"Very well. From now on, he shall be one of my disciples.","de":"Gut. Von heute an soll er zu meinen Schülern zählen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_loyality_15_00_0', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_loyality_15_00_0","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_Loyality_Info","outputIds":["DIA_BaalTondral_Loyality_15_00","DIA_BaalTondral_Loyality_13_01","DIA_BaalTondral_Loyality_13_02"],"lines":[{"speaker":"hero","text":{"pl":"W jaki sposób mogę udowodnić swoją lojalność?","en":"How can I prove my loyalty?","de":"Wie kann ich dir meine Loyalität beweisen?"}},{"speaker":"npc","text":{"pl":"Przede wszystkim, potrzebujemy nowych dusz, które zechcą przyłączyć się do naszej społeczności.","en":"Most of all, we need new souls to join our community.","de":"Was wir am dringendsten brauchen, sind neue Seelen, die sich unserer Gemeinschaft anschließen."}},{"speaker":"npc","text":{"pl":"Jeśli chcesz mnie przekonać o swojej przydatności dla naszego obozu, przyprowadź mi jeszcze jednego człowieka, który zechce zostać członkiem Bractwa.","en":"By recruiting one more man to our camp, you will prove that you''re willing to do good service to our community.","de":"Wenn du dafür sorgst, dass ein weiterer Mann unserem Lager beitritt, hast du deinen Willen, unsere Gemeinschaft zu bereichern, unter Beweis gestellt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_new_member_15_00_0', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_new_member_15_00_0","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_NewMember_Info","outputIds":["DIA_BaalTondral_NewMember_15_00","DIA_BaalTondral_NewMember_13_01","DIA_BaalTondral_NewMember_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mam szukać nowych członków Bractwa?","en":"Where can I recruit new members for the Brotherhood?","de":"Wo kann ich neue Leute für die Bruderschaft anwerben?"}},{"speaker":"npc","text":{"pl":"Na początek rozejrzyj się w Starym Obozie. Wielu z tamtejszych ludzi ma już dość terroru i kłamstw. Potrzebują tylko odrobiny wsparcia.","en":"The Old Camp is a good place to try, since a lot of the people there are fed up with fear and lies. They just need some kind of support.","de":"Das alte Lager ist ein guter Ort dafür. Denn viele, die dort leben, sind der Angst und der Lügen überdrüssig, sie müssen nur ein wenig unterstützt werden."}},{"speaker":"npc","text":{"pl":"W Nowym Obozie raczej wiele nie zwojujesz. Mieszkają tam sami barbarzyńcy.","en":"I guess you won''t be very successful in the New Camp. The men living there are barbarians.","de":"Im Neuen Lager wirst du wahrscheinlich weniger Glück haben. Die Männer, die dort leben sind Barbaren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_new_member2_13_04_4', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_new_member2_13_04_4","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_NewMember2_Info","outputIds":["DIA_BaalTondral_NewMember2_13_04"],"lines":[{"speaker":"npc","text":{"pl":"Jeśli chcesz dowiedzieć się więcej na ten temat, idź na świątynny dziedziniec. Tylko nie przeszkadzaj naszemu mistrzowi w medytacji!","en":"If you want to know more about it, go to the large court in front of the temple hill. But don''t disturb our master in his meditations!","de":"Wenn du mehr darüber erfahren willst, geh zum großen Platz vor dem Tempelberg. Aber störe nicht den Meister bei der Meditation!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_new_member2_15_00_0', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_new_member2_15_00_0","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_NewMember2_Info","outputIds":["DIA_BaalTondral_NewMember2_15_00","DIA_BaalTondral_NewMember2_13_01","DIA_BaalTondral_NewMember2_13_02","DIA_BaalTondral_NewMember2_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego tak desperacko szukacie nowych członków?","en":"Why are you so desperate for new members?","de":"Wieso braucht ihr so dringend neue Leute?"}},{"speaker":"npc","text":{"pl":"Śniący przemówił do naszego mistrza, oznajmiając, że ma dla nas niezwykle ważną wiadomość.","en":"The Sleeper has spoken to our master, revealing that he has an important message for us.","de":"Der Schläfer hat unserem Meister offenbart, dass er eine wichtige Nachricht für uns hat."}},{"speaker":"npc","text":{"pl":"Ale nie zebrał jeszcze wszystkich sił. Dlatego potrzebuje NASZEJ siły, by nawiązać ostateczny kontakt.","en":"However, he has not gathered full strength yet. That''s why he needs OUR strength to contact us.","de":"Aber er ist noch nicht zu seiner vollen Stärke erwacht, und so braucht er UNSERE Kraft, um mit uns in Kontakt treten zu können."}},{"speaker":"npc","text":{"pl":"Dlatego przygotowujemy się do wielkiego przyzwania. Im więcej ludzi weźmie w nim udział, tym większe będą szanse powodzenia.","en":"Therefore we are preparing a great invocation, and the more men participate, the likelier we are to be successful.","de":"Deswegen bereiten wir eine große Anrufung vor und je mehr Männer daran teilnehmen, umso eher werden wir Erfolg haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_send_to_kalom_15_00_0', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_send_to_kalom_15_00_0","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_SendToKalom_Info","outputIds":["DIA_BaalTondral_SendToKalom_15_00","DIA_BaalTondral_SendToKalom_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Mistrzu! Chciałbym dołączyć do Bractwa. Czy mogę liczyć na twoją przychylność?","en":"Master! I would like to join the Brotherhood. I need you to speak in my favor.","de":"Meister! Ich will in die Bruderschaft aufgenommen werden. Ich brauche eure Stimme."}},{"speaker":"npc","text":{"pl":"Udowodniłeś, że jesteś człowiekiem prawym. Cor Kalom powinien cię przyjąć.","en":"You have proven your worth. Go to Cor Kalom and don the robe.","de":"Du hast dich als würdig erwiesen. Cor Kalom soll dir die Robe geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1203_baal_tondral_dia_baal_tondral_you_talked_15_00_0', 'GUR_1203_BaalTondral', '{"id":"missions_dia_gur_1203_baal_tondral_dia_baal_tondral_you_talked_15_00_0","npcId":"GUR_1203_BaalTondral","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1203_BaalTondral.d","sourceFunction":"DIA_BaalTondral_YouTalked_Info","outputIds":["DIA_BaalTondral_YouTalked_15_00","DIA_BaalTondral_YouTalked_13_01","DIA_BaalTondral_YouTalked_13_02","DIA_BaalTondral_YouTalked_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Hej! Odezwałeś się do mnie. Czy to znaczy, że mogę już z tobą rozmawiać?","en":"Hey! You''ve spoken to me. Does that mean I may talk to you now?","de":"Hey! Du hast mich angesprochen. Heißt das, ich kann jetzt mit dir reden?"}},{"speaker":"npc","text":{"pl":"Widzę, że zaznajomiłeś się już z naszymi zasadami. To dobrze.","en":"I see you''ve become familiar with our rules. That''s good.","de":"Ich sehe, du hast dich mit unseren Regeln vertraut gemacht. Das ist gut."}},{"speaker":"npc","text":{"pl":"Wyczuwam w tobie wielką siłę ducha. Wkrótce będziesz gotów, by do nas dołączyć.","en":"I can feel your great spiritual strength! Soon you''ll be allowed to join our community.","de":"Ich spüre große geistige Kraft in dir! Du kannst schon bald ein Mitglied unserer Gemeinschaft sein."}},{"speaker":"npc","text":{"pl":"Przemówiłem do ciebie, bo chcę dać ci szansę udowodnienia swojej lojalności.","en":"I have spoken to you because I wanted to give you a chance to prove your loyalty.","de":"Ich habe dich angesprochen weil ich dir Gelegenheit geben will, uns deine Loyalität zu beweisen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_dia_baal_namib_first_talk_02_00_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_dia_baal_namib_first_talk_02_00_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"DIA_BaalNamib_FirstTalk_Info","outputIds":["DIA_BaalNamib_FirstTalk_02_00","DIA_BaalNamib_FirstTalk_02_01"],"lines":[{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(seufzt)"}},{"speaker":"npc","text":{"pl":"Zostałeś wybrany przez Śniącego. Czy twoim życzeniem naprawdę jest dołączyć do nas?","en":"The Sleeper has chosen you. Do you really want to join us?","de":"Der Schläfer hat dich erwählt. Ist es dir wirklich ernst mit deinem Wunsch, uns beizutreten?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_dia_baal_namib_first_talk_mute_15_00_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_dia_baal_namib_first_talk_mute_15_00_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"DIA_BaalNamib_FirstTalk_Mute","outputIds":["DIA_BaalNamib_FirstTalk_Mute_15_00","DIA_BaalNamib_FirstTalk_Mute_02_01"],"lines":[{"speaker":"hero","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(seufzt)"}},{"speaker":"npc","text":{"pl":"Co takiego?","en":"Well?","de":"Nun?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_dia_baal_namib_first_talk_sleeper_15_00_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_dia_baal_namib_first_talk_sleeper_15_00_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"DIA_BaalNamib_FirstTalk_Sleeper","outputIds":["DIA_BaalNamib_FirstTalk_Sleeper_15_00","DIA_BaalNamib_FirstTalk_Sleeper_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Tak, chcę podążać drogą Śniącego!","en":"Yes, I wish to follow the Sleeper!","de":"Ja, ich will den Weg des Schläfers beschreiten!"}},{"speaker":"npc","text":{"pl":"Idź do Cor Kaloma. Powiedz mu, że przysyłam cię do niego, bo widzę, iż twoja wiara jest szczera!","en":"Go to Cor Kalom. Tell him I sent you because you are a true supporter of the faith!","de":"Geh zu Cor Kalom. Sag ihm, ich schicke ihm einen wahren Anhänger des Glaubens!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_dia_baal_namib_no_talk_hi_15_00_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_dia_baal_namib_no_talk_hi_15_00_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"DIA_BaalNamib_NoTalk_Hi","outputIds":["DIA_BaalNamib_NoTalk_Hi_15_00","DIA_BaalNamib_NoTalk_Hi_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Jestem tu nowy!","en":"Hi! I''m new here!","de":"Hi! Ich bin neu hier!"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_dia_baal_namib_no_talk_imp_15_00_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_dia_baal_namib_no_talk_imp_15_00_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"DIA_BaalNamib_NoTalk_Imp","outputIds":["DIA_BaalNamib_NoTalk_Imp_15_00","DIA_BaalNamib_NoTalk_Imp_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Wszystko w porządku, kolego?","en":"Is everything alright, pal?","de":"Alles, klar, Alter?"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_dia_baal_namib_no_talk_sleeper_15_00_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_dia_baal_namib_no_talk_sleeper_15_00_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"DIA_BaalNamib_NoTalk_Sleeper","outputIds":["DIA_BaalNamib_NoTalk_Sleeper_15_00","DIA_BaalNamib_NoTalk_Sleeper_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Niech Śniący będzie z tobą!","en":"The Sleeper be with you!","de":"Der Schläfer sei mit dir!"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_15_01_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_15_01_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"Info_BaalNamib_BROTHERHOOD_Info","outputIds":["Info_BaalNamib_BROTHERHOOD_15_01","Info_BaalNamib_BROTHERHOOD_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Czy są jakieś zadania, których mógłbym się podjąć?","en":"Are there any tasks I can do for the Brotherhood?","de":"Gibt es Aufgaben, die ich für die Bruderschaft erledigen kann?"}},{"speaker":"npc","text":{"pl":"Nasz mistrz, mądry Y''Berion, kazał sobie przysłać Nowicjusza. Jako że jesteś teraz jednym z nas, możesz iść do niego i zaoferować swoje usługi.","en":"Our master, the wise Y''Berion, has sent for a novice. Since you''re a member of the community now, go to him and offer your services.","de":"Unser Meister, der weise Y''Berion, schickt nach einem Novizen. Nun, da du ein Bruder der Gemeinschaft geworden bist, geh zu ihm und biete ihm deine Hilfe an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ok_15_01_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ok_15_01_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"Info_BaalNamib_BROTHERHOOD_OK","outputIds":["Info_BaalNamib_BROTHERHOOD_OK_15_01","Info_BaalNamib_BROTHERHOOD_OK_02_02"],"lines":[{"speaker":"hero","text":{"pl":"W porządku. Zajrzę do niego natychmiast.","en":"Okay, I''ll call on him right away.","de":"In Ordnung, ich werde ihn sofort aufsuchen."}},{"speaker":"npc","text":{"pl":"Niech Śniący będzie z tobą!","en":"May the Sleeper protect you.","de":"Möge der Schläfer dich beschützen"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ybwas_02_05_4', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ybwas_02_05_4","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"Info_BaalNamib_BROTHERHOOD_YBWAS","outputIds":["Info_BaalNamib_BROTHERHOOD_YBWAS_02_05"],"lines":[{"speaker":"npc","text":{"pl":"Gdyby było łatwe, już dawno mielibyśmy ten artefakt w naszym obozie. Porozmawiaj z Y''Berionem. On ci wszystko wyjaśni.","en":"If it were easy, we''d already have the object. Talk to Y''Berion first. He''ll explain it to you.","de":"Wenn es einfach wäre, hätten wir den Gegenstand schon. Sprich erst mal mit Y''Berion. Er wird dir alles erklären."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ybwas_15_01_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ybwas_15_01_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"Info_BaalNamib_BROTHERHOOD_YBWAS","outputIds":["Info_BaalNamib_BROTHERHOOD_YBWAS_15_01","Info_BaalNamib_BROTHERHOOD_YBWAS_02_02","Info_BaalNamib_BROTHERHOOD_YBWAS_02_03","Info_BaalNamib_BROTHERHOOD_YBWAS_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Wiesz może jakie zadanie ma dla mnie Y''Berion?","en":"Do you know what Y''Berion wants me to do?","de":"Weißt du, was ich für Y''Berion erledigen soll?"}},{"speaker":"npc","text":{"pl":"Aby doszło do wielkiego przyzwania musimy najpierw zdobyć pewien magiczny artefakt.","en":"A great invocation will be taking place. But for it to begin, we need a magical object.","de":"Eine große Beschwörung wird stattfinden. Allerdings brauchen wir dafür einen magischen Gegenstand."}},{"speaker":"npc","text":{"pl":"Y''Berion poszukuje śmiałka, który zechce się podjąć tego zadania.","en":"Y''Berion is looking for men brave enough to get him the artifact.","de":"Y''Berion sucht Männer, die mutig genug sind, ihm dieses Artefakt zu bringen."}},{"speaker":"hero","text":{"pl":"To nie wydaje się zbyt trudne.","en":"Sounds easy.","de":"Klingt einfach."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ybwo_15_01_0', 'GUR_1204_BaalNamib', '{"id":"missions_dia_gur_1204_baal_namib_info_baal_namib_brotherhood_ybwo_15_01_0","npcId":"GUR_1204_BaalNamib","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1204_BaalNamib.d","sourceFunction":"Info_BaalNamib_BROTHERHOOD_YBWO","outputIds":["Info_BaalNamib_BROTHERHOOD_YBWO_15_01","Info_BaalNamib_BROTHERHOOD_YBWO_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę Y''Beriona?","en":"Where can I find Y''Berion?","de":"Wo finde ich Y''Berion?"}},{"speaker":"npc","text":{"pl":"Jego siedziba znajduje się pod świątynnym wzgórzem.","en":"He''s inside the temple hill. As always.","de":"Er hält sich im Inneren des Tempelbergs auf. Wie immer."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_dia_baal_cadar_no_talk_hi_15_00_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_dia_baal_cadar_no_talk_hi_15_00_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"DIA_BaalCadar_NoTalk_Hi","outputIds":["DIA_BaalCadar_NoTalk_Hi_15_00","DIA_BaalCadar_NoTalk_Hi_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Jestem tu nowy!","en":"Hi! I''m new here!","de":"Hi! Ich bin neu hier!"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_dia_baal_cadar_no_talk_imp_15_00_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_dia_baal_cadar_no_talk_imp_15_00_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"DIA_BaalCadar_NoTalk_Imp","outputIds":["DIA_BaalCadar_NoTalk_Imp_15_00","DIA_BaalCadar_NoTalk_Imp_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Wszystko w porządku, kolego?","en":"Everything alright, pal?","de":"Alles klar, Alter?"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_dia_baal_cadar_no_talk_sleeper_15_00_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_dia_baal_cadar_no_talk_sleeper_15_00_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"DIA_BaalCadar_NoTalk_Sleeper","outputIds":["DIA_BaalCadar_NoTalk_Sleeper_15_00","DIA_BaalCadar_NoTalk_Sleeper_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Niech Śniący będzie z tobą!","en":"The Sleeper be with you!","de":"Der Schläfer sei mit dir!"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_dia_baal_cadar_sleep_spell_02_00_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_dia_baal_cadar_sleep_spell_02_00_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"DIA_BaalCadar_SleepSpell_Info","outputIds":["DIA_BaalCadar_SleepSpell_02_00","DIA_BaalCadar_SleepSpell_02_01","DIA_BaalCadar_SleepSpell_15_02","DIA_BaalCadar_SleepSpell_02_03"],"lines":[{"speaker":"npc","text":{"pl":"Co ty wyprawiasz? Próbuję medytować z moimi uczniami.","en":"What are you doing? I''m trying to meditate with my disciples.","de":"Was tust du? Ich versuche hier gerade mit meinen Schülern zu meditieren."}},{"speaker":"npc","text":{"pl":"Kto cię nauczył wykorzystywać magiczne moce Śniącego?","en":"Who taught you to use the magical powers of the Sleeper?","de":"Wer hat dir beigebracht, die Magie des Schläfers zu wirken?"}},{"speaker":"hero","text":{"pl":"Nikt. To było całkiem proste!","en":"Nobody. It was very easy.","de":"Niemand. Es war ganz leicht."}},{"speaker":"npc","text":{"pl":"Wyglądasz mi na pojętnego ucznia. Będę twoim mistrzem.","en":"You seem to be an intelligent student. I will teach you.","de":"Du scheinst ein sehr gelehriger Schüler zu sein. Ich werde dich unterrichten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_firsttest_info_15_01_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_firsttest_info_15_01_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_FIRSTTEST_Info","outputIds":["Gur_1208_BaalCadar_FIRSTTEST_Info_15_01","Gur_1208_BaalCadar_FIRSTTEST_Info_02_02","Gur_1208_BaalCadar_FIRSTTEST_Info_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Naucz mnie wykorzystywać magię runiczną.","en":"Teach me the magic of the runes.","de":"Lehre mich die Magie der Runen."}},{"speaker":"npc","text":{"pl":"Wielu poznało język runiczny, ale tylko kilku rozumie naturę ich magii.","en":"Many have learnt the language of the runes, but only very few understand their magic.","de":"Die Sprache der Runen zu lernen, vermögen viele, doch nur wenige verstehen ihre Magie."}},{"speaker":"npc","text":{"pl":"Spróbuję ci ją wyjaśnić.","en":"I will try to teach you.","de":"Ich werde es mit dir versuchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis1_info_02_05_4', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis1_info_02_05_4","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS1_Info","outputIds":["Gur_1208_BaalCadar_KREIS1_Info_02_05","Gur_1208_BaalCadar_KREIS1_Info_02_06"],"lines":[{"speaker":"npc","text":{"pl":"Tylko Y''Berion, wraz z garstką towarzyszy usłuchał głosu Śniącego. Tak powstało Bractwo.","en":"Only Y''Berion and a few others set off and founded the Brotherhood.","de":"Nur Y''Berion und eine Hand voll anderer machten sich auf und gründeten die Bruderschaft."}},{"speaker":"npc","text":{"pl":"W chwili, w której po raz pierwszy wstąpili na ścieżkę zbawienia, powstał również Pierwszy Krąg. Magia runiczna staje się zrozumiała dla każdego, kto podąża śladem Śniącego.","en":"The moment they obeyed the Sleeper''s call, the First Circle was born. The magic of the runes will be understood by anybody who follows the Sleeper.","de":"In dem Augenblick, als sie dem Ruf des Schläfers folgten, entstand der erste Kreis. Die Magie der Runen offenbart sich demjenigen, der dem Schläfer folgt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis1_info_15_01_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis1_info_15_01_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS1_Info","outputIds":["Gur_1208_BaalCadar_KREIS1_Info_15_01","Gur_1208_BaalCadar_KREIS1_Info_02_02","Gur_1208_BaalCadar_KREIS1_Info_02_03","Gur_1208_BaalCadar_KREIS1_Info_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów, by przystąpić do Pierwszego Kręgu:","en":"I am ready to enter the First Circle.","de":"Ich bin bereit für den ersten Kreis."}},{"speaker":"npc","text":{"pl":"Słuchaj mnie uważnie:","en":"Hear my words:","de":"Höre meine Worte:"}},{"speaker":"npc","text":{"pl":"Dawno temu Śniący przybył tutaj i zesłał ludziom proroczą wizję.","en":"A long time ago the Sleeper appeared and sent mankind a vision.","de":"Der Schläfer erschien vor langer Zeit und gab den Menschen eine Vision."}},{"speaker":"npc","text":{"pl":"Jednak wielu z nich nie chciało zobaczyć jego potęgi. Nie chciało uwierzyć. Zaślepiała ich chciwość rudy.","en":"But many people refused to see his signs, they were blinded by their greed for ore.","de":"Viele wollten seine Zeichen jedoch nicht sehen, weil sie von der Gier nach Erz geblendet waren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis2_info_02_05_4', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis2_info_02_05_4","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS2_Info","outputIds":["Gur_1208_BaalCadar_KREIS2_Info_02_05","Gur_1208_BaalCadar_KREIS2_Info_02_06"],"lines":[{"speaker":"npc","text":{"pl":"Wspólnie spróbowali przez modlitwę zjednoczyć się duchowo ze Śniącym.","en":"Together they tried to contact the Sleeper on a spiritual level.","de":"Und zusammen versuchten sie, durch Gebet und Meditation den Schläfer auf spiritueller Ebene zu treffen."}},{"speaker":"npc","text":{"pl":"Narodził się Drugi Krąg.","en":"The Second Circle was born.","de":"Das war die Geburtsstunde des zweiten Kreises."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis2_info_15_01_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis2_info_15_01_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS2_Info","outputIds":["Gur_1208_BaalCadar_KREIS2_Info_15_01","Gur_1208_BaalCadar_KREIS2_Info_02_02","Gur_1208_BaalCadar_KREIS2_Info_02_03","Gur_1208_BaalCadar_KREIS2_Info_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów, by przystąpić do Drugiego Kręgu.","en":"I am ready to enter the Second Circle.","de":"Ich bin bereit für den zweiten Kreis."}},{"speaker":"npc","text":{"pl":"Zatem słuchaj uważnie:","en":"Then listen and understand:","de":"Dann höre und begreife:"}},{"speaker":"npc","text":{"pl":"Śniący wskazał Y''Berionowi i jego uczniom miejsce, w którym mieli się osiedlić.","en":"The Sleeper led Y''Berion and his faithful disciples to this place, where they settled.","de":"Der Schläfer führte Y''Berion und seine getreuen Anhänger an diesen Ort. Hier ließen sie sich nieder."}},{"speaker":"npc","text":{"pl":"Wybrani pracowali bez przerwy, dniem i nocą, niebaczni na niebezpieczeństwa i zmęczenie. Co chwila przybywali do nich nowi ludzie, gotowi wysłuchać nauk Śniącego.","en":"They worked without respite - for days, weeks, months. The Camp grew. More and more men joined them, following the Sleeper''s call.","de":"Sie arbeiteten ohne Unterlass, Tage, Wochen Monate. Und das Lager wuchs heran. Mehr Männer kamen dazu, die dem Ruf des Schläfers gefolgt waren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis3_info_02_05_4', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis3_info_02_05_4","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS3_Info","outputIds":["Gur_1208_BaalCadar_KREIS3_Info_02_05","Gur_1208_BaalCadar_KREIS3_Info_02_06"],"lines":[{"speaker":"npc","text":{"pl":"W tym samym czasie nasi Nowicjusze wyruszyli do innych obozów, by głosić tam nauki Śniącego i wyprowadzić niewiernych z błędów pogaństwa.","en":"At the same time, the novices set out for the Camps, to preach the Sleeper''s word and to convince the infidels of the truth.","de":"Zur gleichen Zeit machten sich die Novizen auf in die Lager, die Worte des Schläfers zu predigen, um mehr Ungläubige von der Wahrheit zu überzeugen."}},{"speaker":"npc","text":{"pl":"W ten sposób zamknął się Trzeci Krąg.","en":"Thus the Third Circle was accomplished.","de":"Dadurch wurde der dritte Kreis vollendet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis3_info_15_01_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis3_info_15_01_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS3_Info","outputIds":["Gur_1208_BaalCadar_KREIS3_Info_15_01","Gur_1208_BaalCadar_KREIS3_Info_02_02","Gur_1208_BaalCadar_KREIS3_Info_02_03","Gur_1208_BaalCadar_KREIS3_Info_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów, by przystąpić do Trzeciego Kręgu.","en":"I am ready to enter the Third Circle.","de":"Ich bin bereit für den dritten Kreis."}},{"speaker":"npc","text":{"pl":"Zapamiętaj sobie:","en":"Mark this:","de":"Achte das Wort:"}},{"speaker":"npc","text":{"pl":"Zsyłane przez Śniącego wizje były co raz wyraźniejsze, ale Bractwo nie dysponowało siłą wystarczającą by nawiązać kontakt.","en":"The visions became clear, but the spiritual power of the Brotherhood was insufficient for contact.","de":"Die Visionen wurden deutlicher, jedoch war die geistige Kraft der Brüder nicht ausreichend für einen Kontakt."}},{"speaker":"npc","text":{"pl":"Jeden z Guru, alchemik, znalazł rozwiązanie. Przygotował napój sporządzony z wydzieliny z wnętrzności pełzaczy. Bracia wypili go przed rozpoczęciem modłów i ich duchowe siły zjednoczyły się po raz pierwszy.","en":"One of the Gurus, an alchemist, solved the problem. He brewed a potion extracted from the secretion of a minecrawler. The brothers took it before prayers and their spiritual powers were united for the very first time.","de":"Einer der Gurus, ein Alchemist, fand einen Weg. Mit Hilfe eines Elixiers aus dem Sekret der Minecrawler, das die Brüder vor dem Gebet einnahmen, wurde es erstmalig möglich, die geistigen Kräfte zu vereinen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis4_info_02_05_4', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis4_info_02_05_4","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS4_Info","outputIds":["Gur_1208_BaalCadar_KREIS4_Info_02_05","Gur_1208_BaalCadar_KREIS4_Info_02_06"],"lines":[{"speaker":"npc","text":{"pl":"Trwałość i niezmienność naszej wiary symbolizuje Czwarty Krąg.","en":"Perseverance and stability of faith represent the Fourth Circle.","de":"Die Beständigkeit und Festigung des Glaubens, das ist der vierte Kreis."}},{"speaker":"npc","text":{"pl":"Teraz wiesz już wszystko, co członek Bractwa powinien wiedzieć o magii. Byłeś pojętnym uczniem.","en":"Now you know everything a brother needs to know about magic. You have been a good student.","de":"Du weißt nun alles, was ein Bruder über Magie wissen muss. Du warst ein gelehriger Schüler."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis4_info_15_01_0', 'GUR_1208_BaalCadar', '{"id":"missions_dia_gur_1208_baal_cadar_gur_1208_baal_cadar_kreis4_info_15_01_0","npcId":"GUR_1208_BaalCadar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1208_BaalCadar.d","sourceFunction":"Gur_1208_BaalCadar_KREIS4_Info","outputIds":["Gur_1208_BaalCadar_KREIS4_Info_15_01","Gur_1208_BaalCadar_KREIS4_Info_02_02","Gur_1208_BaalCadar_KREIS4_Info_02_03","Gur_1208_BaalCadar_KREIS4_Info_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów, by przystąpić do Czwartego Kręgu.","en":"I am ready to enter the Fourth Circle.","de":"Ich bin bereit für den vierten Kreis."}},{"speaker":"npc","text":{"pl":"Długi czas upłynął od chwili założenia Obozu. Wiele się tutaj zmieniło.","en":"A long time has passed since the Camp was founded. Many things have changed.","de":"Seit der Gründung des Lagers ist viel Zeit vergangen. Viel hat sich geändert."}},{"speaker":"npc","text":{"pl":"Nasza wiara umocniła się i rozprzestrzeniła.","en":"The faith has grown, it has been strengthened and it has spread.","de":"Der Glaube ist gewachsen, hat sich gefestigt und wurde weitergetragen."}},{"speaker":"npc","text":{"pl":"I nie zapomnieliśmy o naszym celu. Nie ustaliśmy w naszych wysiłkach, by przyzwać Śniącego do tego świata.","en":"We have not forgotten our objective. We have not given up on trying to invoke the Sleeper.","de":"Und wir haben unser Ziel nie aus den Augen verloren, haben nicht aufgegeben, den Schläfer zu rufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_first_talk_12_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_first_talk_12_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_FirstTalk_Info","outputIds":["DIA_BaalOrun_FirstTalk_12_00","DIA_BaalOrun_FirstTalk_12_01","DIA_BaalOrun_FirstTalk_12_02","DIA_BaalOrun_FirstTalk_12_03"],"lines":[{"speaker":"npc","text":{"pl":"Rozmawiałem z Ghorimem. Oddałeś jednemu z naszych braci nie lada przysługę. Twoja sprawa była słuszna.","en":"I have spoken to Ghorim. You have done one of our brothers a great service - your cause was just.","de":"Ich habe mit Ghorim gesprochen. Du hast dich für einen unserer Brüder eingesetzt - und deine Sache war gerecht."}},{"speaker":"npc","text":{"pl":"Dlatego postanowiłem wyznaczyć cię do pewnego szczególnego zadania.","en":"That''s why I''ve chosen you for a special task.","de":"Darum habe ich dich für eine besondere Aufgabe erwählt."}},{"speaker":"npc","text":{"pl":"Cor Kalom pilnie potrzebuje do swoich eksperymentów świeżej dostawy bagiennego ziela.","en":"Cor Kalom urgently needs new swampweed for his experiments.","de":"Cor Kalom braucht dringend neues Sumpfkraut für seine Experimente."}},{"speaker":"npc","text":{"pl":"Nasi zbieracze pracują dniem i nocą. Idź do nich i przynieś wszystko co uzbierali do laboratorium alchemicznego Kaloma.","en":"Our gatherers are working day and night. Go to them and take their entire harvest to Kalom''s alchemy lab.","de":"Unsere Sammler im Sumpf arbeiten Tag und Nacht. Gehe zu ihnen und bring ihre gesamte Ernte zu Kalom ins Alchemielabor."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_first_talk_where_15_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_first_talk_where_15_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_FirstTalk_Where","outputIds":["DIA_BaalOrun_FirstTalk_Where_15_00","DIA_BaalOrun_FirstTalk_Where_12_01","DIA_BaalOrun_FirstTalk_Where_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę tych zbieraczy?","en":"Where exactly can I find the gatherers?","de":"Wo genau kann ich die Sammler finden?"}},{"speaker":"npc","text":{"pl":"Nie pozwoliłem ci zwracać się do mnie!","en":"I have not yet given you permission to address me!","de":"Ich habe dir noch nicht gestattet, mich anzusprechen!"}},{"speaker":"npc","text":{"pl":"Módl się, aby Śniący wybaczył ci to bluźnierstwo! A teraz odejdź! Twoje zadanie jest niezwykle ważne.","en":"Pray to the Sleeper that he may pardon your sacrilege! And now leave. Your mission is of extreme importance.","de":"Bete zum Schläfer um Vergebung für dieses Sakrileg! Und nun geh. Deine Mission ist von äußerster Dringlichkeit."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_got_weed_12_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_got_weed_12_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_GotWeed_Info","outputIds":["DIA_BaalOrun_GotWeed_12_00","DIA_BaalOrun_GotWeed_12_01","DIA_BaalOrun_GotWeed_12_02"],"lines":[{"speaker":"npc","text":{"pl":"Obroniłeś naszych zbieraczy...","en":"You have defended our gatherers...","de":"Du hast unsere Sammler verteidigt ..."}},{"speaker":"npc","text":{"pl":"Nie tylko udowodniłeś, że jesteś po naszej stronie - pokazałeś również, że jesteś godnym sługą Śniącego.","en":"You have not only proved that you''re on our side - you have proved that you are a worthy servant of the Sleeper.","de":"Damit hast du nicht nur bewiesen, dass du auf unserer Seite stehst - du hast dich auch als würdiger Diener des Schläfers erwiesen."}},{"speaker":"npc","text":{"pl":"Myślę, że jesteś godzien nosić szatę Nowicjusza.","en":"I believe you are ready to wear the robe of a novice.","de":"Du bist meiner Meinung nach bereit, die Robe eines Novizen zu tragen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_no_talk_hi_15_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_no_talk_hi_15_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_NoTalk_Hi","outputIds":["DIA_BaalOrun_NoTalk_Hi_15_00","DIA_BaalOrun_NoTalk_Hi_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Jestem tu nowy!","en":"Hi! I''m new here!","de":"Hi! Ich bin neu hier!"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_no_talk_imp_15_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_no_talk_imp_15_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_NoTalk_Imp","outputIds":["DIA_BaalOrun_NoTalk_Imp_15_00","DIA_BaalOrun_NoTalk_Imp_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Wszystko w porządku, kolego?","en":"Everything alright, pal?","de":"Alles klar, Alter?"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_no_talk_sleeper_15_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_no_talk_sleeper_15_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_NoTalk_Sleeper","outputIds":["DIA_BaalOrun_NoTalk_Sleeper_15_00","DIA_BaalOrun_NoTalk_Sleeper_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Niech Śniący będzie z tobą!","en":"The Sleeper be with you!","de":"Der Schläfer sei mit dir!"}},{"speaker":"npc","text":{"pl":"(Wzdycha)","en":"(sigh)","de":"(verärgertes Schnauben)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_perm_15_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_perm_15_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_Perm_Info","outputIds":["DIA_BaalOrun_Perm_15_00","DIA_BaalOrun_Perm_12_01","DIA_BaalOrun_Perm_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak przebiega produkcja ziela?","en":"How''s weed production going?","de":"Wie läuft die Krautproduktion?"}},{"speaker":"npc","text":{"pl":"Wytężamy wszystkie siły, żeby nadążyć z produkcją. W końcu musimy zadbać o własne potrzeby, i jeszcze wymieniać część towaru z innymi obozami.","en":"We''re putting maximum strain on every man to produce enough for ourselves AND trade with the other camps.","de":"Wir belasten jeden Mann bis ans Äußerste, um genug für uns UND den Handel mit den anderen Lagern herzustellen."}},{"speaker":"npc","text":{"pl":"Ale nasi Nowicjusze chętnie ponoszą tę ofiarę, ku większej chwale Śniącego.","en":"But it''s a sacrifice for the Sleeper, one our novices willingly make.","de":"Aber es ist ein Opfer für den Schläfer, und so bringen es die Novizen gerne."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1209_baal_orun_dia_baal_orun_weed_at_kaloms_15_00_0', 'GUR_1209_BaalOrun', '{"id":"missions_dia_gur_1209_baal_orun_dia_baal_orun_weed_at_kaloms_15_00_0","npcId":"GUR_1209_BaalOrun","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1209_BaalOrun.d","sourceFunction":"DIA_BaalOrun_WeedAtKaloms_Info","outputIds":["DIA_BaalOrun_WeedAtKaloms_15_00","DIA_BaalOrun_WeedAtKaloms_12_01","DIA_BaalOrun_WeedAtKaloms_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Zaniosłem ziele Cor Kalomowi.","en":"I took the swampweed to Cor Kalom.","de":"Ich habe Cor Kalom das Sumpfkraut gebracht."}},{"speaker":"npc","text":{"pl":"Dobrze się spisałeś. Mam dla ciebie drobną nagrodę za twoje trudy. Proszę, weź to.","en":"You have done well. I have a small reward for your efforts. Here, take it.","de":"Daran hast du gut getan. Ich habe eine kleine Belohnung für deine Mühen. Hier, nimm es."}},{"speaker":"npc","text":{"pl":"To magiczne zaklęcie snu. Możesz go użyć tylko jeden raz, ale jestem pewien, że kiedyś ci się przyda.","en":"It''s a magic sleep spell. You can only use it once, but I hope it will be of good service to you.","de":"Es ist ein magischer Schlafzauber. Du kannst ihn nur einmal verwenden, aber er wird dir hoffentlich gute Dienste leisten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1210_baa_tyon_dia_baal_tyon_vision_11_00_0', 'GUR_1210_BaalTyon', '{"id":"missions_dia_gur_1210_baa_tyon_dia_baal_tyon_vision_11_00_0","npcId":"GUR_1210_BaalTyon","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1210_BaaTyon.d","sourceFunction":"DIA_BaalTyon_Vision_Info","outputIds":["DIA_BaalTyon_Vision_11_00","DIA_BaalTyon_Vision_11_01","DIA_BaalTyon_Vision_11_02","DIA_BaalTyon_Vision_11_03"],"lines":[{"speaker":"npc","text":{"pl":"Na chwałę Śniącego! Miałem wizję!","en":"In the name of the Sleeper! I ''ve had a vision!","de":"Beim Schläfer! Ich hatte eine Vision!"}},{"speaker":"npc","text":{"pl":"To było niesamowite! Zobaczyłem, że wkrótce zyskamy nowego brata, który będzie inny niż wszyscy przed nim.","en":"It was incredible. I saw that we would win a new brother, one who is not like those who came before him.","de":"Es war unglaublich. Ich habe gesehen, dass wir einen neuen Bruder bekommen, der nicht ist wie die, die vor ihm kamen."}},{"speaker":"npc","text":{"pl":"To miało coś wspólnego ze mną. W jego ręku lśnił miecz. On sam zaś zbiegał w dół po szerokich stopniach. Tutaj wizja się skończyła.","en":"He was doing something to us... There was a sword in his hand and he was descending a wide flight of stairs. Then the vision ended.","de":"Er macht irgendwas mit uns ... Er hat ein Schwert in der Hand und steigt eine breite Treppe herunter. Dann hört die Vision auf."}},{"speaker":"npc","text":{"pl":"Wyglądał zupełnie jak TY! Kim jesteś? Czego tu szukasz?","en":"He looked very much like YOU. Who are you? What do you want?","de":"Und er sah DIR verdammt ähnlich.  Wer bist du? Was willst du hier?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1210_baa_tyon_dia_baal_tyon_vision_15_04_4', 'GUR_1210_BaalTyon', '{"id":"missions_dia_gur_1210_baa_tyon_dia_baal_tyon_vision_15_04_4","npcId":"GUR_1210_BaalTyon","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1210_BaaTyon.d","sourceFunction":"DIA_BaalTyon_Vision_Info","outputIds":["DIA_BaalTyon_Vision_15_04","DIA_BaalTyon_Vision_11_05"],"lines":[{"speaker":"hero","text":{"pl":"Jestem tylko skromnym sługą Śniącego...","en":"I''m just a modest servant of the Sleeper...","de":"Ich bin nur ein bescheidener Diener des Schläfers ..."}},{"speaker":"npc","text":{"pl":"Idź do Cor Kaloma. On się tobą zajmie.","en":"Go to Cor Kalom. He''ll take care of you.","de":"Geh zu Cor Kalom. Er soll sich weiter mit dir befassen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_altar_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_altar_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_ALTAR_Info","outputIds":["Info_BaalLukor_ALTAR_13_01","Info_BaalLukor_ALTAR_13_02","Info_BaalLukor_ALTAR_13_03","Info_BaalLukor_ALTAR_13_04"],"lines":[{"speaker":"npc","text":{"pl":"NIE! To nie może być prawda! To nic nie ma... Tylko kurz i... i kości.","en":"NO! This can''t be true! There''s nothing here but... but dust and... and bones.","de":"NEIN! Das darf nicht wahr sein! Hier gibt es nichts außer ... außer Staub und ... und Gebeinen."}},{"speaker":"npc","text":{"pl":"NIE!","en":"NO!","de":"NEIN!"}},{"speaker":"npc","text":{"pl":"PANIE, PRZEMÓW DO MNIE!!!","en":"MASTER, SPEAK TO ME!!!","de":"MEISTER, SPRICH ZU MIR!!!"}},{"speaker":"npc","text":{"pl":"ŚNIĄCY, UKAŻ SIĘ SWOJEMU SŁUDZE!","en":"SLEEPER, REVEAL YOURSELF!!!","de":"SCHLÄFER, OFFENBARE DICH!!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_altar_13_05_4', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_altar_13_05_4","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_ALTAR_Info","outputIds":["Info_BaalLukor_ALTAR_13_05","Info_BaalLukor_ALTAR_15_06","Info_BaalLukor_ALTAR_13_07","Info_BaalLukor_ALTAR_13_08"],"lines":[{"speaker":"npc","text":{"pl":"NIEEE!!!","en":"NOOOOOO!!!","de":"NEEEEEIIIIIINNNNN!!!"}},{"speaker":"hero","text":{"pl":"No to koniec. Teraz całkiem mu odbiło.","en":"That was it. Now he''s gone completely crazy!","de":"Das war''s. Jetzt ist er völlig übergeschnappt!"}},{"speaker":"npc","text":{"pl":"To wszystko twoja wina. Twoja bluźniercza obecność rozgniewała wszechmocnego Śniącego!","en":"This is all your fault. Your unholy presence has enraged the almighty Sleeper!","de":"Das ist alles nur deine Schuld. Deine unheilige Präsenz hat den allmächtigen Schläfer erzürnt!"}},{"speaker":"npc","text":{"pl":"Teraz ja będę musiał ponieść karę za twoje grzeszne czyny!","en":"Now I shall have to suffer for your sacrilegious behavior!","de":"Jetzt muss ich für dein frevelhaftes Verhalten büßen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_altar_13_09_8', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_altar_13_09_8","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_ALTAR_Info","outputIds":["Info_BaalLukor_ALTAR_13_09","Info_BaalLukor_ALTAR_13_10","Info_BaalLukor_ALTAR_13_11","Info_BaalLukor_ALTAR_13_12"],"lines":[{"speaker":"npc","text":{"pl":"Muszę złożyć ofiarę, aby przebłagać mego pana. OFIARĘ Z CZŁOWIEKA!!!","en":"I need to make a sacrifice for the master. A HUMAN SACRIFICE!!!","de":"Ich werde unserem Meister ein Opfer darbringen. Ein MENSCHENOPFER!!!"}},{"speaker":"npc","text":{"pl":"Wtedy Śniący znów spojrzy na mnie przychylnym okiem i uczyni mnie swoim sługą.","en":"Then he''ll be sure to enlighten me and make me his servant.","de":"Bestimmt wird er mich dann erleuchten und zu seiner rechten Hand machen."}},{"speaker":"npc","text":{"pl":"GIŃ, NIEWIERNY PSIE!!!","en":"DIE, INFIDEL!!!!","de":"STIRB, UNGLÄUBIGER!!!!"}},{"speaker":"npc","text":{"pl":"AIIIEEEEHHHHHH!!!!!!","en":"AIIIEEEEHHHHHH!!!!!!","de":"AIIIEEEEHHHHHH!!!!!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_bothscrolls_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_bothscrolls_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_BOTHSCROLLS_Info","outputIds":["Info_BaalLukor_BOTHSCROLLS_15_01","Info_BaalLukor_BOTHSCROLLS_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Co teraz zrobimy z tymi dwoma fragmentami?","en":"What do we do with the two pieces now?","de":"Was fangen wir jetzt mit diesen beiden Stücken an?"}},{"speaker":"npc","text":{"pl":"To dwie połowy tego samego manuskryptu. Ale nie potrafię odcyfrować tego pisma.","en":"The two halves match. But I can''t translate these Orcish signs.","de":"Die beiden Hälften passen zusammen. Doch ich kann die orkischen Zeichen nicht übersetzen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_dead_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_dead_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_DEAD_Info","outputIds":["Info_BaalLukor_DEAD_15_01","Info_BaalLukor_DEAD_13_02","Info_BaalLukor_DEAD_13_03","Info_BaalLukor_DEAD_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Po drodze znalazłem ciała Świątynnych Strażników! Co się stało?","en":"I came across some dead templars on the way here! What happened?","de":"Ich habe tote Templer auf dem Weg hierher gefunden! Was ist passiert?"}},{"speaker":"npc","text":{"pl":"Mistrz Cor Angar przysłał nas tutaj, byśmy przeszukali jaskinie.","en":"Master Cor Angar sent us here to investigate the caves.","de":"Meister Cor Angar hat uns hierhin entsandt, um die Höhlen zu erforschen."}},{"speaker":"npc","text":{"pl":"Spodziewaliśmy się znaleźć tu tylko stare groby i rozpadające się mumie.","en":"We expected to find nothing but stuffy graves and half decomposed mummies.","de":"Wir hatte nichts als muffige Grabnischen und halbzerfallene Mumien erwartet."}},{"speaker":"npc","text":{"pl":"Nagle coś poruszyło się w ciemnościach i dookoła pojawili się Orkowie. Nie wiem, czego tam szukali, ale ich obecność tutaj jest bardzo niepokojąca!","en":"Suddenly the darkness shifted and there were Orcs everywhere. I don''t know what they''re looking for here, but their appearing here is more than unusual!","de":"Dann plötzlich bewegte sich die Dunkelheit und überall waren Orks. Ich weiß nicht, was sie hier suchen, aber ihr Auftauchen hier ist mehr als ungewöhnlich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_dead_15_05_4', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_dead_15_05_4","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_DEAD_Info","outputIds":["Info_BaalLukor_DEAD_15_05","Info_BaalLukor_DEAD_13_06"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie są pozostali Strażnicy?","en":"Where are the other templars?","de":"Wo sind die anderen Templer?"}},{"speaker":"npc","text":{"pl":"Nie żyją! Nieświadomie doprowadziłem do ich zagłady! Niech Śniący zlituje się nad moją duszą!","en":"Dead! I unwittingly led them to their destruction. I hope the Sleeper will pardon me.","de":"Tot! Ich habe sie unwissend ins Verderben geführt. Ich hoffe, der Schläfer wird mir das verzeihen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_door_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_door_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_DOOR_Info","outputIds":["Info_BaalLukor_DOOR_13_01","Info_BaalLukor_DOOR_13_02","Info_BaalLukor_DOOR_13_03"],"lines":[{"speaker":"npc","text":{"pl":"Za tą ścianą... To musi być tutaj!","en":"Behind this wall... that must be it!","de":"Hinter dieser Wand ... Das muss es sein!"}},{"speaker":"npc","text":{"pl":"Moje moce magiczne są wciąż bardzo osłabione.","en":"My magic powers are still very weak.","de":"Meine magische Kraft ist noch immer geschwächt."}},{"speaker":"npc","text":{"pl":"Użyj orkowego zaklęcia teleportacji! Właśnie tutaj, przed tą ścianą.","en":"Use the Orcish teleportation spell here, in front of this wall.","de":"Benutze den orkischen Teleportzauber hier vor dieser Wand."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_firstscroll_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_firstscroll_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_FIRSTSCROLL_Info","outputIds":["Info_BaalLukor_FIRSTSCROLL_15_01","Info_BaalLukor_FIRSTSCROLL_13_02","Info_BaalLukor_FIRSTSCROLL_13_03","Info_BaalLukor_FIRSTSCROLL_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem fragment pergaminu!","en":"I''ve found a piece of parchment!","de":"Ich habe dieses Stück Pergament hier gefunden!"}},{"speaker":"npc","text":{"pl":"Wspaniale! To druga połowa zwoju z zaklęciem Orków!","en":"Very good! It''s the other half of the Orcish spell scroll.","de":"Sehr gut! Dies ist die andere Hälfte der orkischen Spruchrolle."}},{"speaker":"npc","text":{"pl":"To mi wygląda na zwój z zaklęciem Orków. Niestety, został przerwany na pół.","en":"It looks like an Orcish spell scroll, but it''s been torn in two.","de":"Das sieht aus wie eine orkische Zauberspruchrolle, aber sie ist mittendurch gerissen."}},{"speaker":"npc","text":{"pl":"Gdzieś musi być druga połowa tego pergaminu!","en":"There must be another half somewhere.","de":"Es muss noch eine andere Hälfte davon geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_firstwait_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_firstwait_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_FIRSTWAIT_Info","outputIds":["Info_BaalLukor_FIRSTWAIT_13_01"],"lines":[{"speaker":"npc","text":{"pl":"Dalej już nie pójdziemy. Może w tych niszach znajdziemy jakąś wskazówkę.","en":"We can''t go on here! Maybe these niches bear hints.","de":"Hier geht es nicht weiter! Vielleicht bergen die Nischen hier Hinweise."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_foundnone_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_foundnone_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_FOUNDNONE_Info","outputIds":["Info_BaalLukor_FOUNDNONE_15_01","Info_BaalLukor_FOUNDNONE_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Nic tu nie ma.","en":"I can''t find a thing!","de":"Ich kann keinen Hinweis finden!"}},{"speaker":"npc","text":{"pl":"Musimy przeszukać wszystkie trzy tunele.","en":"We''ll need to search the three tunnels.","de":"Wir müssen die drei Stollen durchsuchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_foundone_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_foundone_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_FOUNDONE_Info","outputIds":["Info_BaalLukor_FOUNDONE_15_01","Info_BaalLukor_FOUNDONE_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Najwyraźniej druga połowa pergaminu uległa zniszczeniu!","en":"Apparently there is no other half to the parchment!","de":"Es scheint hier keine andere Pergamenthälfte zu geben!"}},{"speaker":"npc","text":{"pl":"Druga połowa musi być gdzieś w pobliżu! Musimy przeszukać pozostałe tunele!","en":"There must be a second half. We should search all three tunnels!","de":"Es muss eine zweite Hälfte geben. Wir sollten alle drei Stollen gründlich durchsuchen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_hallwith_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_hallwith_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_HALLWITH_Info","outputIds":["Info_BaalLukor_HALLWITH_13_01","Info_BaalLukor_HALLWITH_15_02","Info_BaalLukor_HALLWITH_13_03"],"lines":[{"speaker":"npc","text":{"pl":"To miejsce posiada szczególną aurę. Aurę tajemnicy.","en":"This place has a special aura... the aura of the hidden.","de":"Dieser Ort hat eine besondere Ausstrahlung ... Die Ausstrahlung des Verborgenen."}},{"speaker":"hero","text":{"pl":"To pomieszczenie przypomina mi obraz z naszej wizji.","en":"This hall reminds me of the image in the vision.","de":"Diese Halle erinnert mich an das Bild aus der Vision."}},{"speaker":"npc","text":{"pl":"Wizja... Jesteśmy już bardzo blisko celu...","en":"The vision... We''re very close to our target...","de":"Die Vision ... Wir sind unserem Ziel sehr nahe ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_hallwithout_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_hallwithout_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_HALLWITHOUT_Info","outputIds":["Info_BaalLukor_HALLWITHOUT_13_01","Info_BaalLukor_HALLWITHOUT_13_02"],"lines":[{"speaker":"npc","text":{"pl":"To miejsce... Nie potrafię tego wyjaśnić, ale to miejsce...","en":"This place... I can''t explain it, but this place here...","de":"Dieser Ort ... ich kann es nicht erklären, aber dieser Ort hier ..."}},{"speaker":"npc","text":{"pl":"Och, nieważne. Pewnie mi się tylko wydaje.","en":"Oh, forget it. Must have been my imagination.","de":"Ach vergiss es. Es ist bestimmt nur Einbildung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_help_13_03_4', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_help_13_03_4","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_TELEPORT_Info","outputIds":["Info_BaalLukor_HELP_13_03"],"lines":[{"speaker":"npc","text":{"pl":"Prowadź. Pójdę za tobą!","en":"Go ahead. I''ll follow you!","de":"Geh voraus. Ich folge dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_help_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_help_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_HELP_Info","outputIds":["Info_BaalLukor_HELP_15_01","Info_BaalLukor_HELP_13_02","Info_BaalLukor_HELP_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Pomogę ci.","en":"I''ll help you.","de":"Ich werde dir helfen."}},{"speaker":"npc","text":{"pl":"To wspaniale. Z tego pomieszczenia wychodzą trzy korytarze. Powinniśmy przeszukać każdy z nich.","en":"Good. Excellent. There are three tunnels leading out of this hall. We should search ''em all.","de":"Gut. Sehr gut. Aus dieser Halle führen drei Stollen. Wir sollten sie alle durchsuchen."}},{"speaker":"npc","text":{"pl":"Prowadź. Pójdę za tobą!","en":"Go ahead. I''ll follow you!","de":"Geh voraus. Ich folge dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_meet_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_meet_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_MEET_Info","outputIds":["Info_BaalLukor_MEET_13_01"],"lines":[{"speaker":"npc","text":{"pl":"Dzięki za pomoc. Zjawiłeś się w ostatniej chwili.","en":"Thanks for your help. You really arrived in the last moment.","de":"Danke für deine Hilfe. Du bist wirklich in letzter Sekunde gekommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_runes_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_runes_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_RUNES_Info","outputIds":["Info_BaalLukor_RUNES_13_01","Info_BaalLukor_RUNES_15_02","Info_BaalLukor_RUNES_13_03","Info_BaalLukor_RUNES_13_04"],"lines":[{"speaker":"npc","text":{"pl":"Czekaj! To interesujące...","en":"Hang on! This is interesting...","de":"Warte mal! Das ist interessant ..."}},{"speaker":"hero","text":{"pl":"Cóż, nie widzę tu nic interesującego.","en":"Well, I can''t find anything interesting in this place.","de":"Also ich kann diesem Ort beim besten Willen nichts Interessantes abgewinnen."}},{"speaker":"npc","text":{"pl":"Cicho! Przyjrzyj się uważnie ornamentom zdobiącym tę jaskinię.","en":"Be silent and take a look at the ornamental runes in this cave.","de":"Schweig und betrachte die Runenornamente in dieser Höhle hier."}},{"speaker":"npc","text":{"pl":"Tak, to mi powinno wystarczyć do przetłumaczenia znalezionego przez nas pergaminu.","en":"Yeah, these should suffice to translate the two halves of the parchment.","de":"Das sollte ausreichend Material geben, um die geteilten Pergamenthälften zu übersetzen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_runes_13_05_4', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_runes_13_05_4","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_RUNES_Info","outputIds":["Info_BaalLukor_RUNES_13_05","Info_BaalLukor_RUNES_13_06","Info_BaalLukor_RUNES_13_07"],"lines":[{"speaker":"npc","text":{"pl":"...(murmel)...(murmel)...(murmel)...","en":"...(murmel)...(murmel)...(murmel)...","de":"...(murmel)...(murmel)...(murmel)..."}},{"speaker":"npc","text":{"pl":"Już wiem! To zaklęcie teleportacji! Wygląda na to, że można go użyć tylko w konkretnym miejscu!","en":"I have it! It''s a teleportation spell. It seems that it can only unfold its powers in a certain place.","de":"Das ist es! Es handelt sich um einen Teleportzauber. Er scheint aber nur an einem gewissen Ort seine Kraft entfalten zu können."}},{"speaker":"npc","text":{"pl":"Dziwne!","en":"Strange!","de":"Seltsam!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_secondscroll_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_secondscroll_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_SECONDSCROLL_Info","outputIds":["Info_BaalLukor_SECONDSCROLL_15_01","Info_BaalLukor_SECONDSCROLL_13_02","Info_BaalLukor_SECONDSCROLL_13_03","Info_BaalLukor_SECONDSCROLL_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem fragment pergaminu!","en":"There is a torn piece of parchment here!","de":"Hier ist ein zerrissenes Stück Pergament!"}},{"speaker":"npc","text":{"pl":"Wspaniale! To druga połowa zwoju z zaklęciem Orków!","en":"Very good! It''s the other half of the Orcish spell scroll.","de":"Sehr gut! Dies ist die andere Hälfte der orkischen Spruchrolle."}},{"speaker":"npc","text":{"pl":"To mi wygląda na zwój z zaklęciem Orków. Niestety, został przerwany na pół.","en":"It looks like an Orcish spell scroll, but it''s been torn in two.","de":"Das sieht aus wie eine orkische Zauberspruchrolle, aber sie ist mittendurch gerissen."}},{"speaker":"npc","text":{"pl":"Gdzieś musi być druga połowa tego pergaminu!","en":"There must be another half somewhere.","de":"Es muss noch eine andere Hälfte davon geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_secondwait_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_secondwait_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_SECONDWAIT_Info","outputIds":["Info_BaalLukor_SECONDWAIT_13_01"],"lines":[{"speaker":"npc","text":{"pl":"Hmmm... Ten tunel okazał się ślepą uliczką. Może znajdziemy tutaj jakieś wskazówki, które pomogą nam w naszych poszukiwaniach.","en":"Hmmm... this tunnel leads to a dead end! Maybe you''ll find some clues here that''ll help us further.","de":"Hmmm ... Dieser Stollen ist eine Sackgasse! Vielleicht findest du hier irgendwelche Hinweise, die uns weiterhelfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_summoning_13_05_4', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_summoning_13_05_4","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_SUMMONING_Info","outputIds":["Info_BaalLukor_SUMMONING_13_05","Info_BaalLukor_SUMMONING_13_06"],"lines":[{"speaker":"npc","text":{"pl":"Ale moje zdolności bojowe są dość ograniczone, a Orkowie nie reagują na moją magię jak ci głupcy ze Starego Obozu.","en":"But my fighting skills are limited and the Orcs don''t react to my magic spells like the gullible people in the Old Camp do.","de":"Doch meine Kampfkünste sind sehr begrenzt und die Orks sprechen nicht auf meine magischen Kräfte an, so wie es die leichtgläubigen Menschen aus dem Alten Lager tun."}},{"speaker":"npc","text":{"pl":"Skoro przysyła cię Bractwo, może pomożesz mi w badaniu tego cmentarzyska.","en":"If our Brotherhood sent you, maybe you could help me with the further investigation of this tomb.","de":"Wenn dich schon unsere Bruderschaft schickt, vielleicht könntest du mir bei der restlichen Erforschung dieser Gruft helfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_summoning_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_summoning_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_SUMMONING_Info","outputIds":["Info_BaalLukor_SUMMONING_15_01","Info_BaalLukor_SUMMONING_13_02","Info_BaalLukor_SUMMONING_15_03","Info_BaalLukor_SUMMONING_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Cor Angar. Odnaleźliście jakieś ślady Śniącego?","en":"Cor Angar sent me! Have you found any sign of the Sleeper?","de":"Cor Angar schickt mich! Habt ihr irgendein Zeichen des Schläfers gefunden?"}},{"speaker":"npc","text":{"pl":"Jeszcze nie. A co z Y''Berionem? Doszedł już do siebie?","en":"Not so far. But what about Y''Berion? Has he come to yet?","de":"Bisher noch nicht. Aber was ist mit Y''Berion? Ist er wieder zu sich gekommen?"}},{"speaker":"hero","text":{"pl":"Nie, nadal jest nieprzytomny.","en":"No, he''s still unconscious.","de":"Nein, er ist immer noch ohnmächtig."}},{"speaker":"npc","text":{"pl":"Musimy zbadać ten kompleks jaskiń. Po tych wszystkich straszliwych wydarzeniach nie mogę wrócić do Obozu z pustymi rękami.","en":"We need to solve the riddle of these caves. After all these dreadful losses, I can''t go back to the community empty-handed.","de":"Wir müssen dem Rätsel dieser Höhlen auf den Grund gehen. Nach all den schrecklichen Verlusten kann ich nicht mit leeren Händen zur Gemeinschaft zurückkehren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_teleport_13_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_teleport_13_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_TELEPORT_Info","outputIds":["Info_BaalLukor_TELEPORT_13_01","Info_BaalLukor_TELEPORT_15_02","Info_BaalLukor_TELEPORT_15_03","Info_BaalLukor_TELEPORT_13_04"],"lines":[{"speaker":"npc","text":{"pl":"Znalazłeś ukrytą komorę! Mój instynkt mnie nie zawiódł.","en":"You''ve found the hidden place. My instincts have not deceived me.","de":"Du hast den verborgenen Ort gefunden. Meine Instinkte haben mich nicht getäuscht."}},{"speaker":"hero","text":{"pl":"Naprawdę znajdziemy tu odpowiedź na tajemnicze wydarzenia związane z przyzwaniem Śniącego?","en":"And does the answer to the strange invocation of the Sleeper really lie here???","de":"Und hier liegt die Antwort auf die rätselhafte Anrufung des Schläfers???"}},{"speaker":"hero","text":{"pl":"To mi raczej wygląda na kolejną komorę grobowcową.","en":"It looks more like another burial chamber to me.","de":"Sieht mir eher nach einer weiteren Grabkammer aus."}},{"speaker":"npc","text":{"pl":"Musimy iść dalej.","en":"We need to proceed.","de":"Wir müssen weiter."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1211_baal_lukor_info_baal_lukor_whatnow_15_01_0', 'GUR_1211_BaalLukor', '{"id":"missions_dia_gur_1211_baal_lukor_info_baal_lukor_whatnow_15_01_0","npcId":"GUR_1211_BaalLukor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1211_BaalLukor.d","sourceFunction":"Info_BaalLukor_WHATNOW_Info","outputIds":["Info_BaalLukor_WHATNOW_15_01","Info_BaalLukor_WHATNOW_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Jakim \"konkretnym\" miejscu?","en":"What ''certain'' place?","de":"Was für ein ''gewisser'' Ort!"}},{"speaker":"npc","text":{"pl":"Ta wielka komora, przez którą przechodziliśmy wcześniej wydała mi się dość... niezwykła. Powinniśmy tam czym prędzej wrócić!","en":"The big hall we passed through earlier seemed a very... strange... place. Let''s just go back there!","de":"Die große Halle vorhin, kam mir sehr ... seltsam ... vor. Lass uns noch mal dorthin zurück!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1212_mad_cor_kalom_gur_1212_mad_cor_kalom_talk2_sc_10_01_0', 'GUR_1212_MadCorKalom', '{"id":"missions_dia_gur_1212_mad_cor_kalom_gur_1212_mad_cor_kalom_talk2_sc_10_01_0","npcId":"GUR_1212_MadCorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1212_MadCorKalom.d","sourceFunction":"GUR_1212_MadCorKalom_Talk2SC_Info","outputIds":["GUR_1212_MadCorKalom_Talk2SC_10_01","GUR_1212_MadCorKalom_Talk2SC_10_02","GUR_1212_MadCorKalom_Talk2SC_10_03","GUR_1212_MadCorKalom_Talk2SC_15_04"],"lines":[{"speaker":"npc","text":{"pl":"Nareszcie, znów się spotykamy!","en":"At last we meet again!","de":"Schließlich sehen wir uns also wieder!"}},{"speaker":"npc","text":{"pl":"Mój pan uprzedził mnie o twoim przybyciu!","en":"My master has already told me of your arrival!","de":"Mein Meister hat mir bereits von deiner Ankunft berichtet!"}},{"speaker":"npc","text":{"pl":"On potrafi wyczuć, że jesteś w pobliżu!","en":"He can sense that you''re near.","de":"Er kann deine Nähe spüren."}},{"speaker":"hero","text":{"pl":"Wkrótce znajdę się bliżej niego, niż mógłby sobie tego życzyć!","en":"I''ll soon be nearer to him than he would like me to be!","de":"Schon bald werde ich ihm näher sein, als ihm lieb ist!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1212_mad_cor_kalom_gur_1212_mad_cor_kalom_talk2_sc_10_05_4', 'GUR_1212_MadCorKalom', '{"id":"missions_dia_gur_1212_mad_cor_kalom_gur_1212_mad_cor_kalom_talk2_sc_10_05_4","npcId":"GUR_1212_MadCorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1212_MadCorKalom.d","sourceFunction":"GUR_1212_MadCorKalom_Talk2SC_Info","outputIds":["GUR_1212_MadCorKalom_Talk2SC_10_05","GUR_1212_MadCorKalom_Talk2SC_10_06","GUR_1212_MadCorKalom_Talk2SC_10_07","GUR_1212_MadCorKalom_Talk2SC_10_08"],"lines":[{"speaker":"npc","text":{"pl":"Nie pozwolimy, byś pokrzyżował nasze plany.","en":"We will not let you foil our plans.","de":"Wir werden nicht zulassen, dass du unsere Pläne durchkreuzt."}},{"speaker":"npc","text":{"pl":"Świat doświadczy wkrótce przebudzenia wielkiego Odkupiciela i nikt nie jest w stanie temu zapobiec.","en":"The world is about to witness the awakening of the Redeemer, and nobody can stop him.","de":"Die Welt steht kurz vor dem Erwachen des Erlösers und keiner kann ihn aufhalten."}},{"speaker":"npc","text":{"pl":"Wszyscy niewierni zapłacą słoną cenę.","en":"All the infidels out there will pay the price.","de":"All die Ungläubigen da draußen werden ihren Preis bezahlen ."}},{"speaker":"npc","text":{"pl":"A ty będziesz miał zaszczyt być pierwszym z nich.","en":"And you shall have the honor of being the first to pay.","de":"Und du hast die Ehre, der Erste zu sein, der diesen Preis bezahlen darf ."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_gur_1212_mad_cor_kalom_gur_1212_mad_cor_kalom_talk2_sc_10_09_8', 'GUR_1212_MadCorKalom', '{"id":"missions_dia_gur_1212_mad_cor_kalom_gur_1212_mad_cor_kalom_talk2_sc_10_09_8","npcId":"GUR_1212_MadCorKalom","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_GUR_1212_MadCorKalom.d","sourceFunction":"GUR_1212_MadCorKalom_Talk2SC_Info","outputIds":["GUR_1212_MadCorKalom_Talk2SC_10_09"],"lines":[{"speaker":"npc","text":{"pl":"ŚNIĄCY, ZBUDŹ SIĘ!!!","en":"SSSLLLLLLEEEEEEEEEEEPPPEEEEEERRRR AAWWWAAAAAAAAAAAKKKEEEEEENN!!!!!!!!!","de":"SCHLÄÄÄÄÄÄÄÄÄÄFEEEEEEEEEEEER ERWAAAAAAAAAAAACHEEEEEEEEEEEEE !!!!!!!!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_ie_397_announcer_info_announcer_announce_11_01_0', 'IE_397_Announcer', '{"id":"missions_dia_ie_397_announcer_info_announcer_announce_11_01_0","npcId":"IE_397_Announcer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_IE_397_Announcer.d","sourceFunction":"IE_397_Announcer_ANNOUNCE_Info","outputIds":["Info_Announcer_ANNOUNCE_11_01","Info_Announcer_ANNOUNCE_11_02","Info_Announcer_ANNOUNCE_11_03"],"lines":[{"speaker":"npc","text":{"pl":"Moi szanowni Magnaci, drodzy Strażnicy, Cienie i Kopacze...","en":"My esteemed Ore Barons, honored guards, Shadows and diggers...","de":"Hochverehrte Erzbarone, geehrte Gardisten, Schatten und Buddler ..."}},{"speaker":"npc","text":{"pl":"Z prawdziwą przyjemnością przedstawiam wam...","en":"It gives me great honor to present...","de":"Ich präsentiere ihnen ..."}},{"speaker":"npc","text":{"pl":"!!! IN EXTREMO !!!!","en":"!!! IN EXTREMO !!!!","de":"!!! IN EXTREMO !!!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_400_rodriguez_dia_rodriguez_hello_15_00_0', 'KDF_400_Rodriguez', '{"id":"missions_dia_kdf_400_rodriguez_dia_rodriguez_hello_15_00_0","npcId":"KDF_400_Rodriguez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_400_Rodriguez.d","sourceFunction":"DIA_Rodriguez_Hello_Info","outputIds":["DIA_Rodriguez_Hello_15_00","DIA_Rodriguez_Hello_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Szukam Arcymistrza Magów Ognia!","en":"I''m looking for the High Magician of the Circle of Fire!","de":"Ich suche den obersten Magier des Feuers!"}},{"speaker":"npc","text":{"pl":"Zgłoś się do Miltena. On się zajmuje kurierami.","en":"Just go to Milten. He deals with gofers like you.","de":"Geh zu Milten. Der gibt sich mit Laufburschen wie dir ab."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_401_damarok_kdf_401_damarok_heal_info_14_01_0', 'KDF_401_Damarok', '{"id":"missions_dia_kdf_401_damarok_kdf_401_damarok_heal_info_14_01_0","npcId":"KDF_401_Damarok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_401_Damarok.d","sourceFunction":"KDF_401_Damarok_HEAL_Info","outputIds":["KDF_401_Damarok_HEAL_Info_14_01"],"lines":[{"speaker":"npc","text":{"pl":"Gdybyś został ranny, uzdrowię cię.","en":"If you are injured, I shall heal you.","de":"Wenn du Schaden nehmen solltest, werde ich dich heilen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_401_damarok_kdf_401_damarok_healinfo_info_15_01_0', 'KDF_401_Damarok', '{"id":"missions_dia_kdf_401_damarok_kdf_401_damarok_healinfo_info_15_01_0","npcId":"KDF_401_Damarok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_401_Damarok.d","sourceFunction":"KDF_401_Damarok_HEALINFO_Info","outputIds":["KDF_401_Damarok_HEALINFO_Info_15_01","KDF_401_Damarok_HEALINFO_Info_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Jestem ranny. Możesz mi pomóc?","en":"I''m injured. Can you heal me?","de":"Ich bin verletzt. Kannst du mich heilen?"}},{"speaker":"npc","text":{"pl":"W zdrowym ciele - zdrowy duch.","en":"The body heals, the spirit grows clear.","de":"Der Körper gesundet, der Geist wird klar."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_401_damarok_kdf_401_damarok_welcome_info_14_01_0', 'KDF_401_Damarok', '{"id":"missions_dia_kdf_401_damarok_kdf_401_damarok_welcome_info_14_01_0","npcId":"KDF_401_Damarok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_401_Damarok.d","sourceFunction":"KDF_401_Damarok_WELCOME_Info","outputIds":["KDF_401_Damarok_WELCOME_Info_14_01"],"lines":[{"speaker":"npc","text":{"pl":"Niech Ogień rozświetla twe życie.","en":"May the Fire always protect you!","de":"Möge das Feuer dich allzeit beschützen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_info_saturas_intruder_14_00_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_info_saturas_intruder_14_00_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"Info_Corristo_Intruder_Info","outputIds":["Info_Saturas_Intruder_14_00"],"lines":[{"speaker":"npc","text":{"pl":"Co ty tu robisz? Nie masz tu czego szukać! Precz!","en":"What are you doing here? You''ve no business here! Scram!","de":"Was machst du hier? Du hast hier nichts zu suchen! Verschwinde!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_aufnahme_info_14_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_aufnahme_info_14_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_AUFNAHME_Info","outputIds":["KDF_402_Corristo_AUFNAHME_Info_14_01","KDF_402_Corristo_AUFNAHME_Info_14_02","KDF_402_Corristo_AUFNAHME_Info_14_03","KDF_402_Corristo_AUFNAHME_Info_15_04"],"lines":[{"speaker":"npc","text":{"pl":"Zebraliśmy się tu dzisiaj, aby przyjąć do naszego grona nowego sługę Ognia.","en":"We are gathered here today to ordain a servant of Fire.","de":"Wir sind heute zusammengekommen, um einen Diener des Feuers zu weihen."}},{"speaker":"npc","text":{"pl":"Teraz złożysz przysięgę Ognia.","en":"Now take the oath of Fire.","de":"Schwöre nun den Eid des Feuers."}},{"speaker":"npc","text":{"pl":"Przysięgam, na wszechmocnych bogów...","en":"I swear by the might of the gods...","de":"Ich schwöre bei den Mächten der Götter..."}},{"speaker":"hero","text":{"pl":"Przysięgam, na wszechmocnych bogów...","en":"I swear by the might of the gods...","de":"Ich schwöre bei den Mächten der Götter..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_aufnahme_info_14_05_4', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_aufnahme_info_14_05_4","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_AUFNAHME_Info","outputIds":["KDF_402_Corristo_AUFNAHME_Info_14_05","KDF_402_Corristo_AUFNAHME_Info_15_06","KDF_402_Corristo_AUFNAHME_Info_14_07","KDF_402_Corristo_AUFNAHME_Info_15_08"],"lines":[{"speaker":"npc","text":{"pl":"...Przysięgam, na potęgę świętego Ognia...","en":"... I swear by the force of the holy Fire...","de":"Ich schwöre bei der Macht des heiligen Feuers..."}},{"speaker":"hero","text":{"pl":"...Przysięgam, na potęgę świętego Ognia...","en":"... I swear by the force of the holy Fire...","de":"Ich schwöre bei der Macht des heiligen Feuers..."}},{"speaker":"npc","text":{"pl":"...Że ma wiedza i me czyny teraz i na wieki stanowić będą jedność z płomieniem...","en":"... that my knowledge and my deeds from now on and forever shall be one with the flame...","de":"Dass mein Wissen und Handlen von nun an und auf ewig mit der Flamme verbunden sei..."}},{"speaker":"hero","text":{"pl":"...Że ma wiedza i me czyny teraz i na wieki stanowić będą jedność z płomieniem...","en":"... that my knowledge and my deeds from now on and forever shall be one with the flame...","de":"Dass mein Wissen und Handlen von nun an und auf ewig mit der Flamme verbunden sei..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_aufnahme_info_14_09_8', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_aufnahme_info_14_09_8","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_AUFNAHME_Info","outputIds":["KDF_402_Corristo_AUFNAHME_Info_14_09","KDF_402_Corristo_AUFNAHME_Info_15_10"],"lines":[{"speaker":"npc","text":{"pl":"...Dopóki me ciało nie powróci do królestwa Beliara, gdy płomień mego życia wygaśnie.","en":"... until my body shall return to the realm of Beliar and the fire of my life be extinguished.","de":"Bis mein Körper einkehrt in Beliars Reich und das Feuer des Lebens erlischt."}},{"speaker":"hero","text":{"pl":"...Dopóki me ciało nie powróci do królestwa Beliara, gdy płomień mego życia wygaśnie.","en":"... until my body shall return to the realm of Beliar and the fire of my life be extinguished.","de":"Bis mein Körper einkehrt in Beliars Reich und das Feuer des Lebens erlischt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_explaincircles_info_14_05_4', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_explaincircles_info_14_05_4","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_EXPLAINCIRCLES_Info","outputIds":["KDF_402_Corristo_EXPLAINCIRCLES_Info_14_05","KDF_402_Corristo_EXPLAINCIRCLES_Info_14_06","KDF_402_Corristo_EXPLAINCIRCLES_Info_14_07","KDF_402_Corristo_EXPLAINCIRCLES_Info_14_08"],"lines":[{"speaker":"npc","text":{"pl":"Czeka cię wiele godzin ćwiczeń. To trudna droga, z której łatwo zboczyć, ale nagroda warta jest poświęcenia.","en":"Many hours of learning are required and you''ll need much experience to reach the higher Circles.","de":"Es erfordert viele Lernstunden und es bedarf hoher Erfahrung, willst du die höheren Kreise erreichen."}},{"speaker":"npc","text":{"pl":"Za każdym razem, kiedy awansujesz do kolejnego Kręgu, poznasz nowe, potężniejsze zaklęcia. Oczywiście magiczne Kręgi to coś więcej niż tylko mocniejsze czary.","en":"But your efforts to reach them will be rewarded with new and powerful spells each time. However, the Circles of magic are more than that.","de":"Doch die Mühe, sie zu erlernen, wird jedes Mal mit neuen machtvollen Zaubern belohnt. Die Kreise der Magie sind aber noch mehr als das."}},{"speaker":"npc","text":{"pl":"To istotna część twojego życia. One zawsze będą z tobą. Uczyń je częścią siebie.","en":"They are part of your life. They will always be with you. Make them part of you.","de":"Sie sind ein Teil deines Lebens. Sie werden dich immer begleiten. Mache sie zu einem Teil von dir."}},{"speaker":"npc","text":{"pl":"Pojmując ich potęgę, pojmiesz potęgę siebie samego.","en":"To understand their might, you need to recognize your own.","de":"Ihre Macht zu verstehen, bedeutet deine eigene Macht zu erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_explaincircles_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_explaincircles_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_EXPLAINCIRCLES_Info","outputIds":["KDF_402_Corristo_EXPLAINCIRCLES_Info_15_01","KDF_402_Corristo_EXPLAINCIRCLES_Info_14_02","KDF_402_Corristo_EXPLAINCIRCLES_Info_14_03","KDF_402_Corristo_EXPLAINCIRCLES_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Wyjaśnij mi znaczenie magicznych Kręgów.","en":"Please explain the meaning of the magic Circles.","de":"Erkläre mir das Wesen der magischen Kreise."}},{"speaker":"npc","text":{"pl":"Oczywiście. Kręgi symbolizują twój udział w magicznych mocach.","en":"Of course. The Circles symbolize your share of the magic.","de":"Natürlich. Die Kreise symbolisieren deinen Anteil an der magischen Macht."}},{"speaker":"npc","text":{"pl":"Symbolizują wiedzę, umiejętności i poznanie magicznych zaklęć i formuł.","en":"They stand for knowledge, skill and the learning of new magic spells.","de":"Sie stehen für Wissen, Begabung und für das Erlernen neuer Zaubersprüche."}},{"speaker":"npc","text":{"pl":"Musisz ukończyć każdy Krąg, zanim wolno ci będzie przystąpić do następnego.","en":"You must pass through each Circle before you can join the next.","de":"Du wirst jeden Kreis durchlaufen, bis du in den nächsten aufgenommen werden kannst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_explainmage_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_explainmage_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_EXPLAINMAGE_Info","outputIds":["KDF_402_Corristo_EXPLAINMAGE_Info_15_01","KDF_402_Corristo_EXPLAINMAGE_Info_14_02","KDF_402_Corristo_EXPLAINMAGE_Info_14_03","KDF_402_Corristo_EXPLAINMAGE_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Powiedz mi - jak to jest być magiem?","en":"Tell me - what is it like to be a magician.","de":"Erzähl mir, wie ist es, ein Magier zu sein."}},{"speaker":"npc","text":{"pl":"Jesteśmy Magami Ognia. Służymy Innosowi - najpotężniejszemu z bogów.","en":"We are Magicians of Fire. We are the servants of Innos, the highest of all gods.","de":"Wir sind die Magier des Feuers. Die Diener von Innos, dem obersten aller Götter."}},{"speaker":"npc","text":{"pl":"Nasza magia jest darem niebios. Jesteśmy kapłanami, nauczycielami i sędziami jednocześnie.","en":"Our magic is a gift from the gods. We''ve been chosen to act as priests, tutors and judges.","de":"Unsere Magie ist ein Geschenk der Götter. Wir sind auserwählt, zugleich Priester, Lehrer und Richter zu sein."}},{"speaker":"npc","text":{"pl":"Dar, który jest jednocześnie wielkim ciężarem. To zadanie, które określa cel naszego życia.","en":"It is a gift which is a constant burden to us. A task which determines our lives.","de":"Ein Geschenk, das zugleich eine Bürde ist. Ein Amt, das unser Leben bestimmt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_adanos_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_adanos_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_ADANOS","outputIds":["KDF_402_Corristo_KDFTEST_ADANOS_Info_15_01","KDF_402_Corristo_KDFTEST_ADANOS_Info_14_02","KDF_402_Corristo_KDFTEST_ADANOS_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Adanos.","en":"Adanos.","de":"Adanos."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"To nieprawidłowa odpowiedź. Może w Straży będzie z ciebie więcej pożytku.","en":"That is incorrect. Maybe the Guards can make use of you.","de":"Das ist nicht richtig. Vielleicht kann dich ja die Garde gebrauchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_demut_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_demut_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_DEMUT","outputIds":["KDF_402_Corristo_KDFTEST_DEMUT_Info_15_01","KDF_402_Corristo_KDFTEST_DEMUT_Info_14_02","KDF_402_Corristo_KDFTEST_DEMUT_Info_14_03","KDF_402_Corristo_KDFTEST_DEMUT_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Pokora w obliczu magii.","en":"Humility in the face of magic.","de":"Die Demut vor der Magie."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Udzieliłeś mądrych, przemyślanych odpowiedzi. Możesz zostać moim uczniem.","en":"You have replied well and rightly. I shall teach you the art of magic.","de":"Du hast gut und recht geantwortet. Ich werde dich die Kunst der Magie lehren."}},{"speaker":"npc","text":{"pl":"Chodź za mną. Zaprowadzę cię do Komnaty Magii, gdzie złożysz starożytne ślubowanie.","en":"Follow me to the Hall of Magic, where you will take the ancient vow.","de":"Folge mir nun zur Halle der Magie, wo du den alten Schwur leisten wirst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_disziplin_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_disziplin_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_DISZIPLIN","outputIds":["KDF_402_Corristo_KDFTEST_DISZIPLIN_Info_15_01","KDF_402_Corristo_KDFTEST_DISZIPLIN_Info_14_02","KDF_402_Corristo_KDFTEST_DISZIPLIN_Info_14_03","KDF_402_Corristo_KDFTEST_DISZIPLIN_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Dyscyplina.","en":"The discipline of a man.","de":"Die Disziplin des Mannes."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Udzieliłeś mądrych, przemyślanych odpowiedzi. Możesz zostać moim uczniem.","en":"You have replied well and rightly. I shall teach you the art of magic.","de":"Du hast gut und recht geantwortet. Ich werde dich die Kunst der Magie lehren."}},{"speaker":"npc","text":{"pl":"Chodź za mną. Zaprowadzę cię do Komnaty Magii, gdzie złożysz starożytne ślubowanie.","en":"Follow me to the Hall of Magic, where you will take the ancient vow.","de":"Folge mir nun zur Halle der Magie, wo du den alten Schwur leisten wirst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_ehrfurcht_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_ehrfurcht_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_EHRFURCHT","outputIds":["KDF_402_Corristo_KDFTEST_EHRFURCHT_Info_15_01","KDF_402_Corristo_KDFTEST_EHRFURCHT_Info_14_02","KDF_402_Corristo_KDFTEST_EHRFURCHT_Info_14_03","KDF_402_Corristo_KDFTEST_EHRFURCHT_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Bogobojność.","en":"Awe of the gods.","de":"Die Ehrfurcht vor den Göttern."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Udzieliłeś mądrych, przemyślanych odpowiedzi. Możesz zostać moim uczniem.","en":"You have replied well and rightly. I shall teach you the art of magic.","de":"Du hast gut und recht geantwortet. Ich werde dich die Kunst der Magie lehren."}},{"speaker":"npc","text":{"pl":"Chodź za mną. Zaprowadzę cię do Komnaty Magii, gdzie złożysz starożytne ślubowanie.","en":"Follow me to the Hall of Magic, where you will take the ancient vow.","de":"Folge mir nun zur Halle der Magie, wo du den alten Schwur leisten wirst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_fight_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_fight_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_FIGHT","outputIds":["KDF_402_Corristo_KDFTEST_FIGHT_Info_15_01","KDF_402_Corristo_KDFTEST_FIGHT_Info_14_02","KDF_402_Corristo_KDFTEST_FIGHT_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Honor wojownika.","en":"A warrior''s honor.","de":"Die Ehre des Kämpfers."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Myślę, że ktoś taki jak ty przyda się raczej w Straży. Porozmawiaj z Thorusem!","en":"I believe the Guards would be just right for you! Speak to Thorus!","de":"Ich glaube, die Garde wäre genau das Richtige für dich! Sprich mal mit Thorus!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_gomez_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_gomez_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_GOMEZ","outputIds":["KDF_402_Corristo_KDFTEST_GOMEZ_Info_15_01","KDF_402_Corristo_KDFTEST_GOMEZ_Info_14_02","KDF_402_Corristo_KDFTEST_GOMEZ_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Gomez.","en":"Gomez.","de":"Gomez."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Myślę, że ktoś taki jak ty przyda się raczej w Straży. Porozmawiaj z Thorusem!","en":"I believe the Guards would be just right for you! Speak to Thorus!","de":"Ich glaube, die Garde wäre genau das richtige für dich! Sprich mal mit Thorus!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_Info","outputIds":["KDF_402_Corristo_KDFTEST_Info_15_01","KDF_402_Corristo_KDFTEST_Info_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów. Możesz poddać mnie próbie.","en":"I''m up for it. Just test me.","de":"Ich bin bereit. Stell mich auf die Probe."}},{"speaker":"npc","text":{"pl":"Dobrze. Służyłeś Bractwu na bagnach, czyż nie?","en":"Good. You have served the Brotherhood in the swamp, have you not?","de":"Gut. Du hast der Bruderschaft im Sumpf einen Dienst erwiesen, richtig?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_innos_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_innos_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_INNOS","outputIds":["KDF_402_Corristo_KDFTEST_INNOS_Info_15_01","KDF_402_Corristo_KDFTEST_INNOS_Info_14_02","KDF_402_Corristo_KDFTEST_INNOS_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Innos.","en":"Innos.","de":"Innos."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Jaka jest najważniejsza z cnót?","en":"Which is the highest virtue of all?","de":"Was ist die höchste Tugend?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_ja_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_ja_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_JA","outputIds":["KDF_402_Corristo_KDFTEST_JA_Info_15_01","KDF_402_Corristo_KDFTEST_JA_Info_14_02","KDF_402_Corristo_KDFTEST_JA_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Tak.","en":"Yes.","de":"Ja."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmm...","de":"Hmm..."}},{"speaker":"npc","text":{"pl":"Jak ma na imię najwyższy z bogów?","en":"What is the name of our god?","de":"Wie ist der Name unseres Gottes?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_no_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_no_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_NO","outputIds":["KDF_402_Corristo_KDFTEST_NO_Info_15_01","KDF_402_Corristo_KDFTEST_NO_Info_14_02","KDF_402_Corristo_KDFTEST_NO_Info_14_03","KDF_402_Corristo_KDFTEST_NO_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Nie.","en":"No.","de":"Nein."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Nie potrzebujemy tu ludzi, którzy wypierają się własnych czynów.","en":"We have no use for a man who denies his deeds.","de":"Einen Mann der seine Taten verleugnet, können wir nicht gebrauchen."}},{"speaker":"npc","text":{"pl":"Spróbuj szczęścia jako wojownik, albo Kopacz. Ścieżka magii będzie dla ciebie zamknięta już na zawsze.","en":"Make yourself useful as a fighter or digger. The path of magic will remain forever closed to you.","de":"Mach dich als Kämpfer oder Buddler nützlich. Der Weg der Magie wird dir immer verschlossen bleiben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_sleeper_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kdftest_sleeper_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KDFTEST_SLEEPER","outputIds":["KDF_402_Corristo_KDFTEST_SLEEPER_Info_15_01","KDF_402_Corristo_KDFTEST_SLEEPER_Info_14_02","KDF_402_Corristo_KDFTEST_SLEEPER_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Śniący.","en":"The Sleeper.","de":"Der Schläfer."}},{"speaker":"npc","text":{"pl":"Hmm...","en":"Hmmm...","de":"Hmmm..."}},{"speaker":"npc","text":{"pl":"Wygląda na to, że zbyt dużo czasu spędziłeś pośród wyznawców Śniącego. Chyba lepiej będzie, jeśli tam wrócisz.","en":"Looks like you''ve been spending too much time among the swamp brothers. Maybe you''d better stay there.","de":"Du warst wohl zu lange bei den Sumpfbrüdern. Vielleicht wärst du besser bei ihnen geblieben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis1_info_14_05_4', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis1_info_14_05_4","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS1_Info","outputIds":["KDF_402_Corristo_KREIS1_Info_14_05","KDF_402_Corristo_KREIS1_Info_14_06","KDF_402_Corristo_KREIS1_Info_14_07","KDF_402_Corristo_KREIS1_Info_14_08"],"lines":[{"speaker":"npc","text":{"pl":"W odróżnieniu od magicznych zwojów zawierających formuły zaklęć, magia zawarta w runach jest trwała.","en":"But in contrast to the magic scrolls, which are magic formulas as well, the magic power of the rune ensures that the structure of the spell endures.","de":"Doch anders als Spruchrollen, die auch eine Zauberformel sind, sorgt die magische Kraft, die der Rune innewohnt dafür, dass die Struktur des Zaubers erhalten bleibt."}},{"speaker":"npc","text":{"pl":"Runy są źródłem czarodziejskiej mocy, na którym możesz polegać w każdej sytuacji.","en":"Every rune is a source of magic power which you can fall back on anytime.","de":"Jede Rune ist eine Quelle magischer Kraft, auf die du immer wieder zurückgreifen kannst."}},{"speaker":"npc","text":{"pl":"Twoja własna magia potrzebna jest podczas korzystania z run tak samo, jak gdy korzystasz z magicznych zwojów.","en":"Your own magic power is used up when you use a rune, just as with a spell scroll.","de":"Deine eigene magische Kraft verbraucht sich beim Benutzen der Rune, wie bei einer Spruchrolle."}},{"speaker":"npc","text":{"pl":"W miarę awansowania do kolejnych Kręgów, będziesz poznawał nowe runy.","en":"With every Circle you enter, you learn to use further runes as well.","de":"Mit jedem Kreis, den du lernst, lernst du auch die Möglichkeit weitere Runen zu benutzen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis1_info_14_09_8', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis1_info_14_09_8","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS1_Info","outputIds":["KDF_402_Corristo_KREIS1_Info_14_09"],"lines":[{"speaker":"npc","text":{"pl":"Wykorzystaj drzemiącą w runach moc do poznania samego siebie.","en":"Use the power of the runes to recognize yourself.","de":"Nutze die Kraft der Runen, um dich selber zu erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis1_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis1_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS1_Info","outputIds":["KDF_402_Corristo_KREIS1_Info_15_01","KDF_402_Corristo_KREIS1_Info_14_02","KDF_402_Corristo_KREIS1_Info_14_03","KDF_402_Corristo_KREIS1_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy do przystąpienia do Pierwszego Kręgu.","en":"I am ready to enter the First Circle.","de":"Ich bin jetzt bereit, den ersten Kreis zu erlernen."}},{"speaker":"npc","text":{"pl":"Przystąpienie do Pierwszego Kręgu wiąże się z poznaniem tajników magii runicznej.","en":"To enter the first of the magic Circles means learning to use magic runes.","de":"Den ersten der magischen Kreise zu betreten, bedeutet die Anwendung magischer Runen erlernen."}},{"speaker":"npc","text":{"pl":"Każda runa zawiera esencję szczególnego zaklęcia magicznego.","en":"Each rune contains the structure of a special magic spell.","de":"Jede Rune birgt in sich die Struktur eines speziellen Zaubers."}},{"speaker":"npc","text":{"pl":"Wykorzystując swoje zdolności magiczne, będziesz w stanie ją uwolnić.","en":"By using your own magic powers, you''ll be able to cast the magic of the rune.","de":"Durch den Einsatz deiner eigenen magischen Energie, bist du in der Lage, den Zauber der Rune zu wirken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis2_info_14_05_4', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis2_info_14_05_4","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS2_Info","outputIds":["KDF_402_Corristo_KREIS2_Info_14_05","KDF_402_Corristo_KREIS2_Info_14_06","KDF_402_Corristo_KREIS2_Info_14_07","KDF_402_Corristo_KREIS2_Info_14_08"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz już, że runy mogą być wykorzystywane do chwili wyczerpania twoich własnych pokładów siły magicznej.","en":"You know that you can use every rune as often as you like until you''ve used up all of your own powers.","de":"Du weißt, dass du jede Rune solange einsetzen kannst, bis deine eigene Kraft verbraucht ist."}},{"speaker":"npc","text":{"pl":"Jednak zanim przystąpisz do działania, zastanów się nad celem, jaki ci przyświeca. Moce, którymi będziesz dysponował mogą nieść śmierć i zniszczenie.","en":"But before you act, think about the point of your actions. You have obtained powers with which you may easily conjure up death and destruction.","de":"Aber frage dich, ob es sinnvoll ist. Du hast Macht verliehen bekommen, mit der es dir ein Leichtes ist, Tod und Verderben zu bringen."}},{"speaker":"npc","text":{"pl":"Ale prawdziwy mag wykorzystuje swoje zdolności tylko wtedy, gdy jest to absolutnie niezbędne.","en":"But a true magician only uses magic when it is necessary.","de":"Doch der wahrhafte Magier zaubert nur dann, wenn es angebracht ist."}},{"speaker":"npc","text":{"pl":"Kiedy w pełni uświadomisz sobie ten fakt, zrozumiesz prawdę kryjącą się za magią runiczną.","en":"Understand the situation, then you''ll recognize the power of the runes.","de":"Erkenne die Situation, dann wirst du die Macht der Runen erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis2_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis2_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS2_Info","outputIds":["KDF_402_Corristo_KREIS2_Info_15_01","KDF_402_Corristo_KREIS2_Info_14_02","KDF_402_Corristo_KREIS2_Info_14_03","KDF_402_Corristo_KREIS2_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy do przystąpienia do Drugiego Kręgu.","en":"I am ready to enter the Second Circle.","de":"Ich möchte den zweiten Kreis erlernen."}},{"speaker":"npc","text":{"pl":"Poznałeś już magiczną naturę języka runicznego. Teraz zgłębisz jego tajniki.","en":"You have learned to understand the runes. Now is the time to deepen this understanding.","de":"Du hast das Verständnis der Runen gelernt. Nun ist es an der Zeit, dieses Verständnis zu vertiefen."}},{"speaker":"npc","text":{"pl":"Po przystąpieniu do Drugiego Kręgu poznasz silniejsze zaklęcia ofensywne oraz tajemnicę magii uzdrawiającej.","en":"When you join the Second Circle you will learn the foundations of stronger battle spells, and above all the secret of healing.","de":"Mit dem zweiten Kreis lernst du die Grundsätze stärkerer Kampfzauber und vor allem das Geheimnis der Heilung."}},{"speaker":"npc","text":{"pl":"Musisz się jeszcze wiele nauczyć, zanim dane ci będzie poznać prawdziwe oblicze magii.","en":"But you need to learn much if you want to recognize the true secrets of magic.","de":"Doch du musst noch viel lernen, willst du die tatsächlichen Geheimnisse der Magie ergründen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis3_info_14_05_4', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis3_info_14_05_4","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS3_Info","outputIds":["KDF_402_Corristo_KREIS3_Info_14_05","KDF_402_Corristo_KREIS3_Info_14_06","KDF_402_Corristo_KREIS3_Info_14_07"],"lines":[{"speaker":"npc","text":{"pl":"To, czy z niej skorzystasz, czy nie, powinno zależeć wyłącznie od ciebie.","en":"You may use a rune or not. But you must decide on one of these possibilities.","de":"Du kannst eine Rune nutzen oder nicht. Aber entscheide dich für eine der Möglichkeiten."}},{"speaker":"npc","text":{"pl":"Wybór, którego dokonasz, musi być ostateczny. W magii nie ma miejsca na wahanie.","en":"Do not hesitate to use your powers as soon as you''ve made your choice.","de":"Zögere nicht, deine Macht einzusetzen, wenn du dich einmal entscheiden hast."}},{"speaker":"npc","text":{"pl":"Wyobraź sobie wyraźnie ścieżkę, którą chcesz kroczyć i ponieś wszelkie konsekwencje swojego wyboru.","en":"Understand your path, then you''ll recognize the power of the decision.","de":"Erkenne deinen Weg, dann wirst du die Macht der Entscheidung erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis3_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis3_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS3_Info","outputIds":["KDF_402_Corristo_KREIS3_Info_15_01","KDF_402_Corristo_KREIS3_Info_14_02","KDF_402_Corristo_KREIS3_Info_14_03","KDF_402_Corristo_KREIS3_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie wprowadzić w arkana Trzeciego Kręgu?","en":"Could you teach me the Third Circle?","de":"Kannst du mich den dritten Kreis lehren?"}},{"speaker":"npc","text":{"pl":"Trzeci Krąg to jeden z najważniejszych etapów w życiu każdego maga. Przystępując do niego przestajesz być uczniem.","en":"The Third Circle of Magic is one of the most important steps in the life of a magician. Once you''ve reached it, you cease to be a seeker.","de":"Der dritte Kreis der Magie ist einer der wichtigsten Schritte im Leben eines Magiers. Nicht länger bist du ein Suchender."}},{"speaker":"npc","text":{"pl":"Zaszedłeś już bardzo daleko na ścieżce magii. Potrafisz posługiwać się runami.","en":"You have already come far on the path of magic. You have learned to use the runes.","de":"Du bist bereits ein Stück des magischen Weges gegangen. Du hast gelernt, die Runen zu nutzen."}},{"speaker":"npc","text":{"pl":"Ta wiedza posłuży za fundament twojej dalszej nauki. Używaj magii runicznej świadomie i z rozwagą.","en":"This knowledge is the foundation for your further path. Use the runes with deliberation.","de":"Dieses Wissen ist das Fundament für deinen weiteren Weg. Nutze die Runen mit Bedacht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis4_info_14_05_4', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis4_info_14_05_4","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS4_Info","outputIds":["KDF_402_Corristo_KREIS4_Info_14_05","KDF_402_Corristo_KREIS4_Info_14_06","KDF_402_Corristo_KREIS4_Info_14_07"],"lines":[{"speaker":"npc","text":{"pl":"Z twoją znajomością magii runicznej, cała wiedza zgromadzona przez wszystkie świątynie w tym królestwie stoi przed tobą otworem.","en":"With the runes you control now, you have the entire knowledge of the temples of the realm at your fingertips.","de":"Mit allen Runen, die du nun beherrschen kannst, steht dir das gesammelte Wissen der Tempel zur Verfügung."}},{"speaker":"npc","text":{"pl":"Nauczyłem cię wszystkiego, co sam potrafię.","en":"You have now learned everything I can teach you.","de":"Du hast jetzt alles gelernt, was ich dir beibringen kann."}},{"speaker":"npc","text":{"pl":"Pamiętaj: poznanie natury magii jest kluczem do poznania natury potęgi i władzy.","en":"Understand the magic, then you''ll discover the secret of power.","de":"Erkenne die Magie, dann wirst du das Geheimnis von Macht erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_kreis4_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_kreis4_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_KREIS4_Info","outputIds":["KDF_402_Corristo_KREIS4_Info_15_01","KDF_402_Corristo_KREIS4_Info_14_02","KDF_402_Corristo_KREIS4_Info_14_03","KDF_402_Corristo_KREIS4_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy do przystąpienia do Czwartego Kręgu.","en":"I am ready to enter the Fourth Circle.","de":"Ich bin bereit für den vierten der Kreise."}},{"speaker":"npc","text":{"pl":"Ukończyłeś już pierwsze trzy Kręgi. Nadeszła pora, byś zgłębił prawdziwą naturę magii.","en":"You have completed the first three Circles. Now is the time for you to learn the secrets of magic.","de":"Du hast die ersten drei Kreise durchschritten. Nun ist es an der Zeit, dass du die Geheimnisse der Magie kennenlernst."}},{"speaker":"npc","text":{"pl":"Magia runiczna jest zaklęta w kamieniu. W końcu runy to fragmenty magicznej rudy.","en":"The magic of the runes is based on the stone. They are magic stones, created out of magic ore.","de":"Die Magie der Runen ruht in ihrem Stein. Es sind magische Steine, gewonnen aus magischem Erz."}},{"speaker":"npc","text":{"pl":"Tej samej rudy, która wydobywana jest w kopalniach. Z pomocą bogów runy nasycane są magią w naszych świątyniach stając się narzędziem naszej potęgi.","en":"It''s the same ore which is collected in the mines. This ore is endowed with magic formulas in the temples. There the runes are converted to the instruments of our power.","de":"Das gleiche Erz, was hier abgebaut wird. Dieses Erz wird in den Tempeln mit den Formeln der Magie versehen. Dort werden sie zu den Instrumenten unserer Macht geformt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_mana_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_mana_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_MANA_Info","outputIds":["KDF_402_Corristo_MANA_Info_15_01","KDF_402_Corristo_MANA_Info_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję większej mocy magicznej.","en":"I need more magic power.","de":"Ich benötige mehr magische Kraft."}},{"speaker":"npc","text":{"pl":"Pokażę ci, jak zwiększyć twoje zdolności magiczne. Jak je wykorzystać, zależy już tylko od ciebie.","en":"I can help you to increase your power. What use you make of it is your affair.","de":"Ich kann dir helfen, deine Kraft zu steigern. Wie du sie nutzt, liegt nur an dir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_robe_info_14_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_robe_info_14_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_ROBE_Info","outputIds":["KDF_402_Corristo_ROBE_Info_14_01","KDF_402_Corristo_ROBE_Info_14_02"],"lines":[{"speaker":"npc","text":{"pl":"Wygłaszając słowa przysięgi zostałeś po wsze czasy związany ze świętym Ogniem.","en":"By uttering the words of the oath you have now entered into a bond with the Fire.","de":"Mit den Worten des Schwurs, bist du den Bund mit dem Feuer eingegangen."}},{"speaker":"npc","text":{"pl":"Noś tę szatę na znak tego przymierza.","en":"Wear this robe as a sign of the eternal bond.","de":"Trage diese Robe als Zeichen des ewigen Bundes."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_wannbekdf_info_14_05_4', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_wannbekdf_info_14_05_4","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_WANNBEKDF_Info","outputIds":["KDF_402_Corristo_WANNBEKDF_Info_14_05"],"lines":[{"speaker":"npc","text":{"pl":"Twój duch jest dojrzały i gotów do próby. Zanim zostaniesz magiem musisz pomyślnie przejść egzamin. Daj mi znać, kiedy będziesz gotów.","en":"Your spirit is mature and ready to join us. If you want to become a magician, I must test you first. Let me know when you''re ready for the test.","de":"Dein Geist ist reif für die Aufnahme. Wenn du Magier werden willst, dann muss ich dich zuvor prüfen. Sag mir Bescheid, wenn du dich dieser Prüfung unterziehen willst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_402_corristo_kdf_402_corristo_wannbekdf_info_15_01_0', 'KDF_402_Corristo', '{"id":"missions_dia_kdf_402_corristo_kdf_402_corristo_wannbekdf_info_15_01_0","npcId":"KDF_402_Corristo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_402_Corristo.d","sourceFunction":"KDF_402_Corristo_WANNBEKDF_Info","outputIds":["KDF_402_Corristo_WANNBEKDF_Info_15_01","KDF_402_Corristo_WANNBEKDF_Info_14_02","KDF_402_Corristo_WANNBEKDF_Info_14_04","KDF_402_Corristo_WANNBEKDF_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym przystąpić do magicznego Kręgu.","en":"I''d like to enter the magic Circle.","de":"Ich möchte in den Kreis der Magier aufgenommen werden."}},{"speaker":"npc","text":{"pl":"A więc chcesz zostać Magiem z Kręgu Ognia? Hmmm...","en":"So you want to become a Magician of the Circle of Fire? Hm...","de":"Du willst also ein Magier des Feuers werden? Hm...."}},{"speaker":"npc","text":{"pl":"Nie jesteś jeszcze gotów. Wróć do mnie, kiedy zdobędziesz więcej doświadczenia.","en":"You are not ready yet. Come back when you''ve learned more.","de":"Du bist noch nicht so weit. Komm erst wieder zu mir, wenn du mehr gelernt hast."}},{"speaker":"npc","text":{"pl":"Wielu chciało należeć do naszego Kręgu, ale przez te wszystkie lata przyjąłem tylko jednego ucznia. Wszyscy pozostali zawiedli.","en":"Many have wanted to join us, but throughout the years I have only taken one as my apprentice. All the others have failed.","de":"Schon viele wollten uns angehören und nur einen habe ich in all den Jahren zum Lehrling genommen. Alle anderen haben versagt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_403_drago_kdf_403_drago_rune_info_13_01_0', 'KDF_403_Drago', '{"id":"missions_dia_kdf_403_drago_kdf_403_drago_rune_info_13_01_0","npcId":"KDF_403_Drago","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_403_Drago.d","sourceFunction":"KDF_403_Drago_RUNE_Info","outputIds":["KDF_403_Drago_RUNE_Info_13_01"],"lines":[{"speaker":"npc","text":{"pl":"Przyjmij tę runę jako znak przychylności Innosa. Oby cię chroniła podczas marszu przez twą ścieżkę życia.","en":"Take this rune, the gift of Innos. May it protect you on your path.","de":"Nimm diese Rune als Geschenk von Innos. Sie schütze dich auf deinem Weg."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_accept_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_accept_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_ACCEPT_Info","outputIds":["Info_Xardas_ACCEPT_15_01","Info_Xardas_ACCEPT_14_02","Info_Xardas_ACCEPT_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Porozmawiam z tym szamanem!","en":"I will get the answers from this shaman!","de":"Ich werde mir die Antworten von diesem Schamanen holen!"}},{"speaker":"npc","text":{"pl":"Mój sługa dał ci już magiczną runę uaktywniającą pentagram piętro niżej.","en":"My servant has already given you a teleportation rune for the pentagram one floor below.","de":"Mein Diener hat dir ja bereits eine Teleportations-Rune für das Pentagramm einen Stock tiefer gegeben."}},{"speaker":"npc","text":{"pl":"W ten sposób będziesz mógł wrócić do mnie natychmiast po wykonaniu zadania.","en":"That will make it easier for you to get back here later.","de":"Damit sollte es kein Problem für dich sein, wieder hierher zurück zu kehren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_altrune_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_altrune_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_ALTRUNE_Info","outputIds":["Info_Xardas_ALTRUNE_15_01","Info_Xardas_ALTRUNE_14_02","Info_Xardas_ALTRUNE_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Jestem magiem. Nie wiem, czy potrafię posługiwać się mieczem takim jak URIZIEL!","en":"Since I''m a magician, it''ll be hard for me to wield URIZIEL!","de":"Als Magier werde ich mich schwer tun, URIZIEL wirksam zu führen!"}},{"speaker":"npc","text":{"pl":"Jest na to sposób...","en":"There is a solution...","de":"Es gibt da einen Weg ..."}},{"speaker":"npc","text":{"pl":"Ale najpierw naładuj miecz magiczną energią. Wróć jak najszybciej!","en":"But first you have to restore the blade''s former powers! Then come back!","de":"Aber zuerst musst du der Klinge ihre alten Kräfte wiedergeben! Kehre dann zurück!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_barrier_14_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_barrier_14_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_BARRIER_Info","outputIds":["Info_Xardas_BARRIER_14_05","Info_Xardas_BARRIER_15_06","Info_Xardas_BARRIER_14_07"],"lines":[{"speaker":"npc","text":{"pl":"Wiele stuleci temu, pięciu orkowych szamanów przywołało do tego świata potężnego demona, który miał im pomóc zdominować pozostałe klany.","en":"A few centuries ago, five Orc shamen invoked a very old arch demon which they hoped would give their clan the power to defeat their enemies.","de":"Vor vielen hundert Jahren beschwörten fünf Ork-Schamanen einen uralten Erzdämonen, um ihrem Klan die Macht zu verleihen, ihre Feinde zu vernichten."}},{"speaker":"hero","text":{"pl":"Ten demon... To Śniący, prawda?","en":"This arch demon, was it the Sleeper?","de":"War dieser Erzdämon der Schläfer?"}},{"speaker":"npc","text":{"pl":"Orkowie nadali mu to imię dużo później. Ale nie powiem ci dlaczego wybrali tę nazwę, ani dlaczego tak bardzo się go teraz boją!","en":"The Orcs gave him that name much later. But I won''t tell you why they did it, or why they are now terrified by this supernatural creature!","de":"Diesen Namen gaben ihm die Orks erst viel später. Doch warum sie das taten und warum sie heute vor diesem Überwesen in Furcht erzittern, werde ich dir nicht erzählen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_barrier_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_barrier_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_BARRIER_Info","outputIds":["Info_Xardas_BARRIER_15_01","Info_Xardas_BARRIER_14_02","Info_Xardas_BARRIER_15_03","Info_Xardas_BARRIER_14_04"],"lines":[{"speaker":"hero","text":{"pl":"A ty wiesz, co się stało, tak?","en":"Did you find out why that happened?","de":"Hast du es herausgefunden?"}},{"speaker":"npc","text":{"pl":"Cóż, jedno jest pewne: odpowiedź spoczywa ukryta głęboko pod miastem Orków.","en":"Well, one thing is certain: The answer lies deep beneath the Orc town.","de":"Eins ist auf jeden Fall klar! Die Antwort liegt tief unter der Stadt der Orks."}},{"speaker":"hero","text":{"pl":"Miastem Orków?","en":"The Orc town?","de":"Die Stadt der Orks?"}},{"speaker":"npc","text":{"pl":"Orkowie to nie zwierzęta, choć wielu ludzi tak właśnie myśli. Ich kultura dorównuje wiekiem naszej.","en":"Orcs are not animals, as many people think. Their culture is as old as the human culture.","de":"Die Orks sind nicht etwa, wie viele glauben, Tiere. Ihre Kultur reicht fast ebenso weit zurück, wie die der Menschen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_danger_14_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_danger_14_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_DANGER_Info","outputIds":["Info_Xardas_DANGER_14_05"],"lines":[{"speaker":"npc","text":{"pl":"Żaden z dwunastu magów nie zadał sobie trudu, by zbadać z jakich przyczyn Bariera wymknęła się spod kontroli, ani dlaczego przybrała tak ogromne rozmiary.","en":"None of the twelve magicians ever stopped to wonder why the formation of the Barrier got beyond their control, or why it assumed such gigantic proportions.","de":"Keiner der zwölf Magier von damals scheint sich je gefragt zu haben, warum die Erschaffung der Barriere außer Kontrolle geriet und sie diese riesigen Ausmaße annahm."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_danger_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_danger_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_DANGER_Info","outputIds":["Info_Xardas_DANGER_15_01","Info_Xardas_DANGER_14_02","Info_Xardas_DANGER_14_03","Info_Xardas_DANGER_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Jeśli detonacja kopca rudy nie wystarczy, by zażegnać niebezpieczeństwo...","en":"If the explosion of the ore mound doesn''t avert the great danger...","de":"Wenn die Sprengung des Erzhaufens die große Gefahr nicht beseitigt ..."}},{"speaker":"npc","text":{"pl":"...Zapomnij o tym całym kopcu! Jego potęga nie wystarczy, by przełamać Barierę.","en":"... Forget the ore mound! Its power won''t open the Barrier.","de":"... Vergiss den großen Erzhaufen! Seine Energie wird die Barriere nicht sprengen können."}},{"speaker":"npc","text":{"pl":"Gdyby Corristo i Saturas nie tracili cennego czasu na te swoje dziecinne spory, wiedzieliby teraz co należy zrobić.","en":"If Corristo and Saturas hadn''t wasted their time fighting over foolish and vain issues throughout the past years, they''d all know what I know now.","de":"Hätten Corristo und Saturas in den letzten Jahren weniger Zeit für ihre törichten und eitlen Streitereien verschwendet, dann wüssten sie jetzt vielleicht auch das, was ich weiß."}},{"speaker":"hero","text":{"pl":"A co twoim zdaniem należy zrobić?","en":"Which is?","de":"Was denn?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_disturb_14_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_disturb_14_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_DISTURB_Info","outputIds":["Info_Xardas_DISTURB_14_01","Info_Xardas_DISTURB_15_02","Info_Xardas_DISTURB_14_03","Info_Xardas_DISTURB_14_04"],"lines":[{"speaker":"npc","text":{"pl":"KTO ŚMIE PRZESZKADZAĆ MI W MOICH STUDIACH?","en":"WHO DARES TO DISTURB ME IN MY STUDIES?","de":"WER WAGT ES, MEINE STUDIEN ZU UNTERBRECHEN?"}},{"speaker":"hero","text":{"pl":"Nazywam się...","en":"My name is...","de":"Mein Name ist ..."}},{"speaker":"npc","text":{"pl":"Nie interesuje mnie twoje imię. To nieistotne.","en":"I don''t wish to know your name. It is insignificant.","de":"Ich will deinen Namen nicht wissen. Er ist unwichtig."}},{"speaker":"npc","text":{"pl":"Liczy się tylko to, że jesteś pierwszą osobą od wielu lat, której udało się rozwiązać zagadkę Golemów.","en":"All that matters is that you are the first person in years to have solved my Golem''s riddles.","de":"Wichtig ist nur, dass du der Erste seit vielen Jahren bist, der meine Golemrätsel gelöst hat."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_event_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_event_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_EVENT_Info","outputIds":["Info_Xardas_EVENT_15_01","Info_Xardas_EVENT_14_02","Info_Xardas_EVENT_15_03","Info_Xardas_EVENT_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego nie?","en":"Why not?","de":"Warum nicht?"}},{"speaker":"npc","text":{"pl":"Myślę, że możesz być... NIE, aby mnie przekonać, musisz wykonać jeszcze jedno zadanie!","en":"I believe you could be... NO, to be really sure, you''ll have to perform another task!","de":"Ich glaube du könntest der ... NEIN, um mir ganz sicher zu sein, musst du noch eine weitere Aufgabe lösen!"}},{"speaker":"hero","text":{"pl":"Jakie zadanie?","en":"Which task?","de":"Was für eine Aufgabe?"}},{"speaker":"npc","text":{"pl":"Słuchaj uważnie: Orkowie wygnali z miasta jednego ze swoich szamanów.","en":"Listen carefully: The Orcs have exiled one of their shamen from the town.","de":"Hör gut zu: Die Orks haben einen ihrer Schamanen aus ihrer Stadt verbannt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_eventhow_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_eventhow_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_EVENTHOW_Info","outputIds":["Info_Xardas_EVENTHOW_15_01","Info_Xardas_EVENTHOW_14_02","Info_Xardas_EVENTHOW_15_03","Info_Xardas_EVENTHOW_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Co ten szaman ma wspólnego z moim zadaniem?","en":"What does this Orc shaman have to do with my task?","de":"Was hat dieser Ork-Schamane mit meiner Aufgabe zu tun?"}},{"speaker":"npc","text":{"pl":"On opowie ci resztę historii związanej ze Śniącym.","en":"He''ll tell you the rest of the story about the Sleeper.","de":"Er wird dir den fehlenden Teil der Geschichte über den Schläfer erzählen."}},{"speaker":"hero","text":{"pl":"Obawiam się, że Ork nie będzie zbyt chętny do zwierzeń w mojej obecności!","en":"An Orc shaman is hardly likely to be keen on talking to me!","de":"Ein Ork-Schamane wird sich wohl kaum mit mir unterhalten!"}},{"speaker":"npc","text":{"pl":"Chcesz żebym ci pomógł, czy nie?","en":"Do you want me to help you or do you not?","de":"Willst du nun meine Hilfe oder willst du sie nicht?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_eventhow_15_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_eventhow_15_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_EVENTHOW_Info","outputIds":["Info_Xardas_EVENTHOW_15_05","Info_Xardas_EVENTHOW_14_06","Info_Xardas_EVENTHOW_14_07","Info_Xardas_EVENTHOW_15_08"],"lines":[{"speaker":"hero","text":{"pl":"Tak, ale...","en":"Well, yes, but...","de":"Doch schon, aber ..."}},{"speaker":"npc","text":{"pl":"Więc nigdy więcej nie kwestionuj tego, co mówię!","en":"Then never question my words again!","de":"Dann stelle meine Worte nie wieder in Frage!"}},{"speaker":"npc","text":{"pl":"Znajdź tego szamana. Nie pała miłością do swych braci z miasta Orków, więc może zgodzi się ciebie wysłuchać zanim zamieni cię w żywą pochodnię!","en":"Find the shaman. He''s not on good terms with his brothers in the Orc town, so he may listen to you before turning you into a living torch!","de":"Suche den Schamanen. Er ist nicht gut auf seine Brüder in der Orkstadt zu sprechen, also wird er dir vielleicht zuhören, bevor er dich zu einer lebenden Fackel macht!"}},{"speaker":"hero","text":{"pl":"Bardzo pocieszające!","en":"Very comforting!","de":"Sehr beruhigend!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_eventwhere_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_eventwhere_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_EVENTWHERE_Info","outputIds":["Info_Xardas_EVENTWHERE_15_01","Info_Xardas_EVENTWHERE_14_02","Info_Xardas_EVENTWHERE_15_03","Info_Xardas_EVENTWHERE_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę tego wygnanego szamana?","en":"Where is this exiled shaman?","de":"Wo hält sich dieser Verbannte auf?"}},{"speaker":"npc","text":{"pl":"Idź do starej cytadeli na wschodzie. Na pewno trafisz - znajduje się na szczycie wysokiej góry. Widać ją już z daleka.","en":"Go the old citadel in the east. You can''t miss it, it''s on top of a high mountain which can be seen from a distance.","de":"Gehe zum alten Kastell östlich von hier. Es ist nicht zu übersehen, denn es steht auf dem Gipfel eines hohen Berges, der schon von weitem zu sehen ist."}},{"speaker":"hero","text":{"pl":"I mogę tak po prostu do niej wejść?","en":"Can you just enter it?","de":"Kann man es so einfach betreten?"}},{"speaker":"npc","text":{"pl":"Mówią na nią stara cytadela, choć tak naprawdę to tylko sterta kamieni. Od wielu dziesięcioleci nikt tam nie zagląda.","en":"They call it the old citadel but there''s hardly anything left of it other than the foundation walls. It''s been a ruin for many decades.","de":"Es wird zwar noch Altes Kastell genannt, aber genau genommen stehen da nur noch die Grundmauern. Es ist schon seit vielen Jahrzehnten eine Ruine."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_eventwhy_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_eventwhy_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_EVENTWHY_Info","outputIds":["Info_Xardas_EVENTWHY_15_01","Info_Xardas_EVENTWHY_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego?","en":"Why have they exiled him?","de":"Warum haben sie ihn verbannt?"}},{"speaker":"npc","text":{"pl":"Umierający Ork, którego kazałem przesłuchać moim demonom, nie był w stanie odpowiedzieć mi na to pytanie.","en":"The dying Orc warrior was no longer able to answer that question when he was interrogated by one of my demons.","de":"Das konnte der sterbende Ork-Krieger, der von einem meiner Dämonen befragt wurde, nicht mehr von sich geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_formula_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_formula_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_FORMULA_Info","outputIds":["Info_Xardas_FORMULA_15_01","Info_Xardas_FORMULA_14_02","Info_Xardas_FORMULA_15_03","Info_Xardas_FORMULA_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Przygotowałeś już formułę, która przywróci URIZIELOWI jego dawną moc?","en":"Have you completed the magic formula to reactivate URIZIEL?","de":"Hast du die magische Formel für das Aufladen von URIZIEL fertig gestellt?"}},{"speaker":"npc","text":{"pl":"Tak, wszystko gotowe. Ale sam nie dasz rady jej użyć.","en":"It''s done. But you won''t be able to use it by yourself.","de":"Sie ist vollendet. Aber du wirst sie nicht alleine benutzen können."}},{"speaker":"hero","text":{"pl":"Dlaczego nie?","en":"Why not?","de":"Warum nicht?"}},{"speaker":"npc","text":{"pl":"Będziesz musiał dotknąć mieczem źródła mocy magicznej. Dokładnie w tej samej chwili jakiś mag musi wypowiedzieć formułę.","en":"It has to be spoken by a magician while you touch the power source with the sword.","de":"Sie muss von einem Magier gesprochen werden, während du das Schwert mit der Kraftquelle in Berührung bringst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_formula_15_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_formula_15_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_FORMULA_Info","outputIds":["Info_Xardas_FORMULA_15_05","Info_Xardas_FORMULA_14_06"],"lines":[{"speaker":"hero","text":{"pl":"Zatem muszę sobie poszukać kogoś do pomocy!","en":"Then I''ll have to look around for some support!","de":"Dann werde ich mich nach Unterstützung umschauen müssen!"}},{"speaker":"npc","text":{"pl":"Weź formułę i przywróć URIZIEL do jego dawnej świetności. Będzie ci wkrótce potrzebny!","en":"Take the formula and restore the sword''s former power. You''ll need it!","de":"Nimm die Formel an dich und gib der Waffe ihre alte Macht zurück. Du wirst sie brauchen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_foundtemple_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_foundtemple_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_FOUNDTEMPLE_Info","outputIds":["Info_Xardas_FOUNDTEMPLE_15_01","Info_Xardas_FOUNDTEMPLE_14_02","Info_Xardas_FOUNDTEMPLE_14_03","Info_Xardas_FOUNDTEMPLE_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem drogę do podziemnej świątyni!","en":"I have found a way into the underground temple!","de":"Ich habe einen Weg in den unterirdischen Tempel gefunden!"}},{"speaker":"npc","text":{"pl":"ZNALAZŁEŚ... To niesamowite!","en":"YOU HAVE... That''s remarkable!","de":"DU HAST ... DU ... Bemerkenswert!"}},{"speaker":"npc","text":{"pl":"Stałeś się niezwykle potężny! Potężniejszy niż ktokolwiek wewnątrz Bariery.","en":"You have become very powerful! Stronger than anybody else inside the Barrier.","de":"Du bist sehr stark geworden! Stärker als jeder andere innerhalb der Barriere."}},{"speaker":"npc","text":{"pl":"Może rzeczywiście jesteś człowiekiem, o którym wspomina proroctwo Orków!","en":"Maybe you really are the man the Orcish prophecies told of!","de":"Vielleicht bist du doch derjenige, von dem die alten orkischen Prophezeiungen sprechen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_kdw_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_kdw_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_KDW_Info","outputIds":["Info_Xardas_KDW_15_01","Info_Xardas_KDW_15_02","Info_Xardas_KDW_14_03","Info_Xardas_KDW_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Wszyscy Magowie Ognia zginęli!","en":"All the Magicians of Fire are dead!","de":"Die Feuermagier sind alle tot!"}},{"speaker":"hero","text":{"pl":"Gomez kazał ich zamordować.","en":"Gomez had them assassinated.","de":"Gomez hat sie ermorden lassen."}},{"speaker":"npc","text":{"pl":"Nie powiem, żebym był szczególnie zaskoczony. Tym durnym barbarzyńcom z zamku - z Gomezem na czele - nigdy nie można było ufać.","en":"That does not surprise me. Those foolish barbarian butchers in the castle, especially Gomez, were never to be trusted.","de":"Das wundert mich nicht sonderlich. Diesen dummen barbarischen Schlächtern in der Burg, allen voran Gomez, war noch nie zu trauen."}},{"speaker":"npc","text":{"pl":"Pomagając Gomezowi w objęciu władzy, Corristo i inni sami kopali sobie grób.","en":"Corristo and the other magicians elected their own hangman when they helped Gomez to usurp the power.","de":"Corristo und die anderen Magier haben sich ihren Henker selbst gewählt, als sie Gomez damals halfen, die Macht an sich zu reißen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_loadsword_14_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_loadsword_14_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_LOADSWORD_Info","outputIds":["Info_Xardas_LOADSWORD_14_05","Info_Xardas_LOADSWORD_14_06"],"lines":[{"speaker":"npc","text":{"pl":"Nie wiem z jakiego materiału go wykuto, ani nawet KTO go wykuł.","en":"The weapon was forged from an unknown material. And there''s nothing written about who created it!","de":"Die Waffe ist aus einem völlig unbekannten Material geschmiedet. Auch über den Erschaffer steht nichts geschrieben!"}},{"speaker":"npc","text":{"pl":"Według legendy, miecz ma posiadać niezwykłe moce, ale nie wyczuwam wokół niego magicznej aury!","en":"This blade was said to possess unbelievable powers, but I don''t notice any magical aura!","de":"Angeblich soll diese Klinge unglaubliche Kräfte besessen haben, aber ich kann keinerlei magische Aura feststellen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_loadsword_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_loadsword_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_LOADSWORD_Info","outputIds":["Info_Xardas_LOADSWORD_15_01","Info_Xardas_LOADSWORD_14_02","Info_Xardas_LOADSWORD_14_03","Info_Xardas_LOADSWORD_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem dziwny miecz.","en":"I''ve found this strange sword.","de":"Ich habe dieses seltsame Schwert hier gefunden."}},{"speaker":"npc","text":{"pl":"Pokaż mi go.","en":"Show it to me.","de":"Zeig mal her."}},{"speaker":"npc","text":{"pl":"Hmm... To ciekawe. Wyryto na nim słowo \"URIZIEL\".","en":"That''s interesting... It has ''URIZIEL'' written on it.","de":"Interessant ... hier steht ''URIZIEL''."}},{"speaker":"npc","text":{"pl":"Słyszałem o tym mieczu. To oręż z dawnych lat, kiedy rasa ludzka była jeszcze bardzo młoda.","en":"I''ve heard of this sword. It''s a weapon from the olden days, when the human race was still young.","de":"Ich habe schon von diesem Schwert gehört, es ist eine Waffe aus alten Tagen, als die Menschheit noch jung war."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_loadsword01_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_loadsword01_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_LOADSWORD01_Info","outputIds":["Info_Xardas_LOADSWORD01_15_01","Info_Xardas_LOADSWORD01_14_02","Info_Xardas_LOADSWORD01_15_03","Info_Xardas_LOADSWORD01_14_04"],"lines":[{"speaker":"hero","text":{"pl":"URIZIEL posiadał niezwykłe moce?","en":"URIZIEL possessed unbelievable powers?","de":"URIZIEL besaß unglaubliche Kräfte?"}},{"speaker":"npc","text":{"pl":"Napisano, że posiadacz tej broni był w stanie przebić najgrubszy pancerz i przezwyciężyć najsilniejsze zaklęcia.","en":"It was written that the owner of the weapon was able to pierce the strongest armor and to overcome even the most powerful of protection spells.","de":"Es steht geschrieben, dass der Träger dieser Waffe die stärksten Panzerungen durchbohren und die mächtigsten Schutzzauber überwinden kann."}},{"speaker":"hero","text":{"pl":"W jaki sposób tak potężny oręż trafił w ręce Orków?","en":"How could the Orcs get this powerful weapon into their hands?","de":"Wie konnte diese mächtige Waffe in den Besitz der Orks gelangen?"}},{"speaker":"npc","text":{"pl":"Ponoć Orkowie odebrali go potężnemu rycerzowi. Nie wiedzieli jak go wykorzystać, więc postanowili go ukryć!","en":"It''s claimed that the Orcs took it from a powerful warlord. They didn''t know how to use it, but they did hide it!","de":"Es heißt, dass die Orks dieses Schwert damals einem mächtigen Feldherren der Menschen geraubt hatten. Sie konnten es zwar nicht benutzen, aber sie konnten es gut verstecken!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_loadsword02_14_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_loadsword02_14_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_LOADSWORD02_Info","outputIds":["Info_Xardas_LOADSWORD02_14_05","Info_Xardas_LOADSWORD02_14_06"],"lines":[{"speaker":"npc","text":{"pl":"Oprócz tego potrzebna będzie specjalna magiczna formuła, która przekaże całą wyzwoloną energię na miecz.","en":"Besides, you''ll need a very special magic formula in order to transfer the power.","de":"Außerdem wirst du eine sehr spezielle Zauberformel benötigen, die den Energietransfer vollbringen kann."}},{"speaker":"npc","text":{"pl":"Daj mi trochę czasu na przygotowanie formuły!","en":"Give me some time and I''ll create the magic formula.","de":"Gib mir ein wenig Zeit und ich kann dir die magische Formel herstellen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_loadsword02_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_loadsword02_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_LOADSWORD02_Info","outputIds":["Info_Xardas_LOADSWORD02_15_01","Info_Xardas_LOADSWORD02_14_02","Info_Xardas_LOADSWORD02_15_03","Info_Xardas_LOADSWORD02_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Czy jest jakiś sposób na przywrócenie tej broni dawnej świetności?","en":"Is it possible to restore the former powers of the weapon?","de":"Kann man die damaligen Kräfte der Waffe wiederherstellen?"}},{"speaker":"npc","text":{"pl":"Nie obejdzie się bez odpowiednio silnego źródła magii.","en":"You''d need a very strong magical source of power for that purpose.","de":"Dafür würdest du eine sehr starke magische Energiequelle benötigen."}},{"speaker":"hero","text":{"pl":"Masz na myśli źródło wystarczająco potężne, by wysadzić w powietrze Magiczną Barierę?","en":"You mean strong enough to detonate the Magic Barrier with?","de":"In etwa SO stark, dass man die magische Barriere damit sprengen könnte?"}},{"speaker":"npc","text":{"pl":"Coś w tym rodzaju...","en":"About that strong...","de":"In etwa ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_loadsword09_14_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_loadsword09_14_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_LOADSWORD09_Info","outputIds":["Info_Xardas_LOADSWORD09_14_05","Info_Xardas_LOADSWORD09_14_06","Info_Xardas_LOADSWORD09_14_07"],"lines":[{"speaker":"npc","text":{"pl":"Szósty Krąg pozwala ci wykorzystywać magię dowolnej runy.","en":"The Sixth Circle enables you to use the magic of any rune.","de":"Mit dem sechsten Kreis bist du in der Lage, die Magie sämtlicher Runen anzuwenden."}},{"speaker":"npc","text":{"pl":"I nie zapomnij: twoim zadaniem jest służyć potędze magii, a nie ją wykorzystywać.","en":"And don''t forget: Do not claim the power, but serve it.","de":"Und vergiss nie: Fordere nicht die Macht, sondern diene ihr."}},{"speaker":"npc","text":{"pl":"Jeszcze nie. Jesteś zdolny, ale brak ci niezbędnego doświadczenia. Niech Saturas popracuje nad tobą przez jakiś czas. Wtedy zobaczymy.","en":"Not yet. You have the skill, but you''re not experienced enough. Let Saturas train you first, I shall instruct you afterwards.","de":"Noch nicht, du hast das Talent, aber es fehlt dir an Erfahrung. Lerne erst bei Saturas, dann werde ich dich unterweisen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_loadsword09_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_loadsword09_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_LOADSWORD09_Info","outputIds":["Info_Xardas_LOADSWORD09_15_01","Info_Xardas_LOADSWORD09_14_02","Info_Xardas_LOADSWORD09_14_03","Info_Xardas_LOADSWORD09_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie czegoś nauczyć?","en":"Can you teach me?","de":"Kannst du mich unterrichten?"}},{"speaker":"npc","text":{"pl":"Wprowadzę cię w Szósty Krąg Magii.","en":"I shall raise you into the Sixth Circle of Magic.","de":"Ich werde dich in den sechsten der magischen Kreise aufnehmen."}},{"speaker":"npc","text":{"pl":"Pamiętaj, że to przywilej zarezerwowany wyłącznie dla najbieglejszych magów. Mogą do niego przystąpić ci, których całe życie jest znakiem.","en":"Notice that only the most powerful magicians may join the Sixth Circle. It''s reserved to those whose life is a sign.","de":"Denn wisse, nur die mächtigsten Magier werden in den sechsten Kreis aufgenommen. Er ist denen vorbehalten, deren Leben ein Zeichen ist."}},{"speaker":"npc","text":{"pl":"Twoim znakiem jest zjednoczenie elementów.","en":"Your sign is the unification of the elements.","de":"Dein Zeichen ist die Verbindung der Elemente."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_makerune_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_makerune_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_MAKERUNE_Info","outputIds":["Info_Xardas_MAKERUNE_15_01","Info_Xardas_MAKERUNE_14_02","Info_Xardas_MAKERUNE_14_03","Info_Xardas_MAKERUNE_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Powiedziałeś, że będę mógł posługiwać się tym mieczem mimo, iż jestem magiem?","en":"You said there might be a way for me to wield URIZIEL though I''m a magician?","de":"Du erwähntest einen Weg, wie ich URIZIEL auch als Magier wirksam führen könnte!"}},{"speaker":"npc","text":{"pl":"Przyjrzyj się mu uważnie. Zauważyłeś zapewne ten duży, błękitny klejnot zatopiony w ostrzu.","en":"Look closely at URIZIEL. You''ll notice the big blue jewel in the blade.","de":"Wenn du URIZIEL genau betrachtest, wird dir der große, blau schimmernde Edelstein in der Klinge sofort auffallen."}},{"speaker":"npc","text":{"pl":"Cała energia magiczna miecza skumulowana jest właśnie tutaj.","en":"It contains the magical powers of the blade.","de":"Er ist das Gefäß für die magischen Kräfte der Klinge."}},{"speaker":"npc","text":{"pl":"Jeśli usunę klejnot, będę mógł stworzyć magiczną runę posiadającą wszystkie te cechy, które czynią URIZIEL tak szczególnym orężem.","en":"If I remove the jewel, I''ll be able to create a magic rune which contains the attributes of URIZIEL itself.","de":"Wenn ich den Stein entferne, kann ich daraus eine Zauberrune herstellen, welche die Eigenschaften von URIZIEL selbst in sich trägt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_makerune_15_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_makerune_15_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_MAKERUNE_Info","outputIds":["Info_Xardas_MAKERUNE_15_05","Info_Xardas_MAKERUNE_14_06","Info_Xardas_MAKERUNE_14_07"],"lines":[{"speaker":"hero","text":{"pl":"Magiczna runa stworzona z URIZIEL?","en":"A magic rune made from URIZIEL?","de":"Eine Zauberrune aus URIZIEL?"}},{"speaker":"npc","text":{"pl":"W bitwie ta runa będzie równie niebezpieczna co sam miecz!","en":"In battle, the rune will be as powerful as the sword!","de":"Mit der Kraft der Rune wirst du deine Feinde ebenso besiegen wie mit der Kraft des Schwertes!"}},{"speaker":"npc","text":{"pl":"Ale nie zapominaj, że jedynie mag Szóstego Kręgu może zapanować nad tak potężną magią!","en":"But don''t forget that only a Magician of the Sixth Circle will be able to control such a powerful magic rune!","de":"Aber sei gewahr, dass nur ein Meister des sechsten Kreises der Magie eine solche machtvolle Zauberrune beherrschen kann!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_makerunedoit_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_makerunedoit_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_MAKERUNEDOIT_Info","outputIds":["Info_Xardas_MAKERUNEDOIT_15_01","Info_Xardas_MAKERUNEDOIT_14_02","Info_Xardas_MAKERUNEDOIT_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Chcę, żebyś usunął klejnot z URIZIEL!","en":"Remove the jewel from URIZIEL!","de":"Entferne den Stein aus URIZIEL!"}},{"speaker":"npc","text":{"pl":"Ale nie opanowałeś jeszcze magii Szóstego Kręgu!","en":"But you have not yet mastered the Sixth Circle of Magic!","de":"Du beherrscht noch nicht den sechsten Kreis der Magie!"}},{"speaker":"npc","text":{"pl":"Od tej decyzji nie ma odwrotu. Jesteś pewien, że chcesz abym usunął klejnot?","en":"This decision is final. Do you really want me to remove the jewel?","de":"Dieser Schritt ist endgültig. Soll ich den Stein wirklich aus der Klinge entfernen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_makerunedoit_15_04_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_makerunedoit_15_04_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_MAKERUNE_YES","outputIds":["Info_Xardas_MAKERUNEDOIT_15_04","Info_Xardas_MAKERUNEDOIT_14_05"],"lines":[{"speaker":"hero","text":{"pl":"TAK, zrób to.","en":"YES, do it!","de":"JA, tu es!"}},{"speaker":"npc","text":{"pl":"Jeśli tego właśnie chcesz... Proszę, oto miecz i runa!","en":"Since it''s what you want... Here, take the empty sword and the rune!","de":"Du hast es so gewollt. Hier, nimm das leere Schwert und die Rune!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_makerunedoit_15_06_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_makerunedoit_15_06_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_MAKERUNE_NO","outputIds":["Info_Xardas_MAKERUNEDOIT_15_06","Info_Xardas_MAKERUNEDOIT_14_07"],"lines":[{"speaker":"hero","text":{"pl":"Nie, nie chcę.","en":"NO, don''t do it!","de":"NEIN, lieber doch nicht!"}},{"speaker":"npc","text":{"pl":"Jak sobie życzysz. Ostrze zachowa swą magiczną moc!","en":"As you wish. The blade shall keep its magic powers!","de":"So sei es. Die Klinge behält ihre magischen Kräfte!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_others_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_others_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_OTHERS_Info","outputIds":["Info_Xardas_OTHERS_15_01","Info_Xardas_OTHERS_14_02","Info_Xardas_OTHERS_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Czy ktoś jeszcze tu zaglądał?","en":"Have there been any other visitors?","de":"Gab es andere Besucher?"}},{"speaker":"npc","text":{"pl":"Bardzo rzadko. Zwykle szybko zaczynali mnie irytować i nasyłałem na nich którąś z moich magicznych istot.","en":"Not many, and when they began to annoy me I confronted them with one of my supernatural creatures.","de":"Nicht viele und als sie mir lästig wurden, machten sie Bekanntschaft mit einem meiner höheren Wesen."}},{"speaker":"hero","text":{"pl":"Wolisz wieść żywot samotnika, czyż nie?","en":"You enjoy being on your own, don''t you?","de":"Du bist wohl gerne ungestört, was?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_prophecy_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_prophecy_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_PROPHECY_Info","outputIds":["Info_Xardas_PROPHECY_15_01","Info_Xardas_PROPHECY_14_02","Info_Xardas_PROPHECY_15_03","Info_Xardas_PROPHECY_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Proroctwo? Jakie proroctwo?","en":"Prophecies? What prophecies?","de":"Prophezeiungen? Welche Prophezeiungen?"}},{"speaker":"npc","text":{"pl":"Prastare manuskrypty Orków, spisane tuż po zamknięciu świątyni, wspominają o \"Świętym Nieprzyjacielu\".","en":"Ancient Orcish documents written shortly after the sealing of the underground temple mention a ''Holy Foe''.","de":"Uralte orkische Schriften aus der Zeit kurz nach der Versiegelung des unterirdischen Tempels sprechen von einem ''Heiligen Feind''."}},{"speaker":"hero","text":{"pl":"Świętym Nieprzyjacielu?","en":"A holy foe?","de":"Ein Heiliger Feind?"}},{"speaker":"npc","text":{"pl":"Kogoś, kto raz na zawsze wypędzi Śniącego z naszego świata!","en":"Someone who shall come to drive the SLEEPER from our world forever!","de":"Einer, der kommen wird, um den SCHLÄFER für immer aus unserer Welt zu verbannen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_prophecy_15_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_prophecy_15_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_PROPHECY_Info","outputIds":["Info_Xardas_PROPHECY_15_05","Info_Xardas_PROPHECY_14_06"],"lines":[{"speaker":"hero","text":{"pl":"I to ja mam być tą osobą z przepowiedni?! Mylisz się! Na pewno się mylisz!","en":"I''m supposed to be the one mentioned in the ancient prophecies??? You must be wrong, surely!","de":"Ich soll der Gegenstand einer uralten Prophezeiung sein??? Du musst dich irren!"}},{"speaker":"npc","text":{"pl":"Może tak... Może nie!","en":"Maybe... Maybe not!","de":"Vielleicht ... aber vielleicht auch nicht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_return_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_return_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_RETURN_Info","outputIds":["Info_Xardas_RETURN_15_01","Info_Xardas_RETURN_14_02","Info_Xardas_RETURN_15_03","Info_Xardas_RETURN_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Rozmawiałem z szamanem Orków.","en":"I have the answers from the Orc shaman!","de":"Ich habe mir die Antworten vom Ork-Schamanen geholt!"}},{"speaker":"npc","text":{"pl":"Świetnie! Czego się dowiedziałeś?","en":"Well, then report!","de":"Gut, dann berichte!"}},{"speaker":"hero","text":{"pl":"Pięciu szamanów, którzy przywołali Śniącego, wybudowało dla niego podziemną świątynię. Wejście do niej znajduje się w mieście Orków.","en":"The five Orc shamans that invoked the Sleeper built him an underground temple, its entrance is in the Orc town.","de":"Die fünf Ork-Schamanen, die den Schläfer riefen, erbauten ihm einen unterirdischen Tempel, dessen Zugang in der Ork-Stadt liegt."}},{"speaker":"npc","text":{"pl":"Zgadza się!","en":"That''s right!","de":"Das ist richtig!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_return_15_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_return_15_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_RETURN_Info","outputIds":["Info_Xardas_RETURN_15_05","Info_Xardas_RETURN_14_06","Info_Xardas_RETURN_15_07","Info_Xardas_RETURN_14_08"],"lines":[{"speaker":"hero","text":{"pl":"Miast okazać wdzięczność, Śniący wyrwał ich serca i skazał ich, oraz wszystkich, którzy pracowali przy budowie na wieczne potępienie, zamieniając ich w Ożywieńców!","en":"Ungrateful as he was, he tore out their hearts and condemned them and the workers to an eternal existence as undead creatures!","de":"Undankbarerweise entriss er ihnen ihre Herzen und verfluchte sie und die Arbeiter zu ewigem Untoten-Dasein!"}},{"speaker":"npc","text":{"pl":"Doskonale, doskonale!","en":"Very good, very good!","de":"Sehr gut, sehr gut!"}},{"speaker":"hero","text":{"pl":"Orkowie zapieczętowali wejście do świątyni i próbowali przebłagać demona składając mu ofiary!","en":"The Orcs locked the temple and started making sacrifices to appease the demon!","de":"Die Orks verschlossen den Tempel und bringen ihm seitdem Opfer, um ihn zu besänftigen!"}},{"speaker":"npc","text":{"pl":"Znalazłeś sposób na dostanie się do świątyni?","en":"Have you found a way to enter the temple?","de":"Hast du einen Weg gefunden, wie du in den Tempel gelangst?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_return_15_09_8', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_return_15_09_8","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_RETURN_Info","outputIds":["Info_Xardas_RETURN_15_09","Info_Xardas_RETURN_14_10","Info_Xardas_RETURN_15_11","Info_Xardas_RETURN_14_12"],"lines":[{"speaker":"hero","text":{"pl":"Tak, jest pewien Ork, który...","en":"Yes, there''s an Orc who...","de":"Ja, es gibt da einen Ork, der ..."}},{"speaker":"npc","text":{"pl":"Żadnych szczegółów! Udaj się do podziemnej świątyni. Tam znajdziesz jedyny sposób na zniszczenie Bariery!","en":"No details! Go to the underground temple! There you''ll find the only way to destroy the Barrier!","de":"Keine Einzelheiten! Begib dich zum unterirdischen Tempel! Dort wirst du den einzigen Weg finden, die Barriere zu zerstören!"}},{"speaker":"hero","text":{"pl":"Nic nie rozumiem!","en":"I don''t understand!","de":"Ich verstehe nicht!"}},{"speaker":"npc","text":{"pl":"Poprosiłeś mnie o pomoc w zniszczeniu Bariery, tak czy nie?!","en":"Didn''t you call on me to help with the destruction of the Barrier?","de":"War es nicht die Zerstörung der Barriere, weswegen du mich aufgesucht hast?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_return_15_13_12', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_return_15_13_12","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_RETURN_Info","outputIds":["Info_Xardas_RETURN_15_13","Info_Xardas_RETURN_14_14"],"lines":[{"speaker":"hero","text":{"pl":"Tak, ale...","en":"That''s right, but...","de":"Richtig, aber ..."}},{"speaker":"npc","text":{"pl":"WIĘC IDŹ! Zmarnowano już dość czasu! Idź do podziemnej świątyni! Tam znajdziesz odpowiedź!","en":"THEN GO! A lot of time has already been wasted! Go into the underground temple to find the answer!","de":"DANN GEH! Es ist schon genug Zeit verstrichen! Geh und such die Antwort im unterirdischen Tempel!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_saturas_14_05_4', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_saturas_14_05_4","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_SATURAS_Info","outputIds":["Info_Xardas_SATURAS_14_05"],"lines":[{"speaker":"npc","text":{"pl":"NIE!","en":"NO!","de":"NEIN!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_saturas_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_saturas_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_SATURAS_Info","outputIds":["Info_Xardas_SATURAS_15_01","Info_Xardas_SATURAS_15_02","Info_Xardas_SATURAS_14_03","Info_Xardas_SATURAS_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Saturas. Potrzebujemy twojej pomocy!","en":"I was sent by Saturas. We need your help!","de":"Saturas schickt mich. Wir brauchen deine Hilfe!"}},{"speaker":"hero","text":{"pl":"Magowie Wody zamierzają zrobić użytek ze swojego kopca rudy.","en":"The Magicians of Water plan to use their big ore mound...","de":"Die Wassermagier wollen ihren großen Erzhaufen ..."}},{"speaker":"npc","text":{"pl":"Detonacja wielkiej góry nie jest żadnym rozwiązaniem!","en":"The ore mound is NOT the solution!","de":"Der Erzhaufen ist NICHT die Lösung!"}},{"speaker":"hero","text":{"pl":"Nie jest?","en":"It isn''t?","de":"Nein?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_sleeper_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_sleeper_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_SLEEPER_Info","outputIds":["Info_Xardas_SLEEPER_15_01","Info_Xardas_SLEEPER_15_02","Info_Xardas_SLEEPER_15_03","Info_Xardas_SLEEPER_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Tak zwany \"Śniący\" okazał się ponoć potężnym demonem zagłady.","en":"\"The so-called \"\"Sleeper\"\" is said to be an evil arch demon.\"","de":"Der so genannte \"Schläfer\" soll ein übler Erzdämon sein."}},{"speaker":"hero","text":{"pl":"Przekonało się o tym Bractwo z obozu na bagnie.","en":"That''s what the Brotherhood in the swamp found out.","de":"Das hat die Bruderschaft im Sumpf herausgefunden."}},{"speaker":"hero","text":{"pl":"Magowie Wody uważają teraz, że cała kolonia znalazła się w śmiertelnym niebezpieczeństwie.","en":"Now the Magicians of Water believe that everybody in the colony is in great danger.","de":"Die Wassermagier glauben nun, dass wir alle in der Kolonie in großer Gefahr seien."}},{"speaker":"npc","text":{"pl":"Stoimy przed poważniejszym zagrożeniem niż ktokolwiek wewnątrz Bariery jest w stanie sobie wyobrazić...","en":"There is a greater danger than anyone within the Barrier could possibly imagine.","de":"Die Gefahr ist größer als irgendjemand innerhalb der Barriere erahnen kann."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_404_xardas_info_xardas_swordloaded_15_01_0', 'KDF_404_Xardas', '{"id":"missions_dia_kdf_404_xardas_info_xardas_swordloaded_15_01_0","npcId":"KDF_404_Xardas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_404_Xardas.d","sourceFunction":"Info_Xardas_SWORDLOADED_Info","outputIds":["Info_Xardas_SWORDLOADED_15_01","Info_Xardas_SWORDLOADED_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Udało mi się! URIZIEL znów posiada magiczną aurę!","en":"I''ve reactivated URIZIEL!","de":"Ich habe URIZIEL aufgeladen!"}},{"speaker":"npc","text":{"pl":"Niesamowite! Miecz odzyskał swą dawną moc! Dysponujesz teraz nie lada orężem!","en":"It''s incredible, the sword has regained its former powers. Now you have a really powerful weapon!","de":"Unglaublich, das Schwert hat seine alten Kräfte wiedergewonnen. Nun führst du eine wahrhaft mächtige Waffe!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_belohnung_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_belohnung_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_Belohnung_Info","outputIds":["DIA_Torrez_Belohnung_15_00","DIA_Torrez_Belohnung_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Corristo. Przyniosłem mu list z zewnątrz i mam sobie wybrać nagrodę.","en":"Corristo sent me. I''ve passed the letter on to him, and I''m to choose my own reward.","de":"Corristo schickt mich. Ich habe den Brief übergeben und soll meine Belohnung selber wählen."}},{"speaker":"npc","text":{"pl":"Wyświadczyłeś nam wielką przysługę i otrzymasz każdą nagrodę, jakiej zażądasz.","en":"You have done us a great service and you shall have your reward. Choose carefully.","de":"Du hast uns einen großen Dienst erwiesen und sollst deine Belohnung erhalten. Wähle mit Bedacht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_belohnung_dex_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_belohnung_dex_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_Belohnung_Dex","outputIds":["DIA_Torrez_Belohnung_Dex_15_00","DIA_Torrez_Belohnung_Dex_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Wezmę pierścień zwinności.","en":"I''ll take the Ring of Dexterity.","de":"Ich nehme den Ring des Geschicks."}},{"speaker":"npc","text":{"pl":"Zwinność zawsze powinna iść przed siłą. To był mądry wybór.","en":"Dexterity wins over strength. A good decision.","de":"Geschicklichkeit siegt über Stärke. Eine gute Entscheidung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_belohnung_mana_max_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_belohnung_mana_max_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_Belohnung_ManaMax","outputIds":["DIA_Torrez_Belohnung_ManaMax_15_00","DIA_Torrez_Belohnung_ManaMax_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym dostać ten napój!","en":"I would like to have the potion!","de":"Ich will den Trank!"}},{"speaker":"npc","text":{"pl":"Mądra decyzja! To najcenniejszy z przedmiotów, które mogłeś wybrać. Wypij ten napój, a twoja siła znacznie wrośnie!","en":"A wise choice! You have picked the most precious of all gifts. Drink the potion and your power will grow!","de":"Deine Wahl war weise! Du hast das kostbarste Geschenk von allen gewählt. Trinke den Trank und deine Macht wird wachsen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_belohnung_scrolls_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_belohnung_scrolls_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_Belohnung_Scrolls","outputIds":["DIA_Torrez_Belohnung_Scrolls_15_00","DIA_Torrez_Belohnung_Scrolls_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Wezmę te zwoje z zaklęciami.","en":"Give me the spell scrolls.","de":"Gib mir die Spruchrollen."}},{"speaker":"npc","text":{"pl":"Wykorzystaj je mądrze! Każdego z nich możesz użyć tylko raz!","en":"Use them wisely. You can use each of them only once!","de":"Nutze sie mit Bedacht. Du kannst jede von ihnen nur einmal verwenden!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_belohnung_str_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_belohnung_str_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_Belohnung_Str","outputIds":["DIA_Torrez_Belohnung_Str_15_00","DIA_Torrez_Belohnung_Str_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Wezmę ten pierścień siły.","en":"I''ll take the Ring of Strength.","de":"Ich nehme den Stärkering."}},{"speaker":"npc","text":{"pl":"Tak jak się spodziewałem. Proszę, oto on.","en":"The expected choice. Here, take the ring.","de":"Eine solche Wahl hatte ich von dir erwartet. Hier, nimm den Ring."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_brief_tausch_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_brief_tausch_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_BriefTausch_Info","outputIds":["DIA_Torrez_BriefTausch_15_00","DIA_Torrez_BriefTausch_04_01","DIA_Torrez_BriefTausch_15_02","DIA_Torrez_BriefTausch_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam dla ciebie list! Ale najpierw chcę dostać swoją nagrodę!","en":"I have a letter for you! But I want my reward first!","de":"Ich habe einen Brief für euch! Aber ich will erst meine Belohnung sehen!"}},{"speaker":"npc","text":{"pl":"Dlaczego nie porozmawiasz z Miltenem?","en":"Why don''t you talk to Milten?","de":"Warum sprichst du nicht mit Milten?"}},{"speaker":"hero","text":{"pl":"Już to zrobiłem.","en":"I''ve done that already.","de":"Hab ich bereits."}},{"speaker":"npc","text":{"pl":"Rozumiem. Mam tu twoją nagrodę. Pokaż mi list. Teraz!","en":"I understand. I have your reward here - show me the letter. Now!","de":"Verstehe. Ich habe deine Belohnung bei mir - zeig mir den Brief. Jetzt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_brief_tausch_15_04_4', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_brief_tausch_15_04_4","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_BriefTausch_Info","outputIds":["DIA_Torrez_BriefTausch_15_04","DIA_Torrez_BriefTausch_04_05","DIA_Torrez_BriefTausch_04_06","DIA_Torrez_BriefTausch_04_07"],"lines":[{"speaker":"hero","text":{"pl":"Oto on!","en":"Here it is.","de":"Hier ist er."}},{"speaker":"npc","text":{"pl":"W nagrodę otrzymasz pierścień siły. To niezwykle rzadki artefakt. Z pewnością bardzo ci się przyda.","en":"Your reward is a Ring of Strength. It''s a rare artefact, and will be of great use to you.","de":"Deine Belohnung ist ein Ring der Stärke. Es ist ein seltenes Artefakt und wird dir sicherlich sehr nützlich sein."}},{"speaker":"npc","text":{"pl":"A teraz idź stąd!","en":"Now go!","de":"Und nun geh!"}},{"speaker":"npc","text":{"pl":"Pieczęć została złamana.","en":"The seal is broken.","de":"Das Siegel ist gebrochen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_brief_tausch_15_08_8', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_brief_tausch_15_08_8","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_BriefTausch_Info","outputIds":["DIA_Torrez_BriefTausch_15_08","DIA_Torrez_BriefTausch_04_09"],"lines":[{"speaker":"hero","text":{"pl":"Cóż, wypadki się zdarzają.","en":"Accidents happen.","de":"Unfälle passieren eben."}},{"speaker":"npc","text":{"pl":"Jako zapłatę dostaniesz napój uzdrawiający. Ciesz się, posłańcy, którzy przynoszą otwarte listy zwykle nie dostają nic!","en":"Your reward is a healing potion. Be content with that. Messengers who deliver letters without seals usually don''t get anything!","de":"Deine Belohnung ist ein Trank der Heilung. Sei zufrieden damit. Einem Boten, der einen Brief ohne Siegel übergibt, steht normalerweise gar nichts zu!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_hello_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_hello_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_Hello_Info","outputIds":["DIA_Torrez_Hello_15_00","DIA_Torrez_Hello_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Szukam Arcymistrza Magów Ognia!","en":"I''m looking for the High Magician of the Circle of Fire!","de":"Ich suche den obersten Feuermagier!"}},{"speaker":"npc","text":{"pl":"Zgłoś się do Miltena. A teraz znikaj!","en":"Speak to Milten! And now go!","de":"Sprich mit Milten! Und nun geh!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_dia_torrez_perm_15_00_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_dia_torrez_perm_15_00_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"DIA_Torrez_PERM_Info","outputIds":["DIA_Torrez_PERM_15_00","DIA_Torrez_PERM_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać w świecie magii?","en":"How''s venturing in the magic arts?","de":"Was machen die magischen Künste?"}},{"speaker":"npc","text":{"pl":"Nie twój interes!","en":"That''s none of your business!","de":"Das ist nicht dein Belang!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_kdf_405_torrez_book_info_04_01_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_kdf_405_torrez_book_info_04_01_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"KDF_405_Torrez_BOOK_Info","outputIds":["KDF_405_Torrez_BOOK_Info_04_01","KDF_405_Torrez_BOOK_Info_04_02"],"lines":[{"speaker":"npc","text":{"pl":"Dla każdego magicznego Kręgu powstała księga, opisująca jego zasady. Powinieneś je uważnie przestudiować. Wiedza to potęga!","en":"For each of the Circles there is a book explaining it''s magic. Study these books. Knowledge is power!","de":"Für jeden der Kreise gibt es ein Buch, in welchem die Zauber des Kreises erklärt werden. Studiere sie genau, denn Wissen bedeutet Macht."}},{"speaker":"npc","text":{"pl":"Weź księgę Pierwszego Kręgu i przeczytaj ją uważnie. Zrozumiesz naturę Ognia.","en":"Take the book of the First Circle and learn to understand the Fire.","de":"Nimm das Buch des ersten Kreises und lerne das Feuer zu verstehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_kdf_405_torrez_greet_info_15_01_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_kdf_405_torrez_greet_info_15_01_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"KDF_405_Torrez_GREET_Info","outputIds":["KDF_405_Torrez_GREET_Info_15_01","KDF_405_Torrez_GREET_Info_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Witaj, Magu!","en":"Greetings, Magician.","de":"Ich grüße dich, Magier."}},{"speaker":"npc","text":{"pl":"Niech Innos zawsze ma cię w swojej opiece! Zajmuję się sprzedażą magicznych artefaktów i mogę ci pokazać, jak zwiększyć twoje zdolności magiczne!","en":"May Innos watch over you! I trade in magic knowledge, and I can show you how to increase your magic powers!","de":"Innos wache über dich! Ich handele mit magischem Wissen und kann dir zeigen, wie du deine magische Energie steigerst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_kdf_405_torrez_mana_info_15_01_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_kdf_405_torrez_mana_info_15_01_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"KDF_405_Torrez_MANA_Info","outputIds":["KDF_405_Torrez_MANA_Info_15_01","KDF_405_Torrez_MANA_Info_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję większej mocy magicznej.","en":"I need more magic power.","de":"Ich benötige mehr magische Kraft."}},{"speaker":"npc","text":{"pl":"Pokażę ci, jak zwiększyć twoje zdolności magiczne. Jak je wykorzystać, zależy już tylko od ciebie.","en":"I can help you to increase your power. What use you make of it is up to you.","de":"Ich kann dir helfen, deine Kraft zu steigern. Wie du sie nutzt, liegt nur an dir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdf_405_torrez_kdf_405_torrez_wannabemage_info_15_01_0', 'KDF_405_Torrez', '{"id":"missions_dia_kdf_405_torrez_kdf_405_torrez_wannabemage_info_15_01_0","npcId":"KDF_405_Torrez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDF_405_Torrez.d","sourceFunction":"KDF_405_Torrez_WANNABEMAGE_Info","outputIds":["KDF_405_Torrez_WANNABEMAGE_Info_15_01","KDF_405_Torrez_WANNABEMAGE_Info_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Co powinienem zrobić, żeby zostać magiem?","en":"What do I have to do to become a magician?","de":"Was muss ich tun, um Magier zu werden?"}},{"speaker":"npc","text":{"pl":"Porozmawiaj z Mistrzem Corristo, jeśli znajdzie czas, żeby cię wysłuchać.","en":"Talk to Master Corristo, if he has time for you.","de":"Sprich mit Meister Corristo, wenn er Zeit für dich hat."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_accept_14_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_accept_14_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_ACCEPT_Info","outputIds":["Info_Saturas_ACCEPT_14_09"],"lines":[{"speaker":"npc","text":{"pl":"Mam nadzieję, że to przekona naszych dawnych przyjaciół o szczerości naszych intencji.","en":"I hope that''ll convince our former friends of our good intentions.","de":"Ich hoffe, das überzeugt unsere ehemaligen Freunde von unseren guten Absichten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_accept_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_accept_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_ACCEPT_Info","outputIds":["Info_Saturas_ACCEPT_15_01","Info_Saturas_ACCEPT_15_02","Info_Saturas_ACCEPT_14_03","Info_Saturas_ACCEPT_14_04"],"lines":[{"speaker":"hero","text":{"pl":"No dobrze. Spróbuję jakoś przekonać Magów Ognia!","en":"Alright then, I''ll try to convince the Magicians of Fire!","de":"Nun gut, ich werde versuchen, die Feuermagier zu überreden!"}},{"speaker":"hero","text":{"pl":"Ale nic nie obiecuję! Obawiam się, że to zadanie jest z góry skazane na niepowodzenie!","en":"But I can''t promise anything! It seems nearly impossible to me.","de":"Aber ich kann nichts versprechen! Es scheint mir fast unmöglich."}},{"speaker":"npc","text":{"pl":"Musisz chociaż spróbować. Jeśli ci się nie powiedzie, jest już tylko jeden...","en":"You must try. If you do not succeed in this, there is only one other...","de":"Du musst es versuchen. Wenn du keinen Erfolg hast, dann gibt es nur noch einen ..."}},{"speaker":"npc","text":{"pl":"Tylko jeden...","en":"Just one...","de":"Einen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_accept_15_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_accept_15_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_ACCEPT_Info","outputIds":["Info_Saturas_ACCEPT_15_05","Info_Saturas_ACCEPT_14_06","Info_Saturas_ACCEPT_14_07","Info_Saturas_ACCEPT_14_08"],"lines":[{"speaker":"hero","text":{"pl":"...jeden CO?","en":"... one WHAT?","de":"... Einen WAS?"}},{"speaker":"npc","text":{"pl":"Nieważne! MUSI ci się udać!","en":"Forget it! You MUST succeed!","de":"Vergiss das! Du MUSST Erfolg haben!"}},{"speaker":"npc","text":{"pl":"Weź tę magiczną runę jako znak naszego zaufania. Pokażesz ją Corristo, Arcymistrzowi Magów Ognia.","en":"Here, take this magic rune. Hand it over to Corristo, the High Magician of the Circle of Fire, as a sign of our trust.","de":"Hier, nimm diese Zauberrune. Überbringe sie Corristo, dem obersten Feuermagier, als Zeichen unseres Vertrauens."}},{"speaker":"npc","text":{"pl":"Dzięki jej pomocy będzie mógł przeteleportować się do tej komnaty, nie przechodząc przez posterunki straży.","en":"With this he can teleport into this room without passing the guards anytime he wants.","de":"Damit kann er sich jederzeit vorbei an allen Wachen mitten in diesen Raum teleportieren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_allfoci_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_allfoci_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_ALLFOCI_Info","outputIds":["Info_Saturas_ALLFOCI_15_01","Info_Saturas_ALLFOCI_14_02","Info_Saturas_ALLFOCI_14_03","Info_Saturas_ALLFOCI_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Czy możecie teraz przystąpić do detonacji kopca rudy?","en":"Can you blast the ore mound now?","de":"Kann nun die Sprengung des Erzhaufens beginnen?"}},{"speaker":"npc","text":{"pl":"Mamy już wszystkie artefakty niezbędne do wprowadzenia naszego planu w życie.","en":"We now have all the artefacts we need to fulfill our plan.","de":"Wir haben jetzt alle Artefakte zusammen, die unser großes Vorhaben benötigt."}},{"speaker":"npc","text":{"pl":"Ale Barierę utworzyło dwunastu magów.","en":"But the Barrier was created by twelve magicians.","de":"Doch die Erschaffung der Barriere wurde von zwölf Magiern durchgeführt."}},{"speaker":"npc","text":{"pl":"W całym Kręgu Wody nie ma dość mistrzów magii, by zapanować nad tak ogromną ilością energii. Nie mówiąc już o jej odpowiednim ukierunkowaniu!","en":"There are not enough magicians in the Circle of Water to control the powerful energies and to guide them onto the right course.","de":"Um die gewaltigen Energien zu kontrollieren und in die richtigen Bahnen lenken zu können, sind wir Wassermagier nicht genug."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_allfoci_15_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_allfoci_15_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_ALLFOCI_Info","outputIds":["Info_Saturas_ALLFOCI_15_05","Info_Saturas_ALLFOCI_14_06","Info_Saturas_ALLFOCI_14_07"],"lines":[{"speaker":"hero","text":{"pl":"I co teraz zrobimy?","en":"What can we do?","de":"Was machen wir dann?"}},{"speaker":"npc","text":{"pl":"Wiem ile już zrobiłeś dla naszej społeczności. Wszyscy jesteśmy twoimi dłużnikami...","en":"I am aware that you have already done much for our community, we owe you greatly...","de":"Mir ist bewusst, dass du schon sehr viel für unsere Gemeinschaft getan hast und wir stehen tief in deiner Schuld ..."}},{"speaker":"npc","text":{"pl":"...Ale w interesie wszystkich mieszkańców kolonii muszę cię poprosić o jeszcze jedną przysługę.","en":"... but in the interest of all the inhabitants of the colony, I need to ask one more favor of you.","de":"... Doch im Interesse aller Koloniebewohner muss ich dich noch um einen weiteren Gefallen bitten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_ambush_14_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_ambush_14_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_AMBUSH_Info","outputIds":["Info_Saturas_AMBUSH_14_01","Info_Saturas_AMBUSH_15_02","Info_Saturas_AMBUSH_14_03","Info_Saturas_AMBUSH_14_04"],"lines":[{"speaker":"npc","text":{"pl":"Cieszę się, że wróciłeś. Stało się coś strasznego!","en":"I''m glad you returned. Something terrible''s happened!","de":"Gut, dass du wieder zurück bist. Es ist etwas Schreckliches passiert!"}},{"speaker":"hero","text":{"pl":"Niech zgadnę: Wolna Kopalnia została zaatakowana przez Strażników ze Starego Obozu, którzy niespodziewanie wyrośli jak spod ziemi?","en":"Let me guess, the Free Mine has been assaulted by the guards from the Old Camp. Nobody saw them coming...?","de":"Lass mich raten, die Freie Mine wurde von Gardisten aus dem Alten Lager überfallen, die niemand kommen sah?"}},{"speaker":"npc","text":{"pl":"Zaraz... Jak... Ależ oczywiście! Dowiedziałeś się o tym w Starym Obozie!","en":"Hang on... how... but of course... You found out about it in the Old Camp!","de":"Moment ... woher ... aber natürlich ... Du hast es im Alten Lager erfahren!"}},{"speaker":"npc","text":{"pl":"Gorn zjawił się tutaj tuż przed tobą.","en":"Gorn arrived here just before you did.","de":"Gorn kam kurz vor dir hier an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_ambush_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_ambush_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_AMBUSH_Info","outputIds":["Info_Saturas_AMBUSH_14_05","Info_Saturas_AMBUSH_14_06"],"lines":[{"speaker":"npc","text":{"pl":"Co mogło skłonić Gomeza do podjęcia tak drastycznych działań?","en":"What could have caused Gomez to dare to take such an aggressive step?","de":"Was kann Gomez nur veranlasst haben, solch einen aggressiven Schritt zu wagen?"}},{"speaker":"npc","text":{"pl":"Przecież musiał zdawać sobie sprawę, że ten napad stanowi wypowiedzenie wojny.","en":"He should be aware that such a heinous act can only provoke war.","de":"Ihm müsste klar sein, dass dieser hinterhältige Überfall einen Krieg heraufbeschwört."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_book_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_book_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_BOOK_Info","outputIds":["Info_Saturas_BOOK_15_01","Info_Saturas_BOOK_15_02","Info_Saturas_BOOK_14_03","Info_Saturas_BOOK_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Mam ten almanach...","en":"I have this almanac...","de":"Ich habe diesen Almanach hier ..."}},{"speaker":"hero","text":{"pl":"Y''Berion wykorzystał go do naładowania kamienia ogniskującego.","en":"Y''Berion used it to charge the focus.","de":"Y''Berion hatte ihn benutzt, um den Fokus aufzuladen."}},{"speaker":"npc","text":{"pl":"Świetnie. Wiedza zawarta w tej księdze pozwoli nam naładować pięć pierwotnych kamieni ogniskujących.","en":"Very good. We need the knowledge contained in this book to charge the five original focus stones.","de":"Sehr gut. Wir benötigen das Wissen aus diesem Buch, um alle fünf der ursprünglichen Fokussteine aufzuladen."}},{"speaker":"npc","text":{"pl":"Wezmę ten almanach!","en":"I''ll take the almanac!","de":"Ich werde den Almanach an mich nehmen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"B_DeliverFocus","outputIds":["Info_Saturas_BRINGFOCUS_14_01","Info_Saturas_BRINGFOCUS_14_02","Info_Saturas_BRINGFOCUS_14_03","Info_Saturas_BRINGFOCUS_14_04"],"lines":[{"speaker":"npc","text":{"pl":"Hmmm, na dobry początek wystarczy. Nieźle sobie radzisz.","en":"Hm, that''s a start. You''re doing well.","de":"Hm, das ist ein Anfang. Du schlägst dich gut."}},{"speaker":"npc","text":{"pl":"Musisz jeszcze odnaleźć trzy pozostałe kamienie.","en":"There are still three focus stones missing to accomplish our plan.","de":"Es fehlen noch drei Fokussteine, um unseren großen Plan durchzuführen."}},{"speaker":"npc","text":{"pl":"Ruszaj w drogę! Nie zostało nam zbyt wiele czasu.","en":"Now go and look out for the remaining focus stones.","de":"Gehe nun und suche die restlichen Fokussteine."}},{"speaker":"npc","text":{"pl":"Świetnie. To już drugi kamień, który nam przynosisz!","en":"Good, that''s the second focus stone you''ve brought us.","de":"Gut, das ist schon der zweite Fokusstein, den du uns bringst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"B_DeliverFocus","outputIds":["Info_Saturas_BRINGFOCUS_14_05","Info_Saturas_BRINGFOCUS_14_06","Info_Saturas_BRINGFOCUS_14_07","Info_Saturas_BRINGFOCUS_14_08"],"lines":[{"speaker":"npc","text":{"pl":"Jesteśmy już znacznie bliżej naszego celu.","en":"We''re getting closer and closer to our target.","de":"Wir kommen unserem großen Ziel immer näher."}},{"speaker":"npc","text":{"pl":"Nie ustawaj w wysiłkach. Potrzebujemy jeszcze dwóch kamieni ogniskujących.","en":"Be brave and fetch the two remaining focus stones.","de":"Schlag dich tapfer und suche nun die restlichen zwei Fokussteine."}},{"speaker":"npc","text":{"pl":"Niesamowite! Mamy już cztery kamienie ogniskujące!","en":"Unbelievable, now we have four focus stones altogether.","de":"Unglaublich, nun haben wir schon insgesamt vier Fokussteine."}},{"speaker":"npc","text":{"pl":"Brakuje jeszcze tylko jednego!","en":"There''s only one more missing, then we''ll have them all.","de":"Nur noch ein Einziger fehlt uns, dann haben wir alle ursprünglichen Steine in unserem Besitz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"B_DeliverFocus","outputIds":["Info_Saturas_BRINGFOCUS_14_09","Info_Saturas_BRINGFOCUS_14_10","Info_Saturas_BRINGFOCUS_14_11","Info_Saturas_BRINGFOCUS_14_12"],"lines":[{"speaker":"npc","text":{"pl":"Oddałeś naszej społeczności nieocenione usługi. Jeśli uda ci się odnaleźć ostatni z kamieni, wkrótce będziemy znów na wolności!","en":"You have already done our community a great service. Get the last focus stone, and we''ll soon be able to free ourselves.","de":"Du hast unserer Gemeinschaft schon jetzt sehr viel Ehre erwiesen. Finde den letzten Fokusstein und unsere Befreiung steht kurz bevor."}},{"speaker":"npc","text":{"pl":"Wspaniale! Mamy już wszystkie pięć kamieni!","en":"Brilliant, now we have all five focus stones.","de":"Fantastisch, nun haben wir alle fünf Fokussteine in unserem Besitz."}},{"speaker":"npc","text":{"pl":"Nie wiem jak będziemy ci się mogli odwdzięczyć! Jestem twoim dozgonnym dłużnikiem.","en":"Your deeds are invaluable to our camp. Be assured of my eternal gratitude.","de":"Deine Taten sind von unschätzbarem Wert für unser Lager. Sei dir meines ewigen Dankes gewiss."}},{"speaker":"npc","text":{"pl":"Pójdź teraz do Riordiana. On da ci chociaż skromną namiastkę nagrody za twoje wysiłki!","en":"Go to Riordian now. He''ll give you something for your immense efforts.","de":"Gehe nun zu Riordian. Er wird dir einen Ausgleich für deine unermesslichen Mühen geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_13_12', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_bringfocus_14_13_12","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"B_DeliverFocus","outputIds":["Info_Saturas_BRINGFOCUS_14_13","Info_Saturas_BRINGFOCUS_14_14"],"lines":[{"speaker":"npc","text":{"pl":"Porozmawiaj również z Cronosem, strażnikiem rudy. Od niego dostaniesz kolejny wyraz naszej wdzięczności.","en":"Speak to Cronos, the keeper of the ore, as well. He will give you another gift from our community.","de":"Sprich auch mit Cronos, dem Hüter des Erzes. Auch er wird dir ein Geschenk unserer Gemeinschaft überreichen."}},{"speaker":"npc","text":{"pl":"Widzę, że wykorzystałeś zwój teleportacyjny. Proszę, weź następny.","en":"I see you''ve used up the teleportation scroll. Here, take a new one.","de":"Du hast die Teleport-Spruchrolle verbraucht, wie ich sehe. Hier, nimm eine neue."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_collapse_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_collapse_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_COLLAPSE_Info","outputIds":["Info_Saturas_COLLAPSE_15_01","Info_Saturas_COLLAPSE_14_02","Info_Saturas_COLLAPSE_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Stara Kopalnia została zalana przez podziemną rzekę!","en":"The Old Mine collapsed after water seeped in!","de":"Die Alte Mine wurde nach einem Wassereinbruch verschüttet!"}},{"speaker":"npc","text":{"pl":"...Zalana... Naturalnie... Teraz zaczynam rozumieć...","en":"... Collapsed... of course... then the whole thing makes sense.","de":"... Verschüttet ... natürlich ... dann gibt das Ganze langsam einen Sinn."}},{"speaker":"npc","text":{"pl":"Gomez został przyparty do muru. Jest teraz jeszcze groźniejszy niż kiedyś. Nie ma nic do stracenia, więc stał się całkowicie nieobliczalny!","en":"Gomez has his back to the wall. He''s more dangerous than ever. Now that he doesn''t have anything left to lose, he''ll do anything!","de":"Gomez steht mit dem Rücken zur Wand. Er ist gefährlicher denn je geworden, denn nun, wo er nichts mehr zu verlieren hat, wird er zu allem fähig sein!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_exit_14_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_exit_14_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_EXIT_Info","outputIds":["Info_Saturas_EXIT_14_01"],"lines":[{"speaker":"npc","text":{"pl":"Obyś wrócił cały i zdrowy!","en":"May you return in one piece!","de":"Mögest du in einem Stück zurückkehren!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_favor_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_favor_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_FAVOR_Info","outputIds":["Info_Saturas_FAVOR_14_05","Info_Saturas_FAVOR_14_06"],"lines":[{"speaker":"npc","text":{"pl":"Właśnie dlatego to TY musisz podjąć się tego zadania. Znasz ludzi ze wszystkich obozów w całej kolonii.","en":"That is the exact reason why YOU must accomplish this mission. You know people from all the camps of the colony.","de":"Genau aus diesem Grunde musst DU dich um diese schwierige Mission kümmern. Du kennst Leute aus allen Lagern der Kolonie."}},{"speaker":"npc","text":{"pl":"Przypomnij Magom Ognia stare czasy, kiedy wspólnie studiowaliśmy sztuki magiczne.","en":"Remind the Magicians of Fire of the old times, when we studied the arts of magic together.","de":"Erinnere die Feuermagier an die alten Zeiten, als wir noch gemeinsam die magischen Künste studierten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_favor_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_favor_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_FAVOR_Info","outputIds":["Info_Saturas_FAVOR_15_01","Info_Saturas_FAVOR_14_02","Info_Saturas_FAVOR_15_03","Info_Saturas_FAVOR_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Jeszcze jedną przysługę?","en":"One more favor?","de":"Ein weiterer Gefallen?"}},{"speaker":"npc","text":{"pl":"Tak. Musisz iść do Starego Obozu i przekonać do naszej sprawy kilku Magów Ognia.","en":"Yes. Go to the Old Camp and try to win some of the Magicians of the Circle of Fire for our cause.","de":"Ja. Begib dich ins Alte Lager und versuche, einige der Feuermagier für unsere Sache zu gewinnen."}},{"speaker":"hero","text":{"pl":"MAGÓW OGNIA?? Myślisz, że zechcą przyłączyć się do was i zrezygnować ze swego wygodnego życia?","en":"MAGICIANS OF FIRE??? Why should they want to give up their easy life?","de":"DIE FEUERMAGIER??? Warum sollten die Maden den Speck verlassen wollen?"}},{"speaker":"hero","text":{"pl":"Przecież upadek Bariery pozbawi ich uprzywilejowanej pozycji!","en":"The destruction of the Barrier would rob them of their powerful position!","de":"Ein Zusammenbruch der Barriere würde ihre Machtposition  zunichte machen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_focus_14_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_focus_14_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_FOCUS_Info","outputIds":["Info_Saturas_FOCUS_14_09","Info_Saturas_FOCUS_15_10"],"lines":[{"speaker":"npc","text":{"pl":"Eksplozja energii magicznej może zniszczyć wyłącznie twory utworzone lub zmodyfikowane przy użyciu magii. Nie istnieje żadne zagrożenie dla istot ludzkich.","en":"The explosion will be merely of a magical nature, it will only destroy everything that''s been modified by the magic inside the Barrier. There is no danger to us human beings.","de":"Die Explosion wird rein magischer Natur sein und wird ausschließlich alles magisch Veränderte innerhalb der Barriere zerstören. Für uns Menschen besteht keine Gefahr."}},{"speaker":"hero","text":{"pl":"Proszę, oto kamień ogniskujący. Mam nadzieję, że wasze plany związane z detonacją kopca powiodą się.","en":"Here, take the focus. I hope it really will be of some use to your plans with the ore mound!","de":"Hier, nimm den Fokus. Hoffentlich hilft er dem Plan mit dem Erzhaufen auch wirklich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_focus_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_focus_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_FOCUS_Info","outputIds":["Info_Saturas_FOCUS_15_01","Info_Saturas_FOCUS_14_02","Info_Saturas_FOCUS_14_03","Info_Saturas_FOCUS_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Mam tu ten kamień ogniskujący...","en":"I have this focus...","de":"Ich habe diesen Fokus hier ..."}},{"speaker":"npc","text":{"pl":"Trzymasz w ręku klucz, który może nas wyzwolić z kajdan niewolnictwa.","en":"You''re holding the key that can unlock all our bonds.","de":"Du hältst einen der Schlüssel für die Zerstörung unser aller Fesseln in Händen."}},{"speaker":"npc","text":{"pl":"To jeden z pięciu kamieni ogniskujących, które wykorzystywano podczas tworzenia Magicznej Bariery.","en":"It is one of the five focus stones which were used to create the Magic Barrier.","de":"Es handelt sich um einen der fünf Fokussteine, mit deren Hilfe die magische Barriere erschaffen wurde."}},{"speaker":"npc","text":{"pl":"A my z pomocą tej samej siły ogniskującej zniszczymy wielką magiczną Barierę.","en":"And with the help of the very same focusing power of these stones, we will tear down the great wall of energy.","de":"Und mit der fokussierenden Kraft genau dieser Steine werden wir die Mauern aus Energie auch wieder niederreißen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_focus_15_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_focus_15_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_FOCUS_Info","outputIds":["Info_Saturas_FOCUS_15_05","Info_Saturas_FOCUS_14_06","Info_Saturas_FOCUS_14_07","Info_Saturas_FOCUS_15_08"],"lines":[{"speaker":"hero","text":{"pl":"Ale czy do tego nie będzie potrzeba potężnego źródła magicznej energii?","en":"But won''t that use up an awful lot of power?","de":"Aber kostet das nicht unglaublich viel magische Energie?"}},{"speaker":"npc","text":{"pl":"To prawda. Dlatego przez te wszystkie lata gromadziliśmy rudę, zamiast wymieniać ją na towary z zewnętrznego świata.","en":"True, but in all these years we have untiringly collected ore instead of trading it for luxuries with our jailers.","de":"Richtig, doch wir haben über all die Jahre unermüdlich Erz gesammelt, anstatt es mit unseren Kerkermeistern gegen Annehmlichkeiten zu tauschen."}},{"speaker":"npc","text":{"pl":"Jak zapewne wiesz, każdy kawałek rudy zawiera niewielki ładunek energii magicznej. Mamy nadzieję, że wyzwalając jednocześnie cały potencjał zgromadzonego przez nas kopca, będziemy w stanie zniszczyć Barierę.","en":"As you must know, each ore nugget contains a certain amount of magic power. With the aid of the energy thus amassed in the ore mound, we''ll be able to destroy the Magic Barrier.","de":"Wie du sicher schon weißt, enthält jeder Erzbrocken etwas magische Energie. Mit Hilfe dieser Energie, die in unserem großen Erzhaufen schlummert, können wir die magische Barriere in Fetzen sprengen."}},{"speaker":"hero","text":{"pl":"To chyba dość ryzykowne?","en":"Sounds dangerous.","de":"Das hört sich gefährlich an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_intruder_14_00_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_intruder_14_00_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_Intruder_Info","outputIds":["Info_Saturas_Intruder_14_00"],"lines":[{"speaker":"npc","text":{"pl":"Co ty tu robisz? Nie masz tu czego szukać! Precz!","en":"What are you doing here? You''ve no business here! Scram!","de":"Was machst du hier? Du hast hier nichts zu suchen! Verschwinde!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_murder_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_murder_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_MURDER_Info","outputIds":["Info_Saturas_MURDER_14_05"],"lines":[{"speaker":"npc","text":{"pl":"Mimo wszystko, dziękuję ci za dostarczenie tych przykrych wieści. Wróg już nas nie zaskoczy.","en":"But in spite of that, I thank you for passing this dangerous message on to me.","de":"Ich danke dir trotzdem dafür, dass du diese gefährliche Botschaft an mich überbracht hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_murder_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_murder_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_MURDER_Info","outputIds":["Info_Saturas_MURDER_15_01","Info_Saturas_MURDER_14_02","Info_Saturas_MURDER_15_03","Info_Saturas_MURDER_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Gomez wymordował wszystkich Magów Ognia!","en":"Gomez has had all the Magicians of Fire killed!","de":"Gomez hat alle Feuermagier töten lassen!"}},{"speaker":"npc","text":{"pl":"WYMORDOWAŁ?!? Na Beliara, czemu miałby zrobić coś takiego?!","en":"HAD THEM KILLED??? Why in Beliar''s name would he do a thing like that?","de":"TÖTEN LASSEN??? Wieso bei Beliar hat er so etwas getan?"}},{"speaker":"hero","text":{"pl":"Magowie sprzeciwili się atakowi na Wolną Kopalnię, a tym samym stanęli Gomezowi na drodze.","en":"They were against the attack on the Free Mine, and opposed Gomez.","de":"Sie waren gegen den Überfall auf die Freie Mine und stellten sich gegen Gomez."}},{"speaker":"npc","text":{"pl":"Zatem jesteśmy zgubieni. Bez pomocy pozostałych sześciu magów nie uda się nam zapanować nad energią wyzwoloną podczas detonacji kopca.","en":"Then we''re all doomed. Without the other six magicians, we''ll never be able to control the concentrated power of the massive ore mound.","de":"Dann sind wir alle verloren. Ohne die anderen sechs Magier werden wir die geballte Kraft des großen Erzhaufens nicht kontrollieren können."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_news_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_news_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_NEWS_Info","outputIds":["Info_Saturas_NEWS_15_01","Info_Saturas_NEWS_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Mam ważne wieści z obozu Bractwa!","en":"I have important news from the Brotherhood''s camp!","de":"Ich habe wichtige Neuigkeiten aus dem Lager der Bruderschaft!"}},{"speaker":"npc","text":{"pl":"Jeśli Cronos pozwolił ci mnie odwiedzić, musiało się stać coś naprawdę ważnego!","en":"If Cronos gave you permission to visit me, it must be important news indeed!","de":"Wenn dir Cronos die Erlaubnis gab, mich aufzusuchen, müssen es in der Tat wichtige Nachrichten sein!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_nowsld_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_nowsld_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_NOWSLD_Info","outputIds":["Info_Saturas_NOWSLD_15_01","Info_Saturas_NOWSLD_14_02","Info_Saturas_NOWSLD_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Lee przyjął mnie w poczet Najemników.","en":"Lee has admitted me to the mercenaries.","de":"Lee hat mich bei den Söldnern aufgenommen."}},{"speaker":"npc","text":{"pl":"Dobrze. Bardzo dobrze. Teraz jesteś oficjalnie członkiem naszej społeczności.","en":"Good. Very good. Then you are now officially a part of our community.","de":"Gut. Sehr gut. Dann gehörst du nun offiziell zu unserer Gemeinschaft."}},{"speaker":"npc","text":{"pl":"Witaj wśród nas!","en":"Be welcome!","de":"Sei herzlich willkommen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_offer_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_offer_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_OFFER_Info","outputIds":["Info_Saturas_OFFER_14_05","Info_Saturas_OFFER_15_06","Info_Saturas_OFFER_14_07","Info_Saturas_OFFER_14_08"],"lines":[{"speaker":"npc","text":{"pl":"Będziesz zdany wyłącznie na siebie.","en":"You''ll be totally on your own.","de":"Du wärest ganz auf dich alleine gestellt."}},{"speaker":"hero","text":{"pl":"Cóż... To mi nie pierwszyzna! Jakoś sobie poradzę.","en":"Well... That''s nothing unusual for me! I''ll find a way to organize these things.","de":"Na ja ... Das ist nun wirklich nichts Neues! Ich werde diese Dinger schon irgendwo auftreiben."}},{"speaker":"npc","text":{"pl":"Twoja pewność siebie dobrze o tobie świadczy, ale przyda ci się kilka przedmiotów...","en":"Your confidence does you credit, but you''ll need some items to assist you.","de":"Deine Zuversicht ehrt dich, aber du wirst einige Gegenstände benötigen."}},{"speaker":"npc","text":{"pl":"Weź tę mapę. Jest dość stara, ale zaznaczono na niej oryginalne rozmieszczenie kamieni ogniskujących w chwili tworzenia Bariery.","en":"Take this map here. It''s old, but on it you''ll see the original locations of the focus stones when the Barrier was created.","de":"Nimm diese Karte hier. Sie ist alt, aber auf ihr sind die ursprünglichen Standorte der Fokussteine während der Erschaffung der Barriere verzeichnet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_offer_14_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_offer_14_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_OFFER_Info","outputIds":["Info_Saturas_OFFER_14_09","Info_Saturas_OFFER_14_10","Info_Saturas_OFFER_14_11"],"lines":[{"speaker":"npc","text":{"pl":"Ten zwój magiczny pozwoli ci błyskawicznie przenieść się do naszego obozu.","en":"Also, this spell scroll will enable you to travel back to our camp faster.","de":"Darüber hinaus sollte diese Spruchrolle dir eine schnellere Reise zurück in unser Lager ermöglichen."}},{"speaker":"npc","text":{"pl":"Na koniec powinieneś jeszcze porozmawiać z Riordianem. To człowiek, który przygotowuje magiczne wywary dla naszego obozu.","en":"Finally, you need to speak to Riordian. He brews the potions for the Camp.","de":"Zu guter Letzt sprich mit Riordian. Er braut die Tränke für das Lager."}},{"speaker":"npc","text":{"pl":"Znajdziesz go w jego chacie, tutaj, na najwyższym poziomie.","en":"You''ll find him in his hut, here, on the upper level.","de":"Du findest ihn in seiner Hütte hier auf der obersten Ebene."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_offer_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_offer_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_OFFER_Info","outputIds":["Info_Saturas_OFFER_15_01","Info_Saturas_OFFER_15_02","Info_Saturas_OFFER_14_03","Info_Saturas_OFFER_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Mógłbym spróbować odnaleźć brakujące kamienie.","en":"I''m willing to find the four remaining focus stones for you!","de":"Ich bin bereit diese vier Foki für euch zu suchen!"}},{"speaker":"hero","text":{"pl":"Koniec końców - mi też zależy na wydostaniu się z tej kolonii.","en":"After all, I''m quite keen on getting out of here sometime myself.","de":"Schließlich will ich auch hier irgendwann wieder raus."}},{"speaker":"npc","text":{"pl":"Muszę cię ostrzec: te poszukiwania mogą się okazać równie trudne co i niebezpieczne.","en":"I must warn you. Searching for them will prove as difficult as it will be dangerous.","de":"Ich muss dich warnen. Die Suche wird gleichermaßen schwierig und gefährlich."}},{"speaker":"npc","text":{"pl":"Konflikt ze Starym Obozem zaostrza się z dnia na dzień. Nie mogę ci nawet przydzielić eskorty Najemników.","en":"Since conflict with the Old Camp is getting worse every day, I cannot give you any mercenary either.","de":"Da die Spannungen mit dem Alten Lager immer stärker werden, kann ich hier auch keinen der Söldner entbehren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_whatnow_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_whatnow_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_WHATNOW_Info","outputIds":["Info_Saturas_WHATNOW_15_01","Info_Saturas_WHATNOW_14_03","Info_Saturas_WHATNOW_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Co teraz zrobicie z tym kamieniem i almanachem?","en":"What are you going to do with the focus and the almanac now?","de":"Was machst du jetzt mit Fokus und Almanach?"}},{"speaker":"npc","text":{"pl":"Nic. Najpierw musimy odnaleźć pozostałe cztery kamienie ogniskujące!","en":"Nothing. We need the four remaining focus stones first!","de":"Nichts. Wir benötigen vorher die vier restlichen Fokussteine!"}},{"speaker":"npc","text":{"pl":"Niestety, nie trafiliśmy jeszcze na ślad żadnego z kamieni.","en":"Unfortunately we don''t have any of these four magic stones.","de":"Dummerweise befindet sich kein einziger dieser vier magischen Steine in unserem Besitz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardas_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardas_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDAS_Info","outputIds":["Info_Saturas_XARDAS_14_05","Info_Saturas_XARDAS_15_06","Info_Saturas_XARDAS_14_07","Info_Saturas_XARDAS_15_08"],"lines":[{"speaker":"npc","text":{"pl":"Wiele lat temu...","en":"Many, many years ago...","de":"Vor vielen, vielen Jahren ..."}},{"speaker":"hero","text":{"pl":"Wolałbym wersję skróconą, jeśli łaska!","en":"Give me the shortened version, please!","de":"Bitte die Kurzform!"}},{"speaker":"npc","text":{"pl":"Bądź cierpliwy. Cóż, kiedy tworzyliśmy magiczną Barierę, nadzorował nas jeszcze jeden, trzynasty mag.","en":"Be patient! Well, when we - the twelve magicians - created the Barrier back then, our magic powers were directed and controlled by a thirteenth magician.","de":"Geduld! Also, als wir - die zwölf Magier - damals die Barriere erschufen, wurden unsere magischen Kräfte von einem 13. Zauberer gelenkt und geleitet."}},{"speaker":"hero","text":{"pl":"Trzynasty mag? Według legendy miało was być tylko dwunastu!","en":"A thirteenth magician? I thought there were only twelve!","de":"Ein 13. Zauberer? Ich dachte, es hätte nur zwölf gegeben!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardas_14_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardas_14_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDAS_Info","outputIds":["Info_Saturas_XARDAS_14_09","Info_Saturas_XARDAS_14_10","Info_Saturas_XARDAS_14_11"],"lines":[{"speaker":"npc","text":{"pl":"Niewielu z żyjących pamięta dokładnie wydarzenia tamtych dni, a my - magowie - woleliśmy nie odświeżać im niepotrzebnie pamięci.","en":"Most people who did not experience the early days of the colony believe that.","de":"Die meisten, die die ersten Tage der Kolonie nicht miterlebt haben, glauben das."}},{"speaker":"npc","text":{"pl":"Ten trzynasty mag był naszym przywódcą. Oczywiście działo się to jeszcze przed podziałem na Kręgi Wody i Ognia.","en":"This thirteenth magician was our leader. All this took place before we were divided into the Circles of Fire and Water.","de":"Dieser 13. Zauberer war einst unser Anführer. Das alles war, bevor wir uns in den Feuer- und Wasserkreis zerstritten haben."}},{"speaker":"npc","text":{"pl":"Tuż po założeniu Starego Obozu - a wtedy był to jeszcze jedyny obóz w kolonii - ów mag postanowił wieść życie samotnika.","en":"But he left the Old Camp, which was once the only camp of the colony.","de":"Doch er verließ das Alte Lager, das damals noch das einzige Lager in der Kolonie war."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardas_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardas_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDAS_Info","outputIds":["Info_Saturas_XARDAS_15_01","Info_Saturas_XARDAS_14_02","Info_Saturas_XARDAS_15_03","Info_Saturas_XARDAS_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Kiedy wysyłałeś mnie do Magów Ognia, wspomniałeś coś o... jeszcze jednym?","en":"When you sent me to the Magicians of Fire, you mentioned there was... SOMEBODY.","de":"Als du mich zu den Feuermagiern schicktest, erwähntest du einen weiteren ... JEMAND"}},{"speaker":"npc","text":{"pl":"Cóż, miałem nadzieję, że obejdziemy się bez jego pomocy, ale w świetle ostatnich wydarzeń...","en":"Well, I had hoped we could make it without his help, but the way things are developing...","de":"Nun, ich hoffte wir würden ohne seine Hilfe auskommen, aber so wie die Dinge stehen ..."}},{"speaker":"hero","text":{"pl":"O kim mówisz?","en":"Who is HE?","de":"Wer ist dieser JEMAND?"}},{"speaker":"npc","text":{"pl":"No dobrze już, dobrze.","en":"Alright, alright!","de":"Also gut, also gut!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardasgo_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardasgo_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASGO_Info","outputIds":["Info_Saturas_XARDASGO_15_01","Info_Saturas_XARDASGO_14_02","Info_Saturas_XARDASGO_14_03","Info_Saturas_XARDASGO_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę przedostać się do Xardasa?","en":"How will I get past his creatures?","de":"Wie werde ich mit seinen Kreaturen fertig?"}},{"speaker":"npc","text":{"pl":"Niestety, nie mam żadnego pomysłu...","en":"If I knew that, I would tell you!","de":"Wenn ich es wüsste, würde ich es dir sagen!"}},{"speaker":"npc","text":{"pl":"Radziłbym ci jednak rozejrzeć się trochę w naszej bibliotece.","en":"I''d advise you to do some research in our library.","de":"Am besten, du betreibst etwas Nachforschung in unserer Bibliothek."}},{"speaker":"npc","text":{"pl":"Może w którejś ze starych ksiąg odnajdziesz jakieś wskazówki co do mocnych i słabych stron istot przywołanych magicznie.","en":"Maybe you''ll find something in the old books about the strengths and weaknesses of magically invoked creatures.","de":"Vielleicht wissen die alten Bücher etwas über Stärken und Schwächen von magisch beschwörten Kreaturen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardashelp_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardashelp_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASHELP_Info","outputIds":["Info_Saturas_XARDASHELP_14_05"],"lines":[{"speaker":"npc","text":{"pl":"Jest jednak inny problem...","en":"There is one other problem...","de":"Da wäre noch ein Problem ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardashelp_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardashelp_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASHELP_Info","outputIds":["Info_Saturas_XARDASHELP_15_01","Info_Saturas_XARDASHELP_14_02","Info_Saturas_XARDASHELP_14_03","Info_Saturas_XARDASHELP_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Spróbuję dotrzeć do tego Xardasa i poproszę go o pomoc!","en":"I''ll make my way to Xardas and ask him for help!","de":"Ich werde zu Xardas aufbrechen und ihn um Hilfe bitten!"}},{"speaker":"npc","text":{"pl":"Tylko on jeden może nas teraz uratować.","en":"He''s the only one that can help us now.","de":"Er ist der einzige, der uns jetzt noch helfen kann."}},{"speaker":"npc","text":{"pl":"A gdyby nawet on nie wiedział, jak nas stąd wydostać, albo nie zechciał nam pomóc...","en":"If he knows no way out or doesn''t want to help us...","de":"Wenn er keinen Rat weiß oder uns nicht helfen will ..."}},{"speaker":"hero","text":{"pl":"BĘDZIE... I ZECHCE!","en":"HE WILL!","de":"ER WIRD!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardasproblem_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardasproblem_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASPROBLEM_Info","outputIds":["Info_Saturas_XARDASPROBLEM_14_05","Info_Saturas_XARDASPROBLEM_14_06","Info_Saturas_XARDASPROBLEM_15_07"],"lines":[{"speaker":"npc","text":{"pl":"Żaden z wysłanych przez nas posłańców nie wrócił z jego wieży.","en":"None of the messengers ever returned from his tower.","de":"Keiner der Boten kehrte je von seinem Turm zurück."}},{"speaker":"npc","text":{"pl":"Musisz znaleźć jakiś sposób, aby przedrzeć się przez strażników Xardasa.","en":"You''ll have to find a way to get past his creatures.","de":"Du wirst einen Weg finden müssen, an seinen Kreaturen vorbeizukommen."}},{"speaker":"hero","text":{"pl":"Widzę, że szykuje się nie lada wyprawa!","en":"Looks like this is going to be interesting!","de":"Es scheint also weiterhin interessant zu bleiben!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardasproblem_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardasproblem_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASPROBLEM_Info","outputIds":["Info_Saturas_XARDASPROBLEM_15_01","Info_Saturas_XARDASPROBLEM_14_02","Info_Saturas_XARDASPROBLEM_14_03","Info_Saturas_XARDASPROBLEM_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Mianowicie?","en":"A problem?","de":"Ein Problem?"}},{"speaker":"npc","text":{"pl":"Cóż, przez te wszystkie lata kilkakrotnie próbowaliśmy nawiązać z Xardasem jakiś kontakt.","en":"Yes. Over the years we have tried to get in touch with Xardas several times.","de":"Ja. Wir haben in den vergangenen Jahren öfters versucht, mit Xardas Kontakt aufzunehmen."}},{"speaker":"npc","text":{"pl":"Ale wygląda na to, że nie życzy sobie, żeby mu przeszkadzano.","en":"But it looks like he prefers to remain undisturbed.","de":"Doch er scheint wohl lieber ungestört zu bleiben."}},{"speaker":"hero","text":{"pl":"Co chcesz przez to powiedzieć?","en":"What does that mean?","de":"Was bedeutet das?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardaswhere_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardaswhere_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASWHERE_Info","outputIds":["Info_Saturas_XARDASWHERE_15_01","Info_Saturas_XARDASWHERE_14_02","Info_Saturas_XARDASWHERE_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Wiesz może, gdzie podziewa się teraz ten trzynasty mag?","en":"Where is this magician today?","de":"Wo kann man diesen Zauberer finden?"}},{"speaker":"npc","text":{"pl":"Żyje w odosobnieniu, w swej wieży, gdzieś na terytoriach kontrolowanych przez Orków.","en":"He lives in seclusion, in his tower in the middle of the Orc land.","de":"Er lebt heute zurückgezogen in seinem Turm mitten im Orkgebiet."}},{"speaker":"npc","text":{"pl":"To chyba najdalej wysunięty na południe punkt całej kolonii.","en":"That''s just about the southernmost point of the colony.","de":"Das ist so ziemlich der südlichste Ort der Kolonie."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardaswho_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardaswho_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASWHO_Info","outputIds":["Info_Saturas_XARDASWHO_15_01","Info_Saturas_XARDASWHO_14_02","Info_Saturas_XARDASWHO_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak ma na imię ten trzynasty mag?","en":"What is this thirteenth magician called?","de":"Wie heißt dieser 13. Zauberer?"}},{"speaker":"npc","text":{"pl":"Nazywał się Xardas. Dzisiaj już tylko garstka ludzi pamięta o jego istnieniu.","en":"His name is Xardas. Hardly anybody remembers the old stories about him!","de":"Sein Name ist Xardas. Kaum einer kennt noch die alten Geschichten über ihn!"}},{"speaker":"npc","text":{"pl":"Ale ci, którzy go znali, nazywali go po prostu NEKROMANTĄ!","en":"The ones who do just call him the NECROMANCER!","de":"Die, die es tun, nennen ihn nur den DÄMONENBESCHWÖRER!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardaswhy_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardaswhy_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASWHY_Info","outputIds":["Info_Saturas_XARDASWHY_14_05"],"lines":[{"speaker":"npc","text":{"pl":"W odróżnieniu od Gomeza, Xardas nie był rzeźnikiem i wolał uniknąć otwartego konfliktu. Pewnego dnia opuścił Obóz.","en":"Unlike Gomez, he was no butcher, so he avoided the conflict and left.","de":"Er war - anders als Gomez - kein Schlächter, also ging er dem Konflikt aus dem Weg und verließ die anderen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_xardaswhy_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_xardaswhy_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_XARDASWHY_Info","outputIds":["Info_Saturas_XARDASWHY_15_01","Info_Saturas_XARDASWHY_14_02","Info_Saturas_XARDASWHY_14_03","Info_Saturas_XARDASWHY_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego opuścił Stary Obóz?","en":"Why did he leave the Old Camp?","de":"Warum verließ er das Alte Lager?"}},{"speaker":"npc","text":{"pl":"Xardas chciał kontynuować swe badania nad przyzywaniem ożywieńców i istot z innych wymiarów.","en":"He started to investigate the invocation of undead and magical creatures.","de":"Er begann sich intensiv mit der Beschwörung untoter und magischer Wesen zu beschäftigen."}},{"speaker":"npc","text":{"pl":"Nie tylko Gomez zaczął się tym niepokoić. Pozostali magowie również krzywo patrzyli na niego i jego plugawe badania.","en":"Gomez was not the only one who began to worry. Most of the other magicians opposed him as well and his unholy deeds.","de":"Das beunruhigte nicht nur Gomez. Selbst die meisten der anderen Magier lehnten sich gegen ihn und sein unheiliges Treiben auf."}},{"speaker":"hero","text":{"pl":"I co się z nim stało?","en":"What happened then?","de":"Was passierte dann?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_yberion_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_yberion_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_YBERION_Info","outputIds":["Info_Saturas_YBERION_14_05","Info_Saturas_YBERION_15_06","Info_Saturas_YBERION_15_07","Info_Saturas_YBERION_15_08"],"lines":[{"speaker":"npc","text":{"pl":"Jak to możliwe? Był najważniejszym członkiem Bractwa, zaraz po Y''Berionie!","en":"Why is that? He was in second place after Y''Berion!","de":"Warum das? Er war doch der zweite Mann nach Y''Berion!"}},{"speaker":"hero","text":{"pl":"Pewne wydarzenia uświadomiły wszystkim Guru, że droga, którą podążali była błędna. Ich rzekomy bóg okazał się niszczycielskim demonem.","en":"Certain events have convinced the Gurus that their way is the wrong one. Their god seems to be an evil arch demon.","de":"Gewisse Ereignisse haben die Gurus davon überzeugt, dass der Weg ihres Gottes der falsche ist. Er scheint ein Erzdämon zu sein, der nur Böses im Schilde führt."}},{"speaker":"hero","text":{"pl":"Pod wpływem Śniącego, jeden z Guru próbował mnie zgładzić, mimo, iż kilka chwil wcześniej ocaliłem jego życie.","en":"One of the Gurus nearly killed me under the influence of the Sleeper, although I had saved his life just briefly beforehand.","de":"Einer der Gurus hat mich unter dem Einfluss des Schläfers fast umgebracht, obwohl ich eben diesem Mann kurz zuvor das Leben gerettet hatte."}},{"speaker":"hero","text":{"pl":"Cor Kalom był jedynym Guru, który nie chciał uznać prawdziwej natury Śniącego. Właśnie dlatego opuścił obóz na bagnie.","en":"Cor Kalom was the only Guru who didn''t want to admit the true nature of the hellish creature, that''s why he''s left the camp in the swamp.","de":"Cor Kalom war der einzige Guru, der die wahre Natur der Höllenkreatur nicht sehen wollte und hat daher das Lager im Sumpf verlassen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_yberion_14_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_yberion_14_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_YBERION_Info","outputIds":["Info_Saturas_YBERION_14_09","Info_Saturas_YBERION_14_10"],"lines":[{"speaker":"npc","text":{"pl":"Rozumiem! Cóż, przynajmniej tutaj mamy trochę szczęścia. Cor Angar to dobry człowiek. Twardy, ale uczciwy.","en":"I see! Well, at least we are lucky in this regard. Cor Angar is a good man. He''s tough, but honest.","de":"Ich verstehe! Nun, das ist Glück im Unglück, denn Cor Angar ist ein guter Mann. Hart, aber ehrlich."}},{"speaker":"npc","text":{"pl":"Jeśli ktoś może zapobiec całkowitemu rozpadowi Bractwa po tej katastrofie, to właśnie on.","en":"If anybody could prevent the Brotherhood from falling apart after this spiritual catastrophe, he can.","de":"Wenn jemand den Zerfall der Bruderschaft nach dieser spirituellen Katastrophe verhindern kann, ist er es."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_info_saturas_yberion_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_info_saturas_yberion_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"Info_Saturas_YBERION_Info","outputIds":["Info_Saturas_YBERION_15_01","Info_Saturas_YBERION_14_02","Info_Saturas_YBERION_14_03","Info_Saturas_YBERION_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Y''Berion nie żyje! Zginął podczas rytuału przyzwania Śniącego.","en":"Y''Berion is dead! He died during the ritual invocation of the Sleeper.","de":"Y''Berion ist tot! Er starb bei einer großen rituellen Anrufung des Schläfers."}},{"speaker":"npc","text":{"pl":"Y''Berion martwy? To złe wieści... Bardzo złe.","en":"Y''Berion dead? That''s bad news, very bad news indeed!","de":"Y''Berion tot? Das sind schlechte Nachrichten, sehr schlechte Nachrichten!"}},{"speaker":"npc","text":{"pl":"Kto teraz przewodzi Bractwu? Czyżby ten zbyt ambitny, jadowity wąż - Cor Kalom?","en":"Who''s leading the Brotherhood now? That power-hungry and deceitful Cor Kalom?","de":"Wer hat die Führung der Bruderschaft übernommen? Dieser machtgierige, verschlagene Cor Kalom?"}},{"speaker":"hero","text":{"pl":"Nie! Kalom wyrzekł się Bractwa. Zabrał ze sobą kilku Strażników Świątynnych. Nikt nie wie dokąd się udali.","en":"No! Kalom has turned his back on the Brotherhood. He''s taken some templars with him. Nobody knows where they''ve gone.","de":"Nein! Kalom hat der Bruderschaft den Rücken gekehrt. Er hat einige Templer mitgenommen. Niemand weiß, wohin sie aufgebrochen sind."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_gotolee_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_gotolee_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_GOTOLEE_Info","outputIds":["KDW_600_Saturas_GOTOLEE_Info_15_01","KDW_600_Saturas_GOTOLEE_Info_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Czy to oznacza, że zostanę przyjęty w poczet Najemników?","en":"Does that mean the mercenaries will take me on?","de":"Heißt das, die Söldner werden mich aufnehmen?"}},{"speaker":"npc","text":{"pl":"Porozmawiaj z Lee. On się tobą zajmie. Ale potem zajrzyj koniecznie do mnie!","en":"Talk to Lee. He''ll see to it. Then come back to me.","de":"Sprich mit Lee. Er wird sich darum kümmern. Danach komm wieder zu mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_hoge_aufnahme_15_00_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_hoge_aufnahme_15_00_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_HogeAUFNAHME_Info","outputIds":["KDW_600_Saturas_HogeAUFNAHME_15_00","KDW_600_Saturas_NOMOREOC_Info_14_03","KDW_600_Saturas_OATH_Info_15_01","KDW_600_Saturas_OATH_Info_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Nefarius powiedział, że mogę już założyć szatę Maga Wody.","en":"Nefarius said I was ready to wear the robe of a Magician of Water.","de":"Nefarius sagte, ich sei bereit die Robe der Wassermagier zu tragen."}},{"speaker":"npc","text":{"pl":"Zatem witaj w naszej społeczności!","en":"Then I welcome you to our community.","de":"Dann heiße ich dich in unserer Gemeinschaft willkommen."}},{"speaker":"hero","text":{"pl":"Czy to oznacza, że należę teraz do kręgu Magów Wody?","en":"Does that mean that I now belong to the guild of the Magicians of the Water?","de":"Heißt das, ich gehöre jetzt in die Gilde der Wassermagier?"}},{"speaker":"npc","text":{"pl":"Jeszcze nie. Najpierw musisz złożyć śluby Wody.","en":"Not yet. First you need to take the oath of Water.","de":"Noch nicht. Du musst erst den Eid des Wassers ablegen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_14_06_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_14_06_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_HogeAUFNAHMETeil2_Info","outputIds":["KDW_600_Saturas_KDWAUFNAHME_Info_14_06","KDW_600_Saturas_KDWAUFNAHME_Info_15_07","KDW_600_Saturas_KDWAUFNAHME_Info_14_08","KDW_600_Saturas_KDWAUFNAHME_Info_15_09"],"lines":[{"speaker":"npc","text":{"pl":"...Przysięgam, na potęgę świętej Wody...","en":"... and by the power of the holy Water...","de":"...und bei der Kraft des heiligen Wassers..."}},{"speaker":"hero","text":{"pl":"...Przysięgam, na potęgę świętej Wody...","en":"... and by the power of the holy Water...","de":"...und bei der Kraft des heiligen Wassers..."}},{"speaker":"npc","text":{"pl":"...Że ma wiedza i me czyny teraz i na wieki stanowić będą jedność z Wodą...","en":"... that my knowledge and my deeds from now on and forever shall be one with the Water...","de":"...dass mein Wissen und Handeln von nun an und auf ewig mit dem Wasser verbunden sei..."}},{"speaker":"hero","text":{"pl":"...Że ma wiedza i me czyny teraz i na wieki stanowić będą jedność z Wodą...","en":"... that my knowledge and my deeds from now on and forever shall be one with the Water...","de":"...dass mein Wissen und Handeln von nun an und auf ewig mit dem Wasser verbunden sei..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_14_10_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_14_10_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_HogeAUFNAHMETeil2_Info","outputIds":["KDW_600_Saturas_KDWAUFNAHME_Info_14_10","KDW_600_Saturas_KDWAUFNAHME_Info_15_11","KDW_600_Saturas_KDWAUFNAHME_Info_14_14"],"lines":[{"speaker":"npc","text":{"pl":"...Dopóki me ciało nie powróci do królestwa Beliara, gdy źródło mego życia wyschnie.","en":"... until my body shall return to the realm of Beliar and the source of my life shall dry out.","de":"...bis ich einkehre in Beliars Reich und der Quell des Lebens versiegt."}},{"speaker":"hero","text":{"pl":"...Dopóki me ciało nie powróci do królestwa Beliara, gdy źródło mego życia wyschnie.","en":"... until my body shall return to the realm of Beliar and the source of my life shall dry out.","de":"...bis ich einkehre in Beliars Reich und der Quell des Lebens versiegt."}},{"speaker":"npc","text":{"pl":"Noś tę szatę, jako symbol twojego przymierza ze świętą Wodą i wszechmocnym Adanosem.","en":"Wear this robe as a sign of your bond with the holy Water and with Adanos.","de":"Trage diese Robe als Zeichen deiner Verbundenheit zum heiligen Wasser und zu Adanos."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_14_13_12', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_14_13_12","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KDWAUFNAHME_Info","outputIds":["KDW_600_Saturas_KDWAUFNAHME_Info_14_13","KDW_600_Saturas_KDWAUFNAHME_Info_14_14"],"lines":[{"speaker":"npc","text":{"pl":"Połączyłeś teraz to, co niegdyś rozdzielono. Niech twe życie i czyny będą znakiem zjednoczenia potęgi żywiołów.","en":"You have now bound together what was apart before. May your life be a sign of the unification of the elements.","de":"Du verbindest das, was vorher getrennt war. Möge dein Leben ein Zeichen des Bundes der Elemente sein."}},{"speaker":"npc","text":{"pl":"Noś tę szatę, jako symbol twojego przymierza ze świętą Wodą i wszechmocnym Adanosem.","en":"Wear this robe as a sign of your bond with the holy Water and with Adanos.","de":"Trage diese Robe als Zeichen deiner Verbundenheit zum heiligen Wasser und zu Adanos."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_HogeAUFNAHMETeil2_Info","outputIds":["KDW_600_Saturas_KDWAUFNAHME_Info_15_01","KDW_600_Saturas_KDWAUFNAHME_Info_14_03","KDW_600_Saturas_KDWAUFNAHME_Info_14_04","KDW_600_Saturas_KDWAUFNAHME_Info_15_05"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów do złożenia ślubów.","en":"I''m ready to take the oath.","de":"Ich bin bereit, den Eid abzulegen."}},{"speaker":"npc","text":{"pl":"Powtarzaj za mną słowa przysięgi:","en":"Now speak the words of the oath:","de":"Sprich nun die Worte des Eides:"}},{"speaker":"npc","text":{"pl":"Przysięgam, na wszechmocnych bogów...","en":"I swear by the might of the gods...","de":"Ich schwöre bei den Mächten der Götter..."}},{"speaker":"hero","text":{"pl":"Przysięgam, na wszechmocnych bogów...","en":"I swear by the might of the gods...","de":"Ich schwöre bei den Mächten der Götter..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_15_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_15_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KDWAUFNAHME_Info","outputIds":["KDW_600_Saturas_KDWAUFNAHME_Info_15_05","KDW_600_Saturas_KDWAUFNAHME_Info_14_06","KDW_600_Saturas_KDWAUFNAHME_Info_15_07","KDW_600_Saturas_KDWAUFNAHME_Info_14_08"],"lines":[{"speaker":"hero","text":{"pl":"Przysięgam, na wszechmocnych bogów...","en":"I swear by the might of the gods...","de":"Ich schwöre bei den Mächten der Götter ..."}},{"speaker":"npc","text":{"pl":"...Przysięgam, na potęgę świętej Wody...","en":"... and by the power of the holy Water...","de":"... und bei der Kraft des heiligen Wassers ..."}},{"speaker":"hero","text":{"pl":"...Przysięgam, na potęgę świętej Wody...","en":"... and by the power of the holy Water...","de":"... und bei der Kraft des heiligen Wassers ..."}},{"speaker":"npc","text":{"pl":"...Że ma wiedza i me czyny teraz i na wieki stanowić będą jedność z Wodą...","en":"... that my knowledge and my deeds from now on and forever shall be one with the Water...","de":"... dass mein Wissen und Handeln von nun an und auf ewig mit dem Wasser verbunden sei ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_15_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kdwaufnahme_info_15_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KDWAUFNAHME_Info","outputIds":["KDW_600_Saturas_KDWAUFNAHME_Info_15_09","KDW_600_Saturas_KDWAUFNAHME_Info_14_10","KDW_600_Saturas_KDWAUFNAHME_Info_15_11","KDW_600_Saturas_KDWAUFNAHME_Info_14_12"],"lines":[{"speaker":"hero","text":{"pl":"...Że ma wiedza i me czyny teraz i na wieki stanowić będą jedność z Wodą...","en":"... that my knowledge and my deeds from now on and forever shall be one with the Water...","de":"... dass mein Wissen und Handeln von nun an und auf ewig mit dem Wasser verbunden sei ..."}},{"speaker":"npc","text":{"pl":"...Dopóki me ciało nie powróci do królestwa Beliara, gdy źródło mego życia wyschnie.","en":"... until my body shall return to the realm of Beliar and the source of my life shall dry out.","de":"... bis ich einkehre in Beliars Reich und der Quell des Lebens versiegt."}},{"speaker":"hero","text":{"pl":"...Dopóki me ciało nie powróci do królestwa Beliara, gdy źródło mego życia wyschnie.","en":"... until my body shall return to the realm of Beliar and the source of my life shall dry out.","de":"... bis ich einkehre in Beliars Reich und der Quell des Lebens versiegt."}},{"speaker":"npc","text":{"pl":"Składając tę przysięgę zjednoczyłeś w sobie potęgę Ognia i błogosławieństwo Wody.","en":"With this oath you unite the power of the Fire and the blessing of the Water within you.","de":"Mit diesem Schwur einst du die Kraft des Feuers und den Segen des Wassers in dir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis1_info_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis1_info_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS1_Info","outputIds":["KDW_600_Saturas_KREIS1_Info_14_05","KDW_600_Saturas_KREIS1_Info_14_06","KDW_600_Saturas_KREIS1_Info_14_07","KDW_600_Saturas_KREIS1_Info_14_08"],"lines":[{"speaker":"npc","text":{"pl":"W odróżnieniu od magicznych zwojów zawierających formuły zaklęć, magia zawarta w runach jest trwała.","en":"But in contrast to the magic scrolls, which are magic formulas as well, the magic power of the rune ensures that the structure of the spell endures.","de":"Doch anders als Spruchrollen, die auch eine Zauberformel sind, sorgt die magische Kraft, die der Rune innewohnt, dafür, dass die Struktur des Zaubers erhalten bleibt."}},{"speaker":"npc","text":{"pl":"Runy są źródłem czarodziejskiej mocy, na którym możesz polegać w każdej sytuacji.","en":"Every rune is a source of magic power which you can fall back on anytime.","de":"Jede Rune ist eine Quelle magischer Kraft, auf die du immer wieder zurückgreifen kannst."}},{"speaker":"npc","text":{"pl":"Twoja własna magia potrzebna jest podczas korzystania z run tak samo, jak gdy korzystasz z magicznych zwojów.","en":"Your own magic power is used up when you use a rune, just as with a spell scroll.","de":"Deine eigene magische Kraft verbraucht sich beim Benutzen der Rune, wie bei einer Spruchrolle."}},{"speaker":"npc","text":{"pl":"W miarę awansowania do kolejnych Kręgów, będziesz poznawał nowe runy.","en":"With every Circle you enter, you learn to use further runes as well.","de":"Mit jedem Kreis, den du lernst, lernst du auch die Möglichkeit, weitere Runen zu benutzen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis1_info_14_09_8', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis1_info_14_09_8","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS1_Info","outputIds":["KDW_600_Saturas_KREIS1_Info_14_09"],"lines":[{"speaker":"npc","text":{"pl":"Wykorzystaj drzemiącą w runach moc do poznania samego siebie.","en":"Use the power of the runes to recognize yourself.","de":"Nutze die Kraft der Runen, um dich selber zu erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis1_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis1_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS1_Info","outputIds":["KDW_600_Saturas_KREIS1_Info_15_01","KDW_600_Saturas_KREIS1_Info_14_02","KDW_600_Saturas_KREIS1_Info_14_03","KDW_600_Saturas_KREIS1_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów, by przystąpić do Pierwszego Kręgu.","en":"I am ready to enter the First Circle.","de":"Ich bin bereit, in den ersten Kreis aufgenommen zu werden."}},{"speaker":"npc","text":{"pl":"Przystąpienie do Pierwszego Kręgu wiąże się z poznaniem tajników magii runicznej.","en":"To enter the first of the magic Circles means learning to use magic runes.","de":"Den ersten der magischen Kreise zu betreten, bedeutet die Anwendung magischer Runen lernen."}},{"speaker":"npc","text":{"pl":"Każda runa zawiera esencję szczególnego zaklęcia magicznego.","en":"Each rune contains the structure of a special magic spell.","de":"Jede Rune birgt in sich die Struktur eines speziellen Zaubers."}},{"speaker":"npc","text":{"pl":"Wykorzystując swoje zdolności magiczne, będziesz w stanie ją uwolnić.","en":"By using your own magic powers, you''ll be able to cast the magic of the rune.","de":"Durch den Einsatz deiner eigenen magischen Energie, bist du in der Lage, den Zauber der Rune zu wirken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis2_info_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis2_info_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS2_Info","outputIds":["KDW_600_Saturas_KREIS2_Info_14_05","KDW_600_Saturas_KREIS2_Info_14_06","KDW_600_Saturas_KREIS2_Info_14_07","KDW_600_Saturas_KREIS2_Info_14_08"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz już, że runy mogą być wykorzystywane do chwili wyczerpania twoich własnych pokładów siły magicznej.","en":"You know that you can use every rune as often as you like until you''ve used up all your own powers.","de":"Du weißt, dass du jede Rune solange einsetzen kannst, bis deine eigene Kraft verbraucht ist."}},{"speaker":"npc","text":{"pl":"Jednak zanim przystąpisz do działania, zastanów się nad celem, jaki ci przyświeca. Moce, którymi będziesz dysponował mogą nieść śmierć i zniszczenie.","en":"But before you act, think about the point of your actions. You have obtained powers with which you may easily conjure up death and destruction.","de":"Aber frage dich, ob es sinnvoll ist. Du hast Macht verliehen bekommen, mit der es dir ein Leichtes ist, Tod und Verderben zu bringen."}},{"speaker":"npc","text":{"pl":"Ale prawdziwy mag wykorzystuje swoje zdolności tylko wtedy, gdy jest to absolutnie niezbędne.","en":"But a true magician only uses magic when it is necessary.","de":"Doch der wahrhafte Magier zaubert nur dann, wenn es angebracht ist."}},{"speaker":"npc","text":{"pl":"Kiedy w pełni uświadomisz sobie ten fakt, zrozumiesz prawdę kryjącą się za magią runiczną.","en":"Understand the situation, then you''ll recognize the power of the runes.","de":"Erkenne die Situation, dann wirst du die Macht der Runen erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis2_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis2_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS2_Info","outputIds":["KDW_600_Saturas_KREIS2_Info_15_01","KDW_600_Saturas_KREIS2_Info_14_02","KDW_600_Saturas_KREIS2_Info_14_03","KDW_600_Saturas_KREIS2_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy do przystąpienia do Drugiego Kręgu.","en":"I am ready to enter the Second Circle.","de":"Ich bin bereit, in den zweiten Kreis aufgenommen zu werden."}},{"speaker":"npc","text":{"pl":"Poznałeś już magiczną naturę języka runicznego. Teraz zgłębisz jego tajniki.","en":"You have learned to understand the runes. Now it is time to deepen this understanding.","de":"Du hast das Verständnis der Runen gelernt. Nun ist es an der Zeit, dieses Verständnis zu vertiefen."}},{"speaker":"npc","text":{"pl":"Po przystąpieniu do Drugiego Kręgu poznasz silniejsze zaklęcia ofensywne oraz tajemnicę magii uzdrawiającej.","en":"When you join the Second Circle you will learn the foundations of stronger battle spells, and above all the secret of healing.","de":"Mit dem zweiten Kreis lernst du die Grundsätze stärkerer Kampfzauber und vor allem das Geheimnis der Heilung."}},{"speaker":"npc","text":{"pl":"Musisz się jeszcze wiele nauczyć, zanim dane ci będzie poznać prawdziwe oblicze magii.","en":"But you need to learn much if you want to recognize the true secrets of magic.","de":"Doch du musst noch viel lernen, willst du die tatsächlichen Geheimnisse der Magie ergründen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis3_info_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis3_info_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS3_Info","outputIds":["KDW_600_Saturas_KREIS3_Info_14_05","KDW_600_Saturas_KREIS3_Info_14_06","KDW_600_Saturas_KREIS3_Info_14_07"],"lines":[{"speaker":"npc","text":{"pl":"To, czy z niej skorzystasz, czy nie, powinno zależeć wyłącznie od ciebie.","en":"You may use a rune or not. But you must decide on one of these possibilities.","de":"Du kannst eine Rune nutzen oder nicht. Aber entscheide dich für eine der Möglichkeiten."}},{"speaker":"npc","text":{"pl":"Wybór, którego dokonasz, musi być ostateczny. W magii nie ma miejsca na wahanie.","en":"Do not hesitate to use your powers as soon as you''ve made your choice.","de":"Zögere nicht, deine Macht einzusetzen, wenn du dich einmal entschieden hast."}},{"speaker":"npc","text":{"pl":"Wyobraź sobie wyraźnie ścieżkę, którą chcesz kroczyć i ponieś wszelkie konsekwencje swojego wyboru.","en":"Understand your path, then you''ll recognize the power of the decision.","de":"Erkenne deinen Weg, dann wirst du die Macht der Entscheidung erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis3_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis3_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS3_Info","outputIds":["KDW_600_Saturas_KREIS3_Info_15_01","KDW_600_Saturas_KREIS3_Info_14_02","KDW_600_Saturas_KREIS3_Info_14_03","KDW_600_Saturas_KREIS3_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie wprowadzić w arkana Trzeciego Kręgu?","en":"Could you teach me the Third Circle?","de":"Ich bin bereit, den dritten Kreis zu betreten"}},{"speaker":"npc","text":{"pl":"Trzeci Krąg to jeden z najważniejszych etapów w życiu każdego maga. Przystępując do niego przestajesz być uczniem.","en":"The Third Circle of Magic is one of the most important steps in the life of a magician. Once you''ve reached it, you cease to be a seeker.","de":"Der dritte Kreis der Magie ist einer der wichtigsten Schritte im Leben eines Magiers. Nicht länger bist du ein Suchender."}},{"speaker":"npc","text":{"pl":"Zaszedłeś już bardzo daleko na ścieżce magii. Potrafisz posługiwać się runami.","en":"You have already come far on the path of magic. You have learned to use the runes.","de":"Du bist bereits ein Stück des magischen Weges gegangen. Du hast gelernt die Runen zu nutzen."}},{"speaker":"npc","text":{"pl":"Ta wiedza posłuży za fundament twojej dalszej nauki. Używaj magii runicznej świadomie i z rozwagą.","en":"This knowledge is the foundation for your further path. Use the runes with deliberation.","de":"Dieses Wissen ist das Fundament für deinen weiteren Weg. Nutze die Runen mit Bedacht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis4_info_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis4_info_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS4_Info","outputIds":["KDW_600_Saturas_KREIS4_Info_14_05","KDW_600_Saturas_KREIS4_Info_14_06","KDW_600_Saturas_KREIS4_Info_14_07"],"lines":[{"speaker":"npc","text":{"pl":"Z twoją znajomością magii runicznej, cała wiedza zgromadzona przez wszystkie świątynie w tym królestwie stoi przed tobą otworem.","en":"With the runes you control now, you have the entire knowledge of the temples of the realm at your fingertips.","de":"Mit allen Runen, die du nun beherrschen kannst, steht dir das gesammelte Wissen der Tempel des Reiches zur Verfügung."}},{"speaker":"npc","text":{"pl":"Du hast jetzt alles gelernt, was ich dir beibringen kann.","en":"Du hast jetzt alles gelernt, was ich dir beibringen kann.","de":"Du hast jetzt alles gelernt, was ich dir beibringen kann."}},{"speaker":"npc","text":{"pl":"Pamiętaj: poznanie natury magii jest kluczem do poznania natury potęgi i władzy.","en":"Understand the magic, then you''ll discover the secret of power.","de":"Erkenne die Magie, dann wirst du das Geheimnis von Macht erkennen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis4_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis4_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS4_Info","outputIds":["KDW_600_Saturas_KREIS4_Info_15_01","KDW_600_Saturas_KREIS4_Info_14_02","KDW_600_Saturas_KREIS4_Info_14_03","KDW_600_Saturas_KREIS4_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy do przystąpienia do Czwartego Kręgu.","en":"I am ready to enter the Fourth Circle.","de":"Ich bin bereit für den vierten der Kreise."}},{"speaker":"npc","text":{"pl":"Ukończyłeś już pierwsze trzy Kręgi. Nadeszła pora, byś zgłębił prawdziwą naturę magii.","en":"You have completed the first three Circles. Now is the time for you to learn the secrets of magic.","de":"Du hast die ersten drei Kreise durchschritten. Nun ist es an der Zeit, dass du die Geheimnisse der Magie kennen lernst."}},{"speaker":"npc","text":{"pl":"Magia runiczna jest zaklęta w kamieniu. W końcu runy to fragmenty magicznej rudy.","en":"The magic of the runes is based on the stone. They are magic stones, created out of magic ore.","de":"Die Magie der Runen ruht in ihrem Stein. Es sind magische Steine, gewonnen aus magischem Erz."}},{"speaker":"npc","text":{"pl":"Tej samej rudy, która wydobywana jest w kopalniach. Z pomocą bogów runy nasycane są magią w naszych świątyniach stając się narzędziem naszej potęgi.","en":"It is the same ore which is collected in the mines. This ore is endowed with magic formulas in the temples. There the runes are converted to the instruments of our power.","de":"Das gleiche Erz, das hier abgebaut wird. Dieses Erz wird in den Tempeln mit den Formeln der Magie versehen. Dort werden die Runen zu den Instrumenten unserer Macht geformt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis5_info_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis5_info_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS5_Info","outputIds":["KDW_600_Saturas_KREIS5_Info_14_05","KDW_600_Saturas_KREIS4_Info_14_06","KDW_600_Saturas_KREIS5_Info_14_06"],"lines":[{"speaker":"npc","text":{"pl":"Staraj się nie wykorzystywać magii tego rodzaju bez potrzeby. Jest ona darem od boga ciemności!","en":"Be careful to use this kind of magic as little as possible. It''s a gift from the god of darkness.","de":"Hüte dich vor dem Einsatz dieser Magie. Sie ist eine Gabe des dunklen Gottes."}},{"speaker":"npc","text":{"pl":"Nauczyłem cię wszystkiego, co sam potrafię.","en":"You have now learned everything I can teach you.","de":"Du hast jetzt alles gelernt, was ich dir beibringen kann."}},{"speaker":"npc","text":{"pl":"Poznaj granice swoich możliwości, a poznasz samego siebie.","en":"Expose your limits, then you''ll recognize your true power.","de":"Erkenne deine Grenzen, dann wirst du deine wahre Macht erkennen"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_kreis5_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_kreis5_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_KREIS5_Info","outputIds":["KDW_600_Saturas_KREIS5_Info_15_01","KDW_600_Saturas_KREIS5_Info_14_02","KDW_600_Saturas_KREIS5_Info_14_03","KDW_600_Saturas_KREIS5_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotów do przystąpienia do Piątego Kręgu.","en":"I am ready to enter the Fifth Circle.","de":"Ich bin bereit für den fünften Kreis."}},{"speaker":"npc","text":{"pl":"Dobrze. Wprowadzę cię w arkana Piątego Kręgu Magii.","en":"So be it. I shall teach you the power of the Fifth Circle.","de":"So soll es geschehen. Ich werde dich die Macht des fünften Kreises lehren."}},{"speaker":"npc","text":{"pl":"Od tej pory będziesz mógł wykorzystywać magiczne runy zaklęć Ognistej Burzy i Lodowej Fali oraz posiądziesz moc niszczenia Ożywieńców.","en":"The Storm of Fire, the Wave of Ice and the power to destroy the undead are now spells whose runes you can use.","de":"Der Sturm des Feuers, die Welle aus Eis und die Macht, Untote zu vernichten, sind wahrhaft mächtige Sprüche, deren Runen dir nun untertan sind."}},{"speaker":"npc","text":{"pl":"Jednak najpotężniejszym zaklęciem Piątego Kręgu Magii jest Tchnienie Śmierci. Gdyby udało ci się kiedyś odnaleźć tę runę, dysponowałbyś niewyobrażalną mocą.","en":"But the mightiest spell of the Fifth Circle is the Ripple of Death. If you ever possess this rune, you''ll have dangerous powers.","de":"Doch der mächtigste Zauber des fünften Kreises ist die Welle des Todes. Solltest du in den Besitz dieser Rune gelangen, dann bist du im Besitz gefährlicher Macht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_lesson_info_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_lesson_info_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_LESSON_Info","outputIds":["KDW_600_Saturas_LESSON_Info_14_05"],"lines":[{"speaker":"npc","text":{"pl":"Więcej nie jestem w stanie cię nauczyć!","en":"I can''t teach you any more!","de":"Ich kann dir nichts mehr beibringen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_lesson_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_lesson_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_LESSON_Info","outputIds":["KDW_600_Saturas_LESSON_Info_15_01","KDW_600_Saturas_LESSON_Info_14_02","KDW_600_Saturas_LESSON_Info_14_03","KDW_600_Saturas_LESSON_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie czegoś nauczyć?","en":"Can you instruct me?","de":"Kannst du mich unterrichten?"}},{"speaker":"npc","text":{"pl":"Przed tobą jeszcze wiele nauki. Rozpoczniemy zajęcia, gdy będziesz gotów.","en":"There''s much you need to learn. I shall teach you as soon as you''re ready.","de":"Es gibt noch viel zu lernen für dich. Wenn du bereit bist, werde ich dich unterrichten."}},{"speaker":"npc","text":{"pl":"Jest jeszcze jeden Krąg, o którym nie wiesz. Opowiem ci o nim, gdy będziesz gotów.","en":"There is one more Circle you don''t know yet. I shall teach you as soon as you''re ready.","de":"Es gibt noch einen weiteren Kreis, den du nicht kennst. Wenn du bereit bist, werde ich dich unterrichten."}},{"speaker":"npc","text":{"pl":"Opanowałeś już umiejętności z Piątego Kręgu magii. Nauczyłem cię wszystkiego co sam wiem.","en":"You have already mastered the Fifth Circle of Magic! You know all I know.","de":"Du beherrscht bereits den fünften Kreis der Magie! Du weißt alles, was ich weiß."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_nomoreoc_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_nomoreoc_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_NOMOREOC_Info","outputIds":["KDW_600_Saturas_NOMOREOC_Info_15_01","KDW_600_Saturas_NOMOREOC_Info_14_02","KDW_600_Saturas_NOMOREOC_Info_14_03"],"lines":[{"speaker":"hero","text":{"pl":"Wygnano mnie ze Starego Obozu za to, że wam pomogłem!","en":"I have been exiled from the Old Camp because I have helped you!","de":"Das Alte Lager hat mich verbannt, weil ich euch geholfen habe!"}},{"speaker":"npc","text":{"pl":"Nie należysz już do Starego Obozu?","en":"You don''t belong to the Old Camp any longer?","de":"Du gehörst nicht länger zum Alten Lager?"}},{"speaker":"npc","text":{"pl":"Zatem witaj w naszej społeczności!","en":"Then I welcome you to our community.","de":"Dann heiße ich dich in unserer Gemeinschaft willkommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_oath_info_14_05_4', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_oath_info_14_05_4","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_OATH_Info","outputIds":["KDW_600_Saturas_OATH_Info_14_05","KDW_600_Saturas_OATH_Info_15_06","KDW_600_Saturas_OATH_Info_14_07","KDW_600_Saturas_OATH_Info_14_08"],"lines":[{"speaker":"npc","text":{"pl":"Przecież nie musisz jednocześnie łamać złożonej przysięgi!","en":"It doesn''t mean you''re breaking your vow!","de":"Du brichst den Schwur ja nicht!"}},{"speaker":"hero","text":{"pl":"Eee... Nie rozumiem...","en":"Uhh... I don''t understand...","de":"Ähh ... Ich verstehe nicht ..."}},{"speaker":"npc","text":{"pl":"Ty ją tylko rozszerzysz. Od tej pory będziesz magiem w służbie obydwu żywiołów!","en":"You''re extending your vow. That way you''ll become a magician of both elements!","de":"Du erweiterst deinen Schwur. Damit wirst du zum Magier der beiden Elemente!"}},{"speaker":"npc","text":{"pl":"Posiądziesz siłę Ognia oraz mądrość Wody jednocześnie!","en":"Then you''ll have the force of Fire as well as the wisdom of Water!","de":"Sowohl die Macht des Feuers als auch das Wissen des Wassers stehen dir dann zur Verfügung!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_oath_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_oath_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_OATH_Info","outputIds":["KDW_600_Saturas_OATH_Info_15_01","KDW_600_Saturas_OATH_Info_14_02","KDW_600_Saturas_OATH_Info_15_03","KDW_600_Saturas_OATH_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Czy to oznacza, że należę teraz do kręgu Magów Wody?","en":"Does that mean that I now belong to the guild of the Magicians of the Water?","de":"Heißt das, ich gehöre jetzt in die Gilde der Wassermagier?"}},{"speaker":"npc","text":{"pl":"Jeszcze nie. Najpierw musisz złożyć śluby Wody.","en":"Not yet. First you need to take the oath of Water.","de":"Noch nicht. Du musst erst den Eid des Wassers ablegen."}},{"speaker":"hero","text":{"pl":"Ale składałem już przysięgę Ognia!","en":"But I''ve already taken the oath of Fire!","de":"Aber ich habe mich bereits dem Feuer verschworen!"}},{"speaker":"npc","text":{"pl":"Hmmm...","en":"Hmmm....","de":"Hmmm ...."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_14_00_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_14_00_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_TIMESUP_Info","outputIds":["KDW_600_Saturas_TIMESUP_Info_14_00"],"lines":[{"speaker":"npc","text":{"pl":"Rozmawiałeś z Xardasem?","en":"Have you spoken to Xardas?","de":"Hast du mit Xardas gesprochen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_15_01_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_15_01_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_TIMESUP_JA1","outputIds":["KDW_600_Saturas_TIMESUP_Info_15_01","KDW_600_Saturas_TIMESUP_Info_14_02","KDW_600_Saturas_TIMESUP_Info_15_03","KDW_600_Saturas_TIMESUP_Info_14_04"],"lines":[{"speaker":"hero","text":{"pl":"No wiesz...","en":"Well...","de":"Nun ..."}},{"speaker":"npc","text":{"pl":"Wiesz? CO WIESZ?","en":"Well ..? Well what?","de":"Nun ..? Nun was?"}},{"speaker":"hero","text":{"pl":"Äh ... noch nicht ... ich bin aber schon unterwegs ...","en":"Äh ... noch nicht ... ich bin aber schon unterwegs ...","de":"Äh ... noch nicht ... ich bin aber schon unterwegs ..."}},{"speaker":"npc","text":{"pl":"Beeile dich, wir dürfen keine Zeit mehr verlieren!","en":"Beeile dich, wir dürfen keine Zeit mehr verlieren!","de":"Beeile dich, wir dürfen keine Zeit mehr verlieren!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_15_05_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_15_05_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_TIMESUP_JA2","outputIds":["KDW_600_Saturas_TIMESUP_Info_15_05","KDW_600_Saturas_TIMESUP_Info_14_06","KDW_600_Saturas_TIMESUP_Info_15_07","KDW_600_Saturas_TIMESUP_Info_14_08"],"lines":[{"speaker":"hero","text":{"pl":"Nie...","en":"No...","de":"Nein..."}},{"speaker":"npc","text":{"pl":"Dlaczego?","en":"Why not?","de":"Warum nicht?"}},{"speaker":"hero","text":{"pl":"Nie udało mi się jeszcze do niego dotrzeć.","en":"I couldn''t get into that area yet...","de":"Ich kam bisher nicht in diese Gegend ..."}},{"speaker":"npc","text":{"pl":"Musisz go odnaleźć i poprosić go o pomoc!","en":"You need to find him and ask him for advice!","de":"Du musst ihn finden und um Rat fragen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_15_09_0', 'KDW_600_Saturas', '{"id":"missions_dia_kdw_600_saturas_kdw_600_saturas_timesup_info_15_09_0","npcId":"KDW_600_Saturas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_600_Saturas.d","sourceFunction":"KDW_600_Saturas_TIMESUP_JA3","outputIds":["KDW_600_Saturas_TIMESUP_Info_15_09","KDW_600_Saturas_TIMESUP_Info_14_10","KDW_600_Saturas_TIMESUP_Info_15_11","KDW_600_Saturas_TIMESUP_Info_14_12"],"lines":[{"speaker":"hero","text":{"pl":"To nie jest tak jak myślisz...","en":"The whole thing''s not the way you think...","de":"Die ganze Sache ist anders, als du denkst ..."}},{"speaker":"npc","text":{"pl":"Jak to? Xardas musi nam pomóc w zdetonowaniu kopca rudy!","en":"What do you mean? He needs to find a way how to blow up the ore mound!","de":"Was heißt anders? Er muss einen Weg finden, wie wir den Erzhaufen sprengen können!"}},{"speaker":"hero","text":{"pl":"Kopiec... jest... Ehm... Jest już bardzo duży!","en":"The ore mound... uh... uhm... It''s grown very high!","de":"Der Erzhaufen ... äh ... äh ...  ist mittlerweile sehr groß!"}},{"speaker":"npc","text":{"pl":"Znajdź Xardasa! On musi nam pomóc!","en":"Find Xardas, he needs to help!","de":"Suche Xardas, er muss uns helfen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_603_nefarius_info_nefarius_now_ready_15_00_0', 'KDW_603_Nefarius', '{"id":"missions_dia_kdw_603_nefarius_info_nefarius_now_ready_15_00_0","npcId":"KDW_603_Nefarius","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_603_Nefarius.d","sourceFunction":"Info_Nefarius_NowReady_Info","outputIds":["Info_Nefarius_NowReady_15_00","Info_Nefarius_NowReady_04_01","Info_Nefarius_NowReady_04_02","Info_Nefarius_NowReady_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Czy jestem już gotów, by zostać Magiem Wody?","en":"Am I ready for the Circle of Water?","de":"Bin ich bereit für den Kreis des Wassers?"}},{"speaker":"npc","text":{"pl":"Najpierw zaciągnij się do Najemników, potem - zobaczymy...","en":"Become one of our mercenaries, then we''ll see...","de":"Werde einer unserer Söldner, dann sehen wir weiter..."}},{"speaker":"npc","text":{"pl":"Jak widzę, zostałeś jednym z Najemników. Dobrze, bardzo dobrze!","en":"I see, you''ve become one of our mercenaries. Very good, very good...","de":"Ich sehe, du bist einer unserer Söldner geworden. Sehr gut, sehr gut..."}},{"speaker":"npc","text":{"pl":"Czekaj teraz cierpliwie na swoją szansę...","en":"Time will attend to the rest...","de":"Alles Weitere wird sich mit der Zeit zeigen..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_603_nefarius_info_nefarius_ocnews_04_00_0', 'KDW_603_Nefarius', '{"id":"missions_dia_kdw_603_nefarius_info_nefarius_ocnews_04_00_0","npcId":"KDW_603_Nefarius","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_603_Nefarius.d","sourceFunction":"Info_Nefarius_OCNews_Info","outputIds":["Info_Nefarius_OCNews_04_00","Info_Nefarius_OCNews_15_01","Info_Nefarius_OCNews_04_02","Info_Nefarius_OCNews_04_03"],"lines":[{"speaker":"npc","text":{"pl":"Są jakieś wieści od naszych przyjaciół ze Starego Obozu?","en":"Is there any news of our friends in the Old Camp?","de":"Was gibt es Neues von unseren Freunden aus dem alten Lager?"}},{"speaker":"hero","text":{"pl":"Gomez kazał wymordować wszystkich Magów Ognia!","en":"Gomez has had all the Magicians of Fire killed!","de":"Gomez hat alle Feuermagier töten lassen!"}},{"speaker":"npc","text":{"pl":"Nie! Durny barbarzyńca! Uprzedzałem Corristo - Gomezowi od początku nie można było ufać! Musisz donieść o tym Saturasowi!","en":"No! The cretin! I warned Corristo - he was never to be trusted! You must tell Saturas about it!","de":"Nein! Dieser Hund! Ich hatte Corristo gewarnt - ihm war noch nie zu trauen! Du mußt Saturas davon berichten!"}},{"speaker":"npc","text":{"pl":"Czekaj!","en":"Wait!","de":"Warte!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_603_nefarius_info_nefarius_ocnews_04_04_4', 'KDW_603_Nefarius', '{"id":"missions_dia_kdw_603_nefarius_info_nefarius_ocnews_04_04_4","npcId":"KDW_603_Nefarius","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_603_Nefarius.d","sourceFunction":"Info_Nefarius_OCNews_Info","outputIds":["Info_Nefarius_OCNews_04_04","Info_Nefarius_OCNews_04_05","Info_Nefarius_OCNews_04_06"],"lines":[{"speaker":"npc","text":{"pl":"Naraziłeś się dla nas na nie lada niebezpieczeństwa.","en":"You have braved great dangers on our behalf.","de":"Du hast große Gefahren auf dich genommen, um uns zu dienen."}},{"speaker":"npc","text":{"pl":"Jesteś już chyba godzien, by nosić szaty Maga Wody.","en":"I think you are now ready to wear the robe of a Magician of Water.","de":"Ich denke, du bist jetzt bereit, die Robe eines Wassermagiers zu tragen."}},{"speaker":"npc","text":{"pl":"A teraz spiesz do Saturasa! Nie trać czasu!","en":"But now speak to Saturas! Hurry!","de":"Aber nun sprich mit Saturas! Beeile dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_603_nefarius_info_nefarius_wanna_mage_04_04_4', 'KDW_603_Nefarius', '{"id":"missions_dia_kdw_603_nefarius_info_nefarius_wanna_mage_04_04_4","npcId":"KDW_603_Nefarius","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_603_Nefarius.d","sourceFunction":"Info_Nefarius_WannaMage_Info","outputIds":["Info_Nefarius_WannaMage_04_04","Info_Nefarius_WannaMage_04_05"],"lines":[{"speaker":"npc","text":{"pl":"Jeżeli poważnie myślisz o zostaniu Magiem Wody, dołącz najpierw do Najemników. W ten sposób będziesz mógł nam udowodnić swoją wartość.","en":"If you''re really serious, you should join our mercenaries. There you can serve us.","de":"Wenn es dir wirklich ernst ist, solltest du zu unseren Söldnern gehen. Dort kannst du uns dienen."}},{"speaker":"npc","text":{"pl":"Kto wie, może pewnego dnia uda ci się nas przekonać...","en":"And maybe one day you''ll be granted a chance to do something great.","de":"Und vielleicht erhältst du eines Tages die Chance, etwas Großes zu vollbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_603_nefarius_info_nefarius_wanna_mage_15_00_0', 'KDW_603_Nefarius', '{"id":"missions_dia_kdw_603_nefarius_info_nefarius_wanna_mage_15_00_0","npcId":"KDW_603_Nefarius","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_603_Nefarius.d","sourceFunction":"Info_Nefarius_WannaMage_Info","outputIds":["Info_Nefarius_WannaMage_15_00","Info_Nefarius_WannaMage_04_01","Info_Nefarius_WannaMage_04_02","Info_Nefarius_WannaMage_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać Magiem Kręgu Wody.","en":"I''d like to become a Magician of the Circle of Water!","de":"Ich will ein Magier vom Kreis des Wassers werden!"}},{"speaker":"npc","text":{"pl":"Nie tak szybko, mój chłopcze!","en":"Not so fast, my boy!","de":"(lacht) Nicht so schnell, mein Junge!"}},{"speaker":"npc","text":{"pl":"Nie przyjmujemy do naszego grona byle kogo. Najpierw musisz się wykazać czymś niezwykłym.","en":"Before we let a young man join us, he needs to have done something great.","de":"Bevor wir einen jungen Mann in unsere Reihen aufnehmen, muss er etwas Großes vollbracht haben."}},{"speaker":"npc","text":{"pl":"Potem czeka cię okres próbny.","en":"And he must have served us for some time.","de":"Und er muss uns eine Zeit lang gedient haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_603_nefarius_info_nefarius_wo_saturas_15_00_0', 'KDW_603_Nefarius', '{"id":"missions_dia_kdw_603_nefarius_info_nefarius_wo_saturas_15_00_0","npcId":"KDW_603_Nefarius","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_603_Nefarius.d","sourceFunction":"Info_Nefarius_WoSaturas_Info","outputIds":["Info_Nefarius_WoSaturas_15_00","Info_Nefarius_WoSaturas_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę znaleźć Saturasa?","en":"Where can I find Saturas?","de":"Wo finde ich Saturas?"}},{"speaker":"npc","text":{"pl":"Poszukaj za tą wielką, okrągłą bramą.","en":"Go through the big round gate. You''ll find him there.","de":"Geh durch das große runde Tor. Dort wirst du ihn finden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_bandit_15_00_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_bandit_15_00_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_Bandit_Info","outputIds":["DIA_Cronos_Bandit_15_00","DIA_Cronos_Bandit_08_01","DIA_Cronos_Bandit_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Jestem teraz jednym z ludzi Laresa. Masz jakąś wiadomość dla Magów Ognia, którą mógłbym dostarczyć do Starego Obozu?","en":"I am now one of Lares'' men. Have you got a message for me to take over to the Magicians of Fire?","de":"Ich bin jetzt einer von Lares Leuten. Hast du eine Nachricht für die Feuermagier, die ich überbringen könnte?"}},{"speaker":"npc","text":{"pl":"W rzeczy samej, mam. Ale bez specjalnego znaku kurierskiego ludzie Gomeza nie wpuszczą cię do zamku.","en":"I do indeed. But you''ll need to carry the sign of one of our messengers, else Gomez'' men won''t let you enter the castle.","de":"In der Tat. Aber du brauchst das Zeichen eines unserer Boten, sonst lassen dich Gomez Schergen nicht in die Burg."}},{"speaker":"npc","text":{"pl":"Masz, oto list i znak. Tylko się pospiesz!","en":"Here, take the letter and the sign. And now hurry up!","de":"Hier, nimm Brief und Zeichen. Und nun beeile dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_barrier_08_04_4', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_barrier_08_04_4","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_Barrier_Info","outputIds":["DIA_Cronos_Barrier_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Dlatego potrzebujemy wielu ludzi do pilnowania naszych zapasów.","en":"That''s why we need a man to defend our plan.","de":"Also brauchen wir jeden Mann, der bereit ist unseren Plan zu verteidigen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_barrier_15_00_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_barrier_15_00_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_Barrier_Info","outputIds":["DIA_Cronos_Barrier_15_00","DIA_Cronos_Barrier_08_01","DIA_Cronos_Barrier_08_02","DIA_Cronos_Barrier_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Chcecie ponoć zniszczyć magiczną Barierę. Jak zamierzacie tego dokonać?","en":"You want to destroy the Barrier - how exactly do you plan to do that?","de":"Ihr wollt die Barriere zerstören - wie genau soll das gehen?"}},{"speaker":"npc","text":{"pl":"Próbujemy zgromadzić w jednym miejscu możliwie dużą ilość magicznej rudy.","en":"We need major amounts of magic ore.","de":"Wir brauchen eine große Menge magisches Erz."}},{"speaker":"npc","text":{"pl":"Podczas wielkiego rytuału, cała skumulowana w rudzie magiczna energia zostanie wyzwolona i Bariera pryśnie jak mydlana bańka!","en":"We''ll release the entire magic power in a great magic rite to blow up the Barrier.","de":"In einem großen magischen Ritual werden wir die gesamte magische Energie freilassen und somit die Barriere sprengen."}},{"speaker":"npc","text":{"pl":"Naturalnie tak wielka ilość rudy przyciąga tutaj różnych włóczęgów i bandytów!","en":"Of course such a big amount of ore attracts a lot of rogues and crooks!","de":"Natürlich zieht eine solch große Menge Erz allerlei Lumpen und Banditen an!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_brief_08_04_4', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_brief_08_04_4","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_Brief_Info","outputIds":["DIA_Cronos_Brief_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Ale przesyłki powierzamy wyłącznie ludziom Laresa. Od wielu lat jego chłopcy dbają o to, by nasze przesyłki docierały do Magów Ognia nienaruszone.","en":"But we only entrust these messages to Lares'' men. He''s been seeing to it for many years now that our messengers arrive safely.","de":"Aber wir vertrauen diese Nachrichten nur Lares'' Leuten an. Seit vielen Jahren sorgt er schon dafür, dass unsere Nachrichten sicher ankommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_brief_15_00_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_brief_15_00_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_Brief_Info","outputIds":["DIA_Cronos_Brief_15_00","DIA_Cronos_Brief_08_01","DIA_Cronos_Brief_15_02","DIA_Cronos_Brief_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam tu list dla Arcymistrza Magów Ognia.","en":"I have a letter for the High Magician of the Circle of Fire.","de":"Ich habe einen Brief für den obersten Feuermagier."}},{"speaker":"npc","text":{"pl":"My jesteśmy Magami Wody. Magów z Kręgu Ognia znajdziesz w Starym Obozie.","en":"We are the Magicians of the Circle of Water. The Magicians of the Circle of Fire live in the Old Camp.","de":"Wir sind die Magier vom Kreis des Wassers. Die Magier vom Kreis des Feuers findest du im alten Lager."}},{"speaker":"hero","text":{"pl":"Ale strażnicy nie chcą mnie wpuścić do zamku? Możesz mi jakoś pomóc?","en":"But I can''t get into the castle. Could you help me?","de":"Aber ich komme nicht in die Burg. Kannst du mir helfen?"}},{"speaker":"npc","text":{"pl":"Cóż, co jakiś czas wysyłamy kurierów do naszych braci ze Starego Obozu...","en":"Well, occasionally we send messengers to our brothers in the Old Camp...","de":"Nun, gelegentlich senden wir Boten zu unseren Brüdern ins Alte Lager..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_brief_back_15_00_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_brief_back_15_00_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_BriefBack_Info","outputIds":["DIA_Cronos_BriefBack_15_00","DIA_Cronos_BriefBack_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Dostarczyłem twoje pismo!","en":"I''ve passed the message on!","de":"Ich habe deine Nachricht überbracht!"}},{"speaker":"npc","text":{"pl":"Ach, dobrze! Oto drobny prezent, w nagrodę za twoje trudy...","en":"Ah, good! Here''s a small reward for your efforts...","de":"Ah gut! Hier ist eine kleine Entschädigung für deine Mühen..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_greet_15_00_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_greet_15_00_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_Greet_Info","outputIds":["DIA_Cronos_Greet_15_00","DIA_Cronos_Greet_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Ich grüße dich, Magier.","en":"Ich grüße dich, Magier.","de":"Ich grüße dich, Magier."}},{"speaker":"npc","text":{"pl":"Warum störst du den Hüter des Erzes?","en":"Warum störst du den Hüter des Erzes?","de":"Warum störst du den Hüter des Erzes?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_wanna_join_15_00_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_wanna_join_15_00_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_WannaJoin_Info","outputIds":["DIA_Cronos_WannaJoin_15_00","DIA_Cronos_WannaJoin_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym do was dołączyć!","en":"I''d like to join you!","de":"Ich will bei euch mitmachen!"}},{"speaker":"npc","text":{"pl":"Jeśli chcesz zostać jednym z nas, powinieneś porozmawiać z Lee albo z Laresem.","en":"If you want to join us, you should see Lee or Lares.","de":"Wenn du dich uns anschließen willst, solltest du zu Lee oder Lares gehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_dia_cronos_wanna_mage_15_00_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_dia_cronos_wanna_mage_15_00_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_WannaMage_Info","outputIds":["DIA_Cronos_WannaMage_15_00","DIA_Cronos_WannaMage_08_01","DIA_Cronos_WannaMage_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać magiem!","en":"I''d like to become a magician!","de":"Ich will Magier werden!"}},{"speaker":"npc","text":{"pl":"Nie możemy dzielić się naszą wiedzą z przeciwnikiem!","en":"We cannot afford to spread our knowledge among our enemies.","de":"Wir können es uns nicht leisten unser Wissen unter unseren Feinden zu verbreiten."}},{"speaker":"npc","text":{"pl":"Dopóki nie przekonasz nas o swojej lojalności, nie masz nawet o czym marzyć - nie będziemy cię uczyli!","en":"We will not even consider instructing you unless you prove your loyalty to us.","de":"Erst wenn du deine Loyalität zu uns unter Beweis gestellt hast, werden wir überhaupt in Erwägung ziehen, dich zu unterweisen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_kalom_08_05_4', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_kalom_08_05_4","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_KALOM_Info","outputIds":["Info_Cronos_KALOM_08_05"],"lines":[{"speaker":"npc","text":{"pl":"Powtórzę twoje informacje Saturasowi przy najbliższej okazji. Możesz już odejść!","en":"I''ll tell Saturas about it as soon as I get the chance. Leave now!","de":"Ich werde Saturas bei Gelegenheit davon berichten. Geh nun!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_kalom_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_kalom_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_KALOM_Info","outputIds":["Info_Cronos_KALOM_15_01","Info_Cronos_KALOM_15_02","Info_Cronos_KALOM_08_03","Info_Cronos_KALOM_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Cor Kalom opuścił obóz Bractwa z grupą fanatycznych Strażników Świątynnych!","en":"Cor Kalom has left the Brotherhood with some fanatical templars!","de":"Cor Kalom hat mit ein paar fanatischen Templern die Bruderschaft verlassen!"}},{"speaker":"hero","text":{"pl":"Zamierza na własną rękę odnaleźć Śniącego i przebudzić go za wszelką cenę.","en":"He wants to find the Sleeper on his own and wake him up at all costs.","de":"Er will unbedingt den Schläfer auf eigene Faust finden und ihn erwecken."}},{"speaker":"npc","text":{"pl":"Nigdy nie ufałem temu człowiekowi. Wielki Guru czy nie - to próżny i nieszczery człowiek zdolny do wszystkiego.","en":"I''ve never trusted him. Second Guru or not, he''s vain, insidious and he''s capable of anything.","de":"Ich habe ihm noch nie getraut. Zweiter Guru hin oder her, er ist verblendet, hinterhältig und zu allem fähig."}},{"speaker":"npc","text":{"pl":"Bractwo da sobie radę i bez niego!","en":"The Brotherhood is better off without him!","de":"Sicher ist die Bruderschaft ohne ihn besser dran!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_news_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_news_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_NEWS_Info","outputIds":["Info_Cronos_NEWS_15_01","Info_Cronos_NEWS_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Mam ważną wiadomość dla Saturasa!","en":"I have an important message for Saturas!","de":"Ich habe wichtige Nachrichten für Saturas!"}},{"speaker":"npc","text":{"pl":"Cóż może być tak ważnego, byś miał przeszkadzać naszemu wielkiemu przywódcy w jego badaniach?","en":"What could be so important that our spiritual leader should interrupt his important studies for it?","de":"Was könnte schon so wichtig sein, dass unser spiritueller Anführer seine wertvollen Studien dafür unterbrechen sollte?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_parole_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_parole_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_PAROLE_Info","outputIds":["Info_Cronos_PAROLE_15_01","Info_Cronos_PAROLE_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak brzmiało to hasło?","en":"What was the password again?","de":"Wie war die Parole noch mal?"}},{"speaker":"npc","text":{"pl":"Już moja świętej pamięci babcia miała lepszą pamięć od ciebie. Hasło brzmi \"TETRIANDOCH\".","en":"\"You''re more of a scatterbrain than my old granny. It is \"\"TETRIANDOCH\"\"\"","de":"Du bist vergesslicher als meine Großmutter. Sie lautet \"TETRIANDOCH\""}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_reward_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_reward_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_REWARD_Info","outputIds":["Info_Cronos_REWARD_15_01","Info_Cronos_REWARD_08_02","Info_Cronos_REWARD_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Saturas powiedział, że masz dla mnie nagrodę.","en":"Saturas said you had a reward for me.","de":"Saturas sagte, du hättest eine Belohnung für mich."}},{"speaker":"npc","text":{"pl":"Jako strażnik rudy, chciałbym podarować ci część naszego urobku jako nagrodę za zasługi dla Nowego Obozu.","en":"As the keeper of the ore, I''d like to give you a small portion of our ore for your great deeds on behalf of the Camp.","de":"Als Hüter des Erzes möchte ich für deine großen Dienste für unser Lager einen kleinen Teil des Erzes in deine Hände geben."}},{"speaker":"npc","text":{"pl":"Mam nadzieję, że zrobisz z tej rudy równie dobry użytek jak my!","en":"I hope you''ll make as good use of it as we do!","de":"Ich hoffe, du hast eine ebenso sinnvolle Verwendung wie wir dafür!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_sleeper_08_05_4', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_sleeper_08_05_4","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_SLEEPER_Info","outputIds":["Info_Cronos_SLEEPER_08_05","Info_Cronos_SLEEPER_15_06","Info_Cronos_SLEEPER_08_07","Info_Cronos_SLEEPER_08_08"],"lines":[{"speaker":"npc","text":{"pl":"Powtórzysz te informacje samemu Saturasowi. On zdecyduje co nam wypada czynić.","en":"You must report to Saturas at once. He must decide what is to be done.","de":"Das musst du sofort Saturas berichten. Er muss entscheiden, was zu tun ist."}},{"speaker":"hero","text":{"pl":"Gdzie znajdę Saturasa?","en":"Where can I find Saturas?","de":"Wo finde ich Saturas?"}},{"speaker":"npc","text":{"pl":"Wejdź na wyższy poziom. Powiedz strażnikom, że pozwoliłem ci przejść.","en":"Go to the upper level. Tell the guards there that you have my permission to pass.","de":"Begib dich zur obersten Ebene. Sage den Wachen dort, du hast meine Erlaubnis zum passieren."}},{"speaker":"npc","text":{"pl":"Hasło brzmi TETRIANDOCH.","en":"The password is TETRIANDOCH.","de":"Die Parole lautet TETRIANDOCH."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_sleeper_08_09_8', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_sleeper_08_09_8","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_SLEEPER_Info","outputIds":["Info_Cronos_SLEEPER_08_09","Info_Cronos_SLEEPER_08_10"],"lines":[{"speaker":"npc","text":{"pl":"Saturasa znajdziesz przy wielkim pentagramie.","en":"Saturas is by the pentagram.","de":"Saturas findest du beim großen Pentagramm."}},{"speaker":"npc","text":{"pl":"W zasadzie się stamtąd nie rusza. Cały czas obmyśla sposób na wysadzenie kopca rudy.","en":"He spends almost all day there, studying how to blow up the big ore mound.","de":"Er gibt sich dort fast den ganzen Tag seinen Studien über die Sprengung des großen Erzhaufens hin."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_sleeper_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_sleeper_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_SLEEPER_Info","outputIds":["Info_Cronos_SLEEPER_15_01","Info_Cronos_SLEEPER_08_02","Info_Cronos_SLEEPER_08_03","Info_Cronos_SLEEPER_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Guru zorientowali się, że oddawali cześć potężnemu demonowi z piekła rodem!","en":"The Gurus have recognized that they''re praying to an evil arch demon!","de":"Die Gurus haben erkannt, dass sie einen üblen Erzdämonen anbeten!"}},{"speaker":"npc","text":{"pl":"Raptem doszli do wniosku, że Śniący jest demonem?","en":"All of a sudden they now think their Sleeper is a demon?","de":"Sie halten ihren Schläfer jetzt plötzlich für einen Dämonen?"}},{"speaker":"npc","text":{"pl":"To mi wygląda na kolejny szalony pomysł ludzi z Bractwa, ale...","en":"Sounds like another mad idea of the Brotherhood, but...","de":"Hört sich nach einer weiteren Verworrenheit der Bruderschaft an, aber ..."}},{"speaker":"npc","text":{"pl":"...Gdyby okazało się, że mają rację... Cała kolonia znalazłaby się w śmiertelnym niebezpieczeństwie.","en":"... should they be right... all of us in the colony here might be in grave danger.","de":"... Sollten sie Recht haben ... könnten wir alle hier in der Kolonie in großer Gefahr sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_yberion_08_05_4', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_yberion_08_05_4","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_YBERION_Info","outputIds":["Info_Cronos_YBERION_08_05","Info_Cronos_YBERION_08_06"],"lines":[{"speaker":"npc","text":{"pl":"To smutna wiadomość. Na Y''Berionie zawsze można było polegać.","en":"That''s very sad. Y''Berion was a reliable ally.","de":"Das ist sehr traurig. Y''Berion war ein zuverlässiger Verbündeter."}},{"speaker":"npc","text":{"pl":"Ale to jeszcze nie powód, żeby przeszkadzać Saturasowi.","en":"But it''s no reason to justify interrupting Saturas'' studies.","de":"Aber es rechtfertigt nicht die Störung der Studien von Saturas."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_info_cronos_yberion_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_info_cronos_yberion_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"Info_Cronos_YBERION_Info","outputIds":["Info_Cronos_YBERION_15_01","Info_Cronos_YBERION_08_02","Info_Cronos_YBERION_15_03","Info_Cronos_YBERION_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Y''Berion, duchowy przywódca Bractwa Śniącego, nie żyje!","en":"Y''Berion, the leader of the Sect Camp, is dead!","de":"Y''Berion, der Anführer des Sektenlagers, ist tot!"}},{"speaker":"npc","text":{"pl":"CO?!? Jak to się stało?!","en":"WHAAAAT??? How could that happen?","de":"WAAAS??? Wie konnte das geschehen?"}},{"speaker":"hero","text":{"pl":"Bractwo przeprowadziło rytuał przyzwania Śniącego.","en":"The Brotherhood performed a ritual, invoking their god.","de":"Die Bruderschaft führte ein Ritual durch, eine Anrufung ihres Gottes."}},{"speaker":"hero","text":{"pl":"Wygląda na to, że Y''Berion nie był w stanie wytrzymać tak wielkiego obciążenia.","en":"It seems the mental strain was too much for Y''Berion.","de":"Die mentalen Anstrengungen waren wohl zu viel für Y''Berion."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_kdw_604_cronos_greet_info_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_kdw_604_cronos_greet_info_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_GREET_Info","outputIds":["KDW_604_Cronos_GREET_Info_15_01","KDW_604_Cronos_GREET_Info_08_02","KDW_604_Cronos_GREET_Info_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Witaj, magu!","en":"Greetings, Magician.","de":"Ich grüße dich, Magier."}},{"speaker":"npc","text":{"pl":"Niech błogosławieństwo Adanosa zawsze będzie z tobą. Mogę ci pomóc zwiększyć twoje magiczne moce lub zaopatrzyć cię w kilka pożytecznych przedmiotów.","en":"May the blessing of Adanos be with you. I can help you to increase your magic powers or give you some useful items.","de":"Der Segen Adanos sei mit dir. Ich kann dir helfen, deine geistige Kraft zu stärken oder dir ein paar nützliche Dinge anbieten."}},{"speaker":"npc","text":{"pl":"Co mogę dla ciebie zrobić?","en":"What can I do for you?","de":"Was kann ich für dich tun?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_kdw_604_cronos_mana_info_15_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_kdw_604_cronos_mana_info_15_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_MANA_Info","outputIds":["KDW_604_Cronos_MANA_Info_15_01","KDW_604_Cronos_MANA_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję większej mocy magicznej.","en":"I need more magic power.","de":"Ich benötige mehr magische Kraft"}},{"speaker":"npc","text":{"pl":"Mogę ci pokazać, jak zwiększyć twoje zdolności magiczne. Jak je wykorzystasz zależy już tylko od ciebie.","en":"I can help you to increase your power. Use it wisely.","de":"Ich kann dir helfen, deine Kraft zu steigern. Setze sie mit Bedacht ein!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_604_cronos_kdw_604_cronos_welcome_info_08_01_0', 'KDW_604_Cronos', '{"id":"missions_dia_kdw_604_cronos_kdw_604_cronos_welcome_info_08_01_0","npcId":"KDW_604_Cronos","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_604_Cronos.d","sourceFunction":"KDW_604_Cronos_WELCOME_Info","outputIds":["KDW_604_Cronos_WELCOME_Info_08_01"],"lines":[{"speaker":"npc","text":{"pl":"Mądrze postąpiłeś przystępując do Magów Wody. Bądź pozdrowiony, bracie!","en":"Your decision to join the Magicians of Water was right. Be welcome, brother!","de":"Deine Entscheidung, zu den Wassermagiern zu kommen, war richtig. Willkommen, Bruder!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_info_riordian_message_14_01_0', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_info_riordian_message_14_01_0","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"Info_Riordian_MESSAGE_Info","outputIds":["Info_Riordian_MESSAGE_14_01"],"lines":[{"speaker":"npc","text":{"pl":"Cieszę się, że już jesteś. Czekałem na ciebie!","en":"I''m glad you''ve come! I''ve been expecting you!","de":"Gut, dass du kommst! Ich habe schon auf dich gewartet!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791209);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_info_riordian_messagewhy_15_01_0', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_info_riordian_messagewhy_15_01_0","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"Info_Riordian_MESSAGEWHY_Info","outputIds":["Info_Riordian_MESSAGEWHY_15_01","Info_Riordian_MESSAGEWHY_14_02","Info_Riordian_MESSAGEWHY_15_03","Info_Riordian_MESSAGEWHY_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Czekałeś? Jak to?","en":"You''ve been expecting me? Why?","de":"Du hast auf mich gewartet? Warum?"}},{"speaker":"npc","text":{"pl":"Gorn prosił mnie, żebym cię do niego przysłał, gdy tylko się zjawisz.","en":"Gorn asked me to send you to him as soon as you arrived!","de":"Gorn bat mich, dich bei deinem Auftauchen hier sofort zu ihm zu schicken!"}},{"speaker":"hero","text":{"pl":"O co chodzi?","en":"What''s up?","de":"Was ist los?"}},{"speaker":"npc","text":{"pl":"Ma plan, jak odzyskać zajętą kopalnię.","en":"He has a plan to free the occupied mine.","de":"Er hat einen Plan zur Befreiung der besetzten Mine."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_info_riordian_messagewhy_15_05_4', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_info_riordian_messagewhy_15_05_4","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"Info_Riordian_MESSAGEWHY_Info","outputIds":["Info_Riordian_MESSAGEWHY_15_05","Info_Riordian_MESSAGEWHY_14_06"],"lines":[{"speaker":"hero","text":{"pl":"Czy wciąż pilnuje wejścia do kopalni?","en":"Is he still guarding the entrance to the mine?","de":"Bewacht er noch den Zugang zur Mine?"}},{"speaker":"npc","text":{"pl":"Tak! Proszę, zajrzyj do niego możliwie jak najszybciej!","en":"Yes! Please see him as soon as possible!","de":"Ja! Bitte suche ihn so schnell wie möglich auf!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_info_riordian_news_15_01_0', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_info_riordian_news_15_01_0","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"Info_Riordian_NEWS_Info","outputIds":["Info_Riordian_NEWS_15_01","Info_Riordian_NEWS_14_02","Info_Riordian_NEWS_14_03","Info_Riordian_NEWS_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Saturas.","en":"Saturas sent me.","de":"Saturas schickt mich."}},{"speaker":"npc","text":{"pl":"Ach, chodź bliżej. Już mi o wszystkim doniesiono.","en":"Ahhh, come here. I''ve already been informed.","de":"Ahhh, komm näher. Ich bin bereits informiert."}},{"speaker":"npc","text":{"pl":"Proszę, weź to. Znajdziesz tu najróżniejsze wywary.","en":"Here, take these potions, they''re potions of all kinds.","de":"Hier nimm diese Tränke, da ist von jedem was dabei."}},{"speaker":"npc","text":{"pl":"Teraz możesz już ruszać na poszukiwanie kamieni ogniskujących. Jesteś naszą jedyną nadzieją.","en":"Now go and bring us the focus stones. These artefacts are our only hope.","de":"Nun geh und bring uns die Fokussteine. Diese Artefakte sind unsere einzige Hoffnung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_info_riordian_reward_14_05_4', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_info_riordian_reward_14_05_4","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"Info_Riordian_REWARD_Info","outputIds":["Info_Riordian_REWARD_14_05"],"lines":[{"speaker":"npc","text":{"pl":"Przyjmij tę skromną nagrodę w uznaniu twoich zasług.","en":"Take this as a modest reward for all your efforts.","de":"Nimm dies als einen bescheidenen Ausgleich für all deine Mühen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_info_riordian_reward_15_01_0', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_info_riordian_reward_15_01_0","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"Info_Riordian_REWARD_Info","outputIds":["Info_Riordian_REWARD_15_01","Info_Riordian_REWARD_14_02","Info_Riordian_REWARD_14_03","Info_Riordian_REWARD_14_04"],"lines":[{"speaker":"hero","text":{"pl":"Saturas powiedział, że masz dla mnie nagrodę.","en":"Saturas said you had a reward for me?","de":"Saturas sagt, du hättest eine Belohnung für mich?"}},{"speaker":"npc","text":{"pl":"Ach, chodź, chodź!","en":"Ahhhh, come here, come here.","de":"Ahhhh, komm näher, komm näher."}},{"speaker":"npc","text":{"pl":"Nasz przywódca opowiedział mi o twoich bohaterskich czynach.","en":"Our spiritual leader has told me about your heroic deeds.","de":"Unser spiritueller Führer hat mir von deinen Heldentaten berichtet."}},{"speaker":"npc","text":{"pl":"Cały nasz obóz... Ach, co ja mówię - cała KOLONIA powinna ci być dozgonnie wdzięczna.","en":"All the people in the Camp - no, the whole colony -are deeply indebted to you.","de":"Wir alle hier im Lager, ja in der ganzen Kolonie sind dir zu großem Dank verpflichtet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_kdw_605_riordian_heal_info_14_01_0', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_kdw_605_riordian_heal_info_14_01_0","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"KDW_605_Riordian_HEAL_Info","outputIds":["KDW_605_Riordian_HEAL_Info_14_01"],"lines":[{"speaker":"npc","text":{"pl":"Jeśli jesteś ranny, mogę ci pomóc.","en":"If you''re injured, I will heal you.","de":"Wenn du verletzt bist, werde ich dich heilen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_kdw_605_riordian_healinfo_info_15_01_0', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_kdw_605_riordian_healinfo_info_15_01_0","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"KDW_605_Riordian_HEALINFO_Info","outputIds":["KDW_605_Riordian_HEALINFO_Info_15_01","KDW_605_Riordian_HEALINFO_Info_14_02"],"lines":[{"speaker":"hero","text":{"pl":"Jestem ranny. Możesz coś na to poradzić?","en":"I''m injured. Can you heal me?","de":"Ich bin verletzt. Kannst du mich heilen?"}},{"speaker":"npc","text":{"pl":"Tymi słowy przywołuję uzdrawiającą siłę! Niech twe ciało i duch znów zaznają spokoju!","en":"Through my words I call upon the powers of healing, your body and spirit shall be well!","de":"Durch mein Wort rufe ich die Kraft der Heilung und lasse diesen Körper und den Geist gesunden!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_kdw_605_riordian_kdw_605_riordian_welcome_info_14_01_0', 'KDW_605_Riordian', '{"id":"missions_dia_kdw_605_riordian_kdw_605_riordian_welcome_info_14_01_0","npcId":"KDW_605_Riordian","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_KDW_605_Riordian.d","sourceFunction":"KDW_605_Riordian_WELCOME_Info","outputIds":["KDW_605_Riordian_WELCOME_Info_14_01"],"lines":[{"speaker":"npc","text":{"pl":"Cieszę się, że do nas dołączyłeś.","en":"I''m glad you''ve joined us.","de":"Gut, dass du uns beigetreten bist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_non_1500_gilbert_dia_gilbert_first_04_00_0', 'NON_1500_Gilbert', '{"id":"missions_dia_non_1500_gilbert_dia_gilbert_first_04_00_0","npcId":"NON_1500_Gilbert","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Non_1500_Gilbert.d","sourceFunction":"DIA_Gilbert_First_Info","outputIds":["DIA_Gilbert_First_04_00","DIA_Gilbert_First_04_01"],"lines":[{"speaker":"npc","text":{"pl":"Co tu robisz? Nie miewam tu zbyt często gości, he he!","en":"What are you doing here? Don''t often get visitors up here, he he!","de":"Was machst du denn hier? Hab nicht oft Besuch hier oben, hehe!"}},{"speaker":"npc","text":{"pl":"Widzę, że niezły cwaniak z ciebie. Tak znaleźć moją kryjówkę, no no!","en":"Very clever of you to find my hiding place.","de":"War ne gute Leistung von dir, mein Versteck zu finden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_non_1500_gilbert_dia_gilbert_hallo_15_00_0', 'NON_1500_Gilbert', '{"id":"missions_dia_non_1500_gilbert_dia_gilbert_hallo_15_00_0","npcId":"NON_1500_Gilbert","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Non_1500_Gilbert.d","sourceFunction":"DIA_Gilbert_Hallo_Info","outputIds":["DIA_Gilbert_Hallo_15_00","DIA_Gilbert_Hallo_04_01","DIA_Gilbert_Hallo_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Miałem już dość Starego Obozu. Podpadłem paru ludziom Gomeza. To było dawno temu.","en":"Oh, I''m fed up with the Old Camp. I had trouble with Gomez'' folks. That was some time ago.","de":"Ich hatte die Schnauze voll vom alten Lager. Hatte Ärger mit Gomez Leuten. Ist aber schon ne Weile her."}},{"speaker":"npc","text":{"pl":"Teraz pewnie nikt już o mnie nie pamięta, ale ja się stąd nie ruszam. Jak na mój gust - w Starym Obozie wciąż jest za dużo tępych osiłków.","en":"I guess nobody remembers that now. But I''m staying here. There''s too many blockheads running about in the Old Camp for my liking.","de":"Schätze, jetzt kräht kein Hahn mehr danach. Aber ich bleibe hier. Im alten Lager rennen mir zu viele Schwachköpfe rum."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_info_talas_returned_02_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_info_talas_returned_02_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_RETURNED_Info","outputIds":["Info_Talas_RETURNED_02_01","Info_Talas_RETURNED_15_02","Info_Talas_RETURNED_02_03"],"lines":[{"speaker":"npc","text":{"pl":"No to jesteśmy. Najlepiej zanieś od razu ten almanach Cor Kalomowi.","en":"We''re back. You''d better take the almanac to Cor Kalom right away.","de":"Hier sind wir wieder. Am besten du bringst den Almanach gleich zu Cor Kalom."}},{"speaker":"hero","text":{"pl":"Tylko uważaj, żebyś nie umarł z przepracowania.","en":"Just watch out you don''t stress yourself out.","de":"Pass nur auf, dass du dich nicht überarbeitest."}},{"speaker":"npc","text":{"pl":"Spokojna głowa. Nic mi nie będzie. Nie musisz się o mnie martwić.","en":"Don''t worry, I sure won''t! There''s no need to worry about me.","de":"Keine Angst, darauf achte ich sogar sehr! Mach dir um mich keine Sorgen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_back_info_02_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_back_info_02_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_BACK_Info","outputIds":["Nov_1300_Talas_BACK_Info_02_01"],"lines":[{"speaker":"npc","text":{"pl":"Odzyskałeś almanach! Dobra robota! Wracajmy czym prędzej do Obozu!","en":"You have the almanac! Well done. Let''s go back to the Camp.","de":"Du hast den Almanach! Gut gemacht. Gehen wir wieder zurück ins Lager."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_backagain_info_02_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_backagain_info_02_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_BACKAGAIN_Info","outputIds":["Nov_1300_Talas_BACKAGAIN_Info_02_01","Nov_1300_Talas_BACKAGAIN_Info_02_02","Nov_1300_Talas_BACKAGAIN_Info_15_03"],"lines":[{"speaker":"npc","text":{"pl":"Nie pójdę z tobą na drugą stronę tego mostu. Nie jestem samobójcą.","en":"I''m not taking you across this bridge, I don''t want to commit suicide.","de":"Auch hier werde ich dich nicht über die Brücke begleiten, denn ich bin nicht lebensmüde."}},{"speaker":"npc","text":{"pl":"Oszalałeś, że chcesz tam wchodzić?! Nawet Baal Lukor stamtąd nie wrócił, a on miał ze sobą Świątynnych Strażników!","en":"You must be mad to go in there, even Baal Lukor and his templars didn''t get out again.","de":"Du musst verrückt sein, dort hinein zu gehen, wenn selbst Baal Lukor und seine Templer nicht wieder herauskamen."}},{"speaker":"hero","text":{"pl":"Co ma być to będzie. Wracaj do obozu. Ja się tu trochę rozejrzę.","en":"We''ll see what happens. Go back to the Camp, I''ll be there later.","de":"Das werden wir ja sehen. Geh zurück zum Lager, ich komme nach."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_bridge_info_02_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_bridge_info_02_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_BRIDGE_Info","outputIds":["Nov_1300_Talas_BRIDGE_Info_02_01","Nov_1300_Talas_BRIDGE_Info_15_02","Nov_1300_Talas_BRIDGE_Info_02_03"],"lines":[{"speaker":"npc","text":{"pl":"Te przeklęte bestyjki mieszkają w jaskini, za tym mostem. Uważaj na siebie!","en":"Those damn little beasts live in a cave behind this bridge! Be careful!","de":"Hinter dieser Brücke ist die Höhle dieser verdammten kleinen Biester! Pass auf dich auf!"}},{"speaker":"hero","text":{"pl":"Nie pójdziesz ze mną?","en":"You''re not coming with me?","de":"Du kommst nicht mit?"}},{"speaker":"npc","text":{"pl":"Zostanę tutaj i będę... ubezpieczał tyły.","en":"I''ll wait here and... ahem... cover our retreat.","de":"Ich werde hier auf dich warten und... ähem... unseren Rückzug decken"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_help_bring_15_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_help_bring_15_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_HELP_BRING","outputIds":["Nov_1300_Talas_HELP_BRING_15_01","Nov_1300_Talas_HELP_BRING_02_02"],"lines":[{"speaker":"hero","text":{"pl":"To cię będzie kosztowało 30 bryłek rudy.","en":"That''ll cost you 30 ore.","de":"Das kostet dich 30 Erz."}},{"speaker":"npc","text":{"pl":"W porządku. Możemy wyruszyć, gdy tylko będziesz gotowy.","en":"Okay, we can leave as soon as you''re ready.","de":"In Ordnung, wir können losgehen, sobald du bereit bist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_help_info_15_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_help_info_15_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_HELP_Info","outputIds":["Nov_1300_Talas_HELP_Info_15_01","Nov_1300_Talas_HELP_Info_02_02","Nov_1300_Talas_HELP_Info_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Mogę ci pomóc w odzyskaniu tej księgi.","en":"I can help you to bring the almanac back.","de":"Ich kann dir helfen, den Almanach zurückbringen."}},{"speaker":"npc","text":{"pl":"Naprawdę? Zostałem obrabowany przez gobliny! A teraz mam je odnaleźć i odzyskać księgę!","en":"Really? I was mugged by goblins! And now I''m supposed to go there and get the book back!","de":"Wirklich? Goblins haben mich überfallen! Und jetzt soll ich wieder zu ihnen gehen und das Buch zurückbringen!"}},{"speaker":"npc","text":{"pl":"Mam pomysł: ja ci pokażę, gdzie jest almanach, a ty go odzyskasz!","en":"I have a suggestion to make: I''ll show you the way to the almanac, so you can get it back.","de":"Ich mache dir einen Vorschlag. Ich zeige dir den Weg zum Almanach und du holst ihn zurück."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_help_more_15_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_help_more_15_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_HELP_MORE","outputIds":["Nov_1300_Talas_HELP_MORE_15_01","Nov_1300_Talas_HELP_MORE_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Wejdę w to... za 50 bryłek rudy.","en":"Give me 50 ore and I''m in.","de":"Gib mir 50 Erz und ich bin dabei."}},{"speaker":"npc","text":{"pl":"Co? Toż to rozbój! A zresztą. Daj mi znać, gdy będziesz gotowy do drogi.","en":"What? That''s robbery! Alright then, tell me when you''re ready.","de":"Was? Du beraubst mich. Nun gut, sag mir Bescheid, wenn du so weit bist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_help_ok_15_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_help_ok_15_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_HELP_OK","outputIds":["Nov_1300_Talas_HELP_OK_15_01","Nov_1300_Talas_HELP_OK_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Zgoda.","en":"Agreed.","de":"Einverstanden."}},{"speaker":"npc","text":{"pl":"Świetnie. Wyruszymy, gdy tylko będziesz gotów.","en":"Okay, we can leave as soon as you''re ready.","de":"In Ordnung, wir können losgehen, sobald du bereit bist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_ogy_15_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_ogy_15_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_OGY_Info","outputIds":["Nov_1300_Talas_OGY_15_01","Nov_1300_Talas_OGY_02_02","Nov_1300_Talas_OGY_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Cor Angar. Masz mnie zabrać na Cmentarzysko Orków, gdzie przebywa Baal Lukor i jego Strażnicy.","en":"Cor Angar sent me. He said you should take me to the Orc cemetery so I can find Baal Lukor and his templars.","de":"Cor Angar schickt mich. Er sagt, du sollst mich zum Ork-Friedhof bringen, damit ich dort Baal Lukor und seine Templer suchen kann."}},{"speaker":"npc","text":{"pl":"A więc znów mam robić za przewodnika. Niech to szlag! Bodajbym nigdy nie ujrzał tej księgi na oczy!","en":"So I''m the gofer again. Damn!!! I just should never have lost that almanac...","de":"Schon wieder bin ich der Laufbursche. Verdammt!!! Ich hätte den Almanach einfach nicht verlieren dürfen..."}},{"speaker":"npc","text":{"pl":"No dobrze, chodź za mną.","en":"Well then, come with me.","de":"Na gut, komm mit."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1300_talas_nov_1300_talas_ready_info_15_01_0', 'NOV_1300_Talas', '{"id":"missions_dia_nov_1300_talas_nov_1300_talas_ready_info_15_01_0","npcId":"NOV_1300_Talas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1300_Talas.d","sourceFunction":"Nov_1300_Talas_READY_Info","outputIds":["Nov_1300_Talas_READY_Info_15_01","Nov_1300_Talas_READY_Info_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy, możemy ruszać w drogę.","en":"I''m ready, we can leave now.","de":"Ich bin bereit, wir können losgehen."}},{"speaker":"npc","text":{"pl":"Dobrze. Chodź za mną.","en":"Okay. Follow me.","de":"In Ordnung. Folge mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_add_info_kalom_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_add_info_kalom_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_AddInfoKalom_Info","outputIds":["DIA_Caine_AddInfoKalom_15_00","DIA_Caine_AddInfoKalom_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Co możesz mi jeszcze powiedzieć o swoim mistrzu?","en":"What more can you tell me about your master?","de":"Was kannst du mir noch über deinen Meister erzählen?"}},{"speaker":"npc","text":{"pl":"Jest inny niż pozostali Guru. Każdy może się do niego odezwać, ale NIKOMU nie wolno marnować jego cennego czasu.","en":"He... he''s not like the... the other Gurus. Everybody may address him, but... but NOBODY''s allowed to waste his precious time.","de":"Er ist nicht wie die anderen Gurus. Er getattet jedem, ihn anzusprechen, aber NIEMANDEM seine kostbare Zeit zu verschwenden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_alchemies_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_alchemies_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_Alchemies_Info","outputIds":["DIA_Caine_Alchemies_15_00","DIA_Caine_Alchemies_13_01","DIA_Caine_Alchemies_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Was für alchimistische Substanzen kann ich Kalom bringen?","en":"Was für alchimistische Substanzen kann ich Kalom bringen?","de":"Was für alchimistische Substanzen kann ich Kalom bringen?"}},{"speaker":"npc","text":{"pl":"Kalom benötigt vor allem das Sekret der Minecrawler. Wenn du ihm genug davon beschaffst, wird dich die Wache sicher vorlassen.","en":"Kalom benötigt vor allem das Sekret der Minecrawler. Wenn du ihm genug davon beschaffst, wird dich die Wache sicher vorlassen.","de":"Kalom benötigt vor allem das Sekret der Minecrawler. Wenn du ihm genug davon beschaffst, wird dich die Wache sicher vorlassen."}},{"speaker":"npc","text":{"pl":"Er braucht zwar auch Pflanzen und Beeren, die man zwischen den Lagern findet, aber die nimmt Fortuno unten an.","en":"Er braucht zwar auch Pflanzen und Beeren, die man zwischen den Lagern findet, aber die nimmt Fortuno unten an.","de":"Er braucht zwar auch Pflanzen und Beeren, die man zwischen den Lagern findet, aber die nimmt Fortuno unten an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_hallo_ja_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_hallo_ja_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_Hallo_Ja","outputIds":["DIA_Caine_Hallo_Ja_15_00","DIA_Caine_Hallo_Ja_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Tak.","en":"Yeah.","de":"Ja."}},{"speaker":"npc","text":{"pl":"Zatem wiesz już, że to najważniejszy człowiek w tym obozie, zaraz po Jaśnie Oświeconym Y''Berionie.","en":"Then you''ll know that he''s the second man in this camp... a-after Y''Berion.","de":"Dann weißt du ja, dass er hier der zweitwichtigste Mann nach Y''Berion ist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_hallo_nein_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_hallo_nein_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_Hallo_Nein","outputIds":["DIA_Caine_Hallo_Nein_15_00","DIA_Caine_Hallo_Nein_13_01","DIA_Caine_Hallo_Nein_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie.","en":"No.","de":"Nein."}},{"speaker":"npc","text":{"pl":"Nie?! Chyba jesteś tu od niedawna, co?","en":"No?! You haven''t been here long, have you?","de":"Nicht?! Du bist wohl wirklich noch nicht lange hier, was?"}},{"speaker":"npc","text":{"pl":"Cor Kalom to najważniejszy człowiek w Bractwie, po Y''Berionie. To on decyduje, kto zostanie przyjęty w szeregi Nowicjuszy.","en":"Cor Kalom''s the second most important man after Y''Berion. He decides who may join us as a novice.","de":"Cor Kalom ist der zweitwichtigste Mann nach Y''Berion. Er entscheidet, wer als Novize bei uns aufgenommen wird."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_job_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_job_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_Job_Info","outputIds":["DIA_Caine_Job_15_00","DIA_Caine_Job_13_01","DIA_Caine_Job_13_02"],"lines":[{"speaker":"hero","text":{"pl":"A ty czym się zajmujesz?","en":"And what''s your job?","de":"Und was tust du?"}},{"speaker":"npc","text":{"pl":"Pomagam mojemu mistrzowi w pracach nad jego magicznymi wywarami.","en":"I... I... I help my master prepare his alchemic potions.","de":"Ich helfe meinem Meister bei der Aufbereitung der alchimistischen Substanzen."}},{"speaker":"npc","text":{"pl":"Głównie z ziela bagiennego i wydzieliny pełzaczy. Swoją drogą, mój mistrz pilnie potrzebuje tej wydzieliny.","en":"Mostly s-swampweed and minecrawler secretion. The... the secretion is required very urgently.","de":"Im wesentlichen Sumpfkraut und Minecrawlersekret. Vor allem das Sekret braucht er dringend."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_ways_to_kalom_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_ways_to_kalom_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_WaysToKalom_Info","outputIds":["DIA_Caine_WaysToKalom_15_00","DIA_Caine_WaysToKalom_13_01","DIA_Caine_WaysToKalom_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Ich würde gerne mit Cor Kalom reden - kannst du mir dabei helfen?","en":"Ich würde gerne mit Cor Kalom reden - kannst du mir dabei helfen?","de":"Ich würde gerne mit Cor Kalom reden - kannst du mir dabei helfen?"}},{"speaker":"npc","text":{"pl":"Wenn du zu Cor Kalom willst, mußt du einen guten Grund haben.","en":"Wenn du zu Cor Kalom willst, mußt du einen guten Grund haben.","de":"Wenn du zu Cor Kalom willst, mußt du einen guten Grund haben."}},{"speaker":"npc","text":{"pl":"Die Wache hat Anweisung, nur die vorzulassen, die Alchimistische Substanzen bringen oder von einen der Gurus geschickt wurden.","en":"Die Wache hat Anweisung, nur die vorzulassen, die Alchimistische Substanzen bringen oder von einen der Gurus geschickt wurden.","de":"Die Wache hat Anweisung, nur die vorzulassen, die Alchimistische Substanzen bringen oder von einen der Gurus geschickt wurden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_wie_guru_send_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_wie_guru_send_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_WieGuruSend_Info","outputIds":["DIA_Caine_WieGuruSend_15_00","DIA_Caine_WieGuruSend_13_01","DIA_Caine_WieGuruSend_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Wie bringe ich einen Guru dazu, dass er mich zu Kalom schickt.","en":"Wie bringe ich einen Guru dazu, dass er mich zu Kalom schickt.","de":"Wie bringe ich einen Guru dazu, dass er mich zu Kalom schickt."}},{"speaker":"npc","text":{"pl":"Darüber kann die Lester mehr erzählen.","en":"Darüber kann die Lester mehr erzählen.","de":"Darüber kann die Lester mehr erzählen."}},{"speaker":"npc","text":{"pl":"Bis vor kurzen hat er noch für Cor Kalom gearbeitet, jetzt kümmert er sich zusammen mit den Gurus um die Neuen.","en":"Bis vor kurzen hat er noch für Cor Kalom gearbeitet, jetzt kümmert er sich zusammen mit den Gurus um die Neuen.","de":"Bis vor kurzen hat er noch für Cor Kalom gearbeitet, jetzt kümmert er sich zusammen mit den Gurus um die Neuen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_dia_caine_wo_sekret_15_00_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_dia_caine_wo_sekret_15_00_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"DIA_Caine_WoSekret_Info","outputIds":["DIA_Caine_WoSekret_15_00","DIA_Caine_WoSekret_13_01","DIA_Caine_WoSekret_13_02","DIA_Caine_WoSekret_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę zdobyć tę... Wydzielinę pełzaczy?","en":"Where do I get the minecrawler secretion?","de":"Wo bekomme ich das Sekret der Minecrawler?"}},{"speaker":"npc","text":{"pl":"Stara Kopalnia aż roi się od pełzaczy, ale trzeba umieć pozyskać ich wydzielinę.","en":"You can find crawlers in the Old Mine. But you need to know how to win the secretion.","de":"Crawler findest du in der Alten Mine. Aber du musst wissen wie du ihnen das Sekret abzapfst."}},{"speaker":"npc","text":{"pl":"Jeśli poważnie myślisz o walce z pełzaczami, porozmawiaj z którymś ze Strażników trudniących się polowaniem na nie. Na przykład z Gor Na Drakiem.","en":"If you really want to fight these beasts, you''d better speak to one of the templars who''s had experience. Like Gor Na Drak.","de":"Falls du wirklich vorhast, dich mit den Biestern anzulegen, sprich besser vorher mit einem der Templer, der Erfahrung hat. Zum Beispiel Gor Na Drak."}},{"speaker":"npc","text":{"pl":"On każdego dnia wyrusza z naszego obozu do Starej Kopalni. O świcie znajdziesz go w pobliżu laboratorium.","en":"He travels around between our Camp and... and the Old Mine every day. I-In the mornings you''ll find him at the lab.","de":"Er ist jeden Tag zwischen unserem Lager und der Alten Mine unterwegs. Morgens triffst du ihn unten am Labor."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1301_caine_nov_1301_caine_chest_info_15_01_0', 'NOV_1301_Caine', '{"id":"missions_dia_nov_1301_caine_nov_1301_caine_chest_info_15_01_0","npcId":"NOV_1301_Caine","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1301_Caine.d","sourceFunction":"Nov_1301_Caine_CHEST_Info","outputIds":["Nov_1301_Caine_CHEST_Info_15_01","Nov_1301_Caine_CHEST_Info_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę zdobyć recepturę Kaloma?","en":"How can I get Kalom''s recipe?","de":"Wie komme ich an das Rezept von Kalom?"}},{"speaker":"npc","text":{"pl":"Nie możesz. Wszystkie receptury przechowywane są w zamkniętej skrzyni.","en":"You don''t. He keeps it in a locked chest and won''t give it to anybody.","de":"Gar nicht. Er hält es in seiner Truhe verschlossen. Das rückt er niemals raus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_bloodflies_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_bloodflies_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_Bloodflies_Info","outputIds":["DIA_Viran_Bloodflies_15_00","DIA_Viran_Bloodflies_07_01","DIA_Viran_Bloodflies_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Co mam zrobić?","en":"And what do you want me to do?","de":"Und was soll ich machen?"}},{"speaker":"npc","text":{"pl":"To tylko drobiazg. Praca na bagnach nie należy do najbezpieczniejszych, no i roi się tu od tych przeklętych Krwiopijców.","en":"It''s really nothing. Work in the swamp, it''s a bit risky, and then there''s those damn bloodflies.","de":"Ist nur ''ne Kleinigkeit. Die Arbeit im Sumpf ist nicht ganz ungefährlich, und die verdammten Blutfliegen tun ihr übriges dazu."}},{"speaker":"npc","text":{"pl":"Gdyby ich tutaj nie było, nasza praca stałaby się o wiele bardziej znośna. Kapujesz?","en":"Work would be much easier without them! Do you follow?","de":"Ohne sie wäre das Arbeiten viel leichter! Wir verstehen uns?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_fetch_weed_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_fetch_weed_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_FetchWeed_Info","outputIds":["DIA_Viran_FetchWeed_15_00","DIA_Viran_FetchWeed_07_01","DIA_Viran_FetchWeed_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Przybywam z polecenia Baala Oruna. Mam zabrać wszystko co udało się wam zebrać do Cor Kaloma.","en":"Baal Orun sent me. I''m to take the whole harvest to Kalom.","de":"Baal Orun schickt mich. Ich soll die gesamte Ernte zu Kalom bringen."}},{"speaker":"npc","text":{"pl":"I co, myślisz, że to takie łatwe?","en":"You think it''s that easy, do you?","de":"So einfach stellst du dir das vor, was?"}},{"speaker":"npc","text":{"pl":"Każdy mógłby się tutaj zjawić mówiąc \"Przysyła mnie Baal Orun\". I co wtedy? Mam wydać całe ziele byle włóczędze?","en":"Anybody could turn up like that. ''Baal Orun sent me'' - and whoosh - the whole lot of the weeds were gone.","de":"Da kann ja jeder kommen. ''Baal Orun schickt mich'' - und schwupps - weg ist das ganze Kraut."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_fetch_weed_goto_him_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_fetch_weed_goto_him_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_FetchWeed_GotoHim","outputIds":["DIA_Viran_FetchWeed_GotoHim_15_00","DIA_Viran_FetchWeed_GotoHim_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Jeśli mi nie wierzysz, sam go o to zapytaj!","en":"Go see him and ask him if you don''t believe me!","de":"Geh doch zu ihm und frag ihn, wenn du mir nicht glaubst!"}},{"speaker":"npc","text":{"pl":"Mam lepszy pomysł. Jeśli chcesz nas przekonać, że jesteś tym, za kogo się podajesz, wyświadczysz nam drobną przysługę!","en":"I have a better idea. You prove your loyalty by doing a little job for us!","de":"Ich hab'' ''ne bessere Idee. Du beweist mir deine Loyalität, indem du eine kleine Aufgabe für mich erledigst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_fetch_weed_really_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_fetch_weed_really_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_FetchWeed_Really","outputIds":["DIA_Viran_FetchWeed_Really_15_00","DIA_Viran_FetchWeed_Really_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Ale mnie naprawdę przysyła Baal Orun!","en":"But Baal Orun really has sent me!","de":"Baal Orun schickt mich aber wirklich!"}},{"speaker":"npc","text":{"pl":"Jaaasne.","en":"Sure.","de":"Natürlich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_perm_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_perm_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_Perm_Info","outputIds":["DIA_Viran_Perm_15_00","DIA_Viran_Perm_07_01","DIA_Viran_Perm_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Dobrze się bawicie?","en":"How''s the picking going?","de":"Wie steht''s mit der Sammelei?"}},{"speaker":"npc","text":{"pl":"Śmiało, żartuj sobie ze mnie. Założę się, że zadania, które dostajesz od Guru też nie należą do najprzyjemniejszych.","en":"Yeah, yeah, just take make fun of me. I''m sure you''re getting better jobs from the Gurus.","de":"Ja, ja, verarsch mich ruhig. Ich bin mir sicher, du bekommst bessere Aufgaben von den Gurus."}},{"speaker":"npc","text":{"pl":"Cóż, przynajmniej nie muszę własnoręcznie odwalać brudnej roboty. Od tego jest \"piechota\" - ha ha ha.","en":"Well, at least I don''t need to do the dirty work myself. The ''infantry'' do that - he, he, he.","de":"Na, immerhin muss ich mich nicht selbst bücken. Das übernimmt das Fußvolk - hee, hee, hee."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_rip_off_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_rip_off_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_RipOff_Info","outputIds":["DIA_Viran_RipOff_15_00","DIA_Viran_RipOff_07_01","DIA_Viran_RipOff_15_02","DIA_Viran_RipOff_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam zabrać następny ładunek ziela do Kaloma.","en":"I''m to take all the weeds to Cor Kalom again.","de":"Ich soll noch mal alles Kraut zu Cor Kalom bringen."}},{"speaker":"npc","text":{"pl":"Co, znowu?","en":"Again?","de":"Schon wieder?"}},{"speaker":"hero","text":{"pl":"Chyba nie każesz mi teraz wybić dla ciebie wszystkich błotnych węży, co? Nie mam tyle czasu.","en":"Now you''re not going to tell me to kill all the swampsharks for you, are you? I really don''t have that much time.","de":"Jetzt erzähl mir bloß nicht, ich soll alle Sumpfhaie für dich umbringen - ich hab'' wenig Zeit."}},{"speaker":"npc","text":{"pl":"Dobra już, dobra! Masz tu to cholerne ziele!","en":"Okay okay! Here, take the bloody weeds!","de":"Ist ja schon gut! Hier, nimm das verdammte Kraut!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_running_07_03_4', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_running_07_03_4","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_Running_Info","outputIds":["DIA_Viran_Running_07_03","DIA_Viran_Running_07_04","DIA_Viran_Running_07_05","DIA_Viran_Running_07_06"],"lines":[{"speaker":"npc","text":{"pl":"Cóż, albo jesteś po naszej stronie, albo jesteś skończonym idiotą. Nikt inny nie podjąłby się takiego zadania.","en":"Someone who works like that is either on our side or a complete idiot!","de":"Wer sich so abplagt, ist entweder auf unserer Seite oder ein kompletter Vollidiot!"}},{"speaker":"npc","text":{"pl":"Ale skończony idiota nie próbowałby mnie wykiwać, co nie?","en":"An idiot would be too stupid to fool me, right?","de":"Und ein Idiot wäre zu dumm, um mich aufs Kreuz zu legen, richtig?"}},{"speaker":"npc","text":{"pl":"Masz, to wszystko, co udało się nam zebrać. Zanieś to do Cor Kaloma.","en":"Here, take the harvest and take it to Cor Kalom.","de":"Hier, nimm die Ernte und bring sie zu Cor Kalom."}},{"speaker":"npc","text":{"pl":"Jakby zaczął narzekać, że to za mało, możesz mu powiedzieć, żeby sam ruszył tutaj swój zadek i przekonał się jak ciężko musimy harować.","en":"If he complains and says it''s not enough, tell him to move his butt here himself, to give him an idea of how much hard work it is.","de":"Falls er meckert, es sei zu wenig, sag ihm, er soll seinen Hintern hier selber hinbewegen, dann kann er mal sehen, wie viel Arbeit das ist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_running_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_running_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_Running_Info","outputIds":["DIA_Viran_Running_15_00","DIA_Viran_Running_07_00","DIA_Viran_Running_07_01","DIA_Viran_Running_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie widzę już żadnych Krwiopijców w pobliżu.","en":"I don''t see any more bloodflies anywhere.","de":"Ich seh'' weit und breit keine Blutfliegen mehr."}},{"speaker":"npc","text":{"pl":"Przecież widać kilka z nich w odległości nie większej niż dwadzieścia kroków!","en":"But there are some more bugs within twenty paces!","de":"Da sind aber noch Viecher innerhalb von zwanzig Schritt!"}},{"speaker":"npc","text":{"pl":"Tak łatwo się nie wywiniesz!","en":"You won''t get off that easily!","de":"So leicht kommst du mir nicht davon!"}},{"speaker":"npc","text":{"pl":"Żadnego robala w polu widzenia. Odwaliłeś kawał solidnej roboty!","en":"No more bugs to be seen. That was a good job you did!","de":"Weit und Breit keins von den Biestern mehr zu sehen. Das war ganze Arbeit!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_what_07_04_4', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_what_07_04_4","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_What_Info","outputIds":["DIA_Viran_What_07_04","DIA_Viran_What_07_05"],"lines":[{"speaker":"npc","text":{"pl":"Pozostałe obozy nie mają do niego dostępu. Jesteśmy jedynym osiedlem w całej kolonii, które może zbierać ziele.","en":"Because then the other two camps won''t get it. We''re the only ones in the colony who are able to pick swampweed.","de":"Weil dann die beiden anderen Lager nicht rankommen. Wir sind die Einzigen in der Kolonie, die Sumpfkraut ernten können."}},{"speaker":"npc","text":{"pl":"Możemy je sprzedawać do pozostałych obozów, i to za każdą cenę, jakiej zażądamy!","en":"We can trade it with the other two camps - and WE can set the price.","de":"In den beiden anderen Lagern können wir es tauschen - und WIR bestimmen den Preis."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1302_viran_dia_viran_what_15_00_0', 'NOV_1302_Viran', '{"id":"missions_dia_nov_1302_viran_dia_viran_what_15_00_0","npcId":"NOV_1302_Viran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1302_Viran.d","sourceFunction":"DIA_Viran_What_Info","outputIds":["DIA_Viran_What_15_00","DIA_Viran_What_07_01","DIA_Viran_What_07_02","DIA_Viran_What_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Czym się zajmujecie?","en":"What are you doing here?","de":"Was macht ihr hier?"}},{"speaker":"npc","text":{"pl":"Zbieramy bagienne ziele, które zostanie przetworzone przez naszych braci tak, by można było je palić.","en":"We''re picking the swampweed to be processed by our brothers, so it can be smoked later on.","de":"Wir sammeln das Sumpfkraut, das unsere Brüder dann zu Rauchwaren verarbeiten."}},{"speaker":"npc","text":{"pl":"Praca na bagnach jest bardzo niebezpieczna, ale ziele rośnie wyłącznie tutaj. Oczywiście ma to również pewne zalety.","en":"It''s quite dangerous to pick it in the swamp, but the stuff only grows here. Actually, that''s a good thing.","de":"Es ist ziemlich gefährlich, im Sumpf zu sammeln, aber das Zeug wächst nun mal nur hier. Ist auch gut so."}},{"speaker":"hero","text":{"pl":"Jakie?","en":"Why?","de":"Warum?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_dia_nyras_hallo_15_00_0', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_dia_nyras_hallo_15_00_0","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"DIA_Nyras_Hallo_Info","outputIds":["DIA_Nyras_Hallo_15_00","DIA_Nyras_Hallo_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Cześć, jestem tu nowy.","en":"Hi! I''m new here.","de":"Hi! Ich bin neu hier."}},{"speaker":"npc","text":{"pl":"Niech Śniący będzie z tobą, nieznajomy.","en":"The Sleeper be with you, stranger!","de":"Der Schläfer sei mit dir, Fremder!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_dia_nyras_ort_15_00_0', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_dia_nyras_ort_15_00_0","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"DIA_Nyras_Ort_Info","outputIds":["DIA_Nyras_Ort_15_00","DIA_Nyras_Ort_03_01","DIA_Nyras_Ort_03_02","DIA_Nyras_Ort_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Co możesz mi powiedzieć o tym miejscu?","en":"What can you tell me about this place?","de":"Was kannst du mir über diesen Ort sagen?"}},{"speaker":"npc","text":{"pl":"Cóż - najważniejszymi osobami w obozie są Guru. Oni głoszą słowo Śniącego i przekazują Nowicjuszom informacje o wizjach naszego Mistrza.","en":"Well - the Gurus are the most important people here. They spread the word of the Sleeper and pass our master''s visions on to the novices.","de":"Nun - die Gurus sind die wichtigsten Leute hier. Sie verbreiten die Lehre des Schläfers, und teilen den Novizen die Visionen unseres Meisters mit."}},{"speaker":"npc","text":{"pl":"On sam jest naturalnie zbyt zapracowany, by rozmawiać ze wszystkimi osobiście.","en":"Of course he''s too tired to talk to everybody himself.","de":"Er selbst ist natürlich viel zu erschöpft, um immer zu allen zu reden."}},{"speaker":"npc","text":{"pl":"Ale czasami przemawia do zgromadzonych na świątynnym dziedzińcu, objawiając święte prawdy ustanowione przez Śniącego.","en":"But on some days he speaks to us in the temple courtyard and reveals the holy words of the Sleeper.","de":"Aber an manchen Tagen spricht er auf dem Tempelplatz zu uns und offenbart uns die heiligen Worte des Schläfers."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_dia_nyras_ort_casual_15_00_0', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_dia_nyras_ort_casual_15_00_0","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"DIA_Nyras_Ort_Casual","outputIds":["DIA_Nyras_Ort_Casual_15_00","DIA_Nyras_Ort_Casual_03_01"],"lines":[{"speaker":"hero","text":{"pl":"I co wtedy mówi?","en":"And what does he say then?","de":"Und was sagt er so?"}},{"speaker":"npc","text":{"pl":"Śniący wskazuje nam jedyną słuszną drogę. Ale niewierny nigdy tego nie zrozumie!","en":"The Sleeper guides the way. But an infidel like you wouldn''t understand that!","de":"Der Schläfer weist uns unseren Weg. Aber davon versteht ein Ungläubiger wie du nichts!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_dia_nyras_ort_holy_03_04_4', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_dia_nyras_ort_holy_03_04_4","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"DIA_Nyras_Ort_Holy","outputIds":["DIA_Nyras_Ort_Holy_03_04","DIA_Nyras_Ort_Holy_03_05"],"lines":[{"speaker":"npc","text":{"pl":"Pomaga mu w tym Cor Kalom, alchemik, który przygotowuje magiczne wywary wprowadzające nas w stan transu.","en":"Cor Kalom supports him. He''s an alchemist who brews substances which put us into a sleep-like state.","de":"Cor Kalom unterstützt ihn dabei. Er ist Alchimist und braut Substanzen zusammen, die uns in einen schlafähnlichen Zustand versetzen."}},{"speaker":"npc","text":{"pl":"Tylko w transie - lub we śnie - można usłyszeć słowa naszego Wyzwoliciela.","en":"You can only receive the thoughts of the Sleeper in this state - or when sleeping.","de":"Nur in diesem Zustand - oder wenn du schläfst - kannst du die Gedanken des Schläfers empfangen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_dia_nyras_ort_holy_15_00_0', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_dia_nyras_ort_holy_15_00_0","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"DIA_Nyras_Ort_Holy","outputIds":["DIA_Nyras_Ort_Holy_15_00","DIA_Nyras_Ort_Holy_03_01","DIA_Nyras_Ort_Holy_03_02","DIA_Nyras_Ort_Holy_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi jeszcze o świętych słowach Śniącego.","en":"Tell me about the holy words of the great Sleeper.","de":"Berichte mir von den heiligen Worten des großen Schläfers."}},{"speaker":"npc","text":{"pl":"On będzie tym, który wyprowadzi nas na wolność.","en":"HE tells us what we need to do to gain freedom again.","de":"ER sagt uns, was wir tun müssen, um die Freiheit zu erlangen."}},{"speaker":"npc","text":{"pl":"Y''Berion powiedział, że poznamy właściwą drogę, jak tylko uda się nam nawiązać kontakt ze Śniącym.","en":"Y''Berion says that the Sleeper will show us the way as soon as we''re able to hear him.","de":"Y''Berion sagt, der Schläfer wird uns den Weg mitteilen, sobald wir in der Lage sind, ihn zu hören."}},{"speaker":"npc","text":{"pl":"Nasz Mistrz przygotowuje rytuał wielkiego przyzwania, podczas którego wspólnie z najlepszymi Nowicjuszami nawiąże kontakt ze Śniącym.","en":"He''s preparing a great invocation, in which he''ll contact the Sleeper together with the best novices.","de":"Er bereitet eine große Anrufung vor, in der er zusammen mit den besten Novizen mit dem Schläfer in Kontakt treten will."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_nov_1303_nyras_greet_info_03_00_0', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_nov_1303_nyras_greet_info_03_00_0","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"Nov_1303_Nyras_GREET_Info","outputIds":["Nov_1303_Nyras_GREET_Info_03_00"],"lines":[{"speaker":"npc","text":{"pl":"Idź precz! Nie masz tu czego szukać!","en":"Scram! You have no business to be here!","de":"Verschwinde! Hier gibt es nichts für dich zu holen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_nov_1303_nyras_leave_info_03_05_4', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_nov_1303_nyras_leave_info_03_05_4","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"Nov_1303_Nyras_LEAVE_Info","outputIds":["Nov_1303_Nyras_LEAVE_Info_03_05","Nov_1303_Nyras_LEAVE_Info_03_06","Nov_1303_Nyras_LEAVE_Info_03_07"],"lines":[{"speaker":"npc","text":{"pl":"Teraz jestem jedynym prawdziwym sługą Śniącego. Żadnej Straży, żadnych Guru!","en":"Now I''ll only serve the Sleeper. No more templars or Gurus!","de":"Nun werde nur noch ich dem Schläfer dienen. Keine Templer, keine Gurus mehr!"}},{"speaker":"npc","text":{"pl":"TYLKO JA!!!","en":"OOONNNLLLLYYYYYY MEEEEEEEEE AAALLLOOONE!!!!!!!!!","de":"NUUUUR ICHHHH ALEEEEEINEEEEEEE!!!!!!!!!"}},{"speaker":"npc","text":{"pl":"GIŃ!","en":"DIIIIIIIIEE!!!!!","de":"STIIIIIIRB!!!!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1303_nyras_nov_1303_nyras_leave_info_15_01_0', 'NOV_1303_Nyras', '{"id":"missions_dia_nov_1303_nyras_nov_1303_nyras_leave_info_15_01_0","npcId":"NOV_1303_Nyras","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1303_Nyras.d","sourceFunction":"Nov_1303_Nyras_LEAVE_Info","outputIds":["Nov_1303_Nyras_LEAVE_Info_15_01","Nov_1303_Nyras_LEAVE_Info_03_02","Nov_1303_Nyras_LEAVE_Info_03_03","Nov_1303_Nyras_LEAVE_Info_03_04"],"lines":[{"speaker":"hero","text":{"pl":"Szukam kamienia ogniskującego!","en":"I''m searching for the focus.","de":"Ich bin auf der Suche nach dem Fokus."}},{"speaker":"npc","text":{"pl":"Obawiam się, że trochę się spóźniłeś! Ja go znalazłem wcześniej!","en":"Unfortunately you''re too late for that. I''ve already found it!","de":"Da kommst du leider zu spät. Ich habe ihn bereits gefunden!"}},{"speaker":"npc","text":{"pl":"I zamierzam go sobie zatrzymać!","en":"And I''m keeping it for myself!","de":"Und ich werde ihn für mich selbst behalten!"}},{"speaker":"npc","text":{"pl":"Śniący przemówił do mnie ostatniej nocy i uczynił mnie swym arcykapłanem!","en":"The Sleeper talked to me last night and made me his only tool!","de":"Der Schläfer sprach heute Nacht zu mir und machte mich zu seinem alleinigen Werkzeug!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1304_balor_dia_balor_fetch_weed_15_00_0', 'NOV_1304_Balor', '{"id":"missions_dia_nov_1304_balor_dia_balor_fetch_weed_15_00_0","npcId":"NOV_1304_Balor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1304_Balor.d","sourceFunction":"DIA_Balor_FetchWeed_Info","outputIds":["DIA_Balor_FetchWeed_15_00","DIA_Balor_FetchWeed_01_01","DIA_Balor_FetchWeed_01_02","DIA_Balor_FetchWeed_01_03"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Baal Orun. Mam dostarczyć do obozu zebrane przez was ziele.","en":"Baal Orun sent me. I''m to collect all the swampweed.","de":"Baal Orun schickt mich. Ich soll hier alles Sumpfkraut abholen."}},{"speaker":"npc","text":{"pl":"Świetnie. Nie będę musiał sam tego dźwigać.","en":"Good. Then I don''t need to go myself. Here, take it.","de":"Gut. Dann muss ich nicht selber laufen. Hier, nimm."}},{"speaker":"npc","text":{"pl":"Nie zapomnij zajrzeć do Virana, po drugiej stronie bagna, jeśli jeszcze cię tam nie było.","en":"Don''t forget to go to Viran on the other side of the swamp, if you haven''t been there yet.","de":"Vergiss nicht, zu Viran auf der anderen Seite vom Sumpf zu gehen, wenn du nicht schon da warst."}},{"speaker":"npc","text":{"pl":"W przeciwnym razie dostawa będzie zbyt mała i ktoś mógłby pomyśleć, że sprzedałeś część towaru komuś innemu, he he.","en":"Otherwise your load might be a bit small and people might think you''d sold the other half of it, hee, hee.","de":"Sonst könnte deine Lieferung ein bisschen mickrig ausfallen, und alle würden denken, du hast die Hälfte verhökert, hee, hee."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1304_balor_dia_balor_perm_15_00_0', 'NOV_1304_Balor', '{"id":"missions_dia_nov_1304_balor_dia_balor_perm_15_00_0","npcId":"NOV_1304_Balor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1304_Balor.d","sourceFunction":"DIA_Balor_Perm_Info","outputIds":["DIA_Balor_Perm_15_00","DIA_Balor_Perm_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie przeszkadzaj sobie w pracy!","en":"Just keep picking hard!","de":"Immer tüchtig weitersammeln!"}},{"speaker":"npc","text":{"pl":"A myślisz, że co ja robię? Grzebię sobie w jajach?","en":"Of course, what do you think I''m doing? Rocking my balls?","de":"Na klar, was denkst du denn, was ich hier mache? Mir die Eier schaukeln?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1304_balor_dia_balor_rip_off_15_00_0', 'NOV_1304_Balor', '{"id":"missions_dia_nov_1304_balor_dia_balor_rip_off_15_00_0","npcId":"NOV_1304_Balor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1304_Balor.d","sourceFunction":"DIA_Balor_RipOff_Info","outputIds":["DIA_Balor_RipOff_15_00","DIA_Balor_RipOff_01_01","DIA_Balor_RipOff_01_02","DIA_Balor_RipOff_01_03"],"lines":[{"speaker":"hero","text":{"pl":"To ja, wróciłem. Przychodzę po następną dostawę.","en":"It''s me, I''m back. I''m to pick up the next delivery.","de":"Da bin ich wieder. Ich soll die nächste Ladung abholen."}},{"speaker":"npc","text":{"pl":"Jasne! Żeby sprzedać ją znowu w Nowym Obozie!","en":"Of course! To sell it off to the New Camp again?","de":"Na klar! Und sie wieder ans Neue Lager verhökern!"}},{"speaker":"npc","text":{"pl":"Najpierw moje 50 bryłek zaliczki!","en":"I wanna see 50 ore - my usual advance payment.","de":"Ich will 50 Erz sehen - mein üblicher Vorschuss."}},{"speaker":"npc","text":{"pl":"Znowu ty? No dobra, bierz. Tylko nie próbuj wywinąć jakiegoś numeru, jasne?","en":"You again? Well then, here, take it, but don''t do anything stupid, you got that?","de":"Du schon wieder? Na gut, hier nimm, aber mach keine Dummheiten damit, klar?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1304_balor_dia_balor_tell_dealer_15_00_0', 'NOV_1304_Balor', '{"id":"missions_dia_nov_1304_balor_dia_balor_tell_dealer_15_00_0","npcId":"NOV_1304_Balor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1304_Balor.d","sourceFunction":"DIA_Balor_TellDealer_Info","outputIds":["DIA_Balor_TellDealer_15_00","DIA_Balor_TellDealer_01_01","DIA_Balor_TellDealer_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Dobra. Kto będzie odbiorcą w Nowym Obozie?","en":"Okay - who''s the buyer in the New Camp?","de":"Okay - wer ist der Abnehmer im Neuen Lager?"}},{"speaker":"npc","text":{"pl":"Myślisz, że podam ci imię, a ty ulotnisz się z całym towarem? Tak łatwo ci nie pójdzie!","en":"You think I''ll give you the name and you can just make a run with the weed - it doesn''t work quite like that!","de":"Ich verrat dir den Namen und du bist mit dem Kraut über alle Berge - so läuft das nicht!"}},{"speaker":"npc","text":{"pl":"Chcę 50 bryłek rudy zaliczki. Wtedy pogadamy.","en":"I wanna see 50 ore as an advance payment. Then we''ll see.","de":"Ich will 50 Erz Vorschuss sehen. Dann sehen wir weiter."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1304_balor_dia_balor_tell_dealer_forget_it_15_00_0', 'NOV_1304_Balor', '{"id":"missions_dia_nov_1304_balor_dia_balor_tell_dealer_forget_it_15_00_0","npcId":"NOV_1304_Balor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1304_Balor.d","sourceFunction":"DIA_Balor_TellDealer_ForgetIt","outputIds":["DIA_Balor_TellDealer_ForgetIt_15_00","DIA_Balor_TellDealer_ForgetIt_01_01","DIA_Balor_TellDealer_ForgetIt_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Zapomnij o tym.","en":"Forget it.","de":"Vergiss es."}},{"speaker":"npc","text":{"pl":"Tylko nie wyobrażaj sobie, że możesz tak po prostu pójść do Nowego Obozu i sprzedać towar byle komu! Jeśli nie trafisz na właściwego człowieka, nigdy się go nie pozbędziesz.","en":"Don''t think you can simply walk into the New Camp and sell it to anybody! If you don''t know the right name, you''ll never get rid of it.","de":"Denk bloß nicht, du könntest einfach ins Neue Lager spazieren und es irgendwem andrehen! Wenn du den richtigen Namen nicht kennst, wirst du es nie los."}},{"speaker":"npc","text":{"pl":"No chyba, że jakiś Szkodnik ci go zabierze.","en":"Unless you let some rogue whack you on the nut.","de":"Es sei denn, du lässt dir von einem Banditen über die Rübe hauen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1304_balor_dia_balor_tell_dealer_pay_15_00_0', 'NOV_1304_Balor', '{"id":"missions_dia_nov_1304_balor_dia_balor_tell_dealer_pay_15_00_0","npcId":"NOV_1304_Balor","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1304_Balor.d","sourceFunction":"DIA_Balor_TellDealer_Pay","outputIds":["DIA_Balor_TellDealer_Pay_15_00","DIA_Balor_TellDealer_Pay_01_01","DIA_Balor_TellDealer_Pay_01_02","DIA_Balor_TellDealer_Pay_NoOre_01_00"],"lines":[{"speaker":"hero","text":{"pl":"50 bryłek to uczciwa cena. Proszę bardzo.","en":"50''s fair - here you go.","de":"50 sind fair - hier, nimm."}},{"speaker":"npc","text":{"pl":"Dobra, słuchaj. Facet nazywa się Cipher. Znajdziesz go pewnie w karczmie na jeziorze,","en":"Good... Listen. His name''s Cipher. You''ll probably find him in the bar on the lake.","de":"Gut... Hör zu. Sein Name ist Cipher. Du findest ihn meistens in der Kneipe auf dem See."}},{"speaker":"npc","text":{"pl":"Bądź ostrożny i nie daj się zrobić w konia.","en":"Be careful and don''t let anybody fool you.","de":"Sei vorsichtig und lass dich nicht über''s Ohr hauen."}},{"speaker":"npc","text":{"pl":"Nie widzę tu żadnych 50 bryłek. Chcę 50 i ani sztuki mniej, jasne?","en":"I don''t see any 50 ore. I want 50 ore and not a nugget less, okay?","de":"Ich sehe keine 50. Ich will 50 und keinen Brocken weniger, klar?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_get_magic_15_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_get_magic_15_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_GetMagic_Info","outputIds":["DIA_Joru_GetMagic_15_00","DIA_Joru_GetMagic_07_01","DIA_Joru_GetMagic_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę opanować magię Śniącego?","en":"How do I get at the magic of the Sleeper?","de":"Wie komme ich an die Magie des Schläfers?"}},{"speaker":"npc","text":{"pl":"Baal Cadar sprzedaje magiczne runy i zwoje z zaklęciami, ale to dla ciebie niewielka pociecha, bo nie będzie chciał z tobą rozmawiać.","en":"Baal Cadar sells runes and spell scrolls. That''s no use to you if he doesn''t talk to you, right?","de":"Baal Cadar verkauft Runen und Spruchrollen. Aber das nützt dir ja nicht viel, wenn er nicht mit dir redet, richtig?"}},{"speaker":"npc","text":{"pl":"Może inny Guru będzie mógł ci pomóc.","en":"Maybe another Guru can help you.","de":"Vielleicht kann einer der anderen Gurus dir helfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_greet_07_04_4', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_greet_07_04_4","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_Greet_Info","outputIds":["DIA_Joru_Greet_07_04","DIA_Joru_Greet_07_05"],"lines":[{"speaker":"npc","text":{"pl":"Ale to jeszcze przyszłość. Nie spieszy mi się, rozumiesz? Zostanę mistrzem, gdy przyjdzie odpowiednia pora.","en":"But I''m still putting that off. There''s no rush - you understand? I can still become a master anytime.","de":"Aber ich schiebe das so''n bisschen vor mir her. Eilt ja nicht - verstehst du? Meister kann ich ja immer noch werden."}},{"speaker":"npc","text":{"pl":"Chwilowo jestem bardzo zadowolony z mojej pracy.","en":"At the moment I''m quite happy about my current task.","de":"Im Moment bin ich ganz zufrieden mit meiner jetzigen Aufgabe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_greet_15_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_greet_15_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_Greet_Info","outputIds":["DIA_Joru_Greet_15_00","DIA_Joru_Greet_07_01","DIA_Joru_Greet_07_02","DIA_Joru_Greet_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Czym się tu zajmujesz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Przekazuję mądrość Śniącego naszym Nowicjuszom.","en":"I''m teaching the words of the Sleeper to the novices.","de":"Ich verbreite die Lehre des Schläfers an die Novizen."}},{"speaker":"npc","text":{"pl":"Sam jestem jeszcze Nowicjuszem, ale już wkrótce zostanę Baalem - jednym z Guru.","en":"I''m still a novice myself, but soon I''ll be a Baal - one of the Gurus.","de":"Ich bin selbst noch Novize, aber bald bin ich ein Baal - einer der Gurus."}},{"speaker":"npc","text":{"pl":"Rozmawiałem nawet z Y''Berionem. To wielki Wybraniec. Powiedział mi, że jeśli będę pracował wystarczająco ciężko, niedługo sam zostanę wielkim mistrzem.","en":"I''ve even spoken to Y''Berion. He''s the chosen one. He told me that if I work hard, I can soon be a master myself.","de":"Ich habe sogar schon mit Y''Berion geredet. Er ist der Auserwählte. Er hat mir gesagt, wenn ich hart an mir arbeite, bin ich bald selbst ein Meister."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_impress_gurus_07_04_4', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_impress_gurus_07_04_4","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_ImpressGurus_Info","outputIds":["DIA_Joru_ImpressGurus_07_04","DIA_Joru_ImpressGurus_07_05","DIA_Joru_ImpressGurus_15_06","DIA_Joru_ImpressGurus_07_07"],"lines":[{"speaker":"npc","text":{"pl":"Baal Namib to ten przy bramie. To jeden z najpotężniejszych ludzi w obozie. Lester będzie mógł ci jakoś pomóc. Porozmawiaj z nim jak tylko mistrz oddali się na chwilę.","en":"Baal Namib is over there at the main gate. He''s one of the toughest guys. I think Lester might be able to help you with him. Speak to him as soon as his master is away.","de":"Baal Namib vorne am Haupttor ist einer der harten Brocken. Ich denke, bei ihm kann dir Lester helfen. Sprich ihn drauf an, wenn sein Meister gerade nicht dabei ist."}},{"speaker":"npc","text":{"pl":"Pozostali Guru są mniej wymagający. Spróbuj się im jakoś przypodobać, a raz-dwa - dostaniesz się do Bractwa!","en":"The other Gurus are basically quite okay - just try to make yourself useful.","de":"Die anderen Gurus sind eigentlich ganz in Ordnung - versuch dich einfach nützlich zu machen."}},{"speaker":"hero","text":{"pl":"Dzięki za radę.","en":"Thanks for the advice.","de":"Danke für die Tipps."}},{"speaker":"npc","text":{"pl":"W końcu umowa to umowa, nie?","en":"Hey - a deal''s a deal.","de":"Hey - eine Hand wäscht die andere."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_impress_gurus_15_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_impress_gurus_15_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_ImpressGurus_Info","outputIds":["DIA_Joru_ImpressGurus_15_00","DIA_Joru_ImpressGurus_07_01","DIA_Joru_ImpressGurus_07_02","DIA_Joru_ImpressGurus_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę przekonać do siebie Guru?","en":"How can I impress the Gurus?","de":"Wie kann ich die Gurus beeindrucken?"}},{"speaker":"npc","text":{"pl":"Baal Cadar wprowadza Nowicjuszy w tajniki magii.","en":"Baal Cadar instructs the novices in the magic of the Sleeper.","de":"Baal Cadar unterrichtet die Novizen in der Magie des Schläfers."}},{"speaker":"npc","text":{"pl":"Jeśli chcesz zwrócić na siebie jego uwagę, posłuż się czarami.","en":"If you want his attention, use magic.","de":"Wenn du seine Aufmerksamkeit willst, wende Magie an."}},{"speaker":"npc","text":{"pl":"Tylko nie potraktuj go od razu Uderzeniem Wiatru! Uśpij któregoś z jego uczniów, albo coś w tym stylu.","en":"But don''t give him the Fist of Wind! Send one of his audience to sleep or something like that.","de":"Aber blas ihm keine Windfaust um die Ohren! Versetze einen seiner Zuhörer in Schlaf oder so was."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_join_psi_15_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_join_psi_15_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_JoinPsi_Info","outputIds":["DIA_Joru_JoinPsi_15_00","DIA_Joru_JoinPsi_07_01","DIA_Joru_JoinPsi_07_02","DIA_Joru_JoinPsi_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym dołączyć do waszego obozu. Możesz mi pomóc?","en":"I''d like to join your camp - can you help me?","de":"Ich will mich eurem Lager anschließen - kannst du mir dabei helfen?"}},{"speaker":"npc","text":{"pl":"Chcesz do nas dołączyć! To świetnie! Zaczekaj... Tak, chyba mógłbym ci pomóc!","en":"You want to join us? That''s good! Just wait... yes, I think I can help you.","de":"Du willst bei uns mitmachen? Das ist gut! Warte mal ... Ja, ich glaube, ich kann dir helfen."}},{"speaker":"npc","text":{"pl":"Nie jestem jeszcze Guru, ale mam pewne wpływy w Bractwie.","en":"I''m not a Guru yet, but I have some influence in the Brotherhood.","de":"Ich bin zwar noch kein Guru, aber ich habe einigen Einfluss in der Bruderschaft."}},{"speaker":"npc","text":{"pl":"Oczywiście musiałbyś wyświadczyć mi drobną przysługę. Rozmawiałeś już z Fortuno?","en":"You''d have to do me a favor. Have you seen Fortuno yet?","de":"Du müsstest mir einen kleinen Gefallen tun. Bist du schon bei Fortuno gewesen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_join_psi_ja_07_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_join_psi_ja_07_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_JoinPsi_Ja","outputIds":["DIA_Joru_JoinPsi_Ja_07_00","DIA_Joru_JoinPsi_Ja_15_01"],"lines":[{"speaker":"npc","text":{"pl":"Zatem masz swoją dzienną rację? Jeśli mi ją oddasz, dobijemy targu.","en":"Then you have your daily ration? If you give it to me then we''re in business.","de":"Dann hast du bestimmt schon deine tägliche Ration bekommen? Wenn du sie mir überlässt, sind wir im Geschäft."}},{"speaker":"hero","text":{"pl":"Przemyślę to sobie.","en":"I''ll think about it.","de":"Ich denke drüber nach."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_join_psi_nein_07_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_join_psi_nein_07_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_JoinPsi_Nein","outputIds":["DIA_Joru_JoinPsi_Nein_07_00","DIA_Joru_JoinPsi_Nein_15_01"],"lines":[{"speaker":"npc","text":{"pl":"W takim razie idź do niego i odbierz swoją dzienną rację. Jeśli dasz mi całe ziele, które od niego otrzymasz, dobijemy targu.","en":"Then go, see him and collect your daily ration. If you leave me all the swampweed he gives you, we''re in business.","de":"Dann geh zu ihm und hol dir deine tägliche Ration ab. Wenn du mir alles Sumpfkraut überlässt, das er dir gibt, sind wir im Geschäft."}},{"speaker":"hero","text":{"pl":"Przemyślę to sobie.","en":"I''ll think about it.","de":"Ich denk drüber nach."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_joints_running_15_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_joints_running_15_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_JointsRunning_Info","outputIds":["DIA_Joru_JointsRunning_15_00","DIA_Joru_JointsRunning_07_01","DIA_Joru_JointsRunning_07_02","DIA_Joru_JointsRunning_NO_JOINTS_07_00"],"lines":[{"speaker":"hero","text":{"pl":"Mam ziele przy sobie. Możemy zawrzeć układ.","en":"I have swampweed on me. You can have it.","de":"Ich habe Sumpfkraut bei mir. Du kannst es haben."}},{"speaker":"npc","text":{"pl":"Dobrze. Zauważyłeś pewnie, że żaden z Guru nie chce z tobą rozmawiać.","en":"Good! You must have noticed that none of the Gurus wants to talk to you.","de":"Gut! Du hast sicher schon bemerkt, dass so gut wie keiner der Gurus mit dir reden will."}},{"speaker":"npc","text":{"pl":"Możesz to zmienić, sprawiając na nich dobre wrażenie. Mogę ci powiedzieć, jak tego dokonać.","en":"You can change that by impressing them. I can tell you how to do that.","de":"Du kannst das ändern, indem du sie beeindruckst. Ich kann dir verraten, wie du das anstellst."}},{"speaker":"npc","text":{"pl":"Miał być Mrok Północy a nie jakaś trawa! Przynieś mi to, o co cię prosiłem, wtedy dobijemy targu!","en":"We agreed on three Northern Dark and nothing else! Get me the weeds, THEN we can do business!","de":"Drei Schwarzer Weiser waren ausgemacht, und nichts anderes! Besorg mir erst das Kraut, DANN sind wir im Geschäft!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_sleeper_contact_07_04_4', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_sleeper_contact_07_04_4","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_SleeperContact_Info","outputIds":["DIA_Joru_SleeperContact_07_04"],"lines":[{"speaker":"npc","text":{"pl":"Ale niedługo ja sam zostanę Guru. Wtedy otrzymam odpowiednią porcję ziela i będę mógł osobiście wysłuchać głosu Śniącego.","en":"But soon I''ll be a Guru myself, then I can go right to my limits and listen to the voice of the Sleeper myself.","de":"Aber bald bin ich ja selber ein Guru, dann kann ich bis an meine Grenzen gehen und auch die Stimme des Schläfers vernehmen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_sleeper_contact_15_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_sleeper_contact_15_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_SleeperContact_Info","outputIds":["DIA_Joru_SleeperContact_15_00","DIA_Joru_SleeperContact_07_01","DIA_Joru_SleeperContact_07_02","DIA_Joru_SleeperContact_07_03"],"lines":[{"speaker":"hero","text":{"pl":"A tobie udało się kiedyś stanąć przed obliczem Śniącego?","en":"Have you ever been in contact with the Sleeper?","de":"Hattest du schon Kontakt zum Schläfer?"}},{"speaker":"npc","text":{"pl":"Nie, jeszcze nie! Ale tylko dlatego, że nie dostajemy wystarczającej ilości ziela.","en":"No. Not yet. But that''s because we never get enough of the stuff.","de":"Nein. Bis jetzt noch nicht. Wir kriegen auch nie genug von dem Zeug."}},{"speaker":"npc","text":{"pl":"Kalom zawsze pyta nas o efekty, ale odnoszę wrażenie, że wcale mu nie zależy na moim zdaniu.","en":"Kalom always wants to hear about the effect of it, but I get the impression he''s not really interested in my opinion at all.","de":"Kalom will zwar immer von mir wissen, wie die Wirkung war, aber ich habe den Eindruck, meine Meinung interessiert ihn gar nicht so sehr."}},{"speaker":"npc","text":{"pl":"Jeśli jego wynalazki działają stymulująco, natychmiast trafiają do Guru...","en":"If I find the stuff stimulating, he passes it straight on to the Gurus...","de":"Wenn ich die Wirkung anregend fand, gibt er das Zeug direkt weiter an die Gurus ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1305_joru_dia_joru_tester_15_00_0', 'NOV_1305_Joru', '{"id":"missions_dia_nov_1305_joru_dia_joru_tester_15_00_0","npcId":"NOV_1305_Joru","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1305_Joru.d","sourceFunction":"DIA_Joru_Tester_Info","outputIds":["DIA_Joru_Tester_15_00","DIA_Joru_Tester_07_01","DIA_Joru_Tester_07_02","DIA_Joru_Tester_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Na czym polega twoja praca?","en":"What''s your task here?","de":"Was ist deine Aufgabe hier?"}},{"speaker":"npc","text":{"pl":"Wraz z kolegami testuję magiczne substancje opracowane przez Cor Kaloma w jego laboratorium.","en":"I test the new substances developed by Cor Kalom in his alchemy lab with my pals here.","de":"Ich teste mit den Jungs hier die neuen Substanzen, die Cor Kalom in seinem Alchimielabor entwickelt."}},{"speaker":"npc","text":{"pl":"Jego asystent przynosi nam co kilka dni coś nowego, a my to testujemy.","en":"His aide gives us something new every couple of days. And we test it.","de":"Sein Gehilfe bringt alle paar Tage was Neues raus. Und wir testen es dann."}},{"speaker":"npc","text":{"pl":"To ziele otwiera twoją duszę. Po zażyciu odpowiedniej ilości będziesz mógł nawiązać kontakt ze Śniącym!","en":"This weed opens your spirit. If you take the right amount, you can get in touch with the Sleeper.","de":"Dieses Kraut öffnet deinen Geist. Wenn du die richtige Menge einnimmst, kannst du in Kontakt mit dem Schläfer treten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1310_ghorim_dia_ghorim_missing_harlok_15_00_0', 'NOV_1310_Ghorim', '{"id":"missions_dia_nov_1310_ghorim_dia_ghorim_missing_harlok_15_00_0","npcId":"NOV_1310_Ghorim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1310_Ghorim.d","sourceFunction":"DIA_Ghorim_MissingHarlok_Info","outputIds":["DIA_Ghorim_MissingHarlok_15_00","DIA_Ghorim_MissingHarlok_02_01","DIA_Ghorim_MissingHarlok_02_02","DIA_Ghorim_MissingHarlok_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Cześć, jak leci?","en":"Hi! How''s it going?","de":"Hi! Wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Ledwie się trzymam na nogach. Pracuję od dwóch dni, bez chwili przerwy.","en":"I''m dead on my feet, man. I''ve been working for two days without a single break.","de":"Ich bin total fertig, Mann. Ich arbeite jetzt schon seit 2 Tagen ohne Pause."}},{"speaker":"npc","text":{"pl":"Harlok powinien mnie zmienić już dawno temu. Ten człowiek nigdy się nie zmieni.","en":"Harlok should have taken over ages ago. It''s always the same with that guy.","de":"Harlok sollte mich längst abgelöst haben. Es ist immer dasselbe mir dem Kerl."}},{"speaker":"npc","text":{"pl":"Pewnie śpi teraz jak zabity w swojej chacie!","en":"He''s probably lying in his hut, fast asleep!","de":"Er liegt bestimmt noch in seiner Hütte und pennt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1310_ghorim_dia_ghorim_missing_harlok_15_04_4', 'NOV_1310_Ghorim', '{"id":"missions_dia_nov_1310_ghorim_dia_ghorim_missing_harlok_15_04_4","npcId":"NOV_1310_Ghorim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1310_Ghorim.d","sourceFunction":"DIA_Ghorim_MissingHarlok_Info","outputIds":["DIA_Ghorim_MissingHarlok_15_04","DIA_Ghorim_MissingHarlok_02_05","DIA_Ghorim_MissingHarlok_02_06","DIA_Ghorim_MissingHarlok_02_07"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego nie pójdziesz do niego i nie dasz mu porządnego kopa w tyłek?","en":"Why don''t you just go there and give him a right kick in the butt?","de":"Wieso gehst du dann nicht zu ihm und trittst ihm ordentlich in den Hintern?"}},{"speaker":"npc","text":{"pl":"Nie mogę stąd odejść, póki Baal Orun wszystkiego pilnuje. Tak, czy inaczej - robota musi zostać wykonana!","en":"Can''t leave here while Baal Orun is in charge - the work has to be done either way!","de":"Ich kann hier nicht weg, solange Baal Orun die Aufsicht hat - die Arbeit muss getan werden, so oder so!"}},{"speaker":"npc","text":{"pl":"Ale ty mógłbyś tam pójść zamiast mnie. Jego chata jest zaraz pod laboratorium Cor Kaloma, koło Fortuno.","en":"But you could go there for me - he''s staying right under Cor Kalom''s alchemy lab, at Fortuno''s.","de":"Aber du könntest für mich zu ihm gehen - er wohnt unter dem Alchemielabor von Cor Kalom, direkt bei Fortuno."}},{"speaker":"npc","text":{"pl":"Powiedz mu, żeby ruszył tu swój leniwy tyłek.","en":"Tell him to get his butt over here.","de":"Sag ihm, er soll seinen Hintern hier rüberschwingen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1310_ghorim_dia_ghorim_success_15_00_0', 'NOV_1310_Ghorim', '{"id":"missions_dia_nov_1310_ghorim_dia_ghorim_success_15_00_0","npcId":"NOV_1310_Ghorim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1310_Ghorim.d","sourceFunction":"DIA_Ghorim_SUCCESS_Info","outputIds":["DIA_Ghorim_SUCCESS_15_00","DIA_Ghorim_SUCCESS_02_01"],"lines":[{"speaker":"hero","text":{"pl":"No i? Wreszcie ktoś cię zluzował?","en":"Well? Has he taken over now?","de":"Na? Endlich abgelöst worden?"}},{"speaker":"npc","text":{"pl":"Tak, nareszcie mogę się porządnie wyspać. Dzięki, stary!","en":"Yeah - finally I can get to sleep. Thanks, man!","de":"Ja - jetzt kann ich endlich mal wieder richtig ausschlafen. Danke, Mann!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1312_darrion_dia_darrion_hello_15_00_0', 'NOV_1312_Darrion', '{"id":"missions_dia_nov_1312_darrion_dia_darrion_hello_15_00_0","npcId":"NOV_1312_Darrion","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1312_Darrion.d","sourceFunction":"DIA_Darrion_Hello_Info","outputIds":["DIA_Darrion_Hello_15_00","DIA_Darrion_Hello_11_01","DIA_Darrion_Hello_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Jestem tu nowy i chciałbym poznać lepiej wasz Obóz.","en":"Hi - I''m new here and I''d like to get to know the Camp.","de":"Hi - ich bin neu hier und will das Lager kennen lernen."}},{"speaker":"npc","text":{"pl":"Zatem trafiłeś nie tam gdzie trzeba. Odkąd Strażnicy Świątynni rozpoczęli przygotowania do walki, pracujemy dniem i nocą.","en":"Then you''ve come to the wrong place. Since the templars started preparing for the fight, we''ve been busy day and night.","de":"Da bist du zum falschen Ort gekommen. Seit sich die Templer zum Kampf rüsten, sind wir Tag und Nacht beschäftigt."}},{"speaker":"npc","text":{"pl":"Nie mam wiele czasu na pogawędki, więc nie zawracaj mi głowy jeśli nie chcesz niczego kupić.","en":"I don''t have much time for questions. So don''t disturb me - unless you want to buy something.","de":"Ich hab'' nicht viel Zeit für neugierige Fragen. Also stör mich nicht - es sei denn, du willst was kaufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_at_psi_10_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_at_psi_10_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_AtPSI_Info","outputIds":["DIA_BaalParvez_AtPSI_10_00","DIA_BaalParvez_AtPSI_LATE_10_00","DIA_BaalParvez_AtPSI_10_01","DIA_BaalParvez_AtPSI_10_02"],"lines":[{"speaker":"npc","text":{"pl":"Jesteśmy na miejscu. Tam leży obóz Bractwa Śniącego.","en":"Here we are. Down there lies the camp of the Brotherhood.","de":"Wir sind angekommen. Dort unten liegt das Lager der Bruderschaft."}},{"speaker":"npc","text":{"pl":"Nie spieszyłeś się zbytnio, bracie! Przed nami obóz wyznawców Śniącego!","en":"You''ve taken your time, brother! Down there you see the Camp.","de":"Du hast dir viel Zeit gelassen, Bruder! Da unten siehst du das Lager."}},{"speaker":"npc","text":{"pl":"Przejdź przez bramę i porozmawiaj z moimi braćmi. Gwarantuję ci, że nie przyszedłeś tu na próżno.","en":"Go through the gate and speak to my brothers. I''m sure you haven''t come here for nothing.","de":"Geh durch das Tor und rede mit meinen Brüdern. Ich bin sicher, dass du den Weg nicht umsonst gemacht hast."}},{"speaker":"npc","text":{"pl":"Zapytaj o Cor Kaloma. To on opiekuje się Nowicjuszami.","en":"Ask for Cor Kalom. He''s in charge of the novices and tutors.","de":"Frag nach Cor Kalom. Er hat die Aufsicht über die Novizen und die Lehrer."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_at_psi_10_03_4', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_at_psi_10_03_4","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_AtPSI_Info","outputIds":["DIA_BaalParvez_AtPSI_10_03","DIA_BaalParvez_AtPSI_15_04"],"lines":[{"speaker":"npc","text":{"pl":"Ja wrócę teraz do Starego Obozu. Wielu niewiernych potrzebuje wciąż pomocy w odnalezieniu właściwej ścieżki.","en":"I''ll go back to the Old Camp - there are still many infidels who need to be guided to the right path.","de":"Ich gehe zurück ins alte Lager - es gibt noch viele Unwissende, die auf den richtigen Weg gebracht werden müssen."}},{"speaker":"hero","text":{"pl":"Powodzenia!","en":"Good luck.","de":"Viel Glück."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_goto_psi_15_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_goto_psi_15_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_GotoPSI_Info","outputIds":["DIA_BaalParvez_GotoPSI_15_00","DIA_BaalParvez_GotoPSI_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Zaprowadź mnie do waszego obozu. Chciałbym się tam rozejrzeć.","en":"Take me to your camp. I want to have a look at it!","de":"Bring mich zu eurem Lager. Das will ich mir ansehen!"}},{"speaker":"npc","text":{"pl":"To wspaniale. Chodź za mną!","en":"Very good! I''ll go ahead. Follow me!","de":"Sehr gut! Ich werde vorangehen. Folge mir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_greet_10_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_greet_10_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_Greet_Info","outputIds":["DIA_BaalParvez_Greet_10_00","DIA_BaalParvez_Greet_10_01"],"lines":[{"speaker":"npc","text":{"pl":"Niech Śniący będzie z tobą, nieznajomy.","en":"The Sleeper be with you, stranger!","de":"Der Schläfer sei mit dir, Fremder!"}},{"speaker":"npc","text":{"pl":"Jestem tu, by wskazać ci właściwą ścieżkę.","en":"I''m here to guide you onto the right path.","de":"Ich bin hier, um dich auf den rechten Weg zu führen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_my_advantage_10_04_4', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_my_advantage_10_04_4","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_MyAdvantage_Info","outputIds":["DIA_BaalParvez_MyAdvantage_10_04","DIA_BaalParvez_MyAdvantage_10_05"],"lines":[{"speaker":"npc","text":{"pl":"Jak widzisz, nasze Bractwo otwiera przed tobą wielkie możliwości!","en":"You see, our Brotherhood has a lot of possibilities for you.","de":"Du siehst, in unserer Bruderschaft gibt es viele Möglichkeiten für dich."}},{"speaker":"npc","text":{"pl":"Pamiętaj o tym zanim zdecydujesz się przyłączyć do któregoś z innych obozów!","en":"You should be aware of that before you decide on joining any other camp!","de":"Überzeuge dich selbst davon, bevor du dich vorschnell für ein anderes Lager entscheidest!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_my_advantage_15_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_my_advantage_15_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_MyAdvantage_Info","outputIds":["DIA_BaalParvez_MyAdvantage_15_00","DIA_BaalParvez_MyAdvantage_10_01","DIA_BaalParvez_MyAdvantage_10_02","DIA_BaalParvez_MyAdvantage_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Co mi przyjdzie z przyłączenia się do was?","en":"What would be the benefit of joining you?","de":"Was hätte ich davon, mich euch anzuschließen?"}},{"speaker":"npc","text":{"pl":"Może okażesz się jednym z wybrańców, którzy otrzymują od Śniącego dar magii.","en":"Maybe you''re one of the chosen people who receive the gift of magic from the Sleeper.","de":"Vielleicht bist du einer der Auserwählten, denen der Schläfer die Gabe der Magie verleiht."}},{"speaker":"npc","text":{"pl":"A może dostąpisz zaszczytu służby w Świątynnej Straży. Tylko najlepsi spośród wojowników mogą należeć do Strażników.","en":"Or you might obtain the highest honors and become a templar. Only the best fighters among us can obtain that position.","de":"Oder du erreichst die höchsten Ehren und wirst zum Templer berufen. Nur die besten Kämpfer unter uns dürfen diese Position bekleiden."}},{"speaker":"npc","text":{"pl":"Jeśli Śniące będzie ci szczególnie sprzyjał - może dane ci będzie połączyć jedno z drugim! Najlepsi Strażnicy otrzymują również dar magii!","en":"If the Sleeper is with you, you can even combine both - the best of the templars receive the gift of magic as well.","de":"Wenn der Schläfer mit dir ist, kannst du sogar beides kombinieren - die besten unter den Templern haben nämlich auch die Gabe der Magie."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_psimagic_15_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_psimagic_15_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_PSIMagic_Info","outputIds":["DIA_BaalParvez_PSIMagic_15_00","DIA_BaalParvez_PSIMagic_10_01","DIA_BaalParvez_PSIMagic_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi jeszcze o magii Śniącego.","en":"Tell me about the magic of the Sleeper.","de":"Erzähl mir von der Magie des Schläfers."}},{"speaker":"npc","text":{"pl":"Magia Śniącego pozwala ci kontrolować rzeczy siłą twojej woli.","en":"This gift enables you to control things with the power of your mind.","de":"Diese Gabe verleiht die Fähigkeit, Dinge mit der Kraft deines Willens zu kontrollieren."}},{"speaker":"npc","text":{"pl":"Jednak tylko wtajemniczeni Guru poznali tajniki tej magii.","en":"Only the Gurus of our Brotherhood have been initiated into the secrets of this magic.","de":"Nur die Gurus unserer Bruderschaft sind in die Geheimnisse dieser Magie eingeweiht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_right_way_10_04_4', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_right_way_10_04_4","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_RightWay_Info","outputIds":["DIA_BaalParvez_RightWay_10_04","DIA_BaalParvez_RightWay_10_05"],"lines":[{"speaker":"npc","text":{"pl":"Jednak aby to osiągnąć, potrzebujemy jak największej rzeszy wyznawców. Jednocząc nasze siły duchowe uda nam się nawiązać z nim kontakt.","en":"We''ll need as many supporters as possible for that. By focusing our spiritual power, we''ll get through to him.","de":"Wir brauchen dazu so viele Anhänger wie möglich. Durch unsere gebündelte geistige Kraft werden wir zu ihm durchdringen."}},{"speaker":"npc","text":{"pl":"Nasz obóz znajduje się dość daleko stąd - na wielkim bagnie. Mogę cię tam zaprowadzić, jeśli chcesz.","en":"Our camp is some distance away, in the swamp - I can take you there though, if you want.","de":"Unser Lager liegt etwas weiter entfernt in den Sümpfen - Ich kann dich aber hinbringen, falls du es wünschst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_right_way_15_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_right_way_15_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_RightWay_Info","outputIds":["DIA_BaalParvez_RightWay_15_00","DIA_BaalParvez_RightWay_10_01","DIA_BaalParvez_RightWay_10_02","DIA_BaalParvez_RightWay_10_03"],"lines":[{"speaker":"hero","text":{"pl":"A która ścieżka jest właściwa?","en":"And which is the right path?","de":"Und was ist der rechte Weg?"}},{"speaker":"npc","text":{"pl":"Ścieżka Śniącego, oczywiście. Tylko on może nas stąd uwolnić.","en":"The path of the Sleeper. He alone has the power to set us free.","de":"Der Weg des Schläfers. Er allein hat die Macht, uns von hier zu befreien."}},{"speaker":"npc","text":{"pl":"Guru przygotowują w naszym obozie rytuał wielkiego przyzwania. Zamierzają nawiązać kontakt ze Śniącym.","en":"The Gurus are preparing a great invocation in our camp - they want to get in contact with the Sleeper.","de":"Im unserem Lager bereiten die Gurus eine große Beschwörung vor - sie wollen mit dem Schläfer in Kontakt treten."}},{"speaker":"npc","text":{"pl":"Do tej pory przemawiał do nas wyłącznie za pośrednictwem wizji, ale już wkrótce stanie przed nami w pełni swej chwały.","en":"So far he''s just talked to us in visions - but now it''s time to get in touch with him.","de":"Bisher hat er nur durch Visionen zu uns gesprochen - aber jetzt ist die Zeit gekommen, mit ihm Kontakt aufzunehmen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_15_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_15_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_Sleeper_Info","outputIds":["DIA_BaalParvez_Sleeper_15_00","DIA_BaalParvez_Sleeper_10_01","DIA_BaalParvez_Sleeper_10_02","DIA_BaalParvez_Sleeper_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Kim jest Śniący?","en":"Who''s the Sleeper?","de":"Wer ist der Schläfer?"}},{"speaker":"npc","text":{"pl":"Śniący przemawia do nas poprzez sny i wizje.","en":"The Sleeper speaks to us through dreams and visions.","de":"Der Schläfer spricht zu uns durch unsere Träume und Visionen."}},{"speaker":"npc","text":{"pl":"Przewodzi nam odkąd nawiązał pierwszy kontakt z Y''Berionem, pięć lat temu.","en":"He has been leading us ever since he first made contact with Y''Berion five years ago.","de":"Seit er vor fünf Jahren das erste Mal mit Y''Berion in Kontakt trat, hat er uns geleitet."}},{"speaker":"npc","text":{"pl":"Wszyscy wyznawcy Bractwa wyrzekli się trzech bogów. Teraz modlimy się o zbawienie tylko do Śniącego.","en":"All the followers of the Brotherhood have renounced the three gods. We pray only to the Sleeper for salvation.","de":"Alle Anhänger der Bruderschaft haben dem Glauben an die drei Götter abgeschworen. Wir bitten nur noch den Schläfer um Erlösung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_15_04_4', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_15_04_4","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_Sleeper_Info","outputIds":["DIA_BaalParvez_Sleeper_15_04","DIA_BaalParvez_Sleeper_10_05"],"lines":[{"speaker":"hero","text":{"pl":"Zbawienie od czego?","en":"Salvation from what?","de":"Erlösung wovon?"}},{"speaker":"npc","text":{"pl":"Od tego przeklętego miejsca, naturalnie! Śniący wskaże nam drogę do wolności!","en":"From this goddamn place, of course! The Sleeper will show us the way to freedom!","de":"Na, von diesem gottverdammten Ort hier! Der Schläfer wird uns den Weg in die Freiheit weisen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_said_10_04_4', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_said_10_04_4","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_SleeperSaid_Info","outputIds":["DIA_BaalParvez_SleeperSaid_10_04"],"lines":[{"speaker":"npc","text":{"pl":"Wreszcie obdarzył niektórych z nas darem magii. Magii starożytnej i potężnej. Różnej od tej, którą wykorzystywali dotąd magowie tego królestwa.","en":"And he gave some of us the gift of magic. Of an old and powerful magic which is different from the one the magicians of the realm use.","de":"Und er gab einigen von uns die Gabe der Magie. Einer alten, mächtigen Magie, verschieden von der, die die Magier des Reiches anwenden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_said_15_00_0', 'NOV_1330_BaalParvez', '{"id":"missions_dia_nov_1330_baal_parvez_dia_baal_parvez_sleeper_said_15_00_0","npcId":"NOV_1330_BaalParvez","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1330_BaalParvez.d","sourceFunction":"DIA_BaalParvez_SleeperSaid_Info","outputIds":["DIA_BaalParvez_SleeperSaid_15_00","DIA_BaalParvez_SleeperSaid_10_01","DIA_BaalParvez_SleeperSaid_10_02","DIA_BaalParvez_SleeperSaid_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Co powiedział wam Śniący?","en":"What did the Sleeper tell you?","de":"Was hat euch der Schläfer gesagt?"}},{"speaker":"npc","text":{"pl":"Zaprowadził nas na bagna, na ruiny starej świątyni. Tam zbudowaliśmy nasz obóz.","en":"He guided us to the swamp, to the old temple ruins. That''s where we built our camp.","de":"Er hat uns in den Sumpf geführt, zu den alten Tempelruinen. Dort haben wir unser Lager errichtet."}},{"speaker":"npc","text":{"pl":"Dał nam niezależność - żaden z nas nie musi pracować pod ziemią.","en":"He gave us independence - none of us need to labor in the mines.","de":"Er hat uns die Unabhängigkeit gegeben - keiner von uns muss mehr in den Minen schuften."}},{"speaker":"npc","text":{"pl":"Pokazał nam jaka moc drzemie w bagiennym zielu. Teraz sprzedajemy je innym obozom, otrzymując w zamian wszystko, czego nam potrzeba.","en":"He showed us what swampweed can do. We sell it to the other camps, and in exchange we get everything we need.","de":"Er hat uns die Wirkung des Sumpfkrauts gezeigt. Wir verkaufen es an die anderen Lager und bekommen dafür alles, was wir brauchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_beweis_15_00_0', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_beweis_15_00_0","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_Beweis_Info","outputIds":["DIA_BaalTaran_Beweis_15_00","DIA_BaalTaran_Beweis_05_01","DIA_BaalTaran_Beweis_05_02","DIA_BaalTaran_Beweis_15_03"],"lines":[{"speaker":"hero","text":{"pl":"W jaki sposób wasz bóg udowodnił swoją potęgę?","en":"How does your god prove his might?","de":"Wie beweist euch euer Gott seine Macht?"}},{"speaker":"npc","text":{"pl":"Przemawiając do nas za pośrednictwem wizji. Kto raz usłyszy jego głos, już nigdy nie zbłądzi na ścieżkę zła.","en":"He speaks to us through visions. Whoever hears his voice, no longer doubts his might.","de":"Er spricht zu uns durch Visionen. Wer seine Stimme gehört hat, zweifelt nicht mehr an seiner Macht."}},{"speaker":"npc","text":{"pl":"Zażyj rosnące na bagnach ziele, a zbliżysz się do Śniącego i będziesz mógł usłyszeć jego słowa. Niektórym wybrańcom zdarzyło się go nawet zobaczyć!","en":"If you take the weed which grows in the swamp, you will be close to the Sleeper and able to hear him. Some people even see images.","de":"Wenn man das Kraut, das im Sumpf wächst, einnimmt, ist man dem Schläfer nahe und kann ihn hören. Manche sehen auch Bilder."}},{"speaker":"hero","text":{"pl":"Rozumiem.","en":"I see.","de":"Verstehe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_bruderschaft_15_00_0', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_bruderschaft_15_00_0","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_Bruderschaft_Info","outputIds":["DIA_BaalTaran_Bruderschaft_15_00","DIA_BaalTaran_Bruderschaft_05_01","DIA_BaalTaran_Bruderschaft_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Bractwo Śniącego? A cóż to takiego?","en":"What is the Brotherhood of the Sleeper?","de":"Was ist die Bruderschaft des Schläfers?"}},{"speaker":"npc","text":{"pl":"Jesteśmy wspólnotą wyznawców nowej wiary.","en":"We''re a community of believers in a new faith.","de":"Wir sind eine Gemeinschaft von Anhängern eines neuen Glaubens."}},{"speaker":"npc","text":{"pl":"Nasz obóz znajduje się na wschód stąd, na bagnie. Przyszedłem tutaj, by nauczać niewiernych takich jak ty słów Śniącego.","en":"Our camp is situated in the east, in the swamp. I''ve come to preach the words of the Sleeper to strangers like you.","de":"Unser Lager liegt östlich von hier, im Sumpfgebiet. Ich bin hergekommen, um Fremden wie dir die Lehre des Schläfers zu verkünden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_freiheit_15_00_0', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_freiheit_15_00_0","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_Freiheit_Info","outputIds":["DIA_BaalTaran_Freiheit_15_00","DIA_BaalTaran_Freiheit_05_01","DIA_BaalTaran_Freiheit_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak będzie wyglądać ta droga do wolności?","en":"What will the way to freedom look like?","de":"Wie soll der Weg in die Freiheit aussehen?"}},{"speaker":"npc","text":{"pl":"Przygotowujemy się do wielkiego przyzwania, w którym wszyscy Nowicjusze zjednoczą swoje duchowe siły.","en":"We are preparing a great invocation of the Sleeper, in which all novices create the contact together.","de":"Wir bereiten eine große Anrufung des Schläfers vor, in der alle Novizen zusammen den Kontakt herstellen."}},{"speaker":"npc","text":{"pl":"W trakcie rytuału Śniący ujawni nam świętą drogę do wolności.","en":"In this invocation, the Sleeper will reveal the path to freedom.","de":"In dieser Anrufung wird uns der Schläfer den Weg in die Freiheit offenbaren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_into_castle_05_04_4', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_into_castle_05_04_4","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_IntoCastle_Info","outputIds":["DIA_BaalTaran_IntoCastle_05_04"],"lines":[{"speaker":"npc","text":{"pl":"A czego, jeśli wolno spytać, chcesz szukać w zamku?","en":"What do you want to do in the castle anyway?","de":"Was willst du überhaupt in der Burg?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_into_castle_15_00_0', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_into_castle_15_00_0","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_IntoCastle_Info","outputIds":["DIA_BaalTaran_IntoCastle_15_00","DIA_BaalTaran_IntoCastle_05_01","DIA_BaalTaran_IntoCastle_05_02","DIA_BaalTaran_IntoCastle_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Muszę się dostać do zamku. Mógłbyś mi pomóc?","en":"I need to get into the castle. Can you help me?","de":"Ich muss in die Burg. Kannst du mir dabei helfen?"}},{"speaker":"npc","text":{"pl":"Obawiam się, że nie. Tylko Bracia dostarczający Gomezowi ziele mają wstęp do zamku.","en":"I fear I cannot, brother. The only ones among us who may enter the castle are those who supply the weed to Gomez.","de":"Ich fürchte nicht, Bruder. Die einzigen von uns, die die Burg betreten dürfen, sind diejenigen, die Gomez das Kraut liefern."}},{"speaker":"npc","text":{"pl":"Zbieramy bagienne ziele, i część zbiorów sprzedajemy do Starego Obozu w zamian za różne dobra z zewnętrznego świata.","en":"We gather swampweed and sell part of it to the Old Camp, in exchange for goods from the outside world.","de":"Wir ernten Sumpfkraut und verkaufen einen Teil davon ans Alte Lager, zum Austausch gegen Waren aus der Außenwelt."}},{"speaker":"npc","text":{"pl":"Gdybyś był jednym z kurierów pracujących dla Cor Kaloma, mógłbyś dostać się do zamku. Oczywiście musiałbyś najpierw przystąpić do Bractwa.","en":"If you were one of the couriers working for Cor Kalom, you could get into the castle. But for that you would need to be one of us.","de":"Wenn du einer der Kuriere wärst, die für Cor Kalom arbeiten, könntest du in die Burg kommen. Aber dazu müsstest du natürlich einer von uns sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_lehre_05_04_4', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_lehre_05_04_4","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_Lehre_Info","outputIds":["DIA_BaalTaran_Lehre_05_04","DIA_BaalTaran_Lehre_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Zatem słuchaj: każdy, kto stanie po jego stronie zostanie zbawiony, ale ci, którzy się mu sprzeciwią, poniosą surową karę.","en":"So listen, all those who join the Sleeper will have immortal souls, but those who are against him will be punished.","de":"Denn höre, diejenigen, die sich dem Schläfer anschließen, deren Seelen werden unsterblich, aber die, die ihm entsagen oder sich gar gegen ihn stellen, werden vernichtet werden."}},{"speaker":"npc","text":{"pl":"Ale Śniący jest miłosierny i wszystkim wątpiącym przysyła znak swojej potęgi.","en":"But the Sleeper is compassionate and sends proof of his might to all who doubt him.","de":"Aber der Schläfer ist barmherzig und gibt allen Zweiflern einen Beweis seiner Macht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_lehre_15_00_0', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_lehre_15_00_0","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_Lehre_Info","outputIds":["DIA_BaalTaran_Lehre_15_00","DIA_BaalTaran_Lehre_05_01","DIA_BaalTaran_Lehre_05_02","DIA_BaalTaran_Lehre_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi o naukach Śniącego.","en":"Tell me about the Sleeper''s teachings.","de":"Erzähl mir von der Lehre des Schläfers."}},{"speaker":"npc","text":{"pl":"Śniący jest niezwykle potężny, może nawet potężniejszy od Innosa, boga światła.","en":"The Sleeper is a powerful being, maybe even more powerful than Innos, the god of light.","de":"Der Schläfer ist ein mächtiges Wesen, vielleicht sogar mächtiger als Innos, der Gott des Lichts."}},{"speaker":"npc","text":{"pl":"Zjednoczył się z nami duchowo, ale jego moc jest wciąż ograniczona. Był uśpiony przez tysiące lat, ale moment jego wielkiego przebudzenia jest już bardzo bliski!","en":"He is with us in spirit. But his power is still limited. He has been sleeping for a thousand years, but now the moment of his awakening is near.","de":"Im Geiste ist er mit uns. Aber seine Macht ist noch begrenzt. Er schläft einen tausendjährigen Schlaf, aber die Zeit seines Erwachens ist nahe."}},{"speaker":"npc","text":{"pl":"Wybrał nas na świadków swojego nadejścia i kazał nam szerzyć jego słowa w całej kolonii.","en":"He has chosen us to be witnesses to his awakening and to spread his word.","de":"Uns hat er auserwählt, sein Erwachen zu bezeugen und seine Lehre zu verbreiten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_sleeper_15_00_0', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_sleeper_15_00_0","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_Sleeper_Info","outputIds":["DIA_BaalTaran_Sleeper_15_00","DIA_BaalTaran_Sleeper_05_01","DIA_BaalTaran_Sleeper_05_02","DIA_BaalTaran_Sleeper_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Kim jest Śniący?","en":"Who is the Sleeper?","de":"Wer ist der Schläfer?"}},{"speaker":"npc","text":{"pl":"Śniący będzie naszym wyzwolicielem. Pięć lat temu ujawnił się nam przez Y''Beriona, naszego wielkiego mistrza.","en":"The Sleeper is our redeemer. He disclosed himself five years ago through Y''Berion, our master.","de":"Der Schläfer ist unser Erlöser. Er hat sich uns vor 5 Jahren durch Y''Berion, unseren Meister, offenbart."}},{"speaker":"npc","text":{"pl":"Od tej chwili, wyrzekliśmy się trzech bogów, co i tobie radzę.","en":"Since then, we have all renounced the three gods. And you should do so as well.","de":"Seitdem haben wir den drei Göttern abgeschworen. Und das solltest du auch tun."}},{"speaker":"npc","text":{"pl":"Bogowie przyglądali się bezczynnie, gdy byliśmy skazywani na dożywotnią katorgę w tym więzieniu. Ale Śniący wskaże nam drogę do wolności.","en":"The gods just stood by and watched while we were exiled to this prison. But the Sleeper will lead us to freedom.","de":"Die Götter haben es zugelassen, dass wir in dieses Gefängnis verbannt wurden. Der Schläfer aber wird uns wieder in die Freiheit führen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1331_baa_taran_dia_baal_taran_way_to_st_15_00_0', 'NOV_1331_BaalTaran', '{"id":"missions_dia_nov_1331_baa_taran_dia_baal_taran_way_to_st_15_00_0","npcId":"NOV_1331_BaalTaran","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1331_BaaTaran.d","sourceFunction":"DIA_BaalTaran_WayToST_Info","outputIds":["DIA_BaalTaran_WayToST_15_00","DIA_BaalTaran_WayToST_05_01","DIA_BaalTaran_WayToST_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę dotrzeć do obozu Bractwa?","en":"How do I get to the Brotherhood''s camp?","de":"Wie komme ich zum Lager der Bruderschaft?"}},{"speaker":"npc","text":{"pl":"Jestem teraz zajęty, ale Baal Parvez powinien przebywać jeszcze w tym obozie.","en":"I''m busy. But Baal Parvez should be somewhere in this camp as well.","de":"Ich bin gerade beschäftigt. Aber Baal Parvez müsste sich auch hier im Lager befinden."}},{"speaker":"npc","text":{"pl":"Znajdziesz go gdzieś w pobliżu targowiska, po drugiej stronie zamku. Zdaję się, że ma tam nawet własną chatę!","en":"He''s near the market place, on the other side of the castle. I believe he''s even got his own hut there.","de":"Er ist in der Nähe des Marktplatzes, auf der andern Seite der Burg. Ich glaube, er hat dort sogar ''ne eigene Hütte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_gimme_kraut_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_gimme_kraut_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_GimmeKraut_Info","outputIds":["DIA_BaalKagan_GimmeKraut_15_00","DIA_BaalKagan_GimmeKraut_13_01","DIA_BaalKagan_GimmeKraut_13_02","DIA_BaalKagan_GimmeKraut_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Dobrze, daj mi to ziele. Komu mam je rozdawać?","en":"Okay, give me the weed. Who do you want me to give it to?","de":"Okay, gib her das Kraut. An wen soll ich es verteilen?"}},{"speaker":"npc","text":{"pl":"Na pewno znajdzie się wielu chętnych. Porozmawiaj z ludźmi. Tylko każdemu z nich dawaj JEDNĄ porcję.","en":"You''re sure to find someone who''ll take it. Talk to people. But only give ONE stalk to each person.","de":"Du findest sicher leicht Abnehmer. Rede mit den Leuten. Aber gib jedem nur EINEN Stengel."}},{"speaker":"npc","text":{"pl":"I jeszcze coś: jeśli pozwolisz, by ktoś odebrał ci ziele, albo sam je wypalisz, naszą umowę uznam za nieważną.","en":"One more thing: If you let somebody take the weed from you or if you smoke it yourself, our deal ceases to exist.","de":"Noch was: Wenn du dir das Kraut abnehmen lässt oder es selber rauchst, gilt unsere Abmachung nicht mehr."}},{"speaker":"hero","text":{"pl":"Oczywiście.","en":"Sure.","de":"Sicher."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_order_help_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_order_help_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_OrderHelp_Info","outputIds":["DIA_BaalKagan_OrderHelp_15_00","DIA_BaalKagan_OrderHelp_13_01","DIA_BaalKagan_OrderHelp_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego nie przyślą ci tu kogoś do pomocy?","en":"Why don''t they send an extra man here?","de":"Warum schicken sie nicht einen weiteren Mann?"}},{"speaker":"npc","text":{"pl":"Miał mi pomagać Baal Isidro, ale on woli spędzać całe dnie w karczmie na jeziorze i wymieniać swoje ziele na ryżówkę.","en":"Baal Isidro was meant to help me, but he just spends all day in the bar on the lake and trades his weed for rice schnapps.","de":"Baal Isidro sollte mich unterstützen, aber er sitzt den ganzen Tag in der Kneipe auf dem See und tauscht sein Kraut gegen Reisschnaps ein."}},{"speaker":"npc","text":{"pl":"Obawiam się, że uzależnił się od alkoholu. Nie mogę raczej liczyć na jego pomoc.","en":"He''s addicted to the spirit. I fear I cannot expect any help from him.","de":"Er ist dem Schnaps verfallen. Ich fürchte, von ihm ist keine Hilfe zu erwarten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_SUCCESS_Info","outputIds":["DIA_BaalKagan_SUCCESS_15_00","DIA_BaalKagan_SUCCESS_13_01","DIA_BaalKagan_SUCCESS_13_02","DIA_BaalKagan_NO_SUCCESS_13_00"],"lines":[{"speaker":"hero","text":{"pl":"Rozdałem już całe ziele.","en":"I''ve shared out the weed.","de":"Ich habe das Kraut verteilt."}},{"speaker":"npc","text":{"pl":"Pierwsi klienci zaczęli się już do mnie zgłaszać. Wykonałeś kawał dobrej roboty.","en":"The first new customers have already been to see me. You''ve done a good job.","de":"Die ersten neuen Kunden waren schon bei mir. Du hast gute Arbeit geleistet."}},{"speaker":"npc","text":{"pl":"Co chcesz dostać jako wynagrodzenie?","en":"What will you have as a reward?","de":"Wie soll deine Belohnung aussehen."}},{"speaker":"npc","text":{"pl":"Nie przyszli do mnie jeszcze żadni nowi klienci. Musisz rozdzielić jeszcze trochę ziela.","en":"I haven''t seen any new customers yet. Share out some more.","de":"Ich habe noch keinen neuen Kunden hier gesehen. Verteil mehr."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_erz_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_erz_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_SUCCESS_Erz","outputIds":["DIA_BaalKagan_SUCCESS_Erz_15_00","DIA_BaalKagan_SUCCESS_Erz_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Wezmę 100 bryłek rudy.","en":"I''ll take the 100 ore.","de":"Ich nehme die 100 Erz."}},{"speaker":"npc","text":{"pl":"Proszę bardzo.","en":"Very well. Here.","de":"Wie du willst. Hier."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_join_13_04_4', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_join_13_04_4","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_SUCCESS_Join","outputIds":["DIA_BaalKagan_SUCCESS_Join_13_04"],"lines":[{"speaker":"npc","text":{"pl":"Daj mu to, jeśli chcesz mu rozwiązać język.","en":"If you give him this here, it''ll loosen his tongue.","de":"Wenn du ihm das hier gibst, wird sich seine Zunge lösen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_join_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_join_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_SUCCESS_Join","outputIds":["DIA_BaalKagan_SUCCESS_Join_15_00","DIA_BaalKagan_SUCCESS_Join_13_01","DIA_BaalKagan_SUCCESS_Join_13_02","DIA_BaalKagan_SUCCESS_Join_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Pomóż mi dostać się do Bractwa.","en":"Help me to join the Brotherhood.","de":"Hilf mir, in der Bruderschaft aufgenommen zu werden."}},{"speaker":"npc","text":{"pl":"Twoja prośba jest bardzo skromna. Pomogę ci, tylko słuchaj uważnie. Baal Tyon jest jednym z młodszych Guru, tak jak ja.","en":"Your request is modest. I''ll help you, so listen to me. Baal Tyon is one of the lower Gurus - just like myself.","de":"Deine Bitte ist bescheiden. Ich werde dir helfen, hör gut zu. Baal Tyon ist einer der niederen Gurus - so wie ich."}},{"speaker":"npc","text":{"pl":"Y''Berion uczynił z niego swojego osobistego doradcę. Obawiam się, że to nie była najlepsza decyzja.","en":"Y''Berion has made him one of his advisors. That has not done him any good.","de":"Y''Berion hat ihn zu einem seiner Berater gemacht. Das ist ihm nicht bekommen."}},{"speaker":"npc","text":{"pl":"Tyon stał się przez to tak zarozumiały, że nie chce już pomagać nikomu oprócz swoich uczniów.","en":"He now thinks he''s so important that he''ll talk to nobody but his disciples.","de":"Er hält sich jetzt für so wichtig, dass er mit niemanden außer seinen Schülern mehr redet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_take_scrolls_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_take_scrolls_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_SUCCESS_TakeScrolls","outputIds":["DIA_BaalKagan_SUCCESS_TakeScrolls_15_00","DIA_BaalKagan_SUCCESS_TakeScrolls_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Wezmę te zwoje z zaklęciami.","en":"I''ll take the spell scrolls.","de":"Ich nehme die Spruchrollen."}},{"speaker":"npc","text":{"pl":"Mądra decyzja. Wybierz trzy.","en":"A good decision. Pick three.","de":"Eine gute Entscheidung. Wähle drei aus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_take_scrolls_drei_13_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_take_scrolls_drei_13_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_SUCCESS_TakeScrolls_Charme","outputIds":["DIA_BaalKagan_SUCCESS_TakeScrolls_DREI_13_00"],"lines":[{"speaker":"npc","text":{"pl":"To już trzy. Wykorzystaj je rozsądnie.","en":"That was three. Use them wisely.","de":"Das waren drei. Verwende sie weise."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_what_spells_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_success_what_spells_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_SUCCESS_WhatSpells","outputIds":["DIA_BaalKagan_SUCCESS_WhatSpells_15_00","DIA_BaalKagan_SUCCESS_WhatSpells_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Te zwoje magiczne wydają się całkiem interesujące - jakie zaklęcia zawierają?","en":"These spell scrolls are quite interesting - what kind of spells are they?","de":"Die Spruchrollen interessieren mich - was sind das für Sprüche?"}},{"speaker":"npc","text":{"pl":"Uderzenie wiatru, Urok, Telekinezę, Pirokinezę i Sen. Możesz sobie wybrać trzy z nich.","en":"Fist of Wind, Charm, Telekinesis, Pyrokinesis and Sleep. You may pick three of these spells.","de":"Windfaust, Charme, Telekinese, Pyrokinese und Schlaf. Von diesen Sprüchen darfst du drei wählen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_wanna_help_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_wanna_help_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_WannaHelp_Info","outputIds":["DIA_BaalKagan_WannaHelp_15_00","DIA_BaalKagan_WannaHelp_13_01","DIA_BaalKagan_WannaHelp_13_02","DIA_BaalKagan_WannaHelp_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Mógłbym ci pomóc w sprzedaży ziela...","en":"I could help you sell your weed to the people.","de":"Ich könnte dir helfen, dein Kraut unter die Leute zu bringen."}},{"speaker":"npc","text":{"pl":"Tak duże ładunki ziela mogę powierzyć tylko innym członkom Bractwa.","en":"I can only entrust such a large amount of weed to members of the Brotherhood.","de":"Eine so große Menge Kraut kann ich dir nur anvertrauen, wenn du ein Mitglied der Bruderschaft bist."}},{"speaker":"npc","text":{"pl":"Ale mógłbyś pomóc mi w rozdzielaniu prezentów.","en":"But you could help me give out gifts.","de":"Aber du könntest mir helfen, Geschenke zu verteilen."}},{"speaker":"npc","text":{"pl":"Jeszcze całkiem spora grupa ludzi nie miała okazji skosztować mojego towaru. Gdyby spróbowali, chcieliby kupować więcej, czyli zyski ze sprzedaży mogłyby wzrosnąć.","en":"Not everybody has tasted my goods yet. As soon as they''ve tried the weed, they''ll want more, which means I can sell more.","de":"Es sind noch nicht alle hier auf den Geschmack gekommen. Wenn sie erst einmal unser Kraut gekostet haben, werden sie mehr verlangen und ich kann mehr verkaufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_wanna_help_15_04_4', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_wanna_help_15_04_4","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_WannaHelp_Info","outputIds":["DIA_BaalKagan_WannaHelp_15_04","DIA_BaalKagan_WannaHelp_13_05"],"lines":[{"speaker":"hero","text":{"pl":"Myślałem, że i bez tego ledwie sobie radzisz w pracy!","en":"I thought you could hardly manage to do your task NOW.","de":"Ich denke, du schaffst es JETZT schon kaum, deine Aufgabe zu erfüllen."}},{"speaker":"npc","text":{"pl":"Zająłem się już problemem Baala Isidro. Wysłałem wiadomość do Cor Kaloma.","en":"Baal Isidro will be taken care of soon. I''ve already sent a message to Cor Kalom.","de":"Für Baal Isidro wird bald gesorgt. Ich habe schon eine Nachricht an Cor Kalom geschickt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_was_drin_13_04_4', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_was_drin_13_04_4","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_WasDrin_Info","outputIds":["DIA_BaalKagan_WasDrin_13_04","DIA_BaalKagan_WasDrin_13_05"],"lines":[{"speaker":"npc","text":{"pl":"To bliscy przyjaciele samego Y''Beriona, naszego wielkiego mistrza.","en":"Both are very close to Y''Berion, our master.","de":"Beide stehen Y''Berion, unserem Meister, sehr nahe."}},{"speaker":"npc","text":{"pl":"Wreszcie mogę ci zapłacić rudą, jeśli tak wolisz. 100 bryłek powinno wystarczyć, czyż nie?","en":"I can pay you with plain ore as well if you prefer. 100 nuggets should be enough for your efforts.","de":"Ich kann dich aber auch mit schnödem Erz bezahlen, wenn das dein Wunsch ist. 100 Brocken sollten für deine Mühe genügen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_was_drin_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_was_drin_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_WasDrin_Info","outputIds":["DIA_BaalKagan_WasDrin_15_00","DIA_BaalKagan_WasDrin_13_01","DIA_BaalKagan_WasDrin_13_02","DIA_BaalKagan_WasDrin_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Co będę z tego miał, jeśli zgodzę się rozdawać twoje \"prezenty\"?","en":"What''s in it for me if I hand out the weed for you?","de":"Wenn ich das Kraut für dich verteile - was ist für mich drin?"}},{"speaker":"npc","text":{"pl":"Mogę cię wynagrodzić na kilka różnych sposobów.","en":"I can reward you in many different ways.","de":"Ich kann dich auf viele Arten entlohnen."}},{"speaker":"npc","text":{"pl":"Mogę ci podarować zwoje z magicznymi zaklęciami Śniącego.","en":"You can get magic spell scrolls from me, bearing the powerful magic of the Sleeper.","de":"Du kannst von mir magische Spruchrollen erhalten, die mit mächtiger Magie des Schläfers belegt sind."}},{"speaker":"npc","text":{"pl":"Albo mogę pomóc ci zostać jednym z nas, jeśli zechcesz. Utrzymuję dobre kontakty z Cor Kalomem i Baal Tyonem.","en":"Or I can help you join our community, if that''s what you want. I have very good contacts to Cor Kalom and Baal Tyon.","de":"Ich kann dir aber auch helfen, leichter in unsere Gemeinschaft aufgenommen zu werden, wenn du das wünschst. Ich habe sehr gute Kontakte zu Cor Kalom und Baal Tyon."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1332_baal_kagan_dia_baal_kagan_why_here_15_00_0', 'NOV_1332_BaalKagan', '{"id":"missions_dia_nov_1332_baal_kagan_dia_baal_kagan_why_here_15_00_0","npcId":"NOV_1332_BaalKagan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1332_BaalKagan.d","sourceFunction":"DIA_BaalKagan_WhyHere_Info","outputIds":["DIA_BaalKagan_WhyHere_15_00","DIA_BaalKagan_WhyHere_13_01","DIA_BaalKagan_WhyHere_13_02","DIA_BaalKagan_WhyHere_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Początkowo przybyłem tutaj, by werbować nowych ludzi do naszego Bractwa.","en":"Originally, I was sent here to convince people to join our Brotherhood.","de":"Ursprünglich bin ich hierhin entsandt worden, um für unsere Gemeinschaft zu werben."}},{"speaker":"npc","text":{"pl":"Ale ci barbarzyńcy mają w nosie swoje duchowe zbawienie. Dlatego teraz zajmuję się wyłącznie sprzedażą ziela.","en":"But these barbarians are not interested in spiritual enlightenment. Therefore I''m restricted to selling swampweed.","de":"Aber diese Barbaren wollen nichts wissen von geistiger Erleuchtung. So beschränke ich mich auf den Verkauf von Sumpfkraut."}},{"speaker":"npc","text":{"pl":"Palenie ziela to dość popularne zajęcie w tych stronach. Może nawet zbyt popularne. Ledwie nadążam z kolejnymi dostawami.","en":"And that is a popular occupation here. Too popular. I can hardly deliver as much as they want to have.","de":"Dies wiederum wird hier sehr gerne gesehen. Zu gerne. Ich kann allein kaum alle meine Kunden beliefern."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_drink_15_00_0', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_drink_15_00_0","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_Drink_Info","outputIds":["DIA_BaalIsidro_Drink_15_00","DIA_BaalIsidro_Drink_03_01","DIA_BaalIsidro_NO_Drink_03_00"],"lines":[{"speaker":"hero","text":{"pl":"Proszę, łyknij sobie! Ja stawiam.","en":"Here you go - have another drink on me.","de":"Hier - trink noch einen auf meine Rechnung."}},{"speaker":"npc","text":{"pl":"Dzięki, kolego. Twoje zdrowie!","en":"Thanks, man. I''ll drink to your health!","de":"Danke, Mann. Ich trinke auf dein Wohl!"}},{"speaker":"npc","text":{"pl":"Co? Gdzie?","en":"What? Where?","de":"Was? Wo?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_gimme_kraut_15_00_0', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_gimme_kraut_15_00_0","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_GimmeKraut_Info","outputIds":["DIA_BaalIsidro_GimmeKraut_15_00","DIA_BaalIsidro_GimmeKraut_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Mógłbym pomóc ci sprzedać to ziele. Oczywiście za drobną prowizję.","en":"I could sell the weed for you - for a consideration, of course.","de":"Ich könnte das Kraut für dich verkaufen - gegen Beteiligung versteht sich."}},{"speaker":"npc","text":{"pl":"Zapomnij o tym. Nie jestem aż tak pijany. Dałbyś nogę z całym towarem.","en":"Forget it - I''m not as drunk as all that. You''d just go running away with it.","de":"Vergiss es - so besoffen bin ich nun auch wieder nicht. Du brennst doch einfach damit durch."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_hello_03_04_4', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_hello_03_04_4","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_Hello_Info","outputIds":["DIA_BaalIsidro_Hello_03_04"],"lines":[{"speaker":"npc","text":{"pl":"Tak, ale nie idzie mi najlepiej.","en":"Yes. But I just can''t be bothered.","de":"Ja. Aber ich kann mich einfach nicht aufraffen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_hello_15_00_0', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_hello_15_00_0","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_Hello_Info","outputIds":["DIA_BaalIsidro_Hello_15_00","DIA_BaalIsidro_Hello_03_01","DIA_BaalIsidro_Hello_03_02","DIA_BaalIsidro_Hello_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Nie wyglądasz mi na zbyt zadowolonego.","en":"You don''t look very happy.","de":"Du siehst nicht sehr glücklich aus."}},{"speaker":"npc","text":{"pl":"Bo nie jestem!","en":"I''m not!","de":"Bin ich auch nicht!"}},{"speaker":"npc","text":{"pl":"Muszę się pozbyć dużego ładunku ziela.","en":"I need to get rid of a whole pile of weed.","de":"Ich muss noch ''nen ganzen Berg Kraut loswerden."}},{"speaker":"hero","text":{"pl":"Sprzedajesz towary z obozu Bractwa?","en":"You''re here to sell goods from the Sect Camp?","de":"Du bist hier um Waren aus dem Sektenlager zu verkaufen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_problem_15_00_0', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_problem_15_00_0","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_Problem_Info","outputIds":["DIA_BaalIsidro_Problem_15_00","DIA_BaalIsidro_Problem_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Wiesz co? Masz nieźle przechlapane. Baal Kagan znajdzie sobie kogoś innego na twoje miejsce.","en":"I''ll tell you something - you have a problem. Baal Kagan will make sure you''ll be replaced.","de":"Ich sag dir was - du hast ein Problem. Baal Kagan will dafür sorgen, dass du ersetzt wirst."}},{"speaker":"npc","text":{"pl":"Co? Na potęgę Śniącego! Muszę się koniecznie pozbyć tego towaru!","en":"What? The Sleeper have mercy on me! I need to get rid of the stuff...","de":"Was? Beim großen Schläfer. Ich muss das Zeug loswerden ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_running_03_04_4', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_running_03_04_4","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_RUNNING_Info","outputIds":["DIA_BaalIsidro_RUNNING_03_04","DIA_BaalIsidro_RUNNING_NoOre_15_05","DIA_BaalIsidro_RUNNING_NoOre_03_06"],"lines":[{"speaker":"npc","text":{"pl":"Miło było robić z tobą interesy.","en":"It was a good idea to do business with you.","de":"War ne gute Idee, mit dir Geschäfte zu machen."}},{"speaker":"hero","text":{"pl":"Nie mam ich przy sobie.","en":"I don''t have it on me.","de":"Hab ich nicht bei mir."}},{"speaker":"npc","text":{"pl":"To lepiej je szybko przynieś!","en":"Then get it!","de":"Dann schaff sie ran!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_running_15_00_0', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_running_15_00_0","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_RUNNING_Info","outputIds":["DIA_BaalIsidro_RUNNING_15_00","DIA_BaalIsidro_RUNNING_03_01","DIA_BaalIsidro_RUNNING_15_02","DIA_BaalIsidro_RUNNING_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Sprzedałem całe ziele.","en":"I''ve sold the weed.","de":"Ich hab'' das Kraut verkauft."}},{"speaker":"npc","text":{"pl":"A moje 200 bryłek?","en":"And my 200 ore?","de":"Meine 200?"}},{"speaker":"hero","text":{"pl":"Proszę bardzo.","en":"Here it is.","de":"Hier sind sie."}},{"speaker":"npc","text":{"pl":"Świetnie... Teraz Baal Kagan może mi... No wiesz (Pijacki śmiech)","en":"Good... Now I don''t give a damn about Baal Kagan any more.","de":"Gut ... Jetzt kann mich Baal Kagan mal. (lacht dreckig)"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_think_again_15_00_0', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_think_again_15_00_0","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_ThinkAgain_Info","outputIds":["DIA_BaalIsidro_ThinkAgain_15_00","DIA_BaalIsidro_ThinkAgain_03_01","DIA_BaalIsidro_ThinkAgain_15_02","DIA_BaalIsidro_ThinkAgain_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Sam pomyśl - dasz mi ziele i podzielimy się zyskami.","en":"Think about it - give me the weed and we''ll share the profit.","de":"Überleg''s dir - Gib mir das Kraut und wir teilen den Gewinn."}},{"speaker":"npc","text":{"pl":"Stary, muszę koniecznie sprzedać ten towar! Chyba nie chcesz mnie wystrychnąć na dudka, co?","en":"Oh man, I need to get rid of the stuff. You wouldn''t try to make me look like a fool, would you?","de":"Oh Mann, ich muss das Zeug loswerden. Du willst mich doch nicht über''s Ohr hauen, oder?"}},{"speaker":"hero","text":{"pl":"Masz moje słowo.","en":"I give you my word.","de":"Ich geb'' dir mein Wort."}},{"speaker":"npc","text":{"pl":"Dobrze, oto ziele... Powinieneś za nie dostać jakieś 400 bryłek. To będzie po 200 bryłek na głowę. Zaczekam na ciebie tutaj. Wróć, jak tylko uda ci się sprzedać towar.","en":"Good, here''s the stuff... You should get at least 400 ore for it. That would be 200 for each of us. I''ll be waiting here. Come back as soon as you have the ore.","de":"Gut, hier ist das Zeug... Du müsstest mindestens 400 Erz dafür kriegen. Also 200 für jeden. Ich bin die ganze Zeit hier. Wenn du das Erz hast, komm zurück."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1333_baal_isidro_dia_baal_isidro_think_again_15_04_4', 'NOV_1333_BaalIsidro', '{"id":"missions_dia_nov_1333_baal_isidro_dia_baal_isidro_think_again_15_04_4","npcId":"NOV_1333_BaalIsidro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1333_BaalIsidro.d","sourceFunction":"DIA_BaalIsidro_ThinkAgain_Info","outputIds":["DIA_BaalIsidro_ThinkAgain_15_04","DIA_BaalIsidro_ThinkAgain_03_05","DIA_BaalIsidro_ThinkAgain_03_06","DIA_BaalIsidro_REFUSE_ThinkAgain_03_00"],"lines":[{"speaker":"hero","text":{"pl":"Wiesz może, kto może tutaj kupić większą ilość ziela?","en":"Do you know who''ll take bigger amounts here?","de":"Weißt du, wer hier größere Mengen abnimmt?"}},{"speaker":"npc","text":{"pl":"Gdybym wiedział, sam bym je dawno sprzedał, nie sądzisz?","en":"If I knew that I would have gone myself.","de":"Wenn ich das wüsste, wär'' ich selber losgegangen."}},{"speaker":"npc","text":{"pl":"Poczułem się lepiej po pozbyciu się tego ziela, wiesz?","en":"I feel much better now that I''m rid of the stuff.","de":"Jetzt, wo ich das Zeug los bin, fühle ich mich schon viel besser."}},{"speaker":"npc","text":{"pl":"Nie, jakoś sobie poradzę...","en":"No, man. I''ll manage...","de":"Nee, Mann. Ich schaff das schon noch ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1356_shrat_dia_shrat_come_with_me_15_00_0', 'NOV_1356_Shrat', '{"id":"missions_dia_nov_1356_shrat_dia_shrat_come_with_me_15_00_0","npcId":"NOV_1356_Shrat","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1356_Shrat.d","sourceFunction":"DIA_Shrat_ComeWithMe_Info","outputIds":["DIA_Shrat_ComeWithMe_15_00","DIA_Shrat_ComeWithMe_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Jasne! Trzymajmy się razem! Chodź ze mną!","en":"Let''s move around together! Come with me!","de":"Lass uns zusammen losziehen! Komm mit!"}},{"speaker":"npc","text":{"pl":"To właśnie chciałem usłyszeć! Chodźmy!","en":"Now that''s what I like to hear! Let''s go!","de":"Das ist doch mal ein Wort! Auf geht''s!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1356_shrat_dia_shrat_join_psi_15_00_0', 'NOV_1356_Shrat', '{"id":"missions_dia_nov_1356_shrat_dia_shrat_join_psi_15_00_0","npcId":"NOV_1356_Shrat","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1356_Shrat.d","sourceFunction":"DIA_Shrat_JoinPSI_Info","outputIds":["DIA_Shrat_JoinPSI_15_00","DIA_Shrat_JoinPSI_02_01","DIA_Shrat_JoinPSI_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym dołączyć do Bractwa. Możesz mi pomóc?","en":"I want to join the Brotherhood - can you help me?","de":"Ich will der Bruderschaft beitreten - kannst du mir helfen?"}},{"speaker":"npc","text":{"pl":"Chcesz tu zamieszkać? A ja zastanawiam się właśnie jak stąd uciec!","en":"You want to join this place? I''m actually just thinking about how to get away from here.","de":"Du willst bei dem Laden hier mitmachen? Ich überleg gerade, wie ich hier wegkomme."}},{"speaker":"npc","text":{"pl":"Moglibyśmy przemierzyć całą kolonię, odciążyć kilku frajerów z ich gotówki, zebrać trochę rudy - co ty na to?","en":"We could roam the colony. Relieve a few numskulls of their money, collect some ore - what do you think?","de":"Wir könnten ein bisschen durch die Kolonie ziehen. Ein paar Einfaltspinsel ausplündern, ein bisschen Erz sammeln - was denkst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1356_shrat_dia_shrat_leave_me_15_00_0', 'NOV_1356_Shrat', '{"id":"missions_dia_nov_1356_shrat_dia_shrat_leave_me_15_00_0","npcId":"NOV_1356_Shrat","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1356_Shrat.d","sourceFunction":"DIA_Shrat_LeaveMe_Info","outputIds":["DIA_Shrat_LeaveMe_15_00","DIA_Shrat_LeaveMe_02_01"],"lines":[{"speaker":"hero","text":{"pl":"Tutaj nasze drogi się rozchodzą. Dalej pójdę sam.","en":"Our paths separate here - I''ll go on on my own.","de":"Hier trennen sich unsere Wege - ich werde von hier aus alleine weiterziehen."}},{"speaker":"npc","text":{"pl":"Dobra. Ja wracam do mojej kryjówki na bagnach. Uważaj na siebie!","en":"Okay. I''ll get back to my hiding place in the swamp. Take care of yourself!","de":"Na gut. Ich werd'' zurück in mein Versteck im Sumpf gehen. Pass gut auf dich auf!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1356_shrat_dia_shrat_why_here_15_00_0', 'NOV_1356_Shrat', '{"id":"missions_dia_nov_1356_shrat_dia_shrat_why_here_15_00_0","npcId":"NOV_1356_Shrat","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1356_Shrat.d","sourceFunction":"DIA_Shrat_WhyHere_Info","outputIds":["DIA_Shrat_WhyHere_15_00","DIA_Shrat_WhyHere_02_01","DIA_Shrat_WhyHere_02_02","DIA_Shrat_WhyHere_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du denn hier?"}},{"speaker":"npc","text":{"pl":"Czy pozwoliłem ci się do mnie odezwać?!","en":"Did I give you permission to speak to me?","de":"Habe ich dir erlaubt, mich anzusprechen?"}},{"speaker":"npc","text":{"pl":"Tylko żartuję! Te cholerne świry zaczynają mnie już denerwować, dlatego tu jestem!","en":"Only joking! Those damned loonies are getting on my nerves, that''s why I''m here!","de":"War nur''n Witz! Diese verdammten Spinner gehen mir gehörig auf den Sack, deswegen bin ich hier!"}},{"speaker":"npc","text":{"pl":"\"Nie odzywaj się do mnie!\" - \"Módl się o łaskę Śniącego!\" - \"Twoje zadanie jest szczególnie ważne!\"","en":"Don''t speak to me!'' - ''Pray for forgiveness by the Sleeper!'' - ''Your mission is of extraordinary importance!''","de":"''Sprich mich nicht an!'' - ''Bitte den Schläfer um Vergebung!'' - ''Deine Mission ist von äußerster Dringlichkeit!''"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1357_fortuno_dia_fortuno_daily_ration_15_00_0', 'NOV_1357_Fortuno', '{"id":"missions_dia_nov_1357_fortuno_dia_fortuno_daily_ration_15_00_0","npcId":"NOV_1357_Fortuno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1357_Fortuno.d","sourceFunction":"DIA_Fortuno_DailyRation_Info","outputIds":["DIA_Fortuno_DailyRation_15_00","DIA_Fortuno_DailyRation_05_01","DIA_Fortuno_DailyRation_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Przyszedłem po moją codzienną porcję ziela.","en":"I''ve come to collect my daily ration.","de":"Ich will mir meine tägliche Ration abholen."}},{"speaker":"npc","text":{"pl":"Proszę bardzo. Trzy sztuki Mroku Północy. Tylko nie wypal wszystkiego na raz!","en":"Here, take it. Three of the Northern Dark - but don''t smoke them all at once.","de":"Hier nimm. 3 Schwarzer Weiser - aber nicht alle auf einmal rauchen."}},{"speaker":"npc","text":{"pl":"Dostałeś już dziś swoją porcję. Jeśli chcesz więcej, będziesz musiał zapłacić. Najlepiej przyjdź jutro.","en":"You''ve already had your daily ration. If you want more, come back tomorrow or buy something.","de":"Du hattest deine Tagesration schon. Wenn du mehr willst, komm morgen wieder oder kauf was."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1357_fortuno_dia_fortuno_get_geschenk_15_00_0', 'NOV_1357_Fortuno', '{"id":"missions_dia_nov_1357_fortuno_dia_fortuno_get_geschenk_15_00_0","npcId":"NOV_1357_Fortuno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1357_Fortuno.d","sourceFunction":"DIA_Fortuno_GetGeschenk_Info","outputIds":["DIA_Fortuno_GetGeschenk_15_00","DIA_Fortuno_GetGeschenk_05_01","DIA_Fortuno_GetGeschenk_05_02","DIA_Fortuno_GetGeschenk_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Co to za prezent?","en":"What have you got for me?","de":"Was hast du für mich?"}},{"speaker":"npc","text":{"pl":"To Mrok Północy - dobry towar!","en":"Here, take three rolls of swampweed. It''s Northern Dark. Good stuff.","de":"Hier, nimm drei Rollen Sumpfkraut. Es ist Schwarzer Weiser. Gutes Zeug."}},{"speaker":"npc","text":{"pl":"Możesz do mnie przychodzić codziennie po nową porcję, ale gdybyś chciał dostać więcej niż przewiduje dzienna racja, będziesz musiał zapłacić.","en":"You can have more of it every day, but if you want more than your daily ration, well, you need to pay.","de":"Du kannst jeden Tag mehr davon haben, aber wenn du mehr als deine tägliche Ration willst, musst du zahlen."}},{"speaker":"npc","text":{"pl":"Gdybyś znalazł jakieś zioła lub owoce możesz je przynieść do mnie. Chętnie je od ciebie odkupię.","en":"If you find berries and herbs on the paths between the camps, you can bring them to me. I''ll buy them off you.","de":"Falls du auf deinem Weg zwischen den Lagern Kräuter und Beeren findest, bring sie zu mir. Ich werde sie dir abkaufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1357_fortuno_dia_fortuno_greet_05_00_0', 'NOV_1357_Fortuno', '{"id":"missions_dia_nov_1357_fortuno_dia_fortuno_greet_05_00_0","npcId":"NOV_1357_Fortuno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1357_Fortuno.d","sourceFunction":"DIA_Fortuno_Greet_Info","outputIds":["DIA_Fortuno_Greet_05_00"],"lines":[{"speaker":"npc","text":{"pl":"Chodź bliżej! Każdy nowoprzybyły otrzymuje od Bractwa powitalny prezent!","en":"Come closer! Every newcomer to this place receives a gift of welcome!","de":"Tritt näher! Hier gibt es ein Willkommensgeschenk für jeden Neuen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1358_harlok_dia_harlok_angry_01_00_0', 'NOV_1358_Harlok', '{"id":"missions_dia_nov_1358_harlok_dia_harlok_angry_01_00_0","npcId":"NOV_1358_Harlok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1358_Harlok.d","sourceFunction":"DIA_Harlok_Angry_Info","outputIds":["DIA_Harlok_Angry_01_00"],"lines":[{"speaker":"npc","text":{"pl":"Zostaw mnie w spokoju! Przecież już idę!","en":"Leave me alone! I''m going...","de":"Lass mich in Ruhe! Ich mach'' ja schon ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1358_harlok_dia_harlok_fetch_harlok_15_00_0', 'NOV_1358_Harlok', '{"id":"missions_dia_nov_1358_harlok_dia_harlok_fetch_harlok_15_00_0","npcId":"NOV_1358_Harlok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1358_Harlok.d","sourceFunction":"DIA_Harlok_FetchHarlok_Info","outputIds":["DIA_Harlok_FetchHarlok_15_00","DIA_Harlok_FetchHarlok_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Ghorim.","en":"Ghorim sent me.","de":"Ghorim schickt mich."}},{"speaker":"npc","text":{"pl":"Co?","en":"What?","de":"Was?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1358_harlok_dia_harlok_fetch_harlok_or_else_15_00_0', 'NOV_1358_Harlok', '{"id":"missions_dia_nov_1358_harlok_dia_harlok_fetch_harlok_or_else_15_00_0","npcId":"NOV_1358_Harlok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1358_Harlok.d","sourceFunction":"DIA_Harlok_FetchHarlok_OrElse","outputIds":["DIA_Harlok_FetchHarlok_OrElse_15_00","DIA_Harlok_FetchHarlok_OrElse_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Rusz dupę do roboty, albo dostaniesz kopa!","en":"Get your ass to the weed mashers or you''ll be for it.","de":"Schwing deinen Hintern zu den Krautstampfern, oder es gibt Saures."}},{"speaker":"npc","text":{"pl":"Tylko spróbuj mi podskoczyć, frajerze!","en":"Just TRY to mess with me again, sucker!","de":"VERSUCH doch mal, dich mit mir anzulegen, du Penner!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1358_harlok_dia_harlok_fetch_harlok_please_15_00_0', 'NOV_1358_Harlok', '{"id":"missions_dia_nov_1358_harlok_dia_harlok_fetch_harlok_please_15_00_0","npcId":"NOV_1358_Harlok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1358_Harlok.d","sourceFunction":"DIA_Harlok_FetchHarlok_Please","outputIds":["DIA_Harlok_FetchHarlok_Please_15_00","DIA_Harlok_FetchHarlok_Please_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Mam ci przypomnieć, że powinieneś go wreszcie zluzować.","en":"I''m here to remind you that you''re to take over from him.","de":"Ich soll dich daran erinnern, dass du ihn ablösen sollst."}},{"speaker":"npc","text":{"pl":"To bardzo miło z twojej strony. Przypomnij mi znowu, jak już się wyśpię, dobra?","en":"That''s very nice of you. Remind me again when I''m through sleeping, yeah?","de":"Das ist aber nett von dir. Erinnere mich doch noch mal, wenn ich ausgeschlafen habe, ja?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1358_harlok_dia_harlok_harlok_again_15_00_0', 'NOV_1358_Harlok', '{"id":"missions_dia_nov_1358_harlok_dia_harlok_harlok_again_15_00_0","npcId":"NOV_1358_Harlok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1358_Harlok.d","sourceFunction":"DIA_Harlok_HarlokAgain_Info","outputIds":["DIA_Harlok_HarlokAgain_15_00","DIA_Harlok_HarlokAgain_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Chciałem ci tylko przypomnieć, że masz zmienić twojego kolegę.","en":"I just wanted to remind you to take your pal''s place now!","de":"Ich wollte dich noch mal dran erinnern, deinen Kumpel abzulösen!"}},{"speaker":"npc","text":{"pl":"Słuchaj, koleś. Kazałem ci spadać!","en":"Listen! I told you to get lost!","de":"Hör zu! Ich habe gesagt, mach, dass du wegkommst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1358_harlok_dia_harlok_send_harlok_15_00_0', 'NOV_1358_Harlok', '{"id":"missions_dia_nov_1358_harlok_dia_harlok_send_harlok_15_00_0","npcId":"NOV_1358_Harlok","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1358_Harlok.d","sourceFunction":"DIA_Harlok_SendHarlok_Info","outputIds":["DIA_Harlok_SendHarlok_15_00","DIA_Harlok_SendHarlok_01_01","DIA_Harlok_SendHarlok_15_02","DIA_Harlok_SendHarlok_01_03"],"lines":[{"speaker":"hero","text":{"pl":"No i co? Masz już ochotę zmienić swojego kolegę?","en":"Well, d''you feel like giving your pal a break now?","de":"Na, hast du langsam Lust bekommen, deinen Freund abzulösen?"}},{"speaker":"npc","text":{"pl":"Wiesz co? Jesteś jak wrzód na tyłku! Czemu wtykasz nos w nie swoje sprawy?","en":"You damn pain in the butt! Why do you have to meddle in my affairs?","de":"Du verdammter Mistkerl! Wieso mischst du dich überhaupt in unsere Angelegenheiten?"}},{"speaker":"hero","text":{"pl":"Chciałem tylko zobaczyć cię przy pracy...","en":"I just want to see you mashing.","de":"Ich will dich einfach stampfen sehen."}},{"speaker":"npc","text":{"pl":"Dobra, dobra - już idę... Frajer!","en":"Okay, okay - I''m on my way... sucker!","de":"Ist ja schon gut - ich gehe ja ...  Mistkerl!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1371_baal_netbek_nov_1371_baal_netbek_again_info_15_01_0', 'NOV_1371_BaalNetbek', '{"id":"missions_dia_nov_1371_baal_netbek_nov_1371_baal_netbek_again_info_15_01_0","npcId":"NOV_1371_BaalNetbek","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1371_BaalNetbek.d","sourceFunction":"Nov_1371_BaalNetbek_AGAIN_Info","outputIds":["Nov_1371_BaalNetbek_AGAIN_Info_15_01","Nov_1371_BaalNetbek_AGAIN_Info_03_02"],"lines":[{"speaker":"hero","text":{"pl":"Cześć, co słychać?","en":"Hey, how''s it going?","de":"Hey, geht''s dir gut?"}},{"speaker":"npc","text":{"pl":"Tylko uważaj, żebyś nie skrzywdził moich kochanych drzew!","en":"Mind you don''t hurt my trees!","de":"Pass auf, dass du meine Bäume nicht verletzt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_nov_1371_baal_netbek_nov_1371_baal_netbek_crazy_info_15_05_4', 'NOV_1371_BaalNetbek', '{"id":"missions_dia_nov_1371_baal_netbek_nov_1371_baal_netbek_crazy_info_15_05_4","npcId":"NOV_1371_BaalNetbek","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_NOV_1371_BaalNetbek.d","sourceFunction":"Nov_1371_BaalNetbek_CRAZY_Info","outputIds":["Nov_1371_BaalNetbek_CRAZY_Info_15_05","Nov_1371_BaalNetbek_CRAZY_Info_03_06","Nov_1371_BaalNetbek_CRAZY_Info_15_07","Nov_1371_BaalNetbek_CRAZY_Info_15_08"],"lines":[{"speaker":"hero","text":{"pl":"...Eee, rozumiem. Cóż, chyba pójdę już dalej...","en":"... Oh, I see. Well, I''ll be on my way then...","de":"...ach so, na ich geh dann mal wieder..."}},{"speaker":"npc","text":{"pl":"Zaczekaj, mógłbyś pomóc mi przekształcić to bagno w ogromną łąkę pełną kwiatów!","en":"Wait, you can help me convert this swamp into a massive meadow of flowers!","de":"Warte, du kannst mir helfen, diesen Sumpf in eine gigantische Blumenwiese zu verwandeln!"}},{"speaker":"hero","text":{"pl":"Może zaczniesz beze mnie? Wrócę... niedługo.","en":"Okay, you just get started. Me... I''ll be back later.","de":"Fang am besten schon mal damit an, ich... ich komme dann später wieder."}},{"speaker":"hero","text":{"pl":"Ten człowiek raczej mi nie pomoże...","en":"He''s not going to get me anywhere...","de":"Ich glaube, der Kerl bringt mich nicht wirklich weiter..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_orc_high_priest1_info_high_priest1_17_01_0', 'ORC_Priest_1', '{"id":"missions_dia_orc_high_priest1_info_high_priest1_17_01_0","npcId":"ORC_Priest_1","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Orc_HighPriest1.d","sourceFunction":"Info_HighPriest1_Info","outputIds":["Info_HighPriest1_17_01","Info_HighPriest1_17_02","Info_HighPriest1_17_03","Info_HighPriest1_15_04"],"lines":[{"speaker":"npc","text":{"pl":"ŚMIERTELNY!","en":"MOOOOOOORTAAAL!","de":"STEEERBLICHEEERRRR!!!!"}},{"speaker":"npc","text":{"pl":"JAK ŚMIESZ ZAKŁÓCAĆ MÓJ SPOKÓJ?!","en":"YOU DAAARE TO DISTURB MY PEEEAACE!","de":"DU WAAAGST ES, MEINE RUUHHE ZU STÖÖÖREN!"}},{"speaker":"npc","text":{"pl":"PRZYGOTUJ SIĘ NA ŚMIERĆ!","en":"PREEPAAARE FOR THE EEEND!","de":"BEREEEITE DIIICH AUF DAS EEEENDE VOOOR!"}},{"speaker":"hero","text":{"pl":"Jeszcze się przekonamy, na kogo przyszła pora, ty gnijący ochłapie.","en":"It remains to be seen whose end it''s going to be, you worm-bitten meatloaf!","de":"Fragt sich, nur wessen Ende, du wurmzerfressener Fleischklops!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_orc_high_priest2_info_high_priest2_17_01_0', 'ORC_Priest_2', '{"id":"missions_dia_orc_high_priest2_info_high_priest2_17_01_0","npcId":"ORC_Priest_2","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Orc_HighPriest2.d","sourceFunction":"Info_HighPriest2_Info","outputIds":["Info_HighPriest2_17_01","Info_HighPriest2_17_02","Info_HighPriest2_15_03"],"lines":[{"speaker":"npc","text":{"pl":"NIEWIERNY? W DOMU PANA?!","en":"AN INFIDEL IN THE HOUSE OF THE MASTER!!!!","de":"EIN UNGLÄUBIGEEEEER IM HORT DES MEEEISTERS!!!!"}},{"speaker":"npc","text":{"pl":"BĄDŹ PRZEKLĘTY!","en":"DAMNED BE YOOUUUU!","de":"VERDAMMMMMMMNIS ÜBER DIIIICH!"}},{"speaker":"hero","text":{"pl":"Sam bądź przeklęty, pajacu!","en":"YOU be damned, you stinking moldy carpet!","de":"Verdammt sein wirst DU, stinkender Moderteppich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_orc_high_priest3_info_high_priest3_17_01_0', 'ORC_Priest_3', '{"id":"missions_dia_orc_high_priest3_info_high_priest3_17_01_0","npcId":"ORC_Priest_3","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Orc_HighPriest3.d","sourceFunction":"Info_HighPriest3_Info","outputIds":["Info_HighPriest3_17_01","Info_HighPriest3_17_02","Info_HighPriest3_15_03"],"lines":[{"speaker":"npc","text":{"pl":"ŚMIERTELNY!","en":"MOOORTAAAAL!!!!!","de":"STEEEEERBLICHEEEEER!!!!!"}},{"speaker":"npc","text":{"pl":"TWÓJ CZAS WŁAŚNIE DOBIEGŁ KOŃCA!","en":"YOOOOOOUR TRAAAVELS EEEND HEEERE WIITH MEEEEEEE!!","de":"DEINEEEEEE REISEEEEE EEEENDET HIIEEER BEI MIIIIR!!"}},{"speaker":"hero","text":{"pl":"Ależ skąd, kobiety i gnijące mumie przodem!","en":"I''ll send you traveling first, you moldy maggot''s idea of paradise!","de":"Erst mal schicke ich dich auf eine neue Reise, verfaultes Madenparadies!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_orc_high_priest4_info_high_priest4_17_01_0', 'ORC_Priest_4', '{"id":"missions_dia_orc_high_priest4_info_high_priest4_17_01_0","npcId":"ORC_Priest_4","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Orc_HighPriest4.d","sourceFunction":"Info_HighPriest4_Info","outputIds":["Info_HighPriest4_17_01","Info_HighPriest4_17_02","Info_HighPriest4_15_03"],"lines":[{"speaker":"npc","text":{"pl":"TWOJA DROGA KOŃCZY SIĘ TUTAJ!","en":"YOOUUUUR LOOONG TRAAAVEL WILL BE OOVEEEER!!!","de":"ZUEEEENDEEEE IST DEEEIN LANGER WEEEG!!!"}},{"speaker":"npc","text":{"pl":"NIECH SCZEŹNIE TWA CIELESNA POWŁOKA!","en":"YOOOUUR MOOORTAAAL BOOODDY WILL BUURN!!!","de":"BREEENNEEEN SOLL DEINEEEE STEEEERBLICHEEEE HÜLLEEEE!!!"}},{"speaker":"hero","text":{"pl":"Wolałbym nie, jeśli łaska!","en":"Now I don''t really think that''s such a good idea!","de":"Das wollen wir doch mal schön bleiben lassen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_orc_high_priest5_info_high_priest5_17_04_0', 'ORC_Priest_5', '{"id":"missions_dia_orc_high_priest5_info_high_priest5_17_04_0","npcId":"ORC_Priest_5","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Orc_HighPriest5.d","sourceFunction":"Info_HighPriest5_Info","outputIds":["Info_HighPriest5_17_04","Info_HighPriest5_17_05","Info_HighPriest5_17_01","Info_HighPriest5_17_02"],"lines":[{"speaker":"npc","text":{"pl":"MASZ ZE SOBĄ POTĘŻNY ORĘŻ!","en":"YOUUU have A POWERFUL WEEAAPON!!!","de":"DU HASSST EINE MÄCHTIGEEE WAFFFEE!!!"}},{"speaker":"npc","text":{"pl":"POWSTRZYMAM CIĘ!","en":"I WIIIIL STOOOP YOOUUU!!!","de":"ICCH WERDDDEEEE DIIICH AUFFHALTEEEEEN!!!"}},{"speaker":"npc","text":{"pl":"MUSISZ TUTAJ ZAWRÓCIĆ!","en":"YOOUUU MUST TUUURN BAAACK HEEEERE!!!","de":"UMKEEEHREN MUSST DU HIEEER!!!"}},{"speaker":"npc","text":{"pl":"NIKT NIE MOŻE ZAKŁÓCIĆ SNU MEGO PANA!","en":"NOOOBOODY MAY DISTUUURB THE SLEEEEP OF MY MAAASTER!!!","de":"NIEEEMAND DARF DIE RUHEEE MEINEEES MEEEISTERS STÖÖÖÖREN!!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_orc_high_priest5_info_high_priest5_failed_15_01_0', 'ORC_Priest_5', '{"id":"missions_dia_orc_high_priest5_info_high_priest5_failed_15_01_0","npcId":"ORC_Priest_5","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_Orc_HighPriest5.d","sourceFunction":"Info_HighPriest5FAILED_Info","outputIds":["Info_HighPriest5FAILED_15_01","Info_HighPriest5FAILED_17_02","Info_HighPriest5FAILED_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Cholera! Nie zadaję mu nawet najmniejszych obrażeń. Potrzebuję innej...","en":"Damn! I''m not causing the slightest damage! I need another...","de":"Verdammt! Ich bewirke nicht den geringsten Schaden! Ich brauche eine andere ..."}},{"speaker":"npc","text":{"pl":"TERAZ ZGINIESZ!","en":"NOOOWW YOOOUUU WIIIILL DIIEEE!!!!!","de":"NUUUUN WIIIIRST DUUUU STEEEERBEEEEEN!!!!!"}},{"speaker":"hero","text":{"pl":"Lepiej się stąd wynosić! I to zaraz!","en":"I''d better get out of here fast!","de":"Nichts wie weg hier!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_400_ore_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_400_ore_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_400Ore_Info","outputIds":["ORG_801_Lares_400Ore_15_00","ORG_801_Lares_400Ore_11_01","ORG_801_Lares_400Ore_NOORE_11_00"],"lines":[{"speaker":"hero","text":{"pl":"Mam dla ciebie 400 bryłek.","en":"I have the 400 ore.","de":"Ich hab'' die 400 Erz."}},{"speaker":"npc","text":{"pl":"Dobrze! Świetnie! To mi chyba wystarczy.","en":"Good! Very good. I believe that should be sufficient now.","de":"Gut! Sehr gut. Ich denke, das reicht jetzt."}},{"speaker":"npc","text":{"pl":"Lepiej przelicz jeszcze raz! Mam nadzieję, że nie wydałeś ich na gorzałę!","en":"Count again. I hope you haven''t spent half of it on booze.","de":"Zähl noch mal nach. Ich hoffe, du hast nicht schon die Hälfte versoffen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_bring_list_11_04_4', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_bring_list_11_04_4","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_BringList_Info","outputIds":["ORG_801_Lares_BringList_11_04","ORG_801_Lares_BringList_11_05","ORG_801_Lares_BringList_11_06"],"lines":[{"speaker":"npc","text":{"pl":"Rzeczywiście! Wiesz, co z nią teraz zrobimy? Dopiszemy parę rzeczy, a ty zaniesiesz ją do Starego Obozu!","en":"Indeed! D''you know what we''re going to do with it? We''ll add to it and you''ll take the list back to the Old Camp!","de":"Tatsächlich! Weißt du, was wir jetzt damit machen? Wir schreiben noch ein bisschen was drauf und du bringst die Liste zurück ins Alte Lager!"}},{"speaker":"npc","text":{"pl":"A jak już dostarczą wszystko do kopalni, obrabujemy ich ze wszystkiego! To nie zajmie długo... Ha! Masz tu listę. Wiesz, co masz robić.","en":"Then, when they deliver the stuff to the mine, we''ll mug ''em and take the lot! It won''t take a minute... Hah! Here''s the list. You know what to do.","de":"Wenn sie den Krempel dann an die Mine liefern, überfallen wir sie und sacken uns alles ein! Das haben wir gleich ... So! Hier ist die Liste. Du weißt, was du zu tun hast."}},{"speaker":"npc","text":{"pl":"Das haben wir gleich ... So! Hier ist die Liste. Du weißt, was du zu tun hast.","en":"Das haben wir gleich ... So! Hier ist die Liste. Du weißt, was du zu tun hast.","de":"Das haben wir gleich ... So! Hier ist die Liste. Du weißt, was du zu tun hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_bring_list_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_bring_list_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_BringList_Info","outputIds":["ORG_801_Lares_BringList_15_00","ORG_801_Lares_BringList_11_01","ORG_801_Lares_BringList_11_02","ORG_801_Lares_BringList_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam przy sobie listę zamówień dla Starej Kopalni.","en":"I have the list of requirements for the Old Mine on me.","de":"Ich habe die Bedarfsliste der Alten Mine bei mir."}},{"speaker":"npc","text":{"pl":"O niech mnie... Albo jesteś cholernie odważny, albo cholernie głupi...","en":"No! I don''t believe it! I must say you do seem to have a nerve.","de":"Nein! Das glaub'' ich nicht! Du bist mir schon einer, das muss ich ja sagen."}},{"speaker":"npc","text":{"pl":"Pokaż!","en":"Show me!","de":"Zeig her!"}},{"speaker":"hero","text":{"pl":"Oto ona...","en":"Here it is...","de":"Hier ist sie ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_bring_list_anteil_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_bring_list_anteil_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_BringListAnteil_Info","outputIds":["ORG_801_Lares_BringListAnteil_15_00","ORG_801_Lares_BringListAnteil_11_01","ORG_801_Lares_BringListAnteil_15_02","ORG_801_Lares_BringListAnteil_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Napadliście już na konwój?! A gdzie moja dola?!","en":"They''ve already mugged the convoy? Where''s my share?","de":"Sie haben den Konvoi schon überfallen? Was ist mein Anteil bei der Sache?"}},{"speaker":"npc","text":{"pl":"Pogadaj z Gornem. On ci coś da.","en":"Go to see Gorn. He''ll give you something.","de":"Geh zu Gorn. Er wird dir etwas geben."}},{"speaker":"hero","text":{"pl":"Znam Gorna, ale on nie należy do waszej bandy. Jest Najemnikiem, pracuje dla Magów.","en":"I know Gorn. He''s no member of the gang. He''s a mercenary who works for the mages.","de":"Ich kenne Gorn. Er ist kein Mitglied der Bande. Er ist ein Söldner der Magier."}},{"speaker":"npc","text":{"pl":"Zgadza się.","en":"Yeah, that''s right.","de":"Ja, das ist richtig."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_bring_list_anteil_15_04_4', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_bring_list_anteil_15_04_4","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_BringListAnteil_Info","outputIds":["ORG_801_Lares_BringListAnteil_15_04","ORG_801_Lares_BringListAnteil_11_05"],"lines":[{"speaker":"hero","text":{"pl":"To on też maczał w tym palce?","en":"Was he involved in this business?","de":"War er an der Sache beteiligt?"}},{"speaker":"npc","text":{"pl":"Czasem lepiej jest nie wiedzieć za dużo. Idź do niego po swoją nagrodę.","en":"Knowing too much isn''t good for you. Just go to see him and collect your share.","de":"Es ist nicht gut für dich, wenn du zu viel weißt. Geh einfach zu ihm und hol dir deinen Anteil ab."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_bring_list_back_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_bring_list_back_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_BringListBack_Info","outputIds":["ORG_801_Lares_BringListBack_15_00","ORG_801_Lares_BringListBack_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Przekazałem listę Diego.","en":"I''ve given the list to Diego.","de":"Ich habe Diego die Liste übergeben."}},{"speaker":"npc","text":{"pl":"Świetnie! Rozmieściłem paru ludzi na drodze do Starej Kopalni. Strażnicy Thorusa pewnie już gryzą ziemię.","en":"Good! I positioned some men on the path to the Old Mine. Thorus'' guards are lying dead in the forest even as we speak.","de":"Gut! Ich habe bereits Leute auf dem Weg zur Alten Mine postiert. In diesem Moment liegen Thorus'' Gardisten schon tot im Wald."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_get_kraut_11_04_4', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_get_kraut_11_04_4","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_GetKraut_Info","outputIds":["ORG_801_Lares_GetKraut_11_04","ORG_801_Lares_GetKraut_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Skoro masz już ziele, chcę, żebyś je sprzedał. Przynieś mi 400 bryłek rudy.","en":"If you have the weed, sell it. Bring me the 400 ore.","de":"Wenn du das Kraut hast, verkauf es. Die 400 Erz bringst du zu mir."}},{"speaker":"npc","text":{"pl":"Wtedy wrócimy do twojego członkostwa w mojej bandzie.","en":"Then we''ll talk again to see if you''ll be admitted to the gang.","de":"Dann unterhalten wir uns noch mal darüber, ob du in die Bande aufgenommen wirst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_get_kraut_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_get_kraut_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_GetKraut_Info","outputIds":["ORG_801_Lares_GetKraut_15_00","ORG_801_Lares_GetKraut_11_01","ORG_801_Lares_GetKraut_15_02","ORG_801_Lares_GetKraut_11_03"],"lines":[{"speaker":"hero","text":{"pl":"To co mam zrobić, żeby cię przekonać?","en":"What else can I do?","de":"Was kann ich noch machen?"}},{"speaker":"npc","text":{"pl":"Pewien człowiek z Sekty, niejaki Baal Isidro, ma przy sobie ziele warte co najmniej 400 bryłek rudy. Chcę, żebyś mi je przyniósł. Jak tego dokonasz - to już twoja sprawa.","en":"Baal Isidro from the Sect Camp has weed worth at least 400 ore on him. I want you to get it from him. I don''t care how you do it.","de":"Baal Isidro aus dem Sektenlager hat Kraut im Wert von mindestens 400 Erz bei sich. Ich will, dass du es ihm abnimmst. Egal, wie."}},{"speaker":"hero","text":{"pl":"Jeśli masz na myśli tę stertę trawy, to mam ją już od dawna.","en":"If you mean the massive heap of weed, I''ve already got it.","de":"Wenn du den Riesenhaufen Kraut meinst, den hab'' ich mir schon unter den Nagel gerissen"}},{"speaker":"npc","text":{"pl":"Widzę, że sprytny z ciebie chłopak!","en":"Looks like you''ve been real smart!","de":"Du scheinst mir einer von der schnellen Sorte zu sein!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_goto_kalom_11_04_4', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_goto_kalom_11_04_4","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_GotoKalom_Info","outputIds":["ORG_801_Lares_GotoKalom_11_04","ORG_801_Lares_GotoKalom_11_05","ORG_801_Lares_GotoKalom_11_06","ORG_801_Lares_GotoKalom_11_07"],"lines":[{"speaker":"npc","text":{"pl":"Chcę, żebyś udał się do obozu na bagnie i trochę tam powęszył.","en":"Go to the Brotherhood''s camp and find out what''s going on.","de":"Geh zum Lager der Bruderschaft und finde heraus, was los ist."}},{"speaker":"npc","text":{"pl":"Wrócił Mordrag, jeden z naszych ludzi w Starym Obozie.","en":"Mordrag, one of our people in the Old Camp, has come back.","de":"Mordrag, einer unserer Leute aus dem Alten Lager, ist zurückgekehrt."}},{"speaker":"npc","text":{"pl":"Chcę, żebyś z nim porozmawiał. Powiedz mu, że potrzebuję wtyczki w obozie Sekty. Bractwo planuje coś dużego, a ja chcę wiedzieć, co się tam dzieje.","en":"Go to see him. Tell him I want somebody in that Sect Camp. The Brotherhood is planning something big - I want to know exactly what''s going on.","de":"Geh zu ihm. Sag ihm, ich will jemanden im Sektenlager haben. Die Bruderschaft plant irgendwas Großes - ich will genau wissen, was da abläuft."}},{"speaker":"npc","text":{"pl":"Masz mu pomóc.","en":"Help him.","de":"Hilf ihm bei der Sache."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_goto_kalom_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_goto_kalom_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_GotoKalom_Info","outputIds":["ORG_801_Lares_GotoKalom_15_00","ORG_801_Lares_GotoKalom_11_01","ORG_801_Lares_GotoKalom_11_02","ORG_801_Lares_GotoKalom_11_03"],"lines":[{"speaker":"hero","text":{"pl":"I co mam robić dalej?","en":"And what am I supposed to do now?","de":"Und was soll ich jetzt machen?"}},{"speaker":"npc","text":{"pl":"Należysz teraz do naszej bandy. Możesz robić, co ci się żywnie podoba.","en":"You''re now a member of our gang. You''re free to do what you want.","de":"Du bist jetzt ein Mitglied unserer Bande. Es steht dir frei zu tun, was du willst."}},{"speaker":"npc","text":{"pl":"Jeśli chcesz robić coś pożytecznego, pogadaj z Mordragiem i pomóż mu w sprawie Sekty.","en":"If you want to make yourself useful, go to Mordrag and help him with the sect business.","de":"Wenn du dich nützlich machen willst, geh zu Mordrag und unterstütz ihn bei der Sektensache."}},{"speaker":"npc","text":{"pl":"Zginął Mordrag, jeden z naszych ludzi w Starym Obozie. Przed śmiercią zdążył przysłać nam wiadomość. Wygląda na to, że w obozie Sekty dzieje się coś ważnego.","en":"Mordrag, one of our people in the Old Camp, has been killed. Before he died, he sent us a message. It said that something big''s going on in the Sect Camp.","de":"Mordrag, einer unserer Leute vom Alten Lager, wurde umgebracht. Bevor er starb, hat er uns die Nachricht übermittelt, dass im Lager der Sekte eine große Sache läuft."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_mordrag_sent_me_11_04_4', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_mordrag_sent_me_11_04_4","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_MordragSentMe_Info","outputIds":["ORG_801_Lares_MordragSentMe_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Powiedz mu, że potrzebuję kogoś w obozie na bagnie. Bractwo planuje coś dużego, a ja chcę wiedzieć, co się tam będzie działo.","en":"Tell him I want somebody in the Sect Camp. The Brotherhood is planning something big - I want to know exactly what''s going on there.","de":"Sag ihm, ich will jemanden im Sektenlager haben. Die Bruderschaft plant irgendwas Großes - ich will genau wissen, was da abläuft."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_mordrag_sent_me_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_mordrag_sent_me_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_MordragSentMe_Info","outputIds":["ORG_801_Lares_MordragSentMe_15_00","ORG_801_Lares_MordragSentMe_11_01","ORG_801_Lares_MordragSentMe_11_02","ORG_801_Lares_MordragSentMe_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Mordrag. Mam dla ciebie pierścień.","en":"Mordrag sent me. He gave me a ring for you.","de":"Mordrag schickt mich. Er hat mir einen Ring für dich gegeben."}},{"speaker":"npc","text":{"pl":"Cenna błyskotka. To taki zwyczaj - część łupu oddaje się szefowi bandy.","en":"A precious piece! It''s part of normal procedure here to share your booty with your gang leader.","de":"Ein wertvolles Stück! Es ist bei uns üblich, einen Teil der Beute mit dem Anführer zu teilen."}},{"speaker":"npc","text":{"pl":"Ale skoro powierzył ci ten pierścień, musi mieć o tobie wysokie mniemanie.","en":"But the fact that he gave YOU the ring proves that he must think a lot of you.","de":"Aber dass er DIR den Ring gegeben hat, zeigt, dass er einiges von dir hält."}},{"speaker":"npc","text":{"pl":"Chcę, żebyś poszedł do niego i przekazał mu wiadomość ode mnie.","en":"I want you to go to him and tell him something from me.","de":"Ich will, dass du zu ihm gehst und ihm etwas ausrichtest."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_reicht_11_03_4', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_reicht_11_03_4","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_Reicht_Info","outputIds":["ORG_801_Lares_Reicht_11_03","ORG_801_Lares_Reicht_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Stałeś się bardzo popularny, odkąd przyniosłeś nam tę listę.","en":"You''ve become quite popular since you brought the list here.","de":"Die Liste hier hinzubringen, hat dir einiges Ansehen gebracht."}},{"speaker":"npc","text":{"pl":"Ale nie jesteś gotowy. Popracuj nad sobą jeszcze trochę.","en":"But you''re not ready yet. Do your tasks.","de":"Aber du bist noch nicht bereit. Erledige deine Aufgaben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_reicht_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_reicht_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_Reicht_Info","outputIds":["ORG_801_Lares_Reicht_15_00","ORG_801_Lares_Reicht_AUFNAHME_11_00","ORG_801_Lares_Reicht_AUFNAHME_11_01","ORG_801_Lares_Reicht_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Czy to wystarczy, byście mnie przyjęli?","en":"Is that enough for me to join you?","de":"Reicht das, um bei euch aufgenommen zu werden?"}},{"speaker":"npc","text":{"pl":"Myślę, że tak!","en":"I should say so!","de":"Das will ich meinen!"}},{"speaker":"npc","text":{"pl":"I mam dla ciebie mały prezent! Lepszy pancerz. Może nie jest to szczyt marzeń, ale zasłużyłeś na niego.","en":"And I''ve even got a present for you. A better armor. It''s not much, but you''ve earned it.","de":"Und ich habe sogar ein Geschenk für dich. Eine bessere Rüstung. Nicht viel, aber du hast sie dir verdient."}},{"speaker":"npc","text":{"pl":"Mordrag opowiedział się za tobą.","en":"Mordrag has spoken up for you.","de":"Mordrag hat sich für dich eingesetzt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_vorbeigemogelt_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_vorbeigemogelt_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_Vorbeigemogelt_Info","outputIds":["ORG_801_Lares_Vorbeigemogelt_15_00","ORG_801_Lares_Vorbeigemogelt_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Udało mi się ominąć twoje straże.","en":"I did manage to get past your guards.","de":"Ich bin immerhin an deinen Wachen vorbeigekommen."}},{"speaker":"npc","text":{"pl":"Fakt. Ale to jeszcze za mało.","en":"That''s right. But that alone won''t be enough.","de":"Das ist richtig. Aber das alleine wird noch nicht reichen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_wanna_join_15_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_wanna_join_15_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_WannaJoin_Info","outputIds":["ORG_801_Lares_WannaJoin_15_00","ORG_801_Lares_WannaJoin_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Chcę do was dołączyć.","en":"I want to join your gang.","de":"Ich will mich eurer Bande anschließen."}},{"speaker":"npc","text":{"pl":"Tak? A co takiego możesz nam zaoferować?","en":"Oh yeah? What have you got to show for yourself then?","de":"So? Was hast du denn vorzuweisen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_801_lares_org_801_lares_you_here_11_00_0', 'ORG_801_Lares', '{"id":"missions_dia_org_801_lares_org_801_lares_you_here_11_00_0","npcId":"ORG_801_Lares","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_801_Lares.d","sourceFunction":"ORG_801_Lares_YouHere_Info","outputIds":["ORG_801_Lares_YouHere_11_00","ORG_801_Lares_YouHere_15_01","ORG_801_Lares_YouHere_11_02"],"lines":[{"speaker":"npc","text":{"pl":"Jak się tu dostałeś? Co się dzieje z Roscoe?","en":"How did you get in here? What''s up with Roscoe?","de":"Wie kommst du hier rein? Was ist mit Roscoe?"}},{"speaker":"hero","text":{"pl":"Wolał nie próbować mnie powstrzymywać!","en":"He didn''t feel like stopping me.","de":"Er hatte keine Lust, mich aufzuhalten."}},{"speaker":"npc","text":{"pl":"Czego chcesz?","en":"What do you want?","de":"Was willst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_more_locations_07_04_4', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_more_locations_07_04_4","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_MoreLocations_Info","outputIds":["Org_818_Ratford_MoreLocations_07_04","Org_818_Ratford_MoreLocations_07_05"],"lines":[{"speaker":"npc","text":{"pl":"Często kręcą się tam Orkowie albo jeszcze gorsze poczwary. Na twoim miejscu unikałbym takich miejsc jak ognia. Zwłaszcza nocą.","en":"There are often Orcs in those ruins - or even worse creatures. I''d avoid those places, especially at night.","de":"In diesen Ruinen treiben sich oft Orks herum - oder Schlimmeres. Vor allem nachts würde ich diese Plätze meiden."}},{"speaker":"npc","text":{"pl":"I jeszcze jedna rada - nie wchodź do lasu!","en":"And one more hint - don''t go into the forest!","de":"Und wenn du noch einen letzten Tipp willst - geh nicht in den Wald!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_more_locations_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_more_locations_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_MoreLocations_Info","outputIds":["Org_818_Ratford_MoreLocations_15_00","Org_818_Ratford_MoreLocations_07_01","Org_818_Ratford_MoreLocations_07_02","Org_818_Ratford_MoreLocations_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi jeszcze o kolonii.","en":"Tell me more about the areas of the colony.","de":"Erzähl mir mehr über die Gebiete der Kolonie."}},{"speaker":"npc","text":{"pl":"Jeśli zamierzasz podróżować między obozami, przyda ci się mapa z wszystkimi ścieżkami i ślepymi zaułkami.","en":"If you travel between the camps, you''ll need a map to distinguish paths and dead ends.","de":"Wenn du zwischen den Lagern reist, solltest du eine Karte haben. So kannst du die Verbindungswege von den Sackgassen unterscheiden."}},{"speaker":"npc","text":{"pl":"Niektóre ścieżki prowadzą do niebezpiecznych kanionów, gdzie można wpaść na istoty, na które... lepiej nie wpadać.","en":"Dead ends often lead you to dangerous canyons where you encounter creatures you''d better avoid.","de":"Die Sackgassen führen dich oft in gefährliche Schluchten, in denen du Kreaturen begegnen wirst, denen du am Anfang besser aus dem Weg gehst."}},{"speaker":"npc","text":{"pl":"Pod żadnym pozorem nie włócz się w pobliżu starych ruin. Większość z nich pamięta jeszcze pierwszą wojnę z Orkami. Niektóre są nawet pozostałościami po ich osiedlach.","en":"Do not enter the old ruins. There are many around here. Most of them are old fortifications dating back to the time of the first Orc war. Some are abandoned Orc dwellings.","de":"Meide alte Ruinen, die Gegend hier ist voll davon. Die meisten sind alte Befestigungen aus dem ersten Ork-Krieg oder verlassene Ork-Behausungen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_thanks_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_thanks_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_Thanks_Info","outputIds":["Org_818_Ratford_Thanks_15_00","Org_818_Ratford_Thanks_07_01","Org_818_Ratford_Thanks_07_02","Org_818_Ratford_Thanks_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Dzięki za pomoc.","en":"Thanks for your help.","de":"Danke für die Hilfe."}},{"speaker":"npc","text":{"pl":"Tylko nie myśl, że wszyscy tutaj są tacy mili!","en":"Don''t go thinking everyone''s going to be so friendly, kid!","de":"Glaub bloß nicht, dass hier alle so nett zu dir sind, Kleiner!"}},{"speaker":"npc","text":{"pl":"Niewiele można znaleźć w kieszeniach Nowego, ale w kolonii są ludzie, którzy rozłupaliby ci czaszkę za stary kilof.","en":"There may not be much in a newcomer''s pockets, but some folks would even beat you up for a pickaxe.","de":"Ist zwar nicht viel zu holen bei einem Neuen, aber einige hier würden dir sogar für eine alte Spitzhacke die Seele aus dem Leib prügeln."}},{"speaker":"hero","text":{"pl":"Będę o tym pamiętał.","en":"I''ll keep it in mind.","de":"Werd''s mir merken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_what_game_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_what_game_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_WhatGame_Info","outputIds":["Org_818_Ratford_WhatGame_15_00","Org_818_Ratford_WhatGame_07_01","Org_818_Ratford_WhatGame_15_02","Org_818_Ratford_WhatGame_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Na co polujecie?","en":"What do you hunt?","de":"Was jagt ihr denn so?"}},{"speaker":"npc","text":{"pl":"Głównie na ścierwojady. Da się je zjeść, no i nietrudno je zabić... Jeśli wie się jak to zrobić.","en":"Mostly scavengers. There''s a lot of meat on them. Besides, it isn''t too hard to get them... Once you know how.","de":"Meistens Scavenger. Sie geben ''ne Menge Fleisch ab. Außerdem sind sie nicht so schwer zur Strecke zu bringen - wenn man weiß, wie."}},{"speaker":"hero","text":{"pl":"Naprawdę? Macie jakąś specjalną metodę?","en":"Really? How''s that?","de":"So? Und wie?"}},{"speaker":"npc","text":{"pl":"Zapytaj mojego kumpla, Draxa. Nikt nie wie więcej o ścierwojadach niż on.","en":"Ask my friend Drax here - he knows more about these things than anyone.","de":"Frag meinen Freund Drax hier - der weiß über solche Sachen besser Bescheid als ich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_why_dangerous_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_why_dangerous_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_WhyDangerous_Info","outputIds":["Org_818_Ratford_WhyDangerous_15_00","Org_818_Ratford_WhyDangerous_07_01","Org_818_Ratford_WhyDangerous_07_02","Org_818_Ratford_WhyDangerous_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego ten teren jest tak niebezpieczny?","en":"Why''s this area so dangerous?","de":"Was ist an diesem Gebiet so gefährlich?"}},{"speaker":"npc","text":{"pl":"Jesteś tu nowy, co? W całej kolonii jest mnóstwo mniej lub bardziej niebezpiecznych miejsc.","en":"You''ve just arrived, haven''t you? There are different areas in the colony which are all more or less dangerous.","de":"Du bist gerade angekommen, was? In der Kolonie gibt es unterschiedlich gefährliche Gebiete."}},{"speaker":"npc","text":{"pl":"Ścieżki pomiędzy obozami są dość bezpieczne, ale nawet tam można natknąć się na stado wilków, które będą chciały zjeść cię na kolację.","en":"The paths between the camps are quite safe. But even there you might come across some wolves which will look on you as easy prey.","de":"Auf den Wegen zwischen den Lagern ist es einigermaßen sicher. Aber auch dort kannst du ein paar Wölfen begegnen, die dich als leichte Beute sehen werden."}},{"speaker":"npc","text":{"pl":"Dlatego lepiej nie ruszać się nigdzie bez odpowiedniego oręża i zbroi.","en":"And that''s exactly what you are until you get a proper weapon and armor.","de":"Und genau das bist du auch, bis du geeignete Waffen und Rüstung hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_wo_equipment_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_wo_equipment_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_WoEquipment_Info","outputIds":["Org_818_Ratford_WoEquipment_15_00","Org_818_Ratford_WoEquipment_07_01","Org_818_Ratford_WoEquipment_07_02","Org_818_Ratford_WoEquipment_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Skąd mogę wziąć lepsze wyposażenie?","en":"Where can I get better equipment?","de":"Wo kriege ich bessere Ausrüstung her?"}},{"speaker":"npc","text":{"pl":"Najbliżej będzie pewnie Stary Obóz. Idź dalej tą samą ścieżką, na pewno trafisz.","en":"The nearest place is the Old Camp. Just follow the path that brought you here.","de":"Der nächste Ort ist das Alte Lager. Du musst nur dem Weg folgen, den du gekommen bist."}},{"speaker":"npc","text":{"pl":"Ale lepsze ceny znajdziesz u nas - w Nowym Obozie. Oczywiście pod warunkiem, że znasz właściwych ludzi.","en":"But you can get the stuff cheaper in our New Camp - provided you know the right people.","de":"Aber bei uns im Neuen Lager bekommst du die Sachen billiger - wenn du die richtigen Leute kennst."}},{"speaker":"npc","text":{"pl":"Kiedy trafisz do Starego Obozu, poszukaj mężczyzny imieniem Mordrag. To jeden z naszych. Za kilka bryłek rudy można u niego kupić wiele wartościowych rzeczy.","en":"If you go to the Old Camp, ask for Mordrag. He''s one of us. For just a little ore, he''ll sell you the proper goods.","de":"Wenn du ins alte Lager gehst, frag nach Mordrag. Er ist einer von uns. Er verkauft gute Ware für wenig Erz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_wo_karte_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_wo_karte_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_WoKarte_Info","outputIds":["Org_818_Ratford_WoKarte_15_00","Org_818_Ratford_WoKarte_07_01","Org_818_Ratford_WoKarte_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę zdobyć jakąś mapę?","en":"Where do I get a map?","de":"Wo kriege ich eine Karte her?"}},{"speaker":"npc","text":{"pl":"Popytaj ludzi w Starym Obozie. Mieszka tam jeden kartograf.","en":"Ask the people in the Old Camp. There''s a cartographer living there.","de":"Frag im Alten Lager herum, ich glaube, da gibt es einen Kartenzeichner."}},{"speaker":"npc","text":{"pl":"Może uda ci się gwizdnąć mu jakąś mapę. Przy okazji mógłbyś zwinąć także jedną dla mnie!","en":"Maybe you can steal one of his maps! If you manage to do it, take one for me as well!","de":"Vielleicht kannst du ihm ja eine seiner Karten klauen! Wenn du''s schaffst, bring mir eine mit!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_wo_karte_kaufen_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_wo_karte_kaufen_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_WoKarte_Kaufen","outputIds":["Org_818_Ratford_WoKarte_Kaufen_15_00","Org_818_Ratford_WoKarte_Kaufen_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego? Jego mapy nie są na sprzedaż?","en":"Why? Doesn''t he sell the maps?","de":"Wieso? - Verkauft er die Karten nicht?"}},{"speaker":"npc","text":{"pl":"Jeśli stać cię na tak ogromny wydatek...","en":"If you get enough ore to pay for them...","de":"Wenn du an genug Erz rankommst, um sie zu bezahlen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_wo_karte_stehlen_15_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_wo_karte_stehlen_15_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_WoKarte_Stehlen","outputIds":["Org_818_Ratford_WoKarte_Stehlen_15_00","Org_818_Ratford_WoKarte_Stehlen_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Jeśli uda mi się zdobyć je bez płacenia, wezmę ile tylko dam radę udźwignąć!","en":"If I manage to get them without paying, I''ll take as many as I can carry!","de":"Wenn ich rankomme, ohne zu bezahlen, bringe ich mit, so viel ich tragen kann!"}},{"speaker":"npc","text":{"pl":"Równy z ciebie gość! Powinieneś pomyśleć o dołączeniu do Nowego Obozu. Gdybyś kiedyś tam trafił, pytaj o Laresa. To on zajmuje się nowymi. Na pewno znajdzie dla ciebie jakieś zajęcie!","en":"You''re alright! You should consider coming to the New Camp! In case you go there, ask for Lares. He takes care of the new ones. I''m sure he''ll have a job for you!","de":"Du gefällst mir! Du solltest dir überlegen, zu uns ins Neue Lager zu kommen! Wenn du mal da bist, frag nach Lares. Er kümmert sich um die Neuen. Er hat bestimmt was zu tun für dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_818_ratford_org_818_ratford_wrong_way_07_00_0', 'ORG_818_Ratford', '{"id":"missions_dia_org_818_ratford_org_818_ratford_wrong_way_07_00_0","npcId":"ORG_818_Ratford","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_818_Ratford.d","sourceFunction":"Org_818_Ratford_WrongWay_Info","outputIds":["Org_818_Ratford_WrongWay_07_00","Org_818_Ratford_WrongWay_15_01","Org_818_Ratford_WrongWay_07_02"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey, du!"}},{"speaker":"hero","text":{"pl":"Czego chcesz?","en":"What do you want?","de":"Was willst du?"}},{"speaker":"npc","text":{"pl":"Chcę cię ostrzec. Idąc dalej wejdziesz na nasze tereny łowieckie.","en":"I want to warn you. If you continue this way, you''ll be entering our hunting ground.","de":"Dich warnen. Wenn du hier weiter gehst, kommst du in unser Jagdgebiet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Info","outputIds":["Org_819_Drax_Creatures_15_00","Org_819_Drax_Creatures_06_01","Org_819_Drax_Creatures_06_02","Org_819_Drax_Creatures_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Czego jeszcze możesz mnie nauczyć?","en":"What else can you tell me about hunting?","de":"Was kannst du mir noch über die Jagd beibringen?"}},{"speaker":"npc","text":{"pl":"Wielu rzeczy, ale głupie piwo nie wystarczy.","en":"A lot - but it''ll cost you more than a beer.","de":"''Ne ganze Menge - aber das wird dich mehr kosten als nur ein Bier."}},{"speaker":"npc","text":{"pl":"Wprawny łowca potrafi zdobyć kły, pazury i skórę zwierzyny. Nie jest to łatwe, ale dość opłacalne.","en":"If you know how, you can take the creatures'' teeth, claws and skin. It''s hard to get them but they are valuable.","de":"Wenn du weißt wie, kannst du den Viechern Zähne, Haut oder Krallen abziehen. An die Sachen ist schwer ranzukommen, also sind sie wertvoll."}},{"speaker":"npc","text":{"pl":"W każdym razie każdy kupiec chętnie je od ciebie odkupi.","en":"At least every merchant will trade those things with you.","de":"Zumindest wird jeder Händler diese Dinge mit dir tauschen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_fell_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_fell_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Fell","outputIds":["Org_819_Drax_Creatures_Fell_15_00","Org_819_Drax_Creatures_Fell_06_01","Org_819_Drax_Creatures_Fell_06_02","Org_819_Drax_Creatures_KEINE_LP_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę zdobyć skóry upolowanej zwierzyny?","en":"How can I skin these creatures?","de":"Wie kann ich den Viechern das Fell abziehen?"}},{"speaker":"npc","text":{"pl":"Zaczynaj skórowanie od zadu, przesuwając się stopniowo ku głowie. Spróbuj kilka razy. To nie jest takie trudne, a futra potrafią być bardzo cenne!","en":"It''s very important to skin them from the back to the front. Once you get the hang of it, it''ll be easy. Furs are very valuable!","de":"Wichtig ist vor allem: Immer von vorne nach hinten. Wenn du den Bogen einmal raushast, ist es kein Problem. Felle sind sehr wertvoll!"}},{"speaker":"npc","text":{"pl":"Futra wilków i cieniostworów można wykorzystać do szycia odzieży. Badając futro zabitego zwierza łatwo ocenisz, czy nadaje się do dalszego wykorzystania.","en":"The furs of wolves and shadowbeasts can be used to make clothes. When you examine the fur of a killed animal, you''ll soon notice if it can be used or not.","de":"Das Fell von Wölfen oder Schattenläufern eignet sich zum Herstellen von Kleidung. Du wirst merken, ob ein erlegtes Tier ein brauchbares Fell hat, wenn du es untersuchst."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You need more experience, otherwise my knowledge won''t be of any use to you.","de":"Du mußt mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_haut_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_haut_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Haut","outputIds":["Org_819_Drax_Creatures_Haut_15_00","Org_819_Drax_Creatures_Haut_06_01","Org_819_Drax_Creatures_Haut_06_02","Org_819_Drax_Creatures_KEINE_LP_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Na co powinienem zwracać uwagę zdzierając skórę z gadów?","en":"What do I have to observe while skinning reptiles?","de":"Worauf muss ich beim Häuten von Reptilien achten?"}},{"speaker":"npc","text":{"pl":"Skóry topielców i bagiennych węży są szczególnie cenne.","en":"The only reptiles suited for this purpose are lurkers and swampsharks.","de":"Die einzigen Reptilien, die dafür geeignet sind, sind der Lurker und der Sumpfhai."}},{"speaker":"npc","text":{"pl":"Jeśli przetniesz skórę na bokach, powinna sama odejść od mięsa. Myślę, że od tej pory poradzisz już sobie ze skórowaniem gadów.","en":"If you slit the skin at the sides, it''ll peel off by itself. From now on you should be able to skin reptiles.","de":"Wenn du die Haut an den Seiten anschneidest, löst sie sich wie von selbst. Du solltest ab jetzt kein Problem mehr haben, Echsen zu häuten."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You need more experience, otherwise my knowledge won''t be of any use to you.","de":"Du mußt mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_00_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_00_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Zahn","outputIds":["Org_819_Drax_Creatures_KEIN_ERZ_06_00"],"lines":[{"speaker":"npc","text":{"pl":"Najpierw chcę zobaczyć trochę rudy. W tej kolonii nic nie ma za darmo!","en":"I want to see some ore first. Like I said: Everything has its price!","de":"Erst will ich mein Erz sehen - wie gesagt: Es hat alles seinen Preis!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_01_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_01_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Fell","outputIds":["Org_819_Drax_Creatures_KEIN_ERZ_06_01"],"lines":[{"speaker":"npc","text":{"pl":"Najpierw chcę zobaczyć trochę rudy. W tej kolonii nic nie ma za darmo!","en":"I want to see some ore first. Like I said: Everything has its price!","de":"Erst will ich mein Erz sehen - wie gesagt: Es hat alles seinen Preis!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_02_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_02_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Kralle","outputIds":["Org_819_Drax_Creatures_KEIN_ERZ_06_02"],"lines":[{"speaker":"npc","text":{"pl":"Najpierw chcę zobaczyć trochę rudy. W tej kolonii nic nie ma za darmo!","en":"I want to see some ore first. Like I said: Everything has its price!","de":"Erst will ich mein Erz sehen - wie gesagt: Es hat alles seinen Preis!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_03_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_kein_erz_06_03_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Haut","outputIds":["Org_819_Drax_Creatures_KEIN_ERZ_06_03"],"lines":[{"speaker":"npc","text":{"pl":"Najpierw chcę zobaczyć trochę rudy. W tej kolonii nic nie ma za darmo!","en":"I want to see some ore first. Like I said: Everything has its price!","de":"Erst will ich mein Erz sehen - wie gesagt: Alles hat seinen Preis!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_kralle_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_kralle_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Kralle","outputIds":["Org_819_Drax_Creatures_Kralle_15_00","Org_819_Drax_Creatures_Kralle_06_01","Org_819_Drax_Creatures_Kralle_06_02","Org_819_Drax_Creatures_KEINE_LP_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Pokaż mi jak zdobyć pazury upolowanej zwierzyny.","en":"Show me how to take off the claws!","de":"Bring mir bei, Krallen abzuziehen!"}},{"speaker":"npc","text":{"pl":"Prawdę mówiąc to dziecinnie proste, trzeba tylko znać odpowiednią metodę. Wygnij pazury do przodu - nigdy do tyłu! I pod żadnym pozorem nie próbuj ich wyciągać!","en":"Actually it''s quite simple if you know what to do. Bend the claws forward - never backwards - and you MUSTN''T pull them out either!","de":"Ist im Grunde ganz einfach, wenn du weißt, wie''s geht. Du mußt die Krallen nach vorne wegknicken, auf keinen Fall nach hinten und NICHT ziehen!"}},{"speaker":"npc","text":{"pl":"Najlepiej pozyskiwać pazury jaszczurów. Od tej pory będziesz wiedział, które zwierzęta dostarczają dobrych pazurów.","en":"Claws can be taken especially from lizards. From now on, you''ll know which creature''s claws to take.","de":"Krallen kannst du vor allem von Echsen nehmen. Du wirst ab jetzt erkennen, von welchem erlegten Biest du die Krallen nehmen kannst."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You need more experience, otherwise my knowledge won''t be of any use to you.","de":"Du mußt mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_pretty_much_06_04_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_pretty_much_06_04_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_PrettyMuch","outputIds":["Org_819_Drax_Creatures_PrettyMuch_06_04"],"lines":[{"speaker":"npc","text":{"pl":"Na twoim miejscu spróbowałbym możliwie szybko posiąść te umiejętności.","en":"If I were you, I''d try to gain this knowledge as soon as possible.","de":"Wenn ich du wäre, würde ich mir dieses Wissen so schnell wie möglich aneignen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_pretty_much_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_pretty_much_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_PrettyMuch","outputIds":["Org_819_Drax_Creatures_PrettyMuch_15_00","Org_819_Drax_Creatures_PrettyMuch_06_01","Org_819_Drax_Creatures_PrettyMuch_06_02","Org_819_Drax_Creatures_PrettyMuch_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Dużo żądasz za swoje usługi.","en":"You''re demanding a lot for your advice.","de":"Du verlangst verdammt viel für dein Wissen."}},{"speaker":"npc","text":{"pl":"Być może, ale wiedza, którą mogę ci przekazać pozwoli ci szybko odzyskać zainwestowaną kwotę.","en":"Possibly, but you can earn a lot of ore with this knowledge.","de":"Mag sein, aber du kannst ''ne Menge Erz damit verdienen."}},{"speaker":"npc","text":{"pl":"Wszystkie zwierzęta, które zabijesz nie wiedząc jak je oprawić, po prostu zgniją.","en":"All the animals you kill without knowing how to cut them up will just rot away.","de":"Alle Tiere, die du tötest, ohne zu wissen, wie man sie vernünftig ausschlachtet, werden einfach verwesen."}},{"speaker":"npc","text":{"pl":"A to najzwyklejsze marnotrawstwo. Za ich skórę mógłbyś zarobić sporo pieniędzy.","en":"That''s a wasted opportunity of skinning them and selling the fur at a high price.","de":"Das ist eine verschwendete Gelegenheit, ihnen das Fell abzuziehen und teuer zu verkaufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_taught_all_06_00_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_taught_all_06_00_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Info","outputIds":["Org_819_Drax_Creatures_TaughtAll_06_00"],"lines":[{"speaker":"npc","text":{"pl":"Powiedziałem ci już wszystko co wiem.","en":"I''ve told you everything I know.","de":"Ich habe dir alles beigebracht, was ich weiß."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_creatures_zahn_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_creatures_zahn_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Creatures_Zahn","outputIds":["Org_819_Drax_Creatures_Zahn_15_00","Org_819_Drax_Creatures_Zahn_06_01","Org_819_Drax_Creatures_Zahn_06_02","Org_819_Drax_Creatures_KEINE_LP_06_00"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę zdobyć kły upolowanej zwierzyny?","en":"How do I get the teeth?","de":"Wie komme ich an die Zähne?"}},{"speaker":"npc","text":{"pl":"Przede wszystkim musisz uważać, żeby kły nie popękały podczas wyciągania. W tym celu wbij nóż w pobliżu środka zęba i delikatnie go podważaj.","en":"The most important thing is to make sure the teeth don''t splinter. To avoid that, put your knife near the center of the tooth and lever it out carefully.","de":"Du mußt vor allem darauf achten, dass die Zähne nicht splittern. Um das zu verhindern, mußt du dein Messer in der Mitte des Zahns ansetzen und vorsichtig hebeln."}},{"speaker":"npc","text":{"pl":"Warto zabierać kły wilków, cieniostworów i zębaczy","en":"You can take the teeth of wolves, shadowbeasts and snappers.","de":"Zähne kannst du von Wölfen, Schattenläufern oder Snappern nehmen."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You have to gain more experience otherwise my knowledge won''t be of any use to you.","de":"Du mußt mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_hunt_here_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_hunt_here_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_HuntHere_Info","outputIds":["Org_819_Drax_HuntHere_15_00","Org_819_Drax_HuntHere_06_01","Org_819_Drax_HuntHere_15_02","Org_819_Drax_HuntHere_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Widzę, że jesteś myśliwym.","en":"You''re hunting, aren''t you?","de":"Ihr jagt hier - richtig?"}},{"speaker":"npc","text":{"pl":"Na to wygląda... Czego chcesz?","en":"Looks like it... what do you want?","de":"Sieht so aus... was willst du?"}},{"speaker":"hero","text":{"pl":"Mógłbyś nauczyć mnie polować?","en":"Do you have some hints for the hunt?","de":"Hast du ein paar Tipps für die Jagd?"}},{"speaker":"npc","text":{"pl":"Parę sztuczek mógłbym ci pokazać, ale to będzie kosztować.","en":"I could teach you a few things - but everything has its price.","de":"Ich könnte dir schon was beibringen - aber alles hat seinen Preis."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_hunt_here_15_04_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_hunt_here_15_04_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_HuntHere_Info","outputIds":["Org_819_Drax_HuntHere_15_04","Org_819_Drax_HuntHere_06_05"],"lines":[{"speaker":"hero","text":{"pl":"Ile dokładnie?","en":"Which would be how much?","de":"Und der wäre?"}},{"speaker":"npc","text":{"pl":"Na początek wystarczy łyk dobrego piwa, potem zobaczymy.","en":"A good gulp of beer will do to start with - then we''ll see.","de":"Für den Anfang reicht ein ordentlicher Schluck Bier - danach sehen wir weiter."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_scavenger_06_04_4', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_scavenger_06_04_4","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Scavenger_Info","outputIds":["Org_819_Drax_Scavenger_06_04","Org_819_Drax_Scavenger_KEIN_BIER_15_00","Org_819_Drax_Scavenger_KEIN_BIER_06_01","Org_819_Drax_Scavenger_KEIN_BIER_06_02"],"lines":[{"speaker":"npc","text":{"pl":"A jeśli ON dziobnie cię pierwszy... Cóż, lepiej, żeby nie dziobnął.","en":"If it hits YOU first - well - just don''t let them.","de":"Wenn es DICH zuerst trifft - nun ja - pass einfach auf, dass es dich nicht zuerst trifft."}},{"speaker":"hero","text":{"pl":"Nie mam piwa.","en":"I don''t have any beer.","de":"Ich hab'' kein Bier."}},{"speaker":"npc","text":{"pl":"To poszukaj! To najlepsza rada, jaką otrzymasz ode mnie za darmo. A skoro już będziesz szukał, znajdź dla mnie jeszcze parę bryłek rudy.","en":"Then go and fetch some. That''ll be the best free hint you''ll get in a long time. And as you''re going anyway, bring some ore with you as well!","de":"Dann geh und hol eins, so billig kommst du nie wieder an einen guten Rat. Und wenn du schon mal dabei bist - bring gleich noch etwas Erz mit!"}},{"speaker":"npc","text":{"pl":"Mogę ci wiele opowiedzieć o różnych zwierzakach, ale to cię będzie kosztowało.","en":"I can give you some information about animals, but it''ll cost you!","de":"Ich kann dir einiges über Tiere beibringen, aber das kostet dich was!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_819_drax_org_819_drax_scavenger_15_00_0', 'ORG_819_Drax', '{"id":"missions_dia_org_819_drax_org_819_drax_scavenger_15_00_0","npcId":"ORG_819_Drax","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_819_Drax.d","sourceFunction":"Org_819_Drax_Scavenger_Info","outputIds":["Org_819_Drax_Scavenger_15_00","Org_819_Drax_Scavenger_06_01","Org_819_Drax_Scavenger_06_02","Org_819_Drax_Scavenger_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Proszę, oto piwo. Teraz opowiedz mi o polowaniu.","en":"Here you are, take a beer and tell me about hunting.","de":"Hier, nimm ein Bier und erzähl mir was übers Jagen."}},{"speaker":"npc","text":{"pl":"Ścierwojady - tak nazywamy te wielkie ptaszyska - należy atakować jeden po drugim. Na szczęście łatwo odciągnąć jednego osobnika od reszty stada.","en":"Scavengers, that''s what we call the big birds, should be attacked one after the other. It''s easy to lure single scavengers from the pack.","de":"Scavenger, so nennen wir die großen Vögel, greift man am besten einzeln an. Du kannst einzelne Scavenger leicht aus dem Rudel locken."}},{"speaker":"npc","text":{"pl":"Jeśli podejdziesz do nich zbyt blisko, zaczną się denerwować, aż wreszcie rzucą się w twoją stronę. Lepiej, żebyś w tej chwili miał broń w pogotowiu.","en":"If you come too close, they''ll become irritated. After a while they''ll storm in your direction. At this point, you should be waiting for them with a raised weapon.","de":"Wenn du ihnen zu nahe kommst, reagieren sie gereizt. Nach einer Weile stürmen sie dann auf dich los. Du solltest zu diesem Zeitpunkt schon mit erhobener Waffe warten."}},{"speaker":"npc","text":{"pl":"Jeśli uda ci się trafić ścierwojada zanim on dziobnie ciebie, jak najszybciej wyprowadź kolejne uderzenie. Przy odrobinie szczęścia uda ci się go pokonać bez zadraśnięcia.","en":"If you manage to strike the beast before it hits you, you have to keep fighting, then you''ll be able to defeat the creature without being hurt yourself.","de":"Wenn du gut bist, und ihn triffst, bevor er dich trifft, heißt es dranbleiben, dann kannst du das Vieh besiegen, ohne einen Kratzer abzubekommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_info_mordrag_fight_get_away_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_info_mordrag_fight_get_away_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Info_Mordrag_Fight_GetAway","outputIds":["Info_Mordrag_Fight_GetAway_15_00","Info_Mordrag_Fight_GetAway_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Wynoś się stąd i nigdy nie wracaj!","en":"Just get out of this camp!","de":"Mach, dass du aus diesem Lager verschwindest!"}},{"speaker":"npc","text":{"pl":"Wielkie słowa małego człowieczka...","en":"Big words from a small man...","de":"Große Worte für einen kleinen Mann ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_info_mordrag_fight_ore_barons_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_info_mordrag_fight_ore_barons_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Info_Mordrag_Fight_OreBarons","outputIds":["Info_Mordrag_Fight_OreBarons_15_00","Info_Mordrag_Fight_OreBarons_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie tolerujemy tu ludzi, którzy okradają Magnatów!","en":"There ain''t no room for people who steal from the Ore Barons!","de":"Hier ist kein Platz für Leute, die die Erzbarone bestehlen!"}},{"speaker":"npc","text":{"pl":"Ach, więc o to ci chodzi! Dlaczego nie powiedziałeś tak od razu...","en":"Oh, that''s what you mean! Why didn''t you just say so...","de":"Ach, so ist das! Sag das doch gleich ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_info_mordrag_fight_thorus_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_info_mordrag_fight_thorus_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Info_Mordrag_Fight_Thorus","outputIds":["Info_Mordrag_Fight_Thorus_15_00","Info_Mordrag_Fight_Thorus_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Thorus. Mam się ciebie pozbyć raz na zawsze.","en":"Thorus sent me. He wants to get rid of you once and for all.","de":"Thorus schickt mich. Er will dich für immer loswerden."}},{"speaker":"npc","text":{"pl":"Thorus? Naprawdę? Cóż, to wszystko co chciałem wiedzieć...","en":"Really? Thorus? That''s all I wanted to know...","de":"So? Thorus also? Das war alles, was ich wissen wollte ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_at_newcamp_11_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_at_newcamp_11_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_AtNewcamp_Info","outputIds":["Org_826_Mordrag_AtNewcamp_11_00","Org_826_Mordrag_AtNewcamp_LATE_11_00","Org_826_Mordrag_AtNewcamp_11_01","Org_826_Mordrag_AtNewcamp_11_02"],"lines":[{"speaker":"npc","text":{"pl":"No to jesteśmy.","en":"Well, here we are.","de":"So, hier sind wir."}},{"speaker":"npc","text":{"pl":"Myślałem, że już tu nie dotrzesz! Zresztą nieważne - jesteśmy na miejscu!","en":"I thought you''d never arrive! Never mind - we''re here!","de":"Ich dachte schon, du kommst nie an! Egal - wir sind hier!"}},{"speaker":"npc","text":{"pl":"Za tą bramą rozciąga się Nowy Obóz. Porozmawiaj z Laresem, on ci pomoże. Daj mu ten cenny pierścień.","en":"When you pass through the gate, you''ll reach the New Camp. Talk to Lares. He''ll help you. Give this to him. It''s a precious ring.","de":"Wenn du durch das Tor gehst, kommst du ins Neue Lager. Sprich mit Lares. Er wird dir weiterhelfen. Hier - gib ihm das hier von mir. Es ist ein wertvoller Ring."}},{"speaker":"npc","text":{"pl":"To twoja przepustka do Laresa. Trzeba mieć nie lada powód, żeby się z nim spotkać.","en":"It''s your ticket to see Lares. You need a good reason to be allowed to meet him.","de":"Er ist deine Eintrittskarte zu Lares. Ohne guten Grund kommst du nicht zu ihm."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_at_newcamp_11_03_4', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_at_newcamp_11_03_4","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_AtNewcamp_Info","outputIds":["Org_826_Mordrag_AtNewcamp_11_03","Org_826_Mordrag_AtNewcamp_11_04","Org_826_Mordrag_AtNewcamp_15_05"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz co? Po zastanowieniu - chyba posiedzę tu parę dni. Zarobiłem już niezłą sumkę, a w Starym Obozie zaczyna robić się trochę za gorąco.","en":"Well, thinking about it, I think I''ll stay here for some time. I''ve earned enough for now, and things are heating up in the Old Camp.","de":"Wenn ich''s mir so recht überlege - ich glaub'', ich bleib'' ''ne Weile hier. Ich hab'' fürs Erste genug verdient und im Alten Lager wird''s langsam heiß."}},{"speaker":"npc","text":{"pl":"Jak byś czegoś potrzebował - znajdziesz mnie w karczmie na środku jeziora. Uważaj na siebie!","en":"If you want, come and meet me at the bar - it''s the hut out on the lake. Take care!","de":"Wenn du Lust hast, triff mich in der Kneipe - das Haus direkt auf dem See. Mach''s gut!"}},{"speaker":"hero","text":{"pl":"Do zobaczenia.","en":"See you.","de":"Wir sehen uns."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_courier_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_courier_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_Courier_Info","outputIds":["Org_826_Mordrag_Courier_15_00","Org_826_Mordrag_Courier_11_01","Org_826_Mordrag_Courier_15_02","Org_826_Mordrag_Courier_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Naprawdę jesteś kurierem Magów?","en":"Are you really the magicians'' courier?","de":"Stimmt es, dass du Kurier für die Magier bist?"}},{"speaker":"npc","text":{"pl":"A jeśli jestem?","en":"What if I am?","de":"Und wenn es so wäre?"}},{"speaker":"hero","text":{"pl":"Chciałbym porozmawiać z którymś z magów. Muszę dostać się do zamku.","en":"I''d like to have a chance to talk to the magicians. I have to get inside the castle.","de":"Ich würde gerne mal Gelegenheit haben, mit den Magiern zu reden. Ich muss in die Burg."}},{"speaker":"npc","text":{"pl":"Każdy kurier magów ma przy sobie magiczną pieczęć, dzięki której może wejść do zamku. Gdybyś był jednym z nas, mógłbyś taką zdobyć.","en":"The magicians'' couriers bear seals which allow them entry to the castle. If you were one of us, you could get such a seal...","de":"Die Kuriere der Magier haben ein Siegel, dass ihnen Zutritt zur Burg erlaubt. Wenn du einer von uns wärst, könntest du so ein Siegel bekommen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_fight_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_fight_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_Fight_Info","outputIds":["Org_826_Mordrag_Fight_15_00","Org_826_Mordrag_Fight_11_01"],"lines":[{"speaker":"hero","text":{"pl":"W tym obozie nie ma miejsca dla ludzi takich jak ty!","en":"There camp ain''t big enough for the both of us!","de":"In diesem Lager ist nicht genug Platz für uns beide!"}},{"speaker":"npc","text":{"pl":"Słucham?","en":"Pardon me?","de":"Bitte, was?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_GotoKalom_Info","outputIds":["Org_826_Mordrag_GotoKalom_15_00","Org_826_Mordrag_GotoKalom_11_01","Org_826_Mordrag_GotoKalom_15_02","Org_826_Mordrag_GotoKalom_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Lares ma dla ciebie wiadomość.","en":"Lares has a message for you.","de":"Lares hat eine Nachricht für dich."}},{"speaker":"npc","text":{"pl":"Czego chce?","en":"Tell me about it.","de":"Lass hören."}},{"speaker":"hero","text":{"pl":"Interesują go ostatnie wydarzenia w obozie Sekty. Mam ci przekazać, że to twoje zadanie.","en":"He wants to know what''s going on in the Sect Camp and he wants you to find out.","de":"Er will wissen, was im Lager der Sekte vorgeht. Er sagt, du sollst dich darum kümmern."}},{"speaker":"npc","text":{"pl":"Mam wrażenie, że ten problem sam się wkrótce rozwiąże...","en":"I get the feeling this problem will solve itself...","de":"Ich hab'' so ein Gefühl, als wenn sich die Sache von alleine erledigt ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_11_04_4', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_11_04_4","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_GotoKalomNOW_Info","outputIds":["Org_826_Mordrag_GotoKalomNOW_11_04","Org_826_Mordrag_GotoKalomNOW_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Wiem, że te świry z sekty przygotowują się do wielkiego przywołania, i choć sam nie wierzę w Śniącego powiem ci jedno:","en":"I know that those sect loonies are planning a big invocation. Me, I don''t believe in the Sleeper - but one thing''s for sure:","de":"Ich weiß, dass die Sektenspinner eine große Anrufung planen. Ich persönlich glaube ja nicht an den Schläfer - aber eins steht fest:"}},{"speaker":"npc","text":{"pl":"Guru dysponują potężną magią, dlatego tak uważnie musimy im patrzeć na palce. Nadążasz?","en":"The Gurus have powerful magic at their command. Therefore it''s better to know what''s going on. You with me so far?","de":"Die Gurus sind mit mächtiger Magie im Bunde. Und es ist besser, wenn wir wissen, was da abgeht. Soweit alles klar?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_GotoKalomNOW_Info","outputIds":["Org_826_Mordrag_GotoKalomNOW_15_00","Org_826_Mordrag_GotoKalomNOW_11_01","Org_826_Mordrag_GotoKalomNOW_15_02","Org_826_Mordrag_GotoKalomNOW_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Lares powiedział, że mam ci pomóc w tej sprawie.","en":"Lares told me to help you with this sect business.","de":"Lares sagt, ich soll dich bei der Sektensache unterstützen."}},{"speaker":"npc","text":{"pl":"Widzisz! Wiedziałem, że nie będę musiał sam się z tym męczyć!","en":"You see... I knew I wouldn''t have to take care of it myself.","de":"Siehst du ... Ich dachte mir, ich müsste mich nicht selbst drum kümmern."}},{"speaker":"hero","text":{"pl":"Chcesz żebym zajął się tym w pojedynkę?","en":"Do you want me to settle the affair all by myself?","de":"Soll ich die Sache ganz allein erledigen?"}},{"speaker":"npc","text":{"pl":"Na pewno jakoś sobie poradzisz. Słuchaj: musisz koniecznie wywęszyć, co się kryje za tą całą historią z przywołaniem.","en":"I''m sure you''ll make it. Listen: It''s important to find out the truth about this invocation story.","de":"Das schaffst du schon. Hör zu: Es geht darum, rauszufinden, was an dieser ganzen Beschwörungsklamotte dran ist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_do_it_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_do_it_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_GotoKalomNOW_DoIt","outputIds":["Org_826_Mordrag_GotoKalomNOW_DoIt_15_00","Org_826_Mordrag_GotoKalomNOW_DoIt_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Zobaczę co się da zrobić.","en":"I''ll see what I can do.","de":"Werd'' sehen, was ich rausfinden kann."}},{"speaker":"npc","text":{"pl":"Jak tylko dowiesz się czegoś o ich zamiarach, zgłoś się do mnie.","en":"As soon as you know about their plans, come back and report.","de":"Sobald du genau weißt, was sie im Schilde führen, melde dich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_precise_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_goto_kalom_now_precise_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_GotoKalomNOW_Precise","outputIds":["Org_826_Mordrag_GotoKalomNOW_Precise_15_00","Org_826_Mordrag_GotoKalomNOW_Precise_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie masz dla mnie żadnych dokładniejszych wskazówek?","en":"Could you give me more concrete instructions?","de":"Hast du genauere Anweisungen?"}},{"speaker":"npc","text":{"pl":"Porozmawiaj z Lesterem. Spędziłem kiedyś sporo czasu w obozie sekty, a on mi pomógł. Gość jest w porządku.","en":"Talk to Lester. I once spent a long time in the Sect Camp, and he helped me back then. He''s with the good guys.","de":"Rede mit Lester. Ich war mal ''ne Zeit lang im Sektenlager. Er hat mir damals geholfen. Er ist einer von den Guten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_goto_newcamp_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_goto_newcamp_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_GotoNewcamp_Info","outputIds":["Org_826_Mordrag_GotoNewcamp_15_00","Org_826_Mordrag_GotoNewcamp_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Chodźmy do Nowego Obozu!","en":"Let''s go to the New Camp!","de":"Lass uns zum Neuen Lager gehen!"}},{"speaker":"npc","text":{"pl":"Dobra! Chodź za mną!","en":"O.K.! Follow me.","de":"Gut! Folge mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_join_newcamp_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_join_newcamp_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_JoinNewcamp_Info","outputIds":["Org_826_Mordrag_JoinNewcamp_15_00","Org_826_Mordrag_JoinNewcamp_11_01","Org_826_Mordrag_JoinNewcamp_11_02"],"lines":[{"speaker":"hero","text":{"pl":"A gdybym chciał dołączyć do Nowego Obozu... mógłbyś mi pomóc?","en":"And if I wanted to join the New Camp... could you help me?","de":"Und wenn ich mich dem Neuen Lager anschließen wollte, könntest du mir dabei helfen ..."}},{"speaker":"npc","text":{"pl":"Jeśli myślisz o tym poważnie, możemy wyruszyć od razu. Zaprowadzę cię do Laresa. To szef naszej bandy.","en":"If you''re serious we can go now! I can take you to Lares. He''s the head of our gang.","de":"Wenn du''s wirklich ernst meinst, können wir direkt losgehen. Ich kann dich zu Lares bringen. Er ist der Kopf unserer Bande."}},{"speaker":"npc","text":{"pl":"Ale gdybyś chciał wyrzucić mnie z Obozu siłą - możesz spróbować.","en":"But if you prefer to beat me out of the Camp... Well, go for it!","de":"Aber wenn du lieber versuchen willst, mich aus dem Lager zu prügeln - bitte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_ncinfo_11_04_4', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_ncinfo_11_04_4","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_NCInfo_Info","outputIds":["Org_826_Mordrag_NCInfo_11_04","Org_826_Mordrag_NCInfo_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Nasi magowie opracowują plan ucieczki z kolonii. Zbieranie rudy jest częścią tego planu.","en":"Our magicians are working on a plan to break out of here. All the ore is collected for this plan.","de":"Unsere Magier arbeiten an einem Ausbruchsplan. Dafür wird alles Erz gesammelt."}},{"speaker":"npc","text":{"pl":"Gomez i jego ludzie pławią się w luksusie, a my ciężko pracujemy, żeby się stąd wydostać. Tak to wygląda!","en":"While Gomez and his people are lazing around, we drudge for freedom - that''s what''s going on.","de":"Während Gomez und seine Leute auf der faulen Haut liegen, rackern wir uns für die Freiheit ab - so sieht''s aus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_ncinfo_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_ncinfo_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_NCInfo_Info","outputIds":["Org_826_Mordrag_NCInfo_15_00","Org_826_Mordrag_NCInfo_11_01","Org_826_Mordrag_NCInfo_11_02","Org_826_Mordrag_NCInfo_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi o Nowym Obozie.","en":"Tell me more about the New Camp.","de":"Erzähl mir was über das Neue Lager."}},{"speaker":"npc","text":{"pl":"Tylko tam znajdziesz prawdziwą wolność... jak na kolonię karną, oczywiście. Nie ma tam żadnych Magnatów ani Guru, którzy mogliby tobą pomiatać.","en":"It''s the camp where you have the most freedom within the colony. We don''t have any Ore Barons or Gurus bossing us around.","de":"Es ist das freieste Lager in der Kolonie. Wir haben keine Erzbarone oder Gurus, die uns herumkommandieren."}},{"speaker":"npc","text":{"pl":"Mamy własną kopalnię, ale nie sprzedajemy ani grama rudy temu zramolałemu królowi!","en":"We have our own mine. But the ore that is produced there isn''t given to the damned king!","de":"Wir haben eine eigene Mine. Aber das Erz, das wir dort fördern, wird nicht an den verdammten König geliefert!"}},{"speaker":"hero","text":{"pl":"Więc do czego ją wykorzystujecie?","en":"So what is it used for?","de":"Sondern?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_problem_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_problem_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_Problem_Info","outputIds":["Org_826_Mordrag_Problem_15_00","Org_826_Mordrag_Problem_11_01","Org_826_Mordrag_Problem_15_02","Org_826_Mordrag_Problem_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Masz problem.","en":"You have a problem.","de":"Du hast ein Problem."}},{"speaker":"npc","text":{"pl":"Czyżby? A jaki?","en":"Really? What''s that?","de":"Ach? Und das wäre?"}},{"speaker":"hero","text":{"pl":"Są w tym obozie osoby, które mają cię już serdecznie dosyć.","en":"There are people around here who want to get rid of you.","de":"Es gibt Leute hier, die wollen, dass du dich hier nie wieder blicken lässt."}},{"speaker":"npc","text":{"pl":"Tak? To powiedz im, żeby przysłały tutaj kogoś, kto spróbuje mnie stąd przepędzić!","en":"Really? Then you can tell them they should send someone along to enforce their wish.","de":"So? Dann sag doch den Leuten, sie sollen jemanden schicken, der ihren Willen auch durchsetzt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_problem_15_04_4', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_problem_15_04_4","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_Problem_Info","outputIds":["Org_826_Mordrag_Problem_15_04","Org_826_Mordrag_Problem_11_05","Org_826_Mordrag_Problem_11_06"],"lines":[{"speaker":"hero","text":{"pl":"Skąd pewność, że nie przysłały właśnie mnie?","en":"What makes you so sure I''m not the one to do it?","de":"Wie kommst du darauf, dass ich das nicht tue?"}},{"speaker":"npc","text":{"pl":"Bo myślę, że jesteś na to zbyt mądry. Wkrótce przekonasz się, że są w tej kolonii ciekawsze rzeczy do roboty niż usługiwanie Gomezowi.","en":"Cos I think you''re smarter than that, boy. You''ll soon realize that there are better opportunities than working for Gomez.","de":"Weil ich denke, dass du ein schlauer Junge bist. Du wirst schnell erkennen, dass es Besseres gibt, als für Gomez zu arbeiten."}},{"speaker":"npc","text":{"pl":"Nowy Obóz potrzebuje zdolnych ludzi. Tam przynajmniej nikt nam nie mówi co mamy robić.","en":"We too need capable people in the New Camp, and nobody tells you what to do.","de":"Bei uns im Neuen Lager können wir fähige Leute genauso gut brauchen, und dort gibt es niemanden, der dir sagt, was du zu tun und zu lassen hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_running_15_00_0', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_running_15_00_0","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_RUNNING_Info","outputIds":["Org_826_Mordrag_RUNNING_15_00","Org_826_Mordrag_RUNNING_11_01","Org_826_Mordrag_RUNNING_15_04","Org_826_Mordrag_RUNNING_11_09"],"lines":[{"speaker":"hero","text":{"pl":"Jeśli chodzi o tę sprawę z sektą...","en":"About that sect business...","de":"Wegen der Sektensache ..."}},{"speaker":"npc","text":{"pl":"Tak?","en":"What?","de":"Was gibt''s?"}},{"speaker":"hero","text":{"pl":"Odbyło się wielkie przywołanie.","en":"The great invocation has taken place.","de":"Die große Beschwörung hat stattgefunden."}},{"speaker":"npc","text":{"pl":"Niemożliwe! Chcesz powiedzieć, że brałeś w tym udział?","en":"No! You mean you took part in their folly?","de":"Nein! Du machst bei dem Schwachsinn mit?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_running_15_02_8', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_running_15_02_8","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_RUNNING_Info","outputIds":["Org_826_Mordrag_RUNNING_15_02","Org_826_Mordrag_RUNNING_11_03","Org_826_Mordrag_RUNNING_15_08","Org_826_Mordrag_RUNNING_11_05"],"lines":[{"speaker":"hero","text":{"pl":"Niczego się jeszcze nie dowiedziałem.","en":"I haven''t found anything out yet.","de":"Ich hab'' noch nichts rausgefunden."}},{"speaker":"npc","text":{"pl":"Więc bierz się do roboty!","en":"Then get on with it...","de":"Bleib dran ..."}},{"speaker":"hero","text":{"pl":"Ich hab'' die Eier bei mir.","en":"Ich hab'' die Eier bei mir.","de":"Ich hab'' die Eier bei mir."}},{"speaker":"npc","text":{"pl":"(sarkastisch) Hab'' ich auch gemerkt. Diese verdammten Sektenspinner haben Gomez die alte Mine gekostet. Wird nicht mehr lange dauern, dann stehen seine Gardisten bei UNS vor der Tür, um sich ihr Erz abzuholen...","en":"(sarkastisch) Hab'' ich auch gemerkt. Diese verdammten Sektenspinner haben Gomez die alte Mine gekostet. Wird nicht mehr lange dauern, dann stehen seine Gardisten bei UNS vor der Tür, um sich ihr Erz abzuholen...","de":"(sarkastisch) Hab'' ich auch gemerkt. Diese verdammten Sektenspinner haben Gomez die alte Mine gekostet. Wird nicht mehr lange dauern, dann stehen seine Gardisten bei UNS vor der Tür, um sich ihr Erz abzuholen..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_826_mordrag_org_826_mordrag_running_15_06_4', 'ORG_826_Mordrag', '{"id":"missions_dia_org_826_mordrag_org_826_mordrag_running_15_06_4","npcId":"ORG_826_Mordrag","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_826_Mordrag.d","sourceFunction":"Org_826_Mordrag_RUNNING_Info","outputIds":["Org_826_Mordrag_RUNNING_15_06","Org_826_Mordrag_RUNNING_11_07","Org_826_Mordrag_RUNNING_15_10","Org_826_Mordrag_RUNNING_11_11"],"lines":[{"speaker":"hero","text":{"pl":"Bractwo zamierza wzmocnić swoje siły duchowe przy pomocy potężnego eliksiru wytwarzanego z jaj pełzaczy. Dzięki temu mają nadzieję nawiązać kontakt ze Śniącym.","en":"They intend to strengthen themselves and to contact the Sleeper by means of a potion they produce from minecrawlers'' eggs.","de":"Sie wollen mit der Hilfe eines mächtigen Elixiers, das sie aus Minecrawlereiern gewinnen, ihre geistigen Kräfte stärken und Kontakt zum Schläfer herstellen."}},{"speaker":"npc","text":{"pl":"Banda idiotów! Te świry naprawdę wierzą w te brednie, co?","en":"What a scream! Those madcaps really believe all that, don''t they?","de":"Ich lach'' mich tot! Diese Spinner glauben wirklich daran, was?"}},{"speaker":"hero","text":{"pl":"Jestem ciekaw co z tego wszystkiego wyjdzie.","en":"I''m curious about the result.","de":"Ich bin neugierig, was dabei rauskommt."}},{"speaker":"npc","text":{"pl":"Ja też. Daj mi znać, gdy Guru zbłaźnią się już całkowicie.","en":"Me too. Let me know when the Gurus have finished making complete fools of themselves.","de":"Ich auch. Sag mir Bescheid, wenn sich die Gurus bis auf die Knochen blamiert haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_833_buster_dia_org_833_buster_02_01_0', 'ORG_833_Buster', '{"id":"missions_dia_org_833_buster_dia_org_833_buster_02_01_0","npcId":"ORG_833_Buster","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_833_Buster.d","sourceFunction":"DIA_ORG_833_Buster_Info","outputIds":["DIA_ORG_833_Buster_02_01"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz co, poruszasz się tak jakoś sztywno. Mógłbym ci pomóc.","en":"You don''t look very agile. I could help you.","de":"Du siehst ganz schön ungelenkig aus, ich könnte dir helfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_833_buster_dia_org_833_buster3_02_01_0', 'ORG_833_Buster', '{"id":"missions_dia_org_833_buster_dia_org_833_buster3_02_01_0","npcId":"ORG_833_Buster","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_833_Buster.d","sourceFunction":"DIA_ORG_833_Buster3_Info","outputIds":["DIA_ORG_833_Buster3_02_01"],"lines":[{"speaker":"npc","text":{"pl":"Mogę ci pokazać, jak należy balansować ciałem. Nauczę cię AKROBATYKI.","en":"I can show you how to control your body. It''s the art of ACROBATICS.","de":"Ich kann dir die hohe Kunst der Körperbeherrschung zeigen. AKROBATIK."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_dia_roscoe_bring_list_15_00_0', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_dia_roscoe_bring_list_15_00_0","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"DIA_Roscoe_BringList_Info","outputIds":["DIA_Roscoe_BringList_15_00","DIA_Roscoe_BringList_10_01","DIA_Roscoe_BringList_15_02","DIA_Roscoe_BringList_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam tu listę z zamówieniami dla Starej Kopalni.","en":"I have the list of requirements for the Old Mine.","de":"Ich habe die Bedarfsliste der alten Mine."}},{"speaker":"npc","text":{"pl":"Nieźle! Skąd ją wytrzasnąłeś?","en":"Not bad. How did you get it?","de":"Nicht schlecht. Wie bist du daran gekommen?"}},{"speaker":"hero","text":{"pl":"Dostałem ją od Iana.","en":"Ian gave it to me.","de":"Ian hat sie mir gegeben."}},{"speaker":"npc","text":{"pl":"Masz tupet! Wysłali cię, żeby poddać cię próbie, tak? Założę się, że Thorusa trafia teraz jasny szlag!","en":"You got a nerve! So they sent you to test me, did they? Thorus must already be going mad, I''m sure.","de":"Du hast Nerven. Sie haben dich geschickt, um dich zu prüfen, was? Thorus geht bestimmt schon die Wände hoch."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_dia_roscoe_bring_list_15_04_4', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_dia_roscoe_bring_list_15_04_4","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"DIA_Roscoe_BringList_Info","outputIds":["DIA_Roscoe_BringList_15_04","DIA_Roscoe_BringList_10_05","DIA_Roscoe_BringList_15_06","DIA_Roscoe_BringList_10_07"],"lines":[{"speaker":"hero","text":{"pl":"To Diego zlecił mi to zadanie.","en":"Diego gave me the order.","de":"Diego hat mir den Auftrag gegeben."}},{"speaker":"npc","text":{"pl":"Diego wypełnia tylko rozkazy Thorusa. Jak go znam, pękłby ze śmiechu na wieść, że tu jesteś.","en":"Diego does what Thorus tells him to. If I know him, he''d die laughing if he knew that you were here.","de":"Diego macht, was Thorus ihm sagt. So wie ich ihn kenne, würde er sich totlachen, wenn er wüsste, dass du hier bist."}},{"speaker":"hero","text":{"pl":"To jak - mogę wejść, czy nie?","en":"Can I get in there now or not?","de":"Kann ich jetzt rein oder was?"}},{"speaker":"npc","text":{"pl":"Wchodź śmiało. Laresowi oczy wyjdą na wierzch!","en":"Just go on in. Lares won''t believe his eyes.","de":"Geh nur. Lares werden die Augen aus dem Kopf fallen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_dia_roscoe_come_again_10_00_0', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_dia_roscoe_come_again_10_00_0","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"DIA_Roscoe_ComeAgain_Info","outputIds":["DIA_Roscoe_ComeAgain_10_00"],"lines":[{"speaker":"npc","text":{"pl":"Znowu ty.","en":"You again.","de":"Du schon wieder."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_dia_roscoe_mordrag_15_00_0', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_dia_roscoe_mordrag_15_00_0","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"DIA_Roscoe_Mordrag_Info","outputIds":["DIA_Roscoe_Mordrag_15_00","DIA_Roscoe_Mordrag_10_01","DIA_Roscoe_Mordrag_15_02","DIA_Roscoe_Mordrag_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Przysyła mnie Mordrag.","en":"Mordrag sent me.","de":"Mordrag schickt mich."}},{"speaker":"npc","text":{"pl":"Mordrag już dawno tu nie zaglądał. Pewnie przeszedł na stronę Starego Obozu.","en":"Mordrag hasn''t been seen here for some time. He''s probably changed over to the Old Camp.","de":"Mordrag ist schon lange nicht mehr hier. Er ist vielleicht schon längst zum Alten Lager übergelaufen."}},{"speaker":"hero","text":{"pl":"To on mnie do was przyprowadził.","en":"I came here with him.","de":"Ich bin mit ihm hierhin gekommen."}},{"speaker":"npc","text":{"pl":"Mordrag wrócił?! Jakbyś go jeszcze spotkał, powiedz mu, że Lares chce się z nim widzieć.","en":"Mordrag''s back? If you meet him, tell him Lares wants to see him.","de":"Mordrag ist wieder hier? Wenn du ihn siehst, sag ihm, Lares will ihn sehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_dia_roscoe_mordrag_15_04_4', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_dia_roscoe_mordrag_15_04_4","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"DIA_Roscoe_Mordrag_Info","outputIds":["DIA_Roscoe_Mordrag_15_04","DIA_Roscoe_Mordrag_10_05","DIA_Roscoe_Mordrag_15_06","DIA_Roscoe_Mordrag_10_07"],"lines":[{"speaker":"hero","text":{"pl":"Mordrag dał mi coś dla Laresa.","en":"Mordrag gave me something for Lares.","de":"Mordrag hat mir etwas für Lares gegeben."}},{"speaker":"npc","text":{"pl":"Co takiego?","en":"What is it?","de":"Was?"}},{"speaker":"hero","text":{"pl":"Pierścień.","en":"A ring.","de":"Einen Ring."}},{"speaker":"npc","text":{"pl":"Założę się, że bardzo cenny... Dobra, możesz się zobaczyć z szefem.","en":"Certainly a precious piece... Okay, you can see him.","de":"Bestimmt ein kostbares Stück ... Gut, du kannst zu ihm."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_dia_roscoe_wanna_join_15_00_0', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_dia_roscoe_wanna_join_15_00_0","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"DIA_Roscoe_WannaJoin_Info","outputIds":["DIA_Roscoe_WannaJoin_15_00","DIA_Roscoe_WannaJoin_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym do was dołączyć.","en":"I want to join your gang.","de":"Ich will mich eurer Bande anschließen."}},{"speaker":"npc","text":{"pl":"Nie ty jeden, ale samo \"chcenie\" nie wystarczy. Musisz udowodnić, że będzie z ciebie jakiś pożytek.","en":"Many people want to join us. You''ll have to make a better offer if you want to pass through this gate.","de":"Das wollen viele. Du musst schon mit mehr kommen, wenn du durch diese Tür gehen willst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_info_roscoe_first_warn_info_10_00_0', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_info_roscoe_first_warn_info_10_00_0","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"Info_Roscoe_FirstWarn_Info","outputIds":["Info_Roscoe_FirstWarn_Info_10_00","Info_Roscoe_FirstWarn_Info_15_01","Info_Roscoe_FirstWarn_Info_10_02"],"lines":[{"speaker":"npc","text":{"pl":"Dokąd się wybierasz?","en":"Where do you wanna go?","de":"Wo soll''s denn hingehen?"}},{"speaker":"hero","text":{"pl":"Chcę się zobaczyć z Laresem.","en":"I want to meet Lares.","de":"Ich will zu Lares."}},{"speaker":"npc","text":{"pl":"Szef jest u siebie, ale trzeba mieć niezły powód, żeby mu przeszkodzić.","en":"Lares is here - but you need a good reason to disturb him.","de":"Lares ist hier - aber ohne guten Grund wirst du ihn nicht stören."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_840_roscoe_info_roscoe_last_warn_10_00_0', 'ORG_840_Roscoe', '{"id":"missions_dia_org_840_roscoe_info_roscoe_last_warn_10_00_0","npcId":"ORG_840_Roscoe","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_840_Roscoe.d","sourceFunction":"Info_Roscoe_LastWarn_Info","outputIds":["Info_Roscoe_LastWarn_10_00"],"lines":[{"speaker":"npc","text":{"pl":"Ogłuchłeś?","en":"Are you deaf?","de":"Du hörst wohl schlecht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_841_silas_dia_silas_hehler_15_00_0', 'ORG_841_Silas', '{"id":"missions_dia_org_841_silas_dia_silas_hehler_15_00_0","npcId":"ORG_841_Silas","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_841_Silas.d","sourceFunction":"DIA_Silas_Hehler_Info","outputIds":["DIA_Silas_Hehler_15_00","DIA_Silas_Hehler_06_01","DIA_Silas_Hehler_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak leci?","en":"How are things?","de":"Wie läuft''s denn so?"}},{"speaker":"npc","text":{"pl":"Świetnie! Sprzedajemy tu naszą ryżówkę za parę bryłek rudy.","en":"Great! We trade our home-made rice schnapps for ore.","de":"Gut! Wir verkaufen hier unseren selbstgebrannten Reisschnaps für gutes Erz."}},{"speaker":"npc","text":{"pl":"Da się z tego wyżyć. W końcu co innego mogą chłopcy zrobić z ciężko zarobioną rudą?","en":"Well, the boys carry in enough ore. Where should they spend it if not here?","de":"Kommt ja auch genug rein.  Wo sollen die Jungs ihr Erz auch sonst hinbringen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_842_shrike_dia_shrike_get_lost_15_00_0', 'ORG_842_Shrike', '{"id":"missions_dia_org_842_shrike_dia_shrike_get_lost_15_00_0","npcId":"ORG_842_Shrike","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_842_Shrike.d","sourceFunction":"DIA_Shrike_GetLost_Info","outputIds":["DIA_Shrike_GetLost_15_00","DIA_Shrike_GetLost_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Zejdź mi z oczu.","en":"Get lost.","de":"Mach, dass du wegkommst."}},{"speaker":"npc","text":{"pl":"Porozmawiamy innym razem!","en":"I''ll talk to you later!","de":"Wir sprechen uns noch!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_842_shrike_dia_shrike_hello_15_00_0', 'ORG_842_Shrike', '{"id":"missions_dia_org_842_shrike_dia_shrike_hello_15_00_0","npcId":"ORG_842_Shrike","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_842_Shrike.d","sourceFunction":"DIA_Shrike_Hello_Info","outputIds":["DIA_Shrike_Hello_15_00","DIA_Shrike_Hello_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać?","en":"How are things?","de":"Wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Spadaj!","en":"Get lost!","de":"Verpiss dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_843_sharky_org_843_sharky_fisk_info_15_00_0', 'ORG_843_Sharky', '{"id":"missions_dia_org_843_sharky_org_843_sharky_fisk_info_15_00_0","npcId":"ORG_843_Sharky","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_843_Sharky.d","sourceFunction":"Org_843_Sharky_Fisk_Info","outputIds":["Org_843_Sharky_Fisk_Info_15_00","Org_843_Sharky_Fisk_Info_10_01","Org_843_Sharky_Fisk_Info_15_02","Org_843_Sharky_Fisk_Info_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Fisk ze Starego Obozu szuka nowego partnera do interesów.","en":"Fisk from the Old Camp is looking for a new trading partner.","de":"Fisk aus dem Alten Lager ist auf der Suche nach einem neuen Handelspartner."}},{"speaker":"npc","text":{"pl":"A dlaczego mówisz o tym właśnie mi?","en":"And why are you telling me about it?","de":"Und warum erzählst du mir das?"}},{"speaker":"hero","text":{"pl":"Pomyślałem, że zainteresuje cię możliwość zarobienia paru bryłek rudy.","en":"I thought you might be interested in earning some ore.","de":"Ich dachte, du hättest vielleicht Lust, ein bisschen Erz zu verdienen."}},{"speaker":"npc","text":{"pl":"Czemu nie... Powiedz Fiskowi, że może na mnie liczyć.","en":"Why not... tell Fisk he can count on me in the next few days.","de":"Warum nicht ... Sag Fisk, er kann in den nächsten Tagen mit mir rechnen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_843_sharky_org_843_sharky_greet_info_15_01_0', 'ORG_843_Sharky', '{"id":"missions_dia_org_843_sharky_org_843_sharky_greet_info_15_01_0","npcId":"ORG_843_Sharky","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_843_Sharky.d","sourceFunction":"Org_843_Sharky_GREET_Info","outputIds":["Org_843_Sharky_GREET_Info_15_01","Org_843_Sharky_GREET_Info_10_02"],"lines":[{"speaker":"hero","text":{"pl":"Cześć, jak leci?","en":"Hey, how''s it going?","de":"Hey, wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Chcesz coś kupić?","en":"Do you want to buy something?","de":"Willst du was kaufen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_aidan_hello_15_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_aidan_hello_15_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_FirstAtNight_Info","outputIds":["DIA_Aidan_Hello_15_00","DIA_846_Hello_07_01","DIA_Ricelord_Arbeit_15_00","DIA_Shrike_GetLost_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Pracuję dla Ryżowego Księcia.","en":"I''m working for the Rice Lord.","de":"Ich arbeite für den Reislord."}},{"speaker":"hero","text":{"pl":"A masz dla mnie jakieś zajęcie?","en":"Have you got work for me?","de":"Hast du Arbeit für mich?"}},{"speaker":"npc","text":{"pl":"Porozmawiamy innym razem!","en":"I''ll talk to you later!","de":"Wir sprechen uns noch!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_first_07_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_first_07_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_First_Info","outputIds":["DIA_Lefty_First_07_00","DIA_Lefty_First_07_01"],"lines":[{"speaker":"npc","text":{"pl":"Hej! Jesteś tu nowy, nie? Potrzebuję kogoś, kto zaniesie wodę naszym zbieraczom ryżu.","en":"Hey! Just arrived? We need somebody to take some water to the peasants in the rice fields.","de":"Hey, du! Neu hier, was? Auf den Reisfeldern brauchen wir noch jemanden, der den Bauern Wasser bringt."}},{"speaker":"npc","text":{"pl":"W ten sposób od razu poznasz kilku ludzi. Zainteresowany?","en":"This way you can make friends with a few people. What do you think?","de":"Da kannst du dir direkt ein paar Freunde machen. Was denkst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_first_later_15_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_first_later_15_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_First_Later","outputIds":["DIA_Lefty_First_Later_15_00","DIA_Lefty_First_Later_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Może innym razem.","en":"Maybe later.","de":"Vielleicht später."}},{"speaker":"npc","text":{"pl":"Innym razem mogę cię już nie potrzebować. Zdecyduj się: chcesz mi pomóc czy nie?","en":"But I won''t need anybody later. I need your help right NOW. Do you want to help me or not?","de":"Später brauche ich aber niemanden. Ich brauche JETZT Hilfe.  Willst du mir nun helfen oder nicht?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_first_never_15_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_first_never_15_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_First_Never","outputIds":["DIA_Lefty_First_Never_15_00","DIA_Lefty_First_Never_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Sam sobie noś tę wodę.","en":"Take the water to the peasants yourself!","de":"Bring dein Wasser selbst rum!"}},{"speaker":"npc","text":{"pl":"Tak się nie traktuje przyjaciół! Widzę, że muszę nauczyć cię dobrych manier!","en":"That''s no good way of treating friends! I think I''ll have to teach you some manners!","de":"So geht man aber nicht mit Freunden um! Ich glaube, ich muss dir mal Manieren beibringen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_first_yes_15_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_first_yes_15_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_First_Yes","outputIds":["DIA_Lefty_First_Yes_15_00","DIA_Lefty_First_Yes_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Jasne, chętnie wam pomogę.","en":"Sure, I''ll be glad to help.","de":"Klar, ich helfe gern."}},{"speaker":"npc","text":{"pl":"Świetnie! Idź do Ryżowego Księcia. On da ci wodę i powie ci co należy zrobić.","en":"Great! Go to the Rice Lord. He''ll give you the water and tell you everything you need to know.","de":"Gut! Geh zum Reislord. Er gibt dir das Wasser und erzählt dir alles andere."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_never_again_15_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_never_again_15_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_NeverAgain_Info","outputIds":["DIA_Lefty_NeverAgain_15_00","DIA_Lefty_NeverAgain_07_01","DIA_Lefty_NeverAgain_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Od tej pory możesz sam sobie biegać z tą wodą!","en":"From now on you can carry the water yourself.","de":"Du kannst dein Wasser ab jetzt selbst bringen."}},{"speaker":"npc","text":{"pl":"Czyżby? A co - masz coś lepszego do roboty?","en":"Oh? Have you got better plans?","de":"Ach? Hast du was Besseres vor?"}},{"speaker":"npc","text":{"pl":"Chyba muszę ci przypomnieć kto tu jest szefem!","en":"I think I''ll have to remind you who''s the boss!","de":"Ich glaube, ich muss dich noch einmal daran erinnern, wer hier der Boss ist!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_perm_15_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_perm_15_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_PERM_Info","outputIds":["DIA_Lefty_PERM_15_00","DIA_Lefty_PERM_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać, przyjacielu?","en":"How are you, my friend?","de":"Na, mein Freund?"}},{"speaker":"npc","text":{"pl":"Człowieku! Czego chcesz?!","en":"Oh, man! What do you want?","de":"Mann! Was willst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_perm_durstig_15_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_perm_durstig_15_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_PERM_Durstig","outputIds":["DIA_Lefty_PERM_Durstig_15_00","DIA_Lefty_PERM_Durstig_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Zbieracze wyglądają na spragnionych.","en":"The peasants look thirsty.","de":"Die Bauern sehen durstig aus."}},{"speaker":"npc","text":{"pl":"Zajmę się tym... Nie ma obawy.","en":"I''ll see to it... don''t worry.","de":"Ich kümmere mich drum ... Mach dir keine Sorgen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_work_day_07_00_0', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_work_day_07_00_0","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_WorkDay_Info","outputIds":["DIA_Lefty_WorkDay_07_00","DIA_Lefty_WorkDay_NextChance_07_00","DIA_Lefty_WorkDay_NextChance_07_01","DIA_Lefty_WorkDay_StillRunning_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey, du!"}},{"speaker":"npc","text":{"pl":"Masz ogromne szczęście! Postanowiłem dać ci drugą szansę.","en":"You''re in luck! I''ll give you a second chance.","de":"Du hast Glück! Du bekommst eine neue Chance."}},{"speaker":"npc","text":{"pl":"Ale tym razem postaraj się tego nie spartaczyć! Idź do Ryżowego Księcia, a potem roznieś wodę wszystkim zbieraczom, jasne?","en":"Try not to mess it up this time! Well, go to the Rice Lord and then take water to all the peasants. Got it?","de":"Diesmal solltest du''s nicht vermasseln! Also: Du gehst zum Reislord und dann bringst du schön brav allen Bauern ihr Wasser, klar?"}},{"speaker":"npc","text":{"pl":"Przecież kazałem ci roznieść wodę zbieraczom!","en":"I told you to take some water to the peasants!","de":"Ich habe dir doch gesagt, du sollst den Bauern Wasser bringen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_844_lefty_dia_lefty_work_day_still_running_07_01_4', 'ORG_844_Lefty', '{"id":"missions_dia_org_844_lefty_dia_lefty_work_day_still_running_07_01_4","npcId":"ORG_844_Lefty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_844_Lefty.d","sourceFunction":"DIA_Lefty_WorkDay_Info","outputIds":["DIA_Lefty_WorkDay_StillRunning_07_01","DIA_Lefty_WorkDay_SUCCESS_07_00","DIA_Lefty_WorkDay_SUCCESS_07_01"],"lines":[{"speaker":"npc","text":{"pl":"Nie lubię ludzi, którzy coś obiecują, a potem nie dotrzymują słowa!","en":"I don''t like people who make promises and then don''t keep them!","de":"Ich mag es nicht, wenn man mir Sachen verspricht und sie dann nicht hält!"}},{"speaker":"npc","text":{"pl":"Dobra robota! Może będą z ciebie ludzie.","en":"Well done! You''re useful for something after all.","de":"Gut gemacht! Du bist ja zu was zu gebrauchen."}},{"speaker":"npc","text":{"pl":"Widzę, że jesteś wprost stworzony do tego zadania! Od tej pory będziesz to robił codziennie. Bierz się do roboty!","en":"I think this is exactly the right task for you. From now on, you''ll do it every day. Go on with it right now.","de":"Ich denke, das ist genau die richtige Aufgabe für dich. Du wirst das ab jetzt jeden Tag tun. Fang direkt wieder damit an"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_hello_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_hello_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Hello_Info","outputIds":["DIA_Wedge_Hello_15_00","DIA_Wedge_Hello_05_01","DIA_Wedge_Hello_05_02","DIA_Wedge_Hello_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Czego ode mnie chcesz?","en":"What do you want?","de":"Was willst du von mir?"}},{"speaker":"npc","text":{"pl":"Jesteś tu nowy, co? Od razu zauważyłem.","en":"You''ve just arrived, haven''t you? I noticed it straight away.","de":"Du bist noch nicht lange hier, was? So was sehe ich direkt."}},{"speaker":"npc","text":{"pl":"Musisz się jeszcze wiele nauczyć. Mógłbym ci pokazać, co w trawie piszczy.","en":"There are a lot of things you need to know. I can teach you a few things.","de":"Es gibt ''ne Menge Sachen, die du hier wissen musst. Einige davon kann ich dir beibringen."}},{"speaker":"npc","text":{"pl":"Przede wszystkim musisz uważać z kim rozmawiasz. Widzisz tego faceta, tam - przy ognisku? To Butch. Strzeż się go!","en":"Besides, you have to watch who you talk to. Butch, for example - that''s the guy over there, next to the campfire... Be aware of him!","de":"Außerdem musst du hier aufpassen, mit wem du redest. Butch zum Beispiel - der Typ da drüben am Lagerfeuer, vor dem musst du dich in Acht nehmen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_lehrer_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_lehrer_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Lehrer_Info","outputIds":["DIA_Wedge_Lehrer_15_00","DIA_Wedge_Lehrer_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Czego możesz mnie nauczyć?","en":"What can you teach me?","de":"Was kannst du mir beibringen?"}},{"speaker":"npc","text":{"pl":"To zależy... A co chcesz wiedzieć?","en":"It depends... What do you want to know?","de":"Kommt drauf an, was willst du wissen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_lehrer_lockpick_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_lehrer_lockpick_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Lehrer_Lockpick","outputIds":["DIA_Wedge_Lehrer_Lockpick_15_00","DIA_Wedge_Lehrer_Lockpick_05_01","DIA_Wedge_Lehrer_Lockpick_05_02","DIA_Wedge_Lehrer_Lockpick_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym nauczyć się otwierać zamki.","en":"How can I improve my lock-picking skills?","de":"Wie werde ich besser im Knacken von Schlössern?"}},{"speaker":"npc","text":{"pl":"Nie wątpię! Cóż... Początki nie są zbyt trudne.","en":"You''d like to know that, wouldn''t you! It''s not too difficult to begin with.","de":"Das willst du gerne wissen, hm? Ist für den Anfang nicht so schwer."}},{"speaker":"npc","text":{"pl":"Przede wszystkim musisz uważać, żeby nie złamać wytrycha.","en":"Above all, you have to make sure that your lockpick doesn''t break off.","de":"Du musst vor allem darauf achten, dass dir dein Dietrich nicht abbricht."}},{"speaker":"npc","text":{"pl":"Musisz być bardzo cierpliwy. Wtedy nie będziesz potrzebował tylu wytrychów, he he!","en":"If you''re a little bit more patient in the future, you''ll see that you won''t need that many lockpicks any more!","de":"Wenn du in Zukunft mit weniger Gewalt an die Sache rangehst, wirst du merken, dass du weniger Dietriche verbrauchst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_lehrer_lockpick2_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_lehrer_lockpick2_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Lehrer_Lockpick2","outputIds":["DIA_Wedge_Lehrer_Lockpick2_15_00","DIA_Wedge_Lehrer_Lockpick2_05_01","DIA_Wedge_Lehrer_Lockpick2_05_02","DIA_Wedge_Lehrer_Lockpick2_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać ekspertem w otwieraniu zamków.","en":"How can I become an expert at picking locks?","de":"Wie werde ich ein Meister im Öffnen von Schlössern?"}},{"speaker":"npc","text":{"pl":"Gdy nabierzesz już trochę doświadczenia, nauczysz się rozpoznawać dźwięk, jaki wydaje wytrych zanim pęknie.","en":"Only when you''ve gained some experience can you tell when a lockpick is going to break. It makes a different sound!","de":"Nur wer schon einige Übung hat, merkt genau, wann ihm ein Dietrich abbricht und wann nicht. Du erkennst es am Geräusch!"}},{"speaker":"npc","text":{"pl":"Myślę, że powinieneś sobie z tym poradzić. Wsłuchaj się uważnie w dźwięki jakie wydaje otwierany zamek, a nie będziesz potrzebował tylu wytrychów, he, he!","en":"I think you have it. Learn to listen for the gentle clicking of the lock and you won''t lose so many lockpicks in future.","de":"Ich denke, du bist jetzt so weit - lerne auf das leise Klicken des Schlosses zu achten, und du wirst nur noch selten das Pech haben, einen Dietrich zu verlieren."}},{"speaker":"npc","text":{"pl":"Prawdziwy mistrz w tym fachu potrafi otworzyć każdą skrzynię nie łamiąc ani jednego wytrycha.","en":"An expert in this field stands a good chance of opening a trunk without breaking his lockpick.","de":"Ein Meister des Fachs hat eine gute Chance, eine Truhe zu öffnen, ohne dass sein Dietrich überhaupt abbricht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_lehrer_pickpocket_05_04_4', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_lehrer_pickpocket_05_04_4","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Lehrer_Pickpocket","outputIds":["DIA_Wedge_Lehrer_PICKPOCKET_05_04","DIA_Wedge_lehrer_Pickpocket_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Tylko prawdziwy mistrz potrafi ukraść coś pozostając całkowicie niezauważonym!","en":"Only an expert can take things from people''s pockets without them noticing!","de":"Erst als Meister wirst du in der Lage sein, jemanden etwas aus der Tasche zu ziehen, ohne dass er es bemerkt!"}},{"speaker":"npc","text":{"pl":"Nie ma o czym mówić! Nie będzie z ciebie złodzieja, dopóki nie nauczysz się skradać!","en":"Forget it! You''ll never make a skilled thief unless you can sneak around.","de":"Vergiss es! Ohne dass du schleichen kannst, wirst du NIEMALS ein geschickter Dieb."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_lehrer_pickpocket_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_lehrer_pickpocket_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Lehrer_Pickpocket","outputIds":["DIA_Wedge_Lehrer_PICKPOCKET_15_00","DIA_Wedge_Lehrer_PICKPOCKET_05_01","DIA_Wedge_Lehrer_PICKPOCKET_05_02","DIA_Wedge_Lehrer_PICKPOCKET_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać zręcznym kieszonkowcem!","en":"I want to become a skilled pickpocket!","de":"Ich will ein guter Taschendieb werden!"}},{"speaker":"npc","text":{"pl":"Chciałbyś odciążyć parę osób z ich dobytku, co? No dobra.","en":"So you want to relieve a few people of their belongings? Well then.","de":"So, du willst also ein paar Leute um ihre Sachen erleichtern? Nun gut."}},{"speaker":"npc","text":{"pl":"Pokażę ci na czym powinieneś się skoncentrować, ale szanse, że zostaniesz złapany będą nadal znaczne.","en":"I''ll teach you how to improve your skills, but it''s still very likely that you''ll get caught.","de":"Ich werde dir beibringen, wie du besser wirst, aber es besteht immer noch eine Chance, dass du erwischt wirst."}},{"speaker":"npc","text":{"pl":"Podejmuj ryzyko wyłącznie jeśli w pobliżu ofiary nie ma osób trzecich.","en":"You should only take the risk if nobody but your victim is around.","de":"Das Risiko solltest du nur eingehen, wenn außer deinem Opfer niemand sonst da ist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_lehrer_pickpocket2_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_lehrer_pickpocket2_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Lehrer_Pickpocket2","outputIds":["DIA_Wedge_Lehrer_Pickpocket2_15_00","DIA_Wedge_Lehrer_Pickpocket2_05_01","DIA_Wedge_Lehrer_Pickpocket2_05_02","DIA_Wedge_Lehrer_Pickpocket2_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać mistrzem kieszonkowców!","en":"I want to become an expert pickpocket!","de":"Ich will ein Meister der Taschendiebe werden!"}},{"speaker":"npc","text":{"pl":"Cóż, chyba rzeczywiście potrafisz już wystarczająco dużo, żeby opanować zaawansowane sztuczki.","en":"I think you''ve progressed far enough to be taught the final tricks of the trade.","de":"Ich denke, du bist gut genug, um in die letzten Geheimnisse eingeweiht zu werden."}},{"speaker":"npc","text":{"pl":"Ale musisz pamiętać, że nawet mistrzowie złodziejscy od czasu do czasu zostają złapani.","en":"But you should know that even the best can get caught sometimes.","de":"Du solltest aber wissen, dass es selbst den Besten manchmal passiert, dass sie bemerkt werden."}},{"speaker":"npc","text":{"pl":"Uważaj na siebie.","en":"Take care.","de":"Also pass auf dich auf."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_lehrer_schleichen_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_lehrer_schleichen_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Lehrer_Schleichen","outputIds":["DIA_Wedge_Lehrer_Schleichen_15_00","DIA_Wedge_Lehrer_Schleichen_05_01","DIA_Wedge_Lehrer_Schleichen_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym nauczyć się poruszać bezszelestnie.","en":"I want to learn how to sneak around.","de":"Ich will lernen, mich lautlos zu bewegen."}},{"speaker":"npc","text":{"pl":"Grunt to zachować równowagę. Oprócz tego musisz nauczyć się kontrolować swój oddech.","en":"It''s all a matter of keeping your balance. You also have to learn how to control your breath.","de":"Es ist alles eine Frage des Gleichgewichts. Du musst auch lernen, deinen Atem zu kontrollieren."}},{"speaker":"npc","text":{"pl":"Przyjmij odpowiednią postawę, a nikt nie usłyszy twoich kroków.","en":"Pay attention to your posture and nobody will hear you moving.","de":"Beachte die richtige Haltung, und niemand wird dich hören, wenn du dich bewegst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_psst_05_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_psst_05_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_Psst_Info","outputIds":["DIA_Wedge_Psst_05_00","DIA_Wedge_Psst_15_01","DIA_Wedge_Psst_05_02"],"lines":[{"speaker":"npc","text":{"pl":"Ciiii... Hej, ty!","en":"Sshh... hey, you!","de":"Psst ... Hey,  du!"}},{"speaker":"hero","text":{"pl":"Co? Ja?","en":"Who?... Me?","de":"Wer? ... ich?"}},{"speaker":"npc","text":{"pl":"Tak... Chodź no tutaj!","en":"Exactly... Come over here!","de":"Genau du ... Komm mal her!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_850_wedge_dia_wedge_warns_of_butch_15_00_0', 'ORG_850_Wedge', '{"id":"missions_dia_org_850_wedge_dia_wedge_warns_of_butch_15_00_0","npcId":"ORG_850_Wedge","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_850_Wedge.d","sourceFunction":"DIA_Wedge_WarnsOfButch_Info","outputIds":["DIA_Wedge_WarnsOfButch_15_00","DIA_Wedge_WarnsOfButch_05_01","DIA_Wedge_WarnsOfButch_05_02"],"lines":[{"speaker":"hero","text":{"pl":"A co z nim jest nie tak?","en":"What''s the matter with Butch?","de":"Was ist mit Butch?"}},{"speaker":"npc","text":{"pl":"Ma paskudny nawyk napadania nowoprzybyłych. Na twoim miejscu unikałbym go jak ognia.","en":"He has the mean habit of beating up the new ones. So you''d better avoid meeting him.","de":"Er hat die fiese Angewohnheit, Neuen zur Begrüßung das Fell über die Ohren zu ziehen. Also geh'' ihm am besten aus dem Weg."}},{"speaker":"npc","text":{"pl":"Also, geh ihm am besten aus dem Weg.//***Doppelt***","en":"Also, geh ihm am besten aus dem Weg.//***Doppelt***","de":"Also, geh ihm am besten aus dem Weg.//***Doppelt***"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_851_butch_dia_butch_hello_15_00_0', 'ORG_851_Butch', '{"id":"missions_dia_org_851_butch_dia_butch_hello_15_00_0","npcId":"ORG_851_Butch","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_851_Butch.d","sourceFunction":"DIA_Butch_Hello_Info","outputIds":["DIA_Butch_Hello_15_00","DIA_Butch_Hello_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Cześć. Kim jesteś?","en":"Hi. Who are you?","de":"Hi. Wer bist du?"}},{"speaker":"npc","text":{"pl":"Nie twój interes! Nie podoba mi się twoja gęba!","en":"It''s none of your business! I don''t like your mug!","de":"Das geht dich einen Dreck an! Deine Fresse gefällt mir nicht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_dia_wolf_greet_org_09_00_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_dia_wolf_greet_org_09_00_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"DIA_Wolf_GreetORG_Info","outputIds":["DIA_Wolf_GreetORG_09_00"],"lines":[{"speaker":"npc","text":{"pl":"Hej, teraz jesteś jednym z nas!","en":"Hey! Now you''re one of us, kid.","de":"Hey! Du bist jetzt einer von uns, Kleiner."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_good_15_01_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_good_15_01_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_GOOD_Info","outputIds":["Info_Wolf_GOOD_15_01","Info_Wolf_GOOD_09_02","Info_Wolf_GOOD_15_03","Info_Wolf_GOOD_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Gorn powiedział, że chcesz ze mną pilnie porozmawiać?","en":"Gorn said you wanted to talk to me urgently...","de":"Gorn sagt, du wolltest dringend mit mir sprechen?"}},{"speaker":"npc","text":{"pl":"Dobrze, że zdążyłeś zajrzeć do mnie przed wymarszem!","en":"I''m glad you dropped by before you left!","de":"Gut, dass du vorher noch vorbeikommst!"}},{"speaker":"hero","text":{"pl":"Przed jakim wymarszem?","en":"Before I go where?","de":"Vor was?"}},{"speaker":"npc","text":{"pl":"Przed waszym wymarszem do Niezupełnie-Wolnej-Kopalni.","en":"Before you go to visit the Not-So-Free Mine.","de":"Vor eurem Besuch in der nicht mehr ganz so Freien Mine."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_mcplatesenough_09_05_4', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_mcplatesenough_09_05_4","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_MCPLATESENOUGH_Info","outputIds":["Info_Wolf_MCPLATESENOUGH_09_05"],"lines":[{"speaker":"npc","text":{"pl":"Będziesz musiał zaglądać do mnie od czasu do czasu.","en":"Just drop by now and then when you''re in the area!","de":"Schau einfach ab und zu bei mir rein, wenn du in der Nähe bist!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_mcplatesenough_15_01_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_mcplatesenough_15_01_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_MCPLATESENOUGH_Info","outputIds":["Info_Wolf_MCPLATESENOUGH_15_01","Info_Wolf_MCPLATESENOUGH_09_02","Info_Wolf_MCPLATESENOUGH_15_03","Info_Wolf_MCPLATESENOUGH_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Zebrałem mnóstwo płytek z pancerzy pełzaczy!","en":"I''ve gathered lots of minecrawlers'' armor plates!","de":"Ich habe jede Menge dieser Minecrawler-Panzerplatten eingesammelt!"}},{"speaker":"npc","text":{"pl":"Fantastycznie! Natychmiast zabieram się do roboty!","en":"Fantastic!!! I''ll get to work immediately!","de":"Fantastisch!!! Ich werde mich gleich an die Arbeit machen!"}},{"speaker":"hero","text":{"pl":"Jak długo to zajmie?","en":"How long will it take?","de":"Wie lange wirst du dafür brauchen?"}},{"speaker":"npc","text":{"pl":"Nie mam pojęcia. To coś zupełnie nowego. Jeszcze nigdy czegoś takiego nie robiłem!","en":"I haven''t the faintest idea. This is a completely new development, man!","de":"Ich habe nicht die geringste Ahnung. Das ist eine komplette Neuentwicklung, Mann!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_mcplatesfew_15_01_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_mcplatesfew_15_01_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_MCPLATESFEW_Info","outputIds":["Info_Wolf_MCPLATESFEW_15_01","Info_Wolf_MCPLATESFEW_09_02","Info_Wolf_MCPLATESFEW_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Przyniosłem ci kilka tych płytek, o które prosiłeś!","en":"I''ve gathered some of those minecrawler armor plates!","de":"Ich habe einige der Minecrawler-Panzerplatten eingesammelt!"}},{"speaker":"npc","text":{"pl":"To za mało! Nie starczy na całą zbroję!","en":"Not enough! That''s not enough for a whole armor!","de":"Zu wenig! Das reicht nicht für eine ganze Rüstung!"}},{"speaker":"npc","text":{"pl":"Przynieś mi więcej płytek!","en":"Bring me more of these plates!","de":"Bring mir mehr von diesen Platten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_profit_15_01_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_profit_15_01_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_PROFIT_Info","outputIds":["Info_Wolf_PROFIT_15_01","Info_Wolf_PROFIT_09_02"],"lines":[{"speaker":"hero","text":{"pl":"I mówisz mi to wszystko nie żądając niczego w zamian?","en":"And you''re telling me without wanting anything for yourself?","de":"Und diese Information gibst du mir völlig uneigennützig?"}},{"speaker":"npc","text":{"pl":"No niezupełnie... Jeśli uda mi się sklecić z tych płytek porządną zbroję, będę... bardzo szybko... bardzo dużo... Ach, nieważne!","en":"Not exactly... If I manage to make good armor from these plates, I will... very quickly ... very much ... oh, forget it!","de":"Nicht ganz ... Wenn es mir gelingt, aus solchen Platten eine gute Rüstung zu zimmern, werde ich sehr schnell  ... sehr viel  ... Ach, lassen wird das!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_skin_15_01_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_skin_15_01_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_SKIN_Info","outputIds":["Info_Wolf_SKIN_15_01","Info_Wolf_SKIN_09_02","Info_Wolf_SKIN_09_03","Info_Wolf_SKIN_15_04"],"lines":[{"speaker":"hero","text":{"pl":"W jaki sposób mam oddzielić te płytki od zwłok pełzaczy?","en":"How can I remove the plates from those beasts?","de":"Wie bekomme ich diese Platten von den Biestern ab?"}},{"speaker":"npc","text":{"pl":"To proste. Płytki na grzbiecie przymocowane są tylko przy krawędziach.","en":"That''s quite easy. The back plates are only joined to the body around the edges.","de":"Das ist relativ einfach. Die Rückenplatten sind nur an deren Rändern mit dem Körper verwachsen."}},{"speaker":"npc","text":{"pl":"Wystarczy wziąć ostry nóż i \"ciąć wzdłuż przerywanej linii\".","en":"Just take a razor blade and ''cut along the dotted line''.","de":"Nimm einfach ein Rasiermesser und schneide halbschräg an den Rändern entlang."}},{"speaker":"hero","text":{"pl":"W porządku. Postaram się przynieść ci kilka płytek z pancerzy pełzaczy.","en":"Okay, I get it! I''ll see if I can find those armor plates.","de":"Okay, kapiert! Mal sehen, ob ich solche Panzerplatten finden kann."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_speak_09_05_4', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_speak_09_05_4","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_SPEAK_Info","outputIds":["Info_Wolf_SPEAK_09_05","Info_Wolf_SPEAK_09_06","Info_Wolf_SPEAK_09_07","Info_Wolf_SPEAK_09_08"],"lines":[{"speaker":"npc","text":{"pl":"Oczywiście nie mam tu na myśli tych wychudzonych osobników, które nawiedzały zawaloną kopalnię Gomeza...","en":"I don''t mean the small, harmless specimens found in Gomez'' buried mine...","de":"Nicht etwa die der kleinen, harmlosen Exemplare aus der jetzt verschütteten Mine von Gomez ..."}},{"speaker":"npc","text":{"pl":"... O nie, one nie wystarczą. W NASZEJ kopalni żyją PRAWDZIWE PEŁZACZE. Większe, silniejsze i jeszcze bardziej wredne.","en":"... NOOO. Not them. There is a far more dangerous kind in our mine.","de":"...NEEEEIN. Die nicht. In unserer Mine lebt eine wesentlich gefährlichere Unterart."}},{"speaker":"npc","text":{"pl":"Pancerz tych bestii jest niemal nie do przebicia!","en":"The armor of these beasts is nearly impenetrable!","de":"Der Panzer dieser Biester ist fast nicht zu durchdringen!"}},{"speaker":"npc","text":{"pl":"Gdybyś mógł mi przynieść kilka płytek z ich pancerzy, mógłbym z nich poskładać nie lada zbroję!","en":"If you could bring me some of these armor plates, I could try to make armor from them.","de":"Wenn du mir einige dieser Panzerplatten bringen könntest, würde ich versuchen, daraus eine Rüstung herzustellen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_info_wolf_speak_15_01_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_info_wolf_speak_15_01_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Info_Wolf_SPEAK_Info","outputIds":["Info_Wolf_SPEAK_15_01","Info_Wolf_SPEAK_09_02","Info_Wolf_SPEAK_15_03","Info_Wolf_SPEAK_09_04"],"lines":[{"speaker":"hero","text":{"pl":"O co chodzi?","en":"What''s up?","de":"Worum geht es?"}},{"speaker":"npc","text":{"pl":"Mam pomysł na zupełnie nowy rodzaj pancerza.","en":"I''ve had an idea how to produce a completely new armor.","de":"Ich hatte neulich eine Idee, wie wir völlig neue Rüstungen herstellen können."}},{"speaker":"hero","text":{"pl":"Czyżby? A cóż to za pomysł?","en":"Oh, and how''s that?","de":"Aha, und wie?"}},{"speaker":"npc","text":{"pl":"Pancerze pełzaczy są niezwykle twarde. Znacznie trwalsze niż choćby stal.","en":"The minecrawlers'' armor plates are the hardest material I know.","de":"Das härteste Material, dass ich kenne, sind die Panzerplatten der Minecrawler."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_855_wolf_org_855_wolf_where_hunter_15_00_0', 'ORG_855_Wolf', '{"id":"missions_dia_org_855_wolf_org_855_wolf_where_hunter_15_00_0","npcId":"ORG_855_Wolf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_855_Wolf.d","sourceFunction":"Org_855_Wolf_WhereHunter_Info","outputIds":["Org_855_Wolf_WhereHunter_15_00","Org_855_Wolf_WhereHunter_09_01","Org_855_Wolf_WhereHunter_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę zdobyć futra albo skóry?","en":"How do I get furs and skins?","de":"Wie komme ich an Felle und Häute?"}},{"speaker":"npc","text":{"pl":"Przy drodze do Nowego Obozu kręci się Aidan. On może cię nauczyć, jak ściągać skórę ze zwierząt.","en":"On the way to the New Camp you''ll come across Aidan. He can teach you how to skin animals.","de":"Auf dem Weg zum Neuen Lager findest du Aidan. Er kann dir beibringen, wie du Tieren das Fell abziehst."}},{"speaker":"npc","text":{"pl":"Ratford i Drax polują zwykle na północ od Starego Obozu, na drodze do miejsca wymiany.","en":"Ratford and Drax are hanging around in the north of the Old Camp. It''s on the way to the trading square.","de":"Ratford und Drax treiben sich nördlich vom Alten Lager rum, auf dem Weg zum Austauschplatz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_859_aidan_dia_aidan_hello_15_00_0', 'ORG_859_Aidan', '{"id":"missions_dia_org_859_aidan_dia_aidan_hello_15_00_0","npcId":"ORG_859_Aidan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_859_Aidan.d","sourceFunction":"DIA_Aidan_Hello_Info","outputIds":["DIA_Aidan_Hello_15_00","DIA_Aidan_Hello_13_01","DIA_Aidan_Hello_15_02","DIA_Aidan_Hello_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Jestem myśliwym. Utrzymuję się ze sprzedaży skór i kłów zabitych zwierząt.","en":"I''m a hunter. I make a living out of selling skins and teeth.","de":"Ich bin Jäger. Ich lebe vom Verkauf von Fellen und Zähnen."}},{"speaker":"hero","text":{"pl":"Da się z tego wyżyć?","en":"Does it pay?","de":"Bringt das viel ein?"}},{"speaker":"npc","text":{"pl":"Jeśli potrafi się zręcznie oporządzać zwierzynę - tak, i to całkiem nieźle!","en":"If you know how to cut up the beasts the right way, yeah.","de":"Wenn man weiß, wie man die Viecher richtig ausschlachtet, schon."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_859_aidan_org_859_aidan_creatures_15_00_0', 'ORG_859_Aidan', '{"id":"missions_dia_org_859_aidan_org_859_aidan_creatures_15_00_0","npcId":"ORG_859_Aidan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_859_Aidan.d","sourceFunction":"Org_859_Aidan_Creatures_Info","outputIds":["Org_859_Aidan_Creatures_15_00","Org_859_Aidan_Creatures_13_01","Org_859_Aidan_Creatures_TaughtAll_13_00"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym się nauczyć oprawiać zwierzynę.","en":"I want to learn how to cut up animals.","de":"Ich will lernen, Tiere auszuschlachten."}},{"speaker":"npc","text":{"pl":"A co chcesz wiedzieć?","en":"What do you wanna know?","de":"Was willst du wissen?"}},{"speaker":"npc","text":{"pl":"Nauczyłem cię już wszystkiego co sam wiem.","en":"I''ve taught you everything I know.","de":"Ich habe dir alles beigebracht, was ich weiß."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_859_aidan_org_859_aidan_creatures_fell_15_00_0', 'ORG_859_Aidan', '{"id":"missions_dia_org_859_aidan_org_859_aidan_creatures_fell_15_00_0","npcId":"ORG_859_Aidan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_859_Aidan.d","sourceFunction":"Org_859_Aidan_Creatures_Fell","outputIds":["Org_859_Aidan_Creatures_Fell_15_00","Org_859_Aidan_Creatures_Fell_13_01","Org_859_Aidan_Creatures_Fell_13_02","Org_859_Aidan_Creatures_KEINE_LP_13_00"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę zdobyć skóry upolowanej zwierzyny?","en":"How can I skin these creatures?","de":"Wie kann ich den Viechern das Fell abziehen?"}},{"speaker":"npc","text":{"pl":"Zaczynaj skórowanie od zadu, przesuwając się stopniowo ku głowie. Spróbuj kilka razy. To nie jest takie trudne, a futra potrafią być bardzo cenne!","en":"It''s very important to skin them from the front to the back. Once you get the hang of it, it''ll be easy. Furs are very valuable!","de":"Wichtig ist vor allem: Immer von vorne nach hinten. Wenn du den Bogen einmal raushast, ist es kein Problem. Felle sind sehr wertvoll!"}},{"speaker":"npc","text":{"pl":"Futra wilków i cieniostworów można wykorzystać do szycia odzieży. Badając futro zabitego zwierza łatwo ocenisz, czy nadaje się do dalszego wykorzystania.","en":"The furs of wolves and shadowbeasts can be used to make clothes. When you examine the fur of a killed animal, you''ll soon notice if it can be used or not.","de":"Das Fell von Wölfen oder Schattenläufern eignet sich zum Herstellen von Kleidung. Du wirst merken, ob ein erlegtes Tier ein brauchbares Fell hat, wenn du es untersuchst."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You need more experience, otherwise my knowledge won''t be of any use to you.","de":"Du musst mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_859_aidan_org_859_aidan_creatures_haut_15_00_0', 'ORG_859_Aidan', '{"id":"missions_dia_org_859_aidan_org_859_aidan_creatures_haut_15_00_0","npcId":"ORG_859_Aidan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_859_Aidan.d","sourceFunction":"Org_859_Aidan_Creatures_Haut","outputIds":["Org_859_Aidan_Creatures_Haut_15_00","Org_859_Aidan_Creatures_Haut_13_01","Org_859_Aidan_Creatures_Haut_13_02","Org_859_Aidan_Creatures_KEINE_LP_13_00"],"lines":[{"speaker":"hero","text":{"pl":"Na co powinienem zwracać uwagę zdzierając skórę z gadów?","en":"What do I have to observe while skinning reptiles?","de":"Worauf muss ich beim Häuten von Reptilien achten?"}},{"speaker":"npc","text":{"pl":"Skóry topielców i bagiennych węży są szczególnie cenne.","en":"The only reptiles suited for this purpose are lurkers and swampsharks.","de":"Die einzigen Reptilien, die dafür geeignet sind, sind der Lurker und der Sumpfhai."}},{"speaker":"npc","text":{"pl":"Jeśli przetniesz skórę na bokach, powinna sama odejść od mięsa. Myślę, że od tej pory poradzisz już sobie ze skórowaniem gadów.","en":"If you slit the skin at the sides, it''ll peel off by itself. From now on you should be able to skin reptiles.","de":"Wenn du die Haut an den Seiten anschneidest, löst sie sich wie von selbst. Du solltest ab jetzt kein Problem mehr haben, Echsen zu häuten."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You need more experience, otherwise my knowledge won''t be of any use to you.","de":"Du musst mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_859_aidan_org_859_aidan_creatures_kein_erz_13_00_4', 'ORG_859_Aidan', '{"id":"missions_dia_org_859_aidan_org_859_aidan_creatures_kein_erz_13_00_4","npcId":"ORG_859_Aidan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_859_Aidan.d","sourceFunction":"Org_859_Aidan_Creatures_Haut","outputIds":["Org_859_Aidan_Creatures_KEIN_ERZ_13_00"],"lines":[{"speaker":"npc","text":{"pl":"Najpierw chcę zobaczyć trochę rudy. W tej kolonii nic nie ma za darmo!","en":"I wanna see some ore first. Like I said: Everything has its price!","de":"Erst will ich mein Erz sehen - wie gesagt: Alles hat seinen Preis!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_859_aidan_org_859_aidan_creatures_kralle_15_00_0', 'ORG_859_Aidan', '{"id":"missions_dia_org_859_aidan_org_859_aidan_creatures_kralle_15_00_0","npcId":"ORG_859_Aidan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_859_Aidan.d","sourceFunction":"Org_859_Aidan_Creatures_Kralle","outputIds":["Org_859_Aidan_Creatures_Kralle_15_00","Org_859_Aidan_Creatures_Kralle_13_01","Org_859_Aidan_Creatures_Kralle_13_02","Org_859_Aidan_Creatures_KEINE_LP_13_00"],"lines":[{"speaker":"hero","text":{"pl":"Pokaż mi jak zdobyć pazury upolowanej zwierzyny.","en":"Show me how to take off the claws!","de":"Bring mir bei, Krallen abzuziehen!"}},{"speaker":"npc","text":{"pl":"Prawdę mówiąc to dziecinnie proste, trzeba tylko znać odpowiednią metodę. Wygnij pazury do przodu - nigdy do tyłu! I pod żadnym pozorem nie próbuj ich wyciągać!","en":"Actually it''s quite simple if you know what to do. Bend the claws forward - never backwards - and you MUSTN''T pull them out either!","de":"Ist im Grunde ganz einfach, wenn du weißt, wie''s geht. Du musst die Krallen nach vorne wegknicken, auf keinen Fall nach hinten und NICHT ziehen!"}},{"speaker":"npc","text":{"pl":"Najlepiej pozyskiwać pazury jaszczurów. Od tej pory będziesz wiedział, które zwierzęta dostarczają dobrych pazurów.","en":"Lizards'' claws are especially useful. From now on, you''ll know which creature''s claws to take.","de":"Krallen kannst du vor allem von Echsen nehmen. Du wirst ab jetzt erkennen, von welchem erlegten Biest du die Krallen nehmen kannst."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You need more experience, otherwise my knowledge won''t be of any use to you.","de":"Du musst mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_859_aidan_org_859_aidan_creatures_zahn_15_00_0', 'ORG_859_Aidan', '{"id":"missions_dia_org_859_aidan_org_859_aidan_creatures_zahn_15_00_0","npcId":"ORG_859_Aidan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_859_Aidan.d","sourceFunction":"Org_859_Aidan_Creatures_Zahn","outputIds":["Org_859_Aidan_Creatures_Zahn_15_00","Org_859_Aidan_Creatures_Zahn_13_01","Org_859_Aidan_Creatures_Zahn_13_02","Org_859_Aidan_Creatures_KEINE_LP_13_00"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę zdobyć kły upolowanej zwierzyny?","en":"How do I get the teeth?","de":"Wie komme ich an die Zähne?"}},{"speaker":"npc","text":{"pl":"Przede wszystkim musisz uważać, żeby kły nie popękały podczas wyciągania. W tym celu wbij nóż w pobliżu środka zęba i delikatnie go podważaj.","en":"The most important thing is to make sure the teeth don''t splinter. To avoid that, put your knife near the center of the tooth and lever it out carefully.","de":"Du musst vor allem darauf achten, dass die Zähne nicht splittern. Um das zu verhindern, musst du dein Messer in der Mitte des Zahns ansetzen und vorsichtig hebeln."}},{"speaker":"npc","text":{"pl":"Warto zabierać kły wilków, cieniostworów i zębaczy","en":"You can take the teeth of wolves, shadowbeasts and snappers.","de":"Zähne kannst du von Wölfen, Schattenläufern oder Snappern nehmen."}},{"speaker":"npc","text":{"pl":"Musisz najpierw zdobyć trochę więcej doświadczenia. Inaczej moja wiedza będzie bezużyteczna.","en":"You need more experience, otherwise my knowledge won''t be of any use to you.","de":"Du musst mehr Erfahrung sammeln, vorher wird dich mein Wissen nicht weiterbringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_angebot_info_15_01_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_angebot_info_15_01_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_ANGEBOT_Info","outputIds":["ORG_862_Jacko_ANGEBOT_Info_15_01","ORG_862_Jacko_ANGEBOT_Info_06_02","ORG_862_Jacko_ANGEBOT_Info_15_03","ORG_862_Jacko_ANGEBOT_Info_06_04"],"lines":[{"speaker":"hero","text":{"pl":"Ich will euch ein Angebot machen!","en":"Ich will euch ein Angebot machen!","de":"Ich will euch ein Angebot machen!"}},{"speaker":"npc","text":{"pl":"Was für ein Angebot?","en":"Was für ein Angebot?","de":"Was für ein Angebot?"}},{"speaker":"hero","text":{"pl":"Das werde ich mit demjenigen bereden,der hier das Sagen hat.","en":"Das werde ich mit demjenigen bereden,der hier das Sagen hat.","de":"Das werde ich mit demjenigen bereden,der hier das Sagen hat."}},{"speaker":"npc","text":{"pl":"Na schön,dann rede mit Renyu. Aber keine faulen Tricks, sonst zerschlage ich jeden deiner Knochen einzeln!","en":"Na schön,dann rede mit Renyu. Aber keine faulen Tricks, sonst zerschlage ich jeden deiner Knochen einzeln!","de":"Na schön,dann rede mit Renyu. Aber keine faulen Tricks, sonst zerschlage ich jeden deiner Knochen einzeln!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_banditencamp_15_00_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_banditencamp_15_00_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_Banditencamp_Info","outputIds":["ORG_862_Jacko_Banditencamp_15_00","ORG_862_Jacko_Banditencamp_06_01"],"lines":[{"speaker":"hero","text":{"pl":"A więc to tutaj się zaszyliście.","en":"So this is where you sneaked off to.","de":"Hierher habt ihr euch also verkrümelt."}},{"speaker":"npc","text":{"pl":"Był blisko. Strażnicy z Sekty posiekaliby nas na dzwona.","en":"It was a close shave. The sect templars would have killed us.","de":"Es war knapp. Die Templer der Sekte hätten uns bestimmt kaltgemacht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_drugguard_info_15_01_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_drugguard_info_15_01_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_DRUGGUARD_Info","outputIds":["ORG_862_Jacko_DRUGGUARD_Info_15_01","ORG_862_Jacko_DRUGGUARD_Info_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Was machst du hier?","en":"Was machst du hier?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Gar nichts. Geh weg!","en":"Gar nichts. Geh weg!","de":"Gar nichts. Geh weg!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_go_away_info_06_00_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_go_away_info_06_00_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_GoAway_Info","outputIds":["ORG_862_Jacko_GoAway_Info_06_00"],"lines":[{"speaker":"npc","text":{"pl":"Czego tu do cholery szukasz?","en":"What the hell are you doing here?","de":"Was zum Teufel machst du hier?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_guard_angriff_info_15_00_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_guard_angriff_info_15_00_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_GUARD_Angriff","outputIds":["ORG_862_Jacko_GUARD_Angriff_Info_15_00","ORG_862_Jacko_GUARD_Angriff_Info_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Aby położyć kres całej tej sprawie!","en":"To put an end to the whole business here!","de":"Um der Sache hier ein Ende zu bereiten!"}},{"speaker":"npc","text":{"pl":"Chłopaki! Chodźcie no tu na chwilę!","en":"Guys! Just come over here for a minute!","de":"Jungs! Kommt doch mal kurz her!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_guard_info_06_00_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_guard_info_06_00_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_GUARD_Info","outputIds":["ORG_862_Jacko_GUARD_Info_06_00","ORG_862_Jacko_GUARD_Info_15_01","ORG_862_Jacko_GUARD_Info_06_02"],"lines":[{"speaker":"npc","text":{"pl":"Czyżbyśmy pobłądzili, hę?","en":"Lost our way, have we?","de":"Na, haben wir uns verlaufen?"}},{"speaker":"hero","text":{"pl":"Cor Kalom wie o waszym małym przedsięwzięciu.","en":"Cor Kalom knows about your little enterprise.","de":"Cor Kalom weiß von eurem kleinen Unternehmen."}},{"speaker":"npc","text":{"pl":"Co? Dlaczego tu jesteś?","en":"What? Why are you here?","de":"Was? Warum bist du hier?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_guard_info_wert_info_15_00_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_guard_info_wert_info_15_00_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_GUARD_InfoWert","outputIds":["ORG_862_Jacko_GUARD_InfoWert_Info_15_00","ORG_862_Jacko_GUARD_InfoWert_Info_06_01","ORG_862_Jacko_GUARD_InfoWert_Info_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Chcę wiedzieć ile ta informacja jest dla ciebie warta.","en":"I want to know what this information is worth to you.","de":"Ich will wissen, was dir diese Information wert ist."}},{"speaker":"npc","text":{"pl":"Ach, więc o to ci chodzi... No dobrze. Ty zrobisz coś dla mnie - ja zrobię coś dla ciebie. Proszę, to cała ruda jaką mam przy sobie.","en":"Oh, that''s what you want... Alright. You scratch my back and I''ll scratch yours. Here, this is all the ore I have on me.","de":"Ach so ist das... Gut. Eine Hand wäscht die andere. Hier, das ist alles Erz, was ich bei mir habe."}},{"speaker":"npc","text":{"pl":"Musimy już iść! Tobie zresztą też to radzę!","en":"We have to go! And you''d better disappear as well.","de":"Wir müssen weg! Und du verschwindest hier auch besser."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_guard_templer_info_15_00_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_guard_templer_info_15_00_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_GUARD_Templer","outputIds":["ORG_862_Jacko_GUARD_Templer_Info_15_00","ORG_862_Jacko_GUARD_Templer_Info_06_01","ORG_862_Jacko_GUARD_Templer_Info_15_02","ORG_862_Jacko_GUARD_Templer_Info_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Jestem tu, żeby was ostrzec. Cor Kalom wysłał pięciu Strażników Świątynnych, którzy mają was wykończyć.","en":"I''m here to warn you. Cor Kalom has sent five templars to finish you off.","de":"Ich will euch warnen. Cor Kalom hat fünf Templer geschickt, die euch den Garaus machen sollen."}},{"speaker":"npc","text":{"pl":"Że jak? Chyba żartujesz!","en":"What? You can''t be serious!","de":"Ach? Das glaubst du doch selbst nicht!"}},{"speaker":"hero","text":{"pl":"Mogą tu być w każdej chwili!","en":"They should arrive here any minute.","de":"Sie müßten jeden Moment hier sein."}},{"speaker":"npc","text":{"pl":"Niech to szlag! Musimy stąd wiać!","en":"Damn it! We have to leave!","de":"Verdammt! Wir müssen weg!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_862_jacko_org_862_jacko_kalom_info_15_01_0', 'ORG_862_Jacko', '{"id":"missions_dia_org_862_jacko_org_862_jacko_kalom_info_15_01_0","npcId":"ORG_862_Jacko","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_862_Jacko.d","sourceFunction":"ORG_862_Jacko_KALOM_Info","outputIds":["ORG_862_Jacko_KALOM_Info_15_01","ORG_862_Jacko_KALOM_Info_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Ich bin im Auftrag der Bruderschaft hier.","en":"Ich bin im Auftrag der Bruderschaft hier.","de":"Ich bin im Auftrag der Bruderschaft hier."}},{"speaker":"npc","text":{"pl":"Oh scheisse! Und da schicken die so einen wie dich?","en":"Oh scheisse! Und da schicken die so einen wie dich?","de":"Oh scheisse! Und da schicken die so einen wie dich?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_873_cipher_dia_cipher_fisk_15_00_0', 'ORG_873_Cipher', '{"id":"missions_dia_org_873_cipher_dia_cipher_fisk_15_00_0","npcId":"ORG_873_Cipher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_873_Cipher.d","sourceFunction":"Org_873_Cipher_Fisk_Info","outputIds":["DIA_Cipher_Fisk_15_00","DIA_Cipher_Fisk_12_01","DIA_Cipher_Fisk_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Fisk ze Starego Obozu szuka nowego partnera do interesów.","en":"Fisk from the Old Camp is looking for a trade partner.","de":"Fisk aus dem Alten Lager ist auf der Suche nach einem Handelspartner."}},{"speaker":"npc","text":{"pl":"Nie jestem zainteresowany.","en":"I''m not interested.","de":"Kein Interesse."}},{"speaker":"npc","text":{"pl":"Ale powinieneś porozmawiać z Sharkym. Może on na to pójdzie.","en":"But Sharky might be interested. If you find him, ask him.","de":"Aber Sharky könnte sich dafür interessieren. Wenn du ihn findest, frag ihn."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_873_cipher_dia_cipher_from_balor_15_00_0', 'ORG_873_Cipher', '{"id":"missions_dia_org_873_cipher_dia_cipher_from_balor_15_00_0","npcId":"ORG_873_Cipher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_873_Cipher.d","sourceFunction":"Org_873_Cipher_FromBalor_Info","outputIds":["DIA_Cipher_FromBalor_15_00","DIA_Cipher_FromBalor_12_01","DIA_Cipher_FromBalor_15_02","DIA_Cipher_FromBalor_12_03"],"lines":[{"speaker":"hero","text":{"pl":"Co masz do zaoferowania?","en":"What have you got to offer?","de":"Was hast du anzubieten?"}},{"speaker":"npc","text":{"pl":"Nie, nie! Pytanie brzmi: co TY masz do zaoferowania! Interesują mnie wyłącznie poważne dostawy.","en":"Let''s rephrase that question: What have YOU got to offer? I''m only interested in big consignments.","de":"Die Frage ist doch, was hast DU anzubieten. Ich bin nur an größeren Lieferungen interessiert."}},{"speaker":"hero","text":{"pl":"Balor powiedział mi, że interesuje cię bagienne ziele.","en":"Balor said you''d be interested in swampweed.","de":"Balor sagt, du hättest Interesse an etwas Sumpfkraut."}},{"speaker":"npc","text":{"pl":"Mhm. Masz coś na sprzedaż?","en":"Mhmmm. You want to trade?","de":"Hmmm. Du willst also handeln?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_873_cipher_dia_cipher_from_balor_15_04_4', 'ORG_873_Cipher', '{"id":"missions_dia_org_873_cipher_dia_cipher_from_balor_15_04_4","npcId":"ORG_873_Cipher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_873_Cipher.d","sourceFunction":"Org_873_Cipher_FromBalor_Info","outputIds":["DIA_Cipher_FromBalor_15_04","DIA_Cipher_FromBalor_12_05"],"lines":[{"speaker":"hero","text":{"pl":"Niestety nie.","en":"I can''t help you there.","de":"Damit kann ich nicht dienen."}},{"speaker":"npc","text":{"pl":"Więc wróć do mnie, jak będziesz miał coś co mnie zainteresuje.","en":"Then come back when you can help me.","de":"Dann komm wieder, wenn du es kannst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_873_cipher_dia_cipher_hello_12_04_4', 'ORG_873_Cipher', '{"id":"missions_dia_org_873_cipher_dia_cipher_hello_12_04_4","npcId":"ORG_873_Cipher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_873_Cipher.d","sourceFunction":"Org_873_Cipher_Hello_Info","outputIds":["DIA_Cipher_Hello_12_04"],"lines":[{"speaker":"npc","text":{"pl":"Nie. Napadamy go tylko wtedy, kiedy się to opłaca.","en":"No. Only when it''s worth it.","de":"Nein. Nur wenn sich ''ne lohnende Gelegenheit bietet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_873_cipher_dia_cipher_hello_15_00_0', 'ORG_873_Cipher', '{"id":"missions_dia_org_873_cipher_dia_cipher_hello_15_00_0","npcId":"ORG_873_Cipher","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_873_Cipher.d","sourceFunction":"Org_873_Cipher_Hello_Info","outputIds":["DIA_Cipher_Hello_15_00","DIA_Cipher_Hello_12_01","DIA_Cipher_Hello_12_02","DIA_Cipher_Hello_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać?","en":"How''s things?","de":"Wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Nasypaliśmy trochę piasku w machinę Gomeza.","en":"We put another spoke in Gomez'' wheel.","de":"Wir haben Gomez mal wieder ins Essen gespuckt."}},{"speaker":"npc","text":{"pl":"Trzech zabitych strażników i mnóstwo towaru na sprzedaż. Trzeba to opić!","en":"Three dead guards and lots of stuff to sell. I''ll drink to that!","de":"Drei tote Gardisten und ''ne ganze Menge Zeug zum Verhökern. Darauf trink ich!"}},{"speaker":"hero","text":{"pl":"Jesteś jednym z ludzi, którzy bez przerwy napadają Stary Obóz?","en":"You''re one of the guys who keep raiding the Old Camp?","de":"Du bist einer von den Jungs, die ständig das alte Lager überfallen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_888_erpresser_info_bereits_aufs_maul_info_13_02_0', 'ORG_888_Erpresser', '{"id":"missions_dia_org_888_erpresser_info_bereits_aufs_maul_info_13_02_0","npcId":"ORG_888_Erpresser","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_888_Erpresser.d","sourceFunction":"Info_BereitsAufsMaul_Info","outputIds":["Info_BereitsAufsMaul_Info_13_02"],"lines":[{"speaker":"npc","text":{"pl":"Spadaj zanim zetrę ten głupi uśmiech z twojej gęby!","en":"Get lost, before I wipe that dumb look off your face for you!","de":"Mach, dass du wegkommst, oder ich hau dir noch eins aufs Maul!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_888_erpresser_info_bereits_erpresst_info_13_02_0', 'ORG_888_Erpresser', '{"id":"missions_dia_org_888_erpresser_info_bereits_erpresst_info_13_02_0","npcId":"ORG_888_Erpresser","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_888_Erpresser.d","sourceFunction":"Info_BereitsErpresst_Info","outputIds":["Info_BereitsErpresst_Info_13_02"],"lines":[{"speaker":"npc","text":{"pl":"Zapłaciłeś - możesz przejść. Właź, zanim się rozmyślę.","en":"You''ve paid. You may pass. Now go before I change my mind.","de":"Du hast bezahlt. Du kannst vorbei. Geh jetzt, bevor ich''s mir anders überlege."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_888_erpresser_info_erpresser_choice_aufs_maul_15_01_0', 'ORG_888_Erpresser', '{"id":"missions_dia_org_888_erpresser_info_erpresser_choice_aufs_maul_15_01_0","npcId":"ORG_888_Erpresser","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_888_Erpresser.d","sourceFunction":"Info_Erpresser_Choice_AufsMaul","outputIds":["Info_Erpresser_Choice_AufsMaul_15_01","Info_Erpresser_Choice_AufsMaul_13_02"],"lines":[{"speaker":"hero","text":{"pl":"To dlaczego nie przyjdziesz tutaj i ich sobie nie weźmiesz!","en":"Then why don''t you come here and get your ore!","de":"Dann komm doch her und hol dir dein Erz!"}},{"speaker":"npc","text":{"pl":"Dzięki, stary. Właśnie zaczynałem się nudzić.","en":"Thanks, man. You just made my day.","de":"Danke, Mann. Du rettest mir den Tag."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_888_erpresser_info_erpresser_choice_zahlen_15_01_0', 'ORG_888_Erpresser', '{"id":"missions_dia_org_888_erpresser_info_erpresser_choice_zahlen_15_01_0","npcId":"ORG_888_Erpresser","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_888_Erpresser.d","sourceFunction":"Info_Erpresser_Choice_Zahlen","outputIds":["Info_Erpresser_Choice_Zahlen_15_01","Info_Erpresser_Choice_Zahlen_13_02","Info_Erpresser_Choice_Zahlen_15_03","Info_Erpresser_Choice_Zahlen_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Proszę, oto 10 bryłek.","en":"Here, 10 ore.","de":"Hier, 10 Erz."}},{"speaker":"npc","text":{"pl":"Jaka szkoda.","en":"A shame.","de":"Schade."}},{"speaker":"hero","text":{"pl":"Ummm... Nie mam przy sobie 10 bryłek.","en":"Umm... I just don''t have 10 ore right now...","de":"Ähm... hab'' gerade keine 10 Erz..."}},{"speaker":"npc","text":{"pl":"Wielka szkoda...","en":"That''s a shame...","de":"Das ist aber schade..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_org_888_erpresser_info_erpresser_info_13_01_0', 'ORG_888_Erpresser', '{"id":"missions_dia_org_888_erpresser_info_erpresser_info_13_01_0","npcId":"ORG_888_Erpresser","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_ORG_888_Erpresser.d","sourceFunction":"Info_Erpresser_Info","outputIds":["Info_Erpresser_Info_13_01"],"lines":[{"speaker":"npc","text":{"pl":"Hej, chłopcze! Jeśli chcesz wejść do środka, będziesz musiał zapłacić 10 bryłek, kapujesz?","en":"Hey, boy, if you want to pass, you have to pay 10 ore or you''ll be whacked, got it?","de":"Hey, Junge, wenn du hier vorbei willst, mußt du 10 Erz zahlen, oder du bekommst aufs Maul, kapiert?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_dia_gorn_become_sld_15_00_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_dia_gorn_become_sld_15_00_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"DIA_Gorn_BecomeSLD_Info","outputIds":["DIA_Gorn_BecomeSLD_15_00","DIA_Gorn_BecomeSLD_09_01","DIA_Gorn_BecomeSLD_09_02","DIA_Gorn_BecomeSLD_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Co mam zrobić, żeby zostać członkiem Nowego Obozu?","en":"What do I have to do to join the New Camp?","de":"Was muss ich tun, um im Neuen Lager aufgenommen zu werden?"}},{"speaker":"npc","text":{"pl":"Musisz trochę popracować nad swoimi umiejętnościami bojowymi, zanim Lee zgodzi się cię przyjąć. Nieważne w jakiej broni się specjalizujesz, byleś był w tym dobry.","en":"Before Lee admits you, you''ll have to improve your fighting skills. It doesn''t matter what weapon you use, but you have to be good.","de":"Bevor dich Lee aufnimmt, musst du lernen, besser zu kämpfen. Egal, mit welcher Waffe, aber du musst gut sein."}},{"speaker":"npc","text":{"pl":"Oprócz tego powinieneś mieć chociaż ogólne pojęcie o życiu w kolonii, układach między obozami, i takie tam...","en":"Besides, you should be very experienced with the life here and everything.","de":"Außerdem musst du viel Erfahrung haben mit dem Leben hier und allem."}},{"speaker":"npc","text":{"pl":"Jeśli nie interesują cię inne obozy, spróbuj na początek dołączyć do Szkodników. Na zostanie Najemnikiem jeszcze przyjdzie czas.","en":"If you don''t want to go to the other camps, you should try to join the rogues before you start as a mercenary.","de":"Wenn du keine Lust hast, in die anderen Lager zu gehen, solltest du dich den Banditen anschließen, bevor du als Söldner anfängst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_dia_gorn_du_hehler_15_00_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_dia_gorn_du_hehler_15_00_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"DIA_Gorn_DuHehler_Info","outputIds":["DIA_Gorn_DuHehler_15_00","DIA_Gorn_DuHehler_09_01","DIA_Gorn_DuHehler_15_02","DIA_Gorn_DuHehler_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak to możliwe, że wziąłeś udział w jednym z napadów zorganizowanych przez tę bandę?","en":"Why did you take part in one of the gang''s raids?","de":"Wie kommt es, dass du dich an einem Überfall der Bande beteiligt hast?"}},{"speaker":"npc","text":{"pl":"A kto twierdzi, że wziąłem?","en":"Who says I did?","de":"Wer sagt, dass es so war?"}},{"speaker":"hero","text":{"pl":"Skąd mógłbyś wziąć taką ilość towaru, gdybyś nie uczestniczył w napadzie.","en":"Why would you have so much of the stuff if it wasn''t true?","de":"Warum hast du sonst so viel von diesem Zeug?"}},{"speaker":"npc","text":{"pl":"Naprawdę myślisz, że taką ilość towaru można zebrać po JEDNYM głupim napadzie?","en":"Don''t you think that this is all from ONE haul.","de":"Denk bloß nicht, dass das alles von EINEM Fischzug kommt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_dia_gorn_du_hehler_15_04_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_dia_gorn_du_hehler_15_04_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"DIA_Gorn_DuHehler_Info","outputIds":["DIA_Gorn_DuHehler_15_04","DIA_Gorn_DuHehler_09_05","DIA_Gorn_DuHehler_15_06"],"lines":[{"speaker":"hero","text":{"pl":"To znaczy, że uczestniczysz w nich regularnie?","en":"You take part in raids regularly?","de":"Du beteiligst dich regelmäßig an den Überfällen?"}},{"speaker":"npc","text":{"pl":"Nawet gdyby tak było, nie mógł bym ci o tym powiedzieć. Lee dałby mi zdrowo popalić.","en":"If I did, I couldn''t tell you. Lee wouldn''t like that one bit.","de":"Wenn es so wäre, könnte ich es dir nicht sagen. Lee sieht so was nämlich gar nicht gerne."}},{"speaker":"hero","text":{"pl":"Rozumiem.","en":"I see.","de":"Verstehe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_dia_gorn_hut_09_04_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_dia_gorn_hut_09_04_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"DIA_Gorn_Hut_Info","outputIds":["DIA_Gorn_Hut_09_04","DIA_Gorn_Hut_09_05"],"lines":[{"speaker":"npc","text":{"pl":"No nas, Najemników. Najemnicy i Szkodniki starają się nie włazić sobie w drogę. Ludzie Laresa nie mają wstępu do tej części obozu.","en":"Well, us mercenaries. Mercenaries and rogues live separately here. And none of Lares'' gang should be here, on this side of the big hole.","de":"Den Söldnern eben. Söldner und Banditen leben hier getrennt. Und normalerweise hat keiner aus Lares'' Bande was auf dieser Seite des großen Loches zu suchen."}},{"speaker":"npc","text":{"pl":"W sumie to drobiazg, ale sukinsyn nie zapytał nawet o pozwolenie. Tym Szkodnikom nie można pozwolić na zbyt wiele, bo zrobią się nie do wytrzymania.","en":"It doesn''t make much difference really. But he didn''t ask. And you can''t let those rogues get away with everything, because then they get real cocky!","de":"Im Grunde ist es völlig egal. Aber er hat niemanden gefragt. Und man kann den Banditen nicht alles durchgehen lassen, sonst werden sie aufmüpfig!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_dia_gorn_hut_15_00_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_dia_gorn_hut_15_00_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"DIA_Gorn_Hut_Info","outputIds":["DIA_Gorn_Hut_15_00","DIA_Gorn_Hut_09_01","DIA_Gorn_Hut_09_02","DIA_Gorn_Hut_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Czy w Obozie są jeszcze wolne miejsca, czy będę musiał wykopać kogoś z jego chaty?","en":"Can I stay somewhere here without having to kick somebody out of his hut?","de":"Kann ich hier irgendwo pennen, ohne dass ich vorher jemanden aus seiner Hütte prügeln muss?"}},{"speaker":"npc","text":{"pl":"Chyba będziesz musiał. Jeśli naprawdę chcesz to zrobić, zacznij od Krzykacza.","en":"I don''t think so. But if that''s really what you want to do, go and see Shrike.","de":"Ich fürchte nicht. Aber wenn du das wirklich vorhast, geh zu Shrike."}},{"speaker":"npc","text":{"pl":"Złapał dla siebie chatę przy samym wejściu do jaskini. Była pusta, ale tak naprawdę należała do nas.","en":"He''s taken the hut right at the front, at the entrance to the cave. It was empty - but it really belonged to us.","de":"Er hat sich die Hütte ganz vorne am Höhleneingang geschnappt. Sie stand leer - aber eigentlich gehörte sie uns."}},{"speaker":"hero","text":{"pl":"Nas?","en":"Us?","de":"Uns?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_dia_gorn_hut_free_15_00_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_dia_gorn_hut_free_15_00_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"DIA_Gorn_HutFree_Info","outputIds":["DIA_Gorn_HutFree_15_00","DIA_Gorn_HutFree_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Krzykacz przeniósł się już do innej chaty.","en":"Shrike has moved to another hut.","de":"Shrike hat sich eine andere Hütte gesucht."}},{"speaker":"npc","text":{"pl":"Świetnie! Przed chwilą Torlof powiedział, że zamierza pokazać temu chłoptasiowi, gdzie jest jego miejsce.","en":"Good. Torlof just told me that he wanted to have a word with the guy.","de":"Gut. Gerade noch hat mich Torlof drauf angesprochen, dass er dem Burschen das Fell über die Ohren ziehen wollte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_dia_gorn_leben_15_00_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_dia_gorn_leben_15_00_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"DIA_Gorn_Leben_Info","outputIds":["DIA_Gorn_Leben_15_00","DIA_Gorn_Leben_09_01","DIA_Gorn_Leben_09_02","DIA_Gorn_Leben_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Czym się zajmują Najemnicy?","en":"What do you have to do as a mercenary of the magicians?","de":"Was machst du als Söldner der Magier?"}},{"speaker":"npc","text":{"pl":"Lee zawarł z Magami umowę. Zatrudnia najlepszych wojowników z całej kolonii - czyli nas.","en":"Lee has made a deal with the magicians. He hires the best fighters to be found in the colony. Which means us.","de":"Lee hat mit den Magiern eine Abmachung getroffen. Er heuert die besten Kämpfer an, die in der Kolonie zu finden sind. Also uns."}},{"speaker":"npc","text":{"pl":"Pilnujemy, żeby nikt nie przeszkadzał Kretom w pracy i dbamy o bezpieczeństwo Magów.","en":"We take care that the scrapers can mine the ore without being bothered and keep trouble away from the magicians.","de":"Wir sorgen dafür, dass die Schürfer ungestört Erz abbauen können und halten den Magiern den Rücken frei."}},{"speaker":"npc","text":{"pl":"Magowie natomiast przygotowują plan, który pozwoli się nam stąd wyrwać. Jako wynagrodzenie otrzymujemy trochę rudy.","en":"The magicians make sure we''ll get out of here. And we get a small share of the ore as our pay.","de":"Die Magier kümmern sich darum, dass wir hier rauskommen. Und einen kleinen Teil des Erzes bekommen wir als Sold."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_afterfm_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_afterfm_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_AFTERFM_Info","outputIds":["Info_Gorn_AFTERFM_09_01","Info_Gorn_AFTERFM_09_02","Info_Gorn_AFTERFM_15_03","Info_Gorn_AFTERFM_09_04"],"lines":[{"speaker":"npc","text":{"pl":"Stary, to się dopiero nazywa trudna walka!","en":"Oh, man. That was a really tough fight.","de":"Oh, Mann. Das war ein wirklich beinharter Kampf."}},{"speaker":"npc","text":{"pl":"Nie spodziewałem się, że Strażnicy Gomeza będą stawiali tak zaciekły opór.","en":"I''d never have thought Gomez'' guards would offer that much resistance.","de":"Hätte nicht gedacht, dass Gomez'' Gardisten so viel Widerstand leisten."}},{"speaker":"hero","text":{"pl":"Grunt, że kopalnia znowu jest w naszych rękach.","en":"The main thing is that we''ve driven them out of our mine again.","de":"Die Hauptsache ist, dass wir sie wieder aus unserer Mine vertrieben haben!"}},{"speaker":"npc","text":{"pl":"Zostanę tutaj i dopilnuję, żeby tak już zostało!","en":"I''ll stay here and make sure it stays that way!","de":"Ich werde hier bleiben und dafür sorgen, dass das auch so bleibt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_cronos_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_cronos_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_CRONOS_Info","outputIds":["Info_Gorn_CRONOS_15_01","Info_Gorn_CRONOS_09_01a","Info_Gorn_CRONOS_09_02","Info_Gorn_CRONOS_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę tego \"strażnika rudy\"?","en":"Where can I find this ''keeper of the ore''?","de":"Wo finde ich diesen ''Hüter des Erzes''?"}},{"speaker":"npc","text":{"pl":"Idąc stąd trafisz na wielką jaskinię mieszkalną, niedaleko tamy.","en":"If you proceed from here, you''ll come across the big dwelling cave behind the dam.","de":"Wenn du von hier weitergehst, stößt du nach dem Damm auf die große Wohnhöhle."}},{"speaker":"npc","text":{"pl":"Cronos przebywa zwykle obok kraty broniącej dostępu do kopca rudy.","en":"Cronos is usually at the grid over the big ore mound.","de":"Cronos hält sich normalerweise am Gitter über dem großen Erzhaufen auf."}},{"speaker":"npc","text":{"pl":"Ale to nieco arogancki człowiek. Będziesz musiał go jakoś przekonać, że twoja wiadomość jest naprawdę ważna.","en":"But he''s a bit arrogant. You''ll have to convince him that your message is important.","de":"Aber er ist ein wenig arrogant. Du wirst ihn überzeugen müssen, dass deine Botschaft wichtig ist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_diegomilten_09_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_diegomilten_09_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_DIEGOMILTEN_Info","outputIds":["Info_Gorn_DIEGOMILTEN_09_05"],"lines":[{"speaker":"npc","text":{"pl":"Jesteś już prawie jednym z nas. Udowodniłeś, że można na tobie polegać!","en":"You''re almost one of us by now. You''re reliable!","de":"Auch du gehörst mittlerweile schon fast zu uns. Auf dich ist Verlass!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_diegomilten_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_diegomilten_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_DIEGOMILTEN_Info","outputIds":["Info_Gorn_DIEGOMILTEN_15_01","Info_Gorn_DIEGOMILTEN_09_02","Info_Gorn_DIEGOMILTEN_15_03","Info_Gorn_DIEGOMILTEN_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Spotkałem Diego i Miltena przed Starym Obozem!","en":"I met Diego and Milten in front of the Old Camp!","de":"Ich habe Diego und Milten vor dem Alten Lager getroffen!"}},{"speaker":"npc","text":{"pl":"To dobra wiadomość!","en":"That''s good news!","de":"Eine gute Nachricht!"}},{"speaker":"hero","text":{"pl":"Mają się spotkać z tobą i z Lesterem w zwykłym miejscu.","en":"They want to meet you and Lester. At your usual rendezvous.","de":"Sie wollen sich mit dir und Lester treffen. An eurem üblichen Treffpunkt."}},{"speaker":"npc","text":{"pl":"Dzięki. W dzisiejszych czasach nie ma nic cenniejszego niż kilku oddanych przyjaciół.","en":"Thanks. There''s nothing more valuable than good friends in troubled times like these.","de":"Danke. In diesen turbulenten Zeiten sind gute Freunde unersetzlich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_exit_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_exit_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_EXIT_Info","outputIds":["Info_Gorn_EXIT_09_01","Info_Gorn_EXIT_09_02"],"lines":[{"speaker":"npc","text":{"pl":"Do boju!","en":"Let''s fight!","de":"Auf in den Kampf!"}},{"speaker":"npc","text":{"pl":"Do zobaczenia.","en":"See you later.","de":"Bis später."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_fmcentrance_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_fmcentrance_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_FMCENTRANCE_Info","outputIds":["Info_Gorn_FMCENTRANCE_09_01","Info_Gorn_FMCENTRANCE_09_02","Info_Gorn_FMCENTRANCE_09_03"],"lines":[{"speaker":"npc","text":{"pl":"Zaczekaj! Widzisz te wszystkie ciała?","en":"Hold on, do you see all these corpses?","de":"Warte mal, siehst du all die Leichen hier?"}},{"speaker":"npc","text":{"pl":"Idź do wejścia do kopalni. Ja zaczekam tutaj i przypilnuję, żeby ktoś lub coś nie zaszło nas od tyłu.","en":"You go down to the entrance to the mine, I''ll stay here and make sure that we don''t get a nasty surprise thrown at us from behind.","de":"Geh du runter zum Mineneingang, ich bleib'' erst mal hier oben und stelle sicher, dass es keine Überraschung von hinten gibt."}},{"speaker":"npc","text":{"pl":"Kiedy już zejdziesz na dół, pójdę za tobą.","en":"When you''re down there, I''ll follow.","de":"Wenn du unten bist, komme ich nach."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_fmgate_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_fmgate_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_FMGATE_Info","outputIds":["Info_Gorn_FMGATE_09_01","Info_Gorn_FMGATE_15_02","Info_Gorn_FMGATE_09_03"],"lines":[{"speaker":"npc","text":{"pl":"Usłyszałem odgłosy walki i przybiegłem najszybciej jak mogłem!","en":"I heard you fighting and went after you immediately.","de":"Ich hörte dich kämpfen, da bin ich sofort hinterher."}},{"speaker":"hero","text":{"pl":"Stary znajomy... Rachunek wyrównany.","en":"An old acquaintance... But that account is settled.","de":"Ein alter Bekannter ... aber die Rechnung ist beglichen."}},{"speaker":"npc","text":{"pl":"Dobra, otwieraj bramę. Je będę tu stał na straży!","en":"Good, open the gate, I''ll watch out.","de":"Gut, öffne du das Tor, ich pass'' hier auf!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_fmwatch_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_fmwatch_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_FMWATCH_Info","outputIds":["Info_Gorn_FMWATCH_15_01","Info_Gorn_FMWATCH_09_02","Info_Gorn_FMWATCH_09_03","Info_Gorn_FMWATCH_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać?","en":"How''s the situation?","de":"Wie ist die Lage?"}},{"speaker":"npc","text":{"pl":"Na razie cicho. W Wolnej Kopalni nic się nie rusza.","en":"Everything''s quiet. Nothing moving in the Free Mine.","de":"Alles ruhig. In der Freien Mine rührt sich nichts."}},{"speaker":"npc","text":{"pl":"Lee powinien niedługo podesłać tu posiłki.","en":"It can''t be long now till Lee sends reinforcements up here.","de":"Es kann nicht mehr lange dauern, bis Lee die Verstärkung hier hoch schickt."}},{"speaker":"npc","text":{"pl":"Póki co postaram się tutaj rozgościć.","en":"I''ll just make myself at home until then.","de":"So lange werde ich es mir hier gemütlich machen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_foundulumulu_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_foundulumulu_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_FOUNDULUMULU_Info","outputIds":["Info_Gorn_FOUNDULUMULU_09_01","Info_Gorn_FOUNDULUMULU_09_02","Info_Gorn_FOUNDULUMULU_15_03","Info_Gorn_FOUNDULUMULU_09_04"],"lines":[{"speaker":"npc","text":{"pl":"Masz przy sobie ciekawą ozdóbkę. Orkowa, prawda?","en":"That''s an interesting Orc standard you have there.","de":"Eine interessante Ork-Standarte, die du da hast."}},{"speaker":"npc","text":{"pl":"To od tego niewolnika z kopalni?","en":"Is that from the former Orc slave in the mine?","de":"Stammt sie von dem befreiten Ork-Sklaven in der Mine?"}},{"speaker":"hero","text":{"pl":"To orkowy symbol przyjaźni. Przy jego pomocy zamierzam dostać się do miasta Orków.","en":"It''s an Orcish symbol for friendship. I want to enter the Orc town with it.","de":"Es ist ein orkisches Symbol für Freundschaft. Ich will damit die Stadt der Orks betreten."}},{"speaker":"npc","text":{"pl":"Oby tylko Orkowie uszanowali to... COŚ!","en":"I hope for your sake that the Orcs will respect this... THING!","de":"Ich hoffe für dich, die Orks respektieren dieses ... ETWAS!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_freemine_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_freemine_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_FREEMINE_Info","outputIds":["Info_Gorn_FREEMINE_15_01","Info_Gorn_FREEMINE_09_02","Info_Gorn_FREEMINE_09_03","Info_Gorn_FREEMINE_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Co zobaczyłeś w Wolnej Kopalni?","en":"What did you see in the Free Mine?","de":"Was hast du in der Freien Mine gesehen?"}},{"speaker":"npc","text":{"pl":"Po powrocie ze starego klasztoru chciałem złożyć wizytę Okylowi, szefowi Wolnej Kopalni.","en":"After I returned from the ruined monastery, I wanted to drop by at Okyl''s, the boss of the Free Mine.","de":"Nachdem ich von der Klosterruine zurückkam, wollte ich einen Abstecher zu Okyl, dem Boss der Freien Mine, machen."}},{"speaker":"npc","text":{"pl":"Ale gdy dotarłem na miejsce, zastałem tylko stygnące ciała.","en":"But when I arrived, there were corpses lying everywhere.","de":"Doch als ich ankam, lagen überall Leichen herum."}},{"speaker":"npc","text":{"pl":"Dostrzegłem kilku Strażników okopujących się przy wejściu do kopalni.","en":"I just spotted some guards entrenching themselves at the entrance to the mine.","de":"Ich konnte gerade noch sehen, wie sich einige Gardisten im Mineneingang verschanzten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_freemine_15_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_freemine_15_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_FREEMINE_Info","outputIds":["Info_Gorn_FREEMINE_15_05","Info_Gorn_FREEMINE_09_06","Info_Gorn_FREEMINE_09_07"],"lines":[{"speaker":"hero","text":{"pl":"Jak to możliwe, że duży oddział Najemników uległ garstce Strażników?","en":"How could so many mercenaries be defeated by only two dozen guards?","de":"Wie konnten so viele Söldner zwei Dutzend Gardisten unterliegen?"}},{"speaker":"npc","text":{"pl":"To musiała być jakaś zasadzka. W końcu kto mógłby się spodziewać ataku od strony gór?","en":"It looked like an ambush to me. Nobody would have expected attackers to cross the mountains.","de":"Sah mir sehr nach einem Angriff aus dem Hinterhalt aus! Niemand hätte erwartet, dass Angreifer über die Berge kommen würden."}},{"speaker":"npc","text":{"pl":"Element zaskoczenia może zwielokrotnić zdolności bojowe oddziału.","en":"The element of surprise can multiply the force of a troop.","de":"Das Überraschungsmoment kann die Stärke einer Truppe vervielfachen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_guardnc_09_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_guardnc_09_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_GUARDNC_Info","outputIds":["Info_Gorn_GUARDNC_09_05","Info_Gorn_GUARDNC_09_06"],"lines":[{"speaker":"npc","text":{"pl":"Jeszcze nie, ale wkrótce na pewno to zrobimy.","en":"Not yet, but the day will come.","de":"Noch nicht, aber der Tag wird kommen!"}},{"speaker":"npc","text":{"pl":"Gdybyś mnie kiedyś potrzebował, zacznij tutaj i idź w stronę kopalni. Będę tam stał na straży.","en":"If ever you''re looking for me, start here and walk towards the mine. I''ll be on guard there.","de":"Wenn du mich suchst, gehe von hier in Richtung Mine. Dort werde ich meinen Posten beziehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_guardnc_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_guardnc_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_GUARDNC_Info","outputIds":["Info_Gorn_GUARDNC_15_01","Info_Gorn_GUARDNC_09_02","Info_Gorn_GUARDNC_09_03","Info_Gorn_GUARDNC_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Co zamierzasz robić dalej?","en":"What have you got planned now?","de":"Was hast du jetzt vor?"}},{"speaker":"npc","text":{"pl":"Musimy zmienić całą naszą strategię obrony. To trochę potrwa.","en":"Our entire defense strategy will have to be changed. That takes time.","de":"Die gesamte Verteidigung unseres Lagers muss nun umgestellt werden. Das braucht Zeit."}},{"speaker":"npc","text":{"pl":"Dopóki Lee nie zdoła przeorganizować swoich oddziałów, dołączę do prowizorycznej straży Corda.","en":"Until Lee and his people are ready, I''ll join Cord''s provisional guard.","de":"Bis Lee und seine Leute so weit sind, werde ich mich erst mal Cords provisorischen Wachposten anschließen."}},{"speaker":"hero","text":{"pl":"Przygotowujecie się do kontrataku?","en":"Are you planning a counterattack?","de":"Plant ihr einen Gegenschlag?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_guardncrunning_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_guardncrunning_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_GUARDNCRUNNING_Info","outputIds":["Info_Gorn_GUARDNCRUNNING_15_01","Info_Gorn_GUARDNCRUNNING_09_02","Info_Gorn_GUARDNCRUNNING_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak leci?","en":"How''s it going?","de":"Wie ist die Lage?"}},{"speaker":"npc","text":{"pl":"Na razie cicho. W Wolnej Kopalni nic się nie rusza.","en":"Everything''s quiet. Nothing''s moving in the Free Mine.","de":"Alles ruhig. In der Freien Mine rührt sich nichts."}},{"speaker":"npc","text":{"pl":"Lee zajmuje się jeszcze organizacją naszej obrony!","en":"Lee is still busy organizing our defense!","de":"Lee ist noch damit beschäftigt, unsere Verteidigung zu organisieren!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_kickbutt_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_kickbutt_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_KICKBUTT_Info","outputIds":["Info_Gorn_KICKBUTT_15_01","Info_Gorn_KICKBUTT_09_02","Info_Gorn_KICKBUTT_09_03"],"lines":[{"speaker":"hero","text":{"pl":"No dobrze, chodźmy. Nauczymy tych nieproszonych gości dobrych manier.","en":"Okay, let''s go and teach the unwelcome guests in the mine a lesson!","de":"Okay, lass uns den ungebetenen Gästen in der Mine kräftig in den Hintern treten!"}},{"speaker":"npc","text":{"pl":"Wiedziałem, że można na ciebie liczyć.","en":"I didn''t expect you to say anything else!","de":"Nichts anderes habe ich von dir erwartet!"}},{"speaker":"npc","text":{"pl":"Weź ten klucz. Otwiera stróżówkę przy wejściu do kopalni.","en":"Here, take this key. It opens the gatehouse in front of the entrance to the mine.","de":"Hier, nimm diesen Schlüssel. Er öffnet das Torhaus vor dem Eingang der Mine."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_leaveforpost_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_leaveforpost_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_LEAVEFORPOST_Info","outputIds":["Info_Gorn_LEAVEFORPOST_09_01","Info_Gorn_LEAVEFORPOST_09_02","Info_Gorn_LEAVEFORPOST_09_03"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że jednak nie chcesz porozmawiać z Wilkiem!","en":"Looks like you do want to speak to Wolf!","de":"Du scheinst doch noch mit Wolf sprechen zu wollen!"}},{"speaker":"npc","text":{"pl":"Idziesz w złą stronę! Mamy iść prosto do kopalni!","en":"This is the wrong direction! We have to go to the mine!","de":"Du läufst in die falsche Richtung! Wir müssen zur Mine!"}},{"speaker":"npc","text":{"pl":"Zaczekam na ciebie przy prowizorycznym punkcie strażniczym!","en":"I''ll wait for you at the provisional guardpost!","de":"Ich warte am provisorischen Wachposten auf dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_mages_09_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_mages_09_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_MAGES_Info","outputIds":["Info_Gorn_MAGES_09_05"],"lines":[{"speaker":"npc","text":{"pl":"Ja nie, ale Cronos, strażnik rudy może udzielić ci pozwolenia na spotkanie z Saturasem.","en":"I can''t, but Cronos, the keeper of the ore, might be able to give you permission.","de":"Ich nicht, aber Cronos, der Hüter des Erzes, kann dir vielleicht eine Erlaubnis erteilen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_mages_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_mages_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_MAGES_Info","outputIds":["Info_Gorn_MAGES_15_01","Info_Gorn_MAGES_09_02","Info_Gorn_MAGES_09_03","Info_Gorn_MAGES_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Mam ważną wiadomość dla Magów Wody!","en":"I have an important message for the Magicians of Water!","de":"Ich habe eine wichtige Botschaft für die Wassermagier!"}},{"speaker":"npc","text":{"pl":"W takim razie powinieneś zgłosić się do Saturasa. To najwyższy z Magów Wody. Jak go znam, siedzi teraz nad jakąś magiczną księgą albo czymś w tym stylu.","en":"Then you should talk to Saturas. He''s the highest of the water mages and spends all day studying some writings or other.","de":"Dann sprich am besten gleich mit Saturas. Er ist der oberste Wassermagier und studiert den ganzen Tag irgendwelche Schriften."}},{"speaker":"npc","text":{"pl":"Ale niezależnie od tego jak ważne są wieści, które przynosisz, strażnicy z górnego poziomu nie pozwolą ci się z nim zobaczyć.","en":"But no matter how important your message is, the guards of the upper level won''t let you through to him.","de":"Aber egal, wie wichtig die Botschaft auch ist, die Wachen zur oberen Ebene werden dich nicht zu ihm durch lassen."}},{"speaker":"hero","text":{"pl":"A nie mógłbyś się za mną wstawić?","en":"Can''t you put in a good word for me?","de":"Kannst du nicht ein gutes Wort für mich einlegen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_myway_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_myway_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_MYWAY_Info","outputIds":["Info_Gorn_MYWAY_15_01","Info_Gorn_MYWAY_09_02","Info_Gorn_MYWAY_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Czemu nie. I tak muszę dostać się do kopalni!","en":"Why not. I need to get into the mine anyway!","de":"Warum nicht. Ich muss ohnehin in die Mine!"}},{"speaker":"npc","text":{"pl":"Nieważne DLACZEGO to robisz. Cieszę się, że jesteś z nami!","en":"Whatever YOUR reasons may be, I''m glad we''re dealing with this thing together!","de":"Was immer auch DEINE Gründe sein mögen, ich bin froh, dass wir diese Sache gemeinsam erledigen!"}},{"speaker":"npc","text":{"pl":"Weź ten klucz. Otwiera stróżówkę przy wejściu do kopalni.","en":"Here, take this key. It opens the gatehouse in front of the entrance to the mine.","de":"Hier, nimm diesen Schlüssel. Er öffnet das Torhaus vor dem Eingang der Mine."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ncwait_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ncwait_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_NCWAIT_Info","outputIds":["Info_Gorn_NCWAIT_09_01","Info_Gorn_NCWAIT_09_02","Info_Gorn_NCWAIT_15_03"],"lines":[{"speaker":"npc","text":{"pl":"Ach, to ty! Mój przyjaciel z obozu na bagnie, Lester, doniósł mi o twoich dokonaniach.","en":"Ahh, it''s you! My friend Lester from the swamp camp told me all you did there.","de":"Ahh, du bist es! Mein Freund Lester aus dem Sumpflager hat mir erzählt, was du dort alles vollbracht hast."}},{"speaker":"npc","text":{"pl":"Jak na kogoś, kto jest tu od niedawna, zaszedłeś całkiem daleko.","en":"For somebody who hasn''t been here for long, you''ve come quite a way.","de":"Für jemanden, der noch nicht so lange hier ist, hast du es schon weit gebracht."}},{"speaker":"hero","text":{"pl":"Parę razy zaszedłem nawet na skraj własnego grobu.","en":"I came quite close to becoming worm food a few times, too.","de":"Es hat oft nicht viel gefehlt, und ich wäre als Futter für die Würmer geendet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_post_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_post_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_POST_Info","outputIds":["Info_Gorn_POST_09_01","Info_Gorn_POST_09_02"],"lines":[{"speaker":"npc","text":{"pl":"Przybywasz w samą porę! Przygotowujemy się do kontruderzenia.","en":"You''re just in time! We''re preparing our counterattack.","de":"Du kommst gerade richtig! Wir bereiten uns auf den Gegenschlag vor."}},{"speaker":"npc","text":{"pl":"Na początek spróbujemy odbić Wolną Kopalnię.","en":"Taking back the Free Mine is the first step.","de":"Die Rückeroberung der Freien Mine ist der erste Schritt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_razor_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_razor_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RAZOR_Info","outputIds":["Info_Gorn_RAZOR_09_01","Info_Gorn_RAZOR_09_02","Info_Gorn_RAZOR_09_03"],"lines":[{"speaker":"npc","text":{"pl":"UWAGA! BRZYTWY!","en":"WATCH OUT, RAZORS!!!","de":"VORSICHT, RAZORS!!!"}},{"speaker":"npc","text":{"pl":"Polują w stadach, jak zębacze, tylko gryzą znacznie mocniej!","en":"They hunt in packs like snappers, but they bite much harder!","de":"Die arbeiten genauso in Rudeln wie die Snapper, nur dass sie viel heftiger zubeißen!"}},{"speaker":"npc","text":{"pl":"Powinniśmy się najpierw z nimi rozprawić. Znasz mnie - lubię wiedzieć, co mam za plecami.","en":"We should do away with them. You know me, I like to know what''s at my back.","de":"Wir sollten sie aus dem Weg räumen! Du weißt ja, ich habe gerne einen freien Rücken!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_rejoinforfm_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_rejoinforfm_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_REJOINFORFM_Info","outputIds":["Info_Gorn_REJOINFORFM_15_01","Info_Gorn_REJOINFORFM_09_02","Info_Gorn_REJOINFORFM_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Ruszamy do kopalni!","en":"Let''s set out for the mine!","de":"Es kann losgehen! Auf zur Mine!"}},{"speaker":"npc","text":{"pl":"Pora przepędzić stamtąd ludzi Gomeza!","en":"It''s time to drive the guards out of there!","de":"Höchste Zeit, dass wir die Gardisten von dort vertreiben!"}},{"speaker":"npc","text":{"pl":"Idź przodem. Pójdę za tobą.","en":"You go on ahead, I''ll follow!","de":"Geh du vor, ich folge dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinabyss_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinabyss_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINABYSS_Info","outputIds":["Info_Gorn_RUINABYSS_09_01","Info_Gorn_RUINABYSS_09_02"],"lines":[{"speaker":"npc","text":{"pl":"To się nazywa szczęście! Najwyraźniej ta jaskinia była wykorzystywana jako składowisko.","en":"That''s what I call luck. Apparently this used to be a storage cave.","de":"Das nenne ich Glück. Hier scheint eine Vorratshöhle gewesen zu sein."}},{"speaker":"npc","text":{"pl":"Możesz teraz prowadzić do klasztoru. Chciałem mieć pewność, że nie spotkają nas jakieś paskudne niespodzianki w drodze powrotnej.","en":"Why don''t you take the lead now, I just wanted to make sure that we won''t be surprised on our return trip.","de":"Übernimm du jetzt die Führung, ich wollte nur sicherstellen, dass bei unserer Rückkehr hier keine Überraschung auf uns wartet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinfocus_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinfocus_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINFOCUS_Info","outputIds":["Info_Gorn_RUINFOCUS_15_01","Info_Gorn_RUINFOCUS_15_02","Info_Gorn_RUINFOCUS_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Szukam magicznego kamienia ogniskującego.","en":"I''m looking for a magic focus.","de":"Ich suche einen magischen Fokus."}},{"speaker":"hero","text":{"pl":"Powinien być gdzieś w okolicy.","en":"It must be somewhere in this area.","de":"Er muss irgendwo in dieser Gegend sein."}},{"speaker":"npc","text":{"pl":"Przedmiot, którego szukasz może znajdować się na terenie starego klasztoru, za tym kanionem.","en":"The thing you''re looking for might be in the old ruined monastery beyond the canyon.","de":"Was du suchst, befindet sich vielleicht innerhalb der Klosterruinen dort jenseits der Schlucht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruingate_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruingate_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINGATE_Info","outputIds":["Info_Gorn_RUINGATE_09_01","Info_Gorn_RUINGATE_15_02"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że udało ci się otworzyć tę bramę. To zaklęcie, którego użyłeś było całkiem sprytne.","en":"You actually managed to open the gate. That spell of yours was real clever.","de":"Du hast es tatsächlich geschafft, das Tor zu öffnen. Das mit dem Zauber war wirklich clever."}},{"speaker":"hero","text":{"pl":"No, możemy iść dalej.","en":"And on we go, come on.","de":"Los, weiter geht''s."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791210);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinjoin_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinjoin_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINJOIN_Info","outputIds":["Info_Gorn_RUINJOIN_15_01","Info_Gorn_RUINJOIN_09_02","Info_Gorn_RUINJOIN_09_03","Info_Gorn_RUINJOIN_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Moglibyśmy wybrać się tam razem.","en":"We could go on together.","de":"Wir können unseren Weg gemeinsam fortsetzen."}},{"speaker":"npc","text":{"pl":"Dobry pomysł. Cała okolica aż roi się od zębaczy.","en":"Good idea. This area is crowded with snappers.","de":"Gute Idee. Hier wimmelt es nur so von Snappern."}},{"speaker":"npc","text":{"pl":"W pojedynkę nie powinny stwarzać kłopotu wytrawnemu myśliwemu, ale te bestie zwykle polują całymi stadami.","en":"When they''re on their own, they''re no problem for an experienced hunter. Most of the time they hunt in packs though.","de":"Einzeln sind sie für einen geübten Kämpfer zwar kein Problem, aber sie jagen meistens in Rudeln."}},{"speaker":"npc","text":{"pl":"A grupa zębaczy potrafi rozerwać na strzępy nawet bardzo doświadczonego wojownika.","en":"A pack can even tear the cleverest sword fighter to pieces.","de":"So ein Rudel kann auch den gewieftesten Schwertmeister in Fetzen reißen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinjoin_15_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinjoin_15_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINJOIN_Info","outputIds":["Info_Gorn_RUINJOIN_15_05","Info_Gorn_RUINJOIN_09_06","Info_Gorn_RUINJOIN_09_07"],"lines":[{"speaker":"hero","text":{"pl":"Zatem pójdziemy tam razem?","en":"So we''ll go together?","de":"Wir gehen also zusammen?"}},{"speaker":"npc","text":{"pl":"Dobra, ale zanim przejdziemy po tym pniu, chciałbym przyjrzeć się uważniej temu kanionowi. Lubię wiedzieć, co mam za plecami.","en":"Okay, but before we cross this log, I''d like to examine the canyon. I like to know what''s at my back.","de":"Ok, doch bevor wir über diesen Baumstamm balancieren, möchte ich die Schlucht darunter erforschen. Ich habe gerne einen freien Rücken."}},{"speaker":"npc","text":{"pl":"Chodź za mną. Odkryłem ścieżkę, która nas tam zaprowadzi.","en":"Come with me, I''ve discovered a path which will take us there.","de":"Komm mit, ich habe einen Weg entdeckt, der uns dorthin führt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinleave_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinleave_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINLEAVE_Info","outputIds":["Info_Gorn_RUINLEAVE_09_01","Info_Gorn_RUINLEAVE_09_02","Info_Gorn_RUINLEAVE_09_03"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że ten stary klasztor przestał cię już interesować.","en":"You seem to have lost interest in the ruined monastery.","de":"Du scheinst doch nicht mehr an der Klosterruine interessiert zu sein."}},{"speaker":"npc","text":{"pl":"Zatem dalej pójdę sam.","en":"I''ll go on, on my own.","de":"Ich werde alleine weitergehen."}},{"speaker":"npc","text":{"pl":"Gdybyś zmienił zdanie, możesz mnie dogonić.","en":"Just follow me if you change your mind.","de":"Komm einfach nach, wenn du es dir anders überlegst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinleaveinside_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinleaveinside_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINLEAVEINSIDE_Info","outputIds":["Info_Gorn_RUINLEAVEINSIDE_09_01","Info_Gorn_RUINLEAVEINSIDE_09_02","Info_Gorn_RUINLEAVEINSIDE_09_03"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że ten stary klasztor przestał cię już interesować.","en":"You seem to have lost interest in the ruined monastery.","de":"Du scheinst doch nicht mehr an der Klosterruine interessiert zu sein."}},{"speaker":"npc","text":{"pl":"Dalej pójdę sam.","en":"I''ll go on on my own.","de":"Ich werde alleine weitersuchen."}},{"speaker":"npc","text":{"pl":"Gdybyś zmienił zdanie, możesz mnie dogonić.","en":"Just follow me if you change your mind.","de":"Komm einfach nach, wenn du es dir anders überlegst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinledge_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinledge_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINLEDGE_Info","outputIds":["Info_Gorn_RUINLEDGE_09_01","Info_Gorn_RUINLEDGE_09_02"],"lines":[{"speaker":"npc","text":{"pl":"Na górze jest chyba jakaś platforma. Ale wątpię, żeby udało się nam wspiąć tak wysoko.","en":"There''s some kind of platform up there. But it seems to be too high to climb.","de":"Dort oben ist eine Art Plattform. Aber es scheint zu hoch zu sein, um zu klettern."}},{"speaker":"npc","text":{"pl":"Musimy znaleźć inną drogę.","en":"We''ll have to find another way.","de":"Wir müssen einen anderen Weg finden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinplatform_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinplatform_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINPLATFORM_Info","outputIds":["Info_Gorn_RUINPLATFORM_09_01","Info_Gorn_RUINPLATFORM_09_02"],"lines":[{"speaker":"npc","text":{"pl":"To mi wygląda na jakiś piedestał.","en":"Looks like a pedestal of some sort.","de":"Sieht aus wie ein Podest für irgendetwas."}},{"speaker":"npc","text":{"pl":"Może leżał tu kiedyś artefakt, którego szukasz.","en":"Perhaps the artefact you''re looking for used to lay here.","de":"Vielleicht lag hier mal das Artefakt, dass du suchst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinsuccess_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinsuccess_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINSUCCESS_Info","outputIds":["Info_Gorn_RUINSUCCESS_09_01","Info_Gorn_RUINSUCCESS_15_02","Info_Gorn_RUINSUCCESS_09_03"],"lines":[{"speaker":"npc","text":{"pl":"A więc znalazłeś swój magiczny artefakt!","en":"So you found your magic artefact!","de":"Du hast dein magisches Artefakt also gefunden!"}},{"speaker":"hero","text":{"pl":"Tak. Muszę zanieść ten kamień ogniskujący do Magów Wody.","en":"Yeah. I have to take the focus to the Magicians of Water. They need it.","de":"Ja. Ich muss den Fokus zu den Wassermagiern bringen. Sie brauchen ihn."}},{"speaker":"npc","text":{"pl":"Pójdę kawałek z tobą.","en":"I''ll accompany you for a while.","de":"Ich werde dich noch etwas begleiten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruintroll_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruintroll_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINTROLL_Info","outputIds":["Info_Gorn_RUINTROLL_09_01","Info_Gorn_RUINTROLL_15_02","Info_Gorn_RUINTROLL_09_03","Info_Gorn_RUINTROLL_09_04"],"lines":[{"speaker":"npc","text":{"pl":"O JASNA CHOLERA! A co to za monstrum?","en":"OH HELL!!! What monster''s that over there?","de":"ACH DU SCHEISSE!!! Was ist das für ein Riesenvieh dort drüben?"}},{"speaker":"hero","text":{"pl":"Skąd się tu wzięło coś takiego?","en":"Where did THAT come from?","de":"Wo kommt DAS denn her???"}},{"speaker":"npc","text":{"pl":"To mi wygląda na jednego z tych niezniszczalnych Trolli, ale jest trochę mniejsze.","en":"Looks like one of those virtually invincible trolls. Only smaller!","de":"Sieht aus wie einer dieser fast unverwundbaren Trolle. Allerdings etwas kleiner!"}},{"speaker":"npc","text":{"pl":"Trudno, jeśli chcemy się stąd wydostać, musimy go jakoś minąć.","en":"Whatever, if we want to get out of here, we have to get past that beast.","de":"Wie auch immer, wenn wir hier raus wollen, müssen wie an diesem Biest vorbei."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinvictory_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinvictory_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINVICTORY_Info","outputIds":["Info_Gorn_RUINVICTORY_09_01","Info_Gorn_RUINVICTORY_15_02","Info_Gorn_RUINVICTORY_09_03","Info_Gorn_RUINVICTORY_15_04"],"lines":[{"speaker":"npc","text":{"pl":"Nie było łatwo!","en":"That was hard work.","de":"Das war ein hartes Stück Arbeit."}},{"speaker":"hero","text":{"pl":"Tak, ale w końcu się nam udało! To chyba był jakiś młody Troll.","en":"Yeah, we defeated that monster. But if that was just a young troll...","de":"Ja, wir haben das Monster bezwungen. Doch wenn das nur ein junger Troll war ..."}},{"speaker":"npc","text":{"pl":"... Więc pewnie nie chciałbyś wpaść na jego rodziców, co?","en":"... then you''d rather not bump into its parents, huh?","de":"... dann willst du wohl einem ausgewachsenen Exemplar lieber nicht zwischen die Finger geraten."}},{"speaker":"hero","text":{"pl":"Raczej nie!","en":"Something like that.","de":"So in etwa."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinvictory_09_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinvictory_09_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINVICTORY_Info","outputIds":["Info_Gorn_RUINVICTORY_09_05","Info_Gorn_RUINVICTORY_09_06"],"lines":[{"speaker":"npc","text":{"pl":"Tutaj nasze drogi się rozchodzą. Chcę tu trochę zostać i rozejrzeć się po okolicy.","en":"This is where we go our separate ways. I want to stay here for a while and have a look around.","de":"Unsere Wege trennen sich hier. Ich werde noch eine Weile bleiben und herumstöbern."}},{"speaker":"npc","text":{"pl":"Ale na pewno jeszcze się spotkamy. Do zobaczenia, przyjacielu.","en":"But I''m sure we''ll meet again. See you later, my friend.","de":"Doch wir werden uns sicher wiedersehen. Bis dann, mein Freund."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinwait_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinwait_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINWAIT_Info","outputIds":["Info_Gorn_RUINWAIT_09_01","Info_Gorn_RUINWAIT_09_02"],"lines":[{"speaker":"npc","text":{"pl":"Cześć, żółtodziobie. Jak widzisz kolonia to bardzo małe miejsce.","en":"Hi, greenhorn. As you can see, the colony is quite a small place.","de":"Hallo, Neuer. Wie du siehst, ist die Kolonie ein kleiner Ort."}},{"speaker":"npc","text":{"pl":"Cały czas wpada się na tych samych ludzi.","en":"You can''t help bumping into people all the time.","de":"Man läuft sich hier ständig über den Weg."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinwall_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinwall_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINWALL_Info","outputIds":["Info_Gorn_RUINWALL_09_01","Info_Gorn_RUINWALL_09_02"],"lines":[{"speaker":"npc","text":{"pl":"Cholerna brama. Ponoć nikomu jeszcze nie udało się jej otworzyć.","en":"This damn gate. They say nobody in the colony has ever been able to open it.","de":"Dieses verfluchte Tor. Man erzählt sich, dass bisher kein Mensch in der Kolonie es öffnen konnte."}},{"speaker":"npc","text":{"pl":"Te bestyjki pod drugiej stronie są pewnie jedynymi istotami, którym udało się dostać do środka.","en":"The little beasts over there seem to be the only ones who have managed to get into the inner yard.","de":"Die kleinen Biester da drüben scheinen die Einzigen zu sein, die es geschafft haben, in den Innenhof zu gelangen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinwallwhat_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinwallwhat_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINWALLWHAT_Info","outputIds":["Info_Gorn_RUINWALLWHAT_15_01","Info_Gorn_RUINWALLWHAT_09_02"],"lines":[{"speaker":"hero","text":{"pl":"I co teraz?","en":"What happens now?","de":"Wie geht es nun weiter?"}},{"speaker":"npc","text":{"pl":"Musisz znaleźć jakiś sposób na przedostanie się na drugą stronę bramy.","en":"You have to find a way to get to the other side of the gate.","de":"Du musst einen Weg finden, auf die andere Seite des Tors zu gelangen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinwhat_09_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinwhat_09_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINWHAT_Info","outputIds":["Info_Gorn_RUINWHAT_09_05","Info_Gorn_RUINWHAT_09_06","Info_Gorn_RUINWHAT_09_07","Info_Gorn_RUINWHAT_09_08"],"lines":[{"speaker":"npc","text":{"pl":"Oczywiście to było na długo przed powstaniem Bariery.","en":"Of course, that was long before the Barrier was created.","de":"Das war natürlich lange, bevor es die Barriere gab."}},{"speaker":"npc","text":{"pl":"Ponoć czczono tutaj bóstwo, które pozwalało mnichom przybierać postać zwierząt.","en":"It''s said they worshipped a god who gave them the power to turn into animals.","de":"Sie sollen einem Gott gehuldigt haben, der seinen Anhängern die Macht gab, sich in Tiere zu verwandeln."}},{"speaker":"npc","text":{"pl":"Założę się, że są tu jeszcze jakieś skarby pozostałe po dawnych czasach.","en":"I''m sure there are still treasures from the old times here.","de":"Bestimmt gibt es hier noch Schätze aus der alten Zeit."}},{"speaker":"npc","text":{"pl":"A co ciebie tu sprowadza?","en":"What brings you here?","de":"Was führt dich hierher?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_ruinwhat_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_ruinwhat_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_RUINWHAT_Info","outputIds":["Info_Gorn_RUINWHAT_15_01","Info_Gorn_RUINWHAT_09_02","Info_Gorn_RUINWHAT_15_03","Info_Gorn_RUINWHAT_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was führt dich denn hierher?"}},{"speaker":"npc","text":{"pl":"Och, podążam śladem pewnej prastarej legendy.","en":"Oh, I''m trying to track down an old legend.","de":"Oh, ich versuche, einer alten Legende auf die Spur zu kommen."}},{"speaker":"hero","text":{"pl":"Legendy?","en":"A legend?","de":"Einer Legende?"}},{"speaker":"npc","text":{"pl":"Tak, Milten - mój kumpel ze Starego Obozu, powiedział mi, że kiedyś ten teren zamieszkiwali mnisi.","en":"Yes, Milten, my pal from the Old Camp, told me that monks used to live here.","de":"Ja, Milten, mein Kumpel aus dem Alten Lager, hat mir erzählt, dass hier einst Mönche lebten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_second_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_second_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_SECOND_Info","outputIds":["Info_Gorn_SECOND_15_01","Info_Gorn_SECOND_09_02","Info_Gorn_SECOND_09_03","Info_Gorn_SECOND_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Na początek? A co zamierzacie robić później?","en":"The first step? What will be the second?","de":"Der erste Schritt? Was wird denn der Zweite sein?"}},{"speaker":"npc","text":{"pl":"Jak tylko odbijemy kopalnię, spróbujemy odnaleźć ścieżkę, którą przyszli ludzie Gomeza!","en":"As soon as the mine is ours again, we''ll start looking for the mountain pass that Gomez'' people used in the raid!","de":"Sobald die Mine wieder in unserem Besitz ist, werden wir den Pass über die Berge suchen, den Gomez'' Leute für den Überfall benutzt haben!"}},{"speaker":"npc","text":{"pl":"Kiedy ustawimy przy niej straż, będziemy bezpieczni.","en":"When the pass is closed, the situation will be under control again.","de":"Wenn der Pass dicht gemacht wurde, haben wir die Situation wieder im Griff."}},{"speaker":"hero","text":{"pl":"Rozumiem.","en":"I see.","de":"Verstehe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_takeback_09_05_4', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_takeback_09_05_4","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_TAKEBACK_Info","outputIds":["Info_Gorn_TAKEBACK_09_05","Info_Gorn_TAKEBACK_09_06","Info_Gorn_TAKEBACK_09_07","Info_Gorn_TAKEBACK_09_08"],"lines":[{"speaker":"npc","text":{"pl":"Jako jeden z naszych najlepszych Najemników zostałeś wyznaczony do udziału w tej misji.","en":"As one of our best mercenaries, you have been chosen to carry out this mission.","de":"Als einer unserer besten Söldner wurdest du bestimmt, die Operation durchzuführen!"}},{"speaker":"npc","text":{"pl":"Jako Mag z Kręgu Wody i doświadczony wojownik, zostałeś wybrany do udziału w tej misji.","en":"As a Magician of the Circle of Water and an experienced fighter, you have been chosen to carry out this mission.","de":"Als Wassermagier mit sehr viel Kampferfahrung wurdest du bestimmt, die Operation durchzuführen!"}},{"speaker":"npc","text":{"pl":"Jako jeden z naszych najlepszych Szkodników zostałeś wybrany do udziału w tej misji.","en":"As one of our best rogues, you have been chosen to carry out this mission!","de":"Als einer unserer besten Banditen wurdest du bestimmt, die Operation durchzuführen!"}},{"speaker":"npc","text":{"pl":"Choć nie jesteś jednym z nas, wielokrotnie oddałeś nam nieocenione przysługi.","en":"Although you aren''t one of us, you have done our camp a great service and proved your worth more than once.","de":"Obwohl du nicht zu uns gehörst, hast du unserem Lager schon große Dienste erwiesen und dich mehr als bewährt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_takeback_09_09_8', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_takeback_09_09_8","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_TAKEBACK_Info","outputIds":["Info_Gorn_TAKEBACK_09_09","Info_Gorn_TAKEBACK_09_10"],"lines":[{"speaker":"npc","text":{"pl":"Dlatego chcemy cię prosić o udział w tej misji.","en":"We''re offering you the chance of carrying out this mission!","de":"Wir bieten dir die Durchführung der Operation an!"}},{"speaker":"npc","text":{"pl":"Pójdę z tobą. Razem może się nam udać.","en":"I''ll go with you. Together we can make it!","de":"Ich werde mit dir gehen. Gemeinsam können wir es schaffen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_takeback_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_takeback_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_TAKEBACK_Info","outputIds":["Info_Gorn_TAKEBACK_15_01","Info_Gorn_TAKEBACK_09_02","Info_Gorn_TAKEBACK_09_03","Info_Gorn_TAKEBACK_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Zamierzacie ją zdobyć we czterech? A gdzie są wszyscy Najemnicy?","en":"You''re planning to retake it with just four men? Where are all the mercenaries?","de":"Eine Rückeroberung mit vier Mann? Wo sind all die anderen Söldner?"}},{"speaker":"npc","text":{"pl":"Uderzenie od frontu nie ma szans powodzenia. Ludzie Gomeza za dobrze się okopali.","en":"A frontal attack is no good! Gomez'' people are too well entrenched for that!","de":"Ein frontaler Angriff bringt nichts! Dafür sind Gomez'' Leute zu gut verschanzt!"}},{"speaker":"npc","text":{"pl":"Spróbujemy zaatakować po cichu, zabijając jednego strażnika po drugim. Może się uda...","en":"But we could run a stealth mission, eliminating one man after another - that could work.","de":"Aber eine verdeckte Operation, bei der wir Mann für Mann ausschalten, könnte gelingen!"}},{"speaker":"npc","text":{"pl":"Lee kazał mi przekazać ci wiadomość.","en":"Lee asked me to give you a message.","de":"Lee bat mich, dir etwas auszurichten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_whyme_15_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_whyme_15_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_WHYME_Info","outputIds":["Info_Gorn_WHYME_15_01","Info_Gorn_WHYME_09_02","Info_Gorn_WHYME_09_03","Info_Gorn_WHYME_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego właśnie ja?!","en":"Why me, of all people?","de":"Warum gerade ich?"}},{"speaker":"npc","text":{"pl":"Wielokrotnie udowodniłeś, że jesteś silnym i przebiegłym wojownikiem!","en":"You''ve already proved more than once that you can be brave and clever at the same time!","de":"Du hast schon mehrmals bewiesen, dass du Mut hast und gleichzeitig denken kannst!"}},{"speaker":"npc","text":{"pl":"Poza tym znasz Stary Obóz i jego strażników lepiej niż ktokolwiek z nas.","en":"Besides, you know the Old Camp and the guards better than most of us.","de":"Außerdem kennst du das Alte Lager und die Gardisten besser als die meisten von uns."}},{"speaker":"npc","text":{"pl":"Trudno o kogoś lepszego niż ty!","en":"You are the best man for this difficult job!","de":"Du bist der beste Mann für diesen schwierigen Job!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_wolf_09_01_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_wolf_09_01_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_WOLF_Info","outputIds":["Info_Gorn_WOLF_09_01","Info_Gorn_WOLF_09_02"],"lines":[{"speaker":"npc","text":{"pl":"Ach, prawie zapomniałem!","en":"Oh, I nearly forgot!","de":"Fast hätte ich es vergessen!"}},{"speaker":"npc","text":{"pl":"Wilk chce z tobą koniecznie porozmawiać, zanim ruszymy do kopalni.","en":"The rogue Wolf wants to talk to you urgently before we leave for the mine.","de":"Der Bandit Wolf will dich unbedingt sprechen, bevor wir zur Mine aufbrechen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_wolf_15_04_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_wolf_15_04_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_WOLF_FM","outputIds":["Info_Gorn_WOLF_15_04","Info_Gorn_WOLF_09_05"],"lines":[{"speaker":"hero","text":{"pl":"To może zaczekać, mamy teraz ważniejsze sprawy na głowie.","en":"He can wait, we have more important things to do.","de":"Er kann warten, wir haben jetzt Wichtigeres zu tun!"}},{"speaker":"npc","text":{"pl":"Jak chcesz!","en":"Whatever you say!","de":"Wie du meinst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_fighter_info_gorn_wolf_15_06_0', 'PC_Fighter', '{"id":"missions_dia_pc_fighter_info_gorn_wolf_15_06_0","npcId":"PC_Fighter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Fighter.d","sourceFunction":"Info_Gorn_WOLF_WOLF","outputIds":["Info_Gorn_WOLF_15_06","Info_Gorn_WOLF_09_07"],"lines":[{"speaker":"hero","text":{"pl":"Więc lepiej do niego zajrzę.","en":"Then I''d better go there now.","de":"Dann werde ich ihn besser noch vorher aufsuchen!"}},{"speaker":"npc","text":{"pl":"W porządku. Zaczekam na ciebie tutaj.","en":"You do that. I''ll wait for you right here.","de":"Tu das. Ich warte hier am Wachposten auf dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_dia_milten_letter_give_02_06_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_dia_milten_letter_give_02_06_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"DIA_Milten_Letter_Give","outputIds":["DIA_Milten_Letter_Give_02_06","DIA_Milten_Letter_Give_02_07","DIA_Milten_Letter_Give_02_08"],"lines":[{"speaker":"npc","text":{"pl":"Mieszka w wieży, w samym środku terytorium Orków. Chyba całkowicie poświęcił się swoim badaniom.","en":"He lives in a tower in the middle of the Orc land and concentrates on his studies.","de":"Er lebt in einem Turm mitten im Orkgebiet und widmet sich dort seinen Studien."}},{"speaker":"npc","text":{"pl":"Xardas próbuje na własną rękę dowiedzieć się co poszło nie tak przy tworzeniu Bariery.","en":"He said he would go his own way to find out what went wrong with the Barrier.","de":"Er sagte, er wolle auf seine Art herausfinden, was mit der Barriere nicht stimmt."}},{"speaker":"npc","text":{"pl":"Zaczekaj tu na mnie. Niedługo wrócę.","en":"Wait here. I''ll be back in a moment.","de":"Warte hier. Ich bin gleich wieder da."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_dia_milten_letter_give_15_00_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_dia_milten_letter_give_15_00_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"DIA_Milten_Letter_Give","outputIds":["DIA_Milten_Letter_Give_15_00","DIA_Milten_Letter_Give_02_03","DIA_Milten_Letter_Give_15_04","DIA_Milten_Letter_Give_02_05"],"lines":[{"speaker":"hero","text":{"pl":"Oto i ono.","en":"Here it is.","de":"Hier ist er."}},{"speaker":"npc","text":{"pl":"Ależ ten list zaadresowano do Xardasa!","en":"This letter is addressed to Xardas!","de":"Das ist ein Brief an Xardas!"}},{"speaker":"hero","text":{"pl":"Co w tym takiego niezwykłego?","en":"What''s so exciting about that?","de":"Und was ist daran so aufregend?"}},{"speaker":"npc","text":{"pl":"Xardas już od dawna nie jest sługą Innosa. Opuścił nas wiele lat temu i zwrócił się w stronę czarnej magii.","en":"Xardas has not been a servant of Innos for ages. He left us some years ago and turned towards black magic.","de":"Xardas ist schon lange kein Diener Innos mehr. Vor einigen Jahren hat er uns verlassen und sich der schwarzen Magie zugewandt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_dia_milten_letter_no_15_00_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_dia_milten_letter_no_15_00_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"DIA_Milten_Letter_NO","outputIds":["DIA_Milten_Letter_NO_15_00","DIA_Milten_Letter_NO_02_01","DIA_Milten_Letter_NO_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Najpierw chcę dostać moją nagrodę.","en":"I want my reward first.","de":"Erst will ich meine Belohnung."}},{"speaker":"npc","text":{"pl":"Corristo każe Torrezowi wydać ci nagrodę, jak tylko obejrzy ten list.","en":"Corristo will ask Torrez to give it to you as soon as he has the letter.","de":"Corristo wird Torrez anweisen, sie dir zu geben, sobald er den Brief erhalten hat."}},{"speaker":"npc","text":{"pl":"Jestem sługą Innosa - nigdy nie kłamię. A teraz daj mi ten list.","en":"I''m a servant of Innos - I never lie. Now give me the letter.","de":"Ich bin ein Diener Innos - ich lüge niemals. Gib mir den Brief jetzt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_dia_milten_letter_no_again_15_00_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_dia_milten_letter_no_again_15_00_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"DIA_Milten_Letter_NO_AGAIN","outputIds":["DIA_Milten_Letter_NO_AGAIN_15_00","DIA_Milten_Letter_NO_AGAIN_02_01","DIA_Milten_Letter_NO_AGAIN_15_02","DIA_Milten_Letter_NO_AGAIN_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Wolałbym oddać ten list Torrezowi.","en":"I''d rather give the letter to Torrez himself.","de":"Ich möchte den Brief lieber Torrez direkt geben."}},{"speaker":"npc","text":{"pl":"Nie dasz się przekonać, co?","en":"I can''t talk you out of that, can I?","de":"Du lässt nicht mit dir reden, hm?"}},{"speaker":"hero","text":{"pl":"Nie. Najpierw chcę zobaczyć moją nagrodę.","en":"No. I want to see my reward first.","de":"Nein. Ich will erst meine Belohnung sehen!"}},{"speaker":"npc","text":{"pl":"Cóż. Jeśli tego sobie życzysz. Zaczekaj tutaj.","en":"Well then. If that''s what you want. Wait here.","de":"Nun gut. Du willst es nicht anders. Warte hier."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_loadsword4_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_loadsword4_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LOADSWORD4_Info","outputIds":["Info_Milten_LOADSWORD4_15_01","Info_Milten_LOADSWORD4_15_02","Info_Milten_LOADSWORD4_02_03","Info_Milten_LOADSWORD4_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Xardas dał mi magiczne zaklęcie, które pozwoli mi przenieść energię!","en":"Xardas gave me this magic spell to carry out the transfer!","de":"Xardas gab mir diese magische Formel, um den Transfer zu vollbringen!"}},{"speaker":"hero","text":{"pl":"Będziesz musiał je odczytać, podczas gdy ja dotknę rudy mieczem!","en":"You will have to recite it while I bring the sword and the ore together!","de":"Du musst sie aussprechen, während ich Schwert und Erz in Kontakt bringe!"}},{"speaker":"npc","text":{"pl":"Hmmm... Mówisz, że trzeba je tylko odczytać?","en":"Mmmm... Mmmm... It looks as if I only have to read out this spell ...","de":"Hmmm ... Hmmm ... es sieht so aus, als ob ich diese Zauberformel nur herunterlesen müsste ..."}},{"speaker":"npc","text":{"pl":"Ale Saturas i jego magowie nie puszczą nam tego płazem!","en":"But we''ll get into trouble with Saturas and the other magicians!","de":"Aber wir werden ernsthaften Ärger mit Saturas und den anderen Magiern bekommen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsaway_02_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsaway_02_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSAWAY_Info","outputIds":["Info_Milten_LSAWAY_02_01","Info_Milten_LSAWAY_15_02","Info_Milten_LSAWAY_02_03","Info_Milten_LSAWAY_15_04"],"lines":[{"speaker":"npc","text":{"pl":"A teraz mów - co się stało?","en":"Now tell me, what is it?","de":"Nun sprich, worum geht es?"}},{"speaker":"hero","text":{"pl":"Muszę wykorzystać magiczną energię kopca rudy, a wolałbym nie pytać Magów Wody o pozwolenie.","en":"I need the magic powers of the ore mound and I don''t think it would be a good move to ask the other Magicians of Water.","de":"Ich brauche die magische Energie des Erzhaufens, und ich halte es für unklug, die anderen Wassermagier danach zu fragen!"}},{"speaker":"npc","text":{"pl":"Żartujesz sobie ze mnie!","en":"You''re joking!","de":"Du scherzt!"}},{"speaker":"hero","text":{"pl":"To nie pora na żarty. Mówię poważnie.","en":"This is no time for jokes. I''m deadly serious.","de":"Die Zeit des Scherzens ist vorbei, ich meine es todernst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsaway_15_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsaway_15_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSAWAY_Info","outputIds":["Info_Milten_LSAWAY_15_05","Info_Milten_LSAWAY_15_06","Info_Milten_LSAWAY_02_07","Info_Milten_LSAWAY_02_08"],"lines":[{"speaker":"hero","text":{"pl":"Spotkałem Xardasa, Nekromantę!","en":"I''ve seen Xardas, the Necromancer!","de":"Ich habe Xardas, den Dämonenbeschwörer, getroffen!"}},{"speaker":"hero","text":{"pl":"Wypełniam jego polecenia!","en":"I''m working under his orders!","de":"Ich handle in seinem Auftrag!"}},{"speaker":"npc","text":{"pl":"XARDAS?! Zaczynasz mnie przerażać!","en":"XARDAS??? You''re beginning to scare me!","de":"XARDAS??? Langsam machst du mir Angst!"}},{"speaker":"npc","text":{"pl":"Nikt z nim nie rozmawiał odkąd opuścił Stary Obóz.","en":"Nobody has spoken to him since he left the Old Camp.","de":"Niemand hat mit ihm gesprochen, seit er das Alte Lager verlassen hat!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsaway_15_09_8', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsaway_15_09_8","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSAWAY_Info","outputIds":["Info_Milten_LSAWAY_15_09","Info_Milten_LSAWAY_02_10","Info_Milten_LSAWAY_15_11","Info_Milten_LSAWAY_02_12"],"lines":[{"speaker":"hero","text":{"pl":"Ja rozmawiałem!","en":"I have!","de":"Ich schon!"}},{"speaker":"npc","text":{"pl":"Do czego potrzebna ci jest energia kopca rudy?","en":"What do you need the powers of the ore mound for?","de":"Wofür benötigst du die Energie des Erzhaufens?"}},{"speaker":"hero","text":{"pl":"Muszę ją skumulować w tym oto mieczu.","en":"I want to transfer them to this sword here.","de":"Ich will sie auf dieses Schwert hier übertragen."}},{"speaker":"npc","text":{"pl":"Cóż za niesamowita broń!","en":"Wow, what a weapon!","de":"Wow, was für eine Waffe!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsdone_02_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsdone_02_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSDONE_Info","outputIds":["Info_Milten_LSDONE_02_01","Info_Milten_LSDONE_15_02","Info_Milten_LSDONE_02_03","Info_Milten_LSDONE_02_04"],"lines":[{"speaker":"npc","text":{"pl":"Gotowe!","en":"It''s done!","de":"Es ist vollbracht!"}},{"speaker":"hero","text":{"pl":"Niesamowite! Ten szary kryształ rozbłysnął pięknym błękitem!","en":"Unbelievable! The plain gray gem is shimmering bluish now!","de":"Unglaublich! Der unscheinbare graue Edelstein schimmert nun bläulich!"}},{"speaker":"npc","text":{"pl":"To dobry znak! Wygląda na to, że cała energia z kopca została przeniesiona na miecz!","en":"That''s a good sign! The magic powers of the ore mound really seem to be in the old sword now!","de":"Das ist ein gutes Zeichen! Die magische Energie des Erzhaufens scheint tatsächlich in das alte Schwert übertragen worden zu sein!"}},{"speaker":"npc","text":{"pl":"Ale nasze działania zwróciły uwagę strażników!","en":"But our little operation here seems to have attracted some attention.","de":"Aber unsere kleine Aktion hier scheint etwas Aufmerksamkeit erregt zu haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsdone_02_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsdone_02_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSDONE_Info","outputIds":["Info_Milten_LSDONE_02_05","Info_Milten_LSDONE_15_06","Info_Milten_LSDONE_02_07"],"lines":[{"speaker":"npc","text":{"pl":"Teleportuj się stąd, natychmiast!","en":"You should teleport yourself directly out of here!","de":"Du solltest dich am besten direkt hier heraus teleportieren!"}},{"speaker":"hero","text":{"pl":"A co z tobą?","en":"What about you?","de":"Was wird aus dir?"}},{"speaker":"npc","text":{"pl":"O mnie się nie martw! Coś wymyślę! Uciekaj stąd! Już!","en":"Don''t worry about me, I''ll think of something. Go now!","de":"Mach dir um mich keine Sorgen, ich werde mir schon was einfallen lassen. Geh jetzt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsnow_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsnow_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSNOW_Info","outputIds":["Info_Milten_LSNOW_15_01","Info_Milten_LSNOW_15_02","Info_Milten_LSNOW_02_03","Info_Milten_LSNOW_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Proszę, oto ono!","en":"Here, take the spell!","de":"Hier, nimm die Zauberformel!"}},{"speaker":"hero","text":{"pl":"Jesteś gotów?","en":"Are you ready?","de":"Bist du bereit?"}},{"speaker":"npc","text":{"pl":"Nie, ale nie mamy wielkiego wyboru. Teraz albo nigdy!","en":"As ready as one can be for this crazy plan.","de":"So bereit, wie man für solch eine Wahnsinnstat nur sein kann."}},{"speaker":"hero","text":{"pl":"Zatem do dzieła!","en":"Then let''s do it!","de":"Dann kann es ja losgehen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsoreheap_02_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsoreheap_02_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSOREHEAP_Info","outputIds":["Info_Milten_LSOREHEAP_02_01"],"lines":[{"speaker":"npc","text":{"pl":"Masz miecz i zaklęcie?","en":"Have you got the sword and the spell?","de":"Hast du das Schwert und die Zauberformel?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsrisk_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsrisk_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSRISK_Info","outputIds":["Info_Milten_LSRISK_15_01","Info_Milten_LSRISK_15_02","Info_Milten_LSRISK_15_03","Info_Milten_LSRISK_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Musimy zaryzykować!","en":"We''ll have to take that risk!","de":"Das Risiko müssen wir eingehen!"}},{"speaker":"hero","text":{"pl":"To bardzo, BARDZO ważne!","en":"It really is VERY, VERY important!","de":"Es ist wirklich SEHR, SEHR wichtig!"}},{"speaker":"hero","text":{"pl":"Ważne dla WSZYSTKICH mieszkańców kolonii...","en":"Important for ALL inhabitants of the colony.","de":"Wichtig für ALLE Bewohner der Kolonie."}},{"speaker":"npc","text":{"pl":"Nic nie rozumiem.","en":"I don''t understand...","de":"Ich verstehe nicht ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_lsrisk_15_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_lsrisk_15_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_LSRISK_Info","outputIds":["Info_Milten_LSRISK_15_05","Info_Milten_LSRISK_02_06","Info_Milten_LSRISK_02_07","Info_Milten_LSRISK_02_08"],"lines":[{"speaker":"hero","text":{"pl":"Dzięki temu wydostaniemy się na wolność! Musisz mi zaufać!","en":"It will get us out of here! You have to trust me!","de":"Es wird uns alle hier raus bringen! Du musst mir vertrauen!"}},{"speaker":"npc","text":{"pl":"Dobrze! Po tym wszystkim, co dla nas zrobiłeś, ufam ci bezgranicznie.","en":"Alright! After all you have done for us, I trust you completely.","de":"Einverstanden! Nach all dem, was du bereits für uns getan hast, besitzt du mein Vertrauen."}},{"speaker":"npc","text":{"pl":"No i wygląda na to, że nawet Xardas darzy cię zaufaniem.","en":"Besides, it seems Xardas trusts you as well.","de":"Außerdem scheinst du auch das von Xardas zu besitzen!"}},{"speaker":"npc","text":{"pl":"Spotkamy się przy kopcu rudy. Tylko nikomu ani słowa!","en":"Meet me down at the ore mound, and... Don''t tell anybody!","de":"Triff mich unten beim Erzhaufen, und ... zu keinem ein Sterbenswörtchen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_ocdiego_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_ocdiego_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_OCDIEGO_Info","outputIds":["Info_Milten_OCDIEGO_15_01","Info_Milten_OCDIEGO_02_02","Info_Milten_OCDIEGO_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę Diego?","en":"Where can I find Diego?","de":"Wo kann ich Diego finden?"}},{"speaker":"npc","text":{"pl":"Ukrywa się po drugiej stronie Obozu, w pobliżu tylnej bramy.","en":"He''s hiding on the other side of the Old Camp, near the back gate.","de":"Er hält sich auf der anderen Seite des Alten Lagers in der Nähe des hinteren Tores versteckt."}},{"speaker":"npc","text":{"pl":"Musisz z nim koniecznie porozmawiać!","en":"Please talk to him!","de":"Bitte sprich mit ihm!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_ockdw_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_ockdw_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_OCKDW_Info","outputIds":["Info_Milten_OCKDW_15_01","Info_Milten_OCKDW_02_02","Info_Milten_OCKDW_02_03","Info_Milten_OCKDW_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Mówiłeś coś o Magach Ognia?","en":"What was that you said about the Magicians of Fire?","de":"Was sagtest du über die Feuermagier?"}},{"speaker":"npc","text":{"pl":"Wiem tylko, że wszyscy zostali zabici przez Magnatów tuż po zawaleniu się Starej Kopalni.","en":"I only know that they were all killed by the Ore Barons shortly after the mine caved in.","de":"Ich weiß nur, dass sie kurz nach dem Einsturz alle von den Erzbaronen umgebracht wurden."}},{"speaker":"npc","text":{"pl":"Kiedy wróciłem z naszej wyprawy pod kamienny krąg, strażnicy przy bramie rzucili się na mnie bez ostrzeżenia.","en":"When I returned from our adventure under the ring of stone, the guards at the gate suddenly attacked me.","de":"Als ich von unserem gemeinsamen Abenteuer unter dem Stonehenge zurückkehrte, griffen mich die Wachen am Tor plötzlich an."}},{"speaker":"npc","text":{"pl":"Krzyczeli \"zdrajca\" i \"spiskowiec\". Ledwie uszedłem z życiem.","en":"They shouted words like ''traitor'' and ''collaborator'' at me. I had a very narrow escape.","de":"Sie schrieen mir Worte wie ''Verräter'' und ''Kollaborateur'' entgegen. Ich konnte mich gerade noch in Sicherheit bringen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_ocmine_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_ocmine_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_OCMINE_Info","outputIds":["Info_Milten_OCMINE_15_01","Info_Milten_OCMINE_02_02","Info_Milten_OCMINE_15_03","Info_Milten_OCMINE_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Jak do tego doszło?","en":"How could the mine cave in?","de":"Wie konnte die Mine einstürzen?"}},{"speaker":"npc","text":{"pl":"Nie mam pojęcia. Kilku Kopaczy stojących przy wejściu mówiło coś o potężnym wstrząsie i wielkiej chmurze pyłu z tunelu.","en":"I''ve no idea. Some of the diggers who were waiting in front of the entrance said something about a massive earthquake and a huge cloud of dust coming from the tunnel.","de":"Keine Ahnung. Einige Buddler, die vor dem Mineneingang warteten, erzählten von einem gewaltigen Beben und einer riesigen Staubwolke, die aus dem Stollen kam."}},{"speaker":"hero","text":{"pl":"Byłeś tam, kiedy to się stało?","en":"Were you there?","de":"Warst du dort?"}},{"speaker":"npc","text":{"pl":"Tak. Stąd wiem o zawaleniu się kopalni.","en":"Yes. That''s where I learned about the cave-in.","de":"Ja. Dort erfuhr ich dann auch vom Einsturz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_ocwarn_02_13_12', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_ocwarn_02_13_12","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_OCWARN_Info","outputIds":["Info_Milten_OCWARN_02_13"],"lines":[{"speaker":"npc","text":{"pl":"Strażnicy zablokowali wejście do kopalni.","en":"The guards blocked the entrance to the mine.","de":"Die Gardisten haben den Mineneingang gesperrt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_ocwhy_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_ocwhy_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_OCWHY_Info","outputIds":["Info_Milten_OCWHY_15_01","Info_Milten_OCWHY_02_02","Info_Milten_OCWHY_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego Magnaci mieliby wymordować Magów? To bez sensu!","en":"Why would the Ore Barons want to kill the magicians? It doesn''t make sense...","de":"Warum töten Erzbarone Feuermagier? Das gibt doch keinen Sinn..."}},{"speaker":"npc","text":{"pl":"Wiem, ale nie miałem czasu, żeby zapytać strażników. Zaatakowali mnie natychmiast.","en":"That''s right. The guards just didn''t give me any opportunity to ask. They drew their swords immediately.","de":"Das stimmt. Nur gaben mir die Wachen am Lagereingang keine Gelegenheit, danach zu fragen. Sie zogen sofort ihre Schwerter."}},{"speaker":"npc","text":{"pl":"Może Diego będzie wiedział więcej. Był w Obozie, kiedy rozegrała się ta tragedia.","en":"Perhaps Diego knows more. He was in the Camp when things got worse.","de":"Vielleicht kann dir Diego mehr erzählen. Er war im Lager, als sich die Ereignisse zuspitzten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_ocyou_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_ocyou_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_OCYOU_Info","outputIds":["Info_Milten_OCYOU_15_01","Info_Milten_OCYOU_02_02","Info_Milten_OCYOU_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Powinieneś się ukryć. Najlepiej daleko stąd.","en":"You should hide. Far away from here.","de":"Du solltest dich verstecken. Weit weg von hier!"}},{"speaker":"npc","text":{"pl":"Nie. Diego kazał mi pilnować drugiego wejścia do Obozu. Mamy ostrzegać naszych przyjaciół przed niebezpieczeństwem.","en":"No. Diego and I agreed to keep an eye on the two gates and to warn our unsuspecting friends from the other camps.","de":"Nein. Diego und ich haben beschlossen, die beiden Tore im Auge zu behalten, und ahnungslose Freunde aus anderen Lagern zu warnen."}},{"speaker":"npc","text":{"pl":"Proszę, porozmawiaj z Diego!","en":"Please talk to Diego!","de":"Bitte sprich noch mit Diego!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shaccept_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shaccept_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHACCEPT_Info","outputIds":["Info_Milten_SHACCEPT_15_01","Info_Milten_SHACCEPT_02_02","Info_Milten_SHACCEPT_02_03","Info_Milten_SHACCEPT_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Daj mi ten magiczny zwój i razem zajmiemy się tymi ożywieńcami!","en":"Give me the spell scroll and we''ll do it together!","de":"Gib mir die Spruchrolle und wir heben diese Gruft gemeinsam aus!"}},{"speaker":"npc","text":{"pl":"Ha! Miałem nadzieję, że to powiesz.","en":"Good, very good. I hoped you would say that!","de":"Gut, sehr gut. Ich hoffte, du würdest das sagen!"}},{"speaker":"npc","text":{"pl":"Niestety, mam tylko jeden zwój. Wykorzystaj go przeciw Strażnikowi.","en":"However, we only have one spell scroll. Use it for the guard!","de":"Wir haben aber nur diese eine Spruchrolle. Benutze sie für den Wächter!"}},{"speaker":"npc","text":{"pl":"Pozostałe ożywieńce można zabić zwykłym orężem.","en":"The other undead can be defeated in normal fights as well.","de":"Die anderen Untoten kann man auch im normalen Kampf besiegen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shaccept_15_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shaccept_15_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHACCEPT_Info","outputIds":["Info_Milten_SHACCEPT_15_05","Info_Milten_SHACCEPT_02_06"],"lines":[{"speaker":"hero","text":{"pl":"Rozumiem. No dobrze, którędy do tego kamiennego kręgu?","en":"I see. Well, which way leads to the ring of stone?","de":"Verstehe. Also, wo geht es zum Stonehenge?"}},{"speaker":"npc","text":{"pl":"Chodź za mną!","en":"Follow me.","de":"Folge mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_sharrived_02_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_sharrived_02_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHARRIVED_Info","outputIds":["Info_Milten_SHARRIVED_02_01","Info_Milten_SHARRIVED_15_02"],"lines":[{"speaker":"npc","text":{"pl":"No i jesteśmy. Ten tunel prowadzi wprost do grobowca.","en":"Here we are. The tunnel here leads directly to the tomb.","de":"Hier sind wir. Der Stollen hier führt direkt in die Gruft."}},{"speaker":"hero","text":{"pl":"Zatem ruszajmy. Pora złożyć wizytę strażnikom.","en":"Then let''s go and visit the guard!","de":"Dann statten wir dem Wächter mal einen Besuch ab!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shcontinue_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shcontinue_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHCONTINUE_Info","outputIds":["Info_Milten_SHCONTINUE_15_01","Info_Milten_SHCONTINUE_02_02"],"lines":[{"speaker":"hero","text":{"pl":"To jak? Schodzimy znowu do krypty?","en":"Shall we dare to have another go at the guard?","de":"Wollen wir einen weiteren Versuch beim Wächter wagen?"}},{"speaker":"npc","text":{"pl":"Jestem gotów. Idź przodem. Pójdę za tobą.","en":"I''m ready. Go ahead, I''ll follow.","de":"Ich bin bereit. Geh voraus, ich folge dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shfocus_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shfocus_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHFOCUS_Info","outputIds":["Info_Milten_SHFOCUS_15_01","Info_Milten_SHFOCUS_02_02","Info_Milten_SHFOCUS_15_03","Info_Milten_SHFOCUS_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Czyżbyś mówił o jednym z pięciu kamieni ogniskujących?","en":"Is this artefact one of the five focus stones?","de":"Ist dieses Artefakt einer der fünf Fokussteine?"}},{"speaker":"npc","text":{"pl":"Dokładnie! A więc znasz już historię pięciu kamieni?","en":"Exactly! So you already know the story of the five focus stones?","de":"Genau! Dann kennst du die Geschichte der fünf Fokussteine wohl schon."}},{"speaker":"hero","text":{"pl":"Tylko mi nie mów, że ty też szukasz tego kamienia!","en":"Don''t tell me you''re after the focus as well!","de":"Jetzt sag bloß, du bist auch hinter diesem Fokus her?"}},{"speaker":"npc","text":{"pl":"Nie. Nie interesuje mnie kamień ogniskujący. Szukam pewnego talizmanu Orków.","en":"No. I''m not interested in the focus stone. I''m looking for an Orcish talisman.","de":"Nein. Der Fokusstein interessiert mich nicht. Ich suche einen orkischen Talisman."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shgorn_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shgorn_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHGORN_Info","outputIds":["Info_Milten_SHGORN_15_01","Info_Milten_SHGORN_02_02","Info_Milten_SHGORN_15_03","Info_Milten_SHGORN_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Spotkałem Gorna.","en":"I met Gorn.","de":"Ich habe Gorn getroffen."}},{"speaker":"npc","text":{"pl":"Naprawdę? Gdzie?","en":"Really? Where?","de":"Wirklich? Wo?"}},{"speaker":"hero","text":{"pl":"W ruinach klasztoru, nad morzem. Bawiliśmy się w poszukiwaczy skarbów.","en":"By the old ruined monastery by the sea. The two of us searched it for treasures.","de":"An der alten Klosterruine am Meer. Wir haben sie gemeinsam nach Schätzen durchsucht."}},{"speaker":"npc","text":{"pl":"Zapewne nie omieszka mi o tym opowiedzieć podczas naszego następnego spotkania.","en":"I am sure he''ll tell me all about it when we meet again.","de":"Davon wird er mir bei unserem nächsten Treffen bestimmt erzählen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shheal_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shheal_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHHEAL_Info","outputIds":["Info_Milten_SHHEAL_15_01","Info_Milten_SHHEAL_02_02","Info_Milten_SHHEAL_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Jestem ranny. Możesz mi pomóc?","en":"I''m wounded. Please help me.","de":"Ich bin verwundet. Bitte hilf mir!"}},{"speaker":"npc","text":{"pl":"Weź ten napój uzdrawiający.","en":"Take this healing potion.","de":"Nimm diesen Heiltrank. Aber sei nicht verschwenderisch, ich habe nicht unendlich viel davon."}},{"speaker":"npc","text":{"pl":"Nie mam już żadnych magicznych wywarów.","en":"I don''t have any healing potion left.","de":"Ich habe keinen Heiltrank mehr."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shleave_02_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shleave_02_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHLEAVE_Info","outputIds":["Info_Milten_SHLEAVE_02_01","Info_Milten_SHLEAVE_02_02"],"lines":[{"speaker":"npc","text":{"pl":"Czyżbyś stracił zainteresowanie tym grobowcem?","en":"You seem to have lost interest in the tomb.","de":"Du scheinst kein Interesse mehr an der Gruft zu haben."}},{"speaker":"npc","text":{"pl":"Jakbyś zmienił zdanie, znajdziesz mnie w miejscu naszego pierwszego spotkania.","en":"If you change your mind, you can meet me where we met before.","de":"Wenn du es dir anders überlegst, triff mich dort, wo wir uns vorhin schon einmal getroffen haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shlester_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shlester_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHLESTER_Info","outputIds":["Info_Milten_SHLESTER_15_01","Info_Milten_SHLESTER_02_02","Info_Milten_SHLESTER_15_03","Info_Milten_SHLESTER_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Lester i ja rozejrzeliśmy się trochę po fortecy w górach.","en":"Lester and I took out the mountain fort.","de":"Lester und ich haben die Bergfestung ausgenommen."}},{"speaker":"npc","text":{"pl":"Tak, słyszałem. Wygląda na to, że można ci zaufać.","en":"He told me about it. Apparently you can be trusted.","de":"Er hat mir davon erzählt. Du scheinst vertrauenswürdig zu sein."}},{"speaker":"hero","text":{"pl":"Gdzie wasza czwórka zwykła się spotykać?","en":"Where have the four of you been meeting so far?","de":"Wo habt ihr vier euch bisher getroffen?"}},{"speaker":"npc","text":{"pl":"Ach, tu i tam. Spotykamy się w najróżniejszych miejscach.","en":"Oh, here and there. We meet in a lot of different places.","de":"Ach, hier und da. Wir treffen uns an den verschiedensten Orten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shme_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shme_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHME_Info","outputIds":["Info_Milten_SHME_15_01","Info_Milten_SHME_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Szukam kamienia ogniskującego. Powinien gdzieś tam być.","en":"I''m looking for a focus stone. It must be here somewhere.","de":"Ich suche nach einem Fokusstein. Er muss irgendwo hier in der Gegend sein."}},{"speaker":"npc","text":{"pl":"Wygląda na to, że obydwaj szukamy czegoś w tym samym miejscu.","en":"That almost sounds as if we were both looking for something in the same place.","de":"Hört sich fast so an, als ob wir beide etwas am gleichen Ort suchen würden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shnewscroll_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shnewscroll_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHNEWSCROLL_Info","outputIds":["Info_Milten_SHNEWSCROLL_15_01","Info_Milten_SHNEWSCROLL_02_02","Info_Milten_SHNEWSCROLL_02_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam nowy zwój z zaklęciem \"Śmierć Ożywieńcom!\"","en":"I have a new ''Death to the Undead'' spell scroll!","de":"Ich habe eine neue Spruchrolle ''Untote vernichten''!"}},{"speaker":"npc","text":{"pl":"To wspaniale! Możemy złożyć Strażnikowi kolejną wizytę!","en":"Very good. Now we can pay another visit to the guard.","de":"Sehr gut, dann können wir ja dem Wächter wieder einen Besuch abstatten."}},{"speaker":"npc","text":{"pl":"Idź przodem. Pójdę za tobą.","en":"Go first, I''ll follow.","de":"Geh voraus, ich folge dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shoffer_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shoffer_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHOFFER_Info","outputIds":["Info_Milten_SHOFFER_15_01","Info_Milten_SHOFFER_02_02","Info_Milten_SHOFFER_15_03","Info_Milten_SHOFFER_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Zatem powinniśmy wspólnie przeszukać ten grobowiec! Ty znajdziesz swój talizman, a ja - mój kamień ogniskujący!","en":"We should seek out the tomb together! You get the talisman, and I''ll have the focus stone.","de":"Wir sollten die Gruft gemeinsam ausheben! Du bekommst den Talisman und ich den Fokusstein."}},{"speaker":"npc","text":{"pl":"W porządku, ale jest pewien mały problem...","en":"Alright, but there is one little problem...","de":"Einverstanden, aber da gibt es noch ein ''kleines'' Problem ..."}},{"speaker":"hero","text":{"pl":"Problem?","en":"A problem?","de":"Ein Problem?"}},{"speaker":"npc","text":{"pl":"Tak. Strażnik podziemnej krypty...","en":"Yes. The guard down there in the tomb...","de":"Ja. Der Wächter da unten in der Gruft ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shoffer_15_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shoffer_15_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHOFFER_Info","outputIds":["Info_Milten_SHOFFER_15_05","Info_Milten_SHOFFER_02_06","Info_Milten_SHOFFER_15_07","Info_Milten_SHOFFER_02_08"],"lines":[{"speaker":"hero","text":{"pl":"A nie można go po prostu posiekać na drobne kawałeczki?","en":"Can''t he be cut into handy little pieces?","de":"Kann man ihn nicht in handliche Stücke zerlegen?"}},{"speaker":"npc","text":{"pl":"To nie będzie takie proste. Ten ożywieniec zdaje się być niezwykle odporny na działanie zwykłego oręża.","en":"That wouldn''t be too easy. He seems to be extremely resistant against the effects of normal weapons.","de":"Zumindest nicht so einfach. Er scheint gegen die Wirkung normaler Waffen extrem widerstandsfähig zu sein."}},{"speaker":"hero","text":{"pl":"Niech zgadnę: pewnie masz już jakiś plan, jak go pokonać, tak?","en":"Let me guess, you already got a plan, right?","de":"Lass mich raten, du hast bereits einen Plan dafür, richtig?"}},{"speaker":"npc","text":{"pl":"Umm... No cóż... MAM pewien plan, ale nie jestem w stanie sam go wykonać.","en":"Uhm... well... I have a plan but I can''t carry it out on my own.","de":"Ähem ... tja also ... einen Plan habe ich schon, aber ich kann ihn nicht alleine durchführen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shoffer2_02_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shoffer2_02_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHOFFER2_Info","outputIds":["Info_Milten_SHOFFER2_02_05","Info_Milten_SHOFFER2_02_06","Info_Milten_SHOFFER2_02_07"],"lines":[{"speaker":"npc","text":{"pl":"Hmmm... Nie zupełnie! Obawiam się, że nasz przeklęty strażnik nie jest już sam.","en":"Mhmm... Well... Not quite! The guard is not on his own any longer.","de":"Tja ... also... nicht ganz! Der Wächter hat mittlerweile Gesellschaft bekommen."}},{"speaker":"npc","text":{"pl":"Wygląda na to, że rabusie, którzy przyszli po nim mieli równie mało szczęścia co on sam.","en":"Probably later grave robbers who were no more successful than he was.","de":"Wahrscheinlich nachfolgende Grabräuber, die wenig erfolgreich waren."}},{"speaker":"npc","text":{"pl":"Pewnego razu zszedłem na dół i mało brakowało, a postradałbym życie. Jeden człowiek nie sprosta wszystkim przeciwnikom.","en":"I went down there once, and I was nearly killed. One man on his own cannot do much there.","de":"Ich war bereits einmal dort unten und wäre fast getötet worden. Einer alleine kann da nicht viel ausrichten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shoffer2_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shoffer2_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHOFFER2_Info","outputIds":["Info_Milten_SHOFFER2_15_01","Info_Milten_SHOFFER2_02_02","Info_Milten_SHOFFER2_02_03","Info_Milten_SHOFFER2_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Zamieniam się w słuch!","en":"Tell me!","de":"Lass hören!"}},{"speaker":"npc","text":{"pl":"Mam przy sobie magiczny zwój z niezwykle potężnym zaklęciem.","en":"I have a spell scroll with a very powerful spell here.","de":"Ich habe hier eine Spruchrolle, die einen sehr mächtigen Zauber enthält."}},{"speaker":"npc","text":{"pl":"To zaklęcie natychmiast niszczy wszystkich ożywieńców znajdujących się w okolicy.","en":"The spell will destroy all the undead who fall under it.","de":"Der Zauber vernichtet jeden Untoten, der davon getroffen wird."}},{"speaker":"hero","text":{"pl":"Zatem dostanie się do grobowca powinno być dziecinnie proste, prawda?","en":"Then it should be child''s play to take out the tomb.","de":"Damit sollte das Ausheben der Gruft ein Kinderspiel werden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shproblem_02_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shproblem_02_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHPROBLEM_Info","outputIds":["Info_Milten_SHPROBLEM_02_05"],"lines":[{"speaker":"npc","text":{"pl":"... Jeden z magów zamknął pod ziemią potężny artefakt.","en":"... one of the magicians sealed a magic artefact down there.","de":"...hat einer der beteiligten Magier ein magisches Artefakt dort unten versiegelt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shproblem_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shproblem_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHPROBLEM_Info","outputIds":["Info_Milten_SHPROBLEM_15_01","Info_Milten_SHPROBLEM_02_02","Info_Milten_SHPROBLEM_15_03","Info_Milten_SHPROBLEM_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego nie zejdziesz do grobowca i nie zabierzesz tego, czego szukasz?","en":"Why don''t you go down into the tomb and get what you''re looking for?","de":"Warum gehst du nicht in die Gruft und holst dir was du suchst?"}},{"speaker":"npc","text":{"pl":"Och, to długa historia. Musiałbym zanudzać cię opowieścią o bardzo dawnych czasach.","en":"Oh, that''s a long story. I''d have to go a long way back to explain.","de":"Oh, das ist nicht so schnell erzählt. Dafür müsste ich etwas weiter ausholen."}},{"speaker":"hero","text":{"pl":"Śmiało, nigdzie mi się nie spieszy.","en":"Go ahead, I''m in no hurry.","de":"Erzähl, ich habe Zeit !"}},{"speaker":"npc","text":{"pl":"No dobrze! Po utworzeniu magicznej Bariery, która stała się naszym wspólnym więzieniem...","en":"Alright! After the creation of the Magic Barrier which imprisons us all...","de":"Nun gut! Nach der Erschaffung der magischen Barriere, die uns alle hier gefangen hält ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shrunning_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shrunning_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHRUNNING_Info","outputIds":["Info_Milten_SHRUNNING_15_01","Info_Milten_SHRUNNING_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Strażnik wciąż żyje!","en":"The guard''s still alive!","de":"Der Wächter lebt noch!"}},{"speaker":"npc","text":{"pl":"Więc zniszcz go przy użyciu magicznego zwoju!","en":"Then destroy him with the spell scroll.","de":"Dann vernichte ihn mit der Spruchrolle."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shscroll_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shscroll_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHSCROLL_Info","outputIds":["Info_Milten_SHSCROLL_15_01","Info_Milten_SHSCROLL_02_02","Info_Milten_SHSCROLL_02_03","Info_Milten_SHSCROLL_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Wykorzystałem zwój, ale niestety nie na Strażniku!","en":"I used the spell scroll - but not on the guard!","de":"Ich habe die Spruchrolle verbraucht ... aber nicht auf den Wächter!"}},{"speaker":"npc","text":{"pl":"Jesteśmy zgubieni! Chyba, że znajdziesz jakiś inny sposób, żeby go pokonać!","en":"This is a catastrophe! Then you will have to find another way to defeat him!","de":"Das ist großes Pech. Dann musst du einen anderen Weg finden, ihn zu besiegen."}},{"speaker":"npc","text":{"pl":"Może w którymś z obozów uda ci się kupić następny zwój albo magiczną runę.","en":"Perhaps you can buy another spell scroll or a rune in one of the camps.","de":"Vielleicht kannst du in einem Lager eine weitere Spruchrolle oder sogar eine Rune kaufen."}},{"speaker":"npc","text":{"pl":"Zaczekam na ciebie w miejscu, w którym się spotkaliśmy.","en":"I''ll wait for you over there, where we met.","de":"Ich werde dort drüben, wo wir uns getroffen haben, auf dich warten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shseal_02_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shseal_02_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHSEAL_Info","outputIds":["Info_Milten_SHSEAL_02_05","Info_Milten_SHSEAL_02_06","Info_Milten_SHSEAL_02_07"],"lines":[{"speaker":"npc","text":{"pl":"To już nie będzie potrzebne.","en":"There will be no need for that now.","de":"Das ist nicht mehr nötig."}},{"speaker":"npc","text":{"pl":"Kilka lat temu jeden z Magnatów polujący dla rozrywki na Orków okazał się na tyle bezmyślny, że zszedł do grobowca.","en":"Some years ago, an Ore Baron out pleasure hunting for Orcs was careless enough to enter the tomb.","de":"Vor einigen Jahren war ein Erzbaron, der zum Zeitvertreib Orks jagte, unvorsichtig genug, die Gruft zu betreten."}},{"speaker":"npc","text":{"pl":"Teraz ON jest strażnikiem spoczywających pod ziemią skarbów.","en":"Now HE is the guard of the treasures down there.","de":"Nun ist ER der Wächter über alle Schätze dort unten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shseal_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shseal_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHSEAL_Info","outputIds":["Info_Milten_SHSEAL_15_01","Info_Milten_SHSEAL_02_02","Info_Milten_SHSEAL_02_03","Info_Milten_SHSEAL_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Artefakt jest w jakiś sposób chroniony?","en":"The artefact was sealed away?","de":"Das Artefakt wurde versiegelt?"}},{"speaker":"npc","text":{"pl":"Tak. Strzeże go potężne zaklęcie. Pierwszy rabuś, który spróbuje go zabrać...","en":"Yes. A powerful spell protects it. The first grave robber trying to swipe the focus...","de":"Ja. Ein mächtiger Bannzauber bewirkt, dass der erste Grabräuber, der sich den Fokus unter den Nagel reißen will ..."}},{"speaker":"npc","text":{"pl":"... będzie przeklęty i zostanie skazany na wieczną egzystencję jako Ożywieniec. Od tej pory po wsze czasy sam stanie się strażnikiem kamienia, który próbował ukraść.","en":"... will be cursed, and doomed to an existence as a restless undead, who will have to protect the tomb from other grave robbers.","de":"... zu einem Dasein als ruheloser Untoter verflucht wird, der fortan diese Gruft vor allen nachfolgenden Grabräuber beschützen soll."}},{"speaker":"hero","text":{"pl":"Czy istnieje jakiś sposób na uniknięcie klątwy?","en":"How can you get past that curse?","de":"Wie kommst du dann an diesem Bannzauber vorbei?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shsuccess_02_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shsuccess_02_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHSUCCESS_Info","outputIds":["Info_Milten_SHSUCCESS_02_01","Info_Milten_SHSUCCESS_15_02","Info_Milten_SHSUCCESS_02_03","Info_Milten_SHSUCCESS_02_04"],"lines":[{"speaker":"npc","text":{"pl":"Dobrze. Widzę, że znalazłeś talizman.","en":"Good. You have the talisman.","de":"Sehr gut. Du hast den Talisman!"}},{"speaker":"hero","text":{"pl":"Proszę, weź go. Taka była umowa.","en":"Here, take it. That was our deal!","de":"Hier, nimm ihn. So war unsere Abmachung!"}},{"speaker":"npc","text":{"pl":"Dziękuję, przyjacielu. Nigdy nie zapominam o ludziach, którzy mi pomogli.","en":"Thank you, my friend. I never forget anybody who helped me.","de":"Danke, mein Freund. Ich vergesse niemanden, der mir geholfen hat. Du hast was gut bei mir!"}},{"speaker":"npc","text":{"pl":"Wrócę teraz do Starego Obozu. Może tam się jeszcze kiedyś spotkamy.","en":"I''ll go back to the Old Camp, perhaps we''ll meet there.","de":"Ich gehe zurück ins Alte Lager, vielleicht sehen wir uns dort."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shtalisman_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shtalisman_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHTALISMAN_Info","outputIds":["Info_Milten_SHTALISMAN_15_01","Info_Milten_SHTALISMAN_02_02","Info_Milten_SHTALISMAN_02_03"],"lines":[{"speaker":"hero","text":{"pl":"A co z twoim talizmanem?","en":"What about that talisman?","de":"Was hat es mit diesem Talisman auf sich?"}},{"speaker":"npc","text":{"pl":"Jestem przekonany, że jego poprzedni właściciel wykorzystywał go do ochrony przed rozwścieczonymi Orkami.","en":"I believe its former owner used it to defend himself against angry Orcs.","de":"Ich vermute, sein ehemaliger Besitzer benutzte ihn, um sich wütende Orks vom Hals zu halten."}},{"speaker":"npc","text":{"pl":"Jeśli mam rację, ten talizman może się okazać niezwykle przydatny.","en":"If I''m right, the talisman may be of great use.","de":"Wenn ich Recht habe, kann der Talisman von großem Nutzen sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shwait_02_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shwait_02_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHWAIT_Info","outputIds":["Info_Milten_SHWAIT_02_01","Info_Milten_SHWAIT_02_02","Info_Milten_SHWAIT_15_03","Info_Milten_SHWAIT_02_04"],"lines":[{"speaker":"npc","text":{"pl":"Witaj! Mój przyjaciel Lester, z obozu na bagnie powiadomił mnie o twoich niezwykłych czynach!","en":"Greetings! My friend Lester from the swamp camp told me about your great deeds there!","de":"Sei gegrüßt! Mein Freund Lester aus dem Sumpflager hat mir von deinen großen Taten dort erzählt!"}},{"speaker":"npc","text":{"pl":"Jestem pod wrażeniem. Stałeś się bardzo potężny.","en":"I am impressed. You have become very strong.","de":"Ich bin beeindruckt. Du bist sehr stark geworden."}},{"speaker":"hero","text":{"pl":"Robię co mogę.","en":"I do my best.","de":"Man tut, was man kann."}},{"speaker":"npc","text":{"pl":"Ach, zawsze skromny, co?","en":"Ah, yes. Always modest, aren''t you?","de":"Ja, ja, immer bescheiden, was?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shyou_02_05_4', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shyou_02_05_4","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHYOU_Info","outputIds":["Info_Milten_SHYOU_02_05"],"lines":[{"speaker":"npc","text":{"pl":"W tym grobowcu znajduje się przedmiot, który chciałbym zdobyć.","en":"There is something in that tomb that I''d like to have.","de":"In dieser Gruft gibt es etwas, das ich gerne haben würde."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_mage_info_milten_shyou_15_01_0', 'PC_Mage', '{"id":"missions_dia_pc_mage_info_milten_shyou_15_01_0","npcId":"PC_Mage","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Mage.d","sourceFunction":"Info_Milten_SHYOU_Info","outputIds":["Info_Milten_SHYOU_15_01","Info_Milten_SHYOU_02_02","Info_Milten_SHYOU_15_03","Info_Milten_SHYOU_02_04"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Niedaleko stąd leży starożytny kamienny krąg. W jego centrum znajduje się wejście do podziemnej komory.","en":"There is an ancient ring of stone not far from here. In its center lies the entrance to an underground vault.","de":"Nicht weit von hier befindet sich ein uraltes Stonehenge, in dessen Mitte der Eingang zu einem unterirdischen Gewölbe liegt."}},{"speaker":"hero","text":{"pl":"Jakiś rodzaj grobowca?","en":"Some sort of tomb?","de":"Eine Art Gruft?"}},{"speaker":"npc","text":{"pl":"Tak, coś w tym rodzaju.","en":"Yes, something like that.","de":"Ja, so was in der Richtung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_camp_info_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_camp_info_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_CampInfo_Info","outputIds":["DIA_Lester_CampInfo_15_00","DIA_Lester_CampInfo_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi o waszym obozie.","en":"Tell me something about the Camp.","de":"Erzähl mir was über das Lager."}},{"speaker":"npc","text":{"pl":"A co chcesz wiedzieć?","en":"What do you want to know?","de":"Was willst du wissen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_camp_info_gil_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_camp_info_gil_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_CampInfo_GIL","outputIds":["DIA_Lester_CampInfo_GIL_15_00","DIA_Lester_CampInfo_GIL_05_01","DIA_Lester_CampInfo_GIL_05_02","DIA_Lester_CampInfo_GIL_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi o tutejszych kastach.","en":"Tell me about the guilds.","de":"Erzähl mir was über die Gilden."}},{"speaker":"npc","text":{"pl":"Najwyższą kastę stanowią Guru. To niezwykle potężni duchowi przywódcy naszego obozu. Strażnicy Świątyni wykorzystują siłę swego ducha w walce.","en":"The Gurus form the highest guild. They are the spirit of this camp, for they have great power. The templars use their spiritual power in battle.","de":"Die Gurus bilden die oberste Gilde. Sie sind der Geist des Lagers, denn ihre Macht ist groß. Die Templer benutzen ihre geistige Stärke im Kampf."}},{"speaker":"npc","text":{"pl":"Ich ciało i duch funkcjonują w idealnej harmonii. Lepiej nie wchodź im w drogę. Ja natomiast jestem Nowicjuszem. Naszym zadaniem jest wykonywanie wszystkich pomniejszych zadań, no i oczywiście żarliwa modlitwa do Śniącego.","en":"They have an indomitable willpower. You should NEVER get into trouble with them. As for myself, I am a novice. We pray to the Sleeper and do all the work in the Camp.","de":"Sie haben einen unbezwingbaren Willen. Leg dich besser NIE mit ihnen an. Ich selber gehöre zu den Novizen. Wir beten zum Schläfer und verrichten die Arbeiten, die hier im Lager anfallen."}},{"speaker":"npc","text":{"pl":"Niektórzy Nowicjusze dostąpili zaszczytu pobierania nauk u Guru, ale aby to osiągnąć, trzeba służyć w Obozie przynajmniej kilka lat.","en":"Some of the novices are allowed to join the Gurus, but to get that far you need to study for many years.","de":"Einige der Novizen werden als Gurus aufgenommen, aber dazu gehört eine viele Jahre lange Ausbildung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_camp_info_herb_05_04_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_camp_info_herb_05_04_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_CampInfo_HERB","outputIds":["DIA_Lester_CampInfo_HERB_05_04"],"lines":[{"speaker":"npc","text":{"pl":"Wielu z nich dołącza do nas tylko ze względu na ziele, ale przynajmniej pomagają nam w pracy.","en":"The result is, of course, that some people only join us for the weed. Well, at least they help us with the work in the Camp.","de":"Das führt natürlich dazu, dass viele Leute nur wegen des Krauts zu uns kommen. Na ja, immerhin helfen sie bei den anfallenden Arbeiten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_camp_info_herb_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_camp_info_herb_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_CampInfo_HERB","outputIds":["DIA_Lester_CampInfo_HERB_15_00","DIA_Lester_CampInfo_HERB_05_01","DIA_Lester_CampInfo_HERB_05_02","DIA_Lester_CampInfo_HERB_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Co możesz mi powiedzieć o bagiennym zielu?","en":"What do you know about the weed?","de":"Was weißt du über das Kraut?"}},{"speaker":"npc","text":{"pl":"Cóż, ziele rośnie wyłącznie na bagnach. Zanim da się je palić, trzeba je odpowiednio przetworzyć. Tym właśnie zajmują się Nowicjusze.","en":"Well, the weed''s grown in the swamp. Of course it has to be processed before it can be smoked. That''s what we novices do.","de":"Nun, das Kraut wächst im Sumpf. Es muss natürlich noch verarbeitet werden, damit man es rauchen kann. Das machen wir Novizen."}},{"speaker":"npc","text":{"pl":"Ziele ma działanie relaksujące i uspokajające. Dzięki niemu można osiągnąć stan umysłu pozwalający na nawiązanie kontaktu ze Śniącym.","en":"The weeds have a tranquilizing and relaxing effect. They help you concentrate on the essentials and increase your awareness.","de":"Das Kraut hat eine beruhigende und entspannende Wirkung. Es hilft dir, dich auf das Wesentliche zu konzentrieren und dein Bewusstsein zu öffnen."}},{"speaker":"npc","text":{"pl":"Część zebranego ziela wymieniamy ze Starym Obozem. Tam też pozyskujemy nowych członów Bractwa.","en":"We trade them for goods from the Old Camp and we use them to recruit new people as well.","de":"Wir tauschen es gegen Waren aus den anderen Lagern und benutzen es, um neue Leute anzuwerben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_camp_info_sleeper_05_04_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_camp_info_sleeper_05_04_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_CampInfo_SLEEPER","outputIds":["DIA_Lester_CampInfo_SLEEPER_05_04","DIA_Lester_CampInfo_SLEEPER_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Hej, jestem w tej kolonii od dwóch lat. Wiesz jak długie mogą się wydać DWA LATA w więzieniu?!","en":"Hey, I''ve been inside the Barrier for two years. Do you know how long TWO YEARS can be?","de":"Hey, ich bin seit zwei Jahren in der Barriere. Weißt du überhaupt wie lange ZWEI JAHRE sein können?"}},{"speaker":"npc","text":{"pl":"Nie wyobrażasz sobie w co byłbym w stanie uwierzyć, byle tylko wydostać się z tego przeklętego miejsca!","en":"You can''t imagine what I''m willing to believe and do, just to get out of here again!","de":"Du kannst dir nicht vorstellen, was ich alles bereit bin zu glauben und zu machen, damit ich hier wieder raus komme!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_camp_info_sleeper_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_camp_info_sleeper_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_CampInfo_SLEEPER","outputIds":["DIA_Lester_CampInfo_SLEEPER_15_00","DIA_Lester_CampInfo_SLEEPER_05_01","DIA_Lester_CampInfo_SLEEPER_05_02","DIA_Lester_CampInfo_SLEEPER_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Co możesz mi powiedzieć o Śniącym?","en":"What can you tell me about the Sleeper?","de":"Was hat es mit dem Schläfer auf sich?"}},{"speaker":"npc","text":{"pl":"Śniący to boska istota, która zsyła nam wizje objawiające jego wolę. W każdym razie zsyła je Guru.","en":"The Sleeper''s a divine creature. He causes visions - at least to the Gurus.","de":"Der Schläfer ist ein göttliches Wesen. Er schenkt uns Visionen - zumindest den Gurus."}},{"speaker":"npc","text":{"pl":"Modlimy się do niego, bo obiecał zwrócić nam wolność.","en":"We pray to him, for he will give us freedom.","de":"Wir beten zu ihm, denn er wird uns allen die Freiheit schenken."}},{"speaker":"hero","text":{"pl":"I wierzycie mu?","en":"And you believe that?","de":"Und daran glaubst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_guide_offer_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_guide_offer_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_GuideOffer_Info","outputIds":["DIA_Lester_GuideOffer_15_00","DIA_Lester_GuideOffer_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Jak znajdę najważniejsze miejsca w Obozie?","en":"How can I find my way around here in the Camp?","de":"Wie kann ich mich hier im Lager zurechtfinden?"}},{"speaker":"npc","text":{"pl":"Mogę ci pokazać wszystko, co warto tu obejrzeć.","en":"I can show you the most important places.","de":"Ich kann dir die wichtigen Orte zeigen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_how_proof_worthy_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_how_proof_worthy_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_HowProofWorthy_Info","outputIds":["DIA_Lester_HowProofWorthy_15_00","DIA_Lester_HowProofWorthy_05_01","DIA_Lester_HowProofWorthy_05_02","DIA_Lester_HowProofWorthy_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak mam tego dokonać, jeśli żaden z Guru nie chce się do mnie odezwać?","en":"How''s that supposed to work if none of the Gurus will talk to me?","de":"Wie soll das funktionieren, wenn keiner der Gurus mit mir redet?"}},{"speaker":"npc","text":{"pl":"Chociaż trudno w to uwierzyć, Guru będą obserwowali każdy twój krok.","en":"It might not look like it, but the Gurus observe everything you do here in the Camp.","de":"Es hat vielleicht nicht den Anschein, aber die Gurus beobachten genau, was du hier im Lager tust."}},{"speaker":"npc","text":{"pl":"Jeśli uznają, że zasługujesz na zostanie jednym z nas, sami się do ciebie odezwą.","en":"If they think that you deserve to become a member of the community, they''ll talk to you.","de":"Wenn sie der Meinung sind, dass du dich um unsere Gemeinschaft verdient gemacht hast, werden sie dich ansprechen."}},{"speaker":"npc","text":{"pl":"Z pewnością znajdziesz w Obozie wiele okazji, by udowodnić swoją przydatność.","en":"You''re bound to have opportunities in the Camp to prove that you''re worthy.","de":"Hier im Lager werden sich sicher Gelegenheiten bieten, dich als würdig zu erweisen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_sakrileg_05_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_sakrileg_05_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_Sakrileg_Info","outputIds":["DIA_Lester_Sakrileg_05_00"],"lines":[{"speaker":"npc","text":{"pl":"Odezwałeś się do Guru! Nigdy więcej tego nie rób, to bluźnierstwo! Jeśli jakiś mistrz zechce z tobą rozmawiać, sam się do ciebie odezwie.","en":"You addressed a Guru! Never do that again! It''s sacrilege! If a master wants to talk to you, HE shall address YOU.","de":"Du hast einen Guru angesprochen!! Tu das nie wieder! Es ist ein Sakrileg! Wenn der Meister es für richtig hält, mit dir zu reden, wird ER dich ansprechen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_show_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_show_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_Show_Info","outputIds":["DIA_Lester_Show_15_00","DIA_Lester_Show_05_01","DIA_Lester_Show_15_02","DIA_Lester_Show_05_03"],"lines":[{"speaker":"hero","text":{"pl":"WYRZEKŁEM SIĘ STARYCH BOGÓW!","en":"I HAVE RENOUNCED THE OLD GODS.","de":"ICH HABE DEN ALTEN GÖTTERN ABGESCHWOREN."}},{"speaker":"npc","text":{"pl":"CZYŻBY? CO CIĘ SKŁONIŁO DO TAK DRASTYCZNYCH KROKÓW?","en":"REALLY? WHAT MADE YOU DO THAT?","de":"EHRLICH? WIE KOMMST DU ZU DIESR ENTSCHEIDUNG?"}},{"speaker":"hero","text":{"pl":"PRZEŻYŁEM OBJAWIENIE: ŚNIĄCY ZWRÓCIŁ SIĘ DO MNIE...","en":"I HAD A VISION: THE SLEEPER TALKED TO ME.","de":"ICH HATTE EINE VISION. DER SCHLÄFER HAT ZU MIR GESPROCHEN."}},{"speaker":"npc","text":{"pl":"I CO POWIEDZIAŁ?","en":"WHAT DID HE SAY?","de":"WAS HAT ER GESAGT?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_show_15_04_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_show_15_04_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_Show_Info","outputIds":["DIA_Lester_Show_15_04","DIA_Lester_Show_05_05"],"lines":[{"speaker":"hero","text":{"pl":"POWIEDZIAŁ: IDŹ DO OBOZU NA BAGNIE I PRZYŁĄCZ SIĘ DO BRACTWA.","en":"HE SAID: GO TO THE CAMP IN THE SWAMP AND JOIN THE BROOTHERHOOD.","de":"ER SAGTE, GEH IN DAS LAGER IM SUMPF UND SCHLIESS DICH DER BRUDERSCHAFT AN."}},{"speaker":"npc","text":{"pl":"JESTEŚ SZCZĘŚLIWYM CZŁOWIEKIEM, NIEZNAJOMY: TYLKO NIELICZNI DOSTĄPILI TAKIEJ NAGRODY.","en":"YOU''RE A VERY RICH MAN, STRANGER: THE SLEEPER DOESN''T REWARD MANY PEOPLE LIKE THAT.","de":"DU BIST EIN SEHR REICHER MANN, FREMDER, DER SCHLÄFER BELOHNT NICHT VIELE AUF DIESE WEISE."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_show_hallo_05_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_show_hallo_05_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_ShowHallo_Info","outputIds":["DIA_Lester_ShowHallo_05_00"],"lines":[{"speaker":"npc","text":{"pl":"ACH! MIŁO CIĘ ZNÓW WIDZIEĆ. CO U CIEBIE SŁYCHAĆ?","en":"AH! IT''S GOOD TO SEE YOU AGAIN. HOW HAVE YOU BEEN DOING?","de":"AH! GUT, DICH WIEDER ZU TREFFEN. WIE IST ES DIR ERGANGEN?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_wanna_join_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_wanna_join_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_WannaJoin_Info","outputIds":["DIA_Lester_WannaJoin_15_00","DIA_Lester_WannaJoin_05_01","DIA_Lester_WannaJoin_05_02","DIA_Lester_WannaJoin_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać członkiem Bractwa.","en":"I want to become a member of the Brotherhood!","de":"Ich will mich der Bruderschaft anschließen!"}},{"speaker":"npc","text":{"pl":"O tym, czy możesz zostać jednym z nich zadecyduje Cor Kalom.","en":"Cor Kalom decides whether you''re ready to join the Brotherhood.","de":"Cor Kalom entscheidet, ob du bereit bist, in die Bruderschaft einzutreten."}},{"speaker":"npc","text":{"pl":"Ale on polega zwykle na opinii pozostałych Guru. Baal Namib na przykład jest jednym z nich.","en":"But he relies on the advice of other Gurus. Baal Namib, over there, is one of them.","de":"Aber er verlässt sich auf den Rat der anderen Gurus. Baal Namib hier ist einer von ihnen."}},{"speaker":"npc","text":{"pl":"Najpierw musisz udowodnić, że jesteś godny, by należeć do Bractwa. Dopiero wtedy Guru wyślą cię do Cor Kaloma.","en":"First you''ll have to prove that you''re worthy and then one of the Gurus will send you to Cor Kalom.","de":"Du wirst dich erst als würdig erweisen müssen, dann wird dich einer der Gurus zu Cor Kalom schicken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_wanna_talk_to_master_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_wanna_talk_to_master_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_WannaTalkToMaster_Info","outputIds":["DIA_Lester_WannaTalkToMaster_15_00","DIA_Lester_WannaTalkToMaster_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Ale ja muszę porozmawiać z twoim mistrzem.","en":"But I want to talk to your master.","de":"Ich will aber mit deinem Meister reden."}},{"speaker":"npc","text":{"pl":"Nie próbuj! Gwarantuję ci, że potrafię udzielić ci wszystkich potrzebnych informacji.","en":"Forget it! I''m sure I can help you with any of your problems.","de":"Vergiss es! Ich bin sicher, ICH kann dir bei all deinen Problemen weiterhelfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_weit_weg_05_04_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_weit_weg_05_04_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_WeitWeg_Info","outputIds":["DIA_Lester_WeitWeg_05_04","DIA_Lester_WeitWeg_05_05","DIA_Lester_WeitWeg_05_06","DIA_Lester_WeitWeg_05_07"],"lines":[{"speaker":"npc","text":{"pl":"Baal Namib martwi się, gdyż wielu Nowicjuszy oprócz modlitwy do Śniącego czci jeszcze starych bogów.","en":"Baal Namib is worried because many of the novices don''t only pray to the Sleeper, but also to their former gods.","de":"Baal Namib macht sich zurzeit große Sorgen, weil viele Novizen nicht nur zum Schläfer beten, sondern auch noch zu ihren alten Göttern."}},{"speaker":"npc","text":{"pl":"Powiesz mi, że wyrzekłeś się innych bóstw i od tej pory zamierzasz wznosić modły wyłącznie do Śniącego.","en":"You''ll tell me that you''ve renounced the old gods and that, in future, you''ll pray only to the Sleeper.","de":"Du erzählst mir, dass du den alten Göttern abgeschworen hast, und jetzt nur noch den Schläfer anrufst."}},{"speaker":"npc","text":{"pl":"Wtedy ja zapytam dlaczego podjąłeś taką decyzję, a ty odpowiesz, że przeżyłeś wizję, w której Śniący wzywał cię do siebie.","en":"Then I''ll ask you why you made this decision and you''ll say that you had a vision in which the Sleeper summoned you.","de":"Daraufhin werde ich dich fragen, was dich dazu bewogen hat, und du sagst, du hattest eine Vision, in der der Schläfer dich zu sich gerufen hat."}},{"speaker":"npc","text":{"pl":"To go powinno zainteresować. Myślisz, że dasz sobie radę?","en":"He''ll be interested then. Do you think you''ll manage that?","de":"Das sollte sein Interesse wecken. Denkst du, du kriegst das hin?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_dia_lester_weit_weg_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_dia_lester_weit_weg_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"DIA_Lester_WeitWeg_Info","outputIds":["DIA_Lester_WeitWeg_15_00","DIA_Lester_WeitWeg_05_01","DIA_Lester_WeitWeg_15_02","DIA_Lester_WeitWeg_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogę skłonić twojego mistrza do rozmowy ze mną?","en":"How can I get your master to talk to me?","de":"Wie bringe ich deinen Meister dazu, mit mir zu reden?"}},{"speaker":"npc","text":{"pl":"Musisz wiedzieć, co chciałby usłyszeć?","en":"You have to know what he wants to hear.","de":"Du musst wissen, was er hören will."}},{"speaker":"hero","text":{"pl":"A co chciałby usłyszeć?","en":"And that is?","de":"Nämlich?"}},{"speaker":"npc","text":{"pl":"Kiedy następnym razem będziemy blisko niego, zwrócisz się do mnie i porozmawiamy chwilę.","en":"Listen: When we''re with him the next time, you''ll address me and we''ll have a little talk.","de":"Pass auf: Wenn wir beide das nächste Mal bei ihm sind, sprichst du mich an, und wir unterhalten uns ein bisschen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_info_freemine_orc_exit_15_03_16', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_info_freemine_orc_exit_15_03_16","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"Info_Lester_DIEGOMILTEN_Info","outputIds":["Info_FreemineOrc_EXIT_15_03","Info_Lester_EXIT_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Dziękuję. Muszę już ruszać w dalszą drogę.","en":"Thank you. I''ll be on my way now.","de":"Ich danke dir. Ich werde mich jetzt wieder auf den Weg machen."}},{"speaker":"npc","text":{"pl":"Niech Śniący ma cię w swojej opiece!","en":"May the Sleeper protect you!","de":"Der Schläfer möge dich behüten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_info_lester_diegomilten_15_01_8', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_info_lester_diegomilten_15_01_8","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"Info_Lester_DIEGOMILTEN_Info","outputIds":["Info_lester_DIEGOMILTEN_15_01","SVM_5_YeahWellDone","Info_Gorn_RUINWALLWHAT_15_01","Info_lester_DIEGOMILTEN_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Chce się z tobą spotkać, tam gdzie zawsze.","en":"They want to meet you. At your usual rendezvous.","de":"Sie wollen sich mit dir treffen. An eurem üblichen Treffpunkt."}},{"speaker":"npc","text":{"pl":"Najwyższy czas!","en":"It was about time!","de":"Wurde aber auch Zeit!"}},{"speaker":"hero","text":{"pl":"I co teraz?","en":"What happens now?","de":"Wie geht es nun weiter?"}},{"speaker":"npc","text":{"pl":"Zostanę tutaj, żeby przejrzeć stare księgi.","en":"I''ll stay here to read the old books.","de":"Ich werde noch etwas bleiben, um die alten Bücher zu studieren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_info_lester_exit_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_info_lester_exit_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_Exit_Info","outputIds":["Info_Lester_EXIT_05_01","Info_Lester_EXIT_05_02"],"lines":[{"speaker":"npc","text":{"pl":"Chodźmy.","en":"Let''s go!","de":"Dem Ziel entgegen!"}},{"speaker":"npc","text":{"pl":"Niech Śniący ma cię w swojej opiece!","en":"May the Sleeper protect you!","de":"Der Schläfer möge dich behüten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_info_sfb_1_die_lage_15_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_info_sfb_1_die_lage_15_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"Info_Lester_DIEGOMILTEN_Info","outputIds":["Info_SFB_1_DieLage_15_00","PC_Psionic_FOLLOWME_Info_05_01","Info_Saturas_COLLAPSE_15_01","DIA_Fingers_BecomeShadow_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać?","en":"How are you doing?","de":"Wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Hej, co tu robisz?","en":"Hey, what are you doing here?","de":"Hey, was machst du denn hier?"}},{"speaker":"hero","text":{"pl":"Stara Kopalnia została zalana przez podziemną rzekę!","en":"The Old Mine collapsed after water seeped in!","de":"Die Alte Mine wurde nach einem Wassereinbruch verschüttet!"}},{"speaker":"npc","text":{"pl":"I co z tego?","en":"So?","de":"Und?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_info_xardas_kdw_15_01_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_info_xardas_kdw_15_01_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"Info_Lester_DIEGOMILTEN_Info","outputIds":["Info_Xardas_KDW_15_01","Info_Xardas_KDW_15_02","SVM_5_GetThingsRight","Info_Gorn_DIEGOMILTEN_15_01"],"lines":[{"speaker":"hero","text":{"pl":"Wszyscy Magowie Ognia zginęli!","en":"All the Magicians of Fire are dead!","de":"Die Feuermagier sind alle tot!"}},{"speaker":"hero","text":{"pl":"Gomez kazał ich zamordować.","en":"Gomez had them assassinated.","de":"Gomez hat sie ermorden lassen."}},{"speaker":"npc","text":{"pl":"Nie łatwo będzie to teraz odkręcić!","en":"It won''t be easy to straighten that out!","de":"Das wieder hinzubiegen wird nicht einfach!"}},{"speaker":"hero","text":{"pl":"Spotkałem Diego i Miltena przed Starym Obozem!","en":"I met Diego and Milten in front of the Old Camp!","de":"Ich habe Diego und Milten vor dem Alten Lager getroffen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_kdw_600_saturas_oath_info_15_06_12', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_kdw_600_saturas_oath_info_15_06_12","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"Info_Lester_DIEGOMILTEN_Info","outputIds":["KDW_600_Saturas_OATH_Info_15_06","PC_Psionic_TIP_Info_05_02","Info_Grd_6_DasLager_WasIstAerger_15_04","DIA_Fingers_Lehrer_Pickpocket2_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Eee... Nie rozumiem...","en":"Uhh... I don''t understand...","de":"Ähh ... Ich verstehe nicht ..."}},{"speaker":"npc","text":{"pl":"Mistrz Y''Berion zwykł mawiać: Uczeń próbuje przesuwać przedmioty rękami i nogami. Mistrz porusza je siłą swego ducha.","en":"Master Y''Berion used to say: A student tries to move things with his hands and feet, the master moves them with his spiritual powers.","de":"Meister Y''Berion sagte immer: Der Schüler versucht die Dinge mit Händen und Füßen zu bewegen, der Meister bewegt die Dinge mit der Kraft seiner Gedanken."}},{"speaker":"hero","text":{"pl":"Dobrze, dobrze. Zrozumiałem aluzję.","en":"Okay, okay, I get the point.","de":"Schon gut, ich hab''s verstanden."}},{"speaker":"npc","text":{"pl":"Uważaj na siebie.","en":"Take care.","de":"Also pass auf dich auf."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_balkon_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_balkon_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_BALKON_Info","outputIds":["PC_Psionic_BALKON_Info_05_01"],"lines":[{"speaker":"npc","text":{"pl":"Pójdę rozejrzeć się na górze.","en":"I''ll go and have a look up there.","de":"Ich werde mich mal oben umsehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_brotherhood_todo_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_brotherhood_todo_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_BROTHERHOOD_TODO_Info","outputIds":["PC_Psionic_BROTHERHOOD_TODO_15_01","PC_Psionic_BROTHERHOOD_TODO_05_02","PC_Psionic_BROTHERHOOD_TODO_15_03","PC_Psionic_BROTHERHOOD_TODO_05_04"],"lines":[{"speaker":"hero","text":{"pl":"Czemu miałbym być tym zainteresowany?","en":"What''s that got to do with me?","de":"Was kann ich dabei tun?"}},{"speaker":"npc","text":{"pl":"Porozmawiaj koniecznie z Jaśnie Oświeconym Y''Berionem. To twoja wielka szansa, żeby spojrzał na ciebie łaskawym okiem.","en":"Talk to Y''Berion. He''s the most powerful man around here. This is the opportunity to attain his favor.","de":"Sprich mit Y''Berion. Er ist der mächtigste Mann hier. Dies ist die Gelegenheit, seine Gunst zu erringen."}},{"speaker":"hero","text":{"pl":"Gdzie mogę go znaleźć?","en":"Where do I find him?","de":"Wo finde ich ihn?"}},{"speaker":"npc","text":{"pl":"Idź do świątyni. Bardzo rzadko ją opuszcza. Pewnie w tych zimnych ruinach czuje się bliżej Śniącego niż gdzie indziej.","en":"Go to the temple. He rarely leaves it. Probably he feels closer to the Sleeper in those cold ruins.","de":"Geh zum Tempel. Er kommt selten dort heraus. Wahrscheinlich fühlt er sich in diesem kalten Gemäuer dem Schläfer näher."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_change_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_change_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_CHANGE_Info","outputIds":["PC_Psionic_CHANGE_Info_15_01","PC_Psionic_CHANGE_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Rozmyśliłem się.","en":"I''ve changed my mind.","de":"Ich habe es mir anders überlegt."}},{"speaker":"npc","text":{"pl":"Wiesz, gdzie mnie znaleźć.","en":"Suppose you know where to find me.","de":"Du weißt ja, wo du mich finden kannst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_chestclosed_info_05_05_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_chestclosed_info_05_05_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_CHESTCLOSED_Info","outputIds":["PC_Psionic_CHESTCLOSED_Info_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Zaglądałeś już do biblioteki?","en":"Did you have a look around the library?","de":"Hast du schon in der Bibliothek nachgesehen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_chestclosed_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_chestclosed_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_CHESTCLOSED_Info","outputIds":["PC_Psionic_CHESTCLOSED_Info_15_01","PC_Psionic_CHESTCLOSED_Info_05_02","PC_Psionic_CHESTCLOSED_Info_05_03","PC_Psionic_CHESTCLOSED_Info_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłeś coś?","en":"Have you found anything?","de":"Hast du schon was gefunden?"}},{"speaker":"npc","text":{"pl":"Tamta skrzynia jest zamknięta. Może uda się nam gdzieś znaleźć klucz.","en":"The chest over there is locked. Maybe we can find the key somewhere in this fort.","de":"Die Truhe da vorne ist verschlossen. Vielleicht gibt es irgendwo in dieser Festung einen Schlüssel."}},{"speaker":"npc","text":{"pl":"Znalazłeś już ten dokument?","en":"Have you found the document yet?","de":"Gibt es irgendwelche Hinweise auf die Urkunde?"}},{"speaker":"hero","text":{"pl":"Nie, jeszcze nie...","en":"No, not yet...","de":"Nein, bisher noch nicht ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_comeagain_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_comeagain_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_COMEAGAIN_Info","outputIds":["PC_Psionic_COMEAGAIN_Info_15_01","PC_Psionic_COMEAGAIN_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Przeszukajmy tę fortecę razem.","en":"Let''s sound out the fort together.","de":"Lass uns zusammen die Festung erkunden."}},{"speaker":"npc","text":{"pl":"Dobrze, idź przodem!","en":"Alright, you go first!","de":"In Ordnung, du gehst vor!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_comeback_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_comeback_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_COMEBACK_Info","outputIds":["PC_Psionic_COMEBACK_Info_05_01"],"lines":[{"speaker":"npc","text":{"pl":"Dokąd się wybierasz? Jeszcze nie skończyliśmy!","en":"Where are you going? We''re not finished here yet!","de":"Wo willst du hin? Wir sind hier noch nicht fertig!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_comewithme_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_comewithme_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_COMEWITHME_Info","outputIds":["PC_Psionic_COMEWITHME_Info_15_01","PC_Psionic_COMEWITHME_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Moglibyśmy wspólnie rozejrzeć się po fortecy!","en":"We could have a look around the fort together!","de":"Wir könnten die Festung gemeinsam erkunden!"}},{"speaker":"npc","text":{"pl":"Niezły pomysł. Prowadź. Pójdę za tobą.","en":"That''s a good idea. You go first, I''ll stay near you.","de":"Ein guter Vorschlag. Geh du voraus, ich bleibe in deiner Nähe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_finish_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_finish_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_FINISH_Info","outputIds":["PC_Psionic_FINISH_Info_05_01","PC_Psionic_FINISH_Info_15_02"],"lines":[{"speaker":"npc","text":{"pl":"Teraz obaj mamy to, po co przyszliśmy. Chciałbym tu jeszcze trochę zostać, poczytać stare księgi.","en":"Now both of us have what we wanted. I''ll stay here to read the old books.","de":"Nun haben wir beide, was wir wollten. Ich werde noch etwas bleiben, um die alten Bücher zu studieren."}},{"speaker":"hero","text":{"pl":"Do następnego spotkania!","en":"We''ll meet again.","de":"Wir sehen uns wieder."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_fokusplace_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_fokusplace_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_FOKUSPLACE_Info","outputIds":["PC_Psionic_FOKUSPLACE_Info_05_01","PC_Psionic_FOKUSPLACE_Info_15_02"],"lines":[{"speaker":"npc","text":{"pl":"Patrz, chyba miałeś rację co do tego kamienia ogniskującego.","en":"Look, looks like the focus you''re looking for is up there.","de":"Sieh mal, dort oben scheint der Fokus zu sein, den du suchst."}},{"speaker":"hero","text":{"pl":"Racja, to rzeczywiście wygląda na punkt ogniskujący... Ale nie łatwo go będzie dosięgnąć...","en":"Right, looks like a focus platform, hm... It''s not that easy to reach it...","de":"Ja, sieht aus wie ein Fokusplatz, hm ... so einfach komme ich da nicht dran ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_followme_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_followme_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_FOLLOWME_Info","outputIds":["PC_Psionic_FOLLOWME_Info_05_01","PC_Psionic_FOLLOWME_Info_15_02","PC_Psionic_FOLLOWME_Info_05_03","PC_Psionic_FOLLOWME_Info_15_04"],"lines":[{"speaker":"npc","text":{"pl":"Hej, co tu robisz?","en":"Hey, what are you doing here?","de":"Hey, was machst du denn hier?"}},{"speaker":"hero","text":{"pl":"Przybywam z polecenia Magów Wody. Szukam magicznych artefaktów zwanych kamieniami ogniskującymi.","en":"I came here by order of the Magicians of Water. I''m looking for magical artefacts, so-called focus stones.","de":"Ich bin im Auftrag der Wassermagier unterwegs. Ich suche magische Artefakte, sogenannte Fokussteine."}},{"speaker":"npc","text":{"pl":"Szukasz kamieni ogniskujących, tak? Odważny jesteś.","en":"You''re looking for the focus stones? You''re really brave.","de":"Du bist auf der Suche nach den Fokussteinen? Das ist verdammt mutig."}},{"speaker":"hero","text":{"pl":"Saturas i pozostali magowie z Nowego Obozu zamierzają wykorzystać ich moc, by wysadzić w powietrze Barierę i zwrócić nam wolność.","en":"Saturas and the other magicians from the New Camp want to use it to detonate the Barrier in order to free us from this imprisonment.","de":"Saturas und die anderen Magier aus dem Neuen Lager wollen damit die Barriere sprengen, die uns alle gefangen hält."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_followme_info_05_05_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_followme_info_05_05_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_FOLLOWME_Info","outputIds":["PC_Psionic_FOLLOWME_Info_05_05","PC_Psionic_FOLLOWME_Info_15_06","PC_Psionic_FOLLOWME_Info_05_07","PC_Psionic_FOLLOWME_Info_05_08"],"lines":[{"speaker":"npc","text":{"pl":"Jak zobaczę to uwierzę...","en":"I''ll believe that when I see it with my own eyes.","de":"Das glaube ich erst, wenn ich es gesehen habe."}},{"speaker":"hero","text":{"pl":"Tu się zgadzamy... Ale powiedz, czemu ty tu przyszedłeś?","en":"I feel the same. But tell me, why did you come here?","de":"Das geht mir ähnlich, aber erzähl, was führt dich her?"}},{"speaker":"npc","text":{"pl":"Zastanawiam się, czy warto zaryzykować wyprawę do górskiej fortecy.","en":"I''m weighing up if it''s worthwhile paying a visit to the mountain fort.","de":"Ich wäge gerade ab, ob es sich lohnt, der Festung einen Besuch abzustatten."}},{"speaker":"npc","text":{"pl":"Wiesz... jest tam pewien dokument, który chciałbym odzyskać, ale taka wyprawa może się okazać bardzo niebezpieczna.","en":"You know,... there is a document I''d like to get. On the other hand it''s quite risky to go in there.","de":"Es gibt nämlich eine alte Urkunde, die ich gerne in meiner Tasche hätte. Andererseits ist es nicht ganz ungefährlich, dort hineinzugehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_guidefirst_herb_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_guidefirst_herb_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_GUIDEFIRST_HERB","outputIds":["PC_Psionic_GUIDEFIRST_HERB_Info_15_01","PC_Psionic_GUIDEFIRST_HERB_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"... do laboratorium alchemicznego.","en":"... to the alchemy lab!","de":"... zum Alchemielabor!"}},{"speaker":"npc","text":{"pl":"Chodź za mną!","en":"Follow me!","de":"folge mir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_guidefirst_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_guidefirst_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_GUIDEFIRST_Info","outputIds":["PC_Psionic_GUIDEFIRST_Info_15_01","PC_Psionic_GUIDEFIRST_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Pokaż mi jak dojść...","en":"Show me the way...","de":"Zeig mir den Weg ..."}},{"speaker":"npc","text":{"pl":"Klar, wohin willst du?","en":"Klar, wohin willst du?","de":"Klar, wohin willst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_guidefirst_smith_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_guidefirst_smith_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_GUIDEFIRST_SMITH","outputIds":["PC_Psionic_GUIDEFIRST_SMITH_Info_15_01","PC_Psionic_GUIDEFIRST_SMITH_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"... do kuźni.","en":"... to the blacksmith shop.","de":"... zur Schmiede."}},{"speaker":"npc","text":{"pl":"Chodź za mną!","en":"Follow me!","de":"folge mir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_guidefirst_tempel_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_guidefirst_tempel_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_GUIDEFIRST_TEMPEL","outputIds":["PC_Psionic_GUIDEFIRST_TEMPEL_Info_15_01","PC_Psionic_GUIDEFIRST_TEMPEL_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"... do świątyni.","en":"... to the temple.","de":"... zum Tempel."}},{"speaker":"npc","text":{"pl":"Chodź za mną!","en":"Follow me!","de":"folge mir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_herb_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_herb_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_HERB_Info","outputIds":["PC_Psionic_HERB_Info_05_01","PC_Psionic_HERB_Info_05_02"],"lines":[{"speaker":"npc","text":{"pl":"Na górze tej drabiny znajdziesz laboratorium alchemiczne Cor Kaloma. Tu na dole rezyduje Fortuno, handlarz zielem.","en":"If you climb up this ladder you''ll meet Kalom, the alchemist. Down here is Fortuno, the weed merchant.","de":"Wenn du die Leiter raufsteigst, dann kommst du zu Kalom, dem Alchemisten. Hier unten steht Fortuno, der Krauthändler."}},{"speaker":"npc","text":{"pl":"Zaczekam na ciebie tutaj. Tylko nie marudź zbyt długo, bo wrócę do Baal Namiba.","en":"I''ll wait for you right here. But don''t take too long, otherwise I''ll go back.","de":"Ich warte hier auf dich, aber lass dir nicht zu viel Zeit, sonst gehe ich wieder zurück."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_iamhurt_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_iamhurt_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_IAMHURT_Info","outputIds":["PC_Psionic_IAMHURT_Info_15_01","PC_Psionic_IAMHURT_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Jestem ranny. Możesz mi pomóc?","en":"I''m injured. Can you help me?","de":"Ich bin verletzt, kannst du mir helfen?"}},{"speaker":"npc","text":{"pl":"Weź ten napój uzdrawiający.","en":"Take this healing potion.","de":"Hier, nimm diesen Heiltrank."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_leave_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_leave_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_LEAVE_Info","outputIds":["PC_Psionic_LEAVE_Info_05_01"],"lines":[{"speaker":"npc","text":{"pl":"Zostanę tutaj jeszcze trochę i poszukam dokumentu.","en":"I''ll stay here to find the document.","de":"Ich bleibe noch hier und suche die Urkunde."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_normal_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_normal_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_GOLEM_Info","outputIds":["PC_Psionic_NORMAL_Info_15_01","PC_Psionic_NORMAL_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak ci się udało przejść przez tę żywą górę?","en":"How did you manage to get past that living mountain?","de":"Wie bist du eigentlich an dem wandelnden Steinhaufen vorbeigekommen?"}},{"speaker":"npc","text":{"pl":"Pobierałem nauki u najlepszych Guru. Ich magia potrafi być bardzo przydatna.","en":"I''ve learned a lot from the Gurus. Their magic can be really helpful.","de":"Ich habe einiges von den Gurus gelernt. Vor allem ihre Magie erweist sich immer wieder als sehr hilfreich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_send_info_05_00_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_send_info_05_00_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_SEND_Info","outputIds":["PC_Psionic_SEND_Info_05_00","PC_Psionic_SEND_Info_15_01","PC_Psionic_SEND_Info_05_02","PC_Psionic_SEND_Info_15_03"],"lines":[{"speaker":"npc","text":{"pl":"Cieszę się, że cię widzę. Mam dla ciebie wiadomość.","en":"I''m glad you''re here. I have news for you.","de":"Gut, dass du da bist. Ich habe Neuigkeiten."}},{"speaker":"hero","text":{"pl":"Mam nadzieję, że dobrą?","en":"Good news, I hope.","de":"Ich hoffe, gute Neuigkeiten."}},{"speaker":"npc","text":{"pl":"Nasze Bractwo przygotowuje się do wielkiego wydarzenia.","en":"Our Brotherhood''s planning a really big thing.","de":"Unsere Bruderschaft plant etwas ganz Großes."}},{"speaker":"hero","text":{"pl":"Jakiego wydarzenia? Planujecie ucieczkę?","en":"What are you planning? To break out?","de":"Was plant ihr denn? Den Ausbruch?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_send_info_05_04_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_send_info_05_04_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_SEND_Info","outputIds":["PC_Psionic_SEND_Info_05_04","PC_Psionic_SEND_Info_15_05","PC_Psionic_SEND_Info_05_06"],"lines":[{"speaker":"npc","text":{"pl":"Guru próbują skontaktować się ze Śniącym, ale potrzebują czegoś, co zjednoczy ich duchowe siły.","en":"The Gurus are trying to contact the Sleeper. But they need something to unite their powers.","de":"Die Gurus versuchen, Kontakt zum Schläfer herzustellen. Aber sie brauchen etwas, um ihre Kräfte zu bündeln."}},{"speaker":"hero","text":{"pl":"I co dalej?","en":"Oh, and?","de":"Ja, und?"}},{"speaker":"npc","text":{"pl":"Poszukują magicznego artefaktu, kamienia ogniskującego.","en":"They need a magical object, a focus.","de":"Sie brauchen einen magischen Gegenstand, einen Fokus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_smith_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_smith_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_SMITH_Info","outputIds":["PC_Psionic_SMITH_Info_05_01"],"lines":[{"speaker":"npc","text":{"pl":"Jesteśmy w kuźni. Rozejrzyj się trochę. Będę czekał przez jakąś godzinę. Później znajdziesz mnie przy wejściu do obozu.","en":"\"That''s the smithy! Have a look around; I''ll wait here for about an hour, then I''ll leave.\"","de":"Hier ist die Schmiede! Schau dich um, ich warte etwa eine Stunde, dann haue ich wieder ab."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_soon_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_soon_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_SOON_Info","outputIds":["PC_Psionic_SOON_Info_15_01","PC_Psionic_SOON_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Daleko jeszcze?","en":"Are we nearly there yet?","de":"Sind wir gleich da?"}},{"speaker":"npc","text":{"pl":"Jakbyś mi nie przeszkadzał, dawno bylibyśmy na miejscu.","en":"If you stopped asking me, we''d get there much faster.","de":"Wenn du aufhörst, mich zu fragen, geht es schneller."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_story_info_05_05_4', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_story_info_05_05_4","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_STORY_Info","outputIds":["PC_Psionic_STORY_Info_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Wiem. Ale prędzej czy później magowie zdołają przerwać Barierę. Wtedy ten kawałek papieru zapewni mi dostatnie życie na długie lata.","en":"That''s right. But if the water mages manage to destroy the Barrier, the document might become quite valuable again.","de":"Das stimmt. Aber wenn die Wassermagier es doch schaffen, die Barriere zu zerstören, dann könnte die Urkunde wieder einiges wert sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_story_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_story_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_STORY_Info","outputIds":["PC_Psionic_STORY_Info_15_01","PC_Psionic_STORY_Info_05_02","PC_Psionic_STORY_Info_05_03","PC_Psionic_STORY_Info_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Ten dokument, którego szukasz... Co to jest?","en":"This document you''re looking for... what is it?","de":"Was ist das für eine Urkunde, die du suchst?"}},{"speaker":"npc","text":{"pl":"Wiele lat temu władca tych ziem rezydował w górskiej fortecy, skąd kontrolował kopalnię i okoliczne tereny.","en":"Many years ago, the lord of this area lived in this mountain fort. He controlIed the land and the mines.","de":"In dieser Bergfestung lebte vor vielen Jahren der Lehnsherr dieses Landstriches. Ihm unterstanden das Land und die Minen."}},{"speaker":"npc","text":{"pl":"Jak wszyscy możni, posiadał w swoich zbiorach dokument, który poświadczał jego prawo do tych ziem. Zamierzam odnaleźć to pismo.","en":"Like any other aristocrat, he had, of course, a document to verify his tenure. And I''ll get this document.","de":"Er hatte natürlich, wie jeder Adelige, eine Urkunde über den Besitz. Und die werde ich mir holen."}},{"speaker":"hero","text":{"pl":"Przecież tak długo, jak będziemy uwięzieni wewnątrz Bariery, ten dokument nie będzie wart złamanego grosza!","en":"But as long as we are being kept in here by the Barrier, it won''t be worth anything.","de":"Aber solange die Barriere uns gefangen hält, nützt sie dir gar nichts."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_tempel_info_05_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_tempel_info_05_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_TEMPEL_Info","outputIds":["PC_Psionic_TEMPEL_Info_05_01"],"lines":[{"speaker":"npc","text":{"pl":"Oto świątynia! Zaczekam na ciebie tutaj, ale gdybyś zamarudził, znajdziesz mnie przy wejściu do Obozu.","en":"That''s the temple! I''ll wait for you, but if you take too long, I''ll go back to Baal Namib.","de":"Hier ist der Tempel! Ich werde auf dich warten, aber wenn du dir zu viel Zeit lässt, dann gehe ich zurück zu Baal Namib."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_tip_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_tip_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_TIP_Info","outputIds":["PC_Psionic_TIP_Info_15_01","PC_Psionic_TIP_Info_05_02","PC_Psionic_TIP_Info_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak mam dosięgnąć tego kamienia?","en":"How can I reach the focus?","de":"Wie soll ich den Fokus erreichen?"}},{"speaker":"npc","text":{"pl":"Mistrz Y''Berion zwykł mawiać: Uczeń próbuje przesuwać przedmioty rękami i nogami. Mistrz porusza je siłą swego ducha.","en":"Master Y''Berion used to say: A student tries to move things with his hands and feet, the master moves them with his spiritual powers.","de":"Meister Y''Berion sagte immer: Der Schüler versucht die Dinge mit Händen und Füßen zu bewegen, der Meister bewegt die Dinge mit der Kraft seiner Gedanken."}},{"speaker":"npc","text":{"pl":"Hier ist ein guter Ort, um die Kraft des Geistes zu nutzen!","en":"Hier ist ein guter Ort, um die Kraft des Geistes zu nutzen!","de":"Hier ist ein guter Ort, um die Kraft des Geistes zu nutzen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_psionic_pc_psionic_urkunde_info_15_01_0', 'PC_Psionic', '{"id":"missions_dia_pc_psionic_pc_psionic_urkunde_info_15_01_0","npcId":"PC_Psionic","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Psionic.d","sourceFunction":"PC_Psionic_URKUNDE_Info","outputIds":["PC_Psionic_URKUNDE_Info_15_01","PC_Psionic_URKUNDE_Info_05_02","PC_Psionic_URKUNDE_Info_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem dokument!","en":"I''ve found the document.","de":"Ich habe die Urkunde gefunden."}},{"speaker":"npc","text":{"pl":"Dobra robota! Przyjmij te zwoje magiczne jako wyraz mojej wdzięczności. Przy ich pomocy uda ci się dotrzeć do kamienia.","en":"Hey, well done. Take these magic scrolls as a reward. With them you''ll be able to reach the focus.","de":"Hey, gut gemacht. Dafür gebe ich dir diese Spruchrollen. Damit sollte es kein Problem sein, den Fokus zu erreichen."}},{"speaker":"npc","text":{"pl":"Zaczekam na ciebie przy platformie.","en":"I''ll wait for you down by the focus platform.","de":"Ich werde unten vor der Fokusplattform auf dich warten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_barriere_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_barriere_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Barriere_Info","outputIds":["Info_Diego_Barriere_15_00","Info_Diego_Barriere_11_01","Info_Diego_Barriere_15_02","Info_Diego_Barriere_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi jeszcze o Barierze.","en":"Tell me more about the Barrier.","de":"Erzähl mir was über die Barriere."}},{"speaker":"npc","text":{"pl":"Nie ma za bardzo o czym mówić. Jest nie do sforsowania.","en":"There isn''t much to tell. It''s impenetrable.","de":"Da gibt es nicht viel zu erzählen. Sie ist undurchdringlich."}},{"speaker":"hero","text":{"pl":"A co się stanie, jeśli po prostu spróbuję stąd wyjść?","en":"What happens if I just walk out of here?","de":"Was passiert, wenn ich hier einfach wieder rausspaziere?"}},{"speaker":"npc","text":{"pl":"Ostatni, który tego spróbował dotarł na drugą stronę jako trup. Przez to przeklęte magiczne pole można wejść, ale już nigdy się stąd nie wydostaniesz.","en":"The last one who tried that reached the other side a dead man. This damned Barrier let''s you in, but you''ll never get out of here.","de":"Der Letzte, der das versucht hat, ist tot auf der anderen Seite angekommen. Diese verdammte Barriere lässt dich zwar rein, aber raus kommst du hier nicht mehr."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_barriere_15_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_barriere_15_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Barriere_Info","outputIds":["Info_Diego_Barriere_15_04","Info_Diego_Barriere_11_05"],"lines":[{"speaker":"hero","text":{"pl":"Jeśli jest stąd jakieś wyjście - znajdę je.","en":"If there''s a way out, I''ll find it.","de":"Wenn es einen Weg hier raus gibt, werde ich ihn finden."}},{"speaker":"npc","text":{"pl":"Tak ci spieszno, żeby się stąd wyrwać? Dopiero co tu trafiłeś!","en":"You''re already in a rush to get out of here? But you''ve only just arrived!","de":"Hast du''s SO eilig, hier wieder rauszukommen? Du bist ja gerade mal da!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_brief_11_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_brief_11_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Brief_Info","outputIds":["Info_Diego_Brief_11_04","Info_Diego_Brief_11_05","Info_Diego_Brief_15_06","Info_Diego_Brief_11_07"],"lines":[{"speaker":"npc","text":{"pl":"A to dlatego, że magowie hojnie opłacają swoich kurierów, a większość z tutejszych ludzi nic nie posiada.","en":"That''s because the mages pay their couriers a lot and most people here don''t have anything.","de":"Die Magier belohnen ihre Boten immer sehr gut, und die meisten hier haben gar nichts, verstehst du?"}},{"speaker":"npc","text":{"pl":"Na twoim miejscu trzymałbym język za zębami aż do chwili, gdy spotkasz któregoś z magów. Chociaż wątpię, żeby ci się udało.","en":"If I were you I''d shut up until I met one of the mages. Although, in your situation, that''s not likely to happen.","de":"Wenn ich du wäre, würde ich die Schnauze halten, bis ich einen der Magier treffe. Obwohl das in deiner Lage nicht allzu wahrscheinlich ist."}},{"speaker":"hero","text":{"pl":"Dlaczego?","en":"Why not?","de":"Wieso nicht?"}},{"speaker":"npc","text":{"pl":"Magowie mieszkają w zamku, w Starym Obozie. Tylko ludzie Gomeza mają tam wstęp.","en":"The mages are in the castle in the Old Camp. Only Gomez'' people are allowed to enter the castle.","de":"Die Magier sind in der Burg im Alten Lager. Nur Gomez'' Leuten ist es erlaubt, die Burg zu betreten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_brief_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_brief_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Brief_Info","outputIds":["Info_Diego_Brief_15_00","Info_Diego_Brief_11_01","Info_Diego_Brief_15_02","Info_Diego_Brief_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam list do Arcymistrza Magów Ognia.","en":"I have a letter for the High Magician of the Circle of Fire.","de":"Ich habe einen Brief für den obersten Feuermagier."}},{"speaker":"npc","text":{"pl":"Czyżby...?","en":"Really...?","de":"So...?"}},{"speaker":"hero","text":{"pl":"Jakiś mag dał mi go zanim mnie tu wrzucono.","en":"I was given it by a mage shortly before they threw me in here.","de":"Ein Magier hat ihn mir gegeben, kurz bevor sie mich reingeworfen haben."}},{"speaker":"npc","text":{"pl":"Twoje szczęście, że nie mogę się więcej pokazywać u magów. Ktoś inny mógłby ci poderżnąć gardło za taki list.","en":"You''re lucky I can''t afford to show my face around the mages any more. Anyone else would gladly slit your throat for that letter.","de":"Du kannst von Glück sagen, dass ich mich bei den Magiern nicht mehr blicken lassen kann. Jeder andere wird dir mit Freude für diesen Brief die Kehle durchschneiden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_bring_list_offer_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_bring_list_offer_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_BringList_Offer_Info","outputIds":["Info_Diego_BringList_Offer_15_00","Info_Diego_BringList_Offer_11_01","Info_Diego_BringList_Offer_11_02","Info_Diego_BringList_Offer_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Na czym polega test zaufania?","en":"What''s the test of faith?","de":"Was ist die Prüfung des Vertrauens?"}},{"speaker":"npc","text":{"pl":"Będziesz się musiał wybrać do Starej Kopalni. Tam znajdziesz faceta imieniem Ian. Od niego dostaniesz listę.","en":"You have to go to the Old Mine. There you''ll meet a guy called Ian. He''ll give you a list.","de":"Du sollst für mich zur alten Mine gehen. Dort triffst du einen Kerl namens Ian. Er wird dir eine Liste geben."}},{"speaker":"npc","text":{"pl":"To bardzo ważny dokument. Zawiera spis wszystkich rzeczy, których potrzebują od nas ludzie z kopalni.","en":"This list is important. It contains all the items the guys in the mine need from us.","de":"Diese Liste ist wichtig. Da steht drauf, was die Jungs in der Mine von uns brauchen."}},{"speaker":"npc","text":{"pl":"Postaramy się, żeby dostarczono je z następnym konwojem.","en":"They''ll get the stuff with the next convoy!","de":"Das schicken wir ihnen dann mit dem nächsten Convoy!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_bring_list_offer_15_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_bring_list_offer_15_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_BringList_Offer_Info","outputIds":["Info_Diego_BringList_Offer_15_04","Info_Diego_BringList_Offer_11_05","Info_Diego_BringList_Offer_11_06"],"lines":[{"speaker":"hero","text":{"pl":"Żaden problem!","en":"No problem!","de":"Kein Problem!"}},{"speaker":"npc","text":{"pl":"Właśnie że jest problem. Ta lista nie może wpaść w ręce ludzi z Nowego Obozu!","en":"Yes, there is a problem! The New Camp must not get that list!","de":"Oh, doch! Das ist ein Problem. Das Neue Lager darf auf keinen Fall die Liste in die Finger bekommen!"}},{"speaker":"npc","text":{"pl":"Jak już powiedziałem: to bardzo ważna lista. Jeśli nie zawalisz - daleko tu zajdziesz.","en":"Like I said: The list is important. If you do it right, you''ll get much further.","de":"Wie ich schon sagte, die Liste ist wichtig. Wenn du die Sache gut machst, bringt dich das einen großen Schritt weiter."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_bring_list_success_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_bring_list_success_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_BringList_Success_Info","outputIds":["Info_Diego_BringList_Success_15_00","Info_Diego_BringList_Success_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Mam listę od Iana.","en":"I have the list from Ian.","de":"Ich hab'' die Liste von Ian."}},{"speaker":"npc","text":{"pl":"Dobra robota! Zaczynasz mi się naprawdę podobać!","en":"Well done! That''ll get you a few brownie points!","de":"Gut gemacht! Das bringt dir einige Pluspunkte ein!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_bullit_15_02_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_bullit_15_02_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Bullit_Info","outputIds":["Info_Diego_Bullit_15_02","Info_Diego_Bullit_11_03","Info_Diego_Bullit_11_04"],"lines":[{"speaker":"hero","text":{"pl":"A gdzie jest teraz Bullit?","en":"Where''s Bullit now?","de":"Wo ist dieser Bullit jetzt?"}},{"speaker":"npc","text":{"pl":"On i pozostali przenoszą towary z zewnątrz do Obozu. Tam go znajdziesz.","en":"He and the others bring the goods from the outside world into the Camp. You''ll find him there.","de":"Er und die anderen bringen die Waren aus der Außenwelt ins alte Lager. Dort kannst du ihn finden."}},{"speaker":"npc","text":{"pl":"Ale jeśli chcesz z nim walczyć, radzę ci uważać. To doświadczony wojownik.","en":"But if you plan to fight him, be careful. He''s an experienced warrior.","de":"Aber wenn du vorhast, dich mit ihm anzulegen, sei vorsichtig. Er ist ein erfahrener Kämpfer."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_celebs_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_celebs_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Celebs_Info","outputIds":["Info_Diego_Celebs_15_00","Info_Diego_Celebs_11_01","Info_Diego_Celebs_11_02","Info_Diego_Celebs_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę te ważne osoby?","en":"Where do I find the important people?","de":"Wo finde ich die wichtigen Leute?"}},{"speaker":"npc","text":{"pl":"Cóż, na jednego z nich właśnie patrzysz. Poza tym, jest jeszcze Thorus, jego już znasz.","en":"Well, you''re looking at one of them. Then there''s Thorus... you already know him.","de":"Nun, einer steht hier direkt vor dir, dann wäre da noch Thorus, den kennst du ja schon."}},{"speaker":"npc","text":{"pl":"Co do pozostałych... sam musisz ich rozpoznać. Jeśli nie jesteś w stanie tego zrobić, to i tak nie masz tu czego szukać.","en":"As for the others... you''ll have to find that out by yourself. If you don''t manage to do that, you don''t belong here anyway.","de":"Was die anderen betrifft, das wirst du selbst rausfinden müssen. Wenn du dazu nicht in der Lage bist, hast du hier im Lager sowieso nichts verloren."}},{"speaker":"npc","text":{"pl":"Najlepiej przejdź się po Zewnętrznym Pierścieniu i porozmawiaj z ludźmi.","en":"Just go through the Outer Ring and talk to people, then you''ll find out who''s important.","de":"Geh einfach durch den Außenring und rede mit den Leuten. Du findest dann schon raus, an wen du dich halten mußt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_exit_11_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_exit_11_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_EXIT_Later_Info","outputIds":["Info_Diego_EXIT_11_01","Info_Diego_EXIT_15_00"],"lines":[{"speaker":"npc","text":{"pl":"Chodźmy.","en":"Let''s go on.","de":"Weiter geht''s."}},{"speaker":"hero","text":{"pl":"Trzymaj się.","en":"Take care.","de":"Mach''s gut."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_exit_gamestart_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_exit_gamestart_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_EXIT_Gamestart_Info","outputIds":["Info_Diego_EXIT_Gamestart_15_00","Info_Diego_EXIT_Gamestart_11_01","Info_Diego_EXIT_Gamestart_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Dzięki za pomoc.","en":"Thanks for your help.","de":"Danke für die Hilfe."}},{"speaker":"npc","text":{"pl":"Jak sobie chcesz. Miło było cię poznać.","en":"It''s your decision. It''s been nice knowing you.","de":"Wie du willst. War nett, dich gekannt zu haben."}},{"speaker":"npc","text":{"pl":"Spotkamy się w Starym Obozie.","en":"We''ll meet in the Old Camp.","de":"Wir sehen uns im Alten Lager."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_join_analyze_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_join_analyze_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_JoinAnalyze_15_00","Info_Diego_JoinAnalyze_11_01","Info_Diego_JoinAnalyze_15_02","Info_Diego_JoinAnalyze_Scatty_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Jak tam z moją opinią w Obozie?","en":"What about my esteem within the Camp?","de":"Wie steht''s mit meinem Ansehen im Lager?"}},{"speaker":"npc","text":{"pl":"Rozmawiałem z kilkoma ludźmi...","en":"I''ve talked to a few people...","de":"Ich hab'' mal mit ein paar Leuten geredet..."}},{"speaker":"hero","text":{"pl":"I?","en":"And?","de":"Und?"}},{"speaker":"npc","text":{"pl":"Scatty powiedział mi, że pokonałeś Kirgo.","en":"Scatty told me you defeated Kirgo.","de":"Scatty hat mir gesagt, du hast Kirgo besiegt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_join_analyze_dexter_11_01_16', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_join_analyze_dexter_11_01_16","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_JoinAnalyze_Dexter_11_01","Info_Diego_JoinAnalyze_Dexter_11_02","Info_Diego_JoinAnalyze_Dexter_11_03","Info_Diego_JoinAnalyze_Thorus_11_01"],"lines":[{"speaker":"npc","text":{"pl":"Muszę poważnie porozmawiać z Dexterem. Wykorzystuje cię do załatwiania własnych porachunków.","en":"I really need to talk to Dexter. He''s using you for his own business.","de":"Mit Dexter muss ich noch ein ernstes Wörtchen reden. Er benutzt dich für seine eigenen Geschäfte."}},{"speaker":"npc","text":{"pl":"Ale jeśli chodzi o nasz test - nie ma żadnych przepisów. Jeśli uda ci się dokonać czegoś TAKIEGO, to będzie wielki krok do przodu.","en":"But there aren''t any rules for the test. If you manage THAT you''ll be making a big step.","de":"Aber es gibt keine Regeln für die Probe. Wenn du DAS schaffst, bist du einen großen Schritt weiter."}},{"speaker":"npc","text":{"pl":"Naprawdę udało ci się zdobyć przepis Kaloma. Dexter jest pod wrażeniem. Ja zresztą też!","en":"You''ve really managed to get the recipe from Kalom. Dexter is very impressed, and so am I.","de":"Du hast es tatsächlich geschafft, Kalom das Rezept abzuluchsen. Ich bin mindestens genauso beeindruckt wie Dexter."}},{"speaker":"npc","text":{"pl":"Ta sprawa z Mordragiem to nie lada wyzwanie. Niezły z niego wojownik. Musisz porządnie poćwiczyć, jeśli chcesz go pokonać.","en":"The business with Mordrag is really quite a job. He''s not bad as a warrior. You should exercise if you really want to defeat him.","de":"Bei der Mordrag-Sache hast du ''nen ganz schönen Brocken als Auftrag angenommen. Er ist kein schlechter Kämpfer. Du solltest einigermaßen trainiert sein, wenn du ihn schaffen willst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_join_analyze_scatty_11_02_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_join_analyze_scatty_11_02_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_JoinAnalyze_Scatty_11_02","Info_Diego_JoinAnalyze_Scatty_11_03","Info_Diego_JoinAnalyze_Scatty_11_04","Info_Diego_JoinAnalyze_Scatty_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Scatty powiedział mi, że pozwoliłeś Kirgo spuścić sobie baty. Chyba nie jest tobą zachwycony.","en":"Scatty told me you let Kirgo beat you. He didn''t seem to be very enthusiastic.","de":"Scatty hat mir gesagt, du hast gegen Kirgo verloren. Er hat sich nicht seher begeistert angehört."}},{"speaker":"npc","text":{"pl":"Scatty powiedział mi, że nie może się doczekać na twoją walkę z Kirgo.","en":"Scatty has told me he''s anxious to see how you come off against Kirgo.","de":"Scatty hat mir gesagt, er wäre gespannt, wie du gegen Kirgo abschneidest."}},{"speaker":"npc","text":{"pl":"Ale był pod wrażeniem twojej śmiałości. Nie każdy miałby odwagę, żeby wyzwać Kharima. Choćby nawet z nim przegrał.","en":"But he was impressed by you having the courage to fight against Kharim, even though you''ve been defeated.","de":"Aber dass du den Mumm gehabt hast, gegen Kharim anzutreten hat ihm imponiert, obwohl du verloren hast."}},{"speaker":"npc","text":{"pl":"Ale był pod wielkim wrażeniem twojej walki z Kharimem. Bez przerwy opowiada jaki to z ciebie wojownik.","en":"But he was greatly impressed that you defeated Kharim - he wouldn''t stop talking about you at all.","de":"Aber dass du gegen Kharim gewonnen hast, hat ihn total von den Socken gehauen - er hat gar nicht mehr aufgehört, von dir zu reden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_join_analyze_scatty_11_06_8', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_join_analyze_scatty_11_06_8","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_JoinAnalyze_Scatty_11_06","Info_Diego_JoinAnalyze_Whistler_11_01","Info_Diego_JoinAnalyze_Whistler_11_02","Info_Diego_JoinAnalyze_Whistler_11_03"],"lines":[{"speaker":"npc","text":{"pl":"I nie może się doczekać, kiedy staniesz do walki z Kharimem.","en":"And he''s anxious to see if you''ll challenge Kharim.","de":"Und er war sehr gespannt, ob du Kharim herausfordern wirst."}},{"speaker":"npc","text":{"pl":"Świstak opowiedział mi o tej historii z Fiskiem... Cóż, na twoim miejscu wziąłbym tę rudę i dał nogę, ale tak, czy inaczej - Świstak chyba bardzo cię polubił.","en":"Whistler told me the story about Fisk... Well, if I was you I would have taken the ore and cleared off. But anyway - he thinks a great deal of you.","de":"Whistler hat mir von der Sache mit Fisk erzählt... Also ich an deiner Stelle wäre ja mit dem Erz durchgebrannt. Aber egal - er hält jedenfalls große Stücke auf dich."}},{"speaker":"npc","text":{"pl":"Rozmawiałem ze Świstakiem. Zwiałeś z jego rudą, cwaniaku! Muszę przyznać, że śmiałości ci nie brakuje!","en":"I''ve talked to Whistler. You took his ore, you clever bastard! I must admit, you''re quite brave!","de":"Ich hab'' mit Whistler geredet. Du bist mit seinem Erz durchgebrannt, du gerissener Hund! Ich muss schon sagen, Mut hast du ja!"}},{"speaker":"npc","text":{"pl":"Świstak czeka na swój miecz. Zdecyduj się wreszcie czy zamierzasz mu go dać, czy nie. W przeciwnym wypadku może pomyśleć, że zwiałeś z jego rudą!","en":"Whistler is waiting for his sword. You should make up your mind whether to bring it to him or not, otherwise he''ll think that you''ve cleared off with his ore!","de":"Whistler wartet auf sein Schwert. Du solltest dich entscheiden, ob du''s ihm bringen willst, sonst denkt er noch, du brennst mit seinem Erz durch!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_join_analyze_sly_11_01_12', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_join_analyze_sly_11_01_12","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_JoinAnalyze_Sly_11_01","Info_Diego_JoinAnalyze_Sly_11_02","Info_Diego_JoinAnalyze_Fingers_11_01","Info_Diego_JoinAnalyze_Fingers_11_02"],"lines":[{"speaker":"npc","text":{"pl":"Zły powiedział mi, że znalazłeś Neka. Wydawał się być bardzo zadowolony.","en":"Sly told me that you''ve found Nek. He seemed to be really content.","de":"Sly hat mir erzählt, du hast Nek gefunden. Er wirkte sehr zufrieden."}},{"speaker":"npc","text":{"pl":"Moim zdaniem Zły myli się co do Neka. Był uciążliwy, to fakt, ale nie wierzę, żeby zdezerterował do Nowego Obozu.","en":"I think Sly''s wrong about Nek. He was a real pain, that''s true, but I don''t think he went to the New Camp.","de":"Ich denke, bei der Sache mit Nek liegt Sly falsch. Er hat zwar immer viel gemeckert, aber ins Neue Lager ist er sicher nicht gegangen."}},{"speaker":"npc","text":{"pl":"Mówiłem ci już o Rączce! On może cię wiele nauczyć!","en":"I''ve already sent you to Fingers - he could really teach you something!","de":"Zu Fingers hab'' ich dich ja schon geschickt - du solltest ruhig etwas von ihm lernen."}},{"speaker":"npc","text":{"pl":"Rączka powiedział mi, że trochę się już nauczyłeś, ale uważa, że mógłbyś być jeszcze lepszy.","en":"Fingers told me that you''ve already learned a bit, but he thinks you can still improve your skills.","de":"Fingers sagt, du hättest was gelernt. Er denkt, du wirst noch um einiges besser werden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_join_analyze_thorus_11_02_20', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_join_analyze_thorus_11_02_20","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_JoinAnalyze_Thorus_11_02","Info_Diego_JoinAnalyze_Thorus_11_03","Info_Diego_JoinAnalyze_Fisk_11_01","Info_Diego_JoinAnalyze_Fisk_11_02"],"lines":[{"speaker":"npc","text":{"pl":"Thorus uważa, że przyda się nam ktoś taki jak ty - to dla ciebie niezwykle korzystne.","en":"Thorus says we could make use of someone like you - that''s very good for you.","de":"Thorus sagt, so einen wie dich können wir brauchen - das allein ist schon verdammt viel Wert für dich."}},{"speaker":"npc","text":{"pl":"Thorus dostał ataku apopleksji. Zresztą wcale mu się nie dziwię. Jak można AŻ TAK schrzanić robotę?","en":"Thorus''s head nearly burst because he was raging mad - how dare you screw up the job LIKE THIS?","de":"Thorus ist fast der Kopf geplatzt, so hat er geschrien - was hast du dir dabei gedacht, gerade diese Sache SO zu vermasseln?"}},{"speaker":"npc","text":{"pl":"Fisk powiedział mi, ze go zaskoczyłeś. W każdym razie będzie po twojej stronie.","en":"Fisk told me you surprised him. In any case he''ll be on your side.","de":"Fisk hat mir gesagt, du hättst ihn überascht. Er ist auf jeden Fall auf deiner Seite."}},{"speaker":"npc","text":{"pl":"Fisk bardzo się na ciebie wkurzył. Na twoim miejscu znalazłbym kogoś na miejsce Mordraga.","en":"Fisk is really pissed off with you. If I were you I''d look for someone to replace Mordrag.","de":"Fisk ist echt sauer auf dich, Mann. Wenn ich du wäre würd ich mich um Ersatz für Mordrag kümmern."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_kolonie_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_kolonie_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Kolonie_Info","outputIds":["Info_Diego_Kolonie_15_00","Info_Diego_Kolonie_11_01","Info_Diego_Kolonie_11_02","Info_Diego_Kolonie_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Dobra, co powinienem wiedzieć o tym miejscu?","en":"Okay, what do I need to know about this place?","de":"Okay, was muss ich über diesen Ort wissen?"}},{"speaker":"npc","text":{"pl":"Nazywamy je kolonią. Wiesz już, że wydobywamy rudę dla króla.","en":"We call it the colony. You''ll know already that we produce ore for the King.","de":"Wir nennen es die Kolonie. Du wirst sicher schon gehört haben, dass wir hier Erz für den König fördern."}},{"speaker":"npc","text":{"pl":"Cóż, w każdym razie tak robią ludzie ze Starego Obozu.","en":"Well, at least we do - in the Old Camp.","de":"Nun - zumindest wir vom alten Lager."}},{"speaker":"npc","text":{"pl":"Wewnątrz Bariery powstały trzy obozy. Największy i najstarszy jest tak zwany Stary Obóz.","en":"There are three camps within the Barrier. The Old Camp is the biggest, and it was the first.","de":"Es gibt drei Lager innerhalb der Barriere. Das alte Lager ist das größte von ihnen. Es war auch das erste."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_map_to_old_mine_info_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_map_to_old_mine_info_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_MapToOldMine_Info","outputIds":["Info_Diego_MapToOldMine_Info_15_00","Info_Diego_MapToOldMine_Info_11_01","Info_Diego_MapToOldMine_Info_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę Starą Kopalnię?","en":"Where can I find the Old Mine?","de":"Wo finde ich die Alte Mine?"}},{"speaker":"npc","text":{"pl":"Porozmawiaj z Grahamem, to nasz kartograf. Powiedz mu, że ja cię przysyłam, i że potrzebujesz mapy. Z niej dowiesz się, gdzie leży kopalnia.","en":"Go to Graham. He''s a cartographer. Tell him that I sent you and that you need a map. It''ll show you the way to the mine.","de":"Geh zu Graham. Er zeichnet Karten. Sag ihm, du kommst von mir. Er soll dir ''ne Karte geben. Auf der wirst du die Mine finden."}},{"speaker":"npc","text":{"pl":"Graham mieszka na lewo od północnej bramy.","en":"He lives to the left of the north gate.","de":"Er wohnt drüben links neben dem Nordtor."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocfavor_11_05_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocfavor_11_05_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCFAVOR_Info","outputIds":["Info_Diego_OCFAVOR_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Dzięki, przyjacielu. Widzę, że równy z ciebie gość. Idź już. Jeszcze się kiedyś spotkamy.","en":"Thanks, my friend. You really seem to be an alright guy. Go now, we''ll meet again later.","de":"Danke, mein Freund. Du scheinst wirklich in Ordnung zu sein. Geh nun, wir sehen uns später."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocfavor_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocfavor_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCFAVOR_Info","outputIds":["Info_Diego_OCFAVOR_15_01","Info_Diego_OCFAVOR_11_02","Info_Diego_OCFAVOR_11_03","Info_Diego_OCFAVOR_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Nie ma sprawy. O co chodzi?","en":"Consider it done. Tell me what you want!","de":"Ist schon so gut wie erledigt. Sprich!"}},{"speaker":"npc","text":{"pl":"Znajdź Lestera i Gorna. Muszą się dowiedzieć o tym, co się tutaj wydarzyło.","en":"Look out for Lester and Gorn. They need to know what happened here.","de":"Suche Lester und Gorn. Sie müssen wissen, was hier passiert ist."}},{"speaker":"npc","text":{"pl":"Powiedz im, że spotkamy się we czwórkę tam gdzie zwykle.","en":"Tell them that the four of us will meet at the same place as always.","de":"Richte ihnen aus, dass wir vier uns wie immer am verabredeten Platz treffen."}},{"speaker":"hero","text":{"pl":"Jeśli znajdę ich przed tobą, przekażę im ostrzeżenie i wezwanie na spotkanie.","en":"If I see them before you do, I''ll warn them and send them to your meeting point.","de":"Wenn ich sie vor euch treffe, werde ich sie warnen und zu eurem Treffpunkt schicken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocfm_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocfm_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCFM_Info","outputIds":["Info_Diego_OCFM_15_01","Info_Diego_OCFM_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Napad na Wolną Kopalnię?","en":"A raid on the Free Mine?","de":"Ein Überfall auf die Freie Mine?"}},{"speaker":"npc","text":{"pl":"To długa historia.","en":"That''s a long story.","de":"Das ist eine etwas längere Geschichte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocguards_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocguards_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCGUARDS_Info","outputIds":["Info_Diego_OCGUARDS_15_01","Info_Diego_OCGUARDS_11_02","Info_Diego_OCGUARDS_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Widziałem Strażników pilnujących zamkniętych bram.","en":"I''ve seen the guards in front of the locked gates.","de":"Ich habe Gardisten vor den verschlossenen Toren gesehen."}},{"speaker":"npc","text":{"pl":"Trzymaj się z dala od nich. Zaatakują każdego, kto spróbuje dostać się do Obozu.","en":"Stay away from them. They''ll attack anybody approaching the Camp.","de":"Halt dich bloß von ihnen fern. Sie greifen jeden an, der sich dem Lager nähert."}},{"speaker":"npc","text":{"pl":"Obawiają się odwetu za napad na Wolną Kopalnię.","en":"They are afraid of somebody avenging the raid on the Free Mine.","de":"Sie haben wohl Angst vor den Vergeltungsmaßnahmen nach dem Überfall auf die Freie Mine."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ockdf_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ockdf_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCKDF_Info","outputIds":["Info_Diego_OCKDF_15_01","Info_Diego_OCKDF_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Co się stało z Magami Ognia?","en":"Why are the fire mages dead?","de":"Wieso sind die Feuermagier tot?"}},{"speaker":"npc","text":{"pl":"To długa historia.","en":"That''s a long story.","de":"Das ist eine etwas längere Geschichte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocmine_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocmine_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCMINE_Info","outputIds":["Info_Diego_OCMINE_15_01","Info_Diego_OCMINE_11_02","Info_Diego_OCMINE_11_03","Info_Diego_OCMINE_11_04"],"lines":[{"speaker":"hero","text":{"pl":"Jak mogło dojść do zawalenia się kopalni?","en":"How could the Old Mine cave in?","de":"Wie konnte die Alte Mine einstürzen?"}},{"speaker":"npc","text":{"pl":"Jeden z Kopaczy, któremu udało się uratować, powiedział, że kopiąc na najniższym poziomie trafili na podziemną rzekę.","en":"One of the diggers who survived it told us that they were digging, and they hit an underground river on the bottom level.","de":"Einer der Buddler, der sich retten konnte, erzählte davon, dass sie auf der untersten Minenebene einen unterirdischen Fluß angegraben haben."}},{"speaker":"npc","text":{"pl":"Kiedy woda wdarła się do szybów, popękały podpory i runęła cała górna część.","en":"When the water gushed into the mine, one of the supports broke and the entire upper section collapsed.","de":"Als das Wasser in die Mine einbrach, wusch es einige Stützpfeiler weg und der gesamte obere Bereich stürzte ein."}},{"speaker":"npc","text":{"pl":"Tylko garstce ludzi udało się wydostać na powierzchnię.","en":"Only a handful of people managed to escape from the mine.","de":"Nur eine Hand voll Leute haben es aus der Mine lebend herausgeschafft."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocmurder_11_05_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocmurder_11_05_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCMURDER_Info","outputIds":["Info_Diego_OCMURDER_11_05"],"lines":[{"speaker":"npc","text":{"pl":"No właśnie. Corristo i jego ludzie byli zbyt zadufani w sobie. Gomez przestał im ufać i kazał ich zdradziecko zamordować.","en":"Well, yes, Corristo and the others shouldn''t have been so self-confident. Gomez didn''t trust them any more and had them perfidiously assassinated.","de":"Tja, Corristo und die anderen hätten wohl weniger forsch auftreten sollen. Gomez verlor das Vertrauen zu ihnen und ließ sie hinterrücks niederstrecken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocmurder_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocmurder_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCMURDER_Info","outputIds":["Info_Diego_OCMURDER_15_01","Info_Diego_OCMURDER_11_02","Info_Diego_OCMURDER_11_03","Info_Diego_OCMURDER_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Ale co stało się z Magami Ognia?","en":"But what happened to the fire mages?","de":"Aber was passierte mit den Feuermagiern?"}},{"speaker":"npc","text":{"pl":"Corristo i jego towarzysze byli jedynymi ludźmi w obozie, którzy zachowali zimną krew.","en":"Corristo and the other mages were the only people in the Camp to remain rational.","de":"Corristo und die anderen Magier waren die einzigen im Lager, die vernünftig blieben."}},{"speaker":"npc","text":{"pl":"Zabronili przeprowadzenia ataku i domagali się pertraktacji z pozostałymi obozami.","en":"They forbad the raid and demanded a settlement with the two other camps","de":"Sie verboten den Überfall und forderten eine Einigung mit den beiden anderen Lagern."}},{"speaker":"hero","text":{"pl":"ZABRONILI Gomezowi przeprowadzenia ataku na Wolną Kopalnię?","en":"They FORBADE Gomez to raid the Free Mine?","de":"Sie VERBOTEN Gomez den Überfall auf die Freie Mine?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocretreat_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocretreat_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCRETREAT_Info","outputIds":["Info_Diego_OCRETREAT_15_01","Info_Diego_OCRETREAT_11_02","Info_Diego_OCRETREAT_11_03"],"lines":[{"speaker":"hero","text":{"pl":"I co teraz zamierzacie zrobić? To znaczy - ty i Milten?","en":"What are you and Milten going to do now?","de":"Was wollen Milten und du nun machen?"}},{"speaker":"npc","text":{"pl":"Zostaniemy tu jeszcze przez jakiś czas. Będziemy ostrzegali innych przyjaciół, żeby nie wpadli w łapy Strażników.","en":"We''ll stay here for a while to warn some more friends so they don''t bump straight into the guards.","de":"Wir werden hier noch eine Weile ausharren und andere Freunde warnen, bevor sie den fanatischen Gardisten in die Hände laufen."}},{"speaker":"npc","text":{"pl":"Ale mógłbyś coś dla nas zrobić.","en":"But you could do us a favor.","de":"Aber du könntest uns noch einen Gefallen tun."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocstory_11_05_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocstory_11_05_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCSTORY_Info","outputIds":["Info_Diego_OCSTORY_11_05","Info_Diego_OCSTORY_11_06","Info_Diego_OCSTORY_15_07","Info_Diego_OCSTORY_11_08"],"lines":[{"speaker":"npc","text":{"pl":"No właśnie. Przecież bez stałego napływu rudy, handel ze światem zewnętrznym padnie raz - dwa.","en":"That''s right. Since he has no source of income any more, the goods from the outside world won''t come in any more, either.","de":"Richtig. Nun, da er von seiner einzigen Einnahmequelle abgeschnitten ist, wird auch der Warenfluß von der Außenwelt bald stoppen."}},{"speaker":"npc","text":{"pl":"Jeśli Gomez nie znajdzie szybko nowego źródła dochodu, ludzie przestaną go słuchać.","en":"Nobody will work for him if he doesn''t get another source of income soon.","de":"Niemand wird mehr für ihn arbeiten wollen, wenn nicht bald eine andere Einnahmequelle aufgetrieben wird."}},{"speaker":"hero","text":{"pl":"I dlatego postanowił najechać Wolną Kopalnię?","en":"And that''s the reason for the raid on the Free Mine?","de":"Und deshalb ein Überfall auf die Freie Mine?"}},{"speaker":"npc","text":{"pl":"Cóż, obiektywnie rzecz biorąc, to jedyna szansa Gomeza na zachowanie władzy.","en":"To be honest, that''s Gomez'' only chance to maintain his power.","de":"Das ist - neutral betrachtet - die einzige Chance, die Gomez hat, seine Macht zu erhalten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocstory_11_09_8', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocstory_11_09_8","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCSTORY_Info","outputIds":["Info_Diego_OCSTORY_11_09"],"lines":[{"speaker":"npc","text":{"pl":"Dwie godziny temu dwa tuziny strażników wyruszyły w kierunku Wolnej Kopalni.","en":"Two hours ago two dozen guards set out for the Free Mine.","de":"Vor einigen Stunden sind zwei Dutzend Gardisten in Richtung Freie Mine aufgebrochen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocstory_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocstory_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCSTORY_Info","outputIds":["Info_Diego_OCSTORY_15_01","Info_Diego_OCSTORY_11_02","Info_Diego_OCSTORY_11_03","Info_Diego_OCSTORY_15_04"],"lines":[{"speaker":"hero","text":{"pl":"Opowiadaj, to nie pierwsza długa historia, której musiałem wysłuchać.","en":"Just tell me about it! It''s not the first long story I''ve had to listen to!","de":"Nun erzähl schon! Es ist nicht die erste längere Geschichte, die ich mir anhören muss!"}},{"speaker":"npc","text":{"pl":"No dobra. Na szczęście byłem właśnie w siedzibie Magnatów, kiedy dotarły do nich wieści o zawaleniu się kopalni.","en":"Well then. Luckily, I was in the Ore Barons'' house when they got the news that the mine had collapsed.","de":"Nun gut. Ich hatte das Glück, mich beim Eintreffen der Nachricht vom Einsturz der Mine im Haus der Erzbarone aufzuhalten."}},{"speaker":"npc","text":{"pl":"Kiedy Gomez dowiedział się o wypadku, oszalał z wściekłości. Wcale mu się nie dziwię - jego autorytet mógł runąć w każdej chwili, razem z kopalnią.","en":"Gomez was hopping mad when he heard about the accident and he was afraid that his position could be at stake.","de":"Gomez war über das Unglück völlig außer sich und sah dadurch sofort seine Machtposition gefährdet."}},{"speaker":"hero","text":{"pl":"Jasne. Kto kontroluje rudę, kontroluje całą kolonię!","en":"Of course. Who controls the ore controls the colony as well!","de":"Klar. Wer das Erz kontrolliert, kontrolliert die Kolonie!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_ocwarnnc_15_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_ocwarnnc_15_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OCWARNNC_Info","outputIds":["Info_Diego_OCWARNNC_15_01","Info_Diego_OCWARNNC_11_02","Info_Diego_OCWARNNC_15_03","Info_Diego_OCWARNNC_11_04"],"lines":[{"speaker":"hero","text":{"pl":"To szaleństwo! Muszę uprzedzić Nowy Obóz.","en":"That''s mad! I need to warn the New Camp.","de":"Das ist Wahnsinn! Ich muss das Neue Lager warnen."}},{"speaker":"npc","text":{"pl":"W takim razie lepiej się pospiesz! Strażnicy są już pewnie niedaleko Wolnej Kopalni.","en":"Then you must hurry up! They''ll have almost reached the Free Mine.","de":"Dann solltest du dich beeilen, denn sie dürften die Freie Mine schon fast erreicht haben."}},{"speaker":"hero","text":{"pl":"Ale przecież nie przedrą się tak łatwo przez obronne fortyfikacje Nowego Obozu!","en":"But they never get through the fortifications of the New Camp.","de":"Aber sie würden niemals an den Befestigungen des Neuen Lagers vorbeikommen."}},{"speaker":"npc","text":{"pl":"Wcale nie muszą się przez nie przedzierać. Kilka miesięcy temu znaleźliśmy ścieżkę, która prowadzi przez góry wprost do Wolnej Kopalni. Nikt inny nie wie o jej istnieniu.","en":"They don''t need to get through them. A few months ago, they found a path that leads over the mountains and right to the Free Mine - and nobody else knows about it.","de":"Das ist nicht nötig. Schon vor einigen Monaten haben sie einen Weg über die Berge zur Freien Mine gefunden, den niemand sonst kennt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_old_camp_11_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_old_camp_11_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OldCamp_Info","outputIds":["Info_Diego_OldCamp_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Ty też możesz mieć w tym udział. Musisz tylko dołączyć do ludzi Gomeza.","en":"You can also get some of it. All you have to do is join Gomez'' people.","de":"Du kannst auch deinen Teil davon bekommen. Alles, was du tun mußt, ist dich Gomez'' Leuten anzuschließen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_old_camp_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_old_camp_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OldCamp_Info","outputIds":["Info_Diego_OldCamp_15_00","Info_Diego_OldCamp_11_01","Info_Diego_OldCamp_11_02","Info_Diego_OldCamp_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Opowiedz mi o Starym Obozie.","en":"Tell me something about the Old Camp.","de":"Erzähl mir was über das alte Lager."}},{"speaker":"npc","text":{"pl":"To największy i najpotężniejszy z trzech obozów. Gomez i jego ludzie kontrolują kopalnię, a tym samym - cały handel ze światem zewnętrznym.","en":"It''s the biggest and most powerful of the three camps. Gomez and his guys control the Camp and thereby the whole ore trade.","de":"Es ist das größte und mächtigste der drei Lager. Gomez und seine Jungs kontrollieren das Lager und damit den ganzen Erzaustausch."}},{"speaker":"npc","text":{"pl":"Raz w miesiącu król przysyła nam wszystko, czego potrzebujemy. Mamy staruszka w garści, kapujesz?","en":"Once a month, the King sends us everything we need. We''ve got the old guy in our grip, you understand?","de":"Einmal im Monat schickt der König uns alles, was wir fordern. Wir haben den alten Sack in der Hand, verstehst du? Er ist auf das Erz angewiesen."}},{"speaker":"npc","text":{"pl":"Przysyła nam broń, chleb, mięso... wszystko.","en":"He sends us wine, bread, meat, weapons... everything.","de":"Er schickt uns Wein, Brot, Fleisch, Waffen, einfach alles."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_other_camps_11_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_other_camps_11_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OtherCamps_Info","outputIds":["Info_Diego_OtherCamps_11_04","Info_Diego_OtherCamps_11_05"],"lines":[{"speaker":"npc","text":{"pl":"Wygląda na to, że jeszcze trochę poczekają.","en":"He hasn''t responded so far.","de":"Bis jetzt hat er sich noch nicht gemeldet."}},{"speaker":"npc","text":{"pl":"Na twoim miejscu nie traciłbym czasu na zadawanie się z szaleńcami.","en":"If I were you, I wouldn''t waste my time on those madcaps.","de":"Wenn ich du wäre, würde ich meine Zeit nicht mit den Spinnern verschwenden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_other_camps_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_other_camps_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_OtherCamps_Info","outputIds":["Info_Diego_OtherCamps_15_00","Info_Diego_OtherCamps_11_01","Info_Diego_OtherCamps_11_02","Info_Diego_OtherCamps_11_03"],"lines":[{"speaker":"hero","text":{"pl":"A co z pozostałymi obozami?","en":"What about the two other camps?","de":"Was ist mit den beiden anderen Lagern?"}},{"speaker":"npc","text":{"pl":"Te dwa obozy zamieszkują szaleńcy, którzy próbują się stąd wydostać za wszelką cenę.","en":"The two other camps split up to pursue their crazy escape plans.","de":"Die beiden anderen Lager haben sich abgespalten, um ihren schwachsinnigen Ausbruchsplänen nachzugehen."}},{"speaker":"npc","text":{"pl":"W zachodniej części kolonii znajduje się Nowy Obóz. Rezydują tam magowie, którzy myślą, że uda się im wysadzić Barierę, jak tylko zbiorą dostatecznie dużo rudy.","en":"There''s the New Camp in the west of the colony, where the mages think they can just detonate the Barrier as soon as they''ve scraped enough ore together.","de":"Es gibt das neue Lager im Westen der Kolonie. Die Magier dort meinen, wenn sie genug Erz zusammengekratzt haben, können sie die Barriere einfach sprengen."}},{"speaker":"npc","text":{"pl":"No i są jeszcze świry z Sekty, na wschodzie. Ich obóz znajduje się na środku bagna. Oni z kolei czekają aż ich bóstwo pomoże im się stąd wydostać.","en":"And then there''s the sect loonies in the east. Their camp is in the middle of the swamp, and they''re praying to their idol to set them free.","de":"Dann gibt''s im Osten die Sektenspinner. Sie haben ihr Lager im Sumpf und beten zu ihrem Götzen, er möge ihnen die Freiheit schenken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_points_11_00_24', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_points_11_00_24","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_Points_11_00","Info_Diego_Points_11_01","Info_Diego_Points_11_02","Info_Diego_Points_11_10"],"lines":[{"speaker":"npc","text":{"pl":"Udało ci się zjednać wystarczająco wiele osób.","en":"You''ve found enough people to speak in your favor.","de":"Du hast genug Leute gefunden, die für dich sprechen."}},{"speaker":"npc","text":{"pl":"Przeszedłeś również test zaufania. Idź do Thorusa. Już go o wszystkim powiadomiłem. Pozwoli ci się spotkać z Gomezem.","en":"You also passed the test of faith. Go to Thorus. I''ve already told him everything. He''ll let you go to see Gomez.","de":"Und die Prüfung des Vertrauens hast du auch bestanden. Geh zu Thorus. Ich habe ihm schon alles erzählt. Er wird dich zu Gomez lassen."}},{"speaker":"npc","text":{"pl":"Ale musisz jeszcze przejść test zaufania.","en":"But you still have to pass the test of faith.","de":"Aber die Prüfung des Vertrauens liegt noch vor dir."}},{"speaker":"npc","text":{"pl":"W sumie - całkiem nieźle jak na żółtodzioba.","en":"All things considered, that''s not too bad for a newcomer.","de":"Alles in allem schon nicht so schlecht für eine Neuen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_points_11_20_28', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_points_11_20_28","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_JoinAnalyze_Info","outputIds":["Info_Diego_Points_11_20","Info_Diego_Points_11_30"],"lines":[{"speaker":"npc","text":{"pl":"Bierz się do roboty. Przed tobą jeszcze daleka droga, jeśli chcesz do czegoś dojść w tym obozie.","en":"Get on with it! There are still many things to do if you wanna get anywhere here in the Camp.","de":"Halt dich ran, es gibt noch viel zu tun, wenn du es hier im Lager zu was bringen willst."}},{"speaker":"npc","text":{"pl":"Machst du Witze, Kleiner? Kein Schwein kennt dich hier!","en":"Machst du Witze, Kleiner? Kein Schwein kennt dich hier!","de":"Machst du Witze, Kleiner? Kein Schwein kennt dich hier!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_rules_11_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_rules_11_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Rules_Info","outputIds":["Info_Diego_Rules_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Oprócz tego musisz się jeszcze wiele nauczyć. Im więcej nowych umiejętności zdobędziesz, tym cenniejszy będziesz dla nas.","en":"Besides there are a lot of skills every new arrival has to learn. The more you learn, the more valuable you''ll be for us.","de":"Außerdem gibt es für einen Neuen wie dich jede Menge neuer Talente zu lernen. Je mehr du lernst, desto wertvoller bist du für uns."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_rules_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_rules_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_Rules_Info","outputIds":["Info_Diego_Rules_15_00","Info_Diego_Rules_11_01","Info_Diego_Rules_11_02","Info_Diego_Rules_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Co powinienem wiedzieć, zanim zostanę przyjęty do Starego Obozu?","en":"What do I have to know to be accepted in the Old Camp?","de":"Was muss ich wissen, um im Alten Lager aufgenommen zu werden?"}},{"speaker":"npc","text":{"pl":"Jeśli chcesz do nas należeć, musisz najpierw zaplusować u kilku ludzi.","en":"If you want to join the Camp you''ll have to earn some brownie points.","de":"Wenn du aufgenommen werden willst, mußt du Pluspunkte sammeln."}},{"speaker":"npc","text":{"pl":"W Zewnętrznym Pierścieniu możesz spotkać paru wpływowych ludzi, głównie Cieni. Jeśli uda ci się ich do siebie przekonać, twoje szanse wzrosną.","en":"There''re a few influential people in the Outer Ring. Most of them are Shadows. If you manage to impress them, it''ll earn you a few brownie points.","de":"Es gibt einige einflussreiche Leute hier im Außenring. Die meisten davon sind Schatten. Wenn du es schaffst, sie zu beeindrucken, bringt dir das Pluspunkte ein."}},{"speaker":"npc","text":{"pl":"Później czeka cię test zaufania.","en":"Then you''ll have to stand the test of faith.","de":"Dann mußt du eine Prüfung des Vertrauens ablegen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_thorus_says_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_thorus_says_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_ThorusSays_Info","outputIds":["Info_Diego_ThorusSays_15_00","Info_Diego_ThorusSays_11_01","Info_Diego_ThorusSays_15_02","Info_Diego_ThorusSays_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Rozmawiałem z Thorusem.","en":"I''ve talked to Thorus.","de":"Ich habe mit Thorus geredet."}},{"speaker":"npc","text":{"pl":"I co ci powiedział?","en":"And what did he say?","de":"Und was sagt er?"}},{"speaker":"hero","text":{"pl":"Mówi, że będę mógł dołączyć do Starego Obozu, jeśli TY uznasz, że się nadaję.","en":"He says that I can join the Old Camp if YOU think that I''m good enough.","de":"Er will mich im Lager aufnehmen, wenn DU denkst, dass ich gut genug bin."}},{"speaker":"npc","text":{"pl":"Widzę, że czeka mnie dodatkowa robota.","en":"Looks like I have myself a new job.","de":"Sieht so aus, als hätte ich einen neuen Job."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_thorus_says_15_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_thorus_says_15_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_ThorusSays_Info","outputIds":["Info_Diego_ThorusSays_15_04","Info_Diego_ThorusSays_11_05"],"lines":[{"speaker":"hero","text":{"pl":"Zaczynamy od razu?","en":"Do we start right now?","de":"Fangen wir direkt an?"}},{"speaker":"npc","text":{"pl":"Najpierw powinieneś dowiedzieć się kilku rzeczy.","en":"First there are a few things you should know.","de":"Vorher solltest du ein paar Sachen wissen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_warum_geholfen_11_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_warum_geholfen_11_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_WarumGeholfen_Info","outputIds":["Info_Diego_WarumGeholfen_11_04","Info_Diego_WarumGeholfen_11_05","Info_Diego_WarumGeholfen_11_06"],"lines":[{"speaker":"npc","text":{"pl":"Tak. Po tym zajściu z Bullitem i jego ludźmi powinieneś się domyślić, że przyda ci się ochrona.","en":"Yes. After this little incident with Bullit and his guys, you should be aware now that you need protection.","de":"Ja. Deine Begegnung mit Bullit und seinen Jungs hat dir hoffentlich gezeigt, dass du Schutz brauchst."}},{"speaker":"npc","text":{"pl":"Każdy, kto tu trafia ma wybór. W kolonii są trzy obozy i w końcu będziesz musiał do któregoś dołączyć.","en":"Everyone who arrives here has a choice. There are three camps in the colony, and you''ll have to join one of them.","de":"Jeder, der hier ankommt, wird vor eine Wahl gestellt. Es gibt drei Lager in der Kolonie, und einem davon wirst du dich anschließen müssen."}},{"speaker":"npc","text":{"pl":"Jestem tu, by udowodnić wszystkim nowym, że najlepszym miejscem dla nich będzie Stary Obóz.","en":"I''m here to show the new ones that the Old Camp is the best place for them.","de":"Ich bin hier, um Neuen wie dir klarzumachen, dass sie bei uns im alten Lager am besten aufgehoben sind."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_warum_geholfen_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_warum_geholfen_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_WarumGeholfen_Info","outputIds":["Info_Diego_WarumGeholfen_15_00","Info_Diego_WarumGeholfen_11_01","Info_Diego_WarumGeholfen_11_02","Info_Diego_WarumGeholfen_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego mi pomogłeś?","en":"Why did you help me?","de":"Warum hast du mir geholfen?"}},{"speaker":"npc","text":{"pl":"Bo potrzebowałeś pomocy. Gdyby nie ja, Bullit i jego chłopcy mogliby cię wykończyć.","en":"Because you needed help, otherwise Bullit and his boys might have killed you.","de":"Weil du Hilfe gebraucht hast. Bullit und seine Jungs hätten dich vielleicht kaltgemacht."}},{"speaker":"npc","text":{"pl":"A ja jestem zbyt miły, żeby się temu spokojnie przyglądać. W końcu przebyłem całą tę drogę po to, by złożyć ci propozycję.","en":"And I couldn''t just stand by and watch. ''Cos I came all this way to make a suggestion.","de":"Und das konnte ich nicht mit ansehen. Schließlich bin ich den ganzen weiten Weg gekommen um dir einen Vorschlag zu machen."}},{"speaker":"hero","text":{"pl":"Propozycję...","en":"A suggestion...","de":"Einen Vorschlag..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_way_to_oldcamp_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_way_to_oldcamp_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_WayToOldcamp_Info","outputIds":["Info_Diego_WayToOldcamp_15_00","Info_Diego_WayToOldcamp_11_01","Info_Diego_WayToOldcamp_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Jak dostanę się do Starego Obozu?","en":"How do I get to the Old Camp?","de":"Wie komme ich zum alten Lager?"}},{"speaker":"npc","text":{"pl":"Podążaj tą ścieżką. Stary Obóz to najbliższe, mniej więcej bezpieczne miejsce jakie napotkasz po drodze.","en":"You just follow this path. The Old Camp is the next reasonably safe-looking place you''ll come across.","de":"Du mußt nur dem Weg hier folgen. Das Alte Lager ist der nächste halbwegs sichere Ort von hier aus gesehen."}},{"speaker":"npc","text":{"pl":"Pomiędzy obozami kręci się wiele groźnych zwierząt. Radziłbym ci postarać się o jakąś broń.","en":"There are a lot of wild beasts between the camps. You''d  be mad to walk around without a weapon.","de":"Es treiben sich jede Menge wilder Bestien zwischen den Lagern herum. Ohne Waffe zu gehen ist Wahnsinn."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_what_to_say_to_gomez_info_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_what_to_say_to_gomez_info_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_WhatToSayToGomez_Info","outputIds":["Info_Diego_WhatToSayToGomez_Info_15_00","Info_Diego_WhatToSayToGomez_Info_11_01","Info_Diego_WhatToSayToGomez_Info_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Co mam zrobić, kiedy stanę przed Gomezem?","en":"What do I have to do when I meet Gomez?","de":"Was soll ich machen, wenn ich bei Gomez bin?"}},{"speaker":"npc","text":{"pl":"Gomez podejmuje decyzje na podstawie instynktu. Jeśli spodoba mu się twoja gęba - pozwoli ci zostać.","en":"Gomez'' decisions are made from gut instinct. He''ll look at your mug and then he''ll make up his mind if you can join.","de":"Gomez entscheidet aus dem Bauch heraus. Wenn ihm deine Visage passt, bist du dabei."}},{"speaker":"npc","text":{"pl":"Od tej pory musisz sobie radzić sam - postaraj się! Powodzenia!","en":"From now on you''ll have to get by on your own - make the best of it! Good luck.","de":"Ab jetzt bist du auf dich allein gestellt - Mach das Beste draus! Viel Glück."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_whos_gomez_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_whos_gomez_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_WhosGomez_Info","outputIds":["Info_Diego_WhosGomez_15_00","Info_Diego_WhosGomez_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Kim jest Gomez?","en":"Who''s Gomez?","de":"Wer ist Gomez?"}},{"speaker":"npc","text":{"pl":"Gomez jest najpotężniejszym z Magnatów kierujących handlem rudą. To on rządzi w Starym Obozie i ma najwięcej do powiedzenia w całej kolonii.","en":"Gomez is the most powerful Ore Baron. He''s the boss of the Old Camp - the most powerful man in the colony.","de":"Gomez ist der oberste Erzbaron. Der Boss des Alten Lagers. Der mächtigste Mann in der Kolonie."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_info_diego_wo_waffe_15_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_info_diego_wo_waffe_15_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"Info_Diego_WoWaffe_Info","outputIds":["Info_Diego_WoWaffe_15_00","Info_Diego_WoWaffe_11_01","Info_Diego_WoWaffe_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę znaleźć oręż?","en":"Where do I get a weapon?","de":"Wo kriege ich eine Waffe her?"}},{"speaker":"npc","text":{"pl":"Rozejrzyj się trochę w pobliżu Opuszczonej Kopalni. Na pewno znajdziesz tam coś przydatnego.","en":"When you get to the Old Mine, have a look around. I''m sure you''ll find something useful.","de":"Wenn du an der verlassenen Mine vorbeikommst, sieh dich mal ein bißchen um. Du findest bestimmt was Brauchbares."}},{"speaker":"npc","text":{"pl":"Kopalnię nie trudno znaleźć. Leży parę metrów w dół kanionu.","en":"The mine is easy to find, it''s just a few meters along the canyon.","de":"Die Mine ist leicht zu finden, nur ein paar Meter die Schlucht entlang."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_aftertroll_info_11_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_aftertroll_info_11_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_AFTERTROLL_Info","outputIds":["PC_Thief_AFTERTROLL_Info_11_01","PC_Thief_AFTERTROLL_Info_11_02"],"lines":[{"speaker":"npc","text":{"pl":"To było niesamowite. Niezły jesteś. Teraz możesz iść po kamień ogniskujący.","en":"That was fantastic. You''re really good. And now, go get the focus.","de":"Das war fantastisch. Mann, du hast ja einiges drauf. So, jetzt hol dir den Fokus."}},{"speaker":"npc","text":{"pl":"Ja dopilnuję, żebyśmy nie mieli już więcej niemiłych niespodzianek.","en":"I''ll make sure that there won''t be any other awkward surprises.","de":"Ich passe auf, dass keine weiteren unangenehmen Überraschungen auf uns zu kommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_fixwheel_info_11_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_fixwheel_info_11_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_FIXWHEEL_Info","outputIds":["PC_Thief_FIXWHEEL_Info_11_01"],"lines":[{"speaker":"npc","text":{"pl":"No, teraz powinno działać!","en":"Well, it ought to work now.","de":"So, jetzt sollte es eigentlich wieder gehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_gotit_info_11_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_gotit_info_11_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_GOTIT_Info","outputIds":["PC_Thief_GOTIT_Info_11_01","PC_Thief_GOTIT_Info_11_02","PC_Thief_GOTIT_Info_15_03","PC_Thief_GOTIT_Info_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że znalazłeś kamień! Świetnie.","en":"Hey, you''ve found the focus. Very good.","de":"Hey, du hast den Fokus also gefunden. Sehr gut."}},{"speaker":"npc","text":{"pl":"Chyba powinienem znowu zajrzeć do Starego Obozu. Powodzenia!","en":"I think it''s time for me to stop by at the Old Camp again. Good luck.","de":"Ich werde mal wieder die Lage im Alten Lager prüfen. Viel Glück noch."}},{"speaker":"hero","text":{"pl":"Nie daj się zabić!","en":"Make sure you stay alive!","de":"Sieh zu, das du am Leben bleibst."}},{"speaker":"npc","text":{"pl":"Jeszcze się zobaczymy.","en":"We''ll meet again.","de":"Wir werden uns wieder sehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_meetagain_info_11_00_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_meetagain_info_11_00_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_MEETAGAIN_Info","outputIds":["PC_Thief_MEETAGAIN_Info_11_00","PC_Thief_MEETAGAIN_Info_15_01","PC_Thief_MEETAGAIN_Info_11_02","PC_Thief_MEETAGAIN_Info_15_03"],"lines":[{"speaker":"npc","text":{"pl":"Hej! Myślałem, że już nie żyjesz!","en":"Hey, I thought you were dead.","de":"Hey, ich dachte, du wärst tot."}},{"speaker":"hero","text":{"pl":"Parę razy też mi się tak wydawało.","en":"Sometimes I thought so myself.","de":"Das ein oder andere Mal hab'' ich das auch gedacht."}},{"speaker":"npc","text":{"pl":"Wiele się wydarzyło od naszego ostatniego spotkania. Słyszałem, że miałeś swój wkład w wielkie przywołanie!","en":"A lot of things have happened since we last met. I hear you''ve contributed a great deal to the final invocation.","de":"Seit unserem ersten Treffen ist einiges passiert. Ich hörte, du warst nicht ganz unbeteiligt daran, dass die große Beschwörung stattfinden konnte."}},{"speaker":"hero","text":{"pl":"Widzę, że jesteś świetnie poinformowany.","en":"Obviously you''re quite well informed.","de":"Du kriegst ja anscheinend eine ganze Menge mit."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_meetagain_info_11_04_4', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_meetagain_info_11_04_4","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_MEETAGAIN_Info","outputIds":["PC_Thief_MEETAGAIN_Info_11_04","PC_Thief_MEETAGAIN_Info_15_05","PC_Thief_MEETAGAIN_Info_11_06","PC_Thief_MEETAGAIN_Info_15_07"],"lines":[{"speaker":"npc","text":{"pl":"Lepiej niż myślisz... Teraz szukasz kamienia ogniskującego?","en":"Better than you think... Now you''re looking for the focus?","de":"Mehr als du denkst... Jetzt bist du auf Fokus Suche?"}},{"speaker":"hero","text":{"pl":"Tak. Powinien być gdzieś w pobliżu.","en":"Yes. There must be one somewhere around here.","de":"Ja. Hier in der Gegend muss es irgendwo einen geben."}},{"speaker":"npc","text":{"pl":"Wiem, gdzie go można znaleźć. Jest tylko jeden problem.","en":"I know where to find one. There''s just one problem.","de":"Ich weiß, wo einer liegt. Es gibt da nur ein Problem..."}},{"speaker":"hero","text":{"pl":"Rozumiem. Czego chcesz?","en":"I see. What do you want?","de":"Ich verstehe. Was willst du haben?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_meetagain_info_11_08_8', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_meetagain_info_11_08_8","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_MEETAGAIN_Info","outputIds":["PC_Thief_MEETAGAIN_Info_11_08","PC_Thief_MEETAGAIN_Info_15_09","PC_Thief_MEETAGAIN_Info_11_10","PC_Thief_MEETAGAIN_Info_11_11"],"lines":[{"speaker":"npc","text":{"pl":"Widzę, że szybko się uczysz, ale nie o to mi chodziło.","en":"You''ve really learnt your lesson, but that''s not what I meant.","de":"Du hast tatsächlich gelernt, aber das meine ich nicht."}},{"speaker":"hero","text":{"pl":"Nie? Więc cóż to za problem?","en":"No? What''s the problem then?","de":"Nein? Was ist dann dein Problem?"}},{"speaker":"npc","text":{"pl":"O, to całe trzy tony problemów!","en":"It''s three tons of a problem.","de":"Ein drei Tonnen schweres Problem."}},{"speaker":"npc","text":{"pl":"Chodźmy. Za chwilę sam zobaczysz.","en":"Let''s go. You''ll understand in a moment.","de":"Lass uns gehen. Du wirst es gleich verstehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_showfocus_info_11_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_showfocus_info_11_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_SHOWFOCUS_Info","outputIds":["PC_Thief_SHOWFOCUS_Info_11_01","PC_Thief_SHOWFOCUS_Info_15_02","PC_Thief_SHOWFOCUS_Info_11_03","PC_Thief_SHOWFOCUS_Info_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Po lewej stronie tego kanionu znajdziesz wejście do jaskini, która prowadzi do kamienia.","en":"On the left side of this canyon lies the entrance to a cave that leads to the location of the focus.","de":"Auf der linken Seite dieser Schlucht gibt es einen Höhlengang, der zum Fokusplatz führt."}},{"speaker":"hero","text":{"pl":"Wszystko jasne. Jednak najpierw musimy się jakoś pozbyć tamtego bydlaka.","en":"Alright. But first we have to get rid of that monster over there.","de":"Alles klar. Doch zunächst sollten wir dieses Ungetüm da drüben loswerden."}},{"speaker":"npc","text":{"pl":"Spróbuj znaleźć jakiś jego słaby punkt albo inny sposób na pokonanie tego Trolla.","en":"Try to find a weak point or another possibility to defeat the troll.","de":"Versuche, eine Schwachstelle oder irgendeine Möglichkeit zu finden, wie wir den Troll kleinkriegen können."}},{"speaker":"npc","text":{"pl":"Ściągnę na siebie jego uwagę.","en":"I''ll attract his attention.","de":"Ich lenke seine Aufmerksamkeit auf mich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_waitatfocus_info_11_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_waitatfocus_info_11_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_WAITATFOCUS_Info","outputIds":["PC_Thief_WAITATFOCUS_Info_11_01"],"lines":[{"speaker":"npc","text":{"pl":"Idź po kamień. Zaczekam na ciebie tutaj!","en":"Get the focus and I''ll wait for you here!","de":"Hol dir den Fokus, ich warte hier!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_pc_thief_pc_thief_wheel_info_11_01_0', 'PC_Thief', '{"id":"missions_dia_pc_thief_pc_thief_wheel_info_11_01_0","npcId":"PC_Thief","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_PC_Thief.d","sourceFunction":"PC_Thief_WHEEL_Info","outputIds":["PC_Thief_WHEEL_Info_11_01","PC_Thief_WHEEL_Info_11_02"],"lines":[{"speaker":"npc","text":{"pl":"Kołowrót chyba się zaciął!","en":"The winch seems to be jammed.","de":"Die Winde scheint zu klemmen."}},{"speaker":"npc","text":{"pl":"Czekaj, może uda mi się go naprawić!","en":"Let me see, maybe I can fix it!","de":"Lass mich mal, vielleicht kann ich da was machen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1000_senyan_dia_senyan_hello_15_00_0', 'SFB_1000_Senyan', '{"id":"missions_dia_sfb_1000_senyan_dia_senyan_hello_15_00_0","npcId":"SFB_1000_Senyan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1000_Senyan.d","sourceFunction":"DIA_Senyan_Hello_Info","outputIds":["DIA_Senyan_Hello_15_00","DIA_Senyan_Hello_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Przybywasz z Wolnej Kopalni, tak?","en":"You''re from the Free Mine, right?","de":"Du kommst aus der Freien Mine, richtig?"}},{"speaker":"npc","text":{"pl":"Tak. Skąd wiesz?","en":"Right. How did you find that out?","de":"Richtig. Wie hast du das bloß rausgefunden?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1000_senyan_dia_senyan_just_talk_15_00_0', 'SFB_1000_Senyan', '{"id":"missions_dia_sfb_1000_senyan_dia_senyan_just_talk_15_00_0","npcId":"SFB_1000_Senyan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1000_Senyan.d","sourceFunction":"DIA_Senyan_JustTalk_Info","outputIds":["DIA_Senyan_JustTalk_15_00","DIA_Senyan_JustTalk_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Chcę z tobą chwilę porozmawiać.","en":"I just want to talk to you.","de":"Ich will nur mit dir reden."}},{"speaker":"npc","text":{"pl":"Nie przyszedłem tutaj, żeby gadać.","en":"I''m not here to talk.","de":"Ich bin nicht zum Reden hier."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1037_swiney_info_swiney_hello_15_00_0', 'SFB_1037_Swiney', '{"id":"missions_dia_sfb_1037_swiney_info_swiney_hello_15_00_0","npcId":"SFB_1037_Swiney","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1037_Swiney.d","sourceFunction":"Info_Swiney_Hello_Info","outputIds":["Info_Swiney_Hello_15_00","Info_Swiney_Hello_09_01","Info_Swiney_Hello_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Kim jesteś?","en":"Who are you?","de":"Wer bist du?"}},{"speaker":"npc","text":{"pl":"Jestem najlepszym inżynierem, jakiego ta przeklęta kolonia kiedykolwiek widziała, chłopcze.","en":"I''m the best mining engineer this damn colony has ever seen, my boy.","de":"Ich bin der beste Bergbauer, den diese verdammte Kolonie jemals gesehen hat, mein Junge."}},{"speaker":"npc","text":{"pl":"Pilnuję, żeby nasi chłopcy nie ściągnęli sobie na głowy sterty kamieni kopiąc w niewłaściwym miejscu.","en":"I make sure half our boys don''t go getting themselves killed by falling rocks, just because they''re too stupid to scrape the right places.","de":"Ich passe auf, dass nicht die Hälfte unserer Jungs von Steinen erschlagen werden, weil sie zu dumm sind, an der richtigen Stelle zu schürfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1037_swiney_info_swiney_perm_15_00_0', 'SFB_1037_Swiney', '{"id":"missions_dia_sfb_1037_swiney_info_swiney_perm_15_00_0","npcId":"SFB_1037_Swiney","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1037_Swiney.d","sourceFunction":"Info_Swiney_PERM_Info","outputIds":["Info_Swiney_PERM_15_00","Info_Swiney_PERM_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Jak dużo rudy udało się wam uzbierać do tej pory?","en":"How much ore have you collected so far?","de":"Wie viel Erz habt ihr schon gesammelt?"}},{"speaker":"npc","text":{"pl":"Magowie mówią, że mamy już niemal całą potrzebną ilość. Kiedy będziesz w Nowym Obozie rzuć okiem na kopiec.","en":"The mages say that we won''t need much more. Go to the New Camp and have a look at the mound.","de":"Die Magier sagen, viel brauchen wir nicht mehr. Geh ins Neue Lager und sieh dir den Haufen an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1037_swiney_info_swiney_schuerfer_09_04_4', 'SFB_1037_Swiney', '{"id":"missions_dia_sfb_1037_swiney_info_swiney_schuerfer_09_04_4","npcId":"SFB_1037_Swiney","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1037_Swiney.d","sourceFunction":"Info_Swiney_Schuerfer_Info","outputIds":["Info_Swiney_Schuerfer_09_04","Info_Swiney_Schuerfer_09_05"],"lines":[{"speaker":"npc","text":{"pl":"To najważniejsze rzeczy, które powinieneś wiedzieć.","en":"That''s the most important things you ought to know.","de":"Das waren auch schon die wichtigsten Sachen, die du wissen musst."}},{"speaker":"npc","text":{"pl":"Masz chociaż jakieś doświadczenie w tej robocie?","en":"Do you at least have any experience on the job?","de":"Kennst du dich wenigstens mit der Arbeit aus?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1037_swiney_info_swiney_schuerfer_15_00_0', 'SFB_1037_Swiney', '{"id":"missions_dia_sfb_1037_swiney_info_swiney_schuerfer_15_00_0","npcId":"SFB_1037_Swiney","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1037_Swiney.d","sourceFunction":"Info_Swiney_Schuerfer_Info","outputIds":["Info_Swiney_Schuerfer_15_00","Info_Swiney_Schuerfer_09_01","Info_Swiney_Schuerfer_09_02","Info_Swiney_Schuerfer_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym do was dołączyć, jako Kret.","en":"I''d like to join you as a scraper!","de":"Ich will bei euch als Schürfer mitmachen!"}},{"speaker":"npc","text":{"pl":"Czyżby? Tylko nie oczekuj zbyt wiele po tej robocie. Trzy porcje ryżu na dzień. Resztę musisz sobie sam załatwić.","en":"Oh yeah? Well, just don''t think you''re going to get anything much out of it. There''s three portions of rice a day, any extra you''ll have to see to yourself.","de":"So? Denk bloß nicht, du kannst hier viel erwarten. Jeden Tag gibt''s 3 Portionen Reis und für den Rest musst du selber sorgen."}},{"speaker":"npc","text":{"pl":"Wiesz dlaczego odwalamy całą tę brudną robotę? Żeby pewnego dnia móc wyjść na wolność z tego przeklętego więzienia.","en":"D''you know why we''re doin'' this? We''re doin'' this job so one day we can all walk out of here to freedom.","de":"Du weißt, warum wir das hier machen? Wir machen die Arbeit, damit alle hier eines Tages wieder rausspazieren können."}},{"speaker":"npc","text":{"pl":"Cały nasz urobek jest składowany na wielkim kopcu. Raz w miesiącu każdy z nas dostaje 50 bryłek, żeby móc się porządnie upić.","en":"That means all the ore''s to be handed in, then it goes on the big ore mound. And once a month everybody who''s been working here gets 50 ore to get stoned on.","de":"Das heißt, alles Erz wird abgegeben und kommt auf den großen Haufen. Und einmal im Monat kriegt jeder, der hier hart gearbeitet hat, 50 Brocken Erz zum Versaufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1037_swiney_info_swiney_schuerfer_ja_15_00_0', 'SFB_1037_Swiney', '{"id":"missions_dia_sfb_1037_swiney_info_swiney_schuerfer_ja_15_00_0","npcId":"SFB_1037_Swiney","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1037_Swiney.d","sourceFunction":"Info_Swiney_Schuerfer_Ja","outputIds":["Info_Swiney_Schuerfer_Ja_15_00","Info_Swiney_Schuerfer_Ja_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Tak.","en":"Yes.","de":"Ja."}},{"speaker":"npc","text":{"pl":"To świetnie! Zatem wiesz, na co należy uważać. Masz tu swój strój roboczy. Kilof musisz znaleźć sobie sam. Miłej zabawy.","en":"Good! Then you know what to watch out for. Here''s your protective clothin''. You''ll have to find your own pickaxe. Enjoy yourself.","de":"Gut! Dann weißt du ja, worauf du zu achten hast. Hier ist Schutzkleidung. ''Ne Spitzhacke musst du dir suchen. Viel Spaß."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1037_swiney_info_swiney_schuerfer_nein_09_04_4', 'SFB_1037_Swiney', '{"id":"missions_dia_sfb_1037_swiney_info_swiney_schuerfer_nein_09_04_4","npcId":"SFB_1037_Swiney","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1037_Swiney.d","sourceFunction":"Info_Swiney_Schuerfer_Nein","outputIds":["Info_Swiney_Schuerfer_Nein_09_04"],"lines":[{"speaker":"npc","text":{"pl":"Oczywiście wiele z nim nie zdziałasz... Mówi się trudno...","en":"But you won''t be able to do much with it - well - so what...","de":"Aber viel anfangen kannst du damit sowieso nicht - na ja - was soll''s ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sfb_1037_swiney_info_swiney_schuerfer_nein_15_00_0', 'SFB_1037_Swiney', '{"id":"missions_dia_sfb_1037_swiney_info_swiney_schuerfer_nein_15_00_0","npcId":"SFB_1037_Swiney","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SFB_1037_Swiney.d","sourceFunction":"Info_Swiney_Schuerfer_Nein","outputIds":["Info_Swiney_Schuerfer_Nein_15_00","Info_Swiney_Schuerfer_Nein_09_01","Info_Swiney_Schuerfer_Nein_09_02","Info_Swiney_Schuerfer_Nein_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Nie.","en":"No.","de":"Nein."}},{"speaker":"npc","text":{"pl":"No jasne! Dlaczego to zawsze ja muszę was uświadamiać. Słuchaj uważnie: weź te ciuchy i załóż je na siebie - tutaj.","en":"Of course you don''t! Why''s it always me? Okay. Listen carefully. You take this stuff and put it on - here.","de":"Natürlich nicht! Warum immer ich? Gut. Pass auf. Du nimmst jetzt diese Klamotten und ziehst sie dir an - hier."}},{"speaker":"npc","text":{"pl":"Gdyby kawałek rudy spadł ci na bosą stopę, zostałbyś kaleką do końca życia. Oczywiście wtedy byłbyś dla nas znacznie mniej przydatny.","en":"If an ore nugget falls on your foot while you''re not wearing your protective clothing, you''ll be crippled for life and only worth half of what you were before to us.","de":"Wenn dir ein Erzbrocken auf den Fuß fällt und du keine Schutzkleidung trägst, bist du ein Krüppel und nur noch die Hälfte für uns wert."}},{"speaker":"npc","text":{"pl":"Gdzieś w pobliżu powinien leżeć jakiś kilof.","en":"There''ll be a pickaxe lying somewhere around here.","de":"''Ne Spitzhacke liegt hier bestimmt irgendwo noch rum."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_dia_lee_define_15_00_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_dia_lee_define_15_00_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_Define_Info","outputIds":["DIA_Lee_Define_15_00","DIA_Lee_Define_08_01","DIA_Lee_Define_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Czym zajmuje się najemnik w służbie magów?","en":"Which tasks do the mages'' mercenaries have?","de":"Was sind die Aufgaben eines Söldners der Magier?"}},{"speaker":"npc","text":{"pl":"To proste: pilnuje rudy i broni magów.","en":"Very simple: Protect the ore - protect the mages.","de":"Ganz einfach: Beschütze das Erz - beschütze die Magier."}},{"speaker":"npc","text":{"pl":"Od czasu do czasu magowie zlecają nam jakieś zadania specjalne.","en":"Sometimes the mages have a special task for one of us.","de":"Manchmal haben die Magier aber auch eine besondere Aufgabe für einen von uns."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_dia_lee_fmtaken_15_00_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_dia_lee_fmtaken_15_00_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_FMTaken_Info","outputIds":["DIA_Lee_FMTaken_15_00","DIA_Lee_FMTaken_08_01","Info_Lee_now_freeminefree_15_01","Sld_700_Lee_CHANGESIDE_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Co myślisz o całej tej sprawie z kopalnią?","en":"What do you think about the mine?","de":"Was sagst du zu der Sache mit der Mine?"}},{"speaker":"npc","text":{"pl":"Tym razem posunęli się za daleko. Jeszcze tego pożałują.","en":"They''ve gone too far, they''ll be sorry for it.","de":"Sie sind zu weit gegangen, dafür werden sie büßen."}},{"speaker":"hero","text":{"pl":"Myślę, że zagrożenie już minęło.","en":"They shouldn''t be a threat anymore!","de":"Die Bedrohung dürfte beendet sein!"}},{"speaker":"npc","text":{"pl":"Nasz obóz wiele ci zawdzięcza. Przydałby mi się ktoś taki jak ty.","en":"You''ve done much for our camp. I can make good use of men like you.","de":"Du hast viel für unser Lager getan. Männer wie dich kann ich gebrauchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_dia_lee_greet_15_00_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_dia_lee_greet_15_00_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_Greet_Info","outputIds":["DIA_Lee_Greet_15_00","DIA_Lee_Greet_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Jesteś szefem Najemników, tak?","en":"You''re the boss of the mercenaries, aren''t you?","de":"Du bist der Chef der Söldner, richtig?"}},{"speaker":"npc","text":{"pl":"Zgadza się, chłopcze!","en":"That''s right, boy!","de":"Das ist richtig, mein Junge!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_dia_lee_mitmachen_15_00_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_dia_lee_mitmachen_15_00_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_Mitmachen_Info","outputIds":["DIA_Lee_Mitmachen_15_00","DIA_Lee_Mitmachen_08_01","DIA_Lee_Mitmachen_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym do was dołączyć!","en":"I''d like to join you!","de":"Ich will bei euch mitmachen!"}},{"speaker":"npc","text":{"pl":"Odbiło ci? Myślisz, że przyjmuję każdego włóczęgę, który się do mnie zgłosi?","en":"You have a nerve! D''you honestly think I''ll just take anybody who walks in here?","de":"Du hast Nerven! Denkst du, ich nehme direkt jeden, der hier reinkommt?"}},{"speaker":"npc","text":{"pl":"Musisz najpierw spędzić trochę czasu w naszym obozie. Będę cię miał na oku! Zobaczymy, na co cię stać.","en":"You can only become one of us after you spent a certain time in the Camp. I''ll observe you!","de":"Erst wenn du einige Zeit hier im Lager bist, kannst du einer von uns werden. Ich werde dich beobachten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_dia_lee_now_ready_15_00_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_dia_lee_now_ready_15_00_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_NowReady_Info","outputIds":["DIA_Lee_NowReady_15_00","Sld_700_Lee_BECOMESLD_Info_08_01","Sld_700_Lee_BECOMESLD_Info_08_02","Sld_700_Lee_BECOMESLD_Info_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać najemnikiem w służbie magów. Myślisz, że jestem już gotów?","en":"I''d like to become a mercenary of the mages - am I ready yet?","de":"Ich will ein Söldner der Magier werden - bin ich jetzt soweit?"}},{"speaker":"npc","text":{"pl":"Twoje dokonania w Starej Kopalni dowodzą, że stać cię na wiele.","en":"Your deeds for the people in the Old Mine have demonstrated that you''re quite a good man.","de":"Deine Taten für die Bruderschaft in der Alten Mine haben gezeigt, das du einiges drauf hast."}},{"speaker":"npc","text":{"pl":"Jestem skłonny przyjąć cię w poczet Najemników.","en":"I''d be willing to let you join the mercenaries.","de":"Ich wäre bereit, dich in die Reihen der Söldner aufzunehmen."}},{"speaker":"npc","text":{"pl":"Ale nie jesteś gotowy do służby w naszych szeregach. Musisz zdobyć jeszcze trochę doświadczenia.","en":"But you''re not ready for the mercenaries yet. Just collect some more experience and you''ll be there.","de":"Aber du bist noch nicht bereit für die Söldner. Sammle erst noch mehr Erfahrung, dann bist du dabei."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_info_freemine_orc_exit_15_03_4', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_info_freemine_orc_exit_15_03_4","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_FMTaken_Info","outputIds":["Info_FreemineOrc_EXIT_15_03","Info_CorAngar_TELEPORT_08_01","Info_CorAngar_TELEPORT_08_03","Info_CorAngar_TELEPORT_15_05"],"lines":[{"speaker":"hero","text":{"pl":"Dziękuję. Muszę już ruszać w dalszą drogę.","en":"Thank you. I''ll be on my way now.","de":"Ich danke dir. Ich werde mich jetzt wieder auf den Weg machen."}},{"speaker":"npc","text":{"pl":"Jeszcze coś!","en":"One moment!","de":"Einen Moment noch!"}},{"speaker":"npc","text":{"pl":"Weź tę magiczną runę jako symbol naszej wdzięczności za twoje dokonania.","en":"Take this rune of magic as a sign of our gratitude for your great deeds.","de":"Nimm diese Zauberrune als Zeichen unseres Dankes für deine großen Taten."}},{"speaker":"hero","text":{"pl":"Dziękuję!","en":"Thank you!","de":"Ich danke dir!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_becomesld_info_08_04_4', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_becomesld_info_08_04_4","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_NowReady_Info","outputIds":["Sld_700_Lee_BECOMESLD_Info_08_04","DIA_Lee_NowReady_08_01","Sld_700_Lee_BECOMESLD_Info_08_04"],"lines":[{"speaker":"npc","text":{"pl":"I''ll give you a chance. How about it?","en":"I''ll give you a chance. How about it?","de":"Ich gebe dir eine Chance. Wie siehts aus?"}},{"speaker":"npc","text":{"pl":"Nadal nie jesteś dość doświadczony. Musisz się jeszcze wiele nauczyć.","en":"You still don''t have enough experience. You need to improve your abilities.","de":"Dir fehlt es noch an Erfahrung. Du mußt deine Fähigkeiten noch steigern."}},{"speaker":"npc","text":{"pl":"Dam ci szansę. Co ty na to?","en":"Ich gebe dir eine Chance. Wie siehts aus?","de":"Ich gebe dir eine Chance. Wie siehts aus?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_becomesldnow_freedom_15_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_becomesldnow_freedom_15_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_BECOMESLDNOW_FREEDOM","outputIds":["Sld_700_Lee_BECOMESLDNOW_FREEDOM_15_01","Sld_700_Lee_BECOMESLDNOW_FREEDOM_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Od początku myślałem tylko o odzyskaniu wolności.","en":"I wanted freedom from the very beginning.","de":"Ich wollte von Anfang an die Freiheit."}},{"speaker":"npc","text":{"pl":"I dzięki nam wkrótce ją odzyskasz. Witaj wśród nas, NAJEMNIKU!","en":"We''ll get our freedom back. Welcome, MERCENARY.","de":"Wir werden uns unsere Freiheit zurückholen. Willkommen, SÖLDNER."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_becomesldnow_info_15_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_becomesldnow_info_15_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_BECOMESLDNOW_Info","outputIds":["Sld_700_Lee_BECOMESLDNOW_Info_15_01","Sld_700_Lee_BECOMESLDNOW_Info_08_02","Sld_700_Lee_BECOMESLDNOW_Info_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Chcę zostać Najemnikiem.","en":"I want to become a mercenary.","de":"Ich will Söldner werden."}},{"speaker":"npc","text":{"pl":"Mądra decyzja. Nie pożałujesz.","en":"A good decision. You won''t regret it.","de":"Eine gute Entscheidung. Du wirst sie nicht bereuen."}},{"speaker":"npc","text":{"pl":"Powiedz mi: dlaczego? Dlaczego dołączyłeś do nas, a nie do Bractwa, albo do Starego Obozu?","en":"Tell me something: Why? Why have you joined us and not the Old Camp or the Brotherhood?","de":"Sag mir eins, warum? Warum hast du dich uns angeschlossen und nicht dem Alten Lager oder der Bruderschaft?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_becomesldnow_justbecause_15_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_becomesldnow_justbecause_15_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_BECOMESLDNOW_JUSTBECAUSE","outputIds":["Sld_700_Lee_BECOMESLDNOW_JUSTBECAUSE_15_01","Sld_700_Lee_BECOMESLDNOW_JUSTBECAUSE_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Tak się jakoś złożyło.","en":"It just sort of happened that way.","de":"Es hat sich einfach so ergeben."}},{"speaker":"npc","text":{"pl":"Żeby się tylko nie złożyło, że kiedyś nagle zmienisz zdanie. Witaj wśród nas, NAJEMNIKU!","en":"I only hope it doesn''t just sort of happen that we stay trapped in here forever. Welcome, MERCENARY.","de":"Hauptsache, es ergibt sich nicht, dass uns die Barriere für immer hier drin gefangen hält. Willkommen, SÖLDNER."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_becomesldnow_noother_15_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_becomesldnow_noother_15_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_BECOMESLDNOW_NOOTHER","outputIds":["Sld_700_Lee_BECOMESLDNOW_NOOTHER_15_01","Sld_700_Lee_BECOMESLDNOW_NOOTHER_08_02"],"lines":[{"speaker":"hero","text":{"pl":"W tamtych obozach tylko traciłbym czas.","en":"The other camps aren''t worth the bother.","de":"Die anderen Lager sind es nicht wert."}},{"speaker":"npc","text":{"pl":"Jedyna rzecz, która ma tutaj jakąś prawdziwą wartość to pragnienie wolności. Witaj wśród nas, NAJEMNIKU!","en":"The only thing that''s worth anything in here is the hope of freedom. Welcome, MERCENARY!","de":"Das einzige, was hier drin etwas wert ist, ist die Hoffnung auf Freiheit. Willkommen, SÖLDNER!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_changeside_info_15_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_changeside_info_15_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_CHANGESIDE_Info","outputIds":["Sld_700_Lee_CHANGESIDE_Info_15_01","Sld_700_Lee_CHANGESIDE_Info_08_02","Sld_700_Lee_CHANGESIDE_Info_08_03","Sld_700_Lee_CHANGESIDE_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Wyrzucono mnie ze Starego Obozu. Chciałbym do was dołączyć.","en":"The Old Camp has banned me, I''d like to join you!","de":"Das Alte Lager hat mich verbannt, ich möchte mich euch anschließen!"}},{"speaker":"npc","text":{"pl":"Nasz obóz wiele ci zawdzięcza. Przydałby mi się ktoś taki jak ty.","en":"You''ve done much for our camp. I can make good use of men like you.","de":"Du hast viel für unser Lager getan. Männer wie dich kann ich gebrauchen."}},{"speaker":"npc","text":{"pl":"Przejdźmy od razu do rzeczy. Witaj w Nowym Obozie, Najemniku!","en":"Let''s keep it short. Welcome to the New Camp, MERCENARY!","de":"Machen wir es kurz. Willkommen im Neuen Lager, SÖLDNER!"}},{"speaker":"npc","text":{"pl":"Weź tę zbroję. Dobrze, że mamy cię teraz po naszej stronie.","en":"Here take some armor. Good that you''re here with us.","de":"Hier ist eine von unseren Rüstungen. Gut, dass du bei uns bist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_damnpast_info_08_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_damnpast_info_08_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_DAMNPAST_Info","outputIds":["Sld_700_Lee_DAMNPAST_Info_08_01","Sld_700_Lee_DAMNPAST_Info_08_02","Sld_700_Lee_DAMNPAST_Info_08_03","Sld_700_Lee_DAMNPAST_Info_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Kiedyś wiodłem całkiem inne życie.","en":"There was a time when I led a very different life.","de":"Einst führte ich ein anderes Leben."}},{"speaker":"npc","text":{"pl":"Byłem jednym z najlepszych generałów tego królestwa.","en":"I was one of the best generals of this country.","de":"Ich zählte zu den besten Generälen dieses Landes."}},{"speaker":"npc","text":{"pl":"Całe życie spędziłem broniąc ojczyzny przed wrogiem.","en":"I''ve spent my whole life fighting for my country.","de":"Ich habe mein ganzes Leben lang für dieses Land gekämpft."}},{"speaker":"npc","text":{"pl":"Ale szlachta patrzyła na mnie niechętnie, bo król wysoko cenił sobie moje rady. Te łotry wiedziały, że mogę pokrzyżować ich plany.","en":"But the nobles didn''t like me, because the King listened to my advice. And they knew I posed a threat to their dirty business.","de":"Den Adeligen war ich ein Dorn im Auge, denn der König hörte auf meinen Rat. Und sie sahen ihre schmutzigen Geschäfte in Gefahr."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_damnpast_info_08_05_4', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_damnpast_info_08_05_4","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_DAMNPAST_Info","outputIds":["Sld_700_Lee_DAMNPAST_Info_08_05","Sld_700_Lee_DAMNPAST_Info_08_06","Sld_700_Lee_DAMNPAST_Info_08_07","Sld_700_Lee_DAMNPAST_Info_08_08"],"lines":[{"speaker":"npc","text":{"pl":"Byłem zbyt pewny siebie i nie zauważyłem sideł, które na mnie zastawili. Aby mnie usunąć posłużyli się królewską żoną.","en":"I hadn''t counted on their insidiousness. They used the King''s wife to get me.","de":"Ich habe nicht mit ihrer Hinterhältigkeit gerechnet. Sie haben des Königs Frau benutzt, um mich zu kriegen."}},{"speaker":"npc","text":{"pl":"Posądzono mnie o jej zamordowanie. Rhobar nie miał innego wyboru.","en":"I was blamed for her pointless murder. King Rhobar had no other choice.","de":"Der sinnlose Mord an ihr wurde mir angehängt. König Rhobar blieb keine Wahl."}},{"speaker":"npc","text":{"pl":"Od szubienicy uratowało mnie tylko wiele lat przykładnej służby. W ten sposób trafiłem tutaj.","en":"The services I had rendered my country saved me from the gallows. But they robbed me of my freedom.","de":"Meine Verdienste um das Land retteten mich vor dem Strick. Aber sie haben mir meine Freiheit genommen."}},{"speaker":"npc","text":{"pl":"Ale pewnego dnia odzyskam wolność, a wtedy nadejdzie czas zemsty...","en":"One day I''ll be free again. Then I shall return and take revenge.","de":"Eines Tages werde ich wieder frei sein. Dann werde ich zurückkehren und ich werde Rache nehmen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_damnpast_info_08_09_8', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_damnpast_info_08_09_8","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_DAMNPAST_Info","outputIds":["Sld_700_Lee_DAMNPAST_Info_08_09"],"lines":[{"speaker":"npc","text":{"pl":"Zemszczę się!","en":"I shall have my revenge.","de":"Ich werde mich rächen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_zweihand1_info_08_05_4', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_zweihand1_info_08_05_4","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_ZWEIHAND1_Info","outputIds":["Sld_700_Lee_ZWEIHAND1_Info_08_05","Sld_700_Lee_ZWEIHAND1_Info_08_06","Sld_700_Lee_ZWEIHAND1_Info_08_07"],"lines":[{"speaker":"npc","text":{"pl":"Wykorzystaj bezwładność broni, by unieść ją ponownie do góry.","en":"Use the momentum of the weapon to bring it straight back up again.","de":"Nutze den Schwung, wenn die Waffe unten ist, um direkt wieder nach oben zu schlagen."}},{"speaker":"npc","text":{"pl":"Dwuręczne miecze świetnie sprawdzają się przy zadawaniu ciosów z boku. W ten sposób możesz trzymać przeciwnika na dystans.","en":"Two-handed swords are ideal for coordinating side hits to keep the opponents at a distance.","de":"Seitliche Schläge lassen sich ausgezeichnet mit einem Zweihänder koordinieren. Damit hältst du dir die Gegner vom Hals."}},{"speaker":"npc","text":{"pl":"To ci powinno wystarczyć na początek. Potrenuj trochę.","en":"That should do to begin with. Have a practice.","de":"Das sollte erst einmal reichen. Übe das!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_zweihand1_info_15_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_zweihand1_info_15_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_ZWEIHAND1_Info","outputIds":["Sld_700_Lee_ZWEIHAND1_Info_15_01","Sld_700_Lee_ZWEIHAND1_Info_08_02","Sld_700_Lee_ZWEIHAND1_Info_08_03","Sld_700_Lee_ZWEIHAND1_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Chcę się nauczyć posługiwać dwuręcznym mieczem.","en":"I want to learn how to handle a two-handed sword.","de":"Ich möchte den Umgang mit Zweihändern lernen."}},{"speaker":"npc","text":{"pl":"W porządku. Najpierw omówimy podstawy.","en":"Okay, let''s go through the basics first.","de":"Nun, dann gehen wir zuerst die Grundbegriffe durch."}},{"speaker":"npc","text":{"pl":"Wyciągnij miecz przed siebie. Aby zaatakować wroga tak ciężką bronią, musisz mocniej się zamachnąć.","en":"Hold the sword in a horizontal position. You''ll need a great swing to attack your opponent with such a heavy weapon.","de":"Halte das Schwert waagerecht. Um den Gegner mit einer großen Waffe anzugreifen, brauchst du viel Schwung."}},{"speaker":"npc","text":{"pl":"Unieś rękę i zdecydowanie opuść miecz. To powinno wystarczyć, żeby powalić przeciwnika na ziemię.","en":"Raise your arm and swing it straight down. That''s usually enough to knock the opponent down.","de":"Hole mit der Waffe aus und schlage am besten direkt von oben. Meistens reicht das aus, um den Gegner zu Boden zu strecken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_zweihand2_info_08_05_4', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_zweihand2_info_08_05_4","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_ZWEIHAND2_Info","outputIds":["Sld_700_Lee_ZWEIHAND2_Info_08_05","Sld_700_Lee_ZWEIHAND2_Info_08_06","Sld_700_Lee_ZWEIHAND2_Info_08_07","Sld_700_Lee_ZWEIHAND2_Info_08_08"],"lines":[{"speaker":"npc","text":{"pl":"Albo spróbuj wyprowadzić z lewej strony cios do przodu, aby odrzucić rywala do tyłu.","en":"Or bring the sword down from the top left in a forward thrust to drive your opponent back.","de":"Sonst schlage wieder von links oben nach vorne, um so den Gegner zurückzutreiben."}},{"speaker":"npc","text":{"pl":"Teraz obrót, żeby kolejny cios nabrał odpowiedniej mocy. Przy odrobinie szczęścia wróg nie przeżyje tego uderzenia.","en":"Spin round to give your next blow the necessary momentum to strike your opponent down.","de":"Eine schnelle Körperdrehung verleiht deinem nächsten Schlag die nötige Wucht, um den Gegner zu Boden zu zwingen."}},{"speaker":"npc","text":{"pl":"A jeśli i to nie wystarczy, wykorzystaj resztę siły zamachowej, by ponownie unieść miecz do góry.","en":"If it isn''t enough, use your remaining swing to wield the sword again.","de":"Falls das nicht ausreichen sollte, dann nutze den übrigen Schwung, um die Klinge noch einmal tanzen zu lassen."}},{"speaker":"npc","text":{"pl":"Po skończonym ataku wykonaj zasłonę i wypatruj luki w obronie przeciwnika.","en":"When you''ve finished your attack, block your opponent and wait for an opening to strike again.","de":"Geh nach deinem Angriff in den Block und suche eine Lücke, damit du erneut zuschlagen kannst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_zweihand2_info_08_09_8', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_zweihand2_info_08_09_8","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_ZWEIHAND2_Info","outputIds":["Sld_700_Lee_ZWEIHAND2_Info_08_09"],"lines":[{"speaker":"npc","text":{"pl":"Kluczem do sukcesu jest ciągła zmiana pozycji i umiejętne wykorzystanie bezwładności broni.","en":"The key to success is varying your stances and changing positions.","de":"Abwechslung in den Kampfbewegungen und Positionswechsel sind der Schlüssel zum Sieg."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_700_lee_sld_700_lee_zweihand2_info_15_01_0', 'SLD_700_Lee', '{"id":"missions_dia_sld_700_lee_sld_700_lee_zweihand2_info_15_01_0","npcId":"SLD_700_Lee","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_700_Lee.d","sourceFunction":"Sld_700_Lee_ZWEIHAND2_Info","outputIds":["Sld_700_Lee_ZWEIHAND2_Info_15_01","Sld_700_Lee_ZWEIHAND2_Info_08_02","Sld_700_Lee_ZWEIHAND2_Info_08_03","Sld_700_Lee_ZWEIHAND2_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym się dowiedzieć czegoś więcej o walce dwuręcznym mieczem.","en":"I want to learn more about fighting with a two-handed sword.","de":"Ich möchte mehr über den zweihändigen Kampf lernen."}},{"speaker":"npc","text":{"pl":"Musisz się nauczyć płynnie przenosić swój środek ciężkości. Trzymaj miecz pionowo. Obie dłonie mocno zaciśnij na rękojeści i przesuń go nieco w bok.","en":"First of all, you need to change your basic stance. Hold the sword vertically, grasp the hilt firmly in both hands and hold it at the side of your body.","de":"Ändere zunächst deine Grundhaltung. Halte das Schwert aufrecht, fasse den Griff mit beiden Händen und halte es seitlich am Körper."}},{"speaker":"npc","text":{"pl":"Teraz uderz szybko od góry i pozwól klindze powędrować nad twoje ramię. Teraz możesz wyprowadzić szybkie cięcie na prawo.","en":"Bring it down quickly and swing the blade over your shoulder. Now''s your chance to do a quick slash to your right.","de":"Schlage schnell von oben und lass die Klinge über deine Schulter gleiten. Nun hast du die Möglichkeit, einen schnellen Schlag nach rechts zu machen."}},{"speaker":"npc","text":{"pl":"Twój przeciwnik nie będzie miał okazji podejść bliżej.","en":"Your opponent won''t stand a chance of coming at you.","de":"Damit bietest du dem Gegner keine Chance, an dich ranzukommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_erzhaufen_15_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_erzhaufen_15_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_Erzhaufen_Info","outputIds":["DIA_Jarvis_Erzhaufen_15_00","DIA_Jarvis_Erzhaufen_08_01","DIA_Jarvis_Erzhaufen_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Macie tutaj wielką hałdę rudy?","en":"You have a massive ore mound here?","de":"Ihr habt einen riesigen Haufen Erz hier?"}},{"speaker":"npc","text":{"pl":"Aha, można tak powiedzieć. Za taką ilość rudy Rhobar sprzedałby własną żonę.","en":"You could say that. We could buy the King''s wife for that.","de":"Kann man wohl sagen. Wenn wir den mit der Außenwelt tauschen würden, würde uns der König seine Frau dafür verkaufen ."}},{"speaker":"npc","text":{"pl":"Ale my mamy gdzieś tego starego pierdziela. Chcemy się stąd wydostać!","en":"But we don''t give a damn about trading the ore with that old fart. We want to get OUT OF HERE!","de":"Aber wir werden einen Dreck tun, dem alten Sack das Erz zu geben. Wir wollen hier RAUS!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_exit_08_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_exit_08_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_EXIT_Info","outputIds":["DIA_Jarvis_EXIT_08_00"],"lines":[{"speaker":"npc","text":{"pl":"Uważaj na siebie!","en":"Watch your back!","de":"Pass auf deinen Rücken auf!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_first_08_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_first_08_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_First_Info","outputIds":["DIA_Jarvis_First_08_00","DIA_Jarvis_First_15_01","DIA_Jarvis_First_08_02","DIA_Jarvis_First_15_03"],"lines":[{"speaker":"npc","text":{"pl":"Chcesz przejść przez tę bramę?","en":"Do you intend to go through this gate?","de":"Hast du vor, durch dies Tor zu gehen?"}},{"speaker":"hero","text":{"pl":"A spróbujesz mnie powstrzymać?","en":"Do you intend to stop me?","de":"Willst du mich aufhalten?"}},{"speaker":"npc","text":{"pl":"Nie, ale powinieneś wiedzieć, co cię tam czeka. Nie jesteś w Starym Obozie, ani wśród tych nawiedzonych świrów!","en":"No, but you should know what''s waiting for you. This is not like in the Old Camp and not like being with the sect loonies either!","de":"Nein, aber du solltest wissen, was dich erwartet. Es läuft hier nicht so wie im Alten Lager und erst recht nicht wie bei den Sektenspinnern!"}},{"speaker":"hero","text":{"pl":"No i co mnie tam czeka?","en":"And what am I expecting here?","de":"Und wie läuft es hier?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_first_08_04_4', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_first_08_04_4","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_First_Info","outputIds":["DIA_Jarvis_First_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Tutaj nie ma Cieni ani Świątynnych Strażników, którzy wyciągną cię z kłopotów. W Nowym Obozie każdy musi radzić sobie sam. Tylko my - Najemnicy - trzymamy się razem.","en":"There are no guards or templars to look after you. It''s every man for himself, the only ones who stick together are us mercenaries.","de":"Es gibt hier keine Gardisten oder Templer, die auf dich aufpassen. Jeder ist sich selbst der Nächste, und die einzigen, die zusammenhalten, sind wir Söldner."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_magier_08_04_4', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_magier_08_04_4","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_Magier_Info","outputIds":["DIA_Jarvis_Magier_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Magowie twierdzą, że nie mamy się czego obawiać.","en":"They said we shouldn''t worry.","de":"Sie sagen, wir sollen uns keine Sorgen machen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_magier_15_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_magier_15_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_Magier_Info","outputIds":["DIA_Jarvis_Magier_15_00","DIA_Jarvis_Magier_08_01","DIA_Jarvis_Magier_08_02","DIA_Jarvis_Magier_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Co robią magowie?","en":"What do the mages do?","de":"Was machen die Magier?"}},{"speaker":"npc","text":{"pl":"Badają magiczne właściwości wydobywanej przez Krety rudy.","en":"They investigate the magic characteristics of the ore our scrapers collect in the mine.","de":"Sie erforschen die magischen Eigenschafen des Erzes, das unsere Schürfer aus der Mine holen."}},{"speaker":"npc","text":{"pl":"O ile się orientuję, zamierzają wysadzić w powietrze cały ten piekielny kopiec i zniszczyć Barierę.","en":"As far as I know, they want to blow the whole damn ore mound sky-high to free us from the Barrier.","de":"Soweit ich das verstanden habe, wollen sie den ganzen verdammten Erzhaufen in die Luft jagen, um die Barriere wegzusprengen."}},{"speaker":"hero","text":{"pl":"To chyba niebezpiecznie.","en":"Sounds dangerous.","de":"Klingt gefährlich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_perm_15_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_perm_15_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_PERM_Info","outputIds":["DIA_Jarvis_PERM_15_00","DIA_Jarvis_PERM_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać w Obozie?","en":"How are things going at the moment?","de":"Wie ist die Lage zur Zeit?"}},{"speaker":"npc","text":{"pl":"Krety nadal pracują. Kiedy uzbierają dość rudy, wysadzimy ją w powietrze.","en":"The scrapers are still collecting. Once they have enough ore, we''ll blow the mound up.","de":"Die Schürfer sammeln noch. Wenn sie genug Erz haben, jagen wir den Haufen in die Luft."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_rest_15_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_rest_15_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_Rest_Info","outputIds":["DIA_Jarvis_Rest_15_00","DIA_Jarvis_Rest_08_01"],"lines":[{"speaker":"hero","text":{"pl":"A co z innymi ludźmi?","en":"What about the rest of the people?","de":"Was ist mit dem Rest der Leute?"}},{"speaker":"npc","text":{"pl":"Szumowiny, bez wyjątku. Mają gdzieś ten Obóz. Już wolałbym, żeby byle zbieracze ryżu pilnowali bramy.","en":"All crooks. They don''t give a damn about the Camp. I''d rather just have the peasants guarding the front gate.","de":"Alles Banditen. Sie kümmern sich keinen Deut um das Lager. Ich würde sie nicht mal das Vortor bewachen lassen, wahrscheinlich wäre es sinnvoller, dort ein paar Bauern hinzustellen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_sld_info_15_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_sld_info_15_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_SldInfo_Info","outputIds":["DIA_Jarvis_SldInfo_15_00","DIA_Jarvis_SldInfo_08_01","DIA_Jarvis_SldInfo_08_02","DIA_Jarvis_SldInfo_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Czym zajmują się Najemnicy?","en":"What do the mercenaries do?","de":"Was machen die Söldner?"}},{"speaker":"npc","text":{"pl":"Jesteśmy żołnierzami w służbie Magów Wody.","en":"We - we are the mercenaries of the water mages.","de":"Wir - wir sind die Söldner der Wassermagier."}},{"speaker":"npc","text":{"pl":"Naszym celem jest wyrwanie się z tej przeklętej kolonii. Musimy ciężko pracować, bo nie chcieliśmy iść na łatwiznę, jak Magnaci ze Starego Obozu, którzy żerują na niewolniczej pracy Kopaczy.","en":"Our target is to break free from here. We''re working hard for it and don''t plan to take things easy like the guys from the Old Camp, who are just having an easy time resting on the backs of the diggers.","de":"Unser Ziel ist es, hier auszubrechen. Wir arbeiten hart dafür und wir wollen uns hier keinen Lenz machen, wie die Lumpen aus dem Alten Lager, die sich nur auf den Schultern der Buddler ausruhen."}},{"speaker":"npc","text":{"pl":"I wszyscy jesteśmy posłuszni Lee. To wspaniały człowiek. Tylko dzięki niemu ten cholerny obóz jeszcze się nie rozpadł.","en":"And we all follow Lee. He''s a great man. He''s the one who holds this damn camp together.","de":"Und wir alle folgen Lee. Er ist ein großer Mann. Nur er hält dieses verdammte Lager zusammen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_dia_jarvis_wo_haufen_15_00_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_dia_jarvis_wo_haufen_15_00_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"DIA_Jarvis_WoHaufen_Info","outputIds":["DIA_Jarvis_WoHaufen_15_00","DIA_Jarvis_WoHaufen_08_01","DIA_Jarvis_WoHaufen_08_02","DIA_Jarvis_WoHaufen_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie jest ten kopiec?","en":"Where''s the ore mound?","de":"Wo ist der Erzhaufen?"}},{"speaker":"npc","text":{"pl":"Chcesz zobaczyć wielką górę rudy, co? Na środku jaskini jest dziura. Tam wszystko zrzucają.","en":"You want to see a real mound of ore, do you? There''s a hole in the middle of the cave, they shove it all in there.","de":"Willst mal richtig viel Erz sehen, was? In der Mitte der Höhle ist ein Loch, da kippen sie alles rein."}},{"speaker":"npc","text":{"pl":"Ale nie pozwolą ci się do niej zbliżyć, mówię ci. Magowie i nasi ludzie pilnują rudy dniem i nocą.","en":"But you won''t get anywhere near it, I can tell you. The mages and our people guard the ore day and night.","de":"Aber ran kommst du da nicht, das kann ich dir gleich sagen. Die Magier und unsere Leute bewachen das Erz Tag und Nacht."}},{"speaker":"hero","text":{"pl":"Pytałem z ciekawości.","en":"I was just curious.","de":"Ich war nur neugierig."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_728_jarvis_sld_728_jarvis_aufnahmesoldier_info_08_01_0', 'SLD_728_Jarvis', '{"id":"missions_dia_sld_728_jarvis_sld_728_jarvis_aufnahmesoldier_info_08_01_0","npcId":"SLD_728_Jarvis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_728_Jarvis.d","sourceFunction":"Sld_728_Jarvis_AUFNAHMESOLDIER_Info","outputIds":["Sld_728_Jarvis_AUFNAHMESOLDIER_Info_08_01","Sld_728_Jarvis_AUFNAHMESOLDIER_Info_08_02"],"lines":[{"speaker":"npc","text":{"pl":"Hej, słyszałem, że nieźle dałeś popalić pełzaczom z kopalni!","en":"Hey, I heard you''d been giving the crawlers in the mine a hard time.","de":"Hey, ich habe gehört, du hast die Crawler in der Mine ganz schön aufgemischt."}},{"speaker":"npc","text":{"pl":"Lee pewnie zgodzi się przyjąć cię do Najemników. Powinieneś z nim pogadać.","en":"Lee should be quite willing to accept you as a mercenary. Just speak to him.","de":"Lee ist bestimmt bereit, dich als Söldner aufzunehmen. Sprich doch einfach mal mit ihm."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_729_kharim_info_kharim_charge_15_00_0', 'SLD_729_Kharim', '{"id":"missions_dia_sld_729_kharim_info_kharim_charge_15_00_0","npcId":"SLD_729_Kharim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_729_Kharim.d","sourceFunction":"Info_Kharim_Charge_Info","outputIds":["Info_Kharim_Charge_15_00","Info_Kharim_Charge_09_01","Info_Kharim_Charge_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Wyzywam cię na pojedynek! Chodźmy na arenę!","en":"I''ll challenge you! Let''s go to the arena!","de":"Ich fordere dich heraus! Lass es uns in der Arena austragen!"}},{"speaker":"npc","text":{"pl":"TY?! Takich jak ty zjadam na śniadanie!","en":"YOU?! I''ll have you for breakfast, kid!","de":"DU?! Ich fress'' dich zum Frühstück, Kleiner!"}},{"speaker":"npc","text":{"pl":"Dobrze ci radzę, chłoptasiu - SPADAJ STĄD!","en":"Do yourself a favor and get lost!","de":"Tu dir selber einen Gefallen und mach, dass du wegkommst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_729_kharim_info_kharim_charge_insult_15_00_0', 'SLD_729_Kharim', '{"id":"missions_dia_sld_729_kharim_info_kharim_charge_insult_15_00_0","npcId":"SLD_729_Kharim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_729_Kharim.d","sourceFunction":"Info_Kharim_Charge_Insult","outputIds":["Info_Kharim_Charge_Insult_15_00","Info_Kharim_Charge_Insult_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Boisz się, że oberwiesz, tchórzu?!","en":"So you don''t get hurt, you coward?!","de":"Damit du ungeschoren davonkommst, du feiges Schwein?!"}},{"speaker":"npc","text":{"pl":"Nie stać cię na nic lepszego, chłopcze?","en":"Don''t you have any better ideas, boy?","de":"Fällt dir nichts besseres ein, Kleiner?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_729_kharim_info_kharim_charge_insult_face_15_00_0', 'SLD_729_Kharim', '{"id":"missions_dia_sld_729_kharim_info_kharim_charge_insult_face_15_00_0","npcId":"SLD_729_Kharim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_729_Kharim.d","sourceFunction":"Info_Kharim_Charge_Insult_Face","outputIds":["Info_Kharim_Charge_Insult_Face_15_00","Info_Kharim_Charge_Insult_Face_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Z początku chciałem powiedzieć coś o twoich wątłych ramionach, ale potem zobaczyłem twoją paskudną mordę.","en":"At first I wanted to say something about your thin arms, but then I saw your ugly mug.","de":"Ich wollte zuerst was über deine dürren Ärmchen sagen, aber dann fiel mir deine hässliche Fesse auf."}},{"speaker":"npc","text":{"pl":"To twoja ostatnia szansa, żeby odejść stąd o własnych siłach!","en":"I think this is your last chance to finally GET LOST!","de":"Ich denke, das ist deine letzte Chance, hier ENDLICH ZU VERSCHWINDEN!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_729_kharim_info_kharim_charge_insult_goats_15_00_0', 'SLD_729_Kharim', '{"id":"missions_dia_sld_729_kharim_info_kharim_charge_insult_goats_15_00_0","npcId":"SLD_729_Kharim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_729_Kharim.d","sourceFunction":"Info_Kharim_Charge_Insult_Goats","outputIds":["Info_Kharim_Charge_Insult_Goats_15_00","Info_Kharim_Charge_Insult_Goats_09_01"],"lines":[{"speaker":"hero","text":{"pl":"To może tak: twój ojciec zabawiał się z owcami...","en":"How about: Your mother''s a sheep-shagging...","de":"Wie wär''s mit: Deine Mutter treibt''s mit Ziegen ..."}},{"speaker":"npc","text":{"pl":"Cóż, były takie plotki...","en":"Yeah, I guess she is...","de":"Das tut sie vermutlich wirklich ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_729_kharim_info_kharim_charge_insult_gomez_ass_15_00_0', 'SLD_729_Kharim', '{"id":"missions_dia_sld_729_kharim_info_kharim_charge_insult_gomez_ass_15_00_0","npcId":"SLD_729_Kharim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_729_Kharim.d","sourceFunction":"Info_Kharim_Charge_Insult_GomezAss","outputIds":["Info_Kharim_Charge_Insult_GomezAss_15_00","Info_Kharim_Charge_Insult_GomezAss_09_01","Info_Kharim_Charge_Insult_GomezAss_09_02","Info_Kharim_Charge_Insult_GomezAss_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Powiedzmy sobie szczerze: przyszedłeś tutaj tylko dlatego, żeby móc pocałować Gomeza w dupę!","en":"You''re only here to get a chance to kiss Gomez'' ass!","de":"Du bist doch nur hier, damit du mal ''ne Chance bekommst, Gomez in den Arsch zu kriechen!"}},{"speaker":"npc","text":{"pl":"CO!?! Ty gnido! Nie wiesz o czym mówisz! Nowy Obóz ma was gdzieś!","en":"WHAT!?! You worm! You know nothing about us! The New Camp is INDEPENDENT from all that shit!","de":"WAS!?! Du Wurm! Du weißt gar nichts über uns! Das Neue Lager ist UNABHÄNGIG von dieser ganzen Scheiße!"}},{"speaker":"npc","text":{"pl":"A poza tym jest tylko jeden powód, dla którego tutaj przyszedłem: zamierzam publicznie upokorzyć każdego mięczaka, który ośmieli się wyzwać mnie na pojedynek.","en":"And apart from that there''s only one reason why I''m here: So I can beat the brains out of smart asses like you.","de":"Und im Übrigen gibt es nur einen Grund, warum ich hier bin: Damit ich Klugscheißern wie dir das Hirn aus dem Schädel prügeln kann."}},{"speaker":"npc","text":{"pl":"Ale ciebie załatwię z wyjątkową przyjemnością! Czekam na ciebie na arenie!","en":"It''ll be my pleasure to do the same to YOU! Your destiny is awaiting you in the arena!","de":"Es wird mir ein Vergnügen sein, das bei DIR zu tun! Dein Schicksal erwartet dich in der Arena!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_729_kharim_info_kharim_charge_insult_stupid_15_00_0', 'SLD_729_Kharim', '{"id":"missions_dia_sld_729_kharim_info_kharim_charge_insult_stupid_15_00_0","npcId":"SLD_729_Kharim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_729_Kharim.d","sourceFunction":"Info_Kharim_Charge_Insult_Stupid","outputIds":["Info_Kharim_Charge_Insult_Stupid_15_00","Info_Kharim_Charge_Insult_Stupid_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Pomyślmy... Nie, nie przychodzi mi do głowy nic, co byłbyś w stanie zrozumieć.","en":"Let''s think about it: No, there''s nothing I can think of you''d actually understand.","de":"Lass mal überlegen: Nein, mir fällt nichts ein, was du begreifen würdest."}},{"speaker":"npc","text":{"pl":"Może jednak powinieneś spróbować.","en":"Maybe you should give it a try.","de":"Vielleicht solltest du es auf einen Versuch ankommen lassen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_729_kharim_info_kharim_in_arena_09_00_0', 'SLD_729_Kharim', '{"id":"missions_dia_sld_729_kharim_info_kharim_in_arena_09_00_0","npcId":"SLD_729_Kharim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_729_Kharim.d","sourceFunction":"Info_Kharim_InArena_Info","outputIds":["Info_Kharim_InArena_09_00","SVM_9_LetsForgetOurLittleFight"],"lines":[{"speaker":"npc","text":{"pl":"Ból to tylko kwestia siły woli!","en":"Pain is a question of willpower!","de":"Schmerzen sind eine Frage des Willens!"}},{"speaker":"npc","text":{"pl":"Może zapomnimy o naszej małej sprzeczce...","en":"Von mir aus können wir unseren Streit vergessen ...","de":"Von mir aus können wir unseren Streit vergessen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_737_torlof_dia_torlof_hallo_04_04_4', 'SLD_737_Torlof', '{"id":"missions_dia_sld_737_torlof_dia_torlof_hallo_04_04_4","npcId":"SLD_737_Torlof","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_737_Torlof.d","sourceFunction":"DIA_Torlof_Hallo_Info","outputIds":["DIA_Torlof_Hallo_04_04"],"lines":[{"speaker":"npc","text":{"pl":"W ten sposób wylądowałem tutaj.","en":"That''s how I came to be here.","de":"Seitdem bin ich hier."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_737_torlof_dia_torlof_mitmachen_04_04_4', 'SLD_737_Torlof', '{"id":"missions_dia_sld_737_torlof_dia_torlof_mitmachen_04_04_4","npcId":"SLD_737_Torlof","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_737_Torlof.d","sourceFunction":"DIA_Torlof_Mitmachen_Info","outputIds":["DIA_Torlof_Mitmachen_04_04","DIA_Torlof_Mitmachen_15_05","DIA_Torlof_Mitmachen_04_06"],"lines":[{"speaker":"npc","text":{"pl":"Kiedy chłopcy uznają, że nie przepadasz za Gomezem, przestaną ci sprawiać kłopoty.","en":"As soon as the boys notice that you''re against Gomez, you won''t have any more trouble here.","de":"Wenn die Jungs hier merken, dass du gegen Gomez bist, hast du hier keine Probleme mehr."}},{"speaker":"hero","text":{"pl":"A jak mam to zrobić?","en":"And how do I do that?","de":"Und wie stelle ich das an?"}},{"speaker":"npc","text":{"pl":"Najpierw musisz zyskać ich zaufanie, a potem będziesz mógł ich zrobić w konia!","en":"You need to win their TRUST - and then you can rip ''em off!","de":"Du mußt ihr VERTRAUEN gewinnen - und dann haust du sie über''s Ohr!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_737_torlof_dia_torlof_mitmachen_15_00_0', 'SLD_737_Torlof', '{"id":"missions_dia_sld_737_torlof_dia_torlof_mitmachen_15_00_0","npcId":"SLD_737_Torlof","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_737_Torlof.d","sourceFunction":"DIA_Torlof_Mitmachen_Info","outputIds":["DIA_Torlof_Mitmachen_15_00","DIA_Torlof_Mitmachen_04_01","DIA_Torlof_Mitmachen_04_02","DIA_Torlof_Mitmachen_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym do was dołączyć.","en":"I''d like to join you.","de":"Ich will bei euch mitmachen."}},{"speaker":"npc","text":{"pl":"Lee przyjmuje tylko najlepszych ludzi, możesz mi wierzyć.","en":"Lee won''t take you on until you get real good, I''m telling you now.","de":"Bevor du nicht einiges auf''m Kasten hast, wird Lee dich nicht nehmen, das sag ich dir gleich."}},{"speaker":"npc","text":{"pl":"I dopóki nie będziesz jednym z nich radzę ci dobrze żyć z Laresem i jego zgrają.","en":"And until then you''d better stay on good terms with Lares and his crowd.","de":"Und bis du besser bist, solltest du dich mit Lares und seinen Jungs gut stellen."}},{"speaker":"npc","text":{"pl":"Jeśli chcesz dobrą radę, chłopcze: spróbuj zwinąć coś ze Starego Obozu albo Starej Kopalni.","en":"You want some advice, boy: Steal something important from the Old Camp or the Old Mine.","de":"Wenn du nen Tipp willst, Junge: Klau was wichtiges aus dem Alten Lager oder der Alten Mine."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_737_torlof_dia_torlof_perm_15_00_0', 'SLD_737_Torlof', '{"id":"missions_dia_sld_737_torlof_dia_torlof_perm_15_00_0","npcId":"SLD_737_Torlof","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_737_Torlof.d","sourceFunction":"DIA_Torlof_PERM_Info","outputIds":["DIA_Torlof_PERM_15_00","DIA_Torlof_PERM_04_01","DIA_Torlof_PERM_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Was kannst du mir über dieses Lager sagen?","en":"Was kannst du mir über dieses Lager sagen?","de":"Was kannst du mir über dieses Lager sagen?"}},{"speaker":"npc","text":{"pl":"Ist wie auf''m Piratenschiff, Junge. Solange ab und zu ein fetter Fischzug gegen Gomez drin ist, sind die Banditen zufrieden.","en":"Ist wie auf''m Piratenschiff, Junge. Solange ab und zu ein fetter Fischzug gegen Gomez drin ist, sind die Banditen zufrieden.","de":"Ist wie auf''m Piratenschiff, Junge. Solange ab und zu ein fetter Fischzug gegen Gomez drin ist, sind die Banditen zufrieden."}},{"speaker":"npc","text":{"pl":"Wenn sie kein Erz mehr haben, um sich in der Kneipe vollaufen zu lassen, gibt''s ne Menge Schlägereien.","en":"Wenn sie kein Erz mehr haben, um sich in der Kneipe vollaufen zu lassen, gibt''s ne Menge Schlägereien.","de":"Wenn sie kein Erz mehr haben, um sich in der Kneipe vollaufen zu lassen, gibt''s ne Menge Schlägereien."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_angebotdochannehmen_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_angebotdochannehmen_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Angebotdochannehmen_Info","outputIds":["DIA_SLD_753_Baloro_Angebotdochannehmen_Info_15_01","DIA_SLD_753_Baloro_Angebotdochannehmen_Info_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Zmieniłem zdanie. Porozmawiajmy jeszcze raz o twojej propozycji.","en":"I thought about it. I''d like to get back to your offer now.","de":"Ich hab''s mir überlegt. Ich möchte dein Angebot doch annehmen."}},{"speaker":"npc","text":{"pl":"Teraz jest już za późno. Miałeś swoją szansę!","en":"It''s too late now! You''ve had your chance!","de":"Dafür ist es jetzt zu spät! Du hattest deine Chance!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_exit_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_exit_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Exit_Info","outputIds":["DIA_SLD_753_Baloro_Exit_Info_15_01","DIA_SLD_753_Baloro_Exit_Info_08_02","DIA_SLD_753_Baloro_Exit_Info_15_03","DIA_SLD_753_Baloro_Exit_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Nie, nie! Nieważne! Nie jestem zainteresowany!","en":"No, no! Just leave it! I''m not interested!","de":"Nee, nee! Lass mal! Kein Interesse!"}},{"speaker":"npc","text":{"pl":"Cóż, jak sobie życzysz! Marnujesz niepowtarzalną okazję!","en":"Well then! As you wish! You''ve had your chance!","de":"Na gut! Wie du willst! Du hattest deine Chance!"}},{"speaker":"hero","text":{"pl":"Przykro mi, ale nie mam czasu na pogawędki!","en":"I''m sorry! Unfortunately I don''t have any time to chat!","de":"Tut mir Leid! Ich hab'' leider keine Zeit für ein Pläuschchen!"}},{"speaker":"npc","text":{"pl":"Och, jesteś zajęty! Porozmawiamy innym razem!","en":"Oh, you''re busy! I''ll see you!","de":"Oh, haben wir es eilig! Na dann! Wir sehen uns!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_habsdabei_info_08_05_8', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_habsdabei_info_08_05_8","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_habsdabei_Info","outputIds":["DIA_SLD_753_Baloro_habsdabei_Info_08_05","DIA_SLD_753_Baloro_habsdabei_Info_08_06"],"lines":[{"speaker":"npc","text":{"pl":"Dziwię się, że przeżyłeś tak długo! Jeśli będziesz wierzył we wszystko co ci powiedzą tutejsi ludzie, nie pociągniesz długo!","en":"I''m amazed to see you''re still alive! If you believe everything people say, you won''t survive long here!","de":"Wundert mich, dass du überhaupt noch lebst! Wenn du so leichtgläubig hier in der Gegend rumrennst, machst du''s nicht mehr lange!"}},{"speaker":"npc","text":{"pl":"A zresztą - nieważne! Teraz mamy dość jedzenia na małą ucztę. Wielkie dzięki! Może się jeszcze spotkamy! He he he!","en":"Doesn''t matter though! Now we boys have enough food for a party! Thanks a lot! And maybe we''ll meet you again. He he he!","de":"Macht aber nichts! Jetzt haben wir Jungs wenigstens genügend Fressalien zum Feiern! Schönen Dank auch! Und vielleicht sehen wir uns ja noch mal. He he he!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_habsdabei_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_habsdabei_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_habsdabei_Info","outputIds":["DIA_SLD_753_Baloro_habsdabei_Info_15_01","DIA_SLD_753_Baloro_habsdabei_Info_08_01","DIA_SLD_753_Baloro_habsdabei_Info_15_02","DIA_SLD_753_Baloro_habsdabei_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Mam już wszystko! teraz porozmawiajmy o tej niesamowitej broni, tak?","en":"I have all the stuff on me! Now we''ll do the deal with that super weapon, right?","de":"Ich hab'' den ganzen Kram dabei! Jetzt machen wir den Deal mit der ultimativen Waffe, ja?"}},{"speaker":"npc","text":{"pl":"Najpierw pokaż mi, co dla mnie masz.","en":"Then show me the stuff first!","de":"Dann zeig doch erst mal her!"}},{"speaker":"hero","text":{"pl":"Proszę bardzo!","en":"Here you go!","de":"Hier hast du!"}},{"speaker":"npc","text":{"pl":"Nooo... W porządku!","en":"Yeah, great!","de":"Ja, klasse!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_habsdabei_info_15_03_4', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_habsdabei_info_15_03_4","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_habsdabei_Info","outputIds":["DIA_SLD_753_Baloro_habsdabei_Info_15_03","DIA_SLD_753_Baloro_habsdabei_Info_08_03","DIA_SLD_753_Baloro_habsdabei_Info_15_04","DIA_SLD_753_Baloro_habsdabei_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"A teraz broń!","en":"Well, give me the thing now!!","de":"So, nun her mit dem Ding!!"}},{"speaker":"npc","text":{"pl":"Zapomnij o tym!","en":"Forget it!","de":"Vergiss es!"}},{"speaker":"hero","text":{"pl":"Co?!","en":"What?","de":"Was?"}},{"speaker":"npc","text":{"pl":"Naprawdę myślałeś, że dostaniesz coś w zamian? Jeśli rzeczywiście jesteś taki głupi, to aż ci współczuję!","en":"Did you really think you''d get something for it? I mean, if you''re stupid enough to believe that you don''t deserve any better!!","de":"Glaubst du echt, da kommt jetzt noch was? Ich meine, wer so dämlich ist, sich auf so einen Quatsch einzulassen, der hat''s auch nicht besser verdient!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_habsnichtdabei_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_habsnichtdabei_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_habsnichtdabei_Info","outputIds":["DIA_SLD_753_Baloro_habsnichtdabei_Info_15_01","DIA_SLD_753_Baloro_habsnichtdabei_Info_08_01","DIA_SLD_753_Baloro_habsnichtdabei_Info_08_02","DIA_SLD_753_Baloro_habsnichtdabei_Info_15_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie udało mi się jeszcze zebrać wszystkich potrzebnych ci rzeczy. Mógłbyś mi przypomnieć, co to miało być?","en":"I couldn''t get your stuff yet! What was it again? There were so many different things!","de":"Ich konnte deinen Kram nicht besorgen! Was war das noch mal? Es war so viel Verschiedenes!"}},{"speaker":"npc","text":{"pl":"Jasne. Słuchaj uważnie. Chcę, żebyś mi przyniósł...","en":"Okay then! I''ll repeat it slowly. Well, I want you to get...","de":"Na schön! Noch mal zum Mitschreiben. Also, ich will von dir ..."}},{"speaker":"npc","text":{"pl":"5 jabłek, 2 butelki ryżówki, 5 butelek piwa, 3 bochenki chleba, 2 kawałki sera i 2 kiście winogron! Zapamiętasz tym razem?","en":"5 apples, 2 bottles of rice schnapps, 5 bottles of beer, 3 loafs of bread, 2 pieces of cheese and 2 bunches of grapes! Did you get it this time?","de":"5 Äpfel, 2 Flaschen Reisschnaps, 5 Flaschen Bier, 3 Laib Brot, 2 Käsestücke und 2 Weintraubenreben! Hast du''s jetzt?"}},{"speaker":"hero","text":{"pl":"Oczywiście! Niedługo wrócę!","en":"Alright! Sure! I''ll hurry up!","de":"Ach ja! Sicher! Ich beeil mich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_intro_08_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_intro_08_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Intro_Info","outputIds":["DIA_SLD_753_Baloro_Intro_08_01"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty! Co się dzieje?","en":"Hey, you! What''s up?","de":"Hey, du! Was ist los?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_letztes_wort_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_letztes_wort_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_letztes_Wort_Info","outputIds":["DIA_SLD_753_Baloro_letztes_Wort_Info_15_01","DIA_SLD_753_Baloro_letztes_Wort_Info_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Hej! Nie dam się robić w konia!","en":"Hey man! You can''t do that to me!","de":"Hey, Mann! Das kannst du mit mir nicht machen!"}},{"speaker":"npc","text":{"pl":"Czego znowu chcesz! Uciekaj stąd! Powkurzaj sobie kogoś innego, co? No już - spadaj!","en":"What more do you want! Piss off! Get on somebody else''s nerves, or you''ll get it! Got it?","de":"Was willst du denn noch! Verschwinde! Geh jemand anders auf die Nerven, sonst setzt''s was! Kapiert?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_sc_wills_wissen_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_sc_wills_wissen_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_SC_wills_wissen_Info","outputIds":["DIA_SLD_753_Baloro_SC_wills_wissen_Info_15_01","DIA_SLD_753_Baloro_SC_wills_wissen_Info_08_01","DIA_SLD_753_Baloro_SC_wills_wissen_Info_15_02","DIA_SLD_753_Baloro_SC_wills_wissen_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Widzę, że będę ci musiał dać nauczkę.","en":"I''m afraid I''m going to have to whack you one!","de":"Ich glaube, ich muss dir jetzt leider die Fresse polieren!"}},{"speaker":"npc","text":{"pl":"No już - pośmialiśmy się trochę, a teraz spadaj stąd! Sio!","en":"We''ve had our fun! Now get lost, man!","de":"Wir haben unseren Spaß gehabt! Jetzt zieh´ Leine, Mann!"}},{"speaker":"hero","text":{"pl":"Chyba mnie nie zrozumiałeś!","en":"I believe you didn''t understand me!","de":"Ich glaube, du hast mich nicht verstanden!"}},{"speaker":"npc","text":{"pl":"No dobra! Sam się o to prosiłeś! Ostrzegałem cię!","en":"Okay then! You asked for it! You were warned!","de":"Na gut! Du willst es ja nicht anders! Ich hab'' dich gewarnt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_wasmeinstdu_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_wasmeinstdu_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Wasmeinstdu_Info","outputIds":["DIA_SLD_753_Baloro_Wasmeinstdu_Info_15_01","DIA_SLD_753_Baloro_Wasmeinstdu_Info_08_02","DIA_SLD_753_Baloro_Wasmeinstdu_Info_15_03","DIA_SLD_753_Baloro_Wasmeinstdu_Info_08_04"],"lines":[{"speaker":"hero","text":{"pl":"Cześć!","en":"Hi!","de":"Hi!"}},{"speaker":"npc","text":{"pl":"Kręcisz się tutaj, jakbyś czegoś szukał!","en":"You''re walking about here as if you were searching for something!","de":"Du läufst hier rum, als würdest du was suchen!"}},{"speaker":"hero","text":{"pl":"Czyżby? Mmh, może masz rację. A dlaczego?","en":"Really? Mmh, maybe you''re right. Why?","de":"Tatsächlich? Mmh, stimmt vielleicht. Wieso?"}},{"speaker":"npc","text":{"pl":"Świetnie! Zapytaj MNIE! Może mogę ci jakoś pomóc!","en":"Great! Ask me! Maybe I can help you!","de":"Wunderbar! Frag mich! Ich kann dir vielleicht weiterhelfen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_info_08_03_4', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_info_08_03_4","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Worumgehts_Info","outputIds":["DIA_SLD_753_Baloro_Worumgehts_Info_08_03","DIA_SLD_753_Baloro_Worumgehts_Info_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Mam tu coś takiego, że oczy ci wyjdą na wierzch. Mogę ci dać broń, którą pokonasz każdego wroga!","en":"I can give you something that''ll make your eyes pop out of their sockets! I can give you a weapon that will defeat any foe!","de":"Ich hab'' dir was anzubieten, da werden dir die Augen übergehen! Ich kann dir eine Waffe besorgen, mit der du jeden Gegner besiegst!"}},{"speaker":"npc","text":{"pl":"W zamian, wystarczy, że wyświadczysz mi drobną przysługę. To wszystko! Co ty na to?","en":"You only need to do me a small favor. Then it''ll be yours! What do you say?","de":"Das einzige, was du tun musst, um sie zu bekommen, ist mir einen kleinen Gefallen zu erweisen. Und sie gehört dir! Was sagst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_info_15_01_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_info_15_01_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Worumgehts_Info","outputIds":["DIA_SLD_753_Baloro_Worumgehts_Info_15_01","DIA_SLD_753_Baloro_Worumgehts_Info_08_01","DIA_SLD_753_Baloro_Worumgehts_Info_15_02","DIA_SLD_753_Baloro_Worumgehts_Info_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Co masz na myśli?","en":"What did you have in mind?","de":"Woran hast du dabei gedacht?"}},{"speaker":"npc","text":{"pl":"A czego potrzebujesz?","en":"What do you need?","de":"Was brauchst du denn?"}},{"speaker":"hero","text":{"pl":"Na początek wystarczy dobry miecz, gruby pancerz i wstęp do kopalni.","en":"What about a good sword, thick armor or access to the mine?","de":"Wie wär''s mit einem guten Schwert, einer starken Rüstung oder dem Zugang zur Mine?"}},{"speaker":"npc","text":{"pl":"Phi! To małe piwo!","en":"Aw no! That''s nothing!","de":"Ach was! Das ist alles noch viel zu schlapp!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_ja_15_05_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_ja_15_05_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Worumgehts_ja","outputIds":["DIA_SLD_753_Baloro_Worumgehts_ja_15_05","DIA_SLD_753_Baloro_Worumgehts_ja_08_03","DIA_SLD_753_Baloro_Worumgehts_ja_08_04","DIA_SLD_753_Baloro_Worumgehts_ja_08_05"],"lines":[{"speaker":"hero","text":{"pl":"Co miałbym dla ciebie zrobić?","en":"What will I have to do for it?","de":"Was müsste ich denn dafür tun?"}},{"speaker":"npc","text":{"pl":"To proste!","en":"Very simple!","de":"Ganz einfach!"}},{"speaker":"npc","text":{"pl":"Przynieś mi 5 jabłek, 2 butelki ryżówki, 5 butelek piwa, 3 bochenki chleba, 2 kawałki sera i 2 kiście winogron.","en":"Get me 5 apples, 2 bottles of rice schnapps, 5 bottles of beer, 3 loafs of bread, 2 pieces of cheese and 2 bunches of grapes, and we''re in business!","de":"Bring mir 5 Äpfel, 2 Flaschen Reisschnaps, 5 Flaschen Bier, 3 Laibe Brot, 2 Käsestücke und 2 Weintraubenreben und wir kommen ins Geschäft!"}},{"speaker":"npc","text":{"pl":"Możesz mi wierzyć: nie pożałujesz! Jak już mówiłem - tą bronią pokonasz każdego wroga!","en":"Believe me, you won''t be sorry. As I just said: You''ll really defeat any kind of enemy with it!","de":"Glaub mir, du wirst es nicht bereuen. Wie ich schon sagte: Wirklich jeden Gegner machst du damit platt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_ja_15_06_0', 'SLD_753_Baloro', '{"id":"missions_dia_sld_753_baloro_dia_sld_753_baloro_worumgehts_ja_15_06_0","npcId":"SLD_753_Baloro","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_SLD_753_Baloro.d","sourceFunction":"DIA_SLD_753_Baloro_Worumgehts_jaklar","outputIds":["DIA_SLD_753_Baloro_Worumgehts_ja_15_06","DIA_SLD_753_Baloro_Worumgehts_ja_08_06","DIA_SLD_753_Baloro_Worumgehts_ja_08_07","DIA_SLD_753_Baloro_Worumgehts_ja_15_07"],"lines":[{"speaker":"hero","text":{"pl":"Dobrze! Zobaczę co się da zrobić!","en":"Okay! I''ll see what I can do then!","de":"Na gut! Ich werde sehen, was ich tun kann!"}},{"speaker":"npc","text":{"pl":"To świetnie! Tylko się pospiesz.","en":"Very good! But hurry up!","de":"Sehr schön! Aber beeil dich!"}},{"speaker":"npc","text":{"pl":"Tylko nie zapomnij: 5 jabłek, 2 butelki ryżówki, 5 butelek piwa, 3 bochenki chleba, 2 kawałki sera i 2 kiście winogron! Jasne?","en":"Don''t forget: 5 apples, 2 bottles of rice schnapps, 5 bottles of beer, 3 loafs of bread, 2 pieces of cheese and 2 bunches of grapes! Okay?","de":"Vergiss es nicht: 5 Äpfel, 2 Flaschen Reisschnaps, 5 Flaschen Bier, 3 Laibe Brot, 2 Käsestücke und 2 Weintraubenreben! Klar?"}},{"speaker":"hero","text":{"pl":"Jak słońce.","en":"Of course!","de":"Klar!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_302_viper_stt_302_viper_greet_info_15_01_0', 'STT_302_Viper', '{"id":"missions_dia_stt_302_viper_stt_302_viper_greet_info_15_01_0","npcId":"STT_302_Viper","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_302_Viper.d","sourceFunction":"Stt_302_Viper_GREET_Info","outputIds":["Stt_302_Viper_GREET_Info_15_01","Stt_302_Viper_GREET_Info_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Podobno jesteś hutnikiem.","en":"I hear you''re the smelter.","de":"Ich habe gehört, du bist der Schmelzer."}},{"speaker":"npc","text":{"pl":"Widzę, że bystry z ciebie chłopak.","en":"You''re a smart boy indeed.","de":"Du bist ja ein ganz schlauer Bursche."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_302_viper_stt_302_viper_melt_info_11_05_4', 'STT_302_Viper', '{"id":"missions_dia_stt_302_viper_stt_302_viper_melt_info_11_05_4","npcId":"STT_302_Viper","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_302_Viper.d","sourceFunction":"Stt_302_Viper_MELT_Info","outputIds":["Stt_302_Viper_MELT_Info_11_05"],"lines":[{"speaker":"npc","text":{"pl":"W końcu poprzestaliśmy na przetapianiu części urobku. Magowie więcej się tu nie pojawili.","en":"Finally we only smelted a part of the ore. The mages never came back here.","de":"Das Ende vom Lied war, dass wir nur noch einen Teil des Erzes einschmelzen. Die Magier sind nicht mehr hier runter gekommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_302_viper_stt_302_viper_melt_info_15_01_0', 'STT_302_Viper', '{"id":"missions_dia_stt_302_viper_stt_302_viper_melt_info_15_01_0","npcId":"STT_302_Viper","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_302_Viper.d","sourceFunction":"Stt_302_Viper_MELT_Info","outputIds":["Stt_302_Viper_MELT_Info_15_01","Stt_302_Viper_MELT_Info_11_02","Stt_302_Viper_MELT_Info_11_03","Stt_302_Viper_MELT_Info_11_04"],"lines":[{"speaker":"hero","text":{"pl":"Podobno przetapiasz tutaj część wydobytej rudy.","en":"I hear you only melt down part of the ore.","de":"Ich habe gehört, ihr schmelzt nur einen Teil des Erzes ein."}},{"speaker":"npc","text":{"pl":"Kiedyś przetapialiśmy tutaj cały urobek. Ale Gomezowi i Magom nie bardzo się to podobało.","en":"Some time ago we used to melt the lot down. But Gomez and the mages were none too happy about that.","de":"Früher haben wir alles Erz eingeschmolzen. Aber damit waren Gomez und die Magier nicht einverstanden."}},{"speaker":"npc","text":{"pl":"Siedzieli tu tygodniami, badając rudę i wszystko dookoła.","en":"They hung around here for weeks to examine the ore and everything else.","de":"Wochenlang haben sie sich hier rumgetrieben und haben das Erz und alles andere untersucht."}},{"speaker":"npc","text":{"pl":"Węszyli wszędzie i wtykali swoje szlachetne nochale w rzeczy, o których nie mieli pojęcia.","en":"They fiddled about and stuck their noble noses in things they didn''t have a clue about.","de":"Sie haben hier rumgeschnüffelt und ihre feinen Nasen in Sachen gesteckt, von denen sie keine Ahnung haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_favour_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_favour_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_Favour_Info","outputIds":["DIA_Whistler_Favour_15_00","DIA_Whistler_Favour_11_01","DIA_Whistler_Favour_11_02","DIA_Whistler_Favour_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Co mam dla ciebie zrobić?","en":"What kind of favor do you want?","de":"Was ist das für ein Gefallen, den du von mir erwartest?"}},{"speaker":"npc","text":{"pl":"Chcę jedną z broni, którą ma na składzie Fisk. To jeden z handlarzy na targowisku.","en":"I want one of Fisk''s weapons. He''s one of the traders at the market place.","de":"Ich will eine Waffe von Fisk haben. Er ist einer der Händler am Marktplatz."}},{"speaker":"npc","text":{"pl":"Ale on nie chce mi jej sprzedać. To pewien szczególnie pięknie zdobiony miecz.","en":"He won''t sell it to me. It''s a broadsword with ornaments.","de":"Er will sie mir nicht mehr verkaufen. Es ist ein Breitschwert mit Ornamenten."}},{"speaker":"npc","text":{"pl":"Dam ci 100 bryłek rudy, za które kupisz dla mnie ten miecz. Tylko nie mów mu, że ja cię przysłałem.","en":"I''ll give you 100 ore to collect the weapon for me. But don''t tell him about me.","de":"Ich gebe dir 100 Erz und du holst die Waffe für mich ab. Aber sag ihm nichts von mir, klar?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_favour_ok_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_favour_ok_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_Favour_Ok","outputIds":["DIA_Whistler_Favour_Ok_15_00","DIA_Whistler_Favour_Ok_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Dobrze. Daj mi 100 bryłek, a ja się wszystkim zajmę.","en":"Okay, give me the 100 ore nuggets. I''ll get the thing.","de":"Okay, her mit den 100 Erzbrocken. Ich hol'' das Ding."}},{"speaker":"npc","text":{"pl":"Masz. Tylko nie marudź za długo!","en":"Here you go. Come straight back to me!","de":"Hier hast du sie. Kommt direkt zu mir zurück!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_favour_ore_away_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_favour_ore_away_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_Favour_OreAway","outputIds":["DIA_Whistler_Favour_OreAway_15_00","DIA_Whistler_Favour_OreAway_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Przyszło ci do głowy, że mógłbym po prostu uciec z twoją rudą?","en":"Did you ever consider that I might just run off with the ore...?","de":"Hast du mal daran gedacht, dass ich einfach mit dem Erz durchbrennen könnte ...?"}},{"speaker":"npc","text":{"pl":"Nie zapominaj, że to jest niewielka kolonia. Prędzej czy później bym cię znalazł!","en":"Don''t forget: The colony is small! If you run off with my ore, I''ll find you!","de":"Vergiss nicht: Die Kolonie ist klein! Wenn du mit dem Erz durchbrennst, finde ich dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_iam_new_11_04_4', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_iam_new_11_04_4","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_IAmNew_Info","outputIds":["DIA_Whistler_IAmNew_11_04"],"lines":[{"speaker":"npc","text":{"pl":"Jeśli chcesz, żebym zarekomendował cię u Diego, musisz coś dla mnie zrobić.","en":"If you want me to have a word with Diego about you, you need to do me a favor.","de":"Wenn ich ein gutes Wort bei Diego für dich einlegen soll, schuldest du mir einen Gefallen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_iam_new_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_iam_new_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_IAmNew_Info","outputIds":["DIA_Whistler_IAmNew_15_00","DIA_Whistler_IAmNew_11_01","DIA_Whistler_IAmNew_15_02","DIA_Whistler_IAmNew_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Jestem tu nowy!","en":"Hi! I''m new here!","de":"Hi! Ich bin neu hier!"}},{"speaker":"npc","text":{"pl":"Czego chcesz?","en":"What do you want from me?","de":"Was willst du von mir?"}},{"speaker":"hero","text":{"pl":"Chciałbym zostać jednym z was - chcę zostać członkiem Obozu.","en":"I want to become one of you - I want to join the Camp.","de":"Ich will einer von euch werden - ich will mich dem Lager anschließen."}},{"speaker":"npc","text":{"pl":"Szukasz ludzi, którzy cię poprą, co?","en":"Looking for people to support you, eh?","de":"Auf der Suche nach Fürsprechern, was?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_my_sword_success_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_my_sword_success_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_MySword_Success_Info","outputIds":["DIA_Whistler_MySword_Success_15_00","DIA_Whistler_MySword_Success_11_01","DIA_Whistler_MySword_Success_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Mam dla ciebie miecz...","en":"I have your sword...","de":"Ich hab'' dein Schwert ..."}},{"speaker":"npc","text":{"pl":"To nie było zbyt trudne. Tak, czy inaczej - wyświadczyłeś mi przysługę, teraz ja wyświadczę przysługę tobie.","en":"Wasn''t too hard, was it. Whatever - you do me a favor and I''ll do you one.","de":"War ja auch nicht wirklich schwierig. Wie auch immer - eine Hand wäscht die andere."}},{"speaker":"npc","text":{"pl":"Jeśli Diego zapyta mnie o ciebie, opowiem się za tobą. Póki co - trzymaj się!","en":"If Diego should ask after you, I''ll speak in your favor. Until then - have a good time!","de":"Falls Diego mich nach dir fragt, ist dir meine Stimme sicher. Bis dahin - mach''s gut!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_my_sword_too_late_11_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_my_sword_too_late_11_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_MySword_TooLate_Info","outputIds":["DIA_Whistler_MySword_TooLate_11_00"],"lines":[{"speaker":"npc","text":{"pl":"Tu jesteś! Próbowałeś zwiać z moją rudą, co? Chodź no tu, chłopcze!","en":"Here you are! Wanted to run off with my ore, eh? Come here, sonny!","de":"Da bist du ja! Wolltest mit meinen Erz durchbrennen, was? Komm her, Bürschchen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_running_pay_back_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_running_pay_back_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_RunningPayBack_Info","outputIds":["DIA_Whistler_RunningPayBack_15_00","DIA_Whistler_RunningPayBack_11_01","DIA_Whistler_RunningPayBack_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie mogę zdobyć tego miecza. Zwracam ci twoją rudę.","en":"I can''t get the sword - here''s your 100 ore back.","de":"Ich kriege das Schwert nicht - hier hast du deine 100 Erz zurück."}},{"speaker":"npc","text":{"pl":"Ty idioto! Nie potrzebujemy tu takich jak ty! Zejdź mi z oczu!","en":"You idiot! We don''t need idiots like you here! Get lost!","de":"Du Idiot! So ''ne Flasche wie dich können wir hier nicht gebrauchen! Zieh Leine!"}},{"speaker":"npc","text":{"pl":"Ale ja tu nie widzę żadnych 100 bryłek. Radzę ci, żeby szybko się znalazły, bo inaczej...","en":"I don''t see any 100 ore though - you''d better get them as fast as you can, else you''ll be in trouble!","de":"Ich sehe aber keine 100 Erz - du besorgst sie am besten, so schnell du kannst, sonst gibt''s Ärger!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_running110_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_running110_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_Running110_Info","outputIds":["DIA_Whistler_Running110_15_00","DIA_Whistler_Running110_11_01","DIA_Whistler_Running110_15_02","DIA_Whistler_Running110_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Fisk żąda teraz 110 bryłek rudy za ten miecz.","en":"Fisk wants 110 ore for his sword now.","de":"Fisk will jetzt 110 Erz für dein Schwert."}},{"speaker":"npc","text":{"pl":"I pewnie mam ci teraz dać dodatkowe 10 bryłek...","en":"And you want me to give you the 10 ore now...","de":"Und ich soll dir jetzt noch 10 Erz geben ..."}},{"speaker":"hero","text":{"pl":"Myślałem, że zależy ci na tym mieczu.","en":"I thought you wanted to have that sword.","de":"Ich dachte, du legst Wert auf dein Schwert."}},{"speaker":"npc","text":{"pl":"Masz. Tylko się pospiesz!","en":"Here, take it, and now hurry!","de":"Hier, nimm, und jetzt beeil dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_309_whistler_dia_whistler_standard_kap1_15_00_0', 'STT_309_Whistler', '{"id":"missions_dia_stt_309_whistler_dia_whistler_standard_kap1_15_00_0","npcId":"STT_309_Whistler","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_309_Whistler.d","sourceFunction":"DIA_Whistler_StandardKap1_Info","outputIds":["DIA_Whistler_StandardKap1_15_00","DIA_Whistler_StandardKap1_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Jak leci...","en":"How''s it going...","de":"Wie sieht''s aus ..."}},{"speaker":"npc","text":{"pl":"Świetnie! Wyświadczyłeś mi przysługę, teraz ja wyświadczę przysługę tobie. Powiem Diego, że można na tobie polegać.","en":"Good! You''ve done me a favor, I''ll do you one. I''ll tell Diego that you''re a reliable man.","de":"Gut! Du hast mir einen Gefallen getan, ich tue dir einen. Ich werd Diego erzählen, dass du ein zuverlässiger Mann bist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_forget_sword_15_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_forget_sword_15_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_ForgetSword_Info","outputIds":["Stt_311_Fisk_ForgetSword_15_00","Stt_311_Fisk_ForgetSword_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Porozmawiajmy jeszcze o mieczu Świstaka.","en":"Let''s talk about Whistler''s sword again.","de":"Lass uns noch mal über Whistlers Schwert reden."}},{"speaker":"npc","text":{"pl":"Powiedz mu, że nigdy nie dostanie tej broni.","en":"You can tell him that he''ll never get his sword.","de":"Du kannst ihm sagen, er wird sein Schwert nie kriegen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_hehler_success_12_04_4', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_hehler_success_12_04_4","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_HehlerSuccess_Info","outputIds":["Stt_311_Fisk_HehlerSuccess_12_04","Stt_311_Fisk_HehlerSuccess_12_05"],"lines":[{"speaker":"npc","text":{"pl":"Sharky? Jest jeszcze gorszy niż Mordrag!","en":"Sharky? He''s even worse than Mordrag.","de":"Sharky?  Der ist ja noch schlimmer, als Mordrag jemals hätte sein können."}},{"speaker":"npc","text":{"pl":"Jeśli chodzi o Diego... Nie musisz się już o niego martwić.","en":"About Diego... you don''t need to worry any more.","de":"Was Diego betrifft, brauchst du dir keine Sorgen mehr zu machen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_hehler_success_15_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_hehler_success_15_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_HehlerSuccess_Info","outputIds":["Stt_311_Fisk_HehlerSuccess_15_00","Stt_311_Fisk_HehlerSuccess_12_01","Stt_311_Fisk_HehlerSuccess_12_02","Stt_311_Fisk_HehlerSuccess_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem kogoś z Nowego Obozu, kto chciałby nawiązać z tobą współpracę.","en":"I have somebody from the New Camp who wants to get into business with you.","de":"Ich habe jemanden aus dem Neuen Lager, der mit dir handeln will."}},{"speaker":"npc","text":{"pl":"No nie! Kto by pomyślał. Widzę, że bardzo ci zależy na popularności w naszym Obozie...","en":"No! Who would''ve thought that. Looks like you''re trying to get popular around here...","de":"Nein! Wer hätte das gedacht. Du scheinst dich hier ja richtig beliebt machen zu wollen ..."}},{"speaker":"npc","text":{"pl":"No i udało ci się! Kogo mi tu przyprowadziłeś?","en":"Seems like you managed it, too! Who is it?","de":"Das ist dir auch gelungen! Wer ist es?"}},{"speaker":"hero","text":{"pl":"Nazywa się Sharky.","en":"His name is Sharky.","de":"Sein Name ist Sharky."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_mordrag_ko_12_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_mordrag_ko_12_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_MordragKO_Info","outputIds":["Stt_311_Fisk_MordragKO_12_00","Stt_311_Fisk_MordragKO_12_01","Stt_311_Fisk_MordragKO_12_02"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty!","en":"Hey, you!","de":"Hey, du!"}},{"speaker":"npc","text":{"pl":"Mordrag był jednym z moich najlepszych dostawców, ty głupcze!","en":"Mordrag was one of my most important suppliers, you idiot!","de":"Mordrag war einer meiner wichtigsten Lieferanten, du Schwachkopf!"}},{"speaker":"npc","text":{"pl":"Jeśli chcesz zostać członkiem tego obozu, na mój głos nie masz co liczyć!","en":"If you want to join this camp it''ll be very hard for you to get MY vote!","de":"Wenn du hier im Lager aufgenommen werden willst, kriegst du MEINE Stimme jedenfalls nicht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_mordrag_ko_petze_15_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_mordrag_ko_petze_15_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_MordragKO_Petze","outputIds":["Stt_311_Fisk_MordragKO_Petze_15_00","Stt_311_Fisk_MordragKO_Petze_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Handlujesz przedmiotami, które należały do Magnatów. Założę się, że Thorus chętnie się o tym dowie.","en":"You''re trading things which belong to the Ore Barons. Thorus will be interested in that...","de":"Du handelst mit Ware, die den Erzbaronen gehört. Das wird Thorus sicher interessieren ..."}},{"speaker":"npc","text":{"pl":"Nawet nie próbuj, kolego!","en":"Don''t try it on, pal!","de":"So nicht, Junge!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_mordrag_ko_relax_15_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_mordrag_ko_relax_15_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_MordragKO_Relax","outputIds":["Stt_311_Fisk_MordragKO_Relax_15_00","Stt_311_Fisk_MordragKO_Relax_12_01","Stt_311_Fisk_MordragKO_Relax_15_02","Stt_311_Fisk_MordragKO_Relax_12_03"],"lines":[{"speaker":"hero","text":{"pl":"Uspokój się! Może mogę ci to jakoś wynagrodzić?","en":"Relax! Maybe I can make up for it, can''t I?","de":"Entspann dich! Die Sache lässt sich sicher wieder geradebiegen, oder?"}},{"speaker":"npc","text":{"pl":"Wątpię, żeby ci się udało. No chyba, że znajdziesz dla mnie nowy kontakt w Nowym Obozie!","en":"I wouldn''t know how you''re gonna do that. Unless you get me a new fence from the New Camp!","de":"Ich wüsste nicht, wie du das wieder gutmachen kannst. Es sei denn, du schaffst mir einen neuen Hehler aus dem Neuen Lager ran!"}},{"speaker":"hero","text":{"pl":"Jak ja ci znajdę kogoś takiego?","en":"How am I supposed to find somebody like that?","de":"Wie soll ich so jemanden finden?"}},{"speaker":"npc","text":{"pl":"Przecież mówiłem, że nie wydaje mi się, żeby udało ci się tego dokonać.","en":"I just told you, I don''t believe that you''ll ever be on good terms with me.","de":"Ich sagte ja, ich glaube kaum, dass du bei mir noch mal gute Karten hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_whistlers_sword_15_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_whistlers_sword_15_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_WhistlersSword_Info","outputIds":["Stt_311_Fisk_WhistlersSword_15_00","Stt_311_Fisk_WhistlersSword_12_01","Stt_311_Fisk_WhistlersSword_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym kupić miecz. Ale nie taki zwykły. Chciałbym coś... bogato zdobionego.","en":"I''d like to buy a sword. But not just a simple one. I''d like something more ornamental.","de":"Ich will ein Schwert kaufen. Aber nicht so ein einfaches Ding. Was mit Ornamenten wär schön."}},{"speaker":"npc","text":{"pl":"Mam tu coś w sam raz dla ciebie. Cień, który miał to odebrać więcej się tu nie pokaże.","en":"I have one you''ll like. The Shadow who wanted to collect it won''t be coming any more.","de":"Ich hab'' da eins, das dir gefallen könnte. Der Schatten, der es abholen sollte, kommt nicht mehr ."}},{"speaker":"npc","text":{"pl":"Kosztuje jedyne 110 bryłek rudy. Zainteresowany?","en":"That''ll be 110 ore. Interested?","de":"Kostet 110 Erz. Interessiert?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_whistlers_sword_fault_15_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_whistlers_sword_fault_15_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_WhistlersSword_Fault","outputIds":["Stt_311_Fisk_WhistlersSword_Fault_15_00","Stt_311_Fisk_WhistlersSword_Fault_12_01","Stt_311_Fisk_WhistlersSword_Fault_15_02","Stt_311_Fisk_WhistlersSword_Fault_12_03"],"lines":[{"speaker":"hero","text":{"pl":"Przecież Świstakowi chciałeś go sprzedać za 100!","en":"You wanted to sell it to Whistler for a hundred...","de":"Whistler wolltest du es für hundert verkaufen..."}},{"speaker":"npc","text":{"pl":"Ach! Chwileczkę... Racja! Mało brakowało, a sprzedałbym ci do zbyt tanio. Naturalnie miałem na myśli 500 bryłek.","en":"Ah! Just wait... that''s right, I nearly charged you too little! Of course I meant 500.","de":"Ah! Warte mal ... Stimmt, da hätte ich dir ja fast zu wenig abgeknöpft! Ich meinte natürlich fünfhundert."}},{"speaker":"hero","text":{"pl":"Pięćset?!","en":"Five hundred?","de":"Fünfhundert?"}},{"speaker":"npc","text":{"pl":"Za mało? Może wolisz 1000? Też dobrze. Chociaż wiesz co? Ten miecz nie jest jednak na sprzedaż.","en":"Too little? You prefer 1000? Fine by me. Well, now that I think about it - I''d rather keep it!","de":"Zu wenig? Tausend sind dir lieber? Auch gut. Ach, wenn ich''s mir so recht überlege - ich glaube, ich behalte es einfach!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_311_fisk_stt_311_fisk_whistlers_sword_take_it_15_00_0', 'STT_311_Fisk', '{"id":"missions_dia_stt_311_fisk_stt_311_fisk_whistlers_sword_take_it_15_00_0","npcId":"STT_311_Fisk","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_311_Fisk.d","sourceFunction":"Stt_311_Fisk_WhistlersSword_TakeIt","outputIds":["Stt_311_Fisk_WhistlersSword_TakeIt_15_00","Stt_311_Fisk_WhistlersSword_TakeIt_12_01","Stt_311_Fisk_WhistlersSword_TakeIt_12_02"],"lines":[{"speaker":"hero","text":{"pl":"Dobrze, wezmę go.","en":"Yes, I''ll take it.","de":"Ja, ich nehme es."}},{"speaker":"npc","text":{"pl":"Trafiła ci się nie lada okazja.","en":"You got a good deal here!","de":"Du hast ein gutes Geschäft gemacht!"}},{"speaker":"npc","text":{"pl":"Obawiam się, że masz za mało rudy. Zachowam ten miecz dla ciebie, ale lepiej się pospiesz!","en":"I fear you don''t have enough ore. I''ll hold the sword back for some time, but don''t wait too long!","de":"Ich fürchte, du hast nicht genug Erz. Ich werde das Schwert noch ''ne Weile für dich zurückhalten, aber nimm dir nicht zu viel Zeit!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_315_sly_dia_stt_315_lost_nek_15_00_0', 'STT_315_Sly', '{"id":"missions_dia_stt_315_sly_dia_stt_315_lost_nek_15_00_0","npcId":"STT_315_Sly","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_315_Sly.d","sourceFunction":"DIA_STT_315_LostNek_Info","outputIds":["DIA_STT_315_LostNek_15_00","DIA_STT_315_LostNek_10_01","DIA_STT_315_LostNek_10_02","DIA_STT_315_LostNek_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Masz dla mnie robotę? O co chodzi?","en":"You have a job for me? What is it?","de":"Du hast was zu tun für mich? Um was geht''s?"}},{"speaker":"npc","text":{"pl":"Zniknął gdzieś jeden z naszych strażników. Nazywa się Nek. Możliwe, że dał nogę do Nowego Obozu.","en":"One of our guards has disappeared! He''s called Nek. He might have gone over to the New Camp.","de":"Einer unserer Gardisten ist verschwunden! Er heißt Nek. Er könnte ins Neue Lager übergelaufen sein."}},{"speaker":"npc","text":{"pl":"Jesteś tu nowy i zaglądasz w każdy kąt. Po prostu miej oczy szeroko otwarte.","en":"You''re new here and you''ll get around quite a lot. So keep your eyes peeled.","de":"Du bist neu hier und kommst viel rum. Also halt die Augen offen."}},{"speaker":"npc","text":{"pl":"Jeśli uda ci się go znaleźć, będziesz mógł liczyć na moje poparcie.","en":"If you find him, I''ll speak up for you in the Camp.","de":"Wenn du ihn findest, leg'' ich ein gutes Wort für dich hier im Lager ein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_315_sly_dia_stt_315_lost_nek_do_it_15_00_0', 'STT_315_Sly', '{"id":"missions_dia_stt_315_sly_dia_stt_315_lost_nek_do_it_15_00_0","npcId":"STT_315_Sly","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_315_Sly.d","sourceFunction":"DIA_STT_315_LostNek_DoIt","outputIds":["DIA_STT_315_LostNek_DoIt_15_00","DIA_STT_315_LostNek_DoIt_10_01","DIA_STT_315_LostNek_DoIt_15_02","DIA_STT_315_LostNek_DoIt_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Postaram się go odnaleźć.","en":"I''ll see if I can find him.","de":"Ich werd sehen, ob ich ihn finde."}},{"speaker":"npc","text":{"pl":"Jakbyś spotkał Fletchera, możesz go zapytać o Neka. Fletcher przejął jego rewir po tym całym tajemniczym zniknięciu.","en":"If you meet Fletcher, ask him about Nek. He''s taken over his distric'' since Nek disappeared.","de":"Wenn du Fletcher triffst, frag ihn über Nek. Er hat sein Viertel übernommen, seit Nek verschwunden ist."}},{"speaker":"hero","text":{"pl":"Gdzie znajdę Fletchera?","en":"Where will I find him?","de":"Wo finde ich ihn?"}},{"speaker":"npc","text":{"pl":"Zwykle patroluje teren wokół areny.","en":"His district is the district of the arena.","de":"Sein Viertel ist das Arenaviertel."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_315_sly_dia_stt_315_lost_nek_success_15_00_0', 'STT_315_Sly', '{"id":"missions_dia_stt_315_sly_dia_stt_315_lost_nek_success_15_00_0","npcId":"STT_315_Sly","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_315_Sly.d","sourceFunction":"DIA_STT_315_LostNekSuccess_Info","outputIds":["DIA_STT_315_LostNekSuccess_15_00","DIA_STT_315_LostNekSuccess_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem Neka.","en":"I''ve found Nek.","de":"Ich hab'' Nek gefunden."}},{"speaker":"npc","text":{"pl":"To świetnie! A masz na to jakieś dowody?","en":"Good! Have you got any evidence for that?","de":"Gut! Hast du dafür Beweise?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_315_sly_dia_stt_315_lost_nek_success_no_proof_15_00_0', 'STT_315_Sly', '{"id":"missions_dia_stt_315_sly_dia_stt_315_lost_nek_success_no_proof_15_00_0","npcId":"STT_315_Sly","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_315_Sly.d","sourceFunction":"DIA_STT_315_LostNekSuccess_NoProof","outputIds":["DIA_STT_315_LostNekSuccess_NoProof_15_00","DIA_STT_315_LostNekSuccess_NoProof_10_01","DIA_STT_315_LostNekSuccess_NoProof_10_02","DIA_STT_315_LostNekSuccess_NoProof_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Nie, obawiam się, że nie.","en":"No - I''m afraid not.","de":"Nein - ich befürchte nicht."}},{"speaker":"npc","text":{"pl":"Serio? Chyba nic przede mną nie ukrywasz, co? Nek miał przy sobie taki dziwny amulet.","en":"Oh? You''re not hiding anything from me, are you? Nek had an amulet on him.","de":"So? Du willst mir doch nicht etwas vorenthalten? Nek hat ein Schutzamulett bei sich."}},{"speaker":"npc","text":{"pl":"Nie lubię jak ktoś ukrywa przede mną rzeczy, które należą do mnie. Jakbyś znalazł ten amulet, przynieś go mi!","en":"I don''t like people keeping things from me that are mine. If you find the amulet, bring it to me!","de":"Ich mag nicht, wenn man mir etwas vorenthält, was mir gehört. Solltest du das Amulett finden, bring es mir!"}},{"speaker":"hero","text":{"pl":"Postaram się o tym pamiętać, kiedy już znajdę ten amulet.","en":"I''ll think of you when I hold the amulet in my hand.","de":"Ich werd an dich denken, wenn ich das Amulett in der Hand halte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_315_sly_dia_stt_315_lost_nek_success_proof_15_00_0', 'STT_315_Sly', '{"id":"missions_dia_stt_315_sly_dia_stt_315_lost_nek_success_proof_15_00_0","npcId":"STT_315_Sly","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_315_Sly.d","sourceFunction":"DIA_STT_315_LostNekSuccess_Proof","outputIds":["DIA_STT_315_LostNekSuccess_Proof_15_00","DIA_STT_315_LostNekSuccess_Proof_10_01","DIA_STT_315_LostNekSuccess_Proof_10_02","DIA_STT_315_LostNekSuccess_Proof_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem przy nim ten amulet. Proszę, oto on.","en":"I''ve found this amulet on him - here you go.","de":"Ich hab'' ein Amulett bei ihm gefunden - hier."}},{"speaker":"npc","text":{"pl":"Właśnie o ten amulet mi chodziło. Mądry z ciebie chłopak.","en":"It was actually the amulet the whole thing was about. You''re a clever guy.","de":"Genau um dieses Amulett ging es mir. Du bist ein schlauer Junge."}},{"speaker":"npc","text":{"pl":"Założę się, że kusiło cię, żeby zachować ten amulet dla siebie, co? Spokojnie, dokonałeś mądrego wyboru.","en":"You might have had the idea to keep the amulet yourself, but you''ve made the right decision.","de":"Du hättest auf die Idee kommen können, das Amulett zu behalten, aber du hast die richtige Entscheidung getroffen."}},{"speaker":"npc","text":{"pl":"Jakby Diego pytał o ciebie, opowiem się za tobą.","en":"If Diego asks me about you, I''ll vote in your favor.","de":"Wenn Diego mich nach dir fragt, werd'' ich dir meine Stimme geben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_315_sly_dia_stt_315_lost_nek_why_15_00_0', 'STT_315_Sly', '{"id":"missions_dia_stt_315_sly_dia_stt_315_lost_nek_why_15_00_0","npcId":"STT_315_Sly","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_315_Sly.d","sourceFunction":"DIA_STT_315_LostNek_Why","outputIds":["DIA_STT_315_LostNek_Why_15_00","DIA_STT_315_LostNek_Why_10_01","DIA_STT_315_LostNek_Why_10_02"],"lines":[{"speaker":"hero","text":{"pl":"A co mi przyjdzie z twojego poparcia?","en":"What good will your speaking up for me do?","de":"Was kann ein gutes Wort von dir bewirken?"}},{"speaker":"npc","text":{"pl":"Jeśli chcesz dołączyć do naszego obozu, musisz zjednać sobie poparcie kilku wpływowych ludzi.","en":"If you wannna join the Camp, you need people to speak up for you.","de":"Wenn du hier im Lager aufgenommen werden willst, brauchst du Leute, die für dich sprechen."}},{"speaker":"npc","text":{"pl":"Gdybym szepnął o tobie dobre słowo, Diego spojrzałby na ciebie o wiele przychylniej.","en":"If I speak up for you with Diego, that''d be a great help for you.","de":"Ein gutes Wort von mir über dich bei Diego kann da schon einiges helfen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_315_sly_dia_stt_315_sly_after_success_15_00_0', 'STT_315_Sly', '{"id":"missions_dia_stt_315_sly_dia_stt_315_sly_after_success_15_00_0","npcId":"STT_315_Sly","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_315_Sly.d","sourceFunction":"DIA_STT_315_Sly_AfterSuccess_Info","outputIds":["DIA_STT_315_Sly_AfterSuccess_15_00","DIA_STT_315_Sly_AfterSuccess_10_01","DIA_STT_315_Sly_AfterSuccess_15_02","DIA_STT_315_Sly_AfterSuccess_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak leci?","en":"How''s it going?","de":"Wie läuft''s denn so?"}},{"speaker":"npc","text":{"pl":"Świetnie! Jeśli o mnie chodzi - Diego usłyszy, że równy z ciebie gość!","en":"Good! With me you don''t need to worry about Diego any more!","de":"Gut! Bei mir brauchst du dir wegen Diego keine Sorgen mehr zu machen!"}},{"speaker":"hero","text":{"pl":"Ręka rękę myje, co?","en":"You scratch my back, I''ll scratch yours, eh?","de":"Eine Hand wäscht die andere, denke ich."}},{"speaker":"npc","text":{"pl":"Dokładnie.","en":"That''s the way it is.","de":"So ist es."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_iam_new_10_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_iam_new_10_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_First_Info","outputIds":["DIA_Dexter_IAmNew_10_00"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty! Sprzedaję bagienne ziele i różne wywary z obozu na bagnach. Może czegoś potrzebujesz?","en":"Hey, you! I trade in swampweed and potions from the Sect Camp. Do you want something?","de":"Hey, du! Ich handele mit Sumpfkraut und Tränken aus dem Sektenlager. Willst du was?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_10_04_4', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_10_04_4","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_Info","outputIds":["DIA_Dexter_JoinOC_10_04","DIA_Dexter_JoinOC_10_05","DIA_Dexter_JoinOC_10_06","DIA_Dexter_JoinOC_10_07"],"lines":[{"speaker":"npc","text":{"pl":"W obozie Sekty mieszka mężczyzna imieniem Kalom. To wielka szycha - jeden z Guru całej tej pomylonej zgrai.","en":"In the Sect Camp there''s a man called Kalom. Quite a big shot - one of the Gurus of the sect.","de":"Im Sektenlager gibt es einen Mann, der Kalom heißt. Ist ein ziemlich hohes Tier - einer der Gurus der Sekte."}},{"speaker":"npc","text":{"pl":"Kalom jest alchemikiem. Posiada przepis na niezwykle skuteczny napój uzdrawiający.","en":"Kalom is an alchemist. He has the recipe for an effective healing potion.","de":"Kalom ist Alchimist. Er hat das Rezept für einen ziemlich wirkungsvollen Heiltrank."}},{"speaker":"npc","text":{"pl":"Chciałbym go od niego odkupić, wtedy sam mógłbym zacząć produkcję tego napoju.","en":"I''d like to buy the recipe off him, then I can produce it myself.","de":"Ich will ihm das Rezept abkaufen, dann kann ich die Dinger selber herstellen."}},{"speaker":"npc","text":{"pl":"Ale do Kaloma trudno się zbliżyć, zwłaszcza ludziom z zewnątrz.","en":"But nobody can get near Kalom.","de":"Aber an Kalom kommt niemand ran."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_Info","outputIds":["DIA_Dexter_JoinOC_15_00","DIA_Dexter_JoinOC_10_01","DIA_Dexter_JoinOC_10_02","DIA_Dexter_JoinOC_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym dołączyć do Obozu. Chcę zostać Cieniem.","en":"I want to join the Camp - I want to become a Shadow.","de":"Ich will mich dem Lager anschließen - ich will Schatten werden."}},{"speaker":"npc","text":{"pl":"O, i szukasz pewnie okazji, żeby pokazać, na co cię stać, tak?","en":"Oh? You''re looking for a chance to prove your worth?","de":"So? Du suchst eine Möglichkeit, dich zu bewähren?"}},{"speaker":"npc","text":{"pl":"Dobra - możesz wyświadczyć mi pewną przysługę. Jeśli dobrze się spiszesz, wstawię się za tobą u Diego.","en":"Good - you can do me a favor. If you do it well, I''ll speak up for you in front of Diego.","de":"Gut - du kannst etwas für mich erledigen. Wenn du die Sache gut machst, leg'' ich ein gutes Wort bei Diego für dich ein."}},{"speaker":"hero","text":{"pl":"O co chodzi?","en":"What is it?","de":"Um was geht es?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_15_08_8', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_15_08_8","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_Info","outputIds":["DIA_Dexter_JoinOC_15_08","DIA_Dexter_JoinOC_10_09","DIA_Dexter_JoinOC_10_10","DIA_Dexter_JoinOC_10_11"],"lines":[{"speaker":"hero","text":{"pl":"A czego oczekujesz ode mnie?","en":"And what do you expect me to do?","de":"Und was soll ich da machen?"}},{"speaker":"npc","text":{"pl":"Te świry z sekty bez przerwy szukają nowych ludzi. Jesteś tu nowy, nikt cię nie zna. Udawaj, że chcesz do nich dołączyć.","en":"The sect loonies are looking for new people all the time. You''re new here. Just pretend you want to be recruited.","de":"Die Sektenspinner sind dauernd auf der Suche nach neuen Leuten. Du bist neu hier. Tu einfach so, als wenn du dich anwerben lassen willst."}},{"speaker":"npc","text":{"pl":"Kalom jest jednym z Guru, więc to on sprawdza nowych kandydatów. Jeśli uda ci się z nim spotkać, spróbuj zdobyć dla mnie tę recepturę.","en":"Kalom is one of the Gurus, that means he checks the new candidates. If you get in touch with him, try to get the recipe.","de":"Kalom ist einer der Gurus, das heißt, er prüft die neuen Anwärter. Wenn du mit ihm in Kontakt kommst. versuch, an das Rezept zu kommen."}},{"speaker":"npc","text":{"pl":"Czy za nią zapłacisz, czy nie - to już nie moja sprawa.","en":"Whether you want to pay for it or you don''t, I don''t care.","de":"Ob du dafür bezahlst oder nicht, ist mir egal."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_advance_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_advance_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_Advance","outputIds":["DIA_Dexter_JoinOC_Advance_15_00","DIA_Dexter_JoinOC_Advance_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Może będę mu musiał zapłacić za tę recepturę. Potrzebuję 50 bryłek rudy jako zaliczkę.","en":"Maybe I''ll have to pay for the recipe - give me 50 ore as an advance payment.","de":"Es kann sein, dass ich für das Rezept bezahlen muss - gib mir 50 Erz als Vorschuss."}},{"speaker":"npc","text":{"pl":"Nie ma mowy.","en":"Forget it.","de":"Vergiss es."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_forget_it_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_forget_it_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_ForgetIt","outputIds":["DIA_Dexter_JoinOC_ForgetIt_15_00","DIA_Dexter_JoinOC_ForgetIt_10_01","DIA_Dexter_JoinOC_ForgetIt_15_02","DIA_Dexter_JoinOC_ForgetIt_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Świetnie! Zapomnijmy o całej sprawie.","en":"Okay! Let''s just forget about the whole thing.","de":"Gut! Vergessen wir die Sache."}},{"speaker":"npc","text":{"pl":"Zaraz, powoli! Chciałem tylko zobaczyć, jak daleko się posuniesz... 50 bryłek to trochę dużo jak na żółtodzioba, nie sądzisz?","en":"Not so fast! I just wanted to know how far you''d go... 50 ore is quite a lot for a newcomer, don''t you think?","de":"Nicht so schnell! Wollte nur wissen, wie weit du gehst ... 50 Erz ist ziemlich viel für einen Neuen, was denkst du?"}},{"speaker":"hero","text":{"pl":"To już lepiej...","en":"That sounds better.","de":"Klingt schon besser."}},{"speaker":"npc","text":{"pl":"A niech cię szlag! Masz tu swoje 50 bryłek! Tylko nie próbuj mnie wykiwać, mały!","en":"Okay, okay, I''ve just got 50 ore nuggets spare here. Don''t let me down, kid!","de":"Gut, gut, 50 Erzbrocken kann ich gerade noch entbehren. Enttäusch mich nicht, Kleiner!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_how_much_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_how_much_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_HowMuch","outputIds":["DIA_Dexter_JoinOC_HowMuch_15_00","DIA_Dexter_JoinOC_HowMuch_10_01"],"lines":[{"speaker":"hero","text":{"pl":"To nie będzie łatwe. Co będę z tego miał?","en":"Sounds like a difficult business - how much is in it for me?","de":"Hört sich nach ''ner schwierigen Sache an - wie viel ist für mich drin?"}},{"speaker":"npc","text":{"pl":"Prędzej czy później Diego zapyta mnie co o tobie sądzę. Zgadnij od czego będzie zależała moja odpowiedź.","en":"At some point Diego will ask me if you''re suitable for us. Just guess what my answer will depend on.","de":"Irgendwann wird Diego mich fragen, ob du für uns geeignet bist. Rate mal, wovon meine Antwort abhängen wird."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_ore_now_or_else_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_ore_now_or_else_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_OreNowOrElse","outputIds":["DIA_Dexter_JoinOC_OreNowOrElse_15_00","DIA_Dexter_JoinOC_OreNowOrElse_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie! Albo zapłacisz mi z góry, albo sam sobie idź do obozu na bagnie.","en":"No! I want to see ore right now or you can get your recipe yourself.","de":"Nein! Ich will jetzt Erz sehen, oder du kannst dir dein Rezept selber holen."}},{"speaker":"npc","text":{"pl":"Jest tu wielu żółtodziobów. Chyba jednak zlecę to zadanie komuś innemu...","en":"There''s enough other newcomers, I think I should give the job to one of them...","de":"Es gibt noch genug andere Neue, ich denke, ich sollte den Auftrag einem von denen geben ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_join_oc_threat_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_join_oc_threat_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_JoinOC_Threat","outputIds":["DIA_Dexter_JoinOC_Threat_15_00","DIA_Dexter_JoinOC_Threat_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie ma rudy - nie ma receptury!","en":"No ore - no recipe!","de":"Kein Erz - kein Rezept!"}},{"speaker":"npc","text":{"pl":"No dobra, ale o rudzie porozmawiamy jak będziesz miał recepturę w ręku.","en":"Well then! We can talk about the ore as soon as you have the recipe.","de":"Na schön! Über das Erz können wir reden, wenn du das Rezept hast."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_kaloms_recipe_success_10_04_4', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_kaloms_recipe_success_10_04_4","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_KalomsRecipeSuccess_Info","outputIds":["DIA_Dexter_KalomsRecipeSuccess_10_04"],"lines":[{"speaker":"npc","text":{"pl":"Weź to. To w nagrodę...","en":"Here you go - take that - for your efforts...","de":"Hier - nimm das - für deine Mühen..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_kaloms_recipe_success_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_kaloms_recipe_success_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_KalomsRecipeSuccess_Info","outputIds":["DIA_Dexter_KalomsRecipeSuccess_15_00","DIA_Dexter_KalomsRecipeSuccess_10_01","DIA_Dexter_KalomsRecipeSuccess_10_02","DIA_Dexter_KalomsRecipeSuccess_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Mam dla ciebie recepturę, o którą prosiłeś!","en":"I have the recipe you wanted!","de":"Ich hab'' das Rezept, das du wolltest!"}},{"speaker":"npc","text":{"pl":"To świetnie! Pokaż ją!","en":"Very good! Show it to me!","de":"Sehr gut! Zeig her!"}},{"speaker":"npc","text":{"pl":"Znakomicie! Teraz sam będę mógł wytwarzać napój uzdrawiający.","en":"Good! Now I can produce the potions myself.","de":"Gut! Jetzt kann ich die Tränke selber herstellen."}},{"speaker":"npc","text":{"pl":"Równy z ciebie chłop! Wspomnę o tobie Diego.","en":"You are a good man! I''ll tell Diego about it!","de":"Bist ein guter Mann! Werde Diego von der Sache erzählen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_kraut_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_kraut_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_Kraut_Info","outputIds":["DIA_Dexter_Kraut_15_00","DIA_Dexter_Kraut_10_01"],"lines":[{"speaker":"hero","text":{"pl":"Co to jest \"bagienne ziele\"?","en":"What is swampweed?","de":"Was ist Sumpfkraut?"}},{"speaker":"npc","text":{"pl":"Jesteś tu nowy, co? Bagienne ziele można palić. To bardzo odprężające.","en":"New here, are you? You can smoke it. Very relaxing for most of us.","de":"Neu hier, was? Man kann es rauchen. Wirkt auf die meisten sehr entspannend."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_where_st_10_03_4', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_where_st_10_03_4","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_WhereST_Info","outputIds":["DIA_Dexter_WhereST_10_03"],"lines":[{"speaker":"npc","text":{"pl":"Dokładnie.","en":"Exactly.","de":"Stimmt genau."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_329_dexter_dia_dexter_where_st_15_00_0', 'STT_329_Dexter', '{"id":"missions_dia_stt_329_dexter_dia_dexter_where_st_15_00_0","npcId":"STT_329_Dexter","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_329_Dexter.d","sourceFunction":"DIA_Dexter_WhereST_Info","outputIds":["DIA_Dexter_WhereST_15_00","DIA_Dexter_WhereST_10_01","DIA_Dexter_WhereST_10_02","DIA_Dexter_WhereST_15_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie jest ten cały obóz na bagnie?","en":"Where is the Sect Camp?","de":"Wo ist das Sektenlager?"}},{"speaker":"npc","text":{"pl":"Wyjdź z Zewnętrznego Pierścienia przez południową bramę, potem skieruj się na wschód. Najlepiej będzie, jak weźmiesz mapę...","en":"Leave the Camp through the south exit, then head eastwards. You''d better take a map -","de":"Durch den Südausgang aus dem Lager raus, dann immer östlich halten. Am besten besorgst du dir eine Karte -"}},{"speaker":"npc","text":{"pl":"Mam tu jedną. Kosztuje 50 bryłek...","en":"I''ve got one here for 50 ore...","de":"Ich hab'' eine da für 50 Erz ..."}},{"speaker":"hero","text":{"pl":"Południowa brama to ta przy zawalonej wieży, tak?","en":"The south exit is the collapsed tower, isn''t it?","de":"Der Südausgang ist der umgestürzte Turm, richtig?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_become_shadow_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_become_shadow_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_BecomeShadow_Info","outputIds":["DIA_Fingers_BecomeShadow_15_00","DIA_Fingers_BecomeShadow_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Chcę zostać Cieniem!","en":"I want to become a Shadow!","de":"Ich will Schatten werden!"}},{"speaker":"npc","text":{"pl":"I co z tego?","en":"So?","de":"Und?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_become_shadow_any_tips_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_become_shadow_any_tips_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_BecomeShadow_AnyTips","outputIds":["DIA_Fingers_BecomeShadow_AnyTips_15_00","DIA_Fingers_BecomeShadow_AnyTips_05_01"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mi pomóc?","en":"Can you help me?","de":"Kannst du mir dabei helfen?"}},{"speaker":"npc","text":{"pl":"Nie mam pojęcia jak to zrobić...","en":"I wouldn''t know how...","de":"Ich wüsste nicht, wie ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_lehrer_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_lehrer_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_Lehrer_Info","outputIds":["DIA_Fingers_Lehrer_15_00","DIA_Fingers_Lehrer_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Czego możesz mnie nauczyć?","en":"What can you teach me?","de":"Was kannst du mir beibringen?"}},{"speaker":"npc","text":{"pl":"To zależy tylko od tego, co chciałbyś wiedzieć.","en":"That depends on what you want to know.","de":"Kommt drauf an, was willst du wissen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_lehrer_lockpick_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_lehrer_lockpick_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_Lehrer_Lockpick","outputIds":["DIA_Fingers_Lehrer_Lockpick_15_00","DIA_Fingers_Lehrer_Lockpick_05_01","DIA_Fingers_Lehrer_Lockpick_05_02","DIA_Fingers_Lehrer_Lockpick_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym nauczyć się otwierać zamki.","en":"How can I improve my lock-picking skills?","de":"Wie werde ich besser im Knacken von Schlössern?"}},{"speaker":"npc","text":{"pl":"Nie wątpię! Cóż... Początki nie są zbyt trudne.","en":"You''d like to know that, wouldn''t you! It''s not too difficult to begin with.","de":"Das willst du gerne wissen, hm? Ist für den Anfang nicht so schwer."}},{"speaker":"npc","text":{"pl":"Przede wszystkim musisz uważać, żeby nie złamać wytrycha.","en":"Above all, you have to make sure that your lockpick doesn''t break off.","de":"Du musst vor allem darauf achten, dass dir dein Dietrich nicht abbricht."}},{"speaker":"npc","text":{"pl":"Musisz być bardzo cierpliwy. Wtedy nie będziesz potrzebował tylu wytrychów, he he!","en":"If you''re a little bit more patient in future, you''ll see that you won''t need that many lockpicks any more!","de":"Wenn du in Zukunft mit weniger Gewalt an die Sache rangehst, wirst du merken, dass du weniger Dietriche verbrauchst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_lehrer_lockpick2_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_lehrer_lockpick2_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_Lehrer_Lockpick2","outputIds":["DIA_Fingers_Lehrer_Lockpick2_15_00","DIA_Fingers_Lehrer_Lockpick2_05_01","DIA_Fingers_Lehrer_Lockpick2_05_02","DIA_Fingers_Lehrer_Lockpick2_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać ekspertem w otwieraniu zamków.","en":"How can I become an expert at cracking locks?","de":"Wie werde ich Meister im Öffnen von Schlössern?"}},{"speaker":"npc","text":{"pl":"Gdy nabierzesz już trochę doświadczenia, nauczysz się rozpoznawać dźwięk, jaki wydaje wytrych zanim pęknie.","en":"Only when you''ve gained some experience can you tell when a lockpick is going to break. It makes a different sound!","de":"Nur wer schon einige Übung hat, merkt genau, wann ihm ein Dietrich abbricht und wann nicht. Du erkennst es am Geräusch!"}},{"speaker":"npc","text":{"pl":"Myślę, że powinieneś sobie z tym poradzić. Wsłuchaj się uważnie w dźwięki jakie wydaje otwierany zamek, a nie będziesz potrzebował tylu wytrychów, he, he!","en":"I think you have it. Learn to listen for the gentle clicking of the lock and you won''t lose so many lockpicks in future.","de":"Ich denke, du bist jetzt so weit - lerne, auf das leise Klicken des Schlosses zu achten, und du wirst nur noch selten das Pech haben, einen Dietrich zu verlieren."}},{"speaker":"npc","text":{"pl":"Prawdziwy mistrz w tym fachu potrafi otworzyć każdą skrzynię nie łamiąc ani jednego wytrycha.","en":"An expert in this field stands a good chance of opening a trunk without breaking his lockpick.","de":"Ein Meister des Fachs hat eine gute Chance, eine Truhe zu öffnen, ohne dass sein Dietrich überhaupt abbricht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_lehrer_pickpocket_05_04_4', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_lehrer_pickpocket_05_04_4","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_Lehrer_Pickpocket","outputIds":["DIA_Fingers_Lehrer_PICKPOCKET_05_04","DIA_Fingers_lehrer_Pickpocket_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Tylko prawdziwy mistrz potrafi ukraść coś pozostając całkowicie niezauważonym!","en":"Only an expert can take things from people''s pockets without them noticing!","de":"Erst als Meister wirst du in der Lage sein, jemandem etwas aus der Tasche zu ziehen, ohne dass er es merkt!"}},{"speaker":"npc","text":{"pl":"Nie ma o czym mówić! Nie będzie z ciebie złodzieja, dopóki nie nauczysz się skradać!","en":"Forget it! You''ll never make a skilled thief unless you can sneak around.","de":"Vergiss es! Ohne dass du schleichen kannst, wirst du NIEMALS ein geschickter Dieb."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_lehrer_pickpocket_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_lehrer_pickpocket_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_Lehrer_Pickpocket","outputIds":["DIA_Fingers_Lehrer_PICKPOCKET_15_00","DIA_Fingers_Lehrer_PICKPOCKET_05_01","DIA_Fingers_Lehrer_PICKPOCKET_05_02","DIA_Fingers_Lehrer_PICKPOCKET_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać zręcznym kieszonkowcem!","en":"I wanna become a skilled pickpocket!","de":"Ich will ein guter Taschendieb werden!"}},{"speaker":"npc","text":{"pl":"Chciałbyś odciążyć parę osób z ich dobytku, co? No dobra.","en":"So you want to relieve a few people of their belongings? Well then.","de":"So, du willst also ein paar Leute um ihre Sachen erleichtern? Nun gut."}},{"speaker":"npc","text":{"pl":"Pokażę ci na czym powinieneś się skoncentrować, ale szanse, że zostaniesz złapany będą nadal znaczne.","en":"I''ll teach you how to improve your skills, but it''s still very likely that you''ll get caught.","de":"Ich werde dir beibringen, wie du besser wirst, aber es besteht immer noch eine Chance, dass du erwischt wirst."}},{"speaker":"npc","text":{"pl":"Podejmuj ryzyko wyłącznie jeśli w pobliżu ofiary nie ma osób trzecich.","en":"You should only take the risk if nobody but your victim is around.","de":"Das Risiko solltest du nur eingehen, wenn außer deinem Opfer niemand sonst da ist."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_lehrer_pickpocket2_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_lehrer_pickpocket2_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_Lehrer_Pickpocket2","outputIds":["DIA_Fingers_Lehrer_Pickpocket2_15_00","DIA_Fingers_Lehrer_Pickpocket2_05_01","DIA_Fingers_Lehrer_Pickpocket2_05_02","DIA_Fingers_Lehrer_Pickpocket2_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym zostać mistrzem kieszonkowców!","en":"I want to become an expert pickpocket!","de":"Ich will ein Meister der Taschendiebe werden!"}},{"speaker":"npc","text":{"pl":"Cóż, chyba rzeczywiście potrafisz już wystarczająco dużo, żeby opanować zaawansowane sztuczki.","en":"I think you''ve progressed far enough to be taught the final tricks of the trade.","de":"Ich denke, du bist gut genug, um in die letzten Geheimnisse eingeweiht zu werden."}},{"speaker":"npc","text":{"pl":"Ale musisz pamiętać, że nawet mistrzowie złodziejscy od czasu do czasu zostają złapani.","en":"But you should know that even the best can get caught sometimes.","de":"Du solltest aber wissen, dass es selbst den Besten manchmal passiert, dass sie bemerkt werden."}},{"speaker":"npc","text":{"pl":"Uważaj na siebie.","en":"Take care.","de":"Also pass auf dich auf."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_lehrer_schleichen_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_lehrer_schleichen_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_Lehrer_Schleichen","outputIds":["DIA_Fingers_Lehrer_Schleichen_15_00","DIA_Fingers_Lehrer_Schleichen_05_01","DIA_Fingers_Lehrer_Schleichen_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym umieć poruszać się niepostrzeżenie.","en":"I wanna learn how to sneak around.","de":"Ich will lernen, mich lautlos zu bewegen."}},{"speaker":"npc","text":{"pl":"Myślę - bez żadnej fałszywej skromności - że jestem jednym z najlepszych złodziei zrzuconych do tej przeklętej kolonii.","en":"I believe - no false modesty - that I''m one of the best thieves they ever chucked into this colony.","de":"Ich glaube - ohne falsche Bescheidenheit - ich bin einer der besten Diebe, die sie in die Kolonie geworfen haben."}},{"speaker":"npc","text":{"pl":"Ale jeśli chodzi o skradanie się, powinieneś porozmawiać z Cavalornem.","en":"But when it comes to teaching how to sneak around, Cavalorn is the better man for you!","de":"Aber wenn es darum geht, zu lernen, wie man sich leise bewegt, ist Cavalorn der bessere Mann für dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_331_fingers_dia_fingers_where_cavalorn_15_00_0', 'STT_331_Fingers', '{"id":"missions_dia_stt_331_fingers_dia_fingers_where_cavalorn_15_00_0","npcId":"STT_331_Fingers","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_331_Fingers.d","sourceFunction":"DIA_Fingers_WhereCavalorn_Info","outputIds":["DIA_Fingers_WhereCavalorn_15_00","DIA_Fingers_WhereCavalorn_05_01","DIA_Fingers_WhereCavalorn_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę Cavalorna?","en":"Where can I find Cavalorn?","de":"Wo finde ich Cavalorn?"}},{"speaker":"npc","text":{"pl":"Poluje gdzieś poza Obozem. Pewnie znajdziesz go na drodze do Nowego Obozu. Na zachód stąd jest taki kanion.","en":"He''s hunting out in the wild. You''ll find him at the path to the New Camp. Westwards of the Old Camp there''s a wide canyon.","de":"Er jagt in der Wildnis. Du findest ihn auf dem Weg zum Neuen Lager. Westlich des Alten Lagers beginnt eine breite Schlucht."}},{"speaker":"npc","text":{"pl":"Tam znajdziesz opuszczoną chatę drwala. Cavalorn powinien kręcić się w jej pobliżu.","en":"In this canyon there''s an old woodcutters'' hut. You''ll find him there.","de":"In dieser Schlucht steht eine alte Holzfällerhütte. Dort findest du ihn."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_336_cavalorn_dia_cavalorn_hunter_15_00_0', 'STT_336_Cavalorn', '{"id":"missions_dia_stt_336_cavalorn_dia_cavalorn_hunter_15_00_0","npcId":"STT_336_Cavalorn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_336_Cavalorn.d","sourceFunction":"DIA_cavalorn_Hunter_Info","outputIds":["DIA_cavalorn_Hunter_15_00","DIA_cavalorn_Hunter_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing out here?","de":"Was machst du hier draußen?"}},{"speaker":"npc","text":{"pl":"Jestem myśliwym. Poluję głównie na ścierwojady.","en":"I''m a hunter - above all I hunt scavengers.","de":"Ich bin Jäger - ich jage vor allem Scavenger."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_15_00_0', 'STT_336_Cavalorn', '{"id":"missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_15_00_0","npcId":"STT_336_Cavalorn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_336_Cavalorn.d","sourceFunction":"DIA_cavalorn_Lehrer_Info","outputIds":["DIA_cavalorn_Lehrer_15_00","DIA_cavalorn_Lehrer_12_01"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie nauczyć czegoś o myślistwie?","en":"Can you teach me something about hunting?","de":"Kannst du mir was über die Jagd beibringen?"}},{"speaker":"npc","text":{"pl":"To zależy tylko od tego, co chciałbyś wiedzieć.","en":"That depends - what do you want to know?","de":"Kommt drauf an - was willst du wissen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_bow_12_04_4', 'STT_336_Cavalorn', '{"id":"missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_bow_12_04_4","npcId":"STT_336_Cavalorn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_336_Cavalorn.d","sourceFunction":"DIA_Cavalorn_Lehrer_Bow","outputIds":["DIA_cavalorn_Lehrer_Bow_12_04"],"lines":[{"speaker":"npc","text":{"pl":"Ale jeśli zastosujesz się do moich wskazówek, możesz liczyć na więcej trafień w cel.","en":"But if you bear in mind what I''ve told you, you''ll hit better next time.","de":"Aber wenn du meine Ratschläge beherzigst, wirst du beim nächsten Mal besser treffen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_bow_15_00_0', 'STT_336_Cavalorn', '{"id":"missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_bow_15_00_0","npcId":"STT_336_Cavalorn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_336_Cavalorn.d","sourceFunction":"DIA_Cavalorn_Lehrer_Bow","outputIds":["DIA_cavalorn_Lehrer_Bow_15_00","DIA_cavalorn_Lehrer_Bow_12_01","DIA_cavalorn_Lehrer_Bow_12_02","DIA_cavalorn_Lehrer_Bow_12_03"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie nauczyć, jak sprawniej posługiwać się łukiem?","en":"Can you teach me how to use my bow better?","de":"Kannst du mir beibringen, besser mit dem Bogen umzugehen?"}},{"speaker":"npc","text":{"pl":"Jako początkujący powinieneś zawsze pamiętać, że skuteczność strzelania z łuku zależy przede wszystkim od przyjętej postawy.","en":"For a beginner it''s not hard to get better. It''s a question of your posture.","de":"Für einen Anfänger ist es nicht schwierig, besser zu werden. Es ist eine Frage der Haltung."}},{"speaker":"npc","text":{"pl":"Rozstaw stopy szeroko, ramiona unieś na tę samą wysokość, wstrzymaj oddech i strzelaj!","en":"Place your feet well apart, hold both your arms on one level, hold your breath and - shoot!","de":"Die Füße schön weit auseinander, Arme auf eine Linie bringen, Luft anhalten und - Schuss!"}},{"speaker":"npc","text":{"pl":"Jeśli uda ci się trafić w szczególnie wrażliwe punkty ciała ofiary, nie będzie potrzeby oddawania drugiego strzału. Oczywiście początkujący strzelcy mogą tylko pomarzyć o trafieniu w czuły punkt.","en":"If you hit certain parts of the body, you only need one shot. As a beginner, you''ve only got a very small chance of hitting these parts.","de":"An bestimmten Stellen des Körpers reicht ein Schuss aus, um dein Ziel zu erlegen. Als Anfänger hast du nur eine kleine Chance, diese Stellen zu erwischen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_bow_2_info_12_02_0', 'STT_336_Cavalorn', '{"id":"missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_bow_2_info_12_02_0","npcId":"STT_336_Cavalorn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_336_Cavalorn.d","sourceFunction":"DIA_Cavalorn_Lehrer_Bow_2","outputIds":["DIA_Cavalorn_Lehrer_Bow_2_Info_12_02","DIA_Cavalorn_Lehrer_Bow_2_Info_12_03","DIA_Cavalorn_Lehrer_Bow_2_Info_12_04","DIA_Cavalorn_Lehrer_Bow_2_Info_12_05"],"lines":[{"speaker":"npc","text":{"pl":"Jesteś już całkiem niezłym myśliwym. Teraz pora abyś poznał resztę najważniejszych informacji.","en":"You''re a good hunter already. Now acquire the remaining knowledge.","de":"Du bist jetzt schon ein guter Jäger. Erfahre nun das letzte Wissen."}},{"speaker":"npc","text":{"pl":"Dobry łucznik bierze pod uwagę wiele czynników zewnętrznych, ale robi to odruchowo, nieświadomie.","en":"To become a good marksman, you need to stop trying to be one.","de":"Um ein Meisterschütze zu werden, musst du aufhören, einer sein zu wollen."}},{"speaker":"npc","text":{"pl":"Odkryj tajniki funkcjonowania twojego oka, pamiętaj o sile naciągu i wyobrażaj sobie trajektorię lotu strzały, ale przede wszystkim - zawsze bądź czujny!","en":"Discover the laws of the eye, tension, trajectory and target. Always watch out and be prepared at all times.","de":"Erkenne das Gesetz von Auge, Spannkraft, Flugbahn und Ziel. Sei immer auf der Hut, sei immer bereit."}},{"speaker":"npc","text":{"pl":"Opanowałeś już większość tajników strzelania z łuku. Teraz pozostało ci tylko rozwijać twoje umiejętności podczas polowania i walki.","en":"You''ve mastered the technique very well now. Now go and apply your knowledge and skill.","de":"Die Technik beherrscht du schon lange zur Genüge. Geh einfach hin und wende dein Wissen und Können an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_schleichen_12_04_4', 'STT_336_Cavalorn', '{"id":"missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_schleichen_12_04_4","npcId":"STT_336_Cavalorn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_336_Cavalorn.d","sourceFunction":"DIA_Cavalorn_Lehrer_Schleichen","outputIds":["DIA_cavalorn_Lehrer_Schleichen_12_04"],"lines":[{"speaker":"npc","text":{"pl":"Zapamiętaj sobie dobrze co ci powiedziałem, i przede wszystkim nie daj się złapać!","en":"Keep in mind what I told you, and above all: Never get caught!","de":"Beachte das, was ich dir sage und vor allem: Lass dich nie erwischen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_schleichen_15_00_0', 'STT_336_Cavalorn', '{"id":"missions_dia_stt_336_cavalorn_dia_cavalorn_lehrer_schleichen_15_00_0","npcId":"STT_336_Cavalorn","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_STT_336_Cavalorn.d","sourceFunction":"DIA_Cavalorn_Lehrer_Schleichen","outputIds":["DIA_cavalorn_Lehrer_Schleichen_15_00","DIA_cavalorn_Lehrer_Schleichen_12_01","DIA_cavalorn_Lehrer_Schleichen_12_02","DIA_cavalorn_Lehrer_Schleichen_12_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym poruszać się bezszelestnie.","en":"I wanna learn how to sneak around.","de":"Ich will lernen, mich lautlos zu bewegen."}},{"speaker":"npc","text":{"pl":"I słusznie. Skradanie pozwoli ci dostać się niepostrzeżenie do cudzych domów, albo po cichu zajść od tyłu przeciwnika.","en":"Good idea. That''s most important if you want to enter huts to get at somebody from behind.","de":"Gute Entscheidung. Das ist vor allem wichtig, wenn du in Hütten eindringen willst oder dich von hinten an jemanden anschleichst."}},{"speaker":"npc","text":{"pl":"Chodząc na lekko ugiętych nogach będziesz mógł uważniej obserwować grunt, po którym stąpasz, no i łatwiej będzie ci balansować ciałem.","en":"If you bend your knees when walking, you can see the floor better and you have better control over your body as well.","de":"Wenn du tief nach unten gehst, hast du den Boden besser im Blick und deinen Körper besser unter Kontrolle."}},{"speaker":"npc","text":{"pl":"Oczywiście ktoś obserwujący cię z boku natychmiast nabierze podejrzeń, więc skradaj się zawsze nie będąc widzianym przez osoby trzecie.","en":"But everybody will notice you in this posture, so make sure nobody sees you when you sneak around!","de":"Aber in dieser Haltung wirst du natürlich sofort bemerkt, also, lass dich von keinem hier beim Schleichen sehen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_exit_info_09_02_0', 'TPL_1400_GorNaBar', '{"id":"missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_exit_info_09_02_0","npcId":"TPL_1400_GorNaBar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1400_GorNaBar.d","sourceFunction":"Tpl_1400_GorNaBar_Exit_Info","outputIds":["Tpl_1400_GorNaBar_Exit_Info_09_02"],"lines":[{"speaker":"npc","text":{"pl":"Niech Śniący zawsze będzie z tobą!","en":"May the Sleeper protect you!","de":"Möge der Schläfer dich schützen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_info_info_15_01_0', 'TPL_1400_GorNaBar', '{"id":"missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_info_info_15_01_0","npcId":"TPL_1400_GorNaBar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1400_GorNaBar.d","sourceFunction":"Tpl_1400_GorNaBar_INFO_Info","outputIds":["Tpl_1400_GorNaBar_INFO_Info_15_01","Tpl_1400_GorNaBar_INFO_Info_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Co możesz mi powiedzieć o pełzaczach?","en":"What do you know about the minecrawlers?","de":"Was weißt du über die Minecrawler?"}},{"speaker":"npc","text":{"pl":"Te bestie muszą mieć gdzieś tutaj swoje gniazdo. Gdyby udało się je znaleźć, moglibyśmy wytępić je za jednym zamachem!","en":"The crawlers must have a nest somewhere. If we only knew where, we could destroy the whole brood!","de":"Die Crawler müssen irgendwo ein Nest haben. Wenn wir nur wüssten, wo es ist, dann würden wir die ganze Brut ausrotten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_suggest_info_15_01_0', 'TPL_1400_GorNaBar', '{"id":"missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_suggest_info_15_01_0","npcId":"TPL_1400_GorNaBar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1400_GorNaBar.d","sourceFunction":"Tpl_1400_GorNaBar_SUGGEST_Info","outputIds":["Tpl_1400_GorNaBar_SUGGEST_Info_15_01","Tpl_1400_GorNaBar_SUGGEST_Info_15_02","Tpl_1400_GorNaBar_SUGGEST_Info_15_03","Tpl_1400_GorNaBar_SUGGEST_Info_09_04"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję twojej pomocy.","en":"I need your help.","de":"Ich brauche deine Hilfe"}},{"speaker":"hero","text":{"pl":"Szukam wydzieliny pełzaczy dla Kaloma i chyba wiem już, gdzie znajduje się gniazdo tych drapieżców.","en":"I''m looking for secretion for Kalom and I think I know where the crawlers'' nest is.","de":"Ich bin auf der Suche nach Sekret für Kalom und glaube zu wissen, wo das Nest der Crawler ist."}},{"speaker":"hero","text":{"pl":"Możemy na ciebie liczyć, kiedy już odblokujemy prowadzące do niego przejście?","en":"If we open the passage, will you be there as well?","de":"Wenn der Durchgang geöffnet wird, bist du dabei?"}},{"speaker":"npc","text":{"pl":"Gniazdo pełzaczy! Nareszcie! Mój miecz jest na twoje usługi.","en":"The crawlers'' nest! Finally. My sword is at your service!","de":"Das Nest der Crawler! Endlich. Mein Schwert kämpft für dich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_victory_info_15_01_0', 'TPL_1400_GorNaBar', '{"id":"missions_dia_tpl_1400_gor_na_bar_tpl_1400_gor_na_bar_victory_info_15_01_0","npcId":"TPL_1400_GorNaBar","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1400_GorNaBar.d","sourceFunction":"Tpl_1400_GorNaBar_VICTORY_Info","outputIds":["Tpl_1400_GorNaBar_VICTORY_Info_15_01","Tpl_1400_GorNaBar_VICTORY_Info_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem gniazdo królowej!","en":"I''ve found the nest of the queen!","de":"Ich habe das Nest der Königin gefunden!"}},{"speaker":"npc","text":{"pl":"Wykazałeś się odwagą i hartem ducha. Potrzebujemy ludzi takich jak ty!","en":"You''ve shown courage and spirit. We need people like you!","de":"Du hast Mut und Kampfgeist bewiesen. Solche Leute können wir gebrauchen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_crawler_info_15_01_0', 'TPL_1401_GorNaKosh', '{"id":"missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_crawler_info_15_01_0","npcId":"TPL_1401_GorNaKosh","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1401_GorNaKosh.d","sourceFunction":"Tpl_1401_GorNaKosh_CRAWLER_Info","outputIds":["Tpl_1401_GorNaKosh_CRAWLER_Info_15_01","Tpl_1401_GorNaKosh_CRAWLER_Info_13_02","Tpl_1401_GorNaKosh_CRAWLER_Info_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mi opowiedzieć coś jeszcze o tych pełzaczach?","en":"Can you tell me more about the crawlers?","de":"Kannst du mir mehr von den Crawlern erzählen?"}},{"speaker":"npc","text":{"pl":"Te bestie działają instynktownie. Próbują zabić wszystko co nie jest pełzaczem.","en":"They act instinctively, anything non-crawler is killed.","de":"Sie handeln nach ihrem Instinkt. Alles, was kein Crawler ist, wird getötet."}},{"speaker":"npc","text":{"pl":"Wykorzystaj tę wiedzę w walce z tymi potworami.","en":"Use this knowledge in your fight against them.","de":"Wenn du gegen sie kämpfst, mach dir dieses Wissen zu Nutze."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_exit_info_13_02_0', 'TPL_1401_GorNaKosh', '{"id":"missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_exit_info_13_02_0","npcId":"TPL_1401_GorNaKosh","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1401_GorNaKosh.d","sourceFunction":"Tpl_1401_GorNaKosh_Exit_Info","outputIds":["Tpl_1401_GorNaKosh_Exit_Info_13_02"],"lines":[{"speaker":"npc","text":{"pl":"Niech Śniący zbudzi się ku naszemu zbawieniu!","en":"May the Sleeper awaken!","de":"Der Schläfer erwache!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_info_info_13_05_4', 'TPL_1401_GorNaKosh', '{"id":"missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_info_info_13_05_4","npcId":"TPL_1401_GorNaKosh","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1401_GorNaKosh.d","sourceFunction":"Tpl_1401_GorNaKosh_INFO_Info","outputIds":["Tpl_1401_GorNaKosh_INFO_Info_13_05"],"lines":[{"speaker":"npc","text":{"pl":"Walcz bez strachu i zabijaj bez litości.","en":"Fight without fear and kill without mercy.","de":"Kämpfe ohne Furcht und töte ohne Gnade."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791211);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_info_info_15_01_0', 'TPL_1401_GorNaKosh', '{"id":"missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_info_info_15_01_0","npcId":"TPL_1401_GorNaKosh","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1401_GorNaKosh.d","sourceFunction":"Tpl_1401_GorNaKosh_INFO_Info","outputIds":["Tpl_1401_GorNaKosh_INFO_Info_15_01","Tpl_1401_GorNaKosh_INFO_Info_13_02","Tpl_1401_GorNaKosh_INFO_Info_15_03","Tpl_1401_GorNaKosh_INFO_Info_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Poluję na pełzacze.","en":"I''m hunting minecrawlers.","de":"Ich jage Minecrawler."}},{"speaker":"hero","text":{"pl":"Możesz mi opowiedzieć o sposobach polowania na pełzacze?","en":"Can you tell me something about crawler hunting?","de":"Kannst du mir was über die Crawlerjagd erzählen?"}},{"speaker":"npc","text":{"pl":"Przy łowach na pełzacze obowiązuje tylko jedna zasada: gdy jakiegoś zobaczysz, rzuć się na niego czym prędzej i spróbuj go zabić pierwszym ciosem.","en":"There''s just a single rule to remember when hunting crawlers: When you see them, run at them and kill them as fast as you can.","de":"Beim Crawlerjagen gibt''s nur eine Regel. Wenn du sie siehst, lauf auf sie zu und töte sie, so schnell du kannst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_suggest_info_15_01_0', 'TPL_1401_GorNaKosh', '{"id":"missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_suggest_info_15_01_0","npcId":"TPL_1401_GorNaKosh","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1401_GorNaKosh.d","sourceFunction":"Tpl_1401_GorNaKosh_SUGGEST_Info","outputIds":["Tpl_1401_GorNaKosh_SUGGEST_Info_15_01","Tpl_1401_GorNaKosh_SUGGEST_Info_13_02","Tpl_1401_GorNaKosh_SUGGEST_Info_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Wiem, gdzie znajduje się gniazdo pełzaczy. Muszę tam pójść, żeby zdobyć coś dla Cor Kaloma.","en":"I know where the crawlers'' nest is. I''m going there to get something for Kalom, so he can brew a stronger potion.","de":"Ich weiß, wo das Nest der Crawler ist und werde hineingehen und etwas suchen, aus dem Kalom ein stärkeres Elixier brauen kann."}},{"speaker":"npc","text":{"pl":"Zatem przyda ci się moja pomoc. Pójdę z tobą.","en":"Then you''ll need my blade. I''ll join you.","de":"Dann wirst du meine Klinge brauchen. Ich bin dabei."}},{"speaker":"hero","text":{"pl":"Dobrze. Spotkamy się przy wielkim przejściu.","en":"Good. We''ll meet at the big passage.","de":"Gut. Wir treffen uns beim großen Durchgang."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_victory_info_15_01_0', 'TPL_1401_GorNaKosh', '{"id":"missions_dia_tpl_1401_gor_na_kosh_tpl_1401_gor_na_kosh_victory_info_15_01_0","npcId":"TPL_1401_GorNaKosh","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1401_GorNaKosh.d","sourceFunction":"Tpl_1401_GorNaKosh_VICTORY_Info","outputIds":["Tpl_1401_GorNaKosh_VICTORY_Info_15_01","Tpl_1401_GorNaKosh_VICTORY_Info_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Znalazłem gniazdo pełzaczy!","en":"I''ve found the crawler nest!","de":"Ich habe das Nest der Crawler gefunden!"}},{"speaker":"npc","text":{"pl":"Wspaniale! Wróć do obozu i wypełnij rozkaz do końca. Cor Kalom na pewno się niecierpliwi!","en":"Wonderful! Now go back to the Camp and finish this mission. Cor Kalom will be waiting for you!","de":"Wunderbar! Gehe nun zurück ins Lager und beende deine Mission. Cor Kalom erwartet dich bestimmt schon!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_11_00_0', 'TPL_1402_GorNaToth', '{"id":"missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_11_00_0","npcId":"TPL_1402_GorNaToth","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1402_GorNaToth.d","sourceFunction":"DIA_GorNaToth_AngarTalked_Info","outputIds":["DIA_GorNaToth_AngarTalked_11_00"],"lines":[{"speaker":"npc","text":{"pl":"Rozmawiałeś z Cor Angarem? I co powiedział?","en":"Cor Angar has spoken to you? What did he say?","de":"Cor Angar hat mit dir geredet? Was hat er gesagt?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_15_00_0', 'TPL_1402_GorNaToth', '{"id":"missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_15_00_0","npcId":"TPL_1402_GorNaToth","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1402_GorNaToth.d","sourceFunction":"DIA_GorNaToth_Abweisend_Info","outputIds":["DIA_GorNaToth_AngarTalked_15_00","DIA_GorNaToth_AngarTalked_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mnie czegoś nauczyć?","en":"Can you train me?","de":"Kannst du mich trainieren?"}},{"speaker":"npc","text":{"pl":"Zejdź mi z oczu, niegodny robaku! Uczę wyłącznie Strażników Świątyni Śniącego.","en":"Out of my sight, unworthy one. I instruct only the Sleeper''s templars.","de":"Geh mir aus den Augen, Unwürdiger. Ich trainiere nur die Templer des Schläfers."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_normal_15_00_0', 'TPL_1402_GorNaToth', '{"id":"missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_normal_15_00_0","npcId":"TPL_1402_GorNaToth","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1402_GorNaToth.d","sourceFunction":"DIA_GorNaToth_AngarTalked_Normal","outputIds":["DIA_GorNaToth_AngarTalked_Normal_15_00","DIA_GorNaToth_AngarTalked_Normal_11_01","DIA_GorNaToth_AngarTalked_Normal_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Kazał mi zgłosić się do niego, gdy już zostanę Świątynnym Strażnikiem.","en":"He said I should come back as soon as I''m a templar.","de":"Er hat gesagt, ich soll wiederkommen, wenn ich Templer bin."}},{"speaker":"npc","text":{"pl":"Najwyraźniej ma o tobie wysokie mniemanie. Inaczej nie odezwałby się do ciebie.","en":"It would appear he has a high opinion of you. He never speaks to anybody.","de":"Er scheint sehr viel von dir zu halten. Er redet so gut wie nie mit jemandem."}},{"speaker":"npc","text":{"pl":"To wielki zaszczyt zostać przez niego choćby zauważonym. Do mnie odezwał się po raz ostatni całe dwa miesiące temu!","en":"It is an honor even to be noticed by him. The last time he spoke to ME was about two months ago.","de":"Es ist eine große Ehre für dich, dass er dich überhaupt bemerkt hat. Mit MIR hat er das letzte Mal vor zwei Monaten geredet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_shark_15_00_0', 'TPL_1402_GorNaToth', '{"id":"missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_shark_15_00_0","npcId":"TPL_1402_GorNaToth","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1402_GorNaToth.d","sourceFunction":"DIA_GorNaToth_AngarTalked_Shark","outputIds":["DIA_GorNaToth_AngarTalked_Shark_15_00","DIA_GorNaToth_AngarTalked_Shark_11_01","DIA_GorNaToth_AngarTalked_Shark_11_02"],"lines":[{"speaker":"hero","text":{"pl":"Powiedział, że nigdy nie lubił błotnych węży.","en":"He said he never liked the swampsharks.","de":"Er sagte, die Sumpfhaie habe er noch nie leiden können."}},{"speaker":"npc","text":{"pl":"Co...? (zdecydowanie) Czeka mnie święta misja!","en":"What...? A holy task is waiting for me!","de":"Was ...? (bestimmt) Eine heilige Aufgabe erwartet mich!"}},{"speaker":"npc","text":{"pl":"Życzenie mojego mistrza jest dla mnie rozkazem.","en":"My master''s wish is my command.","de":"Der Wunsch meines Meisters ist mir Befehl."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_unworthy_15_00_0', 'TPL_1402_GorNaToth', '{"id":"missions_dia_tpl_1402_gor_na_toth_dia_gor_na_toth_angar_talked_unworthy_15_00_0","npcId":"TPL_1402_GorNaToth","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1402_GorNaToth.d","sourceFunction":"DIA_GorNaToth_AngarTalked_Unworthy","outputIds":["DIA_GorNaToth_AngarTalked_Unworthy_15_00","DIA_GorNaToth_AngarTalked_Unworthy_11_01"],"lines":[{"speaker":"hero","text":{"pl":"Powiedział, że jesteś niegodny, by nosić zbroję Świątynnego Strażnika.","en":"He says you''ll be unworthy of wearing the armor of a templar.","de":"Er hat gesagt, du seiest unwürdig, die Rüstung eines Templers zu tragen."}},{"speaker":"npc","text":{"pl":"Nigdy! Nie mógł tak powiedzieć! Nie o mnie!","en":"Never! He could not have said that! Not about ME!","de":"Niemals! Das hat er nicht gesagt! Nicht über MICH!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1402_gor_na_toth_tpl_1402_gor_na_toth_getstuff_info_15_01_0', 'TPL_1402_GorNaToth', '{"id":"missions_dia_tpl_1402_gor_na_toth_tpl_1402_gor_na_toth_getstuff_info_15_01_0","npcId":"TPL_1402_GorNaToth","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1402_GorNaToth.d","sourceFunction":"TPL_1402_GorNaToth_GETSTUFF_Info","outputIds":["TPL_1402_GorNaToth_GETSTUFF_Info_15_01","TPL_1402_GorNaToth_GETSTUFF_Info_11_02","TPL_1402_GorNaToth_GETSTUFF_Info_11_03"],"lines":[{"speaker":"hero","text":{"pl":"Chciałbym odebrać moją zbroję Świątynnego Strażnika.","en":"I''d like to collect my templar''s armor.","de":"Ich möchte meine Templer-Rüstung abholen."}},{"speaker":"npc","text":{"pl":"To prawdziwy zaszczyt wręczyć zbroję człowiekowi, który zdobył dla nas jaja pełzaczy.","en":"I''m delighted to have the honor of handing our armor to the man who found the minecrawler eggs.","de":"Es ist mir eine Freude, dem Mann eine von unseren Rüstungen zu überreichen, der die Eier der Minecrawler gefunden hat."}},{"speaker":"npc","text":{"pl":"Niech ta zbroja chroni cię równie dobrze jak Śniący chroni nasze Bractwo!","en":"May this armor protect you, as the Sleeper protects the Brotherhood!","de":"Diese Rüstung soll dich schützen, so wie der Schläfer die Bruderschaft schützt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1405_gor_na_ran_dia_gor_na_ran_wache_15_00_0', 'TPL_1405_GorNaRan', '{"id":"missions_dia_tpl_1405_gor_na_ran_dia_gor_na_ran_wache_15_00_0","npcId":"TPL_1405_GorNaRan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1405_GorNaRan.d","sourceFunction":"DIA_GorNaRan_Wache_Info","outputIds":["DIA_GorNaRan_Wache_15_00","DIA_GorNaRan_Wache_13_01","DIA_GorNaRan_Wache_13_02","DIA_GorNaRan_Wache_13_03"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Pilnuję, żeby błotne węże nie podpływały zbyt blisko Obozu.","en":"I''m making sure no swampsharks come too close to the Camp.","de":"Ich passe auf, das kein Sumpfhai zu nah ans Lager gerät."}},{"speaker":"npc","text":{"pl":"Na twoim miejscu trzymałbym się od nich z dala. W walce z takim potworem nie masz najmniejszych szans!","en":"If I were you, I''d steer clear of the beasts. You don''t stand a chance against them.","de":"Wenn ich du wäre, würde ich ''nen weiten Bogen um die Viecher machen. Du hast keine Chance gegen sie."}},{"speaker":"npc","text":{"pl":"A teraz idź już sobie. Muszę mieć oczy szeroko otwarte.","en":"Now don''t disturb me any more, I need to keep my eyes peeled.","de":"Jetzt stör'' mich nicht weiter, ich muss die Augen aufhalten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_13_01_0', 'TPL_1405_GorNaRan', '{"id":"missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_13_01_0","npcId":"TPL_1405_GorNaRan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1405_GorNaRan.d","sourceFunction":"Info_TPL_1405_GorNaRan_Info","outputIds":["Info_TPL_1405_GorNaRan_Info_13_01"],"lines":[{"speaker":"npc","text":{"pl":"A dokąd to się wybierasz? Nikt nie ma tu prawa wstępu!","en":"Where do you think you are going? Nobody''s allowed to pass here!","de":"Wo willst DU hin, hier darf niemand durch!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_15_02_0', 'TPL_1405_GorNaRan', '{"id":"missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_15_02_0","npcId":"TPL_1405_GorNaRan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1405_GorNaRan.d","sourceFunction":"Info_TPL_1405_GorNaRan2_Info","outputIds":["Info_TPL_1405_GorNaRan_Info_15_02","Info_TPL_1405_GorNaRan_Info_13_03"],"lines":[{"speaker":"hero","text":{"pl":"A co się tu tak w ogóle dzieje?","en":"What''s going on here anyway?","de":"Was ist hier eigentlich los?"}},{"speaker":"npc","text":{"pl":"Pytasz, co się tu dzieje? Padnij na kolana i błagaj Śniącego o litość nad twą grzeszną duszą! Oto bowiem nadszedł moment jego wielkiego przebudzenia!","en":"You''re asking me what''s going on? Throw yourself into the dust and pay tribute to the Sleeper, because at this very moment he awakens to banish all infidels from this world.","de":"Du fragst mich, was hier los ist? Wirf dich in den Staub und huldige dem Schläfer, denn just in diesem Moment erwacht er und wird alle Ungläubigen vom Antlitz dieser Welt verbannen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_15_04_0', 'TPL_1405_GorNaRan', '{"id":"missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_15_04_0","npcId":"TPL_1405_GorNaRan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1405_GorNaRan.d","sourceFunction":"Info_TPL_1405_GorNaRan3_Info","outputIds":["Info_TPL_1405_GorNaRan_Info_15_04","Info_TPL_1405_GorNaRan_Info_13_05"],"lines":[{"speaker":"hero","text":{"pl":"Chciałem się tylko trochę rozejrzeć.","en":"Just wanted to have a look around.","de":"Wollte mich nur umsehen."}},{"speaker":"npc","text":{"pl":"Gnido! Tacy jak ty nie mają tu czego szukać we wzniosłej chwili ostatecznego triumfu Śniącego! Widzę, że muszę ci to wbić do głowy!","en":"You worm, you and your kind have no business here when the Sleeper awakes! I''ll have to clear you out of the way.","de":"Du Wurm, du und deinesgleichen haben hier nichts zu suchen, wenn der Schläfer erwacht! Ich werde dich aus dem Weg räumen müssen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_15_06_0', 'TPL_1405_GorNaRan', '{"id":"missions_dia_tpl_1405_gor_na_ran_info_tpl_1405_gor_na_ran_info_15_06_0","npcId":"TPL_1405_GorNaRan","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1405_GorNaRan.d","sourceFunction":"Info_TPL_1405_GorNaRan4_Info","outputIds":["Info_TPL_1405_GorNaRan_Info_15_06","Info_TPL_1405_GorNaRan_Info_13_07"],"lines":[{"speaker":"hero","text":{"pl":"Nie powstrzymasz mnie!","en":"You can''t stop me!","de":"Du kannst mich nicht aufhalten!"}},{"speaker":"npc","text":{"pl":"Jak sobie życzysz, chłopcze, w imię Śniącego!","en":"Whatever you say, boy, for the Sleeper!","de":"Wie du meinst, Junge, für den Schläfer!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1406_templer_dia_kaloms_guard_perm_15_00_0', 'TPL_1406_Templer', '{"id":"missions_dia_tpl_1406_templer_dia_kaloms_guard_perm_15_00_0","npcId":"TPL_1406_Templer","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1406_Templer.d","sourceFunction":"DIA_KalomsGuard_PERM_Info","outputIds":["DIA_KalomsGuard_PERM_15_00","DIA_KalomsGuard_PERM_13_01"],"lines":[{"speaker":"hero","text":{"pl":"Chyba nie będziesz miał nic przeciwko, jeśli tam wejdę?","en":"I''m sure you won''t mind me going in there...?","de":"Du hast doch nichts dagegen, wenn ich da reingehe?"}},{"speaker":"npc","text":{"pl":"Okazuj mojemu mistrzowi należyty szacunek, albo nie pożyjesz długo!","en":"If you''re disrespectful to my master, I''ll kill you.","de":"Wenn du meinem Meister keinen Respekt entgegen bringst, werde ich dich töten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_arena_15_00_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_arena_15_00_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_Arena_Info","outputIds":["Info_GorHanis_Arena_15_00","Info_GorHanis_Arena_08_01","Info_GorHanis_Arena_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Walczysz na arenie?","en":"You fight in the arena?","de":"Du kämpfst in der Arena?"}},{"speaker":"npc","text":{"pl":"Zostałem wybrany przez moich mistrzów, by bronić na arenie honoru obozu na bagnie.","en":"I was sent here from the swamp by my masters to fight for the Sleeper.","de":"Ich wurde von meinen Meistern aus dem Sumpf hierher geschickt, um für den Schläfer zu kämpfen."}},{"speaker":"npc","text":{"pl":"Przyświeca mi więc wyższy cel. Walczę, by pokazać niewiernym jak wielka jest potęga Śniącego!","en":"I''ll fight here for his higher glory - so all infidels can see how strong his power has made me!","de":"Zu seiner höheren Ehre kämpfe ich hier - Auf dass alle Ungläubigen sehen, wie stark ich dank seiner Macht geworden bin!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_charge_15_00_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_charge_15_00_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_Charge_Info","outputIds":["Info_GorHanis_Charge_15_00","Info_GorHanis_Charge_08_01","Info_GorHanis_Charge_08_02","Info_GorHanis_Charge_08_03"],"lines":[{"speaker":"hero","text":{"pl":"Wyzywam cię na pojedynek na arenie!","en":"I challenge you to a duel in the arena!","de":"Ich fordere dich zum Duell in der Arena!"}},{"speaker":"npc","text":{"pl":"Zabicie kogoś takiego jak ty nie przysporzy raczej chwały Śniącemu.","en":"It will not serve the glory of the Sleeper if I slaughter just any bum in front of the audience.","de":"Es dient nicht der höheren Ehre des Schläfers, wenn ich einen dahergelaufenen Bauertölpel vorm Publikum niedermetzele."}},{"speaker":"npc","text":{"pl":"Stanę z tobą w szranki dopiero w tedy, gdy okażesz się godnym rywalem.","en":"I''ll only fight against you when you''ve become a worthy opponent.","de":"Ich werde erst gegen dich kämpfen, wenn du ein würdiger Gegner für mich bist."}},{"speaker":"npc","text":{"pl":"Ale jestem pewien, że wojownicy z Nowego Obozu nie będą mieli takich skrupułów...…","en":"But I''m sure that the fighters from the Old or New Camp aren''t all men of principle…","de":"Aber ich bin mir sicher, die Kämpfer aus dem Alten oder dem Neuen Lager haben nicht so einen hohen moralischen Anspruch ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_charge_good_15_00_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_charge_good_15_00_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_ChargeGood_Info","outputIds":["Info_GorHanis_ChargeGood_15_00","Info_GorHanis_ChargeGood_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Czy jestem już dość silny, żeby się z tobą zmierzyć?","en":"Am I now strong enough to fight against you?","de":"Bin ich jetzt gut genug, um gegen dich zu kämpfen?"}},{"speaker":"npc","text":{"pl":"Nie! Jesteś jeszcze zbyt słaby. Nie sprostasz mi w walce!","en":"No! Your strength is insufficient - you''re no opponent for me!","de":"Nein! Deine Stärke reicht noch nicht aus - du bist kein Gegner für mich!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_sleeper_08_04_4', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_sleeper_08_04_4","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_Sleeper_Info","outputIds":["Info_GorHanis_Sleeper_08_04"],"lines":[{"speaker":"npc","text":{"pl":"Tak! Nasze oczekiwanie wkrótce dobiegnie końca. W tej chwili przygotowujemy się do rytuału wielkiego przyzwania.","en":"Yes! And the wait will soon be over. A great invocation is currently being prepared.","de":"Ja! Und das Warten wird bald ein Ende haben. Die Vorbereitungen für eine große Anrufung laufen schon."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_sleeper_15_00_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_sleeper_15_00_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_Sleeper_Info","outputIds":["Info_GorHanis_Sleeper_15_00","Info_GorHanis_Sleeper_08_01","Info_GorHanis_Sleeper_08_02","Info_GorHanis_Sleeper_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Kim jest Śniący?","en":"What is the Sleeper?","de":"Was ist der Schläfer?"}},{"speaker":"npc","text":{"pl":"W naszym obozie znajdziesz świętych mężów, którzy odpowiedzą ci na to pytanie znacznie lepiej niż ja.","en":"You will find priests who''ll be able to answer that question better than I can in our camp.","de":"Bei uns im Lager findest du Priester, die dir diese Frage besser beantworten können als ich."}},{"speaker":"npc","text":{"pl":"Powiem ci tylko tyle: Śniący będzie naszym zbawicielem. Przyprowadził nas tutaj i z jego pomocą uda się nam stąd wydostać.","en":"I''ll just tell you this much: The Sleeper is our redeemer, he has led us to this place and he''ll get us out of here.","de":"Ich will dir nur so viel sagen: Der Schläfer ist unser Erlöser, er hat uns an diesen Ort geführt, und er wird uns auch wieder hier herausholen."}},{"speaker":"hero","text":{"pl":"Chcesz przez to powiedzieć, że czekacie aż wasz bóg zwróci wam wolność?","en":"You mean you''re waiting for your god to liberate you?","de":"Du meinst, ihr wartet darauf, dass euch euer Gott befreit?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_summoning_15_00_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_summoning_15_00_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_Summoning_Info","outputIds":["Info_GorHanis_Summoning_15_00","Info_GorHanis_Summoning_08_01","Info_GorHanis_Summoning_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Na czym polega rytuał, który planujecie?","en":"What kind of invocation is it you''re planning?","de":"Was ist das für eine große Anrufung, die ihr plant?"}},{"speaker":"npc","text":{"pl":"Nasi prorocy przewidzieli, że wspólne przywołanie Śniącego jest jedyną drogą do odzyskania wolności!","en":"Our prophets say that the common invocation of the Sleeper is the key to freedom!","de":"Unsere Propheten sagen, die gemeinsame Anrufung des Schläfers sei der Schlüssel zur Freiheit für uns alle!"}},{"speaker":"npc","text":{"pl":"Jeśli chcesz się jeszcze czegoś dowiedzieć, powinieneś udać się do naszego obozu.","en":"If you want to find out more about it, just come to our camp.","de":"Wenn du mehr darüber erfahren willst, begib dich zu uns ins Lager."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_way_to_st_15_00_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_way_to_st_15_00_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_WayToST_Info","outputIds":["Info_GorHanis_WayToST_15_00","Info_GorHanis_WayToST_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Mógłbyś opisać mi drogę do waszego obozu?","en":"Could you describe the way to your camp?","de":"Kannst du mir den Weg zu eurem Lager beschreiben?"}},{"speaker":"npc","text":{"pl":"W Starym Obozie znajdziesz kilku Nowicjuszy Bractwa, którzy chętnie wskażą ci drogę do obozu na bagnie. Znajdź któregoś z nich i porozmawiaj z nim!","en":"There are always some novices around here in the Old Camp, willing to accompany newcomers like you to our camp. You only need to speak to them!","de":"Hier im Alten Lager sind immer einige Novizen, die Neuankömmlinge wie dich in unser Lager begleiten. Du musst sie nur ansprechen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_gor_hanis_what_15_00_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_gor_hanis_what_15_00_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_GorHanis_What_Info","outputIds":["Info_GorHanis_What_15_00","Info_GorHanis_What_08_01"],"lines":[{"speaker":"hero","text":{"pl":"Co tu robisz?","en":"What are you doing here?","de":"Was machst du hier?"}},{"speaker":"npc","text":{"pl":"Ja? Walczę ku chwale wielkiego Śniącego!","en":"Me? I''m fighting for the glory of the Sleeper!","de":"Ich? Ich kämpfe für den Ruhm des Schläfers!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis_08_01_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis_08_01_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_TPL_1422_GorHanis_Info","outputIds":["Info_TPL_1422_GorHanis_08_01"],"lines":[{"speaker":"npc","text":{"pl":"Was machst du hier?","en":"Was machst du hier?","de":"Was machst du hier?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis1_15_01_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis1_15_01_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_TPL_1422_GorHanis1_Info","outputIds":["Info_TPL_1422_GorHanis1_15_01","Info_TPL_1422_GorHanis1_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Ich will helfen den Schläfer zu erwecken.","en":"Ich will helfen den Schläfer zu erwecken.","de":"Ich will helfen den Schläfer zu erwecken."}},{"speaker":"npc","text":{"pl":"Hmm, siehst gar nicht so aus, als wolltest Du wirklich helfen wollen. Geh aber ruhig weiter, ich halte dich nicht auf, falls du lügst, wird der Hohenpriester dir schon eine Lektion erteilen.","en":"Hmm, siehst gar nicht so aus, als wolltest Du wirklich helfen wollen. Geh aber ruhig weiter, ich halte dich nicht auf, falls du lügst, wird der Hohenpriester dir schon eine Lektion erteilen.","de":"Hmm, siehst gar nicht so aus, als wolltest Du wirklich helfen wollen. Geh aber ruhig weiter, ich halte dich nicht auf, falls du lügst, wird der Hohenpriester dir schon eine Lektion erteilen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis2_15_01_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis2_15_01_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_TPL_1422_GorHanis2_Info","outputIds":["Info_TPL_1422_GorHanis2_15_01","Info_TPL_1422_GorHanis2_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Das geht dich nichts an!","en":"Das geht dich nichts an!","de":"Das geht dich nichts an!"}},{"speaker":"npc","text":{"pl":"Soso, dann lasse ich dich lieber passieren, bevor du mir weh tust (lacht). Am Hohenpriester kommst Du eh nicht vorbei und ich muss mein Schwert nicht mit deinem Blut beschmutzen.","en":"Soso, dann lasse ich dich lieber passieren, bevor du mir weh tust (lacht). Am Hohenpriester kommst Du eh nicht vorbei und ich muss mein Schwert nicht mit deinem Blut beschmutzen.","de":"Soso, dann lasse ich dich lieber passieren, bevor du mir weh tust (lacht). Am Hohenpriester kommst Du eh nicht vorbei und ich muss mein Schwert nicht mit deinem Blut beschmutzen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis3_15_01_0', 'TPL_1422_GorHanis', '{"id":"missions_dia_tpl_1422_gor_hanis_info_tpl_1422_gor_hanis3_15_01_0","npcId":"TPL_1422_GorHanis","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1422_GorHanis.d","sourceFunction":"Info_TPL_1422_GorHanis3_Info","outputIds":["Info_TPL_1422_GorHanis3_15_01","Info_TPL_1422_GorHanis3_08_02"],"lines":[{"speaker":"hero","text":{"pl":"Wie seit ihr an dem Priester vorbei gekommen?","en":"Wie seit ihr an dem Priester vorbei gekommen?","de":"Wie seit ihr an dem Priester vorbei gekommen?"}},{"speaker":"npc","text":{"pl":"Ich sage es dir, es wird dir eh nicht nutzen. Der Priester hat uns nur passieren lassen, weil Meister Kalom mit im gesprochen hat, dass Glück wirst du nicht haben. Geh nur (lacht).","en":"Ich sage es dir, es wird dir eh nicht nutzen. Der Priester hat uns nur passieren lassen, weil Meister Kalom mit im gesprochen hat, dass Glück wirst du nicht haben. Geh nur (lacht).","de":"Ich sage es dir, es wird dir eh nicht nutzen. Der Priester hat uns nur passieren lassen, weil Meister Kalom mit im gesprochen hat, dass Glück wirst du nicht haben. Geh nur (lacht)."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_exit_info_13_02_0', 'TPL_1433_GorNaVid', '{"id":"missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_exit_info_13_02_0","npcId":"TPL_1433_GorNaVid","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1433_GorNaVid.d","sourceFunction":"Tpl_1433_GorNaVid_Exit_Info","outputIds":["Tpl_1433_GorNaVid_Exit_Info_13_02"],"lines":[{"speaker":"npc","text":{"pl":"Niech nadejdzie przebudzenie Śniącego.","en":"May the Sleeper awaken.","de":"Der Schläfer erwache."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_health_info_15_01_0', 'TPL_1433_GorNaVid', '{"id":"missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_health_info_15_01_0","npcId":"TPL_1433_GorNaVid","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1433_GorNaVid.d","sourceFunction":"Tpl_1433_GorNaVid_HEALTH_Info","outputIds":["Tpl_1433_GorNaVid_HEALTH_Info_15_01","Tpl_1433_GorNaVid_HEALTH_Info_15_02","Tpl_1433_GorNaVid_HEALTH_Info_15_03","Tpl_1433_GorNaVid_HEALTH_Info_13_04"],"lines":[{"speaker":"hero","text":{"pl":"Potrzebuję twojej pomocy.","en":"I need your help.","de":"Ich brauche deine Hilfe"}},{"speaker":"hero","text":{"pl":"Szukam wydzieliny pełzaczy dla Kaloma, i chyba wiem już, gdzie znajduje się gniazdo tych drapieżców.","en":"I''m looking for secretion for Kalom and I know where the crawlers'' nest is.","de":"Ich bin auf der Suche nach Sekret für Kalom und weiß, wo sich das Nest der Crawler befindet."}},{"speaker":"hero","text":{"pl":"Pomożesz mi po otwarciu przejścia?","en":"Will you be there when the passage is opened?","de":"Wenn der Durchgang geöffnet wird, bist du dabei?"}},{"speaker":"npc","text":{"pl":"Walka z pełzaczami to niebezpieczne zadanie. Przynieś mi napój uzdrawiający, wtedy ci pomogę.","en":"When fighting crawlers it often costs a lot of blood. If you bring me a healing potion, you can count me in.","de":"Der Kampf gegen Crawler kostet Blut. Wenn du mir einen Heiltrank bringst, bin ich dabei."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_health_suc_info_15_01_0', 'TPL_1433_GorNaVid', '{"id":"missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_health_suc_info_15_01_0","npcId":"TPL_1433_GorNaVid","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1433_GorNaVid.d","sourceFunction":"Tpl_1433_GorNaVid_HEALTH_SUC_Info","outputIds":["Tpl_1433_GorNaVid_HEALTH_SUC_Info_15_01","Tpl_1433_GorNaVid_HEALTH_SUC_Info_13_02","Tpl_1433_GorNaVid_HEALTH_SUC_Info_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Proszę, może to ci pomoże.","en":"Here, maybe that''ll help.","de":"Hier, vielleicht hilft dir das."}},{"speaker":"npc","text":{"pl":"Dzięki. Możesz na mnie liczyć. Spotkamy się na dole, u Asghana.","en":"Thanks. You can count on me. We''ll meet down below with Ashgan.","de":"Danke. Du kannst auf meine Stärke zählen. Wir treffen uns unten bei Ashgan."}},{"speaker":"hero","text":{"pl":"Będę czekał.","en":"I''ll be there.","de":"Ich werde dort sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_ian_info_15_01_0', 'TPL_1433_GorNaVid', '{"id":"missions_dia_tpl_1433_gor_na_vid_tpl_1433_gor_na_vid_ian_info_15_01_0","npcId":"TPL_1433_GorNaVid","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1433_GorNaVid.d","sourceFunction":"Tpl_1433_GorNaVid_IAN_Info","outputIds":["Tpl_1433_GorNaVid_IAN_Info_15_01","Tpl_1433_GorNaVid_IAN_Info_13_02"],"lines":[{"speaker":"hero","text":{"pl":"Szukam gniazda pełzaczy.","en":"I''m looking for the nest of the minecrawlers.","de":"Ich suche das Nest der Minecrawler"}},{"speaker":"npc","text":{"pl":"W pobliżu głównego szybu znajduje się wiele jaskiń, ale nie udało się nam jeszcze odnaleźć gniazda.","en":"There are many caves next to the main shaft in the mine, but we haven''t found any nest.","de":"Hier in der Mine gibt es viele Höhlen neben dem Hauptschacht, aber dort haben wir noch kein Nest gefunden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_greet_15_00_0', 'TPL_1439_GorNaDrak', '{"id":"missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_greet_15_00_0","npcId":"TPL_1439_GorNaDrak","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1439_GorNaDrak.d","sourceFunction":"DIA_GorNaDrak_Greet_Info","outputIds":["DIA_GorNaDrak_Greet_15_00","DIA_GorNaDrak_Greet_09_01","DIA_GorNaDrak_Greet_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Dokąd się wybieracie?","en":"Hi! Where are you off to?","de":"Hi! Wohin soll''s denn gehen?"}},{"speaker":"npc","text":{"pl":"Zabieramy wydzielinę pełzaczy zdobytą przez naszych braci w Starej Kopalni do Cor Kaloma.","en":"We take the minecrawler secretion from our brothers in the Old Mine to Cor Kalom.","de":"Wir bringen das Sekret der Minecrawler, das unsere Brüder in der Alten Mine gewinnen, zu Cor Kalom."}},{"speaker":"npc","text":{"pl":"Codziennie udajemy się do kopalni po nową porcję wydzieliny.","en":"We go to the Old Mine every day to collect it.","de":"Einmal täglich gehen wir zur Alten Mine, um es abzuholen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_permanent_15_00_0', 'TPL_1439_GorNaDrak', '{"id":"missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_permanent_15_00_0","npcId":"TPL_1439_GorNaDrak","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1439_GorNaDrak.d","sourceFunction":"DIA_GorNaDrak_Permanent_Info","outputIds":["DIA_GorNaDrak_Permanent_15_00","DIA_GorNaDrak_Permanent_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Czy macie już wystarczająco dużo napoju, by przywołać Śniącego?","en":"Have you enough of the potion for the great invocation of the Sleeper?","de":"Habt ihr schon genug Elixier für die große Anrufung des Schläfers?"}},{"speaker":"npc","text":{"pl":"Niestety! Nasi myśliwi polują na pełzacze dniem i nocą, ale wciąż nie mamy dość wydzieliny.","en":"No - We still have to collect much more - our minecrawler hunting units are in action day and night.","de":"Nein - Wir müssen noch ''ne Menge sammeln - in der Alten Mine sind unsere Minecrawler-Jagdtrupps Tag und Nacht im Einsatz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_was_sekret_15_00_0', 'TPL_1439_GorNaDrak', '{"id":"missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_was_sekret_15_00_0","npcId":"TPL_1439_GorNaDrak","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1439_GorNaDrak.d","sourceFunction":"DIA_GorNaDrak_WasSekret_Info","outputIds":["DIA_GorNaDrak_WasSekret_15_00","DIA_GorNaDrak_WasSekret_09_01"],"lines":[{"speaker":"hero","text":{"pl":"Co to za wydzielina?","en":"What kind of secretion is it?","de":"Was ist das für ein Sekret?"}},{"speaker":"npc","text":{"pl":"Pozyskujemy ją z wnętrzności pełzaczy. Przy odrobinie ostrożności można wyciąć ich gruczoły jadowe.","en":"We obtain it from the mandibles of the minecrawlers. If you know how to do it, you can take them out without losing the secretion.","de":"Wir gewinnen es aus den Zangen der Minecrawler. Wenn man weiß wie, kann man sie herausnehmen, ohne dass das Sekret verloren geht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_what_for_15_00_0', 'TPL_1439_GorNaDrak', '{"id":"missions_dia_tpl_1439_gor_na_drak_dia_gor_na_drak_what_for_15_00_0","npcId":"TPL_1439_GorNaDrak","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1439_GorNaDrak.d","sourceFunction":"DIA_GorNaDrak_WhatFor_Info","outputIds":["DIA_GorNaDrak_WhatFor_15_00","DIA_GorNaDrak_WhatFor_09_01","DIA_GorNaDrak_WhatFor_09_02","DIA_GorNaDrak_WhatFor_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Po co Cor Kalomowi ta wydzielina?","en":"What does Cor Kalom need the secretion for?","de":"Wofür braucht Cor Kalom das Sekret?"}},{"speaker":"npc","text":{"pl":"Z tego co wiem, przyrządza z nich napój, który zwiększa magiczne zdolności Nowicjuszy.","en":"As far as I know, he makes a potion with it which increases the magic powers of a novice.","de":"Soweit ich weiß, gewinnt er daraus ein Elixier, das die magische Kraft eines Novizen steigert."}},{"speaker":"npc","text":{"pl":"Przygotowujemy się teraz do wielkiego przyzwania, więc potrzebujemy jak najwięcej tej wydzieliny.","en":"Since we are preparing for the great invocation, he can''t get enough of the stuff.","de":"Seit wir uns auf die große Anrufung vorbereiten, kann er gar nicht genug von dem Zeug bekommen."}},{"speaker":"npc","text":{"pl":"Przy pomocy tego napoju Nowicjusze przywołają Śniącego.","en":"With the aid of the potion, he''ll prepare the novices for the great day.","de":"Mit Hilfe des Elixiers will er die Novizen auf den großen Tag vorbereiten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1455_gor_boba_info_tpl_1455_gor_boba_08_01_0', 'TPL_1455_GorBoba', '{"id":"missions_dia_tpl_1455_gor_boba_info_tpl_1455_gor_boba_08_01_0","npcId":"TPL_1455_GorBoba","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1455_GorBoba.d","sourceFunction":"Info_TPL_1455_GorBoba_Info","outputIds":["Info_TPL_1455_GorBoba_08_01"],"lines":[{"speaker":"npc","text":{"pl":"Odejdź stąd, nie jesteś tu mile widziany.","en":"Get lost, you aren''t wanted here.","de":"Verschwinde, du bist hier nicht erwünscht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1455_gor_boba_info_tpl_1455_gor_boba1_08_05_4', 'TPL_1455_GorBoba', '{"id":"missions_dia_tpl_1455_gor_boba_info_tpl_1455_gor_boba1_08_05_4","npcId":"TPL_1455_GorBoba","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1455_GorBoba.d","sourceFunction":"Info_TPL_1455_GorBoba1_Info","outputIds":["Info_TPL_1455_GorBoba1_08_05"],"lines":[{"speaker":"npc","text":{"pl":"Przygotuj się na spotkanie ze stwórcą!","en":"Prepare to meet your Creator!","de":"Mache dich bereit, deinem Schöpfer gegenüber zu treten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_tpl_1455_gor_boba_info_tpl_1455_gor_boba1_15_01_0', 'TPL_1455_GorBoba', '{"id":"missions_dia_tpl_1455_gor_boba_info_tpl_1455_gor_boba1_15_01_0","npcId":"TPL_1455_GorBoba","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_TPL_1455_GorBoba.d","sourceFunction":"Info_TPL_1455_GorBoba1_Info","outputIds":["Info_TPL_1455_GorBoba1_15_01","Info_TPL_1455_GorBoba1_08_02","Info_TPL_1455_GorBoba1_08_03","Info_TPL_1455_GorBoba1_15_04"],"lines":[{"speaker":"hero","text":{"pl":"A co, spróbujesz mnie powstrzymać?","en":"And YOU are gonna stop me?","de":"Willst DU mich aufhalten?"}},{"speaker":"npc","text":{"pl":"TAK! Powstrzymam cię. Nie przeszkodzisz mistrzowi Kalomowi w przebudzeniu Śniącego.","en":"YES! I will stop you - you won''t prevent Master Kalom from awakening the Sleeper.","de":"JA! Ich werde dich aufhalten, damit du Meister Kalom nicht von seinem Vorhaben abhalten kannst, den Schläfer zu erwecken."}},{"speaker":"npc","text":{"pl":"Nie próbuj mnie atakować. Arcykapłan przekazał część swojej mocy Mistrzowi Kalomowi i nam. Jesteśmy nieśmiertelni!","en":"Don''t try to attack me, the high priest has transferred part of his powers to Master Kalom and us. Now we are immortal.","de":"Versuche nicht, mich anzugreifen, der Hohepriester hat Meister Kalom und uns anderen einen Teil seiner Macht verliehen, wir sind nun unsterblich."}},{"speaker":"hero","text":{"pl":"Ja ci pokażę tę waszą nieśmiertelność!","en":"I''ll show you how immortal you are!","de":"Ich kann dir zeigen, wie unsterblich du bist!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_511_herek_dia_herek_anlegen_15_00_0', 'VLK_511_Herek', '{"id":"missions_dia_vlk_511_herek_dia_herek_anlegen_15_00_0","npcId":"VLK_511_Herek","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_511_Herek.d","sourceFunction":"DIA_Herek_Anlegen_Info","outputIds":["DIA_Herek_Anlegen_15_00","DIA_Herek_Anlegen_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Myślisz, że taki twardziel z ciebie? Może spróbujesz szczęścia ze mną?!","en":"So you think you''re one of the wild boys, do you? Why don''t you try it with me ...","de":"So, du denkst also, du bist einer von den Harten? Versuch''s doch mal bei mir ..."}},{"speaker":"npc","text":{"pl":"Chcesz dostać w czapę? Cóż, nasz klient - nasz pan!","en":"You wanna get whacked? Alright, if that''s what you want!!","de":"Du willst''n paar aufs Maul?! Kannst du haben!!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_511_herek_dia_herek_bully_01_00_0', 'VLK_511_Herek', '{"id":"missions_dia_vlk_511_herek_dia_herek_bully_01_00_0","npcId":"VLK_511_Herek","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_511_Herek.d","sourceFunction":"DIA_Herek_Bully_Info","outputIds":["DIA_Herek_Bully_01_00","DIA_Herek_Bully_15_01","DIA_Herek_Bully_01_02","DIA_Herek_Bully_01_03"],"lines":[{"speaker":"npc","text":{"pl":"Zaczekaj! Słyszałem, że gadałeś z Bloodwynem?","en":"Hang on! I hear you''ve spoken to Bloodwyn?","de":"Warte doch mal! Ich hab'' gehört, du hast dich mit Bloodwyn unterhalten?"}},{"speaker":"hero","text":{"pl":"A co? Czego chcesz?","en":"Why? What do you want?","de":"Warum? Was willst du?"}},{"speaker":"npc","text":{"pl":"Niezły z ciebie gość! Niewielu ma tyle odwagi, żeby mu podskoczyć!","en":"It was real cool of ya to refuse to pay him protection money!","de":"Fand ich echt gut von dir, dass du dich geweigert hast, ihm Schutzgeld zu zahlen!"}},{"speaker":"npc","text":{"pl":"A to oznacza, że teraz my wszyscy będziemy musieli płacić twoją dolę.","en":"It means we''re all gonna have to pay your share as well!","de":"Das heißt, wir anderen müssen deinen Teil mitbezahlen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_511_herek_dia_herek_bully_01_04_4', 'VLK_511_Herek', '{"id":"missions_dia_vlk_511_herek_dia_herek_bully_01_04_4","npcId":"VLK_511_Herek","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_511_Herek.d","sourceFunction":"DIA_Herek_Bully_Info","outputIds":["DIA_Herek_Bully_01_04"],"lines":[{"speaker":"npc","text":{"pl":"Postaram się, żebyś o tym pamiętał, gdy Bloodwyn znów poprosi cię o datek.","en":"I''ll make sure you remember next time he asks you.","de":"Ich werde dafür sorgen, dass du dich daran erinnerst, wenn er dich das nächste Mal fragt ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_511_herek_dia_herek_motz_01_04_4', 'VLK_511_Herek', '{"id":"missions_dia_vlk_511_herek_dia_herek_motz_01_04_4","npcId":"VLK_511_Herek","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_511_Herek.d","sourceFunction":"DIA_Herek_Motz_Info","outputIds":["DIA_Herek_Motz_01_04"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz dlaczego tu trafiłem? Zabiłem dwunastu ludzi jednej nocy, ot - tak sobie... Hi hi hi!","en":"D''you know why I''m here? I killed a dozen people in one night, just like that... He he he!","de":"Weißt du, warum ich hier bin? In einer Nacht habe ich ein Dutzend Leute umgebracht. Einfach nur so ... hä hä hä!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_511_herek_dia_herek_motz_15_00_0', 'VLK_511_Herek', '{"id":"missions_dia_vlk_511_herek_dia_herek_motz_15_00_0","npcId":"VLK_511_Herek","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_511_Herek.d","sourceFunction":"DIA_Herek_Motz_Info","outputIds":["DIA_Herek_Motz_15_00","DIA_Herek_Motz_01_01","DIA_Herek_Motz_15_02","DIA_Herek_Motz_01_03"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać?","en":"And, how''s things?","de":"Na, wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"W tym obozie jest miejsce tylko dla jednego z nas!","en":"There ain''t enough room in this camp for the two of us!","de":"In diesem Lager ist nicht genug Platz für uns beide!"}},{"speaker":"hero","text":{"pl":"Co proszę?","en":"Pardon me?","de":"Bitte was?"}},{"speaker":"npc","text":{"pl":"Gdyby to zależało ode mnie, dawno już byś nie żył!","en":"If it was up to me, you wouldn''t last out here for long!","de":"Wenn es nach mir ginge, würdest du hier nicht alt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_hello_03_04_4', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_hello_03_04_4","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_Hello_Info","outputIds":["DIA_Dusty_Hello_03_04"],"lines":[{"speaker":"npc","text":{"pl":"Podobno jest tam o wiele lepiej. Przynajmniej nie trzeba harować na tych darmozjadów Gomeza.","en":"I think I''d better go there instead of slaving away for Gomez.","de":"Ich glaube, ich sollte besser zu denen gehen, als mir weiter für Gomez den Rücken krumm zu schuften."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_hello_15_00_0', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_hello_15_00_0","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_Hello_Info","outputIds":["DIA_Dusty_Hello_15_00","DIA_Dusty_Hello_03_01","DIA_Dusty_Hello_03_02","DIA_Dusty_Hello_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Cześć, jestem tu nowy. Jak leci?","en":"Hi! I''m new here - how''s things?","de":"Hi! Ich bin neu hier - wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Zejdź mi z oczu. Harowałem pod ziemią przez ostatnie dwa tygodnie. I za co?!","en":"Go away! I''ve been working my ass off in the mines for the last two weeks. And what for?","de":"Ach hör auf! Ich hab'' die letzten zwei Wochen in den Minen geschuftet. Und wofür?"}},{"speaker":"npc","text":{"pl":"Parę nędznych bryłek rudy - nic ponad to! Większość z tego musiałem wydać na żywność.","en":"Some sad lumps of ore is all I got. I had to spend most of it on food.","de":"Ein paar lausige Brocken Erz sind mir geblieben. Das meiste ging für Essen drauf."}},{"speaker":"npc","text":{"pl":"Rozmawiałem niedawno z Baal Parvezem. Opowiedział mi wiele ciekawych rzeczy o Obozie Sekty.","en":"I talked to Baal Parvez down there. He told me some interesting things about the Sect Camp.","de":"Ich hab'' mich mit Baal Parvez da unten unterhalten. Er hat mir ein paar interessante Sachen über das Lager der Sekte erzählt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_iwould_go_15_00_0', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_iwould_go_15_00_0","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_IWouldGo_Info","outputIds":["DIA_Dusty_IWouldGo_15_00","DIA_Dusty_IWouldGo_03_01","DIA_Dusty_IWouldGo_03_02"],"lines":[{"speaker":"hero","text":{"pl":"To znaczy, że odprowadzę cię do obozu Bractwa.","en":"I WILL go with you to the Sect Camp.","de":"Ich WERDE mit dir zum Sektenlager gehen."}},{"speaker":"npc","text":{"pl":"To wspaniale! Jestem gotowy do drogi. Możemy ruszać w każdej chwili.","en":"Great, man! I''m ready. We can start as soon as you want.","de":"Gut, Mann! Ich bin bereit. Wir können los, sobald du so weit bist."}},{"speaker":"npc","text":{"pl":"Ale nie zapominaj - potrzebujemy 100 bryłek rudy dla Strażników.","en":"But don''t forget - we need 100 ore for the guards.","de":"Aber vergiss nicht - wir brauchen 100 Erz für die Wachen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_lets_go_15_00_0', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_lets_go_15_00_0","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_LetsGo_Info","outputIds":["DIA_Dusty_LetsGo_15_00","DIA_Dusty_LetsGo_03_01","DIA_Dusty_LetsGo_03_02","DIA_Dusty_LetsGo_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy - możemy ruszać.","en":"I''m ready - let''s go!","de":"Ich bin bereit - lass uns gehen."}},{"speaker":"npc","text":{"pl":"Dobra - wyjdźmy południową bramą. Przy północnym wyjściu nic nie wskóramy. Tamtejsi Strażnicy są nieprzekupni.","en":"Okay - let''s take the south gate - the north gate is of no use, it''s impossible to bribe the guards there.","de":"Okay - lass uns durchs Südtor gehen - auf keinen Fall durchs Nordtor - die Wachen dort lassen sich garantiert nicht bestechen."}},{"speaker":"npc","text":{"pl":"Wolałbym, żebyś to ty zajął się całą tą sprawą z rudą. Ja się nie nadaję do takich rzeczy.","en":"And perhaps you should see to the ore - I''m not very good at that kind of thing.","de":"Und die Sache mit dem Erz regelst du am besten - ich bin nicht sehr gut in so was."}},{"speaker":"hero","text":{"pl":"Dobrze - ruszajmy!","en":"Okay - let''s move!","de":"Gut - also los!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_met_melvin_15_00_0', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_met_melvin_15_00_0","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_MetMelvin_Info","outputIds":["DIA_Dusty_MetMelvin_15_00","DIA_Dusty_MetMelvin_03_01","DIA_Dusty_MetMelvin_15_02","DIA_Dusty_MetMelvin_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Byłem w Obozie Sekty i rozmawiałem z Melvinem.","en":"I was in the Sect Camp and met Melvin.","de":"Ich war im Lager der Sekte und hab'' Melvin getroffen."}},{"speaker":"npc","text":{"pl":"Naprawdę?! I co powiedział?","en":"And? What did he say?","de":"Und? Was sagt er?"}},{"speaker":"hero","text":{"pl":"Najwyraźniej przedkłada życie w Bractwie nad ciągłe zatargi ze Strażnikami.","en":"Apparently he likes it more than getting harassed by the guards.","de":"Es gefällt ihm anscheinend besser, als sich von den Gardisten schikanieren zu lassen."}},{"speaker":"npc","text":{"pl":"No nie! Ten stary cap wyleguje się, podczas gdy ja muszę tu tyrać jak wół! Już ja mu pokażę... Ale nie uda mi się opuścić tego obozu.","en":"Hey man! He has all the fun for himself? I have to go there. But I''ll never make it out of the Camp.","de":"Hey, Mann! Er hat den ganzen Spaß ohne mich? Ich muss da hin. Aber ich komme nie aus dem Lager raus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_met_melvin_15_04_4', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_met_melvin_15_04_4","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_MetMelvin_Info","outputIds":["DIA_Dusty_MetMelvin_15_04","DIA_Dusty_MetMelvin_03_05","DIA_Dusty_MetMelvin_03_06"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego nie?","en":"Really? Why not?","de":"So? Warum nicht?"}},{"speaker":"npc","text":{"pl":"Strażnicy dowiedzieli się, że zamierzam stąd odejść. Chyba za dużo o tym gadałem.","en":"The guards have found out that I wanna leave, I guess I talk too much.","de":"Die Gardisten haben spitz gekriegt, dass ich mich verdrücken will - schätze, ich hab'' zu viel geredet."}},{"speaker":"npc","text":{"pl":"Potrzebuję przynajmniej 100 bryłek rudy, żeby ich przekupić.","en":"I need at least 100 ore to bribe the guards.","de":"Ich bräuchte mindestens 100 Erz, um die Wachen zu bestechen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_offer100_ore_15_00_0', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_offer100_ore_15_00_0","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_Offer100Ore_Info","outputIds":["DIA_Dusty_Offer100Ore_15_00","DIA_Dusty_Offer100Ore_03_01","DIA_Dusty_Offer100Ore_15_02","DIA_Dusty_Offer100Ore_03_03"],"lines":[{"speaker":"hero","text":{"pl":"A gdybym tak dał ci te 100 bryłek?","en":"What if I gave you the 100 ore for the guards?","de":"Was wäre, wenn ich dir die 100 Erz für die Wachen geben würde?"}},{"speaker":"npc","text":{"pl":"Zrobiłbyś to? Ale dlaczego?","en":"You''d do that? Why?","de":"Das würdest du tun? Warum?"}},{"speaker":"hero","text":{"pl":"Cóż, powiedzmy, że nie tylko ty wolisz życie w Bractwie od Starego Obozu.","en":"Well, let''s say you aren''t the only one who''d prefer you to hang around in the Sect Camp.","de":"Nun, sagen wir mal, du bist nicht der einzige, der dein dummes Grinsen gerne im Sektenlager sehen würde."}},{"speaker":"npc","text":{"pl":"To znaczy, że chcesz pójść ze mną?","en":"You mean you wanna come with me?","de":"Soll das heißen, du willst mit mir dahin gehen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_524_dusty_dia_dusty_why_not_leave_15_00_0', 'VLK_524_Dusty', '{"id":"missions_dia_vlk_524_dusty_dia_dusty_why_not_leave_15_00_0","npcId":"VLK_524_Dusty","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_524_Dusty.d","sourceFunction":"DIA_Dusty_WhyNotLeave_Info","outputIds":["DIA_Dusty_WhyNotLeave_15_00","DIA_Dusty_WhyNotLeave_03_01","DIA_Dusty_WhyNotLeave_03_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie podoba ci się tutaj? To dlaczego po prostu nie odejdziesz?","en":"You don''t like it here? Why don''t you just go then?","de":"Dir gefällt''s hier nicht? Wieso gehst du dann nicht einfach?"}},{"speaker":"npc","text":{"pl":"Bo nie wiem, co mnie tam czeka. Miałem tutaj kumpla - nazywał się Melvin. Poszedł do obozu na bagnie jakiś tydzień temu.","en":"Because I''m not quite sure what to expect there. I had a pal here - his name was Melvin. He headed off to the Sect Camp a week ago.","de":"Weil ich nicht sicher bin, was mich da erwartet. Ich habe ''nen Kumpel hier gehabt - Melvin heißt er. Er ist vor einer Woche ins Sektenlager abgehauen."}},{"speaker":"npc","text":{"pl":"Ale od tej pory nie mam od niego żadnych wieści. Dopóki się do mnie nie odezwie, wolę się stąd nie ruszać!","en":"But since then I haven''t heard of him. And as long as I don''t get a message from him, I''ll stay here!","de":"Aber ich habe seitdem nichts mehr von ihm gehört. Und so lange sich das nicht ändert, bleibe ich besser hier!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_nc_03_04_4', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_nc_03_04_4","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdNC_Info","outputIds":["DIA_Guy_AdNC_03_04"],"lines":[{"speaker":"npc","text":{"pl":"Jedyni ludzie, którzy mają tam coś do powiedzenia to Magowie Wody. Ale oni spędzają całe dnie na badaniu Bariery.","en":"The only ones powerful enough to have a say there are the water mages, but they''re too busy studying the Barrier all day.","de":"Die einzigen, die mächtig genug wären, den Laden zu schmeißen, sind die Wassermagier, und die forschen den ganzen Tag an der Barriere herum."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_nc_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_nc_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdNC_Info","outputIds":["DIA_Guy_AdNC_15_00","DIA_Guy_AdNC_03_01","DIA_Guy_AdNC_03_02","DIA_Guy_AdNC_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Jakie są zalety Nowego Obozu?","en":"What are the advantages of the New Camp?","de":"Was spricht für das Neue Lager?"}},{"speaker":"npc","text":{"pl":"Jeśli nie masz nic przeciwko poderżniętemu gardłu, możesz tam śmiało iść.","en":"If you''re cool about getting your throat cut for a slice of bread, you should go there.","de":"Wenn du kein Problem damit hast, wegen einem Stück Brot die Kehle durchgeschnitten zu kriegen, bist du da richtig!"}},{"speaker":"npc","text":{"pl":"Nie, nie jest tam aż tak źle, ale to zupełnie inne osiedle.","en":"No - it''s not that bad. But it''s different from here.","de":"Nein - ganz so schlimm ist es nicht. Aber es geht anders zu als hier."}},{"speaker":"npc","text":{"pl":"Tutaj o względny porządek troszczy się Gomez. W Nowym Obozie natomiast pojęcie porządku nie istnieje.","en":"Here Gomez takes care that things are sort of peaceful. In the New Camp, there is no law.","de":"Hier sorgt Gomez dafür, das alles halbwegs ruhig bleibt. Im Neuen Lager gibt es kein Gesetz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_oc_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_oc_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdOC_Info","outputIds":["DIA_Guy_AdOC_15_00","DIA_Guy_AdOC_03_01","DIA_Guy_AdOC_03_02"],"lines":[{"speaker":"hero","text":{"pl":"Jakie są zalety Starego Obozu?","en":"What are the advantages of the Old Camp?","de":"Was sind die Vorteile des Alten Lagers?"}},{"speaker":"npc","text":{"pl":"Jeśli zapłacisz Strażnikom za ochronę, będziesz mógł żyć we względnym spokoju. Strażnicy pilnują, żeby ich ludziom nie działa się krzywda.","en":"If you pay protection money to the guards, you can have a laidback life here. They always interfere if one of the paying diggers is attacked.","de":"Wenn du den Gardisten dein Schutzgeld zahlst, hast du ein ruhiges Leben. Sie mischen sich in alle Kämpfe ein, in denen jemand angegriffen wird, den sie beschützen."}},{"speaker":"npc","text":{"pl":"Poza tym, tylko tutaj dostaniesz towary z zewnętrznego świata po przyzwoitych cenach. W innych obozach zapłacisz za nie fortunę!","en":"Besides, you can only get the goods from the outside world cheap here. These things are unaffordable in the other camps.","de":"Außerdem kommt man nur hier günstig an Außenwelt-Waren. In den anderen Lagern sind diese Sachen unbezahlbar."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_oc_back_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_oc_back_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdOC_BACK","outputIds":["DIA_Guy_AdOC_BACK_15_00","DIA_Guy_AdOC_BACK_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Chyba dość już usłyszałem o Starym Obozie.","en":"I think I''ve heard enough about the Old Camp.","de":"Ich denke, ich hab'' genug über''s Alte Lager gehört..."}},{"speaker":"npc","text":{"pl":"Podoba mi się tutaj.","en":"I like it here.","de":"Also, mir gefällt''s hier."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_oc_protection_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_oc_protection_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdOC_Protection","outputIds":["DIA_Guy_AdOC_Protection_15_00","DIA_Guy_AdOC_Protection_03_01"],"lines":[{"speaker":"hero","text":{"pl":"A co się dzieje, gdy walczy dwóch ludzi, którzy zapłacili za ochronę?","en":"And what if two people fight each other who both pay protection money?","de":"Und was ist, wenn zwei Leute kämpfen, die beide Schutzgeld zahlen?"}},{"speaker":"npc","text":{"pl":"W takiej sytuacji Strażnicy po prostu się przyglądają, czekając aż jeden z walczących zginie. Wtedy zabijają drugiego!","en":"Then the guards just watch - until one of them kills the other: Then they do him in.","de":"Dann sehen sich die Gardisten das in aller Seelenruhe an. Aber wehe, wenn der eine den anderen umbringt. Dann ist er selber dran!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_oc_warez_03_04_4', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_oc_warez_03_04_4","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdOC_Warez","outputIds":["DIA_Guy_AdOC_Warez_03_04"],"lines":[{"speaker":"npc","text":{"pl":"Zresztą łatwo ich rozpoznać właśnie po ich zbroi - tylko Strażnicy mogą takie nosić.","en":"You can always recognize them by their armor, they only sell it to other guards. You could never get hold of one as an outsider.","de":"Diese Rüstungen sind so was wie ihr Erkennungszeichen, die verkaufen sie nur an ihresgleichen, da kommst du als Fremder gar nicht ran."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_oc_warez_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_oc_warez_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdOC_Warez","outputIds":["DIA_Guy_AdOC_Warez_15_00","DIA_Guy_AdOC_Warez_03_01","DIA_Guy_AdOC_Warez_03_02","DIA_Guy_AdOC_Warez_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Jakie towary są tu szczególnie cenne?","en":"What goods are considered precious here?","de":"Was sind hier wertvolle Waren?"}},{"speaker":"npc","text":{"pl":"Wszystko, co pochodzi z zewnętrznego świata: chleb, ser, boczek, ale przede wszystkim piwo i wino. W kolonii wytwarza się tylko tę paskudną ryżówkę!","en":"Everything from the outside world. Bread, cheese, bacon and above all beer and wine - not the cheap rice schnapps from the New Camp, but really good stuff.","de":"Alles, was aus der Außenwelt kommt. Brot, Käse, Schinken und vor allem Bier und Wein - nicht der billige Reisschnaps aus dem Neuen Lager, sondern richtig guter Stoff."}},{"speaker":"npc","text":{"pl":"Zawsze można zarobić na broni, a zbroje są NIEZWYKLE kosztowne.","en":"You always get a good price for weapons, and armor is REALLY expensive.","de":"Für Waffen bekommt man fast immer was und Rüstungen sind RICHTIG teuer."}},{"speaker":"npc","text":{"pl":"Strażnicy zdjęli zbroje z zabitych królewskich rycerzy.","en":"The guards took the old armor off the prison guards after they killed them.","de":"Die Gardisten haben sich die alten Rüstungen der Aufseher unter den Nagel gerissen, nachdem sie sie alle umgebracht hatten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_st_03_04_4', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_st_03_04_4","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdST_Info","outputIds":["DIA_Guy_AdST_03_04"],"lines":[{"speaker":"npc","text":{"pl":"Ze wszystkich trzech osiedli chyba najłatwiej zostać członkiem obozu na bagnie.","en":"None of the three camps seems to be as much in need of new people as the Sect Camp.","de":"Keines der drei Lager scheint so dringend neue Leute zu brauchen wie das der Sekte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_ad_st_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_ad_st_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_AdST_Info","outputIds":["DIA_Guy_AdST_15_00","DIA_Guy_AdST_03_01","DIA_Guy_AdST_03_02","DIA_Guy_AdST_03_03"],"lines":[{"speaker":"hero","text":{"pl":"A co przemawia za przyłączeniem się do Sekty?","en":"Why should I join the sect?","de":"Warum sollte ich mich der Sekte anschließen?"}},{"speaker":"npc","text":{"pl":"O to zapytaj już kogoś z Obozu Bractwa.","en":"Well, you better ask somebody from the Sect Camp.","de":"Tja, das fragst du am besten einen, der von dort kommt."}},{"speaker":"npc","text":{"pl":"Kilku ich Nowicjuszy zawsze kręci się po obozie. Jestem pewien, że udzielą ci wyczerpujących informacji.","en":"There are always a couple of novices in the Camp, and I''m sure they can tell you a lot about the sect.","de":"Es sind immer einige Novizen im Lager, die können dir sicher ''ne Menge über die Sekte erzählen."}},{"speaker":"npc","text":{"pl":"Osobiście nigdy tam nie byłem, ale jeśli wierzyć we wszystko, co o nich mówią, muszą być bardzo hojni.","en":"I''ve never been there myself. But according to everything that''s said, they must be really generous.","de":"Ich war selbst nie da. Aber nach allem, was man hört, sollen sie sehr großzügig sein."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_hello_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_hello_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_Hello_Info","outputIds":["DIA_Guy_Hello_15_00","DIA_Guy_Hello_03_01","DIA_Guy_Hello_15_02","DIA_Guy_Hello_03_03"],"lines":[{"speaker":"hero","text":{"pl":"Witam!","en":"Hello!","de":"Hallo!"}},{"speaker":"npc","text":{"pl":"Mhm? Nie widziałem cię jeszcze tutaj. Jesteś nowy, prawda?","en":"Mhm? I haven''t seen you before - you are new here, aren''t you?","de":"Hm? Dich hab'' ich hier noch nie gesehen - du bist neu hier, oder?"}},{"speaker":"hero","text":{"pl":"Tak, trafiłem tu niedawno...","en":"Just recently arrived...","de":"Vor kurzem angekommen ..."}},{"speaker":"npc","text":{"pl":"Zdecydowałeś już, do którego obozu dołączysz?","en":"Have you already decided which camp you want to join?","de":"Hast du dir schon überlegt, welchem Lager du dich anschließen willst?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_hello_15_04_4', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_hello_15_04_4","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_Hello_Info","outputIds":["DIA_Guy_Hello_15_04","DIA_Guy_Hello_03_05","DIA_Guy_Hello_03_06"],"lines":[{"speaker":"hero","text":{"pl":"Nie. Masz dla mnie jakieś sugestie?","en":"No, what do you think?","de":"Nein, was würdest du mir raten?"}},{"speaker":"npc","text":{"pl":"Cóż, to zależy. Każdy obóz ma swoje wady i zalety.","en":"Well, it depends - each camp has its advantages, I guess.","de":"Kommt drauf an - jedes Lager hat seine Vorteile - denke ich."}},{"speaker":"npc","text":{"pl":"Dopóki nie podejmiesz decyzji, możesz zostać tutaj. Właśnie zwolniła się jedna chata.","en":"Until you''ve made your decision, you can stay here - a hut just became available.","de":"Bist du dir''s überlegt hast, kannst du hier wohnen - ist gerade ''ne Hütte freigeworden."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_530_guy_dia_guy_my_own_hut_15_00_0', 'VLK_530_Guy', '{"id":"missions_dia_vlk_530_guy_dia_guy_my_own_hut_15_00_0","npcId":"VLK_530_Guy","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_530_Guy.d","sourceFunction":"DIA_Guy_MyOwnHut_Info","outputIds":["DIA_Guy_MyOwnHut_15_00","DIA_Guy_MyOwnHut_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Którą chatę mogę zająć?","en":"Which of the huts can I take for myself?","de":"Welche von den Hütten kann ich für mich nehmen?"}},{"speaker":"npc","text":{"pl":"Tamtą, z niewielkim baldachimem.","en":"The hut over there with the little canopy is empty.","de":"Die Hütte da oben mit dem kleinen Vordach ist frei."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_536_kyle_dia_kyle_hut_rage_10_00_0', 'VLK_536_Kyle', '{"id":"missions_dia_vlk_536_kyle_dia_kyle_hut_rage_10_00_0","npcId":"VLK_536_Kyle","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_536_Kyle.d","sourceFunction":"DIA_Kyle_HutRage_Info","outputIds":["DIA_Kyle_HutRage_10_00"],"lines":[{"speaker":"npc","text":{"pl":"Ile razy mam wam powtarzać, sukinsyny, żebyście nie przebiegali przez moją chatę!","en":"How often have I told you bastards not to run through my hut!","de":"Wie oft hab'' ich euch Pennern gesagt, rennt nicht durch meine Hütte."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_536_kyle_dia_kyle_problem_10_04_4', 'VLK_536_Kyle', '{"id":"missions_dia_vlk_536_kyle_dia_kyle_problem_10_04_4","npcId":"VLK_536_Kyle","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_536_Kyle.d","sourceFunction":"DIA_Kyle_Problem_Info","outputIds":["DIA_Kyle_Problem_10_04","DIA_Kyle_Problem_10_05","DIA_Kyle_Problem_10_06","DIA_Kyle_Problem_10_07"],"lines":[{"speaker":"npc","text":{"pl":"Ale żaden z tych sukinkotów nie powiedział mi, co się może stać, jeśli ją tu jednak wybuduję!","en":"But none of these bastards told me what would happen if I still did it.","de":"Aber keiner von den Pennern hat mir gesagt, was passiert, wenn ich es doch tue."}},{"speaker":"npc","text":{"pl":"Jak wróciłem z kopalni kilka dni temu, miałem dodatkowe drzwi.","en":"When I came back from the mine a few days ago, I had a second door.","de":"Als ich vor ein paar Tagen aus der Mine wiederkam, hatte ich  ''ne zweite Tür."}},{"speaker":"npc","text":{"pl":"Banda wieprzy! Nienawidzę ich! Nie wyobrażasz sobie, jak ja ich NIENAWIDZĘ!!!","en":"Those pigs. I hate them. I can''t tell you how much I hate them.","de":"Diese Schweine. Ich hasse sie. Ich kann dir gar nicht sagen, wie ich sie hasse!"}},{"speaker":"npc","text":{"pl":"Teraz wszyscy przełażą przez moją chatę jakby nigdy nic. Każdy cholerny dupek!","en":"Now everybody runs through my hut. Every idiot.","de":"Jetzt rennt jeder durch meine Hütte. Jeder Arsch."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_536_kyle_dia_kyle_problem_15_00_0', 'VLK_536_Kyle', '{"id":"missions_dia_vlk_536_kyle_dia_kyle_problem_15_00_0","npcId":"VLK_536_Kyle","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_536_Kyle.d","sourceFunction":"DIA_Kyle_Problem_Info","outputIds":["DIA_Kyle_Problem_15_00","DIA_Kyle_Problem_10_01","DIA_Kyle_Problem_10_02","DIA_Kyle_Problem_10_03"],"lines":[{"speaker":"hero","text":{"pl":"Co cię ugryzło?","en":"What''s your problem?","de":"Was ist dein Problem?"}},{"speaker":"npc","text":{"pl":"Zostaw mnie w spokoju! Mam was wszystkich serdecznie dość!","en":"Leave me alone, man! Everyone''s a problem with ME!","de":"Mann, lass mich bloß in Ruhe! Jeder hier hat ein Problem mit mir!"}},{"speaker":"npc","text":{"pl":"Wszystko zaczęło się, gdy zbudowałem sobie tę chatę.","en":"It all started when I built my hut.","de":"Es fing alles damit an, dass ich meine Hütte gebaut hab''."}},{"speaker":"npc","text":{"pl":"Wszyscy mówili: nie buduj chaty tak blisko rowu.","en":"Don''t build your hut close to the ditch, they said.","de":"Bau deine Hütte nicht an den Graben, haben sie gesagt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_538_huno_dia_huno_how_long_15_00_0', 'VLK_538_Huno', '{"id":"missions_dia_vlk_538_huno_dia_huno_how_long_15_00_0","npcId":"VLK_538_Huno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_538_Huno.d","sourceFunction":"DIA_Huno_HowLong_Info","outputIds":["DIA_Huno_HowLong_15_00","DIA_Huno_HowLong_09_01","DIA_Huno_HowLong_09_02","DIA_Huno_HowLong_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak długo zajmuje wykucie jednego miecza?","en":"How long does it take you to make one blade?","de":"Wie lange brauchst du für eine Klinge?"}},{"speaker":"npc","text":{"pl":"To zależy. Jeśli chodzi o najprostsze ostrza, wystarczy kilka minut.","en":"That depends. I''m as fast as a hurricane with simple swords.","de":"Kommt drauf an. Ein einfaches Schwert mach'' ich dir schneller, als deine müden Augen zuschauen können."}},{"speaker":"npc","text":{"pl":"Oczywiście pod warunkiem, że jestem odpowiednio zmotywowany... Finansowo.","en":"Of course only on condition that the price motivates me.","de":"Vorausgesetzt, du motivierst mich mit einer entsprechenden Bezahlung."}},{"speaker":"npc","text":{"pl":"Oczywiście świry pokroju Świstaka muszą czekać na swoje cacka nieco dłużej.","en":"A freak like Whistler usually has to wait longer for his toy than other people.","de":"So''n Spinner wie der Whistler muss aber meistens länger auf sein Schmuckstück warten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_538_huno_dia_huno_how_long_15_04_4', 'VLK_538_Huno', '{"id":"missions_dia_vlk_538_huno_dia_huno_how_long_15_04_4","npcId":"VLK_538_Huno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_538_Huno.d","sourceFunction":"DIA_Huno_HowLong_Info","outputIds":["DIA_Huno_HowLong_15_04","DIA_Huno_HowLong_09_05","DIA_Huno_HowLong_09_06","DIA_Huno_HowLong_09_07"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego? Czyżby Świstak za mało ci zapłacił?","en":"Why? Doesn''t he pay enough?","de":"Wieso? Bezahlt er nicht gut?"}},{"speaker":"npc","text":{"pl":"Nie, wręcz przeciwnie. Za swój ostatni miecz dał mi 150 bryłek rudy.","en":"No, on the contrary. He gave me 150 ore for his last sword.","de":"Doch, ganz im Gegenteil. Für sein letztes Schwert hat er 150 Erz locker gemacht."}},{"speaker":"npc","text":{"pl":"Ale facet lubi bogate zdobienia i takie tam babskie fanaberie, a to oczywiście kosztuje!","en":"The guy is into ornaments and girlie stuff like that, and of course that''s not cheap.","de":"Irgendwie hat der Typ ein Faible für Ornamente und so ''nen Weiberkram, und das hat natürlich seinen Preis."}},{"speaker":"npc","text":{"pl":"Hej, ciekawski z ciebie facet, kolego!","en":"Hey, you ain''t curious at all, are you, pal.","de":"Hey, du bist ganz schön neugierig, Freundchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_538_huno_dia_huno_hows_your_business_15_00_0', 'VLK_538_Huno', '{"id":"missions_dia_vlk_538_huno_dia_huno_hows_your_business_15_00_0","npcId":"VLK_538_Huno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_538_Huno.d","sourceFunction":"DIA_Huno_HowsYourBusiness_Info","outputIds":["DIA_Huno_HowsYourBusiness_15_00","DIA_Huno_HowsYourBusiness_09_01","DIA_Huno_HowsYourBusiness_15_02","DIA_Huno_HowsYourBusiness_09_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak stoisz z pracą, kowalu?","en":"Well, blacksmith, how''s business?","de":"Na, Schmied, wie läuft das Geschäft?"}},{"speaker":"npc","text":{"pl":"A co cię to obchodzi?","en":"Why would you want to know?","de":"Was geht dich das an?"}},{"speaker":"hero","text":{"pl":"Być może mam dla ciebie zamówienie.","en":"I may have an order for you.","de":"Vielleicht habe ich einen Auftrag für dich."}},{"speaker":"npc","text":{"pl":"Czyżby? A cóż takiego, jeśli wolno spytać?","en":"Oh really? And what?","de":"Ach ja? Was denn?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_538_huno_dia_huno_hows_your_business_15_04_4', 'VLK_538_Huno', '{"id":"missions_dia_vlk_538_huno_dia_huno_hows_your_business_15_04_4","npcId":"VLK_538_Huno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_538_Huno.d","sourceFunction":"DIA_Huno_HowsYourBusiness_Info","outputIds":["DIA_Huno_HowsYourBusiness_15_04","DIA_Huno_HowsYourBusiness_09_05"],"lines":[{"speaker":"hero","text":{"pl":"Jeszcze się zastanowię.","en":"I''ll think about it.","de":"Ich überleg''s mir."}},{"speaker":"npc","text":{"pl":"Wróć, jak naprawdę będziesz czegoś potrzebował. Póki co - nie zawracaj mi głowy.","en":"Come back when you really need something and don''t get on my nerves.","de":"Komm wieder, wenn du was brauchst, und geh mir nicht auf die Nerven."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_538_huno_dia_huno_you_know_your_job_15_00_0', 'VLK_538_Huno', '{"id":"missions_dia_vlk_538_huno_dia_huno_you_know_your_job_15_00_0","npcId":"VLK_538_Huno","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_538_Huno.d","sourceFunction":"DIA_Huno_YouKnowYourJob_Info","outputIds":["DIA_Huno_YouKnowYourJob_15_00","DIA_Huno_YouKnowYourJob_09_01","DIA_Huno_YouKnowYourJob_09_02"],"lines":[{"speaker":"hero","text":{"pl":"Widzę, że znasz się na swoim fachu.","en":"It looks as if you knew what you were doing.","de":"Wie''s aussieht, beherrschst du dein Handwerk."}},{"speaker":"npc","text":{"pl":"Jeszcze nikt nie miał powodu do narzekania.","en":"Nobody ain''t complained yet.","de":"Bisher hat sich noch niemand beschwert."}},{"speaker":"npc","text":{"pl":"I lepiej, żeby nikt tego nie robił! Każdy dureń potrzebuje miecza, i to właśnie ode mnie dostają!","en":"But that would be a bad idea anyway. Every idiot here needs a sword, and that is what they get from me.","de":"Aber das will ich auch keinem raten. Jeder Pisser hier braucht ein Schwert, und das kriegen sie von mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_hallo_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_hallo_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Hallo_Info","outputIds":["DIA_Jesse_Hallo_15_00","DIA_Jesse_Hallo_03_01","DIA_Jesse_Hallo_03_02"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać?","en":"How''s things?","de":"Wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Jesteś tu nowy, co? Zapamiętaj sobie, żeby nigdy nie włazić w drogę Strażnikom.","en":"New here, are you? You better know that it''s no good getting into trouble with the guards.","de":"Neu hier, was? Du solltest wissen, dass man sich hier besser nicht mit den Gardisten anlegt."}},{"speaker":"npc","text":{"pl":"Jak zażądają od ciebie pieniędzy - zapłać. Inaczej ściągniesz sobie na głowę połowę Obozu.","en":"When they want protection money, you better pay, otherwise half the Camp''ll be against you.","de":"Wenn sie Schutzgeld wollen, zahlst du besser, sonst hast du bald das halbe Lager gegen dich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_mis_success_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_mis_success_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_MisSuccess_Info","outputIds":["DIA_Jesse_MisSuccess_15_00","DIA_Jesse_MisSuccess_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Zapłaciłem Bloodwynowi!","en":"I paid Bloodwyn!","de":"Ich habe Bloodwyn bezahlt!"}},{"speaker":"npc","text":{"pl":"Tak? To świetnie! No to teraz jesteśmy kwita.","en":"Yeah? Great! Then we''re quits now.","de":"Ja? Gut! Dann sind wir ja jetzt quitt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_mis_success_waaas_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_mis_success_waaas_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_MisSuccess_Waaas","outputIds":["DIA_Jesse_MisSuccess_Waaas_15_00","DIA_Jesse_MisSuccess_Waaas_03_01"],"lines":[{"speaker":"hero","text":{"pl":"COOO??? Wydałem 10 bryłek na cynk o którym i tak już wiedziałem?","en":"WHAAAT? I spent 10 ore on a clue I knew about anyway?","de":"WAAAS?! Ich hab'' 10 Erz ausgegeben für einen Tipp, den ich sowieso schon kannte!?"}},{"speaker":"npc","text":{"pl":"Na to wygląda.","en":"Apparently.","de":"Sieht so aus."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_mission_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_mission_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Mission_Info","outputIds":["DIA_Jesse_Mission_15_00","DIA_Jesse_Mission_03_01","DIA_Jesse_Mission_03_02"],"lines":[{"speaker":"hero","text":{"pl":"Dlaczego opowiedziałeś mi o Bloodwynie?","en":"Why did you tell me the story about Bloodwyn?","de":"Warum hast du mir die Sache mit Bloodwyn erzählt?"}},{"speaker":"npc","text":{"pl":"Bo za przysługę należy się przysługa. Jesteś mądrym chłopcem. Chyba się rozumiemy?","en":"Because favors can be returned. And you don''t look like somebody who wouldn''t understand that.","de":"Weil hier eine Hand die andere wäscht. Du siehst nicht so aus wie einer, der das nicht begreifen würde."}},{"speaker":"npc","text":{"pl":"JA wyświadczyłem ci właśnie przysługę, więc teraz TWOJA kolej, żeby mi się odwdzięczyć!","en":"And because I did YOU a favor, I''d like to give you the opportunity to return it.","de":"Und weil ich DIR jetzt einen Gefallen getan habe, möchte ich dir Gelegenheit geben, dich zu revanchieren."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_mission_forget_it_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_mission_forget_it_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Mission_ForgetIt","outputIds":["DIA_Jesse_Mission_ForgetIt_15_00","DIA_Jesse_Mission_ForgetIt_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie jestem ci nic winien!","en":"I don''t owe you anything!","de":"Ich schulde dir GAR nichts!"}},{"speaker":"npc","text":{"pl":"Więc nie mamy o czym mówić!","en":"Oh! Then get lost!","de":"(sauer) Dann vergiss es doch einfach!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_mission_no_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_mission_no_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Mission_NO","outputIds":["DIA_Jesse_Mission_NO_15_00","DIA_Jesse_Mission_NO_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Ja, miałbym zapłacić za ciebie? Chyba śnisz!","en":"Me, pay for you? Forget it!","de":"Ich für dich zahlen? Vergiss es!"}},{"speaker":"npc","text":{"pl":"Widzę, że myliłem się co do ciebie. W przyszłości nie oczekuj ode mnie pomocy.","en":"Apparently I was wrong about you. Don''t count on me in the future.","de":"So kann man sich in jemandem irren. Mit meiner Hilfe rechnest du am besten nicht mehr."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_mission_what_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_mission_what_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Mission_What","outputIds":["DIA_Jesse_Mission_What_15_00","DIA_Jesse_Mission_What_03_01","DIA_Jesse_Mission_What_03_02"],"lines":[{"speaker":"hero","text":{"pl":"Co dokładnie masz na myśli?","en":"What exactly do you have in mind?","de":"An was hattest du denn da gedacht?"}},{"speaker":"npc","text":{"pl":"Nie mam już rudy, a Bloodwyn i mnie zaczyna dobierać się do tyłka.","en":"I don''t have any ore left, and Bloodwyn has already fleeced me as well.","de":"Ich hab'' kein Erz mehr, und Bloodwyn hat schon versucht, das letzte Bröckchen aus mir rauszupressen."}},{"speaker":"npc","text":{"pl":"Pomogłem ci, więc mógłbyś zapłacić za mnie te 10 bryłek, które zalegam, co? Powiedz mu, że to ode mnie!","en":"Now that I''ve helped you, you could give him the 10 ore I owe him, couldn''t you? Tell him it''s from me.","de":"Jetzt, wo ich dir geholfen habe, könntest du ihm doch meine 10 Erz geben, oder? Sag ihm, sie kommen von mir."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_mission_yes_15_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_mission_yes_15_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Mission_YES","outputIds":["DIA_Jesse_Mission_YES_15_00","DIA_Jesse_Mission_YES_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Zobaczę co się da zrobić.","en":"I''ll see what I can do.","de":"Ich werd sehen, was ich machen kann ..."}},{"speaker":"npc","text":{"pl":"Dzięki, stary! Ocaliłeś mi życie! Daj mi znać, jak już wszystko załatwisz, dobra?","en":"Thanks, man! You just saved my day! Tell me when things are settled, will you?","de":"Danke, Mann! Du bist meine Rettung! Sag mir Bescheid, wenn die Sache gelaufen ist, ja?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_warn_03_00_0', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_warn_03_00_0","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Warn_Info","outputIds":["DIA_Jesse_Warn_03_00","DIA_Jesse_Warn_15_01","DIA_Jesse_Warn_03_02","DIA_Jesse_Warn_03_03"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty! Słyszałem, że nie chcesz płacić Bloodwynowi za ochronę!","en":"Hey, you! I learned you didn''t want to pay protection money to Bloodwyn?","de":"Hey, du! Ich hab'' gehört, du wolltest Bloodwyn kein Schutzgeld zahlen?"}},{"speaker":"hero","text":{"pl":"Czego chcesz?","en":"What do you want?","de":"Was willst du?"}},{"speaker":"npc","text":{"pl":"Chcę cię ostrzec! Bloodwyn zapłacił paru ludziom, żeby cię załatwili.","en":"To warn you! Bloodwyn paid some people: They''re gonna do you in.","de":"Dich warnen! Bloodwyn hat einige Leute bezahlt, damit sie dir Ärger machen."}},{"speaker":"npc","text":{"pl":"Widziałem, jak rozmawiał z paroma osobami, na przykład z tamtym gościem, Herekiem. Bóg wie, kogo jeszcze wynajął!","en":"I saw how he talked to people like Herek over there, and God knows who else he hired!","de":"Ich hab'' zum Beispiel gesehen, wie er mit Herek da drüben geredet hat. Und nur die Götter wissen, mit wem noch!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_564_jesse_dia_jesse_warn_15_04_4', 'VLK_564_Jesse', '{"id":"missions_dia_vlk_564_jesse_dia_jesse_warn_15_04_4","npcId":"VLK_564_Jesse","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_564_Jesse.d","sourceFunction":"DIA_Jesse_Warn_Info","outputIds":["DIA_Jesse_Warn_15_04","DIA_Jesse_Warn_03_05"],"lines":[{"speaker":"hero","text":{"pl":"Jeśli chodzi o Hereka, to twoje ostrzeżenie jest nieco spóźnione.","en":"Your warning about Herek is a bit late.","de":"Was Herek betrifft, kommt deine Warnung etwas spät."}},{"speaker":"npc","text":{"pl":"Na pewno rozmawiał z kimś jeszcze, możesz mi wierzyć. Uważaj na siebie.","en":"He must have talked to somebody else as well, that much I know. So do take care.","de":"Er muss noch mit jemand anderem geredet haben - so viel hab'' ich mitgekriegt. Also pass auf dich auf."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_b_gravo_help_attitude_angry_04_00_0', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_b_gravo_help_attitude_angry_04_00_0","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"B_Gravo_HelpAttitude","outputIds":["B_Gravo_HelpAttitude_ANGRY_04_00","B_Gravo_HelpAttitude_ANGRY_04_01","B_Gravo_HelpAttitude_ANGRY_04_02","B_Gravo_HelpAttitude_ANGRY_04_03"],"lines":[{"speaker":"npc","text":{"pl":"Zgadza się. Zagiął na ciebie parol.","en":"That''s right, you''re in his bad books.","de":"Stimmt, er ist nicht besonders gut auf dich zu sprechen."}},{"speaker":"npc","text":{"pl":"Poproszę paru ludzi, żeby go trochę uspokoili. 100 bryłek rudy i będzie po sprawie.","en":"I''ll have some people talk to him. 100 ore and I''ll take care of the problem.","de":"Ich werd'' zusehen, dass sich ein paar Leute mal mit ihm unterhalten. 100 Erz und ich erledige die Sache."}},{"speaker":"npc","text":{"pl":"Zobaczmy ile tu masz... Tak, powinno wystarczyć. Możesz uznać sprawę za niebyłą.","en":"Well, let''s see how much you have... Ah! Yeah, that should be enough. You can consider the affair settled.","de":"Lass sehen, wie viel du hast ... Ah! Das sollte reichen. Betrachte die Sache als erledigt."}},{"speaker":"npc","text":{"pl":"Tylko nikomu ani słowa. Zachowuj się, jakby w ogóle nic się nie stało.","en":"And don''t talk to anyone about it. Just behave as if nothing had happened at all.","de":"Und sprich mit keinem darüber. Tu einfach so, als wär'' nichts passiert."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_b_gravo_help_attitude_hostile_04_02_8', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_b_gravo_help_attitude_hostile_04_02_8","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"B_Gravo_HelpAttitude","outputIds":["B_Gravo_HelpAttitude_HOSTILE_04_02","B_Gravo_HelpAttitude_HOSTILE_04_03","B_Gravo_HelpAttitude_NoOre_15_01","B_Gravo_HelpAttitude_NoOre_04_02"],"lines":[{"speaker":"npc","text":{"pl":"Zobaczmy ile tu masz... Widzę, że ci się poszczęściło. Wezmę te 500 bryłek i spróbuję to wszystko odkręcić.","en":"Let''s see what you have there... You seem to be a rich boy. I''ll take the 500 and sort the thing out.","de":"Lass sehen, wie viel du hast ... Du scheinst ein reicher Bursche zu sein. Ich nehme die 500 und kümmere mich drum."}},{"speaker":"npc","text":{"pl":"I pamiętaj: nigdy, przenigdy nie wspominaj, że pomogłem ci załatwić tę sprawę. Trzymaj język za zębami. Zrozumiano?","en":"And remember: He is never ever to know that I took care of the problem - so don''t you talk to anybody about it, you understand?","de":"Und noch was: Er darf nie erfahren, dass ICH die Sache für dich geregelt habe - also rede mit KEINEM darüber!"}},{"speaker":"hero","text":{"pl":"Nie mam tyle przy sobie.","en":"Soviel hab'' ich nicht.","de":"Soviel hab'' ich nicht."}},{"speaker":"npc","text":{"pl":"Przykro mi, chłopcze, ale w takim razie nic nie mogę dla ciebie zrobić.","en":"Dann kann ich nichts für dich tun - tut mit leid, Junge.","de":"Dann kann ich nichts für dich tun - tut mit leid, Junge."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_b_gravo_help_attitude_no_ore_15_01_4', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_b_gravo_help_attitude_no_ore_15_01_4","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"B_Gravo_HelpAttitude","outputIds":["B_Gravo_HelpAttitude_NoOre_15_01","B_Gravo_HelpAttitude_NoOre_04_02","B_Gravo_HelpAttitude_HOSTILE_04_00","B_Gravo_HelpAttitude_HOSTILE_04_01"],"lines":[{"speaker":"hero","text":{"pl":"I don''t have that much.","en":"I don''t have that much.","de":"So viel hab'' ich nicht."}},{"speaker":"npc","text":{"pl":"Then I can''t do anything for you - I''m sorry, boy.","en":"Then I can''t do anything for you - I''m sorry, boy.","de":"Dann kann ich nichts für dich tun - tut mir Leid, Junge."}},{"speaker":"npc","text":{"pl":"To mają być kłopoty? To jest cholerna katastrofa! Obawiam się, że on najchętniej rozdarłby cię na strzępy.","en":"You call that trouble? That''s an understatement, I think. I think he would like to tear you into little pieces, boy.","de":"Ärger ist gar kein Ausdruck, Junge. Er würde dir am liebsten den Kopf abreißen."}},{"speaker":"npc","text":{"pl":"Spróbuję przekonać paru ludzi, żeby się za tobą wstawili, ale to nie będzie tanio kosztować. 500 bryłek rudy, jeśli nie więcej!","en":"It won''t be cheap if I''m to convince some people to calm him down again. It''ll cost you 500 ore at least.","de":"Wenn ich ein paar Jungs davon überzeugen soll, ihn wieder gut zu stimmen, wird das nicht billig. 500 Erz musst du schon hinlegen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_b_gravo_help_attitude_no_prob_04_00_12', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_b_gravo_help_attitude_no_prob_04_00_12","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"B_Gravo_HelpAttitude","outputIds":["B_Gravo_HelpAttitude_NoProb_04_00"],"lines":[{"speaker":"npc","text":{"pl":"Z tego co mi wiadomo, nie masz z nim żadnego zatargu.","en":"As far as I know he doesn''t have a problem with you - don''t worry.","de":"Soweit ich weiß, hat er kein Problem mit dir - mach dir keine Sorgen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_dia_gravo_hallo_04_04_4', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_dia_gravo_hallo_04_04_4","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"DIA_Gravo_Hallo_Info","outputIds":["DIA_Gravo_Hallo_04_04"],"lines":[{"speaker":"npc","text":{"pl":"Jeśli podpadniesz któremuś z wpływowych ludzi, zgłoś się do mnie. Razem coś wymyślimy.","en":"If you get into trouble with influential people here, I can help you sort the thing out.","de":"Wenn du hier Ärger mit einflussreichen Leuten hast, kann ich dafür sorgen, dass die Sache wieder ins Lot kommt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_dia_gravo_hallo_15_00_0', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_dia_gravo_hallo_15_00_0","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"DIA_Gravo_Hallo_Info","outputIds":["DIA_Gravo_Hallo_15_00","DIA_Gravo_Hallo_04_01","DIA_Gravo_Hallo_15_02","DIA_Gravo_Hallo_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Co słychać?","en":"How are you doing?","de":"Wie steht''s denn so?"}},{"speaker":"npc","text":{"pl":"Odkąd rzuciłem robotę w kopalni, nie mogę narzekać.","en":"Well, since I stopped working in the mine, I can''t really complain.","de":"Seit ich aufgehört habe, in der Mine zu arbeiten, lässt sich''s hier richtig gut leben."}},{"speaker":"hero","text":{"pl":"A skąd bierzesz środki na utrzymanie?","en":"And where do you get your ore from?","de":"Und woher kriegst du dein Erz?"}},{"speaker":"npc","text":{"pl":"Pomagam ludziom w rozwiązywaniu ich problemów.","en":"I help people who have problems.","de":"Ich helfe Leuten, die Probleme haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_dia_gravo_help_angry_now_15_00_0', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_dia_gravo_help_angry_now_15_00_0","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"DIA_Gravo_HelpAngryNow_Info","outputIds":["DIA_Gravo_HelpAngryNow_15_00","DIA_Gravo_HelpAngryNow_04_01"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mi pomóc? Chyba mam kłopoty.","en":"Can you help me - I think I''m in trouble.","de":"Kannst du mir helfen - ich glaub, ich hab'' Ärger."}},{"speaker":"npc","text":{"pl":"Mogę spróbować, ale uprzedzam - moja pomoc będzie cię kosztowała od 100 do 500 bryłek rudy!","en":"I think so, but I warn you, my help could cost between 100 and 500 ore.","de":"Ich denke schon, aber ich warne dich, die Sache kann dich zwischen 100 und 500 Erz kosten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_dia_gravo_help_how_04_04_4', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_dia_gravo_help_how_04_04_4","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"DIA_Gravo_HelpHow_Info","outputIds":["DIA_Gravo_HelpHow_04_04","DIA_Gravo_HelpHow_04_05"],"lines":[{"speaker":"npc","text":{"pl":"Oni szepną o tobie dobre słówko i Thorus przestanie się na ciebie boczyć. Oczywiście chłopcy nie zrobią tego za darmo. Takie przysługi kosztują.","en":"They put in a good word for you, and Thorus is your friend again. Of course the boys want to see some ore for these kind of favors. Your ore.","de":"Die legen ein gutes Wort für dich ein und Thorus ist wieder auf deiner Seite. Natürlich wollen die Jungs dafür Erz sehen. Dein Erz."}},{"speaker":"npc","text":{"pl":"A ja pilnuję, żeby ruda trafiła do właściwych osób...","en":"And I take care that your ore gets to the right people...","de":"Und ICH kümmere mich darum, dass dein Erz die richtigen Leute erreicht ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_dia_gravo_help_how_15_00_0', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_dia_gravo_help_how_15_00_0","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"DIA_Gravo_HelpHow_Info","outputIds":["DIA_Gravo_HelpHow_15_00","DIA_Gravo_HelpHow_04_01","DIA_Gravo_HelpHow_04_02","DIA_Gravo_HelpHow_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Gdybym miał kłopoty, TY mógłbyś mi pomóc? W jaki sposób?","en":"If I was in trouble, YOU could help me? How?","de":"Wenn ich hier Ärger habe, kannst DU mir also helfen? Wie?"}},{"speaker":"npc","text":{"pl":"No załóżmy, że nadepnąłeś na odcisk Thorusowi. Lepiej nigdy nie włazić mu w drogę, ale wypadki się zdarzają...","en":"Well, let''s assume you''re in trouble with Thorus. You better never get into trouble with him, but then, well, you never know.","de":"Nun - sagen wir mal, du hast Ärger mit Thorus. Du solltest es besser nie dazu kommen lassen, aber man weiß ja nie, was passiert."}},{"speaker":"npc","text":{"pl":"Thorus potrafi być bardzo uparty. Jak raz się na ciebie wkurzy, nie będzie chciał zamienić z tobą słowa. A to już bardzo niedobrze.","en":"Thorus can be quite stubborn - when he''s pissed off with you once, he''ll never talk to you again. And that''s a bad thing.","de":"Thorus kann ziemlich stur sein - wenn du''s dir einmal mit ihm verscherzt hast, redet er nicht mehr mit dir. Das ist schlecht."}},{"speaker":"npc","text":{"pl":"Jako żółtodziób, musisz go mieć po swojej stronie. Więc przychodzisz do mnie i mówisz w czym rzecz. Znam tu wiele osób, z których zdaniem liczy się nawet Thorus.","en":"As a greenhorn, you depend on him. So you come to see me. I know a lot of people here Thorus listens to.","de":"Denn als Neuer bist du auf ihn angewiesen. Also kommst du zu mir. Ich kenne ''ne Menge Leute hier, die Einfluss auf Thorus haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_dia_gravo_influence_04_04_4', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_dia_gravo_influence_04_04_4","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"DIA_Gravo_Influence_Info","outputIds":["DIA_Gravo_Influence_04_04"],"lines":[{"speaker":"npc","text":{"pl":"No i jest jeszcze Scatty. On rządzi na arenie, organizuje walki i takie tam. Wielu ludzi jest mu winnych pieniądze, więc on również jest sporą szychą.","en":"And then there''s Scatty. He''s in charge of the arena, and determines who fights and all that. Many people here owe him ore - he''s important as well.","de":"Und dann wäre da noch Scatty, er leitet die Arena, bestimmt wer kämpft und so. Es gibt viele hier, die ihm noch Erz schulden - auch an ihn kannst du dich halten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_572_gravo_dia_gravo_influence_15_00_0', 'VLK_572_Gravo', '{"id":"missions_dia_vlk_572_gravo_dia_gravo_influence_15_00_0","npcId":"VLK_572_Gravo","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_572_Gravo.d","sourceFunction":"DIA_Gravo_Influence_Info","outputIds":["DIA_Gravo_Influence_15_00","DIA_Gravo_Influence_04_01","DIA_Gravo_Influence_04_02","DIA_Gravo_Influence_04_03"],"lines":[{"speaker":"hero","text":{"pl":"Możesz mi powiedzieć, które Cienie należą do najbardziej wpływowych?","en":"Could you tell me which of the Shadows belongs to the influential people here?","de":"Kannst du mir sagen, wer von den Schatten hier zu den einflussreichen Leuten gehört?"}},{"speaker":"npc","text":{"pl":"Chcesz mieć po swojej stronie najważniejszych ludzi, co?","en":"You want to impress the right people, do you?","de":"Du willst die richtigen Leute beeindrucken, he?"}},{"speaker":"npc","text":{"pl":"Najpotężniejszym z Cieni jest Diego. Do jego zaufanych ludzi należą Rączka, Świstak i Zły.","en":"Diego has the most power of all the Shadows. He trusts Fingers, Whistler and Sly.","de":"Diego hat von allen Schatten am meisten zu melden. Zu seinen Vertrauten zählen Fingers, Whistler und Sly."}},{"speaker":"npc","text":{"pl":"Dexter i Fisk handlują na targowisku. Mają szeroką klientelę, w tym nawet Strażników, więc są dość wpływowi.","en":"Dexter and Fisk sell their stuff on the market square. They have many customers, even the guards, and that makes them rather influential.","de":"Dexter und Fisk verscherbeln ihre Sachen auf dem Marktplatz. Sie haben viele Kunden, selbst unter den Gardisten und sind dementsprechend einflussreich."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_first_exit_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_first_exit_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_FirstEXIT_Info","outputIds":["DIA_Mud_FirstEXIT_07_00","DIA_Mud_FirstEXIT_07_01"],"lines":[{"speaker":"npc","text":{"pl":"Hej, kolego! Nowy? Chyba cię jeszcze tu nie widziałem.","en":"Hey, man! New here? I haven''t seen you before.","de":"Hey, Mann! Neu hier? Dich hab'' ich hier noch nie gesehen."}},{"speaker":"npc","text":{"pl":"Przyłączę się do ciebie na chwilę, jeśli nie masz nic przeciwko. Przyda ci się przyjaciel...","en":"I''ll join you for a while, if you don''t mind. I''m sure you''ll need a friend.","de":"Wenn du nichts dagegen hast, komme ich ein Stück mit. Du kannst sicher einen Freund brauchen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_first_exit_komm_15_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_first_exit_komm_15_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_FirstEXIT_Komm","outputIds":["DIA_Mud_FirstEXIT_Komm_15_00","DIA_Mud_FirstEXIT_Komm_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Czemu nie? Chodźmy!","en":"Why not - come along!","de":"Warum nicht - komm mit!"}},{"speaker":"npc","text":{"pl":"Świetnie. Po drodze możemy sobie trochę porozmawiać.","en":"Great! We can talk while we''re going.","de":"Großartig! Wir können uns ja auf dem Weg etwas unterhalten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_first_exit_verpiss_15_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_first_exit_verpiss_15_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_FirstEXIT_Verpiss","outputIds":["DIA_Mud_FirstEXIT_Verpiss_15_00","DIA_Mud_FirstEXIT_Verpiss_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Spadaj!","en":"Get lost!","de":"Verpiss dich!"}},{"speaker":"npc","text":{"pl":"Oho, nie jesteśmy w humorze, co? Lepiej będzie jak pójdę z tobą!","en":"You''re not in a good mood today, are you? I better come with you...","de":"Bist heute nicht so gut drauf, was? Ich glaub'', ich komm'' mal besser mit ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_get_lost_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_get_lost_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Defeated_Info","outputIds":["DIA_Mud_GetLost_07_00","DIA_Mud_GetLost_15_01","DIA_Mud_GetLost_07_02"],"lines":[{"speaker":"npc","text":{"pl":"Hej, stary! Czemu mnie bijesz? Co ci takiego zrobiłem?","en":"Hey, man, you hit me! What was that for?","de":"Hey, Mann, du hast mich geschlagen! Was sollte das?"}},{"speaker":"hero","text":{"pl":"Za chwilę znowu ci przyłożę! Bardzo lubię to robić!","en":"I''ll hit you again in a second! I''m into that!","de":"Ich schlag'' dich gleich noch mal! Ich steh'' auf Schlagen!"}},{"speaker":"npc","text":{"pl":"Jakiś świr z ciebie, czy co? Nie chcę mieć z tobą nic wspólnego!","en":"You''re a lunatic, man! I don''t want to have anything to do with you!","de":"Mann, was bist DU denn für''n Freak! Mit dir will ich nichts mehr zu tun haben!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_get_lost_15_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_get_lost_15_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_GetLost_Info","outputIds":["DIA_Mud_GetLost_15_00","DIA_Mud_GetLost_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Spadaj!","en":"Get lost!","de":"Verpiss dich!"}},{"speaker":"npc","text":{"pl":"Chcesz być przez chwilę sam, tak? Rozumiem... Będę się trzymał na uboczu.","en":"You wanna be on your own for a while, do you? I understand... I''ll stay in the background...","de":"Willst ''nen Moment allein sein, hm? Kann ich verstehen ... Ich halt mich im Hintergrund ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_0_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_0_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_0_Info","outputIds":["DIA_Mud_Nerve_0_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Powiedz, dokąd idziemy? A może to niespodzianka?! Uwielbiam niespodzianki!","en":"Tell me, where are we going? Or is it supposed to be a surprise? I like surprises.","de":"Sag mal, wohin geht es eigentlich? Oder ist das eine Überraschung für mich? Ich mag Überraschungen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_1_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_1_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_1_Info","outputIds":["DIA_Mud_Nerve_1_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Nie zwracaj na mnie uwagi. Będę się trzymał ciebie, spokojna głowa.","en":"Don''t pay attention to me. I''ll just stay with you, don''t worry.","de":"Lass dich von mir nicht stören. Ich bleib'' einfach bei dir, keine Sorge."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_10_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_10_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_10_Info","outputIds":["DIA_Mud_Nerve_10_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz co? Wyświadczę ci przysługę. Wstawię się za tobą. Może wtedy zostaniesz przyjęty do Obozu. W ten sposób moglibyśmy spotykać się codziennie.","en":"You know what? I''ll do you a favor. I''ll put in a good word for you, then perhaps you''ll be admitted to the Camp. Then we could meet every day.","de":"Weißt du was? Ich tu dir einen Gefallen. Ich werde ein gutes Wort für dich einlegen. Dann nehmen sie dich vielleicht in das Lager auf. Dann können wir uns jeden Tag sehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_11_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_11_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_11_Info","outputIds":["DIA_Mud_Nerve_11_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Niektórzy tutaj mają mnie za jakiegoś wariata. Ale przecież ktoś taki jak ty nie zadawałby się z wariatem, prawda? Teraz wszyscy zrozumieją jak niesprawiedliwie mnie ocenili.","en":"Some people think I''m a complete lunatic. But somebody like you would never hang out with a lunatic. People would talk about that. So they''ll finally understand that they were wrong about me.","de":"Manche halten mich ja für einen durchgeknallten Spinner. Aber jemand wie du würde sich hier ja niemals mit einem Spinner sehen lassen. So was spricht sich ja rum. Also werden sie einsehen, dass sie sich in mir getäuscht haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_12_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_12_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_12_Info","outputIds":["DIA_Mud_Nerve_12_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Jestem moim najlepszym kumplem, wiesz? Inni tylko próbują się mnie pozbyć. Jestem ci bardzo wdzięczny, naprawdę!","en":"You''re my best friend here. The others only want to get rid of me all the time. I''m really grateful to you.","de":"Du bist mein bester Freund hier drinnen. Die anderen wollen mich immer nur loswerden. Ich bin dir echt dankbar."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_13_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_13_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_13_Info","outputIds":["DIA_Mud_Nerve_13_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Słuchaj, całe to bieganie zaczyna mnie męczyć. Może poszukamy sobie jakiegoś przytulnego gniazdka i chwilę odpoczniemy, co?","en":"Listen, this running around is really getting tiring. Shouldn''t we look for a cosy place and get comfy somewhere?","de":"Hör mal, die Rennerei wird langsam anstrengend. Wollen wir uns nicht irgendwo ein kuscheliges Plätzchen suchen und es uns gemütlich machen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_14_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_14_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_14_Info","outputIds":["DIA_Mud_Nerve_14_07_00","DIA_Mud_Nerve_14_15_01"],"lines":[{"speaker":"npc","text":{"pl":"Jesteś dla mnie jak starszy brat. Nigdy nie miałem starszego brata... Ani nawet młodszego! Moi rodzice mnie nie kochali, ale to musiało być dla nich bardzo trudne.","en":"You''re like a big brother to me. I never had a big brother. Or a small one. My parents didn''t want me. But I''m sure it was difficult for them.","de":"Du bist wie ein großer Bruder für mich. Ich hatte nie einen großen Bruder. Auch keinen kleinen. Meine Eltern wollten mich nicht behalten. Ich bin sicher, das fiel ihnen nicht leicht."}},{"speaker":"hero","text":{"pl":"Jaaasne.","en":"Sure it was.","de":"Bestimmt nicht."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_15_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_15_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_15_Info","outputIds":["DIA_Mud_Nerve_15_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Skąd jesteś? Na pewno cieszysz się, że znalazłeś tu bratnią duszę, kogoś, kto cię zrozumie. Jestem z Khorinis. Byłeś tam kiedyś? Zresztą - nieważne.","en":"Where are you from? You must be happy as well that you finally found somebody who understands you. I''m from Khorinis. Have you ever been there? Well, doesn''t matter anyway.","de":"Wo kommst du denn her? Du freust dich sicher auch so, dass du jetzt endlich jemanden gefunden hast, der dich versteht. Ich komme aus Khorinis. Warst du schon mal dort? Ist ja eigentlich auch egal."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_16_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_16_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_16_Info","outputIds":["DIA_Mud_Nerve_16_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Masz może dla mnie coś do jedzenia. Jestem jakby twoim gościem, więc uprzejmość nakazywałaby, abyś mnie czymś poczęstował. Nauczyłem się tego w Khorinis. Tam mieszkają uprzejmi ludzie.","en":"Have you got something to eat for me? Since I''m some sort of visitor, it''d be polite if you gave me something. That''s manners. My friends in Khorinis taught me that. They really liked me.","de":"Hast du was zu essen für mich? Da ich ja so was wie Besuch bin, fände ich es toll, wenn du mir was geben würdest. Das gehört sich so. Das haben mir meine Freunde in Khorinis beigebracht. Die hatten mich echt gerne."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_17_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_17_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_17_Info","outputIds":["DIA_Mud_Nerve_17_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Myślisz, że ktoś wpadnie do nas z wizytą? Pewnie nie, bo nie mogliby wydostać się z powrotem, co nie?","en":"D''you think anybody is ever going to visit us? Probably not, they wouldn''t get out of here again, would they?","de":"Glaubst du, dass uns mal jemand von außerhalb besucht? Wohl kaum, was, weil die kommen ja dann nicht mehr raus, oder?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_18_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_18_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_18_Info","outputIds":["DIA_Mud_Nerve_18_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Teraz, gdy jesteśmy razem, moglibyśmy pokazać kilku ludziom, gdzie raki zimują. Te skurczybyki nachodzą mnie od lat! Jak zobaczę któregoś z nich, dam im do słuchu!","en":"Now that you''re with me, we could show a few people where to go. These bastards have been harassing me for years. When I see one of them now, I''m gonna tell him a few things.","de":"Jetzt, wo du bei mir bist, können wir ja mal einigen Arschlöchern aufs Maul hauen. Die haben mich jahrelang getriezt. Wenn ich einen von denen sehe, dann sag'' ich ihnen die Meinung."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_19_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_19_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_19_Info","outputIds":["DIA_Mud_Nerve_19_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz co? Stanowimy dobraną parę. Moglibyśmy przejąć kontrolę nad całym Starym Obozem. Jesteśmy zespołem, więc powinniśmy łatwo uporać się z Magnatami. Obmyślę jakiś plan.","en":"The two of us are a dream team. We could take over the Old Camp. The Ore Barons wouldn''t be a problem for us since we''re a team. I''ll think of a plan.","de":"Zusammen sind wir echt unschlagbar. Wir könnten das Alte Lager übernehmen. Mit den Erzbaronen werden wir schon fertig, wir sind ja zu zweit. Ich werde mir etwas ausdenken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_2_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_2_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_2_Info","outputIds":["DIA_Mud_Nerve_2_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Zdecydowałeś się wreszcie dokąd chcesz iść?","en":"Don''t you have any plan of where you want to go?","de":"Hast du eigentlich keinen Plan, wo du hinwillst? Suchst du ein stilles Plätzchen? Wo wir ein bisschen reden können und so?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_3_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_3_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_3_Info","outputIds":["DIA_Mud_Nerve_3_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Może szukasz jakiegoś spokojnego miejsca, gdzie moglibyśmy pogadać?","en":"Are you looking for a quiet place? Where we can talk for a bit or something?","de":"Hast du eigentlich keinen Plan, wo du hinwillst? Suchst du ein stilles Plätzchen? Wo wir ein bisschen reden können und so?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_4_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_4_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_4_Info","outputIds":["DIA_Mud_Nerve_4_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Czy to możliwe, że chodzimy w kółko... To znaczy, nie wiem dokąd chcesz iść, ale...","en":"Is it possible we''re walking in circles? I mean, I don''t know where you want to go...","de":"Kann es sein, dass du im Kreis läufst? Ich meine, ich weiß ja nicht, wo du hin willst ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_5_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_5_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_5_Info","outputIds":["DIA_Mud_Nerve_5_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Ale fajnie! Dzięki, że zabrałeś mnie ze sobą! Moglibyśmy robić to częściej. Nie mam nic do roboty przez większość dnia!","en":"This is real fun. Thanks for taking me with you. We could do that more often, there''s loads of more time left today.","de":"Das macht richtig Spaß mit dir. Schön, dass du mich mitnimmst. Das können wir öfter mal machen. Und heute ist ja auch noch viel Zeit."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_6_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_6_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_6_Info","outputIds":["DIA_Mud_Nerve_6_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Wiesz co? Już cię polubiłem! Przeżyjemy wspólnie wiele ciekawych przygód! Co nie?! Gdzie nocujesz? Jakbyś chciał, możesz przenocować u mnie!","en":"I have gotten used to you already. We''ll have much fun together, I''m sure of that. Aren''t you? Where do you sleep anyway? You can come to my place, no problem.","de":"Ich hab'' mich schon richtig an dich gewöhnt. Wir werden sicher eine Menge Spaß miteinander haben. Nicht wahr? Wo schläfst du eigentlich? Du kannst gerne zu mir kommen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_7_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_7_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_7_Info","outputIds":["DIA_Mud_Nerve_7_07_00"],"lines":[{"speaker":"npc","text":{"pl":"A tak w ogóle, to za co tutaj trafiłeś? Ty też za bardzo lubisz zwierzęta? Oni krzywo na to patrzą, wiesz? Właśnie tak tutaj wylądowałem.","en":"Why did they put you in here anyway? Do you like animals as well? They''re not into that one bit. That''s why they locked me in here.","de":"Wegen was haben sie dich eigentlich hier reingeworfen? Hast du auch einen Faible für Tiere? Das haben sie ja gar nicht gerne. Da haben sie mich eingebuchtet."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_8_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_8_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_8_Info","outputIds":["DIA_Mud_Nerve_8_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Kilku facetów bez przerwy próbuje mnie pobić. Paskudni ludzie z Nowego Obozu! Bandziory jedne! Następnym razem powiem im, że kto ze mną zadziera, będzie miał z tobą do czynienia! To ich nauczy!","en":"There are some people who constantly try to beat me up. Horrible guys from the New Camp. Real cut-throats. The next time I''ll tell them that they''ll have you to deal with in the future. Then they''ll be dead scared.","de":"Es gibt da ein paar Leute, die versuchen ständig, mich zu verprügeln. Fiese Typen aus dem Neuen Lager. Richtige Brutalos. Ich werde ihnen beim nächsten Mal gleich sagen, dass sie es in Zukunft mir dir zu tun kriegen. Das wird sie sicher abschrecken."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_nerve_9_07_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_nerve_9_07_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_Nerve_9_Info","outputIds":["DIA_Mud_Nerve_9_07_00"],"lines":[{"speaker":"npc","text":{"pl":"Ale się zdziwią ci z Nowego Obozu, jak im powiem jakiego mam obrońcę! Posikają się ze strachu! Ale będzie fajnie. Normalnie zabijają ludzi bez mrugnięcia okiem, ale teraz będą musieli dobrze się zastanowić.","en":"Those bastards from the New Camp will be amazed when they get to know that I have a protector. They''ll piss themselves. That''ll be fun. Normally they finish people off quickly, but now they''ll think twice.","de":"Diese fiesen Schweine aus dem Neuen Lager werden staunen, wenn sie erfahren, dass ich einen Beschützer habe. Die werden sich in die Hosen machen. Das wird ein Spaß. Sonst machen sie ja mit allen kurzen Prozess, aber jetzt werden sie sich das zweimal überlegen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_574_mud_dia_mud_shut_up_15_00_0', 'VLK_574_Mud', '{"id":"missions_dia_vlk_574_mud_dia_mud_shut_up_15_00_0","npcId":"VLK_574_Mud","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_574_Mud.d","sourceFunction":"DIA_Mud_ShutUp_Info","outputIds":["DIA_Mud_ShutUp_15_00","DIA_Mud_ShutUp_07_01"],"lines":[{"speaker":"hero","text":{"pl":"Możesz się zamknąć choć na chwilę?","en":"Could you PLEASE keep quiet for a minute?","de":"Kannst du mal BITTE einen Moment die Klappe halten?"}},{"speaker":"npc","text":{"pl":"Jasne.","en":"Sure.","de":"Klar."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_at_ocdraussen_06_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_at_ocdraussen_06_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_AtOCdraussen_Info","outputIds":["DIA_Grim_AtOCdraussen_06_00","DIA_Grim_AtOCdraussen_06_01","DIA_Grim_AtOCdraussen_06_02"],"lines":[{"speaker":"npc","text":{"pl":"Oto jesteśmy - daleko od twojego kumpla, Diego.","en":"So, here we are - far away from your friend Diego.","de":"So, hier sind wir. Schön weit weg von deinem Freund Diego."}},{"speaker":"npc","text":{"pl":"Mamy ci przekazać pozdrowienia od Bloodwyna!","en":"We''re to send you regards from Bloodwyn!","de":"Wir sollen dir schöne Grüße von Bloodwyn bestellen!"}},{"speaker":"npc","text":{"pl":"Mam ci przekazać pozdrowienia od Bloodwyna!","en":"I''m to send you regards from Bloodwyn!","de":"Ich soll dir schöne Grüße von Bloodwyn bestellen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_aufnahme_06_04_4', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_aufnahme_06_04_4","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Aufnahme_Info","outputIds":["DIA_Grim_Aufnahme_06_04"],"lines":[{"speaker":"npc","text":{"pl":"Jeśli ci się uda, zostaniesz jednym z nas.","en":"If you manage them, you''ll be with us.","de":"Wenn du die gelöst hast, bist du dabei."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_aufnahme_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_aufnahme_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Aufnahme_Info","outputIds":["DIA_Grim_Aufnahme_15_00","DIA_Grim_Aufnahme_06_01","DIA_Grim_Aufnahme_06_02","DIA_Grim_Aufnahme_06_03"],"lines":[{"speaker":"hero","text":{"pl":"Co mam zrobić, jeśli chcę zostać przyjęty do tego obozu?","en":"What do I have to do if I want to get admitted to this camp?","de":"Was muss ich machen, wenn ich in diesem Lager aufgenommen werden will?"}},{"speaker":"npc","text":{"pl":"Na początek musisz zostać Cieniem. W tym celu poszukaj sobie jakiegoś wpływowego opiekuna. Kogoś, kto wyjaśni ci co w trawie piszczy i wskaże ci właściwą drogę.","en":"Well, first of all you have to become a Shadow. Therefore, you have to find somebody who supports you. Somebody who explains everything to you and takes responsibility for you.","de":"Also zuerst mal wirst du Schatten. Dazu musst du einen Fürsprecher finden. Jemand, der dir alles erklärt und für dich einsteht."}},{"speaker":"npc","text":{"pl":"Na twoim miejscu trzymałbym się blisko Diego - ja tak zrobiłem i nie żałuję!","en":"If I was you I''d try and keep close to Diego - I did it like that - he''s quite alright.","de":"Ich an deiner Stelle würd'' mich direkt an Diego halten - hab'' ich auch gemacht - der ist ganz in Ordnung."}},{"speaker":"npc","text":{"pl":"On podda cię testowi zaufania - dla każdego wygląda on trochę inaczej. No i musisz wypełniać jeszcze zadania zlecane ci przez Cienie.","en":"He''ll make you take the test of faith - that''s different for everybody. Then there''ll be some other smaller tasks from other Shadows.","de":"Er stellt dir die Prüfung des Vertrauens - die sieht bei jedem anders aus. Dann gibt''s noch einige kleinere Aufgaben von anderen Schatten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_falle_06_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_falle_06_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Falle_Info","outputIds":["DIA_Grim_Falle_06_00","DIA_Grim_Falle_15_01","DIA_Grim_Falle_06_02","DIA_Grim_Falle_15_03"],"lines":[{"speaker":"npc","text":{"pl":"Hej, ty! Czy to nie ty chcesz dołączyć do naszego obozu?","en":"Hey, you! Aren''t you the guy who wants to join the Camp?","de":"Hey, du! Du bist doch der Typ, der hier im Lager aufgenommen werden will?"}},{"speaker":"hero","text":{"pl":"A jeśli chcę?","en":"What if I am?","de":"Und wenn es so wäre?"}},{"speaker":"npc","text":{"pl":"Mógłbym ci pomóc...","en":"I could help you...","de":"Ich könnte dir dabei helfen ..."}},{"speaker":"hero","text":{"pl":"Jak?","en":"And how?","de":"Und wie?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_falle_06_04_4', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_falle_06_04_4","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Falle_Info","outputIds":["DIA_Grim_Falle_06_04","DIA_Grim_Falle_06_05"],"lines":[{"speaker":"npc","text":{"pl":"Na zewnątrz Obozu siedzi dwóch gości. Jeden z nich ukradł coś cennego Magnatom. To cenny amulet, który miał nam zostać przysłany z ostatnim transportem ze świata zewnętrznego.","en":"There are two guys sitting around outside the Camp, and one of them has stolen something from the Ore Barons. It''s a precious amulet, which should have arrived with the last convoy.","de":"Draußen vorm Lager sitzen zwei Typen rum, von denen einer die Erzbarone bestohlen hat. Es ist ein wertvolles Amulett, das mit dem letzten Konvoi gekommen sein sollte."}},{"speaker":"npc","text":{"pl":"Któryś z nich powinien mieć ten amulet przy sobie. Jeśli zaatakujemy ich razem, powinno nam się udać. Sam raczej nie dam rady. Co ty na to?","en":"One of them should still be in possession of the amulet. If we attack them together, we should manage - I couldn''t do it on my own. What d''you say?","de":"Einer von ihnen müsste das Amulett noch haben. Wenn wir beide auf sie draufgehen, schaffen wir sie - alleine kann ich''s nicht machen. Was sagst du?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_falle_accepr_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_falle_accepr_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Falle_Accepr","outputIds":["DIA_Grim_Falle_Accepr_15_00","DIA_Grim_Falle_Accepr_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Pójdę z tobą.","en":"Count me in!","de":"Ich bin dabei!"}},{"speaker":"npc","text":{"pl":"Świetnie, daj mi znać, gdy będziesz gotów.","en":"Alright, just tell me when we can start!","de":"Gut, sag Bescheid, sobald wir losgehen können!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_falle_deny_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_falle_deny_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Falle_Deny","outputIds":["DIA_Grim_Falle_Deny_15_00","DIA_Grim_Falle_Deny_06_01"],"lines":[{"speaker":"hero","text":{"pl":"To nie dla mnie. Poszukaj sobie kogoś innego.","en":"Not interested - you''ll have to look for somebody else.","de":"Kein Interesse - such dir einen anderen."}},{"speaker":"npc","text":{"pl":"Z takim podejściem długo tu miejsca nie zagrzejesz. Daj mi znać, gdybyś zmienił zdanie!","en":"With this kind of attitude you won''t last long here - just tell me if you change your mind!","de":"Mit der Einstellung kommst du hier nicht weit - sag mir Bescheid, falls du''s dir doch noch überlegen solltest!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_falle_half_half_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_falle_half_half_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Falle_HalfHalf","outputIds":["DIA_Grim_Falle_HalfHalf_15_00","DIA_Grim_Falle_HalfHalf_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie! Albo dzielimy się po połowie, albo baw się sam!","en":"No! It''s either fifty-fifty or you can do it on your own!","de":"Nein! Wir machen halbe-halbe! Oder du kannst dich alleine mit den Typen anlegen!"}},{"speaker":"npc","text":{"pl":"Niech będzie, pół na pół! Nagrody wystarczy dla nas dwóch! To jak? Mogę na ciebie liczyć?","en":"Okay, okay, fifty-fifty. I suppose it''ll be enough for the two of us anyway. So - can I count on you?","de":"Okay, okay, halbe-halbe. Wird schon genug dabei rausspringen. Also - bist du dabei?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_falle_how_share_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_falle_how_share_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Falle_HowShare","outputIds":["DIA_Grim_Falle_HowShare_15_00","DIA_Grim_Falle_HowShare_06_01"],"lines":[{"speaker":"hero","text":{"pl":"A co się stanie, gdy już zdobędziemy amulet?","en":"What will happen when we have the amulet?","de":"Was passiert, wenn wir das Amulett haben?"}},{"speaker":"npc","text":{"pl":"To proste. Zwrócę go Magnatom i odbiorę nagrodę. Przy okazji powiem im, że mi pomogłeś. Ta wiadomość na pewno dotrze do Gomeza!","en":"That''s an easy one! I''ll return it and get the reward. I''l tell them you helped me. Then you''ll be in Gomez'' good books for sure...","de":"Ganz einfach! Ich geb''s zurück und kassier die Belohnung - dabei sag'' ich, dass du mir geholfen hast. Damit hast du bei Gomez ''nen Stein in Brett."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_how_far_are_you_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_how_far_are_you_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_HowFarAreYou_Info","outputIds":["DIA_Grim_HowFarAreYou_15_00","DIA_Grim_HowFarAreYou_06_01"],"lines":[{"speaker":"hero","text":{"pl":"A ty, jak sobie radzisz?","en":"And - how far have you got with your tests?","de":"Und - wie weit bist du mit deinen Prüfungen?"}},{"speaker":"npc","text":{"pl":"Rozmawiałem już z Dexterem, Złym i Rączką. To jedni najbardziej wpływowych ludzi w Zewnętrznym Pierścieniu.","en":"I''ve already talked to Dexter and Sly and Fingers. They are some of the most influential Shadows here in the Camp.","de":"Ich hab'' schon mit Dexter, Sly und Fingers geredet. Das sind einige der einflussreichsten Schatten hier im Lager."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_inextremo_06_01_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_inextremo_06_01_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_INEXTREMO_Info","outputIds":["DIA_Grim_INEXTREMO_06_01","DIA_Grim_INEXTREMO_06_02","DIA_Grim_INEXTREMO_06_03"],"lines":[{"speaker":"npc","text":{"pl":"Hej, słyszałeś już wieści?","en":"Hey, have you heard the news?","de":"Hey, hast du schon gehört?"}},{"speaker":"npc","text":{"pl":"Są tu In Extremo! Właśnie weszli na scenę!","en":"In Extremo are here. They''re on stage over there.","de":"In Extremo ist hier. Sie sind drüben auf der Bühne."}},{"speaker":"npc","text":{"pl":"Pospiesz się, albo przegapisz koncert!","en":"Hurry, otherwise, you''ll miss the gig!","de":"Schnell, sonst versäumst du noch den Auftritt!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_inextremoaway_15_01_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_inextremoaway_15_01_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_INEXTREMOAWAY_Info","outputIds":["DIA_Grim_INEXTREMOAWAY_15_01","DIA_Grim_INEXTREMOAWAY_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie są In Extremo?","en":"Where are In Extremo?","de":"Wo sind InExtremo?"}},{"speaker":"npc","text":{"pl":"Pojechali dalej. Szkoda. Zdążyłem się przyzwyczaić do imprez pod sceną.","en":"They''ve moved on. It''s a shame, I got really used to the evenings in front of the stage.","de":"Sie sind weitergezogen. Schade, ich hatte mich an die Abende vor der Bühne gewöhnt."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_leben_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_leben_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_Leben_Info","outputIds":["DIA_Grim_Leben_15_00","DIA_Grim_Leben_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Jak wygląda życie w kolonii?","en":"What''s life like here?","de":"Wie ist das Leben hier so?"}},{"speaker":"npc","text":{"pl":"Nie jest źle, jeśli zapłacisz Strażnikom za ochronę.","en":"Easy going, as long as you pay your share of protection money to the guards.","de":"Ganz ruhig, so lange du dein Schutzgeld an die Gardisten bezahlst."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_nachfalle_06_05_4', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_nachfalle_06_05_4","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_NACHFalle_Info","outputIds":["DIA_Grim_NACHFalle_06_05"],"lines":[{"speaker":"npc","text":{"pl":"Osobiście nic do ciebie nie mam. To jak będzie - wojna czy pokój.","en":"Personally, I don''t dislike you. So what do you think - peace or further fighting?","de":"Persönlich hab'' ich nichts gegen dich. Also was ist - Frieden oder weiterprügeln?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_nachfalle_15_01_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_nachfalle_15_01_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_NACHFalle_Info","outputIds":["DIA_Grim_NACHFalle_15_01","DIA_Grim_NACHFalle_06_02","DIA_Grim_NACHFalle_06_03","DIA_Grim_NACHFalle_06_04"],"lines":[{"speaker":"hero","text":{"pl":"Ty głupcze, chciałeś mnie zwabić w pułapkę...","en":"So you idiot, just wanted to trap me...","de":"Du Penner wolltest mir also nur ''ne Falle stellen ..."}},{"speaker":"npc","text":{"pl":"Hej, stary! Jedziemy na tym samym wózku! Ja też nie zamierzam ryć pod ziemią do końca moich dni!","en":"Hey, man! We''re sitting in the same boat! I am not into digging in the mines either.","de":"Hey, Mann! Wir spielen beide dasselbe Spiel! Ich hab'' auch keine Lust, in den Minen buddeln zu gehen."}},{"speaker":"npc","text":{"pl":"Dlatego wypełniam polecenia Strażników. Ja też chcę dołączyć do Obozu!","en":"So I''ll do what the guards tell me, then I''ll be accepted soon.","de":"Also werd'' ich tun, was mir die Gardisten sagen, dann werde ich hier bald aufgenommen."}},{"speaker":"npc","text":{"pl":"Zresztą sam zasłużyłeś na cały ten bajzel. Dlaczego zadarłeś ze Strażnikami?","en":"That I should whack YOU of all people is your own fault really. Why did you have to start a bloody fight with the guards?","de":"Dass ich ausgerechnet DIR aufs Maul hauen sollte, hast du dir im Grunde selber zuzuschreiben. Warum legst du dich auch mit den Gardisten an."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_nachfalle_frieden_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_nachfalle_frieden_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_NACHFalle_Frieden","outputIds":["DIA_Grim_NACHFalle_Frieden_15_00","DIA_Grim_NACHFalle_Frieden_06_01","DIA_Grim_NACHFalle_Frieden_06_02"],"lines":[{"speaker":"hero","text":{"pl":"Niech będzie pokój.","en":"Peace sounds good.","de":"Frieden klingt gut."}},{"speaker":"npc","text":{"pl":"Cieszę się, że mogliśmy to sobie wyjaśnić. Najlepiej zapomnijmy o całej sprawie. Od tej chwili jestem po twojej stronie.","en":"I''m glad we see eye to eye on this. Let''s forget about it. From now on, I''m on your side.","de":"Freut mich, dass du das Ganze durch meine Augen sehen kannst. Die Sache ist vergessen. Ab jetzt bin ich auf deiner Seite."}},{"speaker":"npc","text":{"pl":"Gdybyś jeszcze kiedyś wpadł w tarapaty, możesz na mnie liczyć. W końcu jestem ci coś winien.","en":"If you ever have trouble again, you can count on me - I owe you some, after all.","de":"Wenn du noch mal Ärger haben solltest - kannst du auf mich zählen - schließlich schulde ich dir was."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_nachfalle_weiterpruegeln_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_nachfalle_weiterpruegeln_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_NACHFalle_Weiterpruegeln","outputIds":["DIA_Grim_NACHFalle_Weiterpruegeln_15_00","DIA_Grim_NACHFalle_Weiterpruegeln_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Nie mam nic przeciwko wojnie!","en":"I feel like fighting!","de":"Mir ist eher nach Weiterprügeln!"}},{"speaker":"npc","text":{"pl":"Stary, mam już tego dość...","en":"Oh man, you get me down...","de":"Oh Mann, du schaffst mich ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_ready_to_go_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_ready_to_go_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_ReadyToGo_Info","outputIds":["DIA_Grim_ReadyToGo_15_00","DIA_Grim_ReadyToGo_06_01"],"lines":[{"speaker":"hero","text":{"pl":"Jestem gotowy. Chodźmy po ten amulet.","en":"I''m ready to go with you - let''s get the amulet!","de":"Ich bin bereit, mit dir zu gehen - lass uns das Amulett holen!"}},{"speaker":"npc","text":{"pl":"Zatem do dzieła!","en":"Okay, let''s do it then ...","de":"Gut! Dann wollen wir mal ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_580_grim_dia_grim_your_pdv_15_00_0', 'VLK_580_Grim', '{"id":"missions_dia_vlk_580_grim_dia_grim_your_pdv_15_00_0","npcId":"VLK_580_Grim","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_580_Grim.d","sourceFunction":"DIA_Grim_YourPDV_Info","outputIds":["DIA_Grim_YourPDV_15_00","DIA_Grim_YourPDV_06_01"],"lines":[{"speaker":"hero","text":{"pl":"A jak wyglądał TWÓJ test zaufania?","en":"What was YOUR test of faith?","de":"Was ist DEINE Prüfung des Vertrauens?"}},{"speaker":"npc","text":{"pl":"Tego nie mogę ci powiedzieć. O takich rzeczach lepiej nie mówić głośno!","en":"I can''t tell you, man. You have to be silent about things like that here!","de":"Das kann ich dir nicht sagen, Mann. Über solche Dinge musst du hier schweigen!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_after_success_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_after_success_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_AfterSuccess_Info","outputIds":["DIA_Snaf_AfterSuccess_15_00","DIA_Snaf_AfterSuccess_01_01","DIA_Snaf_AfterSuccess_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Powiedziałeś, że mogę dostać tyle potrawki ile tylko zapragnę...","en":"You told me I could have as much stew as I wanted...","de":"Du hast gesagt, ich kann so viel von den Eintopf haben, wie ich will ..."}},{"speaker":"npc","text":{"pl":"I dotrzymam słowa. Proszę, weź te 3 porcje.","en":"And that''s true. Here, take 3 portions.","de":"Und das stimmt auch. Hier, nimm 3 Portionen!"}},{"speaker":"npc","text":{"pl":"Jasne! Ale nic mi już dzisiaj nie zostało. Wróć jutro!","en":"Sure! But there''s nothing left today. Come back tomorrow!","de":"Klar! Heute ist aber alles schon auf. Komm morgen wieder!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_hello_01_04_4', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_hello_01_04_4","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_Hello_Info","outputIds":["DIA_Snaf_Hello_01_04"],"lines":[{"speaker":"npc","text":{"pl":"Mógłbyś coś dla mnie zrobić...","en":"You could do me a favor.","de":"Du könntest mir einen Gefallen tun."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_hello_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_hello_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_Hello_Info","outputIds":["DIA_Snaf_Hello_15_00","DIA_Snaf_Hello_01_01","DIA_Snaf_Hello_01_02","DIA_Snaf_Hello_15_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak leci?","en":"How''s things?","de":"Wie steht''s?"}},{"speaker":"npc","text":{"pl":"Nienajgorzej! Człowiek, który umie dobrze gotować, ma tutaj wielu przyjaciół!","en":"Not bad. If you can cook well, you have many friends here.","de":"Nicht schlecht. Wenn man gut kochen kann, hat man viele Freunde hier."}},{"speaker":"npc","text":{"pl":"Chcesz może trochę mojej ryżowej zupy?","en":"Would you like some of my rice stew?","de":"Willst du etwas von meinem Reiseintopf? Hier, nimm und lass es dir schmecken."}},{"speaker":"hero","text":{"pl":"Dzięki.","en":"Thanks.","de":"Danke."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_where_meatbugs_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_where_meatbugs_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_WhereMeatbugs_Info","outputIds":["DIA_Snaf_WhereMeatbugs_15_00","DIA_Snaf_WhereMeatbugs_01_01","DIA_Snaf_WhereMeatbugs_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie mogę znaleźć te chrząszcze?","en":"Where can I find the meatbugs?","de":"Wo finde ich Fleischwanzen?"}},{"speaker":"npc","text":{"pl":"Wszędzie, gdzie walają się jakieś odpady. Poszukaj w opuszczonych chatach przy zamkowych murach.","en":"Everywhere where there''s garbage lying around. You should be able to find some at the deserted huts near the castle wall.","de":"Überall da, wo Müll rumliegt. An der Burgmauer gibt es einige verlassene Hütten, da solltest du welche finden."}},{"speaker":"npc","text":{"pl":"Tylko niech cię nie odstraszy ich paskudny wygląd. Po ugotowaniu są całkiem smaczne.","en":"Don''t get confused by their ugly looks. Once cooked they are tasty.","de":"Lass dich von ihrem fiesen Aussehen nicht täuschen. Gekocht sind sie lecker."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_where_mushrooms_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_where_mushrooms_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_WhereMushrooms_Info","outputIds":["DIA_Snaf_WhereMushrooms_15_00","DIA_Snaf_WhereMushrooms_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Gdzie znajdę te piekielniki?","en":"Where can I find hell mushrooms?","de":"Wo finde ich Höllenpilze?"}},{"speaker":"npc","text":{"pl":"Wyjdź z Obozu przez południową bramę, to ta pod zawaloną wieżą. Znajdziesz się na łące, na której rosną grzyby.","en":"If you leave through the south gate - that''s the collapsed tower - you''ll see a plain directly in front of you. There''s mushrooms growing there.","de":"Wenn du aus dem Südtor rausgehst - das ist der umgestürzte Turm - findest du direkt vor dir eine Ebene, auf der Pilze wachsen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_where_nek_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_where_nek_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_WhereNek_Info","outputIds":["DIA_Snaf_WhereNek_15_00","DIA_Snaf_WhereNek_01_01","DIA_Snaf_WhereNek_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Kim był człowiek, którego wysłałeś na poszukiwania przede mną?","en":"Who was the guy you sent before me?","de":"Wer war der Typ, den du vor mir losgeschickt hast?"}},{"speaker":"npc","text":{"pl":"Nazywał się Nek. Chyba nie czuł się tu zbyt dobrze. Podejrzewam, że uciekł do Nowego Obozu.","en":"His name was Nek. He was pretty discontented here - I think he''s in the New Camp now.","de":"Sein Name war Nek. Er war ziemlich unzufrieden hier - ich denke, er ist jetzt im Neuen Lager."}},{"speaker":"npc","text":{"pl":"Wysłałem go po grzyby, ale nigdy nie wrócił...","en":"I sent him to collect mushrooms - but he didn''t come back...","de":"Hab ihn Pilze suchen geschickt - aber er kam nicht wieder ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_zutaten_do_it_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_zutaten_do_it_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_Zutaten_DoIt","outputIds":["DIA_Snaf_Zutaten_DoIt_15_00","DIA_Snaf_Zutaten_DoIt_01_01","DIA_Snaf_Zutaten_DoIt_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Brzmi nieźle.","en":"Sounds good.","de":"Hört sich gut an."}},{"speaker":"npc","text":{"pl":"Zatem idź, i przynieś mi potrzebne składniki.","en":"Then go and see you get me the things.","de":"Dann sieh mal zu, dass du die Sachen besorgst."}},{"speaker":"npc","text":{"pl":"Poprzedni człowiek, którego wysłałem nie wrócił. Zapewne uciekł do Nowego Obozu.","en":"The last one I sent just hasn''t come back - must have deserted to the New Camp.","de":"Der Letzte, den ich losgeschickt hab, kommt einfach nicht wieder - ist bestimmt zum Neuen Lager übergelaufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_zutaten_kotz_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_zutaten_kotz_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_Zutaten_KOTZ","outputIds":["DIA_Snaf_Zutaten_KOTZ_15_00","DIA_Snaf_Zutaten_KOTZ_01_01","DIA_Snaf_Zutaten_KOTZ_01_02"],"lines":[{"speaker":"hero","text":{"pl":"Chcesz, żebym się porzygał?","en":"You want me to throw up?","de":"Willst du, dass ich kotze?"}},{"speaker":"npc","text":{"pl":"Nie musisz tego jeść, ale powinieneś przynajmniej spróbować! Zresztą, zawsze możesz to komuś odsprzedać!","en":"You don''t have to eat it, but I think at least you could try! If you happen to get the things, think of me.","de":"Du musst es ja nicht essen, aber zumindest probieren solltest du es! Falls du an die Sachen rankommst, denk an mich."}},{"speaker":"npc","text":{"pl":"Wysłałem już kogoś po składniki, ale ślad po nim zaginął. Pewnie uciekł do Nowego Obozu.","en":"I''ve already sent somebody but he just hasn''t come back - must have deserted to the New Camp.","de":"Ich hab'' schon jemanden geschickt, aber der kommt einfach nicht wieder - ist bestimmt zum Neuen Lager übergelaufen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_581_snaf_dia_snaf_zutaten_success_15_00_0', 'VLK_581_Snaf', '{"id":"missions_dia_vlk_581_snaf_dia_snaf_zutaten_success_15_00_0","npcId":"VLK_581_Snaf","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_581_Snaf.d","sourceFunction":"DIA_Snaf_ZutatenSuccess_Info","outputIds":["DIA_Snaf_ZutatenSuccess_15_00","DIA_Snaf_ZutatenSuccess_01_01"],"lines":[{"speaker":"hero","text":{"pl":"Mam przy sobie rzeczy, o które prosiłeś!","en":"I have the things you wanted from me!","de":"Ich hab'' die Sachen, die du von mir wolltest!"}},{"speaker":"npc","text":{"pl":"Świetnie! Teraz muszę je tylko wrzucić i za chwilę potrawka będzie gotowa. Zaczekaj...","en":"Good, I just have to add them, then the stew will be ready... Wait ...","de":"Gut, ich brauch sie nur noch dazuzugeben, dann ist der Eintopf fertig ... warte ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_582_melvin_dia_melvin_hello_15_00_0', 'VLK_582_Melvin', '{"id":"missions_dia_vlk_582_melvin_dia_melvin_hello_15_00_0","npcId":"VLK_582_Melvin","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_582_Melvin.d","sourceFunction":"DIA_Melvin_Hello_Info","outputIds":["DIA_Melvin_Hello_15_00","DIA_Melvin_Hello_03_01"],"lines":[{"speaker":"hero","text":{"pl":"Cześć! Nie jesteś z tego obozu, prawda?","en":"Hi! You aren''t from this camp, are you?","de":"Hi! Du bist nicht aus diesem Lager, oder?"}},{"speaker":"npc","text":{"pl":"Cóż, teraz już jestem! Tydzień temu wyruszyłem ze Starego Obozu. Mój kumpel, Dusty, miał iść ze mną, ale postanowił jeszcze trochę poczekać.","en":"Well, now I am! I left the Old Camp a week ago. Told my pal Dusty to come along but he wanted to wait.","de":"Jetzt schon! Ich bin vor ''ner Woche aus dem Alten Lager abgehauen. Hab'' meinem Kumpel Dusty gesagt, er soll mitkommen, aber er wollte lieber noch warten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_582_melvin_dia_melvin_met_dusty_15_00_0', 'VLK_582_Melvin', '{"id":"missions_dia_vlk_582_melvin_dia_melvin_met_dusty_15_00_0","npcId":"VLK_582_Melvin","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_582_Melvin.d","sourceFunction":"DIA_Melvin_MetDusty_Info","outputIds":["DIA_Melvin_MetDusty_15_00","DIA_Melvin_MetDusty_03_01","DIA_Melvin_MetDusty_15_02"],"lines":[{"speaker":"hero","text":{"pl":"Znam Dustego - zamieniliśmy kiedyś kilka słów.","en":"I know Dusty - I talked to him for a short time.","de":"Ich kenne Dusty - hab'' mich kurz mit ihm unterhalten."}},{"speaker":"npc","text":{"pl":"Gdybyś go jeszcze kiedyś spotkał, powiedz mu, że głupio zrobił nie idąc ze mną. Życie w Bractwie jest sto razy lepsze od ciągłego użerania się ze Strażnikami ze Starego Obozu.","en":"If you meet him again, tell him that he was dumb to stay there. It''s ten times better than getting harassed by the guards in the Old Camp.","de":"Wenn du ihn noch mal triffst, sag ihm, er ist schön blöd, dass er dageblieben ist. Wenn das hier nicht zehnmal besser ist, als sich im Alten Lager von den Gardisten schikanieren zu lassen, dann weiß ich''s auch nicht mehr."}},{"speaker":"hero","text":{"pl":"Nie omieszkam mu tego powtórzyć.","en":"I''ll tell him if I see him again.","de":"Werd''s ihm ausrichten, wenn ich ihn noch mal sehe."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_583_glen_vlk_583_glen_info_info_02_05_4', 'VLK_583_Glen', '{"id":"missions_dia_vlk_583_glen_vlk_583_glen_info_info_02_05_4","npcId":"VLK_583_Glen","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_583_Glen.d","sourceFunction":"VLK_583_Glen_INFO_Info","outputIds":["VLK_583_Glen_INFO_Info_02_05"],"lines":[{"speaker":"npc","text":{"pl":"Są bezlitosne i bardzo szybkie. Jeśli ci życie miłe, uciekaj stąd ile sił w nogach. Prędzej czy później padnie i na ciebie.","en":"They''re merciless and fast. If you enjoy being alive, you shouldn''t be down here. You better go before something happens to you.","de":"Gnadenlos und schnell. Wenn du am Leben hängst, solltest du dich nicht hier unten aufhalten. Geh lieber, bevor dir noch was passiert."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_583_glen_vlk_583_glen_info_info_15_01_0', 'VLK_583_Glen', '{"id":"missions_dia_vlk_583_glen_vlk_583_glen_info_info_15_01_0","npcId":"VLK_583_Glen","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_583_Glen.d","sourceFunction":"VLK_583_Glen_INFO_Info","outputIds":["VLK_583_Glen_INFO_Info_15_01","VLK_583_Glen_INFO_Info_02_02","VLK_583_Glen_INFO_Info_02_03","VLK_583_Glen_INFO_Info_02_04"],"lines":[{"speaker":"hero","text":{"pl":"O czym powinienem pamiętać, będąc w kopalni?","en":"What should I keep in mind when I''m in the mine?","de":"Worauf sollte ich in der Mine achten?"}},{"speaker":"npc","text":{"pl":"Uważaj na pełzacze.","en":"Beware of the minecrawlers.","de":"Auf die Minecrawler."}},{"speaker":"npc","text":{"pl":"Im niżej zejdziesz, tym częściej możesz na nie wpaść. Te przeklęte stwory przychodzą chyba wprost z królestwa samego Beliara!","en":"The further you get down, the closer you get to the beasts. Those rotten creatures come directly from Beliar''s realm!","de":"Je weiter du nach unten kommst, desto näher bist den Viechern. Die Mistdinger kommen direkt aus Beliars Reich!"}},{"speaker":"npc","text":{"pl":"Bez przerwy słychać, jak grzebią i kopią. Siedzą w ciemności i czekają na jakiegoś biednego górnika, z którego zrobią sobie obiad.","en":"You can hear them scraping and scratching. They are sitting in the dark, just waiting for you. I''ve seen them kill...","de":"Man kann sie schaben und kratzen hören. Sie lauern in der Dunkelheit und warten nur auf dich. Ich habe gesehen, wie sie getötet haben."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_583_glen_vlk_583_glen_lockpick_15_01_0', 'VLK_583_Glen', '{"id":"missions_dia_vlk_583_glen_vlk_583_glen_lockpick_15_01_0","npcId":"VLK_583_Glen","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_583_Glen.d","sourceFunction":"VLK_583_Glen_LOCKPICK_Info","outputIds":["VLK_583_Glen_LOCKPICK_15_01","VLK_583_Glen_LOCKPICK_02_02"],"lines":[{"speaker":"hero","text":{"pl":"Słyszałem, że można tu kupić wytrychy?","en":"I heard I could buy lockpicks here?","de":"Ich hab'' gehört, bei dir kann ich Dietriche kaufen."}},{"speaker":"npc","text":{"pl":"Skoro okazałeś się na tyle sprytny, żeby do mnie dotrzeć, możesz kilka kupić. To będzie 10 bryłek rudy za sztukę.","en":"Well, since you were brainy enough to find that out, you can have some. 10 ore a piece.","de":"Nun, wenn du schlau genug warst, das herauszufinden, dann kannst du welche haben. 10 Erz das Stück."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_584_snipes_info_exit_info_15_001_0', 'VLK_584_Snipes', '{"id":"missions_dia_vlk_584_snipes_info_exit_info_15_001_0","npcId":"VLK_584_Snipes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_584_Snipes.d","sourceFunction":"VLK_584_Snipes_Exit_Info","outputIds":["Info_Exit_Info_15_001","Info_Exit_Info_07_02"],"lines":[{"speaker":"hero","text":{"pl":"Do zobaczenia następnym razem!","en":"I''ll see you later.","de":"Wir sehen uns."}},{"speaker":"npc","text":{"pl":"Jasne!","en":"Yes, sure!","de":"Na, aber sicher doch!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_584_snipes_vlk_584_snipes_deal_2_info_07_05_4', 'VLK_584_Snipes', '{"id":"missions_dia_vlk_584_snipes_vlk_584_snipes_deal_2_info_07_05_4","npcId":"VLK_584_Snipes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_584_Snipes.d","sourceFunction":"VLK_584_Snipes_DEAL_2_Info","outputIds":["VLK_584_Snipes_DEAL_2_Info_07_05"],"lines":[{"speaker":"npc","text":{"pl":"Ma być 30 bryłek! Daj mi rudę, to dostaniesz klucz.","en":"I said 30 ore! Give me the ore and I''ll give you the key!","de":"Ich sagte 30 Erz! Gib mir das Erz und ich gebe dir den Schlüssel!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_584_snipes_vlk_584_snipes_deal_2_info_15_01_0', 'VLK_584_Snipes', '{"id":"missions_dia_vlk_584_snipes_vlk_584_snipes_deal_2_info_15_01_0","npcId":"VLK_584_Snipes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_584_Snipes.d","sourceFunction":"VLK_584_Snipes_DEAL_2_Info","outputIds":["VLK_584_Snipes_DEAL_2_Info_15_01","VLK_584_Snipes_DEAL_2_Info_07_02","VLK_584_Snipes_DEAL_2_Info_15_03","VLK_584_Snipes_DEAL_2_Info_07_04"],"lines":[{"speaker":"hero","text":{"pl":"Wezmę ten klucz.","en":"Give me the key.","de":"Gib mir den Schlüssel."}},{"speaker":"npc","text":{"pl":"Trafiła ci się nie lada okazja.","en":"You made good business there.","de":"Du hast ein gutes Geschäft gemacht!"}},{"speaker":"hero","text":{"pl":"Zastanawiam się co TY z tego masz.","en":"I just wonder what you get out of it.","de":"Ich frage mich, was dein Gewinn an der Sache ist."}},{"speaker":"npc","text":{"pl":"Zawsze się cieszę, kiedy mogę dać prztyczka w nos któremuś ze Strażników. Zresztą, gdyby znaleźli przy mnie rzeczy z tej skrzyni, byłbym martwy.","en":"I''m always glad when I can get one over on the guards. And if they found the content of the chest with me, I''d be a dead man.","de":"Ich freue mich immer, wenn ich den Gardisten eins auswischen kann. Und wenn die den Inhalt der Truhe bei mir finden, bin ich dran!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_584_snipes_vlk_584_snipes_deal_info_15_01_0', 'VLK_584_Snipes', '{"id":"missions_dia_vlk_584_snipes_vlk_584_snipes_deal_info_15_01_0","npcId":"VLK_584_Snipes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_584_Snipes.d","sourceFunction":"VLK_584_Snipes_DEAL_Info","outputIds":["VLK_584_Snipes_DEAL_Info_15_01","VLK_584_Snipes_DEAL_Info_07_02","VLK_584_Snipes_DEAL_Info_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Jak leci?","en":"How''s things?","de":"Wie sieht''s aus?"}},{"speaker":"npc","text":{"pl":"Mam dla ciebie pewną propozycję.","en":"I have a deal to suggest.","de":"Ich schlage dir ein Geschäft vor."}},{"speaker":"npc","text":{"pl":"Spraw, żeby Aaron odczepił się od tej skrzyni, a zapłacę ci 10 bryłek rudy.","en":"If you make Aaron leave the chest alone, I''ll give you 10 ore!","de":"Wenn du Aaron dazu kriegst, dass er von der Truhe abhaut, dann gebe ich dir 10 Erz!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_584_snipes_vlk_584_snipes_deal_run_info_15_01_0', 'VLK_584_Snipes', '{"id":"missions_dia_vlk_584_snipes_vlk_584_snipes_deal_run_info_15_01_0","npcId":"VLK_584_Snipes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_584_Snipes.d","sourceFunction":"VLK_584_Snipes_DEAL_RUN_Info","outputIds":["VLK_584_Snipes_DEAL_RUN_Info_15_01","VLK_584_Snipes_DEAL_RUN_Info_07_02","VLK_584_Snipes_DEAL_RUN_Info_07_03"],"lines":[{"speaker":"hero","text":{"pl":"Należy mi się 10 bryłek rudy!","en":"You owe me 10 ore!","de":"Du schuldest mir 10 Erz"}},{"speaker":"npc","text":{"pl":"Proszę, zasłużyłeś na nie.","en":"Here, you''ve already earned the 10 ore.","de":"Hier, die 10 Erz hast du dir verdient."}},{"speaker":"npc","text":{"pl":"Ach, i jeszcze coś: mam przy sobie klucz do tej skrzyni. Jak dla ciebie - 30 bryłek.","en":"Oh, and one more thing: I have the key to his chest as well. For you... only 30 ore!","de":"Ach noch was, den Schlüssel für seine Truhe hab'' ich auch. Für dich nur 30 Erz!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_angry_info_05_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_angry_info_05_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_ANGRY_Info","outputIds":["VLK_585_Aleph_ANGRY_Info_05_01"],"lines":[{"speaker":"npc","text":{"pl":"Doniosłeś na mnie Brandickowi? Spadaj stąd!","en":"You ran me down with Brandick? Get lost!","de":"Du hast mich bei Brandick angeschwärzt? Mach, dass du wegkommst!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_clever_info_05_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_clever_info_05_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_CLEVER_Info","outputIds":["VLK_585_Aleph_CLEVER_Info_05_01"],"lines":[{"speaker":"npc","text":{"pl":"He he he, strażnicy nigdy mnie nie złapią!","en":"Hehehe, the guards will never get me!","de":"Hehehe, die Wachen erwischen mich nie!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_dirty_100_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_dirty_100_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_DIRTY_100","outputIds":["VLK_585_Aleph_DIRTY_100_Info_15_01","VLK_585_Aleph_DIRTY_100_Info_05_02","VLK_585_Aleph_DIRTY_100_Info_05_03"],"lines":[{"speaker":"hero","text":{"pl":"Niech będzie, ty zdzierco. Masz tu swoje 100 bryłek.","en":"Alright, you crook. Here are 100 ore.","de":"Na gut, du Halsabschneider. Hier sind deine 100 Erz."}},{"speaker":"npc","text":{"pl":"Trzeba było ze mną nie zadzierać. Oto twój klucz.","en":"You shouldn''t have grassed me up. Here''s the key.","de":"Du hättest mich halt nicht verpfeifen sollen. Hier ist der Schlüssel."}},{"speaker":"npc","text":{"pl":"Masz mnie za głupca?! 100 bryłek, to moje ostatnie słowo!","en":"Do you think I''m stupid or what? 100 ore, and not a nugget less!","de":"Für wie blöd hältst du mich eigentlich? 100 Erz, nicht einen Brocken weniger!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_dirty_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_dirty_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_DIRTY_Info","outputIds":["VLK_585_Aleph_DIRTY_Info_15_01","VLK_585_Aleph_DIRTY_Info_05_02","VLK_585_Aleph_DIRTY_Info_15_03","VLK_585_Aleph_DIRTY_Info_05_04"],"lines":[{"speaker":"hero","text":{"pl":"Wiesz może coś o kluczu do skrzyni ze składowiska?","en":"Do you know anything about the key to the chests in the storage shed?","de":"Weißt du was über den Schlüssel für die Truhen im Lagerschuppen?"}},{"speaker":"npc","text":{"pl":"Cóż, to zależy...","en":"Well, that depends...","de":"Nun, das kommt ganz darauf an ..."}},{"speaker":"hero","text":{"pl":"Od ilości bryłek rudy, które jestem gotów zapłacić?","en":"On how much ore I''ll give you?","de":"Darauf, wieviel Erz ich dir gebe?"}},{"speaker":"npc","text":{"pl":"Szybko się uczysz. To cię będzie kosztować 100 bryłek.","en":"You learn quickly. I want 100 ore.","de":"Du lernst schnell. Ich will 100 Erz."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_dirty_no_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_dirty_no_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_DIRTY_NO","outputIds":["VLK_585_Aleph_DIRTY_NO_Info_15_01","VLK_585_Aleph_DIRTY_NO_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Nie będę wyrzucał w błoto takiej ilości rudy!","en":"I''m not gonna throw 100 ore at you!","de":"Ich werfe dir doch keine 100 Erz in den Rachen!"}},{"speaker":"npc","text":{"pl":"To po co mnie w ogóle zaczepiasz?","en":"Hey, it''s you who constantly starts talking to me!","de":"Hey, immerhin bist du derjenige, der mich die ganze Zeit anquatscht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_exit_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_exit_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_Exit_Info","outputIds":["VLK_585_Aleph_Exit_Info_15_01","VLK_585_Aleph_Exit_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Powodzenia!","en":"Good luck!","de":"Viel Glück noch."}},{"speaker":"npc","text":{"pl":"Cóż, wiesz, gdzie mnie znaleźć.","en":"Well, you know where to find me.","de":"Du weißt ja, wo du mich findest."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_glen_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_glen_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_GLEN_Info","outputIds":["VLK_585_Aleph_GLEN_Info_15_01","VLK_585_Aleph_GLEN_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Za taką cenę oczekuję czegoś naprawdę dobrego!","en":"I expect good information for my ore!","de":"Für mein Erz erwarte ich auch eine gute Information!"}},{"speaker":"npc","text":{"pl":"W kopalni można znaleźć mnóstwo zamkniętych skrzyń. Glen, jeden z Kopaczy na górze, może ci dostarczyć parę wytrychów.","en":"There''s loads of locked chests here. Glen, the digger at the top, can get you a couple of lockpicks.","de":"Hier gibt''s eine Menge verschlossener Truhen. Glen, der Buddler, der ganz oben steht, kann dir ein paar Dietriche besorgen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_guards_info_05_05_4', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_guards_info_05_05_4","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_GUARDS_Info","outputIds":["VLK_585_Aleph_GUARDS_Info_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Mam oczy szeroko otwarte, więc dowiedziałem się kilku ciekawych rzeczy. Masz może przy sobie trochę rudy? Jakieś 10 bryłek?","en":"I keep my ears open, so I get to know many useful things. You don''t happen to have some ore on you? Let''s say about 10 ore?","de":"Ich halt immer meine Ohren offen und bekomme viele nützliche Dinge mit. Du hast nicht zufällig etwas Erz bei dir? So ungefähr 10 Erz?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_guards_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_guards_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_GUARDS_Info","outputIds":["VLK_585_Aleph_GUARDS_Info_15_01","VLK_585_Aleph_GUARDS_Info_05_02","VLK_585_Aleph_GUARDS_Info_15_03","VLK_585_Aleph_GUARDS_Info_05_04"],"lines":[{"speaker":"hero","text":{"pl":"Co masz na myśli?","en":"What do you mean?","de":"Wie meinst du das?"}},{"speaker":"npc","text":{"pl":"Pracuję tylko wtedy, gdy w pobliżu jest jakiś Strażnik, który może mnie zobaczyć. Poza tym tylko sobie odpoczywam.","en":"I only work when the guards are nearby or they can see me. Otherwise I just hang around here.","de":"Ich arbeite nur, wenn Wachen in der Nähe sind oder mich sehen können. Ansonsten häng'' ich hier meine Zeit ab."}},{"speaker":"hero","text":{"pl":"I nie robią się podejrzliwi?","en":"Don''t they get suspicious?","de":"Werden sie nicht misstrauisch?"}},{"speaker":"npc","text":{"pl":"Oczywiście, że tak! Wydobywam mniej rudy niż inny Kopacze, więc muszę nadrabiać braki drobnym handlem wymiennym.","en":"Yeah, well of course, I dig less ore than all the others do. It''s not always enough, so I have to do a bit of trading.","de":"Nun ja, ich schürfe natürlich weniger Erz als alle anderen. Es reicht natürlich nicht immer, da muss ich halt mal ein bisschen geschickt tauschen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_info_info_05_05_4', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_info_info_05_05_4","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_INFO_Info","outputIds":["VLK_585_Aleph_INFO_Info_05_05"],"lines":[{"speaker":"npc","text":{"pl":"Gdybyś potrzebował najświeższych informacji zgłoś się do mnie. Na pewno będę mógł ci pomóc.","en":"And if you need or hear something, come back to me, I''m sure I''ll be able to help....","de":"Und wenn du mal wieder was brauchst oder hörst, dann komm ruhig zu mir, ich kann dir bestimmt weiterhelfen ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_info_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_info_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_INFO_Info","outputIds":["VLK_585_Aleph_INFO_Info_15_01","VLK_585_Aleph_INFO_Info_05_02","VLK_585_Aleph_INFO_Info_05_03","VLK_585_Aleph_INFO_Info_05_04"],"lines":[{"speaker":"hero","text":{"pl":"Jasne, oto 10 bryłek.","en":"Alright, here''s 10 ore for you.","de":"In Ordnung, hier sind 10 Erz für dich."}},{"speaker":"npc","text":{"pl":"Dzięki. Idź do głównego szybu i zejdź na dół po rusztowaniu. Powinieneś trafić na dwie boczne jaskinie.","en":"Thanks. If you go to the main shaft and follow the catwalks further down, you''ll soon get to two side caves.","de":"Danke. Wenn du zurück zum Hauptschacht gehst und den Stegen weiter nach unten folgst, kommst du bald an zwei Nebenhöhlen."}},{"speaker":"npc","text":{"pl":"W drugiej z nich jest strażnik i stara młocarnia.","en":"There''s a guard in the second one, and there''s also an old masher.","de":"In der zweiten Höhle steht eine Wache. Da steht auch ein alter Stampfer."}},{"speaker":"npc","text":{"pl":"Gdzieś niedaleko znajdziesz napój uzdrawiający, tylko uważaj na pełzacze!","en":"There''s a healing potion lying about somewhere, but be careful and beware of the crawlers!","de":"Dort liegt noch irgendwo ein Heiltrank, aber sei vorsichtig und nimm dich vor den Crawlern in Acht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_key_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_key_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_KEY_Info","outputIds":["VLK_585_Aleph_KEY_Info_15_01","VLK_585_Aleph_KEY_Info_05_02"],"lines":[{"speaker":"hero","text":{"pl":"Masz dla mnie jeszcze jakieś pożyteczne informacje?","en":"Have you got any other useful information?","de":"Hast du noch ein paar nützliche Informationen?"}},{"speaker":"npc","text":{"pl":"Jasne, a masz 10 bryłek rudy?","en":"Sure, have you got 10 ore?","de":"Na klar, hast du noch 10 Erz?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_15_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_15_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_SCHUPPEN_15","outputIds":["VLK_585_Aleph_SCHUPPEN_15_15_01","VLK_585_Aleph_SCHUPPEN_15_05_02"],"lines":[{"speaker":"hero","text":{"pl":"15 bryłek wystarczy?","en":"Is 15 ore alright with you?","de":"Bist du mit 15 Erz einverstanden?"}},{"speaker":"npc","text":{"pl":"15 bryłek? Za 15 bryłek nie mam pojęcia o jakim kluczu mówisz!","en":"15 ore? I don''t know anything about a key!","de":"15 Erz? Ich weiß nichts von einem Schlüssel!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_30_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_30_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_SCHUPPEN_30","outputIds":["VLK_585_Aleph_SCHUPPEN_30_15_01","VLK_585_Aleph_SCHUPPEN_30_05_02","VLK_585_Aleph_SCHUPPEN_30_05_03"],"lines":[{"speaker":"hero","text":{"pl":"30 bryłek powinno wystarczyć.","en":"30 ore should be enough.","de":"30 Erz sollten reichen."}},{"speaker":"npc","text":{"pl":"W porządku. Tak się składa, że mam ten klucz przy sobie.","en":"Alright, I happen to have the key here.","de":"Nun gut, zufällig habe ich hier einen Schlüssel."}},{"speaker":"npc","text":{"pl":"Nie masz tyle przy sobie!","en":"You don''t have that much ore.","de":"So viel Erz hast du nicht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_50_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_50_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_SCHUPPEN_50","outputIds":["VLK_585_Aleph_SCHUPPEN_50_15_01","VLK_585_Aleph_SCHUPPEN_50_05_02","VLK_585_Aleph_SCHUPPEN_50_05_03"],"lines":[{"speaker":"hero","text":{"pl":"50 bryłek to chyba uczciwa cena!","en":"50 ore should be more than enough for you!","de":"50 Erz sind mehr als genug für dich!"}},{"speaker":"npc","text":{"pl":"Jesteś bardzo hojny! Oto klucz. Weź też ten pierścień. Zawsze przynosił mi szczęście.","en":"Very generous! Here''s the key. And take this ring as well. It''s always brought good luck to me.","de":"Überaus großzügig. Hier ist der Schlüssel. Und nimm auch diesen Ring. Mir hat er immer Glück gebracht."}},{"speaker":"npc","text":{"pl":"Nie masz tyle przy sobie!","en":"You don''t have that much ore!","de":"So viel Erz hast du nicht!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_info_15_01_0', 'VLK_585_Aleph', '{"id":"missions_dia_vlk_585_aleph_vlk_585_aleph_schuppen_info_15_01_0","npcId":"VLK_585_Aleph","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_585_Aleph.d","sourceFunction":"VLK_585_Aleph_SCHUPPEN_Info","outputIds":["VLK_585_Aleph_SCHUPPEN_Info_15_01","VLK_585_Aleph_SCHUPPEN_Info_05_02","VLK_585_Aleph_SCHUPPEN_Info_15_03","VLK_585_Aleph_SCHUPPEN_Info_05_04"],"lines":[{"speaker":"hero","text":{"pl":"Wiesz może coś o kluczu do skrzyni ze składowiska?","en":"Do you know anything about the key for the chests in the storage shed??","de":"Weißt du was über den Schlüssel für die Truhen im Lagerschuppen?"}},{"speaker":"npc","text":{"pl":"Cóż... To zależy...","en":"Well, that depends...","de":"Nun, das kommt ganz darauf an ..."}},{"speaker":"hero","text":{"pl":"Od ilości bryłek rudy, które jestem gotów zapłacić?","en":"On how much ore I''ll give you?","de":"Darauf, wieviel Erz ich dir gebe?"}},{"speaker":"npc","text":{"pl":"Szybko się uczysz.","en":"You learn fast.","de":"Du lernst schnell."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_586_grimes_vlk_586_grimes_exit_info_15_01_0', 'VLK_586_Grimes', '{"id":"missions_dia_vlk_586_grimes_vlk_586_grimes_exit_info_15_01_0","npcId":"VLK_586_Grimes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_586_Grimes.d","sourceFunction":"VLK_586_Grimes_Exit_Info","outputIds":["VLK_586_Grimes_Exit_Info_15_01","VLK_586_Grimes_Exit_Info_04_02"],"lines":[{"speaker":"hero","text":{"pl":"Powodzenia!","en":"Good luck.","de":"Viel Glück noch."}},{"speaker":"npc","text":{"pl":"Nawzajem, chłopcze. Nawzajem.","en":"Same to you, boy, same to you.","de":"Dir auch, Jungchen, dir auch."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_586_grimes_vlk_586_grimes_first_info_04_02_0', 'VLK_586_Grimes', '{"id":"missions_dia_vlk_586_grimes_vlk_586_grimes_first_info_04_02_0","npcId":"VLK_586_Grimes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_586_Grimes.d","sourceFunction":"VLK_586_Grimes_FIRST_Info","outputIds":["VLK_586_Grimes_FIRST_Info_04_02"],"lines":[{"speaker":"npc","text":{"pl":"Oho! Nowa twarz! Pracowałeś kiedyś jako górnik, chłopcze?","en":"A new face. Have you ever dug ore, boy?","de":"Ein neues Gesicht. Na, schon mal Erz geschürft, Jungchen?"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_586_grimes_vlk_586_grimes_know_info_15_01_0', 'VLK_586_Grimes', '{"id":"missions_dia_vlk_586_grimes_vlk_586_grimes_know_info_15_01_0","npcId":"VLK_586_Grimes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_586_Grimes.d","sourceFunction":"VLK_586_Grimes_KNOW_Info","outputIds":["VLK_586_Grimes_KNOW_Info_15_01","VLK_586_Grimes_KNOW_Info_04_02","VLK_586_Grimes_KNOW_Info_04_03","VLK_586_Grimes_KNOW_Info_04_04"],"lines":[{"speaker":"hero","text":{"pl":"Zapewne słyszałeś też o wielu planach ucieczki.","en":"You must have heard about many escape plans as well.","de":"Du hast doch bestimmt auch eine Menge Ausbruchspläne mitgekriegt."}},{"speaker":"npc","text":{"pl":"Posłuchaj, chłopcze. Wiem, że chciałbyś się stąd wydostać, ale zapomnij o tym.","en":"Listen, boy: I know you want to get out of here - but forget it.","de":"Hör zu, mein Junge: Ich weiß genau, du willst hier raus - aber vergiss es."}},{"speaker":"npc","text":{"pl":"Stąd nie ma ucieczki! Widziałem twarze tych, którzy próbowali sforsować Barierę.","en":"You better forget the thought of escape. I saw the faces of those who tried to get out of the Barrier.","de":"Gewöhn dich direkt daran und vergiss die Gedanken vom Ausbruch. Ich hab'' die Gesichter der Leute gesehen, die versucht haben, aus der Barriere zu fliehen."}},{"speaker":"npc","text":{"pl":"Nie popełniaj tego samego błędu. Bariera powstrzyma każdego.","en":"Don''t make the same mistake, the Barrier will stop everybody.","de":"Mach nicht denselben Fehler, die Barriere hält jeden auf!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_586_grimes_vlk_586_grimes_know_info_15_05_4', 'VLK_586_Grimes', '{"id":"missions_dia_vlk_586_grimes_vlk_586_grimes_know_info_15_05_4","npcId":"VLK_586_Grimes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_586_Grimes.d","sourceFunction":"VLK_586_Grimes_KNOW_Info","outputIds":["VLK_586_Grimes_KNOW_Info_15_05","VLK_586_Grimes_KNOW_Info_04_06","VLK_586_Grimes_KNOW_Info_04_07"],"lines":[{"speaker":"hero","text":{"pl":"Nie chcę spędzić następnych 10 lat mojego życia wydobywając rudę!","en":"I don''t want to dig in the mine for the next ten years of my life!","de":"Ich habe nicht vor, die nächsten 10 Jahre meines Lebens hier zu schürfen!"}},{"speaker":"npc","text":{"pl":"Wcale nie musisz. Może zostaniesz wielką szychą, kto wie?","en":"No, you won''t. Perhaps you''ll be one of the real big shots, who knows.","de":"Nein. Das wirst du nicht. Vielleicht wirst du zu den ganz Grossen gehören, wer weiß."}},{"speaker":"npc","text":{"pl":"Możesz piąć się do góry, ale nieważne jak wysokie stanowisko uda ci się osiągnąć - Bariera wreszcie cię zatrzyma.","en":"You''ll work your way up, but no matter how far you''ll get, the Barrier will finally stop you.","de":"Du wirst dich nach oben arbeiten, aber ganz egal, wie weit du auch kommst, die Barriere wird dich aufhalten!"}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_586_grimes_vlk_586_grimes_story_info_04_05_4', 'VLK_586_Grimes', '{"id":"missions_dia_vlk_586_grimes_vlk_586_grimes_story_info_04_05_4","npcId":"VLK_586_Grimes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_586_Grimes.d","sourceFunction":"VLK_586_Grimes_STORY_Info","outputIds":["VLK_586_Grimes_STORY_Info_04_05"],"lines":[{"speaker":"npc","text":{"pl":"Ale to stare dzieje...","en":"But that''s old stories...","de":"Aber das sind alte Geschichten."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_586_grimes_vlk_586_grimes_story_info_15_01_0', 'VLK_586_Grimes', '{"id":"missions_dia_vlk_586_grimes_vlk_586_grimes_story_info_15_01_0","npcId":"VLK_586_Grimes","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_586_Grimes.d","sourceFunction":"VLK_586_Grimes_STORY_Info","outputIds":["VLK_586_Grimes_STORY_Info_15_01","VLK_586_Grimes_STORY_Info_04_02","VLK_586_Grimes_STORY_Info_04_03","VLK_586_Grimes_STORY_Info_04_04"],"lines":[{"speaker":"hero","text":{"pl":"Od dawna tu jesteś?","en":"Have you been here long?","de":"Bist du schon lange hier?"}},{"speaker":"npc","text":{"pl":"Od całych 10 lat. Uwierz mi, dużo już tu widziałem.","en":"I''ve already been here 10 years. Believe me, I''ve learned and experienced quite a lot here.","de":"Ich bin schon seit 10 Jahren hier. Du kannst mir glauben, dass ich schon einiges gesehen und erlebt hab''."}},{"speaker":"npc","text":{"pl":"Stawiłem czoła wielu niebezpieczeństwom, ale jakoś udało mi się z nich wybrnąć.","en":"I''ve encountered many dangers and managed to stay alive.","de":"So manche Gefahr hab'' ich schon gemeistert und es immer verstanden, am Leben zu bleiben!"}},{"speaker":"npc","text":{"pl":"Pamiętam jak pracowaliśmy jeszcze w pierwszej kopalni, tej, która teraz stoi pusta. Pewnego dnia nie wytrzymały podpory...","en":"In the old times, when we worked in the abandoned mine, the one which is deserted now, and the supporting beams collapsed...","de":"Damals, als wir noch in der inzwischen verlassenen Mine gearbeitet haben und die Stützbalken eingekracht sind ..."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
INSERT OR REPLACE INTO content_quotes (id, npc_id, data_json, enabled, quality_status, admin_note, updated_at) VALUES ('missions_dia_vlk_587_garp_vlk_587_garp_ork_info_15_01_0', 'VLK_587_Garp', '{"id":"missions_dia_vlk_587_garp_vlk_587_garp_ork_info_15_01_0","npcId":"VLK_587_Garp","sourceFile":"_work/Data/Scripts/Content/Story/Missions/DIA_VLK_587_Garp.d","sourceFunction":"Vlk_587_Garp_ORK_Info","outputIds":["Vlk_587_Garp_ORK_Info_15_01","Vlk_587_Garp_ORK_Info_01_02","Vlk_587_Garp_ORK_Info_15_03","Vlk_587_Garp_ORK_Info_01_04"],"lines":[{"speaker":"hero","text":{"pl":"To tu robi ten Ork?","en":"What''s the Orc doing here?","de":"Was macht der Ork hier?"}},{"speaker":"npc","text":{"pl":"Złapali go nasi strażnicy. Od tej pory pracuje dla nas.","en":"The guards caught him. Ever since he''s been forced to work here.","de":"Die Gardisten haben ihn gefangen. Seitdem wird er hier zur Arbeit gezwungen."}},{"speaker":"hero","text":{"pl":"Przecież nie jest nawet skuty łańcuchami. Czemu po prostu nie ucieknie?","en":"He''s not even in chains. Why doesn''t he just run away?","de":"Er ist ja noch nicht mal angekettet. Warum haut er nicht einfach ab?"}},{"speaker":"npc","text":{"pl":"Raz spróbował. Strażnicy tak go urządzili, że nie mógł się ruszyć przez parę tygodni. Od tej pory nigdy więcej się nie buntował.","en":"He tried that once. The guards gave it to him in such a way that he couldn''t walk for a couple of weeks. Since then, he''s never tried it again.","de":"Er hat es einmal versucht. Die Gardisten haben ihm so stark zugesetzt, dass er ein paar Wochen nicht laufen konnte. Seitdem hat er nie wieder versucht zu fliehen."}}],"context":{"pl":"Oryginalny dialog z Gothic 1.","en":"Original Gothic 1 dialogue.","de":"Originaldialog aus Gothic 1."}}', 1, 'ok', NULL, 1781529791212);
